struct CLIError: Error, CustomStringConvertible {
    let message: String
    let exitCode: Int32
    /// Structured v2 protocol error code when the failure came from a v2 error response.
    let v2Code: String?

    init(message: String, exitCode: Int32 = 1, v2Code: String? = nil) {
        self.message = message
        self.exitCode = exitCode
        self.v2Code = v2Code
    }

    var description: String { message }
}

struct WindowInfo {
    let index: Int
    let id: String
    let key: Bool
    let selectedWorkspaceId: String?
    let workspaceCount: Int
}

struct NotificationInfo {
    let id: String
    let workspaceId: String
    let surfaceId: String?
    let isRead: Bool
    let title: String
    let subtitle: String
    let body: String
    let createdAt: String?
    let tabTitle: String?
}

struct ClaudeHookParsedInput {
    let rawObject: [String: Any]?
    let object: [String: Any]?
    let rawFallback: String?
    let sessionId: String?
    let turnId: String?
    let cwd: String?
    let transcriptPath: String?
}

enum AgentHookRuntimeStatus: String, Codable {
    case running
    case idle
    case needsInput
    case error
}

#if DEBUG
private func agentHookDebugLog(
    _ message: @autoclosure () -> String,
    socketPath: String? = nil,
    env: [String: String] = ProcessInfo.processInfo.environment
) {
    let logPath = agentHookDebugLogPath(socketPath: socketPath, env: env)
    let timestamp = String(format: "%.3f", Date().timeIntervalSince1970)
    let line = "\(timestamp) \(message())\n"
    guard let data = line.data(using: .utf8) else { return }

    if let handle = FileHandle(forWritingAtPath: logPath) {
        defer { try? handle.close() }
        guard (try? handle.seekToEnd()) != nil else { return }
        try? handle.write(contentsOf: data)
    } else {
        FileManager.default.createFile(atPath: logPath, contents: data)
    }
}

private func agentHookDebugLogPath(socketPath: String?, env: [String: String]) -> String {
    if let explicit = agentHookDebugNonEmpty(env["CMUX_DEBUG_LOG"]) {
        return NSString(string: explicit).expandingTildeInPath
    }

    if let socketPath {
        let socketName = URL(fileURLWithPath: socketPath).lastPathComponent
        if socketName.hasPrefix("cmux-debug-"), socketName.hasSuffix(".sock") {
            let logName = String(socketName.dropLast(".sock".count)) + ".log"
            return URL(fileURLWithPath: "/tmp", isDirectory: true)
                .appendingPathComponent(logName, isDirectory: false)
                .path
        }
    }

    if let lastPath = try? String(contentsOfFile: "/tmp/cmux-last-debug-log-path", encoding: .utf8),
       let normalized = agentHookDebugNonEmpty(lastPath) {
        return NSString(string: normalized).expandingTildeInPath
    }

    return "/tmp/cmux-debug.log"
}

private func agentHookDebugNonEmpty(_ value: String?) -> String? {
    guard let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines),
          !trimmed.isEmpty else {
        return nil
    }
    return trimmed
}

private func agentHookDebugShort(_ value: String?) -> String {
    guard let value = agentHookDebugNonEmpty(value) else { return "nil" }
    return String(value.prefix(12))
}

private func agentHookDebugSocketName(_ socketPath: String?) -> String {
    guard let socketPath = agentHookDebugNonEmpty(socketPath) else { return "nil" }
    return URL(fileURLWithPath: socketPath).lastPathComponent
}
#endif

struct ClaudeHookSessionRecord: Codable {
    var sessionId: String
    var workspaceId: String
    var surfaceId: String
    var cwd: String?
    var transcriptPath: String?
    var pid: Int?
    var launchCommand: AgentHookLaunchCommandRecord?
    /// Last hook-observed `permission_mode`, re-applied as `--permission-mode`
    /// on user-owned session restore (https://github.com/manaflow-ai/cmux/issues/8066).
    var lastPermissionMode: String?
    var isRestorable: Bool?
    var agentLifecycle: AgentHibernationLifecycleState?
    var lastSubtitle: String?
    var lastBody: String?
    var lastNotificationStatus: AgentHookNotificationStatus?
    var lastEmittedNotificationFingerprint: String?
    var lastEmittedNotificationAt: TimeInterval?
    var recentEmittedNotificationFingerprints: [String: TimeInterval]?
    var runtimeStatus: AgentHookRuntimeStatus?
    var activePromptDepth: Int?
    var activePromptTurnId: String?
    var activePromptTurnIds: [String]?
    var lastPromptTurnId: String?
    var terminalPromptTurnIds: [String]?
    var startedAt: TimeInterval
    var updatedAt: TimeInterval
    // Auto-naming engine state (all optional so stores written before the
    // feature decode unchanged). The durable baseline advances only after a
    // confirmed title apply; the in-flight marker dedupes concurrent Stops.
    var autoNameLastTitle: String?
    var autoNameLastLineCount: Int?
    var autoNameLastNamedAt: TimeInterval?
    var autoNameInFlightAt: TimeInterval?
    /// Wall-clock of the last summarization attempt (success OR failure), so a
    /// persistently failing summarizer (rate-limited, signed out, timing out)
    /// gets the same minInterval cooldown instead of respawning every turn.
    var autoNameLastAttemptAt: TimeInterval?
    var autoNameRecentMessages: [AutoNamingTranscriptMessage]?
    var autoNameMessageSequence: Int?
    /// Whether the most recent Stop reported unfinished background work
    /// (a running `background_tasks` entry or a pending `session_crons`).
    /// Cached here because the ~60s-later `idle_prompt` Notification payload
    /// does not carry `background_tasks`, so the idle-reminder gate reads this.
    /// Optional so stores written before this field decode unchanged.
    var hadPendingBackgroundWorkAtStop: Bool?
}

struct ClaudeHookActiveSessionRecord: Codable {
    var sessionId: String
    var turnId: String?
    var allowsNewSessionReplacement: Bool?
    var updatedAt: TimeInterval
}

struct AgentHookLaunchCommandRecord: Codable {
    var launcher: String?
    var executablePath: String?
    var arguments: [String]
    var workingDirectory: String?
    var environment: [String: String]?
    var capturedAt: TimeInterval?
    var source: String?
}

private struct CodexMonitorLeaseRecord: Codable {
    var leaseId: String
    var sessionId: String
    var turnId: String?
    var workspaceId: String
    var surfaceId: String?
    var createdAt: TimeInterval
    var retiredAt: TimeInterval?
}

struct ClaudeHookSessionStoreFile: Codable {
    var version: Int = 1
    var sessions: [String: ClaudeHookSessionRecord] = [:]
    var activeSessionsByWorkspace: [String: ClaudeHookActiveSessionRecord] = [:]
    // The pane-scoped active boundary. The workspace slot only remembers ONE
    // active session, so once another pane promotes (e.g. a forked conversation
    // in a split), it can no longer prove that a late hook from a superseded
    // session in this pane is stale. Keyed by surface id.
    // https://github.com/manaflow-ai/cmux/issues/5908
    var activeSessionsBySurface: [String: ClaudeHookActiveSessionRecord] = [:]

    enum CodingKeys: String, CodingKey {
        case version
        case sessions
        case activeSessionsByWorkspace
        case activeSessionsBySurface
    }

    init() {}

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        version = try container.decodeIfPresent(Int.self, forKey: .version) ?? 1
        sessions = try container.decodeIfPresent([String: ClaudeHookSessionRecord].self, forKey: .sessions) ?? [:]
        activeSessionsByWorkspace = try container.decodeIfPresent(
            [String: ClaudeHookActiveSessionRecord].self,
            forKey: .activeSessionsByWorkspace
        ) ?? [:]
        activeSessionsBySurface = try container.decodeIfPresent(
            [String: ClaudeHookActiveSessionRecord].self,
            forKey: .activeSessionsBySurface
        ) ?? [:]
    }
}

final class ClaudeHookSessionStore {
    private static let defaultStatePath = "~/.cmuxterm/claude-hook-sessions.json"
    private static let maxStateAgeSeconds: TimeInterval = 60 * 60 * 24 * 7
    private static let maxRememberedTerminalPromptTurnIds = 32
    private static let maxAutoNameRecentMessages = 24
    private static let maxAutoNameMessageCharacters = 1_000

    private let statePath: String
    private let fileManager: FileManager
    private let decoder = JSONDecoder()
    private let encoder = JSONEncoder()

    init(
        processEnv: [String: String] = ProcessInfo.processInfo.environment,
        fileManager: FileManager = .default
    ) {
        if let overridePath = processEnv["CMUX_CLAUDE_HOOK_STATE_PATH"]?.trimmingCharacters(in: .whitespacesAndNewlines),
           !overridePath.isEmpty {
            self.statePath = NSString(string: overridePath).expandingTildeInPath
        } else if let overrideDirectory = processEnv["CMUX_AGENT_HOOK_STATE_DIR"]?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !overrideDirectory.isEmpty {
            self.statePath = URL(fileURLWithPath: NSString(string: overrideDirectory).expandingTildeInPath, isDirectory: true)
                .appendingPathComponent("claude-hook-sessions.json", isDirectory: false)
                .path
        } else {
            self.statePath = NSString(string: Self.defaultStatePath).expandingTildeInPath
        }
        self.fileManager = fileManager
        self.encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
    }

    func lookup(sessionId: String) throws -> ClaudeHookSessionRecord? {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return nil }
        return try withLockedState { state in
            state.sessions[normalized]
        }
    }

    /// Records the hook-observed permission mode on an existing session record.
    /// The already-current check happens INSIDE the lock: an unlocked pre-check
    /// can race an overlapping hook's write and skip persisting the newest mode,
    /// leaving restore on a stale (possibly more permissive) mode. Unknown
    /// sessions are left alone (the session-start upsert owns record creation).
    func updateLastPermissionMode(sessionId: String, permissionMode: String) throws {
        let normalized = normalizeSessionId(sessionId)
        let mode = permissionMode.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalized.isEmpty, !mode.isEmpty else { return }
        try withLockedState { state in
            guard var record = state.sessions[normalized],
                  record.lastPermissionMode != mode else { return }
            record.lastPermissionMode = mode
            state.sessions[normalized] = record
        }
    }

    struct AutoNamingRecentMessagesSnapshot {
        var messages: [AutoNamingTranscriptMessage]
        var totalMessageCount: Int
    }

    func autoNamingRecentMessages(sessionId: String) throws -> [AutoNamingTranscriptMessage] {
        try autoNamingRecentMessagesSnapshot(sessionId: sessionId).messages
    }

    func autoNamingRecentMessagesSnapshot(sessionId: String) throws -> AutoNamingRecentMessagesSnapshot {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else {
            return AutoNamingRecentMessagesSnapshot(messages: [], totalMessageCount: 0)
        }
        return try withLockedState { state in
            let record = state.sessions[normalized]
            let messages = record?.autoNameRecentMessages ?? []
            return AutoNamingRecentMessagesSnapshot(
                messages: messages,
                totalMessageCount: max(messages.count, record?.autoNameMessageSequence ?? 0)
            )
        }
    }

    struct AutoNamingBeginOutcome {
        var decision: AutoNamingThrottleDecision
        var lastTitle: String?
    }

    /// Atomically evaluates the auto-naming throttle for a session and, when
    /// the decision is to proceed, records the in-flight marker inside the
    /// same locked transaction so a concurrent Stop hook sees it and skips.
    /// When no session record exists yet (the auto-name hook can race the
    /// sync Stop hook's upsert), a minimal record is synthesized so the
    /// marker and baseline writes are never silently dropped.
    func beginAutoNaming(
        sessionId: String,
        workspaceId: String,
        surfaceId: String,
        transcriptLineCount: Int,
        now: Date,
        engine: AutoNamingEngine
    ) throws -> AutoNamingBeginOutcome {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else {
            return AutoNamingBeginOutcome(decision: .skipShortTranscript, lastTitle: nil)
        }
        return try withLockedState { state in
            var record = state.sessions[normalized] ?? ClaudeHookSessionRecord(
                sessionId: normalized,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                startedAt: now.timeIntervalSince1970,
                updatedAt: now.timeIntervalSince1970
            )
            let snapshot = AutoNamingSessionSnapshot(
                lastTitle: record.autoNameLastTitle,
                lastLineCount: record.autoNameLastLineCount,
                lastNamedAt: record.autoNameLastNamedAt,
                inFlightAt: record.autoNameInFlightAt,
                lastAttemptAt: record.autoNameLastAttemptAt
            )
            let decision = engine.throttleDecision(
                snapshot: snapshot,
                transcriptLineCount: transcriptLineCount,
                now: now
            )
            switch decision {
            case .proceed:
                record.autoNameInFlightAt = now.timeIntervalSince1970
            case .reseedBaseline(let to):
                record.autoNameLastLineCount = to
            case .skipShortTranscript, .skipInFlight, .skipTooSoon, .skipInsufficientGrowth:
                break
            }
            record.updatedAt = Date().timeIntervalSince1970
            state.sessions[normalized] = record
            return AutoNamingBeginOutcome(decision: decision, lastTitle: snapshot.lastTitle)
        }
    }

    /// Records a completed naming pass. On a confirmed apply, the durable
    /// baseline (title, line count, timestamp) advances; on failure only the
    /// in-flight marker clears, so the next qualifying Stop retries.
    func finishAutoNaming(
        sessionId: String,
        appliedTitle: String?,
        baselineLineCount: Int?,
        now: Date
    ) throws {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return }
        try withLockedState { state in
            guard var record = state.sessions[normalized] else { return }
            record.autoNameInFlightAt = nil
            // Stamp every completed pass (success or failure) so the throttle
            // enforces a cooldown before retrying a failing summarizer.
            record.autoNameLastAttemptAt = now.timeIntervalSince1970
            if let appliedTitle, let baselineLineCount {
                record.autoNameLastTitle = appliedTitle
                record.autoNameLastLineCount = baselineLineCount
                record.autoNameLastNamedAt = now.timeIntervalSince1970
            }
            record.updatedAt = Date().timeIntervalSince1970
            state.sessions[normalized] = record
        }
    }

    func clearAgentLifecycleIfPresent(
        sessionId: String,
        workspaceId: String?,
        surfaceId: String?
    ) throws {
        let normalizedSessionId = normalizeSessionId(sessionId)
        guard !normalizedSessionId.isEmpty else { return }
        try withLockedState { state in
            guard var record = state.sessions[normalizedSessionId] else { return }
            record.agentLifecycle = .unknown
            record.updatedAt = Date().timeIntervalSince1970
            state.sessions[normalizedSessionId] = record
        }
    }

    @discardableResult
    func recordPromptSubmit(
        sessionId: String,
        workspaceId: String,
        surfaceId: String,
        cwd: String?,
        transcriptPath: String? = nil,
        turnId: String? = nil,
        previousActivePromptTurnIsTerminal: Bool = false,
        terminalActivePromptTurnIds: Set<String> = [],
        pid: Int?,
        launchCommand: AgentHookLaunchCommandRecord?,
        agentLifecycle: AgentHibernationLifecycleState? = nil,
        runtimeStatus: AgentHookRuntimeStatus? = nil,
        updateRuntimeStatus: Bool = false,
        autoNameMessages: [AutoNamingTranscriptMessage] = [],
        rejectTerminalTurn: Bool = false
    ) throws -> (staleTerminalTurn: Bool, nested: Bool) {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return (staleTerminalTurn: false, nested: false) }
        return try withLockedState { state in
            let now = Date().timeIntervalSince1970
            var record = makeSessionRecord(
                state: state,
                sessionId: normalized,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                now: now
            )
            let normalizedTurnId = normalizeOptional(turnId)
            if rejectTerminalTurn,
               let normalizedTurnId,
               terminalPromptTurnSet(from: record).contains(normalizedTurnId) {
                return (staleTerminalTurn: true, nested: false)
            }
            update(
                &record,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                cwd: cwd,
                transcriptPath: transcriptPath,
                pid: pid,
                launchCommand: launchCommand,
                isRestorable: nil,
                agentLifecycle: agentLifecycle,
                lastSubtitle: nil,
                lastBody: nil,
                lastNotificationStatus: nil,
                updateLastNotificationStatus: false,
                runtimeStatus: runtimeStatus,
                updateRuntimeStatus: updateRuntimeStatus,
                now: now
            )
            appendAutoNameMessages(autoNameMessages, to: &record)
            if let normalizedTurnId {
                markPromptTurnActive(normalizedTurnId, on: &record)
                var turnStack = activePromptTurnStack(from: record)
                let legacyDepth = max(0, record.activePromptDepth ?? 0)
                if turnStack.isEmpty, legacyDepth > 0 {
                    record.activePromptDepth = legacyDepth + 1
                    record.activePromptTurnId = nil
                    record.activePromptTurnIds = nil
                    record.lastPromptTurnId = normalizedTurnId
                    state.sessions[normalized] = record
                    return (staleTerminalTurn: false, nested: true)
                } else if let activeTurnId = turnStack.last,
                          activeTurnId != normalizedTurnId {
                    var removedTurnCount = 0
                    var removedTerminalTurnIds: [String] = []
                    if previousActivePromptTurnIsTerminal {
                        removedTerminalTurnIds.append(turnStack.removeLast())
                        removedTurnCount += 1
                        while let activeTurnId = turnStack.last,
                              terminalActivePromptTurnIds.contains(activeTurnId) {
                            removedTerminalTurnIds.append(turnStack.removeLast())
                            removedTurnCount += 1
                        }
                    }
                    let totalDepth = max(0, max(legacyDepth, turnStack.count + removedTurnCount) - removedTurnCount) + 1
                    turnStack.append(normalizedTurnId)
                    setActivePromptTurnStack(turnStack, totalDepth: totalDepth, on: &record)
                    markPromptTurnsTerminal(removedTerminalTurnIds, on: &record)
                    record.lastPromptTurnId = normalizedTurnId
                    state.sessions[normalized] = record
                    return (staleTerminalTurn: false, nested: totalDepth > 1)
                }
                if turnStack.last == normalizedTurnId {
                    let totalDepth = max(legacyDepth, turnStack.count)
                    setActivePromptTurnStack(turnStack, totalDepth: totalDepth, on: &record)
                    record.lastPromptTurnId = normalizedTurnId
                    state.sessions[normalized] = record
                    return (staleTerminalTurn: false, nested: totalDepth > 1)
                }
                let totalDepth = max(legacyDepth, turnStack.count) + 1
                turnStack.append(normalizedTurnId)
                setActivePromptTurnStack(turnStack, totalDepth: totalDepth, on: &record)
                record.lastPromptTurnId = normalizedTurnId
                state.sessions[normalized] = record
                return (staleTerminalTurn: false, nested: totalDepth > 1)
            }
            let existingTurnStackDepth = activePromptTurnStack(from: record).count
            record.activePromptDepth = max(max(0, record.activePromptDepth ?? 0), existingTurnStackDepth) + 1
            state.sessions[normalized] = record
            return (staleTerminalTurn: false, nested: (record.activePromptDepth ?? 0) > 1)
        }
    }

    @discardableResult
    func recordPromptStop(
        sessionId: String,
        workspaceId: String,
        surfaceId: String,
        cwd: String?,
        transcriptPath: String? = nil,
        turnId: String? = nil,
        terminalActivePromptTurnIds: Set<String> = [],
        pid: Int?,
        launchCommand: AgentHookLaunchCommandRecord?,
        agentLifecycle: AgentHibernationLifecycleState? = nil,
        lastSubtitle: String?,
        lastBody: String?,
        lastNotificationStatus: AgentHookNotificationStatus? = nil,
        updateLastNotificationStatus: Bool = false,
        runtimeStatus: AgentHookRuntimeStatus? = nil,
        updateRuntimeStatus: Bool = false,
        autoNameMessages: [AutoNamingTranscriptMessage] = []
    ) throws -> Bool {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return false }
        return try withLockedState { state in
            let now = Date().timeIntervalSince1970
            var record = makeSessionRecord(
                state: state,
                sessionId: normalized,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                now: now
            )
            let depthBeforeStop = max(0, record.activePromptDepth ?? 0)
            let depthAfterStop = max(0, depthBeforeStop - 1)
            update(
                &record,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                cwd: cwd,
                transcriptPath: transcriptPath,
                pid: pid,
                launchCommand: launchCommand,
                isRestorable: nil,
                agentLifecycle: depthAfterStop == 0 ? agentLifecycle : .running,
                lastSubtitle: lastSubtitle,
                lastBody: lastBody,
                lastNotificationStatus: lastNotificationStatus,
                updateLastNotificationStatus: updateLastNotificationStatus,
                runtimeStatus: runtimeStatus,
                updateRuntimeStatus: updateRuntimeStatus,
                now: now
            )
            appendAutoNameMessages(autoNameMessages, to: &record)
            let normalizedTurnId = normalizeOptional(turnId)
            if let normalizedTurnId {
                var turnStack = activePromptTurnStack(from: record)
                var totalDepthBeforeStop = max(depthBeforeStop, turnStack.count)
                let terminalTurnIdsToPrune = terminalActivePromptTurnIds.subtracting([normalizedTurnId])
                if !terminalTurnIdsToPrune.isEmpty {
                    var removedTerminalTurnIds: [String] = []
                    turnStack.removeAll { activeTurnId in
                        if terminalTurnIdsToPrune.contains(activeTurnId) {
                            removedTerminalTurnIds.append(activeTurnId)
                            return true
                        }
                        return false
                    }
                    if !removedTerminalTurnIds.isEmpty {
                        totalDepthBeforeStop = max(0, totalDepthBeforeStop - removedTerminalTurnIds.count)
                        setActivePromptTurnStack(turnStack, totalDepth: totalDepthBeforeStop, on: &record)
                        markPromptTurnsTerminal(removedTerminalTurnIds, on: &record)
                    }
                }
                if let lastTurnId = turnStack.last {
                    if lastTurnId == normalizedTurnId {
                        let nested = totalDepthBeforeStop > 1
                        turnStack.removeLast()
                        setActivePromptTurnStack(
                            turnStack,
                            totalDepth: max(0, totalDepthBeforeStop - 1),
                            on: &record
                        )
                        markPromptTurnTerminal(normalizedTurnId, on: &record)
                        state.sessions[normalized] = record
                        return nested
                    }
                    if let staleIndex = turnStack.lastIndex(of: normalizedTurnId) {
                        turnStack.remove(at: staleIndex)
                        setActivePromptTurnStack(
                            turnStack,
                            totalDepth: max(0, totalDepthBeforeStop - 1),
                            on: &record
                        )
                        markPromptTurnTerminal(normalizedTurnId, on: &record)
                    } else if depthBeforeStop > turnStack.count {
                        setActivePromptTurnStack(
                            turnStack,
                            totalDepth: max(0, totalDepthBeforeStop - 1),
                            on: &record
                        )
                        markPromptTurnTerminal(normalizedTurnId, on: &record)
                    }
                    state.sessions[normalized] = record
                    return true
                }
                if totalDepthBeforeStop == 0, terminalPromptTurnSet(from: record).contains(normalizedTurnId) {
                    state.sessions[normalized] = record
                    return true
                }
                markPromptTurnTerminal(normalizedTurnId, on: &record)
                if totalDepthBeforeStop == 0 {
                    state.sessions[normalized] = record
                    return false
                }
                let depthAfterTurnStop = max(0, totalDepthBeforeStop - 1)
                if depthAfterTurnStop == 0 {
                    record.activePromptDepth = nil
                } else {
                    record.activePromptDepth = depthAfterTurnStop
                }
                record.activePromptTurnId = nil
                record.activePromptTurnIds = nil
                state.sessions[normalized] = record
                return totalDepthBeforeStop > 1
            }
            if depthAfterStop == 0 {
                record.activePromptDepth = nil
                record.activePromptTurnId = nil
                record.activePromptTurnIds = nil
            } else {
                let turnStack = activePromptTurnStack(from: record)
                if !turnStack.isEmpty {
                    setActivePromptTurnStack(
                        Array(turnStack.prefix(depthAfterStop)),
                        totalDepth: depthAfterStop,
                        on: &record
                    )
                } else {
                    record.activePromptDepth = depthAfterStop
                }
                if let normalizedTurnId, turnStack.isEmpty {
                    record.activePromptTurnId = normalizedTurnId
                    record.activePromptTurnIds = Array(repeating: normalizedTurnId, count: depthAfterStop)
                }
            }
            state.sessions[normalized] = record
            return depthBeforeStop > 1
        }
    }

    func upsert(
        sessionId: String,
        workspaceId: String,
        surfaceId: String,
        cwd: String?,
        transcriptPath: String? = nil,
        pid: Int? = nil,
        launchCommand: AgentHookLaunchCommandRecord? = nil,
        isRestorable: Bool? = nil,
        agentLifecycle: AgentHibernationLifecycleState? = nil,
        lastSubtitle: String? = nil,
        lastBody: String? = nil,
        lastNotificationStatus: AgentHookNotificationStatus? = nil,
        updateLastNotificationStatus: Bool = false,
        runtimeStatus: AgentHookRuntimeStatus? = nil,
        updateRuntimeStatus: Bool = false,
        hadPendingBackgroundWorkAtStop: Bool? = nil,
        markActive: Bool = false,
        turnId: String? = nil,
        allowsNewSessionReplacement: Bool = false
    ) throws {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return }
        try withLockedState { state in
            let now = Date().timeIntervalSince1970
            var record = state.sessions[normalized] ?? ClaudeHookSessionRecord(
                sessionId: normalized,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                cwd: nil,
                transcriptPath: nil,
                pid: nil,
                launchCommand: nil,
                isRestorable: nil,
                agentLifecycle: nil,
                lastSubtitle: nil,
                lastBody: nil,
                lastNotificationStatus: nil,
                lastEmittedNotificationFingerprint: nil,
                lastEmittedNotificationAt: nil,
                runtimeStatus: nil,
                activePromptDepth: nil,
                activePromptTurnId: nil,
                activePromptTurnIds: nil,
                lastPromptTurnId: nil,
                terminalPromptTurnIds: nil,
                startedAt: now,
                updatedAt: now
            )
            update(
                &record,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                cwd: cwd,
                transcriptPath: transcriptPath,
                pid: pid,
                launchCommand: launchCommand,
                isRestorable: isRestorable,
                agentLifecycle: agentLifecycle,
                lastSubtitle: lastSubtitle,
                lastBody: lastBody,
                lastNotificationStatus: lastNotificationStatus,
                updateLastNotificationStatus: updateLastNotificationStatus,
                runtimeStatus: runtimeStatus,
                updateRuntimeStatus: updateRuntimeStatus,
                hadPendingBackgroundWorkAtStop: hadPendingBackgroundWorkAtStop,
                now: now
            )
            state.sessions[normalized] = record
            if markActive {
                let activeRecord = ClaudeHookActiveSessionRecord(
                    sessionId: normalized,
                    turnId: normalizeOptional(turnId),
                    allowsNewSessionReplacement: allowsNewSessionReplacement ? true : nil,
                    updatedAt: now
                )
                if let normalizedWorkspace = normalizeOptional(workspaceId) {
                    state.activeSessionsByWorkspace[normalizedWorkspace] = activeRecord
                }
                if let normalizedSurface = normalizeOptional(surfaceId) {
                    state.activeSessionsBySurface[normalizedSurface] = activeRecord
                }
            }
        }
    }

    @discardableResult
    func upsertCodexSessionStartIfFresh(
        sessionId: String,
        workspaceId: String,
        surfaceId: String,
        cwd: String?,
        transcriptPath: String? = nil,
        pid: Int? = nil,
        launchCommand: AgentHookLaunchCommandRecord? = nil,
        agentLifecycle: AgentHibernationLifecycleState? = nil,
        runtimeStatus: AgentHookRuntimeStatus? = nil,
        updateRuntimeStatus: Bool = false
    ) throws -> Bool {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return false }
        return try withLockedState { state in
            let now = Date().timeIntervalSince1970
            var record = makeSessionRecord(
                state: state,
                sessionId: normalized,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                now: now
            )
            if codexSessionStartIsStale(record, incomingPID: pid) {
                return false
            }
            clearCodexSessionStartTurnState(on: &record)
            update(
                &record,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                cwd: cwd,
                transcriptPath: transcriptPath,
                pid: pid,
                launchCommand: launchCommand,
                isRestorable: nil,
                agentLifecycle: agentLifecycle,
                lastSubtitle: nil,
                lastBody: nil,
                lastNotificationStatus: nil,
                updateLastNotificationStatus: false,
                runtimeStatus: runtimeStatus,
                updateRuntimeStatus: updateRuntimeStatus,
                now: now
            )
            state.sessions[normalized] = record
            return true
        }
    }

    @discardableResult
    func upsertCodexPromptRunningIfFresh(
        sessionId: String,
        workspaceId: String,
        surfaceId: String,
        cwd: String?,
        transcriptPath: String? = nil,
        turnId: String? = nil,
        pid: Int? = nil,
        launchCommand: AgentHookLaunchCommandRecord? = nil
    ) throws -> Bool {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return false }
        return try withLockedState { state in
            let now = Date().timeIntervalSince1970
            var record = makeSessionRecord(
                state: state,
                sessionId: normalized,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                now: now
            )
            if let normalizedTurnId = normalizeOptional(turnId),
               terminalPromptTurnSet(from: record).contains(normalizedTurnId) {
                return false
            }
            update(
                &record,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                cwd: cwd,
                transcriptPath: transcriptPath,
                pid: pid,
                launchCommand: launchCommand,
                isRestorable: nil,
                agentLifecycle: .running,
                lastSubtitle: nil,
                lastBody: nil,
                lastNotificationStatus: nil,
                updateLastNotificationStatus: false,
                runtimeStatus: .running,
                updateRuntimeStatus: true,
                now: now
            )
            state.sessions[normalized] = record
            return true
        }
    }

    func codexSessionStartIsStale(
        sessionId: String,
        incomingPID: Int?,
        includeTerminalPromptTurnIds: Bool = true
    ) throws -> Bool {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return false }
        return try withLockedState { state in
            guard let record = state.sessions[normalized] else { return false }
            return codexSessionStartIsStale(
                record,
                incomingPID: incomingPID,
                includeTerminalPromptTurnIds: includeTerminalPromptTurnIds
            )
        }
    }

    func codexPromptTurnIsTerminal(sessionId: String, turnId: String?) throws -> Bool {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty, let normalizedTurnId = normalizeOptional(turnId) else { return false }
        return try withLockedState { state in
            guard let record = state.sessions[normalized] else { return false }
            return terminalPromptTurnSet(from: record).contains(normalizedTurnId)
        }
    }

    func markNotificationResolved(
        sessionId: String,
        workspaceId: String,
        surfaceId: String,
        cwd: String?,
        transcriptPath: String? = nil,
        pid: Int? = nil,
        launchCommand: AgentHookLaunchCommandRecord? = nil,
        agentLifecycle: AgentHibernationLifecycleState? = nil,
        runtimeStatus: AgentHookRuntimeStatus? = nil
    ) throws {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return }
        try withLockedState { state in
            let now = Date().timeIntervalSince1970
            var record = makeSessionRecord(
                state: state,
                sessionId: normalized,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                now: now
            )
            update(
                &record,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                cwd: cwd,
                transcriptPath: transcriptPath,
                pid: pid,
                launchCommand: launchCommand,
                isRestorable: nil,
                agentLifecycle: agentLifecycle,
                lastSubtitle: nil,
                lastBody: nil,
                lastNotificationStatus: nil,
                updateLastNotificationStatus: true,
                runtimeStatus: runtimeStatus,
                updateRuntimeStatus: runtimeStatus != nil,
                now: now
            )
            record.lastSubtitle = nil
            record.lastBody = nil
            record.lastNotificationStatus = nil
            state.sessions[normalized] = record
        }
    }

    private func makeSessionRecord(
        state: ClaudeHookSessionStoreFile,
        sessionId: String,
        workspaceId: String,
        surfaceId: String,
        now: TimeInterval
    ) -> ClaudeHookSessionRecord {
        state.sessions[sessionId] ?? ClaudeHookSessionRecord(
            sessionId: sessionId,
            workspaceId: workspaceId,
            surfaceId: surfaceId,
            cwd: nil,
            transcriptPath: nil,
            pid: nil,
            launchCommand: nil,
            isRestorable: nil,
            agentLifecycle: nil,
            lastSubtitle: nil,
            lastBody: nil,
            lastNotificationStatus: nil,
            lastEmittedNotificationFingerprint: nil,
            lastEmittedNotificationAt: nil,
            runtimeStatus: nil,
            activePromptDepth: nil,
            activePromptTurnId: nil,
            activePromptTurnIds: nil,
            lastPromptTurnId: nil,
            terminalPromptTurnIds: nil,
            startedAt: now,
            updatedAt: now
        )
    }

    private func activePromptTurnStack(from record: ClaudeHookSessionRecord) -> [String] {
        if let activePromptTurnIds = record.activePromptTurnIds {
            let normalized = activePromptTurnIds.compactMap { normalizeOptional($0) }
            if !normalized.isEmpty {
                return normalized
            }
        }
        if let activePromptTurnId = normalizeOptional(record.activePromptTurnId) {
            return [activePromptTurnId]
        }
        return []
    }

    private func setActivePromptTurnStack(_ stack: [String], totalDepth: Int? = nil, on record: inout ClaudeHookSessionRecord) {
        let normalizedStack = stack.compactMap { normalizeOptional($0) }
        let resolvedDepth = max(max(0, totalDepth ?? normalizedStack.count), normalizedStack.count)
        if resolvedDepth == 0 {
            record.activePromptDepth = nil
            record.activePromptTurnId = nil
            record.activePromptTurnIds = nil
        } else {
            record.activePromptDepth = resolvedDepth
            record.activePromptTurnId = normalizedStack.last
            record.activePromptTurnIds = normalizedStack.isEmpty ? nil : normalizedStack
        }
    }

    private func terminalPromptTurnStack(from record: ClaudeHookSessionRecord) -> [String] {
        record.terminalPromptTurnIds?.compactMap { normalizeOptional($0) } ?? []
    }

    private func terminalPromptTurnSet(from record: ClaudeHookSessionRecord) -> Set<String> {
        Set(terminalPromptTurnStack(from: record))
    }

    private func codexSessionStartIsStale(
        _ record: ClaudeHookSessionRecord,
        incomingPID: Int?,
        includeTerminalPromptTurnIds: Bool = true
    ) -> Bool {
        if max(record.activePromptDepth ?? 0, record.activePromptTurnIds?.count ?? 0) > 0 {
            return true
        }
        let hasCompletedTurnState = normalizeOptional(record.lastPromptTurnId) != nil
            || (includeTerminalPromptTurnIds && !terminalPromptTurnSet(from: record).isEmpty)
        guard hasCompletedTurnState,
              let incomingPID,
              let existingPID = record.pid else {
            return false
        }
        return incomingPID == existingPID
    }

    private func clearCodexSessionStartTurnState(on record: inout ClaudeHookSessionRecord) {
        record.activePromptDepth = nil
        record.activePromptTurnId = nil
        record.activePromptTurnIds = nil
        record.lastPromptTurnId = nil
    }

    private func markPromptTurnActive(_ turnId: String, on record: inout ClaudeHookSessionRecord) {
        var terminalTurnIds = terminalPromptTurnStack(from: record)
        terminalTurnIds.removeAll { $0 == turnId }
        record.terminalPromptTurnIds = terminalTurnIds.isEmpty ? nil : terminalTurnIds
    }

    private func markPromptTurnsTerminal(_ turnIds: [String], on record: inout ClaudeHookSessionRecord) {
        for turnId in turnIds {
            markPromptTurnTerminal(turnId, on: &record)
        }
    }

    private func markPromptTurnTerminal(_ turnId: String, on record: inout ClaudeHookSessionRecord) {
        guard let normalizedTurnId = normalizeOptional(turnId) else { return }
        var terminalTurnIds = terminalPromptTurnStack(from: record)
        terminalTurnIds.removeAll { $0 == normalizedTurnId }
        terminalTurnIds.append(normalizedTurnId)
        if terminalTurnIds.count > Self.maxRememberedTerminalPromptTurnIds {
            terminalTurnIds.removeFirst(terminalTurnIds.count - Self.maxRememberedTerminalPromptTurnIds)
        }
        record.lastPromptTurnId = normalizedTurnId
        record.terminalPromptTurnIds = terminalTurnIds.isEmpty ? nil : terminalTurnIds
    }

    private func appendAutoNameMessages(
        _ messages: [AutoNamingTranscriptMessage],
        to record: inout ClaudeHookSessionRecord
    ) {
        guard !messages.isEmpty else { return }
        var recent = record.autoNameRecentMessages ?? []
        var appendedCount = 0
        for message in messages {
            guard let normalized = normalizedAutoNameMessage(message) else { continue }
            if recent.last == normalized { continue }
            recent.append(normalized)
            appendedCount += 1
        }
        if recent.count > Self.maxAutoNameRecentMessages {
            recent.removeFirst(recent.count - Self.maxAutoNameRecentMessages)
        }
        record.autoNameRecentMessages = recent.isEmpty ? nil : recent
        if appendedCount > 0 {
            record.autoNameMessageSequence = (record.autoNameMessageSequence ?? 0) + appendedCount
        }
    }

    private func normalizedAutoNameMessage(_ message: AutoNamingTranscriptMessage) -> AutoNamingTranscriptMessage? {
        let role = message.role.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        guard role == "user" || role == "assistant" else { return nil }
        let text = autoNameNormalizedSingleLine(message.text)
        guard !text.isEmpty else { return nil }
        return AutoNamingTranscriptMessage(
            role: role,
            text: autoNameTruncate(text, maxLength: Self.maxAutoNameMessageCharacters)
        )
    }

    private func autoNameNormalizedSingleLine(_ value: String) -> String {
        let collapsed = value.replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
        return collapsed.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func autoNameTruncate(_ value: String, maxLength: Int) -> String {
        guard value.count > maxLength else { return value }
        let index = value.index(value.startIndex, offsetBy: max(0, maxLength - 1))
        return String(value[..<index]) + "…"
    }

    private func update(
        _ record: inout ClaudeHookSessionRecord,
        workspaceId: String,
        surfaceId: String,
        cwd: String?,
        transcriptPath: String?,
        pid: Int?,
        launchCommand: AgentHookLaunchCommandRecord?,
        isRestorable: Bool?,
        agentLifecycle: AgentHibernationLifecycleState?,
        lastSubtitle: String?,
        lastBody: String?,
        lastNotificationStatus: AgentHookNotificationStatus?,
        updateLastNotificationStatus: Bool,
        runtimeStatus: AgentHookRuntimeStatus?,
        updateRuntimeStatus: Bool,
        hadPendingBackgroundWorkAtStop: Bool? = nil,
        now: TimeInterval
    ) {
        record.workspaceId = workspaceId
        if !surfaceId.isEmpty {
            record.surfaceId = surfaceId
        }
        if let cwd = normalizeOptional(cwd) {
            record.cwd = cwd
        }
        if let transcriptPath = normalizeOptional(transcriptPath) {
            record.transcriptPath = transcriptPath
        }
        if let pid {
            record.pid = pid
        }
        if let launchCommand {
            let existingHasArguments = !(record.launchCommand?.arguments.isEmpty ?? true)
            let incomingHasArguments = !launchCommand.arguments.isEmpty
            let incomingHasEnvironment = !(launchCommand.environment?.isEmpty ?? true)
            // Persist an argv-bearing record always. Persist an argv-less, env-only record (the
            // CODEX_HOME / CLAUDE_CONFIG_DIR fallback for a plain agent whose launch argv couldn't be
            // captured) only when we don't already hold an argv-bearing one — so the durable store
            // keeps the non-default home for the fork/resume path without ever downgrading a richer
            // earlier capture to an env-only stub.
            if incomingHasArguments || normalizeOptional(launchCommand.source)?.lowercased() == "rejected" || (normalizeOptional(launchCommand.source)?.lowercased() == "default" && !existingHasArguments && normalizeOptional(record.launchCommand?.environment?["CODEX_HOME"]) == nil) || (incomingHasEnvironment && !existingHasArguments) {
                record.launchCommand = launchCommand
            }
        }
        if let isRestorable {
            // Preserve sticky true: a later isRestorable=false must not clear
            // record.isRestorable=true from a transcript-backed event.
            record.isRestorable = isRestorable || record.isRestorable == true
        }
        if let agentLifecycle {
            record.agentLifecycle = agentLifecycle
        }
        if let subtitle = normalizeOptional(lastSubtitle) {
            record.lastSubtitle = subtitle
        }
        if let body = normalizeOptional(lastBody) {
            record.lastBody = body
        }
        if updateLastNotificationStatus {
            record.lastNotificationStatus = lastNotificationStatus
        }
        if updateRuntimeStatus {
            record.runtimeStatus = runtimeStatus
        }
        if let hadPendingBackgroundWorkAtStop {
            record.hadPendingBackgroundWorkAtStop = hadPendingBackgroundWorkAtStop
        }
        record.updatedAt = now
    }

    func clearNotificationEmission(sessionId: String) throws {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return }
        try withLockedState { state in
            guard var record = state.sessions[normalized] else { return }
            let now = Date().timeIntervalSince1970
            record.lastEmittedNotificationFingerprint = nil
            record.lastEmittedNotificationAt = nil
            record.recentEmittedNotificationFingerprints = nil
            record.updatedAt = now
            state.sessions[normalized] = record
        }
    }

    func recentlyEmittedNotification(
        sessionId: String,
        fingerprint: String,
        within interval: TimeInterval = 60 * 60
    ) throws -> Bool {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return false }
        let normalizedFingerprint = fingerprint.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedFingerprint.isEmpty else { return false }
        return try withLockedState { state in
            guard let record = state.sessions[normalized] else { return false }
            let now = Date().timeIntervalSince1970
            if let emittedAt = record.recentEmittedNotificationFingerprints?[normalizedFingerprint],
               now - emittedAt <= interval {
                return true
            }
            guard record.lastEmittedNotificationFingerprint == normalizedFingerprint,
                  let emittedAt = record.lastEmittedNotificationAt else {
                return false
            }
            return now - emittedAt <= interval
        }
    }

    func markNotificationEmitted(sessionId: String, fingerprint: String) throws {
        let normalized = normalizeSessionId(sessionId)
        guard !normalized.isEmpty else { return }
        let normalizedFingerprint = fingerprint.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedFingerprint.isEmpty else { return }
        try withLockedState { state in
            guard var record = state.sessions[normalized] else { return }
            let now = Date().timeIntervalSince1970
            record.lastEmittedNotificationFingerprint = normalizedFingerprint
            record.lastEmittedNotificationAt = now
            var recent = record.recentEmittedNotificationFingerprints ?? [:]
            recent[normalizedFingerprint] = now
            recent = recent.filter { now - $0.value <= 60 * 60 }
            if recent.count > 16 {
                let keep = recent.sorted { lhs, rhs in
                    if lhs.value == rhs.value { return lhs.key < rhs.key }
                    return lhs.value > rhs.value
                }.prefix(16)
                recent = Dictionary(uniqueKeysWithValues: keep.map { ($0.key, $0.value) })
            }
            record.recentEmittedNotificationFingerprints = recent.isEmpty ? nil : recent
            record.updatedAt = now
            state.sessions[normalized] = record
        }
    }

    func hasRunningSession(
        workspaceId: String,
        surfaceId: String?,
        excludingSessionId: String?,
        onlyNewerThanExcludedSession: Bool = false,
        requireLiveProcess: Bool = false
    ) throws -> Bool {
        guard let normalizedWorkspace = normalizeOptional(workspaceId) else {
            return false
        }
        let normalizedSurface = normalizeOptional(surfaceId)
        let excluded = normalizeOptional(excludingSessionId)
        return try withLockedState { state in
            let excludedUpdatedAt = excluded.flatMap { state.sessions[$0]?.updatedAt }
            var foundRunningSession = false
            let now = Date().timeIntervalSince1970

            for sessionId in Array(state.sessions.keys) {
                guard var record = state.sessions[sessionId] else { continue }
                guard normalizeOptional(record.workspaceId) == normalizedWorkspace,
                      record.sessionId != excluded,
                      record.runtimeStatus == .running else {
                    continue
                }
                if let normalizedSurface, normalizeOptional(record.surfaceId) != normalizedSurface {
                    continue
                }
                if onlyNewerThanExcludedSession, let excludedUpdatedAt {
                    guard record.updatedAt > excludedUpdatedAt else {
                        continue
                    }
                }

                if requireLiveProcess, !Self.processExists(record.pid) {
                    record.runtimeStatus = nil
                    record.updatedAt = now
                    state.sessions[sessionId] = record
                    continue
                }

                foundRunningSession = true
                break
            }

            return foundRunningSession
        }
    }

    private static func processExists(_ pid: Int?) -> Bool {
        guard let pid, pid > 0 else { return false }
        if kill(pid_t(pid), 0) == 0 {
            return true
        }
        return errno == EPERM
    }

    /// Returns true when an event belongs to the workspace's active Claude session.
    /// It fails open when the event cannot identify a session/workspace, when no
    /// active session is registered yet, or when either side lacks a turnId so
    /// multi-turn continuations can proceed after Stop clears the active turn.
    func isCurrent(
        sessionId: String?,
        workspaceId: String,
        surfaceId: String? = nil,
        turnId: String? = nil
    ) throws -> Bool {
        guard let normalizedSessionId = normalizeOptional(sessionId),
              let normalizedWorkspace = normalizeOptional(workspaceId) else {
            return true
        }
        return try withLockedState { state in
            // The pane's own active boundary decides first: a hook is stale when a
            // DIFFERENT session was promoted in the SAME surface (post-/clear or
            // replaced-session races in one pane). This stays true even after a
            // sibling pane — e.g. a forked conversation in a split — later takes
            // the single workspace-active slot.
            // https://github.com/manaflow-ai/cmux/issues/5908
            if let normalizedSurfaceId = normalizeOptional(surfaceId),
               let surfaceActive = state.activeSessionsBySurface[normalizedSurfaceId] {
                guard surfaceActive.sessionId == normalizedSessionId else {
                    return false
                }
                guard let activeTurnId = normalizeOptional(surfaceActive.turnId),
                      let normalizedTurnId = normalizeOptional(turnId) else {
                    return true
                }
                return activeTurnId == normalizedTurnId
            }
            guard let active = state.activeSessionsByWorkspace[normalizedWorkspace] else {
                return true
            }
            guard active.sessionId == normalizedSessionId else {
                // Legacy fallback for stores written before per-surface tracking:
                // a different active session only makes this hook stale when that
                // session lives in the SAME surface; concurrent sessions in
                // sibling panes stay current for their own surface.
                guard let normalizedSurfaceId = normalizeOptional(surfaceId),
                      let activeRecord = state.sessions[active.sessionId],
                      let activeSurfaceId = normalizeOptional(activeRecord.surfaceId) else {
                    // Cross-surface protection needs both surfaces; when the caller
                    // omits surfaceId or the active session's record is gone/surface-
                    // less, fall back to the stricter workspace-scoped staleness.
                    return false
                }
                return activeSurfaceId != normalizedSurfaceId
            }
            guard let activeTurnId = normalizeOptional(active.turnId),
                  let normalizedTurnId = normalizeOptional(turnId) else {
                return true
            }
            return activeTurnId == normalizedTurnId
        }
    }

    func canReplaceActiveSession(
        sessionId: String?,
        workspaceId: String,
        surfaceId: String? = nil
    ) throws -> Bool {
        guard let normalizedSessionId = normalizeOptional(sessionId),
              let normalizedWorkspace = normalizeOptional(workspaceId) else {
            return false
        }
        return try withLockedState { state in
            // Replacement is pane-scoped like staleness: a stopped session in
            // THIS surface allows its own pane to start a new session even when
            // another pane currently holds the workspace-active slot.
            // https://github.com/manaflow-ai/cmux/issues/5908
            if let normalizedSurfaceId = normalizeOptional(surfaceId),
               let surfaceActive = state.activeSessionsBySurface[normalizedSurfaceId] {
                guard surfaceActive.sessionId != normalizedSessionId else {
                    return false
                }
                return surfaceActive.allowsNewSessionReplacement == true
            }
            guard let active = state.activeSessionsByWorkspace[normalizedWorkspace],
                  active.sessionId != normalizedSessionId else {
                return false
            }
            return active.allowsNewSessionReplacement == true
        }
    }

    func consume(
        sessionId: String?,
        workspaceId: String?,
        surfaceId: String?,
        turnId: String? = nil
    ) throws -> ClaudeHookSessionRecord? {
        let normalizedSessionId = normalizeOptional(sessionId)
        let normalizedWorkspace = normalizeOptional(workspaceId)
        let normalizedSurface = normalizeOptional(surfaceId)
        return try withLockedState { state in
            if let normalizedSessionId,
               let existing = state.sessions[normalizedSessionId] {
                guard !hasActiveTurnMismatch(state, record: existing, turnId: turnId) else {
                    return nil
                }
                let removed = state.sessions.removeValue(forKey: normalizedSessionId) ?? existing
                clearActiveSessionIfMatching(&state, removed: removed, turnId: turnId)
                return removed
            }

            guard let fallback = fallbackRecord(
                sessions: Array(state.sessions.values),
                workspaceId: normalizedWorkspace,
                surfaceId: normalizedSurface
            ) else {
                return nil
            }
            guard !hasActiveTurnMismatch(state, record: fallback, turnId: turnId) else {
                return nil
            }
            state.sessions.removeValue(forKey: fallback.sessionId)
            clearActiveSessionIfMatching(&state, removed: fallback, turnId: turnId)
            return fallback
        }
    }

    private func hasActiveTurnMismatch(
        _ state: ClaudeHookSessionStoreFile,
        record: ClaudeHookSessionRecord,
        turnId: String?
    ) -> Bool {
        guard let incomingTurnId = normalizeOptional(turnId) else {
            return false
        }
        // Consult the pane-scoped slot alongside the workspace slot: once a
        // sibling pane takes the single workspace-active slot, only the
        // surface slot still proves that this session is mid-turn in its own
        // pane and a stale SessionEnd from an older turn must not consume it.
        // https://github.com/manaflow-ai/cmux/issues/5908
        var activeRecords: [ClaudeHookActiveSessionRecord] = []
        if let workspaceId = normalizeOptional(record.workspaceId),
           let active = state.activeSessionsByWorkspace[workspaceId] {
            activeRecords.append(active)
        }
        if let surfaceId = normalizeOptional(record.surfaceId),
           let active = state.activeSessionsBySurface[surfaceId] {
            activeRecords.append(active)
        }
        return activeRecords.contains { active in
            guard active.sessionId == record.sessionId,
                  let activeTurnId = normalizeOptional(active.turnId) else {
                return false
            }
            return activeTurnId != incomingTurnId
        }
    }

    private func clearActiveSessionIfMatching(
        _ state: inout ClaudeHookSessionStoreFile,
        removed: ClaudeHookSessionRecord,
        turnId: String?
    ) {
        let incomingTurnId = normalizeOptional(turnId)
        func matches(_ active: ClaudeHookActiveSessionRecord) -> Bool {
            guard active.sessionId == removed.sessionId else { return false }
            if let activeTurnId = normalizeOptional(active.turnId),
               let incomingTurnId,
               activeTurnId != incomingTurnId {
                return false
            }
            return true
        }
        if let workspaceId = normalizeOptional(removed.workspaceId),
           let active = state.activeSessionsByWorkspace[workspaceId],
           matches(active) {
            state.activeSessionsByWorkspace.removeValue(forKey: workspaceId)
        }
        for (surfaceId, active) in state.activeSessionsBySurface where matches(active) {
            state.activeSessionsBySurface.removeValue(forKey: surfaceId)
        }
    }

    private func fallbackRecord(
        sessions: [ClaudeHookSessionRecord],
        workspaceId: String?,
        surfaceId: String?
    ) -> ClaudeHookSessionRecord? {
        if let surfaceId {
            let matches = sessions.filter { $0.surfaceId == surfaceId }
            return matches.max(by: { $0.updatedAt < $1.updatedAt })
        }
        if let workspaceId {
            let matches = sessions.filter { $0.workspaceId == workspaceId }
            if matches.count == 1 {
                return matches[0]
            }
        }
        return nil
    }

    private func withLockedState<T>(_ body: (inout ClaudeHookSessionStoreFile) throws -> T) throws -> T {
        let lockPath = statePath + ".lock"
        let fd = open(lockPath, O_CREAT | O_RDWR, mode_t(S_IRUSR | S_IWUSR))
        if fd < 0 {
            throw CLIError(message: "Failed to open Claude hook state lock: \(lockPath)")
        }
        defer { Darwin.close(fd) }

        if flock(fd, LOCK_EX) != 0 {
            throw CLIError(message: "Failed to lock Claude hook state: \(lockPath)")
        }
        defer { _ = flock(fd, LOCK_UN) }

        var state = loadUnlocked()
        pruneExpired(&state)
        let result = try body(&state)
        try saveUnlocked(state)
        return result
    }

    private func loadUnlocked() -> ClaudeHookSessionStoreFile {
        guard fileManager.fileExists(atPath: statePath) else {
            return ClaudeHookSessionStoreFile()
        }
        guard let data = try? Data(contentsOf: URL(fileURLWithPath: statePath)),
              var decoded = try? decoder.decode(ClaudeHookSessionStoreFile.self, from: data) else {
            return ClaudeHookSessionStoreFile()
        }
        backfillSurfaceActiveSlots(&decoded)
        return decoded
    }

    /// Stores written before per-surface tracking (or rewritten by an older
    /// CLI, which drops the unknown key) carry only workspace-active slots.
    /// Rebuild the pane boundary from each workspace-active session's recorded
    /// surface so pre-upgrade panes keep suppressing stale hooks after a
    /// sibling pane takes the workspace slot.
    /// https://github.com/manaflow-ai/cmux/issues/5908
    private func backfillSurfaceActiveSlots(_ state: inout ClaudeHookSessionStoreFile) {
        guard state.activeSessionsBySurface.isEmpty else { return }
        for active in state.activeSessionsByWorkspace.values {
            guard let surfaceId = normalizeOptional(state.sessions[active.sessionId]?.surfaceId) else {
                continue
            }
            state.activeSessionsBySurface[surfaceId] = active
        }
    }

    private func saveUnlocked(_ state: ClaudeHookSessionStoreFile) throws {
        let stateURL = URL(fileURLWithPath: statePath)
        let parentURL = stateURL.deletingLastPathComponent()
        try fileManager.createDirectory(
            at: parentURL,
            withIntermediateDirectories: true,
            attributes: [.posixPermissions: NSNumber(value: Int16(0o700))]
        )
        try? fileManager.setAttributes([.posixPermissions: NSNumber(value: Int16(0o700))], ofItemAtPath: parentURL.path)
        let data = try encoder.encode(state)
        let tempURL = parentURL.appendingPathComponent(".\(stateURL.lastPathComponent).\(UUID().uuidString).tmp")
        guard fileManager.createFile(atPath: tempURL.path, contents: data, attributes: [
            .posixPermissions: NSNumber(value: Int16(0o600))
        ]) else {
            throw CocoaError(.fileWriteUnknown, userInfo: [NSFilePathErrorKey: statePath])
        }
        let renameResult = tempURL.path.withCString { source in
            stateURL.path.withCString { destination in
                Darwin.rename(source, destination)
            }
        }
        if renameResult != 0 {
            let code = POSIXErrorCode(rawValue: errno) ?? .EIO
            try? fileManager.removeItem(at: tempURL)
            throw POSIXError(code)
        }
        try? fileManager.setAttributes([.posixPermissions: NSNumber(value: Int16(0o600))], ofItemAtPath: stateURL.path)
    }

    private func pruneExpired(_ state: inout ClaudeHookSessionStoreFile) {
        let now = Date().timeIntervalSince1970
        let cutoff = now - Self.maxStateAgeSeconds
        state.sessions = state.sessions.filter { _, record in
            record.updatedAt >= cutoff
        }
        state.activeSessionsByWorkspace = state.activeSessionsByWorkspace.filter { workspaceId, active in
            guard active.updatedAt >= cutoff, let record = state.sessions[active.sessionId] else { return false }
            // Self-heal cross-workspace/pane pollution: a session may only be active
            // for its own recorded workspace (and surface, below). Stale focused/TTY
            // misroutes from older builds could register a session as active for an
            // unrelated tab or pane, stealing its notifications (isCurrent trusts the
            // surface slot first) and suppressing that pane's own session.
            return normalizeOptional(record.workspaceId) == workspaceId
        }
        state.activeSessionsBySurface = state.activeSessionsBySurface.filter { surfaceId, active in
            active.updatedAt >= cutoff && normalizeOptional(state.sessions[active.sessionId]?.surfaceId) == surfaceId
        }
    }

    private func normalizeSessionId(_ value: String) -> String {
        value.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func normalizeOptional(_ value: String?) -> String? {
        guard let value = value?.trimmingCharacters(in: .whitespacesAndNewlines), !value.isEmpty else {
            return nil
        }
        return value
    }
}

private let agentHookWrapperProcessNames: Set<String> = [
    "sh",
    "bash",
    "zsh",
    "env"
]

private let suppressSubagentNotificationsDefaultsKey = "suppressSubagentNotifications"
private let suppressSubagentNotificationsEnvironmentKey = "CMUX_SUPPRESS_SUBAGENT_NOTIFICATIONS"
private let managedSubagentEnvironmentKey = "CMUX_AGENT_MANAGED_SUBAGENT"
private let codexTeamsThreadEnvironmentKey = "CMUX_CODEX_TEAMS_THREAD_ID"
private let codexTeamsParentThreadEnvironmentKey = "CMUX_CODEX_TEAMS_PARENT_THREAD_ID"
private let codexTeamsDepthEnvironmentKey = "CMUX_CODEX_TEAMS_DEPTH"

enum CLIIDFormat: String {
    case refs
    case uuids
    case both

    static func parse(_ raw: String?) throws -> CLIIDFormat? {
        guard let raw else { return nil }
        guard let parsed = CLIIDFormat(rawValue: raw.lowercased()) else {
            throw CLIError(message: "--id-format must be one of: refs, uuids, both")
        }
        return parsed
    }
}

private enum TopSortKey: Equatable {
    case cpu
    case memory
    case proc
}

private enum TopTextFormat: Equatable {
    case tree
    case tsv
}

enum SocketPasswordResolver {
    private static let service = "com.cmuxterm.app.socket-control"
    private static let account = "local-socket-password"

    static func resolve(explicit: String?, socketPath: String) -> String? {
        if let explicit = normalized(explicit) {
            return explicit
        }
        if let env = normalized(ProcessInfo.processInfo.environment["CMUX_SOCKET_PASSWORD"]) {
            return env
        }
        if let filePassword = loadFromFile() {
            return filePassword
        }
        return loadFromKeychain(socketPath: socketPath)
    }

    private static func normalized(_ value: String?) -> String? {
        guard let value else { return nil }
        let trimmed = value.trimmingCharacters(in: .newlines)
        return trimmed.isEmpty ? nil : trimmed
    }

    private static func loadFromFile() -> String? {
        // Resolve through the shared store so the CLI reads the exact path the app
        // writes — the non-TCC cmux state directory, not Application Support
        // (https://github.com/manaflow-ai/cmux/issues/5146). The CLI is a
        // composition root, so it names the concrete `FileManager.default` here.
        guard let passwordURL = SocketControlPasswordStore.defaultPasswordFileURL(fileManager: .default) else {
            return nil
        }
        guard let data = try? Data(contentsOf: passwordURL) else {
            return nil
        }
        guard let value = String(data: data, encoding: .utf8) else {
            return nil
        }
        return normalized(value)
    }

    static func keychainServices(
        socketPath: String,
        environment: [String: String] = ProcessInfo.processInfo.environment
    ) -> [String] {
        guard let scope = keychainScope(socketPath: socketPath, environment: environment) else {
            return [service]
        }
        return ["\(service).\(scope)", service]
    }

    private static func keychainScope(
        socketPath: String,
        environment: [String: String] = ProcessInfo.processInfo.environment
    ) -> String? {
        if let tag = normalized(environment["CMUX_TAG"]) {
            let scoped = sanitizeScope(tag)
            if !scoped.isEmpty {
                return scoped
            }
        }

        let candidate = URL(fileURLWithPath: socketPath).lastPathComponent
        let prefixes = ["cmux-debug-", "cmux-"]
        for prefix in prefixes {
            guard candidate.hasPrefix(prefix), candidate.hasSuffix(".sock") else { continue }
            let start = candidate.index(candidate.startIndex, offsetBy: prefix.count)
            let end = candidate.index(candidate.endIndex, offsetBy: -".sock".count)
            guard start < end else { continue }
            let rawScope = String(candidate[start..<end])
            let scoped = sanitizeScope(rawScope)
            if !scoped.isEmpty {
                return scoped
            }
        }
        return nil
    }

    private static func sanitizeScope(_ raw: String) -> String {
        let lowered = raw.lowercased()
        let allowed = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: ".-"))
        let mappedScalars = lowered.unicodeScalars.map { scalar -> Character in
            allowed.contains(scalar) ? Character(scalar) : "."
        }
        var normalizedScope = String(mappedScalars)
        normalizedScope = normalizedScope.replacingOccurrences(
            of: "\\.+",
            with: ".",
            options: .regularExpression
        )
        normalizedScope = normalizedScope.trimmingCharacters(in: CharacterSet(charactersIn: "."))
        return normalizedScope
    }

    private static func loadFromKeychain(socketPath: String) -> String? {
        for service in keychainServices(socketPath: socketPath) {
            let authContext = LAContext()
            authContext.interactionNotAllowed = true
            let query: [String: Any] = [
                kSecClass as String: kSecClassGenericPassword,
                kSecAttrService as String: service,
                kSecAttrAccount as String: account,
                kSecReturnData as String: true,
                kSecMatchLimit as String: kSecMatchLimitOne,
                // Never trigger keychain UI from CLI commands; fail fast instead.
                kSecUseAuthenticationContext as String: authContext,
            ]
            var result: CFTypeRef?
            let status = SecItemCopyMatching(query as CFDictionary, &result)
            if status == errSecItemNotFound || status == errSecInteractionNotAllowed || status == errSecAuthFailed {
                continue
            }
            guard status == errSecSuccess else {
                continue
            }
            guard let data = result as? Data,
                  let password = String(data: data, encoding: .utf8) else {
                continue
            }
            return password
        }
        return nil
    }
}

final class SocketClient {
    private struct RelayEndpoint {
        let host: String
        let port: UInt16
    }

    private struct SocketConnectError: Error, CustomStringConvertible {
        let path: String
        let errnoValue: Int32

        var description: String {
            "Failed to connect to socket at \(path) (\(String(cString: strerror(errnoValue))), errno \(errnoValue))"
        }
    }

    private struct RelayCredentials {
        let relayID: String
        let relayToken: Data
    }

    private let path: String
    private var socketFD: Int32 = -1
    private var lastConfiguredReceiveTimeout: TimeInterval?
    private var lastOperationTelemetry: CLISocketOperationTelemetry.State?
    private static let defaultResponseTimeoutSeconds: TimeInterval = 15.0
    private static let multilineResponseIdleTimeoutSeconds: TimeInterval = 0.12
    private static let maxSocketTimeoutSeconds: TimeInterval = 9_007_199_254_740_991
    private static let connectRetryDeadline: TimeInterval = 0.35
    private static let connectRetryIntervalMicros: useconds_t = 25_000
    private static let responseTimeoutSeconds: TimeInterval = {
        let env = ProcessInfo.processInfo.environment
        if let raw = env["CMUXTERM_CLI_RESPONSE_TIMEOUT_SEC"],
           let seconds = Double(raw),
           seconds.isFinite,
           seconds > 0 {
            return seconds
        }
        return defaultResponseTimeoutSeconds
    }()

    private static func isCompleteSingleLineResponse(_ data: Data) -> Bool {
        guard data.contains(UInt8(0x0A)),
              let response = String(data: data, encoding: .utf8) else {
            return false
        }
        let normalized = response.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalized.isEmpty, !normalized.contains("\n") else {
            return false
        }

        if normalized == "OK" ||
            normalized == "PONG" ||
            normalized.hasPrefix("OK ") ||
            normalized.hasPrefix("ERROR:") {
            return true
        }

        if let jsonData = normalized.data(using: .utf8), (try? JSONSerialization.jsonObject(with: jsonData, options: [.fragmentsAllowed])) != nil {
            return true
        }

        return false
    }

    init(path: String) {
        self.path = path
    }

    var socketPath: String {
        path
    }

    var isRelayBacked: Bool {
        relayEndpoint != nil
    }

    func connectionAppearsOpen() -> Bool {
        if relayEndpoint != nil, socketFD < 0 {
            do {
                try connect()
            } catch {
                return false
            }
        }
        guard socketFD >= 0 else { return false }
        while true {
            var descriptor = pollfd(
                fd: socketFD,
                events: Int16(POLLIN | POLLHUP | POLLERR),
                revents: 0
            )
            let ready = Darwin.poll(&descriptor, 1, 0)
            if ready < 0 {
                if errno == EINTR { continue }
                return false
            }
            let terminalEvents = Int16(POLLHUP | POLLERR | POLLNVAL)
            return descriptor.revents & terminalEvents == 0
        }
    }

    func operationTelemetryContext() -> [String: Any] {
        lastOperationTelemetry?.context() ?? [:]
    }

    func hasUnfinishedOperationTelemetry() -> Bool { lastOperationTelemetry.map { $0.phase != .completed } ?? false }

    private var relayEndpoint: RelayEndpoint? {
        Self.parseRelayEndpoint(path)
    }

    private static func trimmedEnvValue(_ value: String?) -> String? {
        guard let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines),
              !trimmed.isEmpty else {
            return nil
        }
        return trimmed
    }

    private static func socketTimeval(for timeout: TimeInterval) -> timeval {
        let sanitizedTimeout = timeout.isFinite ? timeout : defaultResponseTimeoutSeconds
        let clampedTimeout = min(max(sanitizedTimeout, 0.01), maxSocketTimeoutSeconds)
        let seconds = floor(clampedTimeout)
        let microseconds = min(
            max(Int((clampedTimeout - seconds) * 1_000_000), 0),
            999_999
        )
        return timeval(
            tv_sec: Int(seconds),
            tv_usec: __darwin_suseconds_t(microseconds)
        )
    }

    private func recordOperation(_ operation: CLISocketOperationTelemetry.State) {
        lastOperationTelemetry = operation
    }

    func connect() throws {
        if socketFD >= 0 { return }
        let deadline = Date().addingTimeInterval(Self.connectRetryDeadline)
        while true {
            do {
                try connectOnce()
                return
            } catch {
                guard Self.shouldRetryConnect(error), Date() < deadline else {
                    throw error
                }
                usleep(Self.connectRetryIntervalMicros)
            }
        }
    }

    func connectWithoutRetry(responseTimeout: TimeInterval? = nil) throws {
        if socketFD >= 0 { return }
        try connectOnce(responseTimeout: responseTimeout)
    }

    func close() {
        if socketFD >= 0 {
            Darwin.close(socketFD)
            socketFD = -1
        }
        lastConfiguredReceiveTimeout = nil
    }

    func send(command: String, responseTimeout: TimeInterval? = nil) throws -> String {
        if relayEndpoint != nil, socketFD < 0 {
            try connect()
        }
        guard socketFD >= 0 else { throw CLIError(message: "Not connected") }
        let shouldCloseAfterSend = relayEndpoint != nil
        defer {
            if shouldCloseAfterSend {
                close()
            }
        }

        let initialResponseTimeout = responseTimeout ?? Self.responseTimeoutSeconds
        if lastConfiguredReceiveTimeout != initialResponseTimeout {
            try configureReceiveTimeout(initialResponseTimeout)
        }
        _ = try? configureSocketWriteSafety(initialResponseTimeout)
        var operation = CLISocketOperationTelemetry.State(
            name: CLISocketOperationTelemetry.operationName(for: command),
            timeout: initialResponseTimeout,
            startedAt: Date(),
            phase: .writeRequest
        )
        recordOperation(operation)

        let payload = capabilityWrappedCommand(command) + "\n"
        try writeAll(
            Data(payload.utf8),
            timeoutMessage: "Command timed out",
            failureMessage: "Failed to write to socket"
        )

        var data = Data()
        var sawNewline = false
        var receivedCompleteResponse = false

        while true {
            let currentTimeout = sawNewline ? Self.multilineResponseIdleTimeoutSeconds : initialResponseTimeout
            operation.phase = sawNewline ? .readMultilineResponse : .waitForResponse
            operation.sawNewline = sawNewline
            operation.timeout = currentTimeout
            recordOperation(operation)
            if lastConfiguredReceiveTimeout != currentTimeout {
                try configureReceiveTimeout(currentTimeout)
            }

            var buffer = [UInt8](repeating: 0, count: 8192)
            let count = Darwin.read(socketFD, &buffer, buffer.count)
            if count < 0 {
                if errno == EINTR {
                    continue
                }
                if errno == EAGAIN || errno == EWOULDBLOCK {
                    if sawNewline {
                        receivedCompleteResponse = true
                        break
                    }
                    throw CLIError(message: "Command timed out")
                }
                throw CLIError(message: "Socket read error")
            }
            if count == 0 {
                operation.sawNewline = sawNewline
                recordOperation(operation)
                if data.isEmpty {
                    throw CLIError(message: "Socket closed before reply")
                }
                if !sawNewline {
                    throw CLIError(message: "Socket closed before complete reply")
                }
                receivedCompleteResponse = true
                break
            }
            data.append(buffer, count: count)
            operation.bytesRead += count
            if data.contains(UInt8(0x0A)) {
                sawNewline = true
                if Self.isCompleteSingleLineResponse(data) {
                    receivedCompleteResponse = true
                    break
                }
            }
        }

        operation.sawNewline = sawNewline
        if receivedCompleteResponse {
            operation.phase = .completed
        }
        recordOperation(operation)

        guard var response = String(data: data, encoding: .utf8) else {
            throw CLIError(message: "Invalid UTF-8 response")
        }
        if response.hasSuffix("\n") {
            response.removeLast()
        }
        return response
    }

    func sendOneWay(command: String, writeTimeout: TimeInterval) throws {
        if relayEndpoint != nil, socketFD < 0 {
            try connect()
        }
        guard socketFD >= 0 else { throw CLIError(message: "Not connected") }
        let shouldCloseAfterSend = relayEndpoint != nil

        try configureSocketWriteSafety(writeTimeout)
        var operation = CLISocketOperationTelemetry.State(
            name: CLISocketOperationTelemetry.operationName(for: command),
            timeout: writeTimeout,
            startedAt: Date(),
            phase: .writeRequest
        )
        recordOperation(operation)

        do {
            try writeAllNonBlocking(
                Data((capabilityWrappedCommand(command) + "\n").utf8),
                deadline: Date().addingTimeInterval(writeTimeout),
                timeoutMessage: "Command timed out",
                failureMessage: "Failed to write to socket"
            )
        } catch {
            close()
            throw error
        }
        operation.phase = .completed
        recordOperation(operation)
        if shouldCloseAfterSend {
            close()
        } else {
            if (try? configureSocketWriteSafety(Self.responseTimeoutSeconds)) == nil {
                close()
            }
        }
    }

    private func connectOnce(responseTimeout: TimeInterval? = nil) throws {
        if let relayEndpoint {
            try connectToRelay(endpoint: relayEndpoint, responseTimeout: responseTimeout)
            return
        }

        // Verify socket is owned by the current user to prevent fake-socket attacks.
        var st = stat()
        guard stat(path, &st) == 0 else {
            throw CLIError(message: "Socket not found at \(path)")
        }
        guard (st.st_mode & mode_t(S_IFMT)) == mode_t(S_IFSOCK) else {
            throw CLIError(message: "Path exists at \(path) but is not a Unix socket")
        }
        guard st.st_uid == getuid() else {
            throw CLIError(message: "Socket at \(path) is not owned by the current user — refusing to connect")
        }

        socketFD = socket(AF_UNIX, SOCK_STREAM, 0)
        if socketFD < 0 {
            throw CLIError(message: "Failed to create socket")
        }
        do {
            let timeout = responseTimeout ?? Self.responseTimeoutSeconds
            try configureSocketWriteSafety(timeout)
            try configureReceiveTimeout(timeout)
        } catch {
            close()
            throw error
        }

        var addr = sockaddr_un()
        addr.sun_family = sa_family_t(AF_UNIX)
        let maxLength = MemoryLayout.size(ofValue: addr.sun_path)
        path.withCString { ptr in
            withUnsafeMutablePointer(to: &addr.sun_path) { pathPtr in
                let buf = UnsafeMutableRawPointer(pathPtr).assumingMemoryBound(to: CChar.self)
                strncpy(buf, ptr, maxLength - 1)
            }
        }

        let result = withUnsafePointer(to: &addr) { ptr in
            ptr.withMemoryRebound(to: sockaddr.self, capacity: 1) { sockaddrPtr in
                Darwin.connect(socketFD, sockaddrPtr, socklen_t(MemoryLayout<sockaddr_un>.size))
            }
        }
        if result == 0 {
            return
        }

        let connectErrno = errno
        Darwin.close(socketFD)
        socketFD = -1
        throw SocketConnectError(path: path, errnoValue: connectErrno)
    }

    private static func shouldRetryConnect(_ error: Error) -> Bool {
        guard let error = error as? SocketConnectError else {
            return false
        }
        switch error.errnoValue {
        case ECONNREFUSED, EAGAIN, EWOULDBLOCK:
            return true
        default:
            return false
        }
    }

    private static func parseRelayEndpoint(_ raw: String) -> RelayEndpoint? {
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty,
              !trimmed.hasPrefix("/") else {
            return nil
        }
        let components = trimmed.split(separator: ":", omittingEmptySubsequences: false)
        guard components.count == 2,
              let port = UInt16(components[1]),
              port > 0 else {
            return nil
        }
        let host = String(components[0]).lowercased()
        guard host == "127.0.0.1" || host == "localhost" else {
            return nil
        }
        return RelayEndpoint(host: host == "localhost" ? "127.0.0.1" : host, port: port)
    }

    private static func relayCredentials(for endpoint: RelayEndpoint) throws -> RelayCredentials {
        let environment = ProcessInfo.processInfo.environment
        if let relayID = trimmedEnvValue(environment["CMUX_RELAY_ID"]),
           let relayTokenHex = trimmedEnvValue(environment["CMUX_RELAY_TOKEN"]),
           let relayToken = hexData(from: relayTokenHex) {
            return RelayCredentials(relayID: relayID, relayToken: relayToken)
        }

        let authURL = URL(fileURLWithPath: NSHomeDirectory(), isDirectory: true)
            .appendingPathComponent(".cmux/relay/\(endpoint.port).auth", isDirectory: false)
        guard let authData = try? Data(contentsOf: authURL),
              let authObject = try? JSONSerialization.jsonObject(with: authData) as? [String: Any],
              let relayID = trimmedEnvValue(authObject["relay_id"] as? String),
              let relayTokenHex = trimmedEnvValue(authObject["relay_token"] as? String),
              let relayToken = hexData(from: relayTokenHex) else {
            throw CLIError(message: "Missing relay auth metadata for \(endpoint.host):\(endpoint.port)")
        }

        return RelayCredentials(relayID: relayID, relayToken: relayToken)
    }

    private static func hexData(from string: String) -> Data? {
        let normalized = string.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalized.isEmpty,
              normalized.count.isMultiple(of: 2) else {
            return nil
        }

        var data = Data(capacity: normalized.count / 2)
        var cursor = normalized.startIndex
        while cursor < normalized.endIndex {
            let next = normalized.index(cursor, offsetBy: 2)
            guard let byte = UInt8(normalized[cursor..<next], radix: 16) else {
                return nil
            }
            data.append(byte)
            cursor = next
        }
        return data
    }

    private static func hexString(from data: Data) -> String {
        data.map { String(format: "%02x", $0) }.joined()
    }

    private func connectToRelay(endpoint: RelayEndpoint, responseTimeout: TimeInterval? = nil) throws {
        let credentials = try Self.relayCredentials(for: endpoint)
        let timeout = responseTimeout ?? Self.responseTimeoutSeconds

        socketFD = socket(AF_INET, SOCK_STREAM, 0)
        guard socketFD >= 0 else {
            throw CLIError(message: "Failed to create relay socket")
        }
        do {
            try configureSocketWriteSafety(timeout)
            try configureReceiveTimeout(timeout)
        } catch {
            close()
            throw error
        }

        var address = sockaddr_in()
        address.sin_len = UInt8(MemoryLayout<sockaddr_in>.stride)
        address.sin_family = sa_family_t(AF_INET)
        address.sin_port = endpoint.port.bigEndian
        let parsedAddress = withUnsafeMutablePointer(to: &address.sin_addr) { pointer in
            endpoint.host.withCString { hostPointer in
                inet_pton(AF_INET, hostPointer, pointer)
            }
        }
        guard parsedAddress == 1 else {
            close()
            throw CLIError(message: "Invalid relay endpoint \(endpoint.host):\(endpoint.port)")
        }

        let result = withUnsafePointer(to: &address) { pointer in
            pointer.withMemoryRebound(to: sockaddr.self, capacity: 1) { sockaddrPointer in
                Darwin.connect(socketFD, sockaddrPointer, socklen_t(MemoryLayout<sockaddr_in>.stride))
            }
        }
        if result != 0 {
            let connectErrno = errno
            close()
            throw CLIError(
                message: "Failed to connect to relay at \(endpoint.host):\(endpoint.port) (\(String(cString: strerror(connectErrno))), errno \(connectErrno))"
            )
        }

        do {
            try authenticateRelay(credentials: credentials, responseTimeout: timeout)
        } catch {
            close()
            throw error
        }
    }

    private func authenticateRelay(credentials: RelayCredentials, responseTimeout: TimeInterval) throws {
        let challengeLine = try readLine(responseTimeout: responseTimeout)
        guard let challengeData = challengeLine.data(using: .utf8),
              let challenge = try JSONSerialization.jsonObject(with: challengeData) as? [String: Any],
              (challenge["protocol"] as? String) == "cmux-relay-auth",
              let version = challenge["version"] as? Int,
              let relayID = challenge["relay_id"] as? String,
              relayID == credentials.relayID,
              let nonce = challenge["nonce"] as? String,
              !nonce.isEmpty else {
            throw CLIError(message: "Invalid relay authentication challenge")
        }

        let authMessage = Data("relay_id=\(relayID)\nnonce=\(nonce)\nversion=\(version)".utf8)
        let key = SymmetricKey(data: credentials.relayToken)
        let mac = Data(HMAC<SHA256>.authenticationCode(for: authMessage, using: key))
        let authPayload = try JSONSerialization.data(withJSONObject: [
            "relay_id": relayID,
            "mac": Self.hexString(from: mac),
        ])
        try writeAll(
            authPayload + Data([0x0A]),
            timeoutMessage: "Relay command timed out",
            failureMessage: "Failed to write to relay socket"
        )

        let authResponseLine = try readLine(responseTimeout: responseTimeout)
        guard let authResponseData = authResponseLine.data(using: .utf8),
              let authResponse = try JSONSerialization.jsonObject(with: authResponseData) as? [String: Any],
              (authResponse["ok"] as? Bool) == true else {
            throw CLIError(message: "Relay authentication failed")
        }
    }

    private func writeAll(
        _ data: Data,
        timeoutMessage: String,
        failureMessage: String
    ) throws {
        try data.withUnsafeBytes { rawBuffer in
            guard let baseAddress = rawBuffer.baseAddress?.assumingMemoryBound(to: UInt8.self) else {
                return
            }
            var offset = 0
            while offset < data.count {
                let written = Darwin.write(socketFD, baseAddress.advanced(by: offset), data.count - offset)
                if written < 0 {
                    let errorCode = errno
                    if errorCode == EINTR {
                        continue
                    }
                    close()
                    if errorCode == EAGAIN || errorCode == EWOULDBLOCK || errorCode == ETIMEDOUT {
                        throw CLIError(message: timeoutMessage)
                    }
                    let reason = String(cString: strerror(errorCode))
                    throw CLIError(
                        message: "\(failureMessage) (\(reason), errno \(errorCode))"
                    )
                }
                if written == 0 {
                    close()
                    throw CLIError(message: failureMessage)
                }
                offset += written
            }
        }
    }

    private func writeAllNonBlocking(
        _ data: Data,
        deadline: Date,
        timeoutMessage: String,
        failureMessage: String
    ) throws {
        let originalFlags = fcntl(socketFD, F_GETFL, 0)
        guard originalFlags >= 0 else {
            throw CLIError(message: failureMessage)
        }
        guard fcntl(socketFD, F_SETFL, originalFlags | O_NONBLOCK) == 0 else {
            throw CLIError(message: failureMessage)
        }
        defer {
            if socketFD >= 0 {
                _ = fcntl(socketFD, F_SETFL, originalFlags)
            }
        }

        try data.withUnsafeBytes { rawBuffer in
            guard let baseAddress = rawBuffer.baseAddress?.assumingMemoryBound(to: UInt8.self) else {
                return
            }
            var offset = 0
            while offset < data.count {
                let remaining = deadline.timeIntervalSinceNow
                guard remaining > 0 else {
                    close()
                    throw CLIError(message: timeoutMessage)
                }

                var descriptor = pollfd(fd: socketFD, events: Int16(POLLOUT), revents: 0)
                let timeoutMillis = min(max(Int(ceil(remaining * 1000)), 0), Int(Int32.max))
                let ready = Darwin.poll(&descriptor, 1, Int32(timeoutMillis))
                if ready < 0 {
                    let errorCode = errno
                    if errorCode == EINTR { continue }
                    close()
                    let reason = String(cString: strerror(errorCode))
                    throw CLIError(message: "\(failureMessage) (\(reason), errno \(errorCode))")
                }
                if ready == 0 {
                    close()
                    throw CLIError(message: timeoutMessage)
                }
                let terminalEvents = Int16(POLLHUP | POLLERR | POLLNVAL)
                if descriptor.revents & terminalEvents != 0 {
                    close()
                    throw CLIError(message: failureMessage)
                }
                guard descriptor.revents & Int16(POLLOUT) != 0 else {
                    continue
                }

                let written = Darwin.write(socketFD, baseAddress.advanced(by: offset), data.count - offset)
                if written < 0 {
                    let errorCode = errno
                    if errorCode == EINTR || errorCode == EAGAIN || errorCode == EWOULDBLOCK {
                        continue
                    }
                    close()
                    if errorCode == ETIMEDOUT {
                        throw CLIError(message: timeoutMessage)
                    }
                    let reason = String(cString: strerror(errorCode))
                    throw CLIError(message: "\(failureMessage) (\(reason), errno \(errorCode))")
                }
                if written == 0 {
                    close()
                    throw CLIError(message: failureMessage)
                }
                offset += written
            }
        }
    }

    private func configureSocketWriteSafety(_ timeout: TimeInterval) throws {
        var interval = Self.socketTimeval(for: timeout)
        let sendTimeoutResult = withUnsafePointer(to: &interval) { ptr in
            setsockopt(
                socketFD,
                SOL_SOCKET,
                SO_SNDTIMEO,
                ptr,
                socklen_t(MemoryLayout<timeval>.size)
            )
        }
        guard sendTimeoutResult == 0 else {
            throw CLIError(message: "Failed to configure socket write timeout")
        }

#if os(macOS)
        var noSigPipe: Int32 = 1
        let noSigPipeResult = withUnsafePointer(to: &noSigPipe) { ptr in
            setsockopt(
                socketFD,
                SOL_SOCKET,
                SO_NOSIGPIPE,
                ptr,
                socklen_t(MemoryLayout<Int32>.size)
            )
        }
        guard noSigPipeResult == 0 else {
            throw CLIError(message: "Failed to disable SIGPIPE on socket")
        }
#endif
    }

    private func readLine(maxBytes: Int = 16 * 1024, responseTimeout: TimeInterval? = nil) throws -> String {
        var data = Data()

        while data.count < maxBytes {
            try configureReceiveTimeout(responseTimeout ?? Self.responseTimeoutSeconds)

            var byte: UInt8 = 0
            let count = Darwin.read(socketFD, &byte, 1)
            if count < 0 {
                if errno == EINTR {
                    continue
                }
                if errno == EAGAIN || errno == EWOULDBLOCK {
                    throw CLIError(message: "Relay command timed out")
                }
                throw CLIError(message: "Relay socket read error")
            }
            if count == 0 {
                break
            }
            if byte == 0x0A {
                break
            }
            data.append(byte)
        }

        guard !data.isEmpty else {
            throw CLIError(message: "Unexpected EOF from relay")
        }
        guard let line = String(data: data, encoding: .utf8) else {
            throw CLIError(message: "Invalid UTF-8 relay response")
        }
        return line.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func configureReceiveTimeout(_ timeout: TimeInterval) throws {
        var interval = Self.socketTimeval(for: timeout)
        let result = withUnsafePointer(to: &interval) { ptr in
            setsockopt(
                socketFD,
                SOL_SOCKET,
                SO_RCVTIMEO,
                ptr,
                socklen_t(MemoryLayout<timeval>.size)
            )
        }
        guard result == 0 else {
            let errorCode = errno
            let reason = String(cString: strerror(errorCode))
            throw CLIError(message: "Failed to configure socket receive timeout (\(reason), errno \(errorCode))")
        }
        lastConfiguredReceiveTimeout = timeout
    }

    static func waitForConnectableSocket(path: String, timeout: TimeInterval) throws -> SocketClient {
        let client = SocketClient(path: path)
        if (try? client.connect()) != nil {
            if client.relayEndpoint != nil {
                client.close()
            }
            return client
        }

        guard let watchDirectory = existingWatchDirectory(forPath: path) else {
            throw CLIError(message: "cmux app did not start in time (socket not found at \(path))")
        }
        let watchFD = open(watchDirectory, O_EVTONLY)
        guard watchFD >= 0 else {
            throw CLIError(message: "cmux app did not start in time (socket not found at \(path))")
        }

        let queue = DispatchQueue(label: "com.cmux.cli.socket-watch.\(UUID().uuidString)")
        let semaphore = DispatchSemaphore(value: 0)
        var connected = false
        let source = DispatchSource.makeFileSystemObjectSource(
            fileDescriptor: watchFD,
            eventMask: [.write, .rename, .delete, .attrib, .extend, .link],
            queue: queue
        )

        func attemptConnect() {
            guard !connected else { return }
            if (try? client.connect()) != nil {
                connected = true
                semaphore.signal()
            }
        }

        source.setEventHandler {
            attemptConnect()
        }
        source.setCancelHandler {
            Darwin.close(watchFD)
        }
        source.resume()
        queue.async {
            attemptConnect()
        }

        guard semaphore.wait(timeout: .now() + timeout) == .success else {
            source.cancel()
            client.close()
            throw CLIError(message: "cmux app did not start in time (socket not found at \(path))")
        }

        source.cancel()
        return client
    }

    static func waitForFilesystemPath(_ path: String, timeout: TimeInterval) throws {
        if FileManager.default.fileExists(atPath: path) {
            return
        }

        guard let watchDirectory = existingWatchDirectory(forPath: path) else {
            throw CLIError(message: "Timed out waiting for \(path)")
        }
        let watchFD = open(watchDirectory, O_EVTONLY)
        guard watchFD >= 0 else {
            throw CLIError(message: "Timed out waiting for \(path)")
        }

        let queue = DispatchQueue(label: "com.cmux.cli.path-watch.\(UUID().uuidString)")
        let semaphore = DispatchSemaphore(value: 0)
        var found = false
        let source = DispatchSource.makeFileSystemObjectSource(
            fileDescriptor: watchFD,
            eventMask: [.write, .rename, .delete, .attrib, .extend, .link],
            queue: queue
        )

        func checkPath() {
            guard !found else { return }
            if FileManager.default.fileExists(atPath: path) {
                found = true
                semaphore.signal()
            }
        }

        source.setEventHandler {
            checkPath()
        }
        source.setCancelHandler {
            Darwin.close(watchFD)
        }
        source.resume()
        queue.async {
            checkPath()
        }

        guard semaphore.wait(timeout: .now() + timeout) == .success else {
            source.cancel()
            throw CLIError(message: "Timed out waiting for \(path)")
        }

        source.cancel()
    }

    private static func existingWatchDirectory(forPath path: String) -> String? {
        let fileManager = FileManager.default
        var candidate = URL(fileURLWithPath: (path as NSString).deletingLastPathComponent, isDirectory: true)

        while !candidate.path.isEmpty {
            var isDirectory: ObjCBool = false
            if fileManager.fileExists(atPath: candidate.path, isDirectory: &isDirectory), isDirectory.boolValue {
                return candidate.path
            }
            let parent = candidate.deletingLastPathComponent()
            if parent.path == candidate.path {
                break
            }
            candidate = parent
        }
        return nil
    }

    func sendV2(
        method: String,
        params: [String: Any] = [:],
        responseTimeout: TimeInterval? = nil
    ) throws -> [String: Any] {
        let request: [String: Any] = [
            "id": UUID().uuidString,
            "method": method,
            "params": params
        ]
        guard JSONSerialization.isValidJSONObject(request) else {
            throw CLIError(message: "Failed to encode v2 request")
        }

        let requestData = try JSONSerialization.data(withJSONObject: request, options: [])
        guard let requestLine = String(data: requestData, encoding: .utf8) else {
            throw CLIError(message: "Failed to encode v2 request")
        }

        let raw = try send(command: requestLine, responseTimeout: responseTimeout)

        // The server may return plain-text errors (e.g., "ERROR: Access denied ...")
        // before the JSON protocol starts. Surface these directly instead of letting
        // JSONSerialization throw a confusing parse error.
        if raw.hasPrefix("ERROR:") {
            throw CLIError(message: raw)
        }

        guard let responseData = raw.data(using: .utf8) else {
            throw CLIError(message: "Invalid UTF-8 v2 response")
        }
        guard let response = try JSONSerialization.jsonObject(with: responseData, options: []) as? [String: Any] else {
            throw CLIError(message: "Invalid v2 response: \(raw)")
        }

        if let ok = response["ok"] as? Bool, ok {
            return (response["result"] as? [String: Any]) ?? [:]
        }

        if let error = response["error"] as? [String: Any] {
            let code = (error["code"] as? String) ?? "error"
            let message = (error["message"] as? String) ?? "Unknown v2 error"
            let action = error["action"] as? String
            let reason = error["reason"] as? String
            throw CLIError(
                message: formatV2Error(
                    code: code,
                    message: message,
                    action: action,
                    reason: reason,
                    details: safeV2Details(error["details"])
                ),
                v2Code: error["code"] as? String
            )
        }

        throw CLIError(message: "v2 request failed")
    }

    private func formatV2Error(
        code: String,
        message: String,
        action: String? = nil,
        reason: String? = nil,
        details: String? = nil
    ) -> String {
        let header: String
        if code == "vm_error" {
            header = message
        } else if message.contains("\n") {
            header = "\(code):\n\(message)"
        } else {
            header = "\(code): \(message)"
        }
        var sections = [header]
        if let reason = trimmedNonEmptyV2Text(reason) {
            sections.append("Reason:\n\(indentV2ErrorLines(reason))")
        }
        if let action = trimmedNonEmptyV2Text(action) {
            sections.append("What to do:\n\(indentV2ErrorLines(action))")
        }
        if let details = trimmedNonEmptyV2Text(details) {
            sections.append("Details:\n\(indentV2ErrorLines(details))")
        }
        return sections.joined(separator: "\n\n")
    }

    private func safeV2Details(_ value: Any?) -> String? {
        guard let value else { return nil }
        if let string = value as? String {
            return trimmedNonEmptyV2Text(string)
        }
        if let dictionary = value as? [String: Any] {
            let allowedKeys = Set([
                "amount",
                "code",
                "duration",
                "durationMs",
                "field",
                "idempotencyKeySet",
                "imageRequested",
                "limit",
                "operation",
                "retryable",
                "status",
                "type",
                "vmId",
            ])
            let lines = dictionary.keys.sorted().compactMap { key -> String? in
                guard allowedKeys.contains(key), let value = dictionary[key], !(value is NSNull) else { return nil }
                return "\(key): \(safeV2DetailValue(value))"
            }
            return lines.isEmpty ? nil : lines.joined(separator: "\n")
        }
        return nil
    }

    private func safeV2DetailValue(_ value: Any) -> String {
        if let string = value as? String {
            return string.replacingOccurrences(of: "\n", with: "\\n")
                .replacingOccurrences(of: "\r", with: "\\r")
        }
        if let number = value as? NSNumber {
            if CFGetTypeID(number) == CFBooleanGetTypeID() {
                return number.boolValue ? "true" : "false"
            }
            return "\(number)"
        }
        if value is [String: Any] || value is [Any] {
            return "available"
        }
        return String(describing: value)
            .replacingOccurrences(of: "\n", with: "\\n")
            .replacingOccurrences(of: "\r", with: "\\r")
    }

    private func trimmedNonEmptyV2Text(_ value: String?) -> String? {
        let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed?.isEmpty == false ? trimmed : nil
    }

    private func indentV2ErrorLines(_ value: String) -> String {
        value
            .split(separator: "\n", omittingEmptySubsequences: false)
            .map { "  \($0)" }
            .joined(separator: "\n")
    }

    func streamV2(
        method: String,
        params: [String: Any] = [:],
        onLine: (String) throws -> Void
    ) throws {
        guard socketFD >= 0 else { throw CLIError(message: "Not connected") }
        let request: [String: Any] = [
            "id": UUID().uuidString,
            "method": method,
            "params": params
        ]
        guard JSONSerialization.isValidJSONObject(request),
              let requestData = try? JSONSerialization.data(withJSONObject: request, options: []),
              let requestLine = String(data: requestData, encoding: .utf8) else {
            throw CLIError(message: "Failed to encode v2 stream request")
        }

        try writeAll(
            Data((capabilityWrappedCommand(requestLine) + "\n").utf8),
            timeoutMessage: "Stream request timed out",
            failureMessage: "Failed to write stream request"
        )

        while true {
            let line = try readStreamLine()
            try onLine(line)
        }
    }

    private func readStreamLine(maxBytes: Int = 4 * 1024 * 1024) throws -> String {
        var data = Data()
        try configureReceiveTimeout(45)
        while data.count < maxBytes {
            var byte: UInt8 = 0
            let count = Darwin.read(socketFD, &byte, 1)
            if count < 0 {
                if errno == EINTR {
                    continue
                }
                if errno == EAGAIN || errno == EWOULDBLOCK {
                    throw CLIError(message: "Timed out waiting for event stream frame")
                }
                throw CLIError(message: "Event stream socket read error")
            }
            if count == 0 {
                throw CLIError(message: "Event stream closed")
            }
            if byte == 0x0A {
                guard let line = String(data: data, encoding: .utf8) else {
                    throw CLIError(message: "Invalid UTF-8 event stream frame")
                }
                return line.trimmingCharacters(in: .whitespacesAndNewlines)
            }
            data.append(byte)
        }
        throw CLIError(message: "Event stream frame exceeded \(maxBytes) bytes")
    }
}

struct CMUXCLI {
    let args: [String]
    let initialSIGPIPEInspectionPayload: [String: Any]?

    private static let vmCreateIdempotencyTTLSeconds: TimeInterval = 10 * 60
    private static let vmCreateResponseTimeoutSeconds: TimeInterval = 16 * 60
    private static let vmAttachResponseTimeoutSeconds: TimeInterval = 16 * 60
    // Stable per-user slot for the pinned Cloud VM. This value is intentionally reused as
    // both the backend create idempotency key and the local daemon slot so every open,
    // reconnect, session restore, and mobile attach targets the same provider VM once
    // creation succeeds. Do not rotate it without a migration.
    private static let persistentCloudVMSlotID = "cmux-default-freestyle-sshd-v1"
    private static let persistentCloudVMWorkspaceName = "sshd"
    private static let claudeCodeStatusKey = "claude_code"

    private static var allowedAgentLifecycleStatusKeys: Set<String> {
        var keys = Set(agentDefs.map(\.statusKey))
        keys.formUnion(AgentHibernationLifecycleStatusKeys.allowedStatusKeys)
        keys.insert(claudeCodeStatusKey)
        return keys
    }

    init(args: [String], initialSIGPIPEInspectionPayload: [String: Any]? = nil) {
        self.args = args
        self.initialSIGPIPEInspectionPayload = initialSIGPIPEInspectionPayload
    }

    private func captureSocketTransportError(telemetry: CLISocketSentryTelemetry, stage: String, error: Error, client: SocketClient) {
        if client.hasUnfinishedOperationTelemetry() {
            telemetry.captureError(stage: stage, error: error, data: client.operationTelemetryContext())
        }
    }

    private struct VMCreateIdempotencyStore: Codable {
        var records: [String: VMCreateIdempotencyRecord] = [:]
    }

    private struct VMCreateIdempotencyRecord: Codable {
        let key: String
        let createdAt: TimeInterval
    }

    private struct ActiveVMCreateIdempotency {
        let signature: String
        let key: String
    }

    private static func normalizedEnvValue(_ value: String?) -> String? {
        guard let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines),
              !trimmed.isEmpty else {
            return nil
        }
        return trimmed
    }

    private static func isCodingAgentEnvironment(_ environment: [String: String]) -> Bool {
        if let kind = normalizedEnvValue(environment["CMUX_AGENT_LAUNCH_KIND"])?.lowercased() {
            let agentKinds: Set<String> = [
                "claude",
                "codex",
                "opencode",
                "omo",
                "omx",
                "omc",
            ]
            if agentKinds.contains(kind) {
                return true
            }
        }

        let directAgentKeys = [
            "CODEX_CI",
            "CODEX_THREAD_ID",
            "CODEX_SESSION_ID",
            "CODEX_SANDBOX",
            "CODEX_MANAGED_BY_BUN",
            "CLAUDECODE",
            "CLAUDE_CODE",
            "CLAUDE_CODE_ENTRYPOINT",
            "CLAUDE_CODE_SESSION_ID",
            "OPENCODE",
            "OPENCODE_PORT",
            "OPENCODE_SESSION_ID",
        ]
        return directAgentKeys.contains { normalizedEnvValue(environment[$0]) != nil }
    }

    private static func vmCreateIdempotencySignature(image: String?, provider: String?) -> String {
        let normalizedImage = image?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let normalizedProvider = provider?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased() ?? ""
        return "image=\(normalizedImage)\u{1f}provider=\(normalizedProvider)"
    }

    private static func normalizedVMProvider(_ provider: String?) throws -> String? {
        guard let trimmed = provider?.trimmingCharacters(in: .whitespacesAndNewlines),
              !trimmed.isEmpty else {
            return nil
        }
        let normalized = trimmed.lowercased()
        guard normalized == "e2b" || normalized == "freestyle" || normalized == "daytona" else {
            throw CLIError(message: """
                vm new: unsupported Cloud VM service override.

                Try:
                  cmux vm new
                """)
        }
        return normalized
    }

    private static func isFlagToken(_ value: String) -> Bool { value.hasPrefix("-") && value != "-" }

    private static func isUnknownFlagToken(_ value: String, allowedShortFlags: Set<String> = []) -> Bool { isFlagToken(value) && !allowedShortFlags.contains(value) }

    private static func validatedVMSessionIdentifier(_ value: String?, flag: String) throws -> String? {
        guard let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines),
              !trimmed.isEmpty else {
            return nil
        }
        let safePattern = "^[A-Za-z0-9._:-]{1,200}$"
        guard trimmed.range(of: safePattern, options: .regularExpression) != nil else {
            throw CLIError(message: "\(flag) must contain only letters, numbers, dot, underscore, colon, or dash.")
        }
        return trimmed
    }

    private static func vmCreateIdempotencyStoreURL() -> URL {
        FileManager.default.homeDirectoryForCurrentUser
            .appendingPathComponent(".cmuxterm", isDirectory: true)
            .appendingPathComponent("vm-create-idempotency.json", isDirectory: false)
    }

    private static func loadVMCreateIdempotencyStore(from url: URL) -> VMCreateIdempotencyStore {
        guard let data = try? Data(contentsOf: url),
              let store = try? JSONDecoder().decode(VMCreateIdempotencyStore.self, from: data) else {
            return VMCreateIdempotencyStore()
        }
        return store
    }

    private static func saveVMCreateIdempotencyStore(_ store: VMCreateIdempotencyStore, to url: URL) throws {
        let directory = url.deletingLastPathComponent()
        let fileManager = FileManager.default
        try fileManager.createDirectory(at: directory, withIntermediateDirectories: true)
        try? fileManager.setAttributes([.posixPermissions: 0o700], ofItemAtPath: directory.path)
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
        let data = try encoder.encode(store)
        try data.write(to: url, options: .atomic)
        try? fileManager.setAttributes([.posixPermissions: 0o600], ofItemAtPath: url.path)
    }

    private static func activeVMCreateIdempotency(image: String?, provider: String?, usesPersistentDefaultCloud: Bool) throws -> ActiveVMCreateIdempotency {
        if usesPersistentDefaultCloud {
            return ActiveVMCreateIdempotency(
                signature: "persistent-cloud-vm-slot",
                key: persistentCloudVMSlotID
            )
        }

        let url = vmCreateIdempotencyStoreURL()
        let signature = vmCreateIdempotencySignature(image: image, provider: provider)
        let now = Date().timeIntervalSince1970
        var store = loadVMCreateIdempotencyStore(from: url)
        store.records = store.records.filter { _, record in
            !record.key.isEmpty && now - record.createdAt < vmCreateIdempotencyTTLSeconds
        }
        if let existing = store.records[signature] {
            try saveVMCreateIdempotencyStore(store, to: url)
            return ActiveVMCreateIdempotency(signature: signature, key: existing.key)
        }
        let key = UUID().uuidString.lowercased()
        store.records[signature] = VMCreateIdempotencyRecord(key: key, createdAt: now)
        try saveVMCreateIdempotencyStore(store, to: url)
        return ActiveVMCreateIdempotency(signature: signature, key: key)
    }

    private static func clearVMCreateIdempotency(_ active: ActiveVMCreateIdempotency) {
        let url = vmCreateIdempotencyStoreURL()
        var store = loadVMCreateIdempotencyStore(from: url)
        guard store.records[active.signature]?.key == active.key else { return }
        store.records.removeValue(forKey: active.signature)
        try? saveVMCreateIdempotencyStore(store, to: url)
    }

    private static func usesPersistentDefaultFreestyleCloud(image: String?, providerOption: String?) -> Bool {
        let normalizedImage = image?.trimmingCharacters(in: .whitespacesAndNewlines)
        guard normalizedImage?.isEmpty != false else { return false }
        let normalizedProvider = providerOption?.trimmingCharacters(in: .whitespacesAndNewlines)
        return normalizedProvider == nil || normalizedProvider == ""
    }

    private static let browserDisabledDefaultsKey = "browserDisabledOverride"
    private static let defaultBrowserSettingsDomain = "com.cmuxterm.app"

    private static func containingAppBundleIdentifier() -> String? {
        normalizedEnvValue(CLIExecutableLocator.enclosingAppBundle()?.bundleIdentifier)
    }

    private static func browserSettingsDomain(environment: [String: String]) -> String {
        normalizedEnvValue(environment["CMUX_BUNDLE_ID"])
        ?? containingAppBundleIdentifier()
        ?? defaultBrowserSettingsDomain
    }

    // Presentation flags are global, but command option values can also look like flags.
    private static let commandOptionsWithValues: Set<String> = [
        "--action", "--after-workspace", "--agent", "--amount", "--arch",
        "--attr", "--before-workspace", "--body", "--color", "--command",
        "--config", "--cwd", "--description", "--direction", "--domain",
        "--dx", "--dy", "--email", "--event", "--expires", "--focus",
        "--function", "--id", "--image", "--index", "--key", "--kind",
        "--label", "--layout", "--lines", "--load-state", "--max-depth", "--name", "--os",
        "--order", "--out", "--pane", "--panel", "--path", "--profile", "--property",
        "--provider", "--relay-port", "--script", "--selector", "--session",
        "--shell", "--source", "--subtitle", "--surface", "--tab", "--target-pane", "--team",
        "--text", "--timeout", "--timeout-ms", "--title", "--transcript",
        "--turn", "--type", "--url", "--url-contains", "--value", "--window",
        "--workspace", "--checkpoint", "--checkpoint-id",
    ]

    private func parsePresentationOptions(
        _ commandArgs: [String]
    ) throws -> (jsonOutput: Bool, idFormat: String?, remaining: [String]) {
        var jsonOutput = false
        var idFormat: String?
        var remaining: [String] = []
        var index = 0
        var pastTerminator = false
        while index < commandArgs.count {
            let arg = commandArgs[index]
            if pastTerminator {
                remaining.append(arg)
                index += 1
                continue
            }
            if arg == "--" {
                pastTerminator = true
                remaining.append(arg)
                index += 1
                continue
            }
            if arg == "--json" {
                jsonOutput = true
                index += 1
                continue
            }
            if arg == "--id-format" {
                guard index + 1 < commandArgs.count else {
                    throw CLIError(message: "--id-format requires a value (refs|uuids|both)")
                }
                idFormat = commandArgs[index + 1]
                index += 2
                continue
            }
            remaining.append(arg)
            if Self.commandOptionsWithValues.contains(arg), index + 1 < commandArgs.count {
                remaining.append(commandArgs[index + 1])
                index += 2
                continue
            }
            index += 1
        }
        return (jsonOutput, idFormat, remaining)
    }

    private func runBrowserAvailabilityCommand(
        command: String,
        commandArgs: [String],
        jsonOutput globalJSONOutput: Bool,
        environment: [String: String]
    ) throws {
        var effectiveJSONOutput = globalJSONOutput
        var args = commandArgs
        if let jsonIndex = args.firstIndex(of: "--json") {
            effectiveJSONOutput = true
            args.remove(at: jsonIndex)
        }

        let action: String
        if command == "browser" {
            guard let first = args.first?.lowercased() else {
                throw CLIError(message: "browser requires a subcommand")
            }
            action = first
            args = Array(args.dropFirst())
        } else {
            action = command
        }

        guard args.isEmpty else {
            throw CLIError(message: "Unexpected argument: \(args[0])")
        }

        let domain = Self.browserSettingsDomain(environment: environment)
        let defaults = UserDefaults(suiteName: domain) ?? .standard

        switch action {
        case "disable", "disable-browser":
            defaults.set(true, forKey: Self.browserDisabledDefaultsKey)
            defaults.synchronize()
        case "enable", "enable-browser":
            defaults.set(false, forKey: Self.browserDisabledDefaultsKey)
            defaults.synchronize()
        case "status", "browser-status":
            break
        default:
            throw CLIError(message: "Unknown browser availability command: \(action)")
        }

        let disabled = defaults.object(forKey: Self.browserDisabledDefaultsKey) == nil
            ? false
            : defaults.bool(forKey: Self.browserDisabledDefaultsKey)
        let payload: [String: Any] = [
            "enabled": !disabled,
            "disabled": disabled,
            "domain": domain,
            "key": Self.browserDisabledDefaultsKey
        ]
        if effectiveJSONOutput {
            print(jsonString(payload))
        } else if action == "status" || action == "browser-status" {
            print(disabled ? "disabled" : "enabled")
        } else {
            print(disabled ? "cmux browser disabled" : "cmux browser enabled")
        }
    }

    private static func shouldFocusWindowBeforeDispatch(command: String, commandArgs: [String]) -> Bool {
        let normalizedCommand = command.lowercased()
        // `window` repositions a window (e.g. `window display`); it must not
        // pre-focus, or it would steal macOS focus before moving the window.
        if normalizedCommand == "window" {
            return false
        }
        if normalizedCommand == "surface-resume" {
            return false
        }
        if normalizedCommand == "surface", commandArgs.first?.lowercased() == "resume" {
            return false
        }
        return true
    }

    func run() throws {
        let processEnv = ProcessInfo.processInfo.environment
        let cliBundleIdentifier = CLISocketPathResolver.currentAppBundleIdentifier()
        var explicitSocketPath: String? = nil
        var jsonOutput = false
        var idFormatArg: String? = nil
        var windowId: String? = nil
        var socketPasswordArg: String? = nil

        var index = 1
        while index < args.count {
            let arg = args[index]
            if arg == "--socket" {
                guard index + 1 < args.count else {
                    throw CLIError(message: "--socket requires a path")
                }
                explicitSocketPath = args[index + 1]
                index += 2
                continue
            }
            if arg == "--json" {
                jsonOutput = true
                index += 1
                continue
            }
            if arg == "--id-format" {
                guard index + 1 < args.count else {
                    throw CLIError(message: "--id-format requires a value (refs|uuids|both)")
                }
                idFormatArg = args[index + 1]
                index += 2
                continue
            }
            if arg == "--window" {
                guard index + 1 < args.count else {
                    throw CLIError(message: "--window requires a window id")
                }
                windowId = args[index + 1]
                index += 2
                continue
            }
            if arg == "--password" {
                guard index + 1 < args.count else {
                    throw CLIError(message: "--password requires a value")
                }
                socketPasswordArg = args[index + 1]
                index += 2
                continue
            }
            if arg == "-v" || arg == "--version" {
                print(versionSummary())
                return
            }
            if arg == "-h" || arg == "--help" {
                print(usage())
                return
            }
            break
        }

        guard index < args.count else {
            throw CLIError(
                message: "Missing command. Usage: cmux <path>|<command> [options]. Run 'cmux --help' for the full command list.",
                exitCode: 2
            )
        }

        let command = args[index]
        let presentationOptions = try parsePresentationOptions(Array(args[(index + 1)...]))
        if presentationOptions.jsonOutput {
            jsonOutput = true
        }
        if let parsedIDFormat = presentationOptions.idFormat {
            idFormatArg = parsedIDFormat
        }
        let commandArgs = presentationOptions.remaining

        if command == "version" {
            print(versionSummary())
            return
        }

        // Check for --help/-h on subcommands before resolving sockets,
        // so help text is available even when cmux is not running.
        let preSeparatorArgs = commandArgs.firstIndex(of: "--").map { commandArgs[..<$0] } ?? commandArgs[...]
        if command != "__tmux-compat",
           preSeparatorArgs.contains(where: { $0 == "--help" || $0 == "-h" }) {
            if dispatchSubcommandHelp(command: command, commandArgs: commandArgs) {
                return
            }
            throw unknownCommandError(command)
        }

        if command == "help" { print(usage()); return }; if command == "remote-daemon-status" { try runRemoteDaemonStatus(commandArgs: commandArgs, jsonOutput: jsonOutput); return }
        if command == "vm-pty-connect" { try runVMPtyConnect(commandArgs: commandArgs); return }
        if command == "docs" { try runDocsCommand(commandArgs: commandArgs, jsonOutput: jsonOutput); return }
        if command == "welcome" { printWelcome(); return }
        if command == "sessions" || command == "session-debug" { try runSessionsCommand(commandArgs: command == "session-debug" ? ["debug"] + commandArgs : commandArgs, jsonOutput: jsonOutput, processEnv: processEnv); return }
        if command == "__sigpipe-probe" { try runSIGPIPEProbe(commandArgs: commandArgs); return }
        if command == "__sigpipe-stdin-pipe-probe" { try runSIGPIPEStdinPipeProbe(); return }
        if command == "__sigpipe-inspect" { try runSIGPIPEInspect(commandArgs: commandArgs); return }
        if command == "diff-viewer-server" { try runDiffViewerServerCommand(commandArgs: commandArgs); return }
        if command == "__diff-viewer-refs" { try runDiffViewerRefsCommand(commandArgs: commandArgs); return }
        if command == "__diff-viewer-branch" { try runDiffViewerBranchRegenerateCommand(commandArgs: commandArgs); return }
        if command == "settings",
           settingsCommandDoesNotNeedSocket(commandArgs) {
            try runSettings(
                commandArgs: commandArgs,
                socketPath: CLISocketPathResolver.defaultSocketPath(
                    bundleIdentifier: cliBundleIdentifier,
                    environment: processEnv
                ),
                explicitPassword: socketPasswordArg,
                jsonOutput: jsonOutput
            )
            return
        }

        // `window default-display` only reads/writes the shared dev setting file;
        // it must work with no cmux running, so handle it before socket resolution.
        if command == "window",
           commandArgs.first?.lowercased() == "default-display" {
            try runWindowDefaultDisplayCommand(
                commandArgs: Array(commandArgs.dropFirst()),
                jsonOutput: jsonOutput
            )
            return
        }

        // Keep no-socket config subcommands on the early path. Socket-backed
        // config subcommands fall through to the resolved-socket dispatch below.
        if command == "config",
           configCommandDoesNotNeedSocket(commandArgs) {
            try runConfigCommand(
                commandArgs: commandArgs,
                socketPath: nil,
                explicitPassword: socketPasswordArg,
                jsonOutput: jsonOutput
            )
            return
        }

        // If the argument is a path (not a known command), open a workspace there.
        if shouldOpenAsPathArgument(command), explicitSocketPath == nil {
            try openPath(command)
            return
        }

        let envSocketPath = explicitSocketPath == nil
            ? try CLISocketEnvironment.socketPath(in: processEnv)
            : CLISocketEnvironment.socketPathForTelemetry(in: processEnv)
        let socketPath = explicitSocketPath ?? envSocketPath ?? CLISocketPathResolver.defaultSocketPath(
            bundleIdentifier: cliBundleIdentifier,
            environment: processEnv
        )
        let socketPathSource: CLISocketPathSource
        if explicitSocketPath != nil {
            socketPathSource = .explicitFlag
        } else if let envSocketPath {
            socketPathSource = CLISocketPathResolver.isImplicitDefaultPath(
                envSocketPath,
                bundleIdentifier: cliBundleIdentifier,
                environment: processEnv
            ) ? .implicitDefault : .environment
        } else {
            socketPathSource = .implicitDefault
        }
        let cliTelemetry = CLISocketSentryTelemetry(
            command: command,
            commandArgs: commandArgs,
            socketPath: socketPath,
            processEnv: processEnv
        )
        let resolvedSocketPath = CLISocketPathResolver.resolve(
            requestedPath: socketPath,
            source: socketPathSource,
            environment: processEnv,
            bundleIdentifier: cliBundleIdentifier
        )

        if shouldOpenAsPathArgument(command) {
            try openPathViaExplicitSocket(command, socketPath: resolvedSocketPath, explicitPassword: socketPasswordArg)
            return
        }

        if command == "settings" {
            try runSettings(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg,
                jsonOutput: jsonOutput
            )
            return
        }

        if command == "config" {
            try runConfigCommand(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg,
                jsonOutput: jsonOutput
            )
            return
        }

        if command == "shortcuts" {
            try runShortcuts(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg,
                jsonOutput: jsonOutput
            )
            return
        }
        if command == "open" { try runOpenCommand(commandArgs: commandArgs, socketPath: resolvedSocketPath, explicitPassword: socketPasswordArg, jsonOutput: jsonOutput, idFormat: try resolvedIDFormat(jsonOutput: jsonOutput, raw: idFormatArg)); return }
        if command == "diff" { try runDiffCommand(commandArgs: commandArgs, socketPath: resolvedSocketPath, explicitPassword: socketPasswordArg, jsonOutput: jsonOutput, idFormat: try resolvedIDFormat(jsonOutput: jsonOutput, raw: idFormatArg)); return }
        if command == "restore-session" {
            try runRestoreSession(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg,
                jsonOutput: jsonOutput
            )
            return
        }

        if command == "feedback" {
            try runFeedback(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg,
                jsonOutput: jsonOutput
            )
            return
        }

        if command == "right-sidebar" {
            let parsed = try parseRightSidebarCLIArguments(commandArgs)
            _ = try rightSidebarSocketArguments(from: parsed)
        }

        if command == "themes" {
            try runThemes(
                commandArgs: commandArgs,
                jsonOutput: jsonOutput,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg
            )
            return
        }

        if command == "claude-teams" {
            try runClaudeTeams(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg
            )
            return
        }

        if command == "codex-teams" {
            try runCodexTeams(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg
            )
            return
        }

        if command == "omo" {
            try runOMO(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg
            )
            return
        }

        if command == "omx" {
            try runOMX(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg
            )
            return
        }

        if command == "__debug-tmux-compat-env" {
            try debugDumpTmuxCompatEnvironment(
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg
            )
            return
        }

        if command == "omc" {
            try runOMC(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg
            )
            return
        }

        if command == "codex" {
            // Backwards compatibility for old hook setup docs/scripts. Hidden from help.
            let sub = commandArgs.first?.lowercased() ?? "help"
            guard let codexDef = Self.agentDef(named: "codex") else { throw CLIError(message: "Codex hook integration is unavailable.") }
            if sub == "install-hooks" {
                try installHooksForAgent(codexDef, arguments: Array(commandArgs.dropFirst()))
                return
            } else if sub == "uninstall-hooks" {
                try uninstallHooksForAgent(codexDef, arguments: Array(commandArgs.dropFirst()))
                return
            }
        }
        if command == "setup-hooks" || command == "uninstall-hooks" { try runSetupHooks(uninstall: command == "uninstall-hooks"); return } // Backwards compatibility for old hook setup docs/scripts.
        if (command == "codex-hook" || command == "feed-hook"), processEnv["CMUX_SURFACE_ID"]?.isEmpty != false, processEnv["CMUX_WORKSPACE_ID"]?.isEmpty != false,
           !commandArgs.contains(where: { $0 == "--workspace" || $0 == "--surface" || $0.hasPrefix("--workspace=") || $0.hasPrefix("--surface=") }) { print("{}"); return } // Backwards compatibility for old installed hooks outside cmux terminals.
        if command == "hooks" {
            if try runHooksNoSocketCommand(commandArgs: commandArgs) {
                return
            }
            if Self.hooksCommandNeedsCmuxTarget(commandArgs),
               processEnv["CMUX_SURFACE_ID"]?.isEmpty != false,
               processEnv["CMUX_WORKSPACE_ID"]?.isEmpty != false,
               !commandArgs.contains(where: { $0 == "--workspace" || $0 == "--surface" || $0.hasPrefix("--workspace=") || $0.hasPrefix("--surface=") }) {
                print("{}")
                return
            }
            if commandArgs.first?.lowercased() == "feed" {
                try runFeedHook(
                    commandArgs: Array(commandArgs.dropFirst()),
                    socketPath: resolvedSocketPath,
                    socketPassword: socketPasswordArg,
                    telemetry: cliTelemetry
                )
                return
            }
        }
        if command == "feed-hook" {
            try runFeedHook(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                socketPassword: socketPasswordArg,
                telemetry: cliTelemetry
            )
            return
        }

        // Feed helpers: clear the persistent workstream history.
        if command == "feed" {
            let sub = commandArgs.first?.lowercased() ?? "help"
            switch sub {
            case "clear":
                try runFeedClear()
                return
            case "tui":
                try runFeedTUI(
                    arguments: Array(commandArgs.dropFirst()),
                    socketPath: resolvedSocketPath,
                    socketPassword: socketPasswordArg
                )
                return
            case "help", "--help", "-h":
                print("Usage: cmux feed tui [--opentui|--legacy]\n       cmux feed clear [--yes]")
                return
            default:
                throw CLIError(message: "Unknown feed subcommand: \(sub)")
            }
        }
        if command == "events" {
            try runEventsCommand(
                commandArgs: commandArgs,
                socketPath: resolvedSocketPath,
                explicitPassword: socketPasswordArg
            )
            return
        }

        let browserAvailabilityArgs = commandArgs.filter { $0 != "--json" }
        if command == "disable-browser" ||
            command == "enable-browser" ||
            command == "browser-status" ||
            (command == "browser" && ["disable", "enable", "status"].contains(browserAvailabilityArgs.first?.lowercased() ?? "")) {
            try runBrowserAvailabilityCommand(
                command: command,
                commandArgs: commandArgs,
                jsonOutput: jsonOutput,
                environment: processEnv
            )
            return
        }

        try validateSurfaceResumeCommandValueOptionsBeforeSocket(
            command: command,
            commandArgs: commandArgs
        )
        try validateWorkspaceLoadingCommandBeforeSocket(command: command, commandArgs: commandArgs)
        let client = SocketClient(path: resolvedSocketPath)
        if resolvedSocketPath != socketPath {
            cliTelemetry.breadcrumb(
                "socket.path.autodiscovered",
                data: [
                    "requested_path": socketPath,
                    "resolved_path": resolvedSocketPath
                ]
            )
        }
        cliTelemetry.breadcrumb(
            "socket.connect.attempt",
            data: [
                "command": command,
                "path": resolvedSocketPath
            ]
        )
        do {
            try client.connect()
            cliTelemetry.breadcrumb("socket.connect.success", data: ["path": resolvedSocketPath])
        } catch {
            cliTelemetry.breadcrumb("socket.connect.failure", data: ["path": resolvedSocketPath])
            cliTelemetry.captureError(stage: "socket_connect", error: error)
            throw error
        }
        defer { client.close() }

        try authenticateClientIfNeeded(
            client,
            explicitPassword: socketPasswordArg,
            socketPath: resolvedSocketPath
        )

        let idFormat = try resolvedIDFormat(jsonOutput: jsonOutput, raw: idFormatArg)
        // Most CLI --window routing focuses first so commands without an
        // explicit window_id still target the selected window.
        if let windowId, Self.shouldFocusWindowBeforeDispatch(command: command, commandArgs: commandArgs) {
            do {
                let normalizedWindow = try normalizeWindowHandle(windowId, client: client) ?? windowId
                _ = try client.sendV2(method: "window.focus", params: ["window_id": normalizedWindow])
            } catch {
                captureSocketTransportError(telemetry: cliTelemetry, stage: "socket_command_window_focus", error: error, client: client)
                throw error
            }
        }

        let capturesSocketErrorsInsideCommand = ["claude-hook", "codex-hook", "feed-hook", "hooks"].contains(command) // Backwards compatibility aliases stay hidden from help.
        do {
        switch command {
        case "__internal_flags":
            let response = try sendV1Command("__internal_flags", client: client)
            print(response)

        case "ping":
            let response = try sendV1Command("ping", client: client)
            print(response)

        case "capabilities":
            let response = try client.sendV2(method: "system.capabilities")
            print(jsonString(formatIDs(response, mode: idFormat)))

        case "agent-hibernation":
            try runAgentHibernation(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput)

        case "auth", "login", "logout":
            let authArgs = command == "auth" ? commandArgs : [command] + commandArgs
            let sub = authArgs.first?.lowercased() ?? "status"
            switch sub {
            case "status":
                let response = try client.sendV2(method: "auth.status")
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                let signedIn = (response["signed_in"] as? Bool) ?? false
                if !signedIn {
                    print("Not signed in.")
                    print("Run: cmux auth login")
                    break
                }
                let user = response["user"] as? [String: Any]
                let email = user?["email"] as? String
                let display = user?["display_name"] as? String
                let userID = user?["id"] as? String
                print("Signed in.")
                if let email { print("  email:    \(email)") }
                if let display { print("  name:     \(display)") }
                if let userID { print("  user_id:  \(userID)") }
                if let teamID = response["selected_team_id"] as? String {
                    print("  team_id:  \(teamID)")
                }

            case "login":
                let statusBefore = try client.sendV2(method: "auth.status")
                if (statusBefore["signed_in"] as? Bool) == true {
                    let email = (statusBefore["user"] as? [String: Any])?["email"] as? String
                    print("Already signed in\(email.map { " as \($0)" } ?? ""). Use `cmux auth logout` to sign out first.")
                    break
                }
                if let signInURLResponse = try? client.sendV2(method: "auth.sign_in_url"),
                   let signInURL = signInURLResponse["url"] as? String,
                   !signInURL.isEmpty {
                    print("Fallback sign-in URL:")
                    print(signInURL)
                }
                print("Opening sign-in popup on the cmux web app.")
                // auth.begin_sign_in blocks on the server side until the
                // popup completes (or 5min timeout). The response is the
                // callback — no polling.
                let result = try client.sendV2(method: "auth.begin_sign_in", responseTimeout: 305)
                if (result["signed_in"] as? Bool) == true {
                    let email = (result["user"] as? [String: Any])?["email"] as? String
                    print("Signed in\(email.map { " as \($0)" } ?? "").")
                } else if (result["timed_out"] as? Bool) == true {
                    print("Timed out waiting for sign-in. Run `cmux auth status` once you've finished in the popup.")
                } else {
                    print("Sign-in did not complete. Run `cmux auth status` to check.")
                }

            case "logout":
                let statusBefore = try client.sendV2(method: "auth.status")
                if (statusBefore["signed_in"] as? Bool) != true {
                    print("Already signed out.")
                    break
                }
                // auth.sign_out awaits the token clear before replying.
                let result = try client.sendV2(method: "auth.sign_out")
                if (result["signed_in"] as? Bool) != true {
                    print("Signed out.")
                } else {
                    print("Sign-out requested but state hasn't cleared yet. Run `cmux auth status` to confirm.")
                }

            default:
                throw CLIError(message: "Usage: cmux auth <status|login|logout>")
            }

        case "vm", "cloud":
            let sub = commandArgs.first?.lowercased() ?? "ls"
            let rest = Array(commandArgs.dropFirst())
            switch sub {
            case "ls", "list":
                let response = try client.sendV2(method: "vm.list")
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                let vms = (response["vms"] as? [[String: Any]]) ?? []
                if vms.isEmpty {
                    print("No cloud VMs. Try: cmux vm new")
                    break
                }
                for vm in vms {
                    let id = (vm["id"] as? String) ?? "?"
                    let provider = (vm["provider"] as? String) ?? "?"
                    let status = (vm["status"] as? String) ?? "unknown"
                    let image = (vm["image"] as? String) ?? "?"
                    print("\(id)  [\(provider)] \(status)  \(image)")
                }

            case "status", "info":
                guard let vmId = rest.first else {
                    throw CLIError(message: """
                        Usage: cmux vm status <id>

                        Find an id:
                          cmux vm ls
                        """)
                }
                let response = try client.sendV2(method: "vm.status", params: ["id": vmId], responseTimeout: 60)
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                let id = (response["id"] as? String) ?? vmId
                let provider = (response["provider"] as? String) ?? "?"
                let image = (response["image"] as? String) ?? "?"
                let status = (response["status"] as? String) ?? "unknown"
                print("\(id)  [\(provider)] \(status)")
                print("image: \(image)")

            case "base":
                let baseAction = rest.first?.lowercased()
                if baseAction == nil || baseAction == "open" {
                    let baseArgs = baseAction == "open" ? Array(rest.dropFirst()) : rest
                    try runPersistentBaseOpenCommand(
                        args: baseArgs,
                        client: client,
                        jsonOutput: jsonOutput,
                        idFormat: idFormat,
                        windowId: windowId
                    )
                } else if baseAction == "reset" {
                    try runPersistentBaseResetCommand(
                        args: Array(rest.dropFirst()),
                        client: client,
                        jsonOutput: jsonOutput,
                        idFormat: idFormat,
                        windowId: windowId
                    )
                } else if rest.first?.hasPrefix("-") == true {
                    try runPersistentBaseOpenCommand(
                        args: rest,
                        client: client,
                        jsonOutput: jsonOutput,
                        idFormat: idFormat,
                        windowId: windowId
                    )
                } else {
                    throw CLIError(message: """
                        Usage:
                          cmux vm base open [--workspace <workspace-id>] [--window <id|ref|index>] [--session <session-id>] [--detach|-d]
                          cmux vm base reset [--reason <text>] [--workspace <workspace-id>] [--window <id|ref|index>] [--detach|-d]

                        Base is your persistent cloud workspace. Opening it reuses the
                        same VM. Reset creates a new Base generation and retains the old VM.
                        """)
                }

            case "new", "create":
                let (imageOpt, rem0) = parseOption(rest, name: "--image")
                let (providerOpt, rem1) = parseOption(rem0, name: "--provider")
                let (targetWorkspaceOpt, rem1a) = parseOption(rem1, name: "--workspace")
                let (windowOpt, rem2) = parseOption(rem1a, name: "--window")
                let detach = hasFlag(rem2, name: "--detach") || hasFlag(rem2, name: "-d")
                let remaining = rem2.filter { $0 != "--detach" && $0 != "-d" }
                if let unknown = remaining.first(where: { Self.isUnknownFlagToken($0, allowedShortFlags: ["-d"]) }) {
                    throw CLIError(message: """
                        vm new: unknown flag '\(unknown)'.

                        Known flags:
                          --image <image-id>
                          --provider <provider>
                          --workspace <workspace-id>
                          --detach, -d

                        Try:
                          cmux vm new
                        """)
                }
                // Stray positional args (e.g. a typo like `cmux vm new myvm`) previously fell
                // through and still provisioned a VM. That silently costs the user money and
                // hides the typo. Reject them explicitly.
                if let extra = remaining.first(where: { !Self.isFlagToken($0) }) {
                    throw CLIError(
                        message: """
                            vm new: unexpected argument '\(extra)'.

                            `cmux vm new` does not take a VM name or positional arguments.

                            Try:
                              cmux vm new
                              cmux vm new --detach
                            """
                    )
                }
                let normalizedProvider = try Self.normalizedVMProvider(providerOpt)
                var params: [String: Any] = [:]
                if let imageOpt { params["image"] = imageOpt }
                if let normalizedProvider { params["provider"] = normalizedProvider }
                let usesPersistentDefaultCloud = Self.usesPersistentDefaultFreestyleCloud(
                    image: imageOpt,
                    providerOption: providerOpt
                )
                if usesPersistentDefaultCloud {
                    params["provider"] = "freestyle"
                }
                let targetWindow = try validatedWindowHandle(windowOpt ?? windowId, client: client)
                let idempotency = try Self.activeVMCreateIdempotency(
                    image: imageOpt,
                    provider: normalizedProvider,
                    usesPersistentDefaultCloud: usesPersistentDefaultCloud
                )
                params["idempotency_key"] = idempotency.key
                let vmCreateStartedAt = Date()
                let response = try client.sendV2(
                    method: "vm.create",
                    params: params,
                    responseTimeout: Self.vmCreateResponseTimeoutSeconds
                )
                logVMTiming(
                    "create",
                    vmID: (response["id"] as? String) ?? "?",
                    provider: (response["provider"] as? String) ?? normalizedProvider ?? "?",
                    startedAt: vmCreateStartedAt
                )
                if jsonOutput {
                    Self.clearVMCreateIdempotency(idempotency)
                    print(jsonString(response))
                    break
                }
                let id = (response["id"] as? String) ?? "?"
                let provider = (response["provider"] as? String) ?? "?"
                let image = (response["image"] as? String) ?? "?"
                if detach {
                    Self.clearVMCreateIdempotency(idempotency)
                    print("OK \(id)")
                    print("  provider: \(provider)")
                    print("  image:    \(image)")
                    break
                }
                // Create the VM then drop the user into a cmux-managed workspace. Managed
                // Cloud VMs use the cmuxd-remote WebSocket PTY so they can reconnect and
                // attach from mobile clients without minting foreground SSH passwords.
                let shortId = String(id.prefix(8))
                let createdMessage = String(
                    format: String(
                        localized: "cli.vm.create.createdCloudVM",
                        defaultValue: "Created Cloud VM %@"
                    ),
                    id
                )
                print(createdMessage)
                try vmOpenShell(
                    id: id,
                    workspaceName: usesPersistentDefaultCloud ? Self.persistentCloudVMWorkspaceName : "vm:\(shortId)",
                    windowRaw: targetWindow,
                    targetWorkspaceId: targetWorkspaceOpt,
                    forceSSH: false,
                    shouldPinWorkspaceToTop: usesPersistentDefaultCloud,
                    client: client,
                    jsonOutput: jsonOutput,
                    idFormat: idFormat
                )
                Self.clearVMCreateIdempotency(idempotency)

            case "snapshot", "checkpoint":
                let (nameOpt, snapshotArgs) = parseOption(rest, name: "--name")
                guard let vmId = snapshotArgs.first else {
                    throw CLIError(message: """
                        Usage: cmux vm snapshot <id> [--name <name>]

                        Find an id:
                          cmux vm ls
                        """)
                }
                var params: [String: Any] = ["id": vmId]
                if let nameOpt { params["name"] = nameOpt }
                let response = try client.sendV2(method: "vm.snapshot", params: params, responseTimeout: Self.vmCreateResponseTimeoutSeconds)
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                let snapshotId = (response["snapshot_id"] as? String) ?? (response["id"] as? String) ?? "?"
                print("OK snapshot=\(snapshotId)")

            case "fork":
                let (nameOpt, rem0) = parseOption(rest, name: "--name")
                let (windowOpt, rem1) = parseOption(rem0, name: "--window")
                let detach = hasFlag(rem1, name: "--detach") || hasFlag(rem1, name: "-d")
                let vmArgs = rem1.filter { $0 != "--detach" && $0 != "-d" }
                guard let vmId = vmArgs.first else {
                    throw CLIError(message: """
                        Usage: cmux vm fork <id> [--name <name>] [--window <id|ref|index>] [--detach|-d]

                        Find an id:
                          cmux vm ls
                        """)
                }
                let targetWindow = try validatedWindowHandle(windowOpt ?? windowId, client: client)
                var params: [String: Any] = [
                    "id": vmId,
                    "idempotency_key": UUID().uuidString.lowercased(),
                ]
                if let nameOpt { params["name"] = nameOpt }
                let response = try client.sendV2(method: "vm.fork", params: params, responseTimeout: Self.vmCreateResponseTimeoutSeconds * 2)
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                let id = (response["id"] as? String) ?? "?"
                let snapshotId = response["snapshot_id"] as? String
                let provider = (response["provider"] as? String) ?? "?"
                let image = (response["image"] as? String) ?? "?"
                if detach {
                    print("OK \(id)")
                    print("  provider: \(provider)")
                    print("  image:    \(image)")
                    print("  snapshot: \(snapshotId ?? "native fork")")
                    break
                }
                print("Forked Cloud VM \(id)")
                print("  snapshot: \(snapshotId ?? "native fork")")
                try vmOpenShell(
                    id: id,
                    workspaceName: "vm:\(String(id.prefix(8)))",
                    windowRaw: targetWindow,
                    forceSSH: false,
                    shouldPinWorkspaceToTop: false,
                    client: client,
                    jsonOutput: jsonOutput,
                    idFormat: idFormat
                )

            case "restore":
                let (providerOpt, rem0) = parseOption(rest, name: "--provider")
                let (windowOpt, rem1) = parseOption(rem0, name: "--window")
                let detach = hasFlag(rem1, name: "--detach") || hasFlag(rem1, name: "-d")
                let restoreArgs = rem1.filter { $0 != "--detach" && $0 != "-d" }
                guard let snapshotId = restoreArgs.first else {
                    throw CLIError(message: """
                        Usage: cmux vm restore <snapshot-id> [--provider <provider>] [--window <id|ref|index>] [--detach|-d]
                    """)
                }
                let normalizedProvider = try Self.normalizedVMProvider(providerOpt)
                let targetWindow = try validatedWindowHandle(windowOpt ?? windowId, client: client)
                var params: [String: Any] = [
                    "snapshot_id": snapshotId,
                    "idempotency_key": UUID().uuidString.lowercased(),
                ]
                if let normalizedProvider { params["provider"] = normalizedProvider }
                let response = try client.sendV2(method: "vm.restore", params: params, responseTimeout: Self.vmCreateResponseTimeoutSeconds)
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                let id = (response["id"] as? String) ?? "?"
                let provider = (response["provider"] as? String) ?? normalizedProvider ?? "?"
                let image = (response["image"] as? String) ?? snapshotId
                if detach {
                    print("OK \(id)")
                    print("  provider: \(provider)")
                    print("  image:    \(image)")
                    break
                }
                print("Restored Cloud VM \(id)")
                try vmOpenShell(
                    id: id,
                    workspaceName: "vm:\(String(id.prefix(8)))",
                    windowRaw: targetWindow,
                    forceSSH: false,
                    shouldPinWorkspaceToTop: false,
                    client: client,
                    jsonOutput: jsonOutput,
                    idFormat: idFormat
                )

            case "shell", "attach":
                let (windowOpt, vmArgs) = parseOption(rest, name: "--window")
                guard let vmId = vmArgs.first else {
                    throw CLIError(message: """
                        Usage: cmux \(command) shell <id>

                        Find an id:
                          cmux vm ls
                        """)
                }
                let shortId = String(vmId.prefix(8))
                try vmOpenShell(
                    id: vmId,
                    workspaceName: "vm:\(shortId)",
                    windowRaw: windowOpt ?? windowId,
                    forceSSH: false,
                    shouldPinWorkspaceToTop: false,
                    client: client,
                    jsonOutput: jsonOutput,
                    idFormat: idFormat
                )

            case "rm", "destroy", "delete":
                guard let vmId = rest.first else {
                    throw CLIError(message: """
                        Usage: cmux vm rm <id>

                        Find an id:
                          cmux vm ls
                        """)
                }
                _ = try client.sendV2(method: "vm.destroy", params: ["id": vmId], responseTimeout: 60)
                if jsonOutput {
                    print("{\"ok\":true,\"id\":\"\(vmId)\"}")
                } else {
                    print("OK \(vmId)")
                }

            case "ssh":
                let (windowOpt, vmArgs) = parseOption(rest, name: "--window")
                guard let vmId = vmArgs.first else {
                    throw CLIError(message: """
                        Usage: cmux \(command) ssh <id>

                        Find an id:
                          cmux vm ls
                        """)
                }
                let shortId = String(vmId.prefix(8))
                try vmOpenShell(
                    id: vmId,
                    workspaceName: "vm:\(shortId)",
                    windowRaw: windowOpt ?? windowId,
                    forceSSH: true,
                    shouldPinWorkspaceToTop: false,
                    client: client,
                    jsonOutput: jsonOutput,
                    idFormat: idFormat
                )

            case "ssh-info":
                guard let vmId = rest.first else {
                    throw CLIError(message: """
                        Usage: cmux \(command) ssh-info <id>

                        Find an id:
                          cmux vm ls
                        """)
                }
                try printVMSSHInfo(id: vmId, command: command, client: client, jsonOutput: jsonOutput)

            case "ssh-attach":
                try runVMSSHAttach(commandArgs: rest, client: client)

            case "exec":
                guard let vmId = rest.first else {
                    throw CLIError(message: """
                        Usage: cmux vm exec <id> -- <command...>

                        Examples:
                          cmux vm ls
                          cmux vm exec <id> -- pwd
                        """)
                }
                var commandArgsForVM: [String] = Array(rest.dropFirst())
                // Consume a leading "--" separator if present.
                if commandArgsForVM.first == "--" {
                    commandArgsForVM.removeFirst()
                }
                guard !commandArgsForVM.isEmpty else {
                    throw CLIError(message: """
                        Usage: cmux vm exec <id> -- <command...>

                        Example:
                          cmux vm exec \(vmId) -- uname -a
                        """)
                }
                // Shell-quote each argv element before joining. Plain-space join previously
                // dropped quoting so `cmux vm exec <id> -- printf '%s\n' "a b"` reached the
                // VM as `printf %s\n a b`, changing semantics for any non-trivial command
                // (Codex P2).
                let command = commandArgsForVM.map(shellQuote).joined(separator: " ")
                let response = try client.sendV2(
                    method: "vm.exec",
                    params: ["id": vmId, "command": command],
                    responseTimeout: 35
                )
                let stdout = (response["stdout"] as? String) ?? ""
                let stderr = (response["stderr"] as? String) ?? ""
                let exitCode = (response["exit_code"] as? Int) ?? -1
                if jsonOutput {
                    print(jsonString(response))
                    if exitCode != 0 {
                        throw CLIError(message: "exit \(exitCode)")
                    }
                    break
                }
                if !stdout.isEmpty { print(stdout, terminator: stdout.hasSuffix("\n") ? "" : "\n") }
                if !stderr.isEmpty {
                    cliWriteStderr(Data(stderr.utf8))
                    if !stderr.hasSuffix("\n") {
                        cliWriteStderr(Data("\n".utf8))
                    }
                }
                if exitCode != 0 {
                    throw CLIError(message: "exit \(exitCode)")
                }

            case "tools", "tool-inspector":
                guard let vmId = rest.first else {
                    throw CLIError(message: "Usage: cmux vm tools <id>")
                }
                let command = [
                    "printf 'shell: '; printf '%s\\n' \"$SHELL\"",
                    "for tool in zsh git gh htop btop node bun python3; do if command -v \"$tool\" >/dev/null 2>&1; then printf '%-8s %s\\n' \"$tool\" \"$(command -v \"$tool\")\"; else printf '%-8s missing\\n' \"$tool\"; fi; done",
                    "zsh --version 2>/dev/null || true",
                    "gh --version 2>/dev/null | head -n 1 || true",
                ].joined(separator: "; ")
                let response = try client.sendV2(method: "vm.exec", params: ["id": vmId, "command": command, "timeout_ms": 30_000], responseTimeout: 35)
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                print((response["stdout"] as? String) ?? "")

            case "ports":
                guard let vmId = rest.first else {
                    throw CLIError(message: "Usage: cmux vm ports <id>")
                }
                let command = "if command -v ss >/dev/null 2>&1; then ss -ltnp; elif command -v netstat >/dev/null 2>&1; then netstat -ltnp; else echo 'No port inspector found'; fi"
                let response = try client.sendV2(method: "vm.exec", params: ["id": vmId, "command": command, "timeout_ms": 30_000], responseTimeout: 35)
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                print((response["stdout"] as? String) ?? "")

            case "handoff":
                guard let vmId = rest.first else {
                    throw CLIError(message: "Usage: cmux vm handoff <id>")
                }
                let response = try client.sendV2(method: "vm.status", params: ["id": vmId], responseTimeout: 60)
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                let provider = (response["provider"] as? String) ?? "?"
                let status = (response["status"] as? String) ?? "unknown"
                print("cmux Cloud VM handoff")
                print("id:       \(vmId)")
                print("provider: \(provider)")
                print("status:   \(status)")
                print("attach:   cmux vm ssh \(vmId)")
                print("inspect:  cmux vm tools \(vmId)")

            case "promote-template":
                guard let vmId = rest.first else {
                    throw CLIError(message: "Usage: cmux vm promote-template <id>")
                }
                let name = "template-\(String(vmId.prefix(12)))-\(Int(Date().timeIntervalSince1970))"
                let response = try client.sendV2(method: "vm.snapshot", params: ["id": vmId, "name": name], responseTimeout: Self.vmCreateResponseTimeoutSeconds)
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                let snapshotId = (response["snapshot_id"] as? String) ?? (response["id"] as? String) ?? "?"
                print("OK template=\(snapshotId)")

            default:
                throw CLIError(message: """
                    Usage: cmux \(command) <ls|new|status|snapshot|fork|restore|shell|rm|exec|ssh> [args...]

                    Common commands:
                      cmux vm ls
                      cmux vm new
                      cmux vm status <id>
                      cmux vm snapshot <id>
                      cmux vm fork <id>
                      cmux vm ssh <id>
                      cmux vm rm <id>
                    """)
            }

        case "remotes", "remote":
            try runRemotesCommand(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput)

        case "ai-accounts":
            try runAIAccountsCommand(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput)

        case "mobile":
            let sub = commandArgs.first?.lowercased()
            let rest = Array(commandArgs.dropFirst())
            let mobileUsage = String(
                localized: "cli.mobile.setFont.usage",
                defaultValue: "Usage: cmux mobile set-font <points> [--surface <id>] [--workspace <id>]"
            )
            switch sub {
            case "set-font":
                guard let sizeArg = rest.first(where: { !$0.hasPrefix("--") }),
                      let size = Double(sizeArg), size.isFinite, size > 0 else {
                    throw CLIError(message: mobileUsage)
                }
                var params: [String: Any] = ["font_size": size]
                if let surface = optionValue(rest, name: "--surface") {
                    params["surface_id"] = surface
                }
                if let workspace = optionValue(rest, name: "--workspace") {
                    params["workspace_id"] = workspace
                }
                let response = try client.sendV2(method: "mobile.terminal.set_font", params: params)
                if jsonOutput {
                    print(jsonString(response))
                    break
                }
                let delivered = (response["delivered"] as? Bool) ?? false
                if delivered {
                    print(localizedFormat(
                        "cli.mobile.setFont.applied",
                        defaultValue: "Set mobile terminal font to %@pt on connected device(s).",
                        sizeArg
                    ))
                } else {
                    print(localizedFormat(
                        "cli.mobile.setFont.appliedNoDevice",
                        defaultValue: "Set mobile terminal font to %@pt (no iOS device is currently connected).",
                        sizeArg
                    ))
                }
            default:
                throw CLIError(message: mobileUsage)
            }

        case "rpc":
            guard let method = commandArgs.first?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !method.isEmpty else {
                throw CLIError(message: "Usage: cmux rpc <method> [json-params]")
            }
            let params = try parseRPCParams(Array(commandArgs.dropFirst()))
            let response = try client.sendV2(method: method, params: params)
            let output: Any = idFormatArg == nil ? response : formatIDs(response, mode: idFormat)
            print(jsonString(output))

        case "identify":
            var params: [String: Any] = [:]
            let localWindowRaw = optionValue(commandArgs, name: "--window")
            let effectiveWindowRaw = localWindowRaw ?? windowId
            let targetWindow = try normalizeWindowHandle(effectiveWindowRaw, client: client)
            if let targetWindow {
                params["window_id"] = targetWindow
            }
            let includeCaller = !hasFlag(commandArgs, name: "--no-caller")
            if includeCaller {
                let idWsFlag = optionValue(commandArgs, name: "--workspace")
                let workspaceArg = idWsFlag ?? (effectiveWindowRaw == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)
                let surfaceArg = optionValue(commandArgs, name: "--surface") ?? (idWsFlag == nil && effectiveWindowRaw == nil ? ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"] : nil)
                if workspaceArg != nil || surfaceArg != nil {
                    let workspaceId = try normalizeWorkspaceHandle(
                        workspaceArg,
                        client: client,
                        windowHandle: targetWindow,
                        allowCurrent: surfaceArg != nil
                    )
                    var caller: [String: Any] = [:]
                    if let workspaceId {
                        caller["workspace_id"] = workspaceId
                    }
                    if surfaceArg != nil {
                        guard let surfaceId = try normalizeSurfaceHandle(
                            surfaceArg,
                            client: client,
                            workspaceHandle: workspaceId,
                            windowHandle: targetWindow
                        ) else {
                            throw CLIError(message: "Invalid surface handle")
                        }
                        caller["surface_id"] = surfaceId
                    }
                    if !caller.isEmpty {
                        params["caller"] = caller
                    }
                }
            }
            let response = try client.sendV2(method: "system.identify", params: params)
            print(jsonString(formatIDs(response, mode: idFormat)))

        case "list-windows":
            let response = try sendV1Command("list_windows", client: client)
            if jsonOutput {
                let windows = parseWindows(response)
                let payload = windows.map { item -> [String: Any] in
                    var dict: [String: Any] = [
                        "index": item.index,
                        "id": item.id,
                        "key": item.key,
                        "workspace_count": item.workspaceCount,
                    ]
                    dict["selected_workspace_id"] = item.selectedWorkspaceId ?? NSNull()
                    return dict
                }
                print(jsonString(payload))
            } else {
                print(response)
            }

        case "current-window":
            let response = try sendV1Command("current_window", client: client)
            if jsonOutput {
                print(jsonString(["window_id": response]))
            } else {
                print(response)
            }

        case "new-window":
            let response = try sendV1Command("new_window", client: client)
            print(response)

        case "focus-window":
            guard let target = optionValue(commandArgs, name: "--window"), let windowID = try normalizeWindowHandle(target, client: client) else {
                throw CLIError(message: "focus-window requires --window")
            }
            let response = try sendV1Command("focus_window \(windowID)", client: client)
            print(response)

        case "close-window":
            guard let target = optionValue(commandArgs, name: "--window"), let windowID = try normalizeWindowHandle(target, client: client) else {
                throw CLIError(message: "close-window requires --window")
            }
            let response = try sendV1Command("close_window \(windowID)", client: client)
            print(response)

        case "move-workspace-to-window":
            guard let workspaceRaw = optionValue(commandArgs, name: "--workspace") else {
                throw CLIError(message: "move-workspace-to-window requires --workspace")
            }
            guard let windowRaw = optionValue(commandArgs, name: "--window") else {
                throw CLIError(message: "move-workspace-to-window requires --window")
            }
            var params: [String: Any] = [:]
            let wsId = try normalizeWorkspaceHandle(workspaceRaw, client: client)
            if let wsId { params["workspace_id"] = wsId }
            let winId = try normalizeWindowHandle(windowRaw, client: client)
            if let winId { params["window_id"] = winId }
            let payload = try client.sendV2(method: "workspace.move_to_window", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["workspace", "window"]))

        case "move-surface":
            try runMoveSurface(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat)

        case "split-off":
            try runSplitOff(commandName: "split-off", commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat)

        case "reorder-surface":
            try runReorderSurface(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat)

        case "reorder-workspace":
            try runReorderWorkspace(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat)

        case "reorder-workspaces":
            try runReorderWorkspaces(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat)

        case "simulate-sidebar-drag":
            try runSimulateSidebarDrag(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat)

        case "workspace-action":
            try runWorkspaceAction(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat, windowOverride: windowId)
        case "tab-action":
            try runTabAction(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat, windowOverride: windowId)
        case "move-tab-to-new-workspace", "detach-tab":
            try runMoveTabToNewWorkspace(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat, windowOverride: windowId)
        case "rename-tab":
            try runRenameTab(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat, windowOverride: windowId)

        case "workspace-group":
            try runWorkspaceGroup(
                commandArgs: commandArgs,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowId
            )

        case "window":
            try runWindowNamespace(
                commandArgs: commandArgs,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowId
            )

        case "canvas":
            try runCanvasNamespace(
                commandArgs: commandArgs,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat
            )

        case "workspace":
            try runWorkspaceNamespace(
                commandArgs: commandArgs,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowId
            )

        case "todo":
            try runTodoNamespace(
                commandArgs: commandArgs,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowId
            )

        case "layout": try runLayoutNamespace(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat, windowOverride: windowId)

        case "list-workspaces":
            Self.warnLegacyVerbDeprecated("list-workspaces", replacement: "cmux workspace list")
            try runWorkspaceListCommand(
                commandArgs: commandArgs,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowId
            )

        case "ssh":
            try runSSH(
                commandArgs: commandArgs,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowId
            )
        case "ssh-tmux":
            try runRemoteTmux(
                commandArgs: commandArgs,
                client: client,
                jsonOutput: jsonOutput
            )
        case "ssh-pty-attach":
            let (requestedLifecycleID, attachArgsWithoutLifecycle) = parseOption(commandArgs, name: "--lifecycle-id")
            let stableLifecycleID = Self.normalizedEnvValue(requestedLifecycleID) ?? UUID().uuidString.lowercased()
            let stableAttachArgs = attachArgsWithoutLifecycle + ["--lifecycle-id", stableLifecycleID]
            do {
                try runSSHPTYAttach(commandArgs: stableAttachArgs, client: client, explicitPassword: socketPasswordArg)
            } catch let error as CLIError
                where error.exitCode == SSHPTYAttachExitCode.sessionNotFound.rawValue &&
                stableAttachArgs.contains("--require-existing") {
                let notice = String(
                    localized: "cli.sshPtyAttach.remoteSessionLostRespawn",
                    defaultValue: "[cmux] remote session was lost; starting a new shell."
                )
                cliWriteStderr(Data((notice + "\n").utf8))
                try runSSHPTYAttach(
                    commandArgs: stableAttachArgs.filter { $0 != "--require-existing" },
                    client: client,
                    explicitPassword: socketPasswordArg
                )
            }
        case "ssh-session-list":
            try runSSHSessionList(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat)
        case "ssh-session-attach":
            try runSSHSessionAttach(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat)
        case "ssh-session-cleanup":
            try runSSHSessionCleanup(commandArgs: commandArgs, client: client, jsonOutput: jsonOutput, idFormat: idFormat)
