        }
        } catch {
            if !capturesSocketErrorsInsideCommand {
                captureSocketTransportError(telemetry: cliTelemetry, stage: "socket_command", error: error, client: client)
            }
            throw error
        }
    }

    /// Validates a `cmux markdown open --font-size <points>` value. The viewer
    /// clamps the rendered size to 8...96 points, so reject anything outside
    /// that range here instead of silently clamping the user's input.
    private func parseMarkdownViewerFontSize(_ rawValue: String) throws -> Double {
        let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let size = Double(trimmed), size >= 8, size <= 96 else {
            throw CLIError(message: "--font-size must be a number between 8 and 96")
        }
        return (size * 100).rounded() / 100
    }

    func resolvePath(_ path: String) -> String {
        let expanded = NSString(string: path).expandingTildeInPath
        if expanded.hasPrefix("/") { return expanded }
        let cwd = FileManager.default.currentDirectoryPath
        return (cwd as NSString).appendingPathComponent(expanded)
    }

    private func sanitizedFilenameComponent(_ raw: String) -> String {
        let sanitized = raw.replacingOccurrences(
            of: #"[^\p{L}\p{N}._-]+"#,
            with: "-",
            options: .regularExpression
        )
        let trimmed = sanitized.trimmingCharacters(in: CharacterSet(charactersIn: "-."))
        return trimmed.isEmpty ? "item" : trimmed
    }

    private func bestEffortPruneTemporaryFiles(
        in directoryURL: URL,
        keepingMostRecent maxCount: Int = 50,
        maxAge: TimeInterval = 24 * 60 * 60
    ) {
        guard let entries = try? FileManager.default.contentsOfDirectory(
            at: directoryURL,
            includingPropertiesForKeys: [.isRegularFileKey, .contentModificationDateKey, .creationDateKey],
            options: [.skipsHiddenFiles]
        ) else {
            return
        }

        let now = Date()
        let datedEntries = entries.compactMap { url -> (url: URL, date: Date)? in
            guard let values = try? url.resourceValues(forKeys: [.isRegularFileKey, .contentModificationDateKey, .creationDateKey]),
                  values.isRegularFile == true else {
                return nil
            }
            return (url, values.contentModificationDate ?? values.creationDate ?? .distantPast)
        }.sorted { $0.date > $1.date }

        for (index, entry) in datedEntries.enumerated() {
            if index >= maxCount || now.timeIntervalSince(entry.date) > maxAge {
                try? FileManager.default.removeItem(at: entry.url)
            }
        }
    }

    // MARK: - Markdown Commands

    private func runMarkdownCommand(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        var args = commandArgs

        // Parse routing flags
        let (workspaceOpt, argsAfterWorkspace) = parseOption(args, name: "--workspace")
        let (windowOpt, argsAfterWindow) = parseOption(argsAfterWorkspace, name: "--window")
        let (surfaceOpt, argsAfterSurface) = parseOption(argsAfterWindow, name: "--surface")
        let (directionOpt, argsAfterDirection) = parseOption(argsAfterSurface, name: "--direction")
        let (focusOpt, argsAfterFocus) = parseOption(argsAfterDirection, name: "--focus")
        let (fontSizeOpt, argsAfterFontSize) = parseOption(argsAfterFocus, name: "--font-size")
        args = argsAfterFontSize

        let fontSize = try fontSizeOpt.map(parseMarkdownViewerFontSize)

        // Determine subcommand. Explicit "open" is supported, otherwise treat
        // a single positional argument as shorthand path.
        let subArgs: [String]
        if let first = args.first, first.lowercased() == "open" {
            subArgs = Array(args.dropFirst())
        } else if args.count == 1, let first = args.first, !first.hasPrefix("-") {
            subArgs = [first]
        } else {
            // Allow path-like first tokens (e.g. plan.md) with trailing args
            // so we can surface specific trailing-arg/flag errors below.
            if let first = args.first, first.hasPrefix("-") {
                throw CLIError(
                    message:
                        "markdown open: unknown flag '\(first)'. Usage: cmux markdown open <path> [--workspace <id|ref|index>] [--surface <id|ref|index>] [--window <id|ref|index>] [--direction right|down|left|up] [--focus <true|false>] [--font-size <points>]"
                )
            } else if let first = args.first, looksLikePath(first) || first.contains(".") {
                subArgs = args
            } else if let first = args.first {
                throw CLIError(message: "Unknown markdown subcommand: \(first). Usage: cmux markdown open <path>")
            } else {
                subArgs = []
            }
        }

        guard let rawPath = subArgs.first, !rawPath.isEmpty else {
            throw CLIError(message: "markdown open requires a file path. Usage: cmux markdown open <path>")
        }
        let trailingArgs = Array(subArgs.dropFirst())
        if let unknownFlag = trailingArgs.first(where: { $0.hasPrefix("-") }) {
            throw CLIError(
                message:
                    "markdown open: unknown flag '\(unknownFlag)'. Usage: cmux markdown open <path> [--workspace <id|ref|index>] [--surface <id|ref|index>] [--window <id|ref|index>] [--direction right|down|left|up] [--focus <true|false>] [--font-size <points>]"
            )
        }
        if let extraArg = trailingArgs.first {
            throw CLIError(
                message:
                    "markdown open: unexpected argument '\(extraArg)'. Usage: cmux markdown open <path> [--workspace <id|ref|index>] [--surface <id|ref|index>] [--window <id|ref|index>] [--direction right|down|left|up] [--focus <true|false>] [--font-size <points>]"
            )
        }

        let absolutePath = resolvePath(rawPath)

        // Build params
        let direction = directionOpt ?? "right"
        var params: [String: Any] = ["path": absolutePath, "direction": direction]
        if let fontSize {
            params["font_size"] = fontSize
        }
        if let surfaceRaw = surfaceOpt {
            if let surface = try normalizeSurfaceHandle(surfaceRaw, client: client) {
                params["surface_id"] = surface
            }
        }
        let workspaceRaw = workspaceOpt ?? (windowOpt == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)
        if let workspaceRaw {
            if let workspace = try normalizeWorkspaceHandle(workspaceRaw, client: client) {
                params["workspace_id"] = workspace
            }
        }
        if let windowRaw = windowOpt {
            if let window = try normalizeWindowHandle(windowRaw, client: client) {
                params["window_id"] = window
            }
        }
        try applyFocusOption(focusOpt, defaultValue: false, to: &params)

        let payload = try client.sendV2(method: "markdown.open", params: params)

        if jsonOutput {
            print(jsonString(formatIDs(payload, mode: idFormat)))
        } else {
            let surfaceText = formatHandle(payload, kind: "surface", idFormat: idFormat) ?? "unknown"
            let paneText = formatHandle(payload, kind: "pane", idFormat: idFormat) ?? "unknown"
            let filePath = (payload["path"] as? String) ?? absolutePath
            print("OK surface=\(surfaceText) pane=\(paneText) path=\(filePath)")
        }
    }

    private func runProjectCommand(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        var args = commandArgs
        let (workspaceOpt, argsAfterWorkspace) = parseOption(args, name: "--workspace")
        let (windowOpt, argsAfterWindow) = parseOption(argsAfterWorkspace, name: "--window")
        let (focusOpt, argsAfterFocus) = parseOption(argsAfterWindow, name: "--focus")
        args = argsAfterFocus

        // Treat first token as subcommand if it's "open", else require it.
        guard let first = args.first?.lowercased() else {
            throw CLIError(message: "project requires a subcommand. Usage: cmux project open <path-to-.xcodeproj-or-.xcworkspace>")
        }
        let subArgs: [String]
        if first == "open" {
            subArgs = Array(args.dropFirst())
        } else if args.count == 1 {
            subArgs = args
        } else {
            throw CLIError(message: "Unknown project subcommand: \(first). Usage: cmux project open <path>")
        }

        guard let rawPath = subArgs.first, !rawPath.isEmpty else {
            throw CLIError(message: "project open requires a path. Usage: cmux project open <path-to-.xcodeproj-or-.xcworkspace>")
        }
        let absolutePath = resolvePath(rawPath)
        var params: [String: Any] = ["path": absolutePath]
        let workspaceRaw = workspaceOpt ?? (windowOpt == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)
        if let workspaceRaw {
            if let workspace = try normalizeWorkspaceHandle(workspaceRaw, client: client) {
                params["workspace_id"] = workspace
            }
        }
        if let windowRaw = windowOpt {
            if let window = try normalizeWindowHandle(windowRaw, client: client) {
                params["window_id"] = window
            }
        }
        try applyFocusOption(focusOpt, defaultValue: true, to: &params)

        let payload = try client.sendV2(method: "project.open", params: params)

        if jsonOutput {
            print(jsonString(formatIDs(payload, mode: idFormat)))
        } else {
            let surfaceText = formatHandle(payload, kind: "surface", idFormat: idFormat) ?? "unknown"
            let paneText = formatHandle(payload, kind: "pane", idFormat: idFormat) ?? "unknown"
            let path = (payload["path"] as? String) ?? absolutePath
            print("OK surface=\(surfaceText) pane=\(paneText) project=\(path)")
        }
    }

    /// Returns true if the argument looks like a filesystem path rather than a CLI command.
    private func looksLikePath(_ arg: String) -> Bool {
        if arg == "." || arg == ".." { return true }
        if arg.hasPrefix("/") || arg.hasPrefix("./") || arg.hasPrefix("../") || arg.hasPrefix("~") { return true }
        if arg.contains("/") { return true }
        return false
    }

    private func shouldOpenAsPathArgument(_ arg: String) -> Bool {
        if looksLikePath(arg) {
            return true
        }
        guard !arg.hasPrefix("-"),
              !Self.topLevelCommandNames.contains(arg) else {
            return false
        }
        return FileManager.default.fileExists(atPath: resolvePath(arg))
    }

    /// Open a path in cmux by asking LaunchServices to deliver a directory URL to the app.
    private func openPath(_ path: String) throws {
        let directory = try directoryForPathOpen(path)
        try openDirectoryWithLaunchServices(directory)
        print(String(localized: "common.ok", defaultValue: "OK"))
    }

    /// Open a path through an explicitly selected socket, preserving deliberate instance routing.
    private func openPathViaExplicitSocket(_ path: String, socketPath: String, explicitPassword: String?) throws {
        let directory = try directoryForPathOpen(path)
        let client = try connectClient(
            socketPath: socketPath,
            explicitPassword: explicitPassword,
            launchIfNeeded: true
        )
        defer { client.close() }

        let response = try client.sendV2(method: "workspace.create", params: ["cwd": directory])
        let wsRef = (response["workspace_ref"] as? String) ?? (response["workspace_id"] as? String) ?? ""
        let okText = String(localized: "common.ok", defaultValue: "OK")
        print(wsRef.isEmpty ? okText : "\(okText) \(wsRef)")
        try activateApp()
    }

    private func directoryForPathOpen(_ path: String) throws -> String {
        let resolved = URL(fileURLWithPath: resolvePath(path)).standardizedFileURL.path
        var isDir: ObjCBool = false
        let exists = FileManager.default.fileExists(atPath: resolved, isDirectory: &isDir)

        if exists && isDir.boolValue {
            return resolved
        }
        if exists {
            return (resolved as NSString).deletingLastPathComponent
        }

        throw CLIError(message: localizedFormat("cli.pathOpen.error.pathDoesNotExist", defaultValue: "Path does not exist: %@", resolved))
    }

    private func openDirectoryWithLaunchServices(_ directory: String) throws {
        try runOpenTool(
            arguments: ["-a", appLaunchTarget(), directory],
            failureMessage: localizedFormat("cli.pathOpen.error.openFailed", defaultValue: "Failed to open %@ in cmux", directory),
            environment: launchServicesPathOpenEnvironment()
        )
    }

    private func runOpenTool(
        arguments: [String],
        failureMessage: String,
        environment: [String: String]? = nil
    ) throws {
        let process = Process()
        process.executableURL = URL(fileURLWithPath: openToolPath())
        process.arguments = arguments
        if let environment {
            process.environment = environment
        }
        process.standardOutput = FileHandle.nullDevice
        process.standardError = FileHandle.nullDevice

        try process.run()

        if try !waitForProcessExit(process, timeout: 10) {
            process.terminate()
            if try !waitForProcessExit(process, timeout: 1) {
                kill(process.processIdentifier, SIGKILL)
                _ = try? waitForProcessExit(process, timeout: 1)
            }
            throw CLIError(message: localizedFormat("cli.pathOpen.error.timedOut", defaultValue: "%@ (timed out)", failureMessage))
        }

        guard process.terminationStatus == 0 else {
            throw CLIError(message: failureMessage)
        }
    }

    private static let launchServicesPathOpenScrubbedEnvironmentKeys: Set<String> = [
        "CMUX_ALLOW_SOCKET_OVERRIDE",
        "CMUX_SOCKET",
        "CMUX_SOCKET_ENABLE",
        "CMUX_SOCKET_MODE",
        "CMUX_SOCKET_PASSWORD",
        "CMUX_SOCKET_PATH",
        "CMUX_PANEL_ID",
        "CMUX_SURFACE_ID",
        "CMUX_TAB_ID",
        "CMUX_WORKSPACE_ID",
    ]

    private func launchServicesPathOpenEnvironment() -> [String: String] {
        var environment = ProcessInfo.processInfo.environment
        for key in Self.launchServicesPathOpenScrubbedEnvironmentKeys {
            environment.removeValue(forKey: key)
        }
        return environment
    }

    func waitForProcessExit(_ process: Process, timeout: TimeInterval) throws -> Bool {
        if !process.isRunning {
            process.waitUntilExit()
            return true
        }

        let queue = kqueue()
        guard queue >= 0 else {
            throw CLIError(message: String(localized: "cli.pathOpen.error.processMonitorFailed", defaultValue: "Failed to monitor process exit"))
        }
        defer { close(queue) }

        var event = kevent(
            ident: UInt(process.processIdentifier),
            filter: Int16(EVFILT_PROC),
            flags: UInt16(EV_ADD | EV_ENABLE | EV_ONESHOT),
            fflags: UInt32(NOTE_EXIT),
            data: 0,
            udata: nil
        )
        guard kevent(queue, &event, 1, nil, 0, nil) == 0 else {
            if errno == ESRCH {
                process.waitUntilExit()
                return true
            }
            throw CLIError(message: String(localized: "cli.pathOpen.error.processMonitorFailed", defaultValue: "Failed to monitor process exit"))
        }

        let deadline = Date().addingTimeInterval(timeout)
        while true {
            let remaining = deadline.timeIntervalSinceNow
            guard remaining > 0 else {
                return false
            }

            var timeoutSpec = timespec(
                tv_sec: Int(remaining),
                tv_nsec: Int((remaining - floor(remaining)) * 1_000_000_000)
            )
            var triggeredEvent = kevent()
            let result = kevent(queue, nil, 0, &triggeredEvent, 1, &timeoutSpec)
            if result > 0 {
                process.waitUntilExit()
                return true
            }
            if result == 0 {
                return false
            }
            if errno != EINTR {
                throw CLIError(message: String(localized: "cli.pathOpen.error.processMonitorFailed", defaultValue: "Failed to monitor process exit"))
            }
        }
    }

    private func localizedFormat(_ key: String, defaultValue: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, bundle: .main, value: defaultValue, comment: "")
        return String(format: format, locale: Locale.current, arguments: arguments)
    }

    private func openToolPath() -> String {
#if DEBUG
        if let override = ProcessInfo.processInfo.environment["CMUX_TEST_OPEN_TOOL_PATH"]?
            .trimmingCharacters(in: .whitespacesAndNewlines),
           !override.isEmpty {
            return NSString(string: override).expandingTildeInPath
        }
#endif
        return "/usr/bin/open"
    }

    private func appLaunchTarget() -> String {
        CLIExecutableLocator.enclosingAppBundle()?.bundleURL.path ?? "cmux"
    }

    private func runFeedback(
        commandArgs: [String],
        socketPath: String,
        explicitPassword: String?,
        jsonOutput: Bool
    ) throws {
        let (emailOpt, rem0) = parseOption(commandArgs, name: "--email")
        let (bodyOpt, rem1) = parseOption(rem0, name: "--body")
        let (imagePaths, rem2) = parseRepeatedOption(rem1, name: "--image")
        let remaining = rem2.filter { $0 != "--" }

        if let unknown = remaining.first {
            throw CLIError(message: "feedback: unknown flag '\(unknown)'. Known flags: --email <email>, --body <text>, --image <path>")
        }

        let client = try connectClient(
            socketPath: socketPath,
            explicitPassword: explicitPassword,
            launchIfNeeded: true
        )
        defer { client.close() }

        if emailOpt == nil && bodyOpt == nil && imagePaths.isEmpty {
            var params: [String: Any] = [:]
            let env = ProcessInfo.processInfo.environment
            if let workspaceId = env["CMUX_WORKSPACE_ID"]?.trimmingCharacters(in: .whitespacesAndNewlines),
               !workspaceId.isEmpty {
                params["workspace_id"] = workspaceId
                params["activate"] = false
            } else {
                params["activate"] = true
            }
            let response = try client.sendV2(method: "feedback.open", params: params)
            if jsonOutput {
                print(jsonString(response))
            } else {
                print("OK")
            }
            return
        }

        guard let email = emailOpt?.trimmingCharacters(in: .whitespacesAndNewlines),
              email.isEmpty == false else {
            throw CLIError(message: "feedback requires --email <email> when sending feedback")
        }
        guard let body = bodyOpt, body.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false else {
            throw CLIError(message: "feedback requires --body <text> when sending feedback")
        }

        let resolvedImages = imagePaths.map(resolvePath)
        let response = try client.sendV2(method: "feedback.submit", params: [
            "email": email,
            "body": body,
            "image_paths": resolvedImages,
        ])
        if jsonOutput {
            print(jsonString(response))
        } else {
            print("OK")
        }
    }

    private func runRestoreSession(
        commandArgs: [String],
        socketPath: String,
        explicitPassword: String?,
        jsonOutput: Bool
    ) throws {
        let remaining = commandArgs.filter { $0 != "--" }
        if let unknown = remaining.first {
            throw CLIError(message: "restore-session: unknown flag '\(unknown)'")
        }

        let initialClient = SocketClient(path: socketPath)
        let client: SocketClient
        let launched: Bool
        if (try? initialClient.connect()) == nil {
            initialClient.close()
            try launchApp()
            client = try SocketClient.waitForConnectableSocket(path: socketPath, timeout: 10)
            launched = true
        } else {
            client = initialClient
            launched = false
        }

        defer { client.close() }
        try authenticateClientIfNeeded(
            client,
            explicitPassword: explicitPassword,
            socketPath: socketPath
        )

        let response = try client.sendV2(method: "session.restore_previous")
        if jsonOutput {
            var payload = response
            payload["launched"] = launched
            print(jsonString(payload))
        } else {
            print("OK")
        }
    }

    func connectClient(
        socketPath: String,
        explicitPassword: String?,
        launchIfNeeded: Bool
    ) throws -> SocketClient {
        let client = SocketClient(path: socketPath)
        if launchIfNeeded && (try? client.connect()) == nil {
            client.close()
            try launchApp()
            let launchedClient = try SocketClient.waitForConnectableSocket(path: socketPath, timeout: 10)
            try authenticateClientIfNeeded(
                launchedClient,
                explicitPassword: explicitPassword,
                socketPath: socketPath
            )
            return launchedClient
        }

        try client.connect()
        try authenticateClientIfNeeded(
            client,
            explicitPassword: explicitPassword,
            socketPath: socketPath
        )
        return client
    }

    func authenticateClientIfNeeded(
        _ client: SocketClient,
        explicitPassword: String?,
        socketPath: String,
        responseTimeout: TimeInterval? = nil
    ) throws {
        try Self.authenticateSocketClientIfNeeded(
            client,
            explicitPassword: explicitPassword,
            socketPath: socketPath,
            responseTimeout: responseTimeout
        )
    }

    static func authenticateSocketClientIfNeeded(
        _ client: SocketClient,
        explicitPassword: String?,
        socketPath: String,
        responseTimeout: TimeInterval? = nil
    ) throws {
        if let socketPassword = SocketPasswordResolver.resolve(
            explicit: explicitPassword,
            socketPath: socketPath
        ) {
            let authResponse = try client.send(command: "auth \(socketPassword)", responseTimeout: responseTimeout)
            if authResponse.hasPrefix("ERROR:"),
               !authResponse.contains("Unknown command 'auth'") {
                throw CLIError(message: authResponse)
            }
        }
    }

    private func launchApp() throws {
        try runOpenTool(
            arguments: ["-a", appLaunchTarget()],
            failureMessage: String(localized: "cli.pathOpen.error.launchFailed", defaultValue: "Failed to launch cmux")
        )
    }

    private func activateApp() throws {
        try runOpenTool(
            arguments: ["-a", appLaunchTarget()],
            failureMessage: String(localized: "cli.pathOpen.error.activateFailed", defaultValue: "Failed to activate cmux")
        )
    }

    private func resolvedIDFormat(jsonOutput: Bool, raw: String?) throws -> CLIIDFormat {
        _ = jsonOutput
        if let parsed = try CLIIDFormat.parse(raw) {
            return parsed
        }
        return .refs
    }

    func sendV1Command(_ command: String, client: SocketClient) throws -> String {
        let response = try client.send(command: command)
        if response.hasPrefix("ERROR:") {
            throw CLIError(message: response)
        }
        return response
    }

    func formatIDs(_ object: Any, mode: CLIIDFormat) -> Any {
        switch object {
        case let dict as [String: Any]:
            var out: [String: Any] = [:]
            for (k, v) in dict {
                out[k] = formatIDs(v, mode: mode)
            }

            switch mode {
            case .both:
                break
            case .refs:
                if out["ref"] != nil && out["id"] != nil {
                    out.removeValue(forKey: "id")
                }
                let keys = Array(out.keys)
                for key in keys where key.hasSuffix("_id") {
                    let prefix = String(key.dropLast(3))
                    if out["\(prefix)_ref"] != nil {
                        out.removeValue(forKey: key)
                    }
                }
                for key in keys where key.hasSuffix("_ids") {
                    let prefix = String(key.dropLast(4))
                    if out["\(prefix)_refs"] != nil {
                        out.removeValue(forKey: key)
                    }
                }
            case .uuids:
                if out["id"] != nil && out["ref"] != nil {
                    out.removeValue(forKey: "ref")
                }
                let keys = Array(out.keys)
                for key in keys where key.hasSuffix("_ref") {
                    let prefix = String(key.dropLast(4))
                    if out["\(prefix)_id"] != nil {
                        out.removeValue(forKey: key)
                    }
                }
                for key in keys where key.hasSuffix("_refs") {
                    let prefix = String(key.dropLast(5))
                    if out["\(prefix)_ids"] != nil {
                        out.removeValue(forKey: key)
                    }
                }
            }
            return out

        case let array as [Any]:
            return array.map { formatIDs($0, mode: mode) }

        default:
            return object
        }
    }

    func intFromAny(_ value: Any?) -> Int? {
        if let i = value as? Int { return i }
        if let n = value as? NSNumber { return n.intValue }
        if let s = value as? String { return Int(s) }
        return nil
    }

    private func doubleFromAny(_ value: Any?) -> Double? {
        if let d = value as? Double { return d }
        if let f = value as? Float { return Double(f) }
        if let n = value as? NSNumber { return n.doubleValue }
        if let s = value as? String { return Double(s) }
        return nil
    }

    func boolFromAny(_ value: Any?) -> Bool? {
        if let bool = value as? Bool { return bool }
        if let number = value as? NSNumber {
            let numeric = number.doubleValue
            if numeric == 0 { return false }
            if numeric == 1 { return true }
            return nil
        }
        if let string = value as? String {
            return parseBoolString(string.trimmingCharacters(in: .whitespacesAndNewlines))
        }
        return nil
    }

    func parseBoolString(_ raw: String) -> Bool? {
        switch raw.lowercased() {
        case "1", "true", "yes", "on":
            return true
        case "0", "false", "no", "off":
            return false
        default:
            return nil
        }
    }

    private func parsePositiveInt(_ raw: String?, label: String) throws -> Int? {
        guard let raw else { return nil }
        guard let value = Int(raw) else {
            throw CLIError(message: "\(label) must be an integer")
        }
        return value
    }

    private func isHandleRef(_ value: String) -> Bool {
        let pieces = value.split(separator: ":", omittingEmptySubsequences: false)
        guard pieces.count == 2 else { return false }
        let kind = String(pieces[0]).lowercased()
        guard ["window", "workspace", "pane", "surface"].contains(kind) else { return false }
        return Int(String(pieces[1])) != nil
    }

    func normalizeWindowHandle(_ raw: String?, client: SocketClient, allowCurrent: Bool = false) throws -> String? {
        guard let raw else {
            if !allowCurrent { return nil }
            let current = try client.sendV2(method: "window.current")
            return (current["window_ref"] as? String) ?? (current["window_id"] as? String)
        }

        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty { return nil }
        if isUUID(trimmed) {
            return trimmed
        }
        if isHandleRef(trimmed) {
            if let matched = try matchingWindowHandle(trimmed, client: client) {
                return matched
            }
            throw CLIError(message: "Window not found: \(trimmed)")
        }
        guard let wantedIndex = Int(trimmed) else {
            throw CLIError(message: "Invalid window handle: \(trimmed) (expected UUID, ref like window:1, or index)")
        }

        let listed = try client.sendV2(method: "window.list")
        let windows = listed["windows"] as? [[String: Any]] ?? []
        for item in windows where intFromAny(item["index"]) == wantedIndex {
            return (item["id"] as? String) ?? (item["ref"] as? String)
        }
        throw CLIError(message: "Window index not found")
    }

    private func matchingWindowHandle(_ handle: String, client: SocketClient) throws -> String? {
        let listed = try client.sendV2(method: "window.list")
        let windows = listed["windows"] as? [[String: Any]] ?? []
        for window in windows where windowHandleMatches(handle, item: window) {
            return (window["id"] as? String) ?? (window["ref"] as? String) ?? handle
        }
        return nil
    }

    private func windowHandleMatches(_ handle: String, item: [String: Any]) -> Bool {
        guard let target = normalizedHandleValue(handle) else { return false }
        for candidate in [item["id"] as? String, item["ref"] as? String] {
            guard let candidate = normalizedHandleValue(candidate) else { continue }
            if handlesMatch(target, candidate) {
                return true
            }
        }
        return false
    }

    func validatedWindowHandle(_ raw: String?, client: SocketClient) throws -> String? {
        guard let raw else { return nil }
        guard let normalized = try normalizeWindowHandle(raw, client: client) else { return nil }

        let listed = try client.sendV2(method: "window.list")
        let windows = listed["windows"] as? [[String: Any]] ?? []
        let found = windows.contains { item in
            windowHandleMatches(normalized, item: item)
        }
        guard found else {
            throw CLIError(message: "Window not found: \(raw)")
        }
        return normalized
    }

    func normalizeWorkspaceHandle(
        _ raw: String?,
        client: SocketClient,
        windowHandle: String? = nil,
        allowCurrent: Bool = false
    ) throws -> String? {
        guard let raw else {
            if !allowCurrent { return nil }
            // Prefer the caller's own workspace before the focused one (see
            // resolveWorkspaceId). After the !allowCurrent guard, so explicit-surface
            // routing (allowCurrent: false, resolves globally) is unaffected.
            if let callerWorkspaceId = callerWorkspaceIdFromEnvironment(windowHandle: windowHandle) {
                return callerWorkspaceId
            }
            let current: [String: Any]
            if let windowHandle {
                current = try client.sendV2(method: "workspace.current", params: ["window_id": windowHandle])
            } else {
                current = try client.sendV2(method: "workspace.current")
            }
            return (current["workspace_id"] as? String) ?? (current["workspace_ref"] as? String)
        }

        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty { return nil }
        if isUUID(trimmed) {
            return trimmed
        }
        if isHandleRef(trimmed) {
            guard windowHandle != nil else { return trimmed }
            return try resolveWorkspaceId(trimmed, client: client, windowHandle: windowHandle)
        }
        guard let wantedIndex = Int(trimmed) else {
            throw CLIError(message: "Invalid workspace handle: \(trimmed) (expected UUID, ref like workspace:1, or index)")
        }

        var params: [String: Any] = [:]
        if let windowHandle {
            params["window_id"] = windowHandle
        }
        let listed = try client.sendV2(method: "workspace.list", params: params)
        let items = listed["workspaces"] as? [[String: Any]] ?? []
        for item in items where intFromAny(item["index"]) == wantedIndex {
            return (item["id"] as? String) ?? (item["ref"] as? String)
        }
        throw CLIError(message: "Workspace index not found")
    }

    func normalizePaneHandle(
        _ raw: String?,
        client: SocketClient,
        workspaceHandle: String? = nil,
        windowHandle: String? = nil,
        allowFocused: Bool = false
    ) throws -> String? {
        guard let raw else {
            if !allowFocused { return nil }
            if workspaceHandle != nil { return nil }
            let params: [String: Any] = windowHandle.map { ["window_id": $0] } ?? [:]
            let ident = try client.sendV2(method: "system.identify", params: params)
            let focused = ident["focused"] as? [String: Any] ?? [:]
            return (focused["pane_id"] as? String) ?? (focused["pane_ref"] as? String)
        }

        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty { return nil }
        if isUUID(trimmed) || isHandleRef(trimmed) {
            if let windowHandle {
                return try validatePaneHandleInWindow(
                    trimmed,
                    client: client,
                    workspaceHandle: workspaceHandle,
                    windowHandle: windowHandle
                )
            }
            return trimmed
        }
        guard let wantedIndex = Int(trimmed) else {
            throw CLIError(message: "Invalid pane handle: \(trimmed) (expected UUID, ref like pane:1, or index)")
        }

        var params: [String: Any] = [:]
        if let workspaceHandle {
            params["workspace_id"] = workspaceHandle
        }
        if let windowHandle {
            params["window_id"] = windowHandle
        }
        let listed = try client.sendV2(method: "pane.list", params: params)
        let items = listed["panes"] as? [[String: Any]] ?? []
        for item in items where intFromAny(item["index"]) == wantedIndex {
            return (item["id"] as? String) ?? (item["ref"] as? String)
        }
        throw CLIError(message: "Pane index not found")
    }

    private func validatePaneHandleInWindow(
        _ paneHandle: String,
        client: SocketClient,
        workspaceHandle: String?,
        windowHandle: String
    ) throws -> String {
        if let workspaceHandle {
            if let matched = try matchingPaneHandleInWorkspace(
                paneHandle,
                client: client,
                workspaceHandle: workspaceHandle,
                windowHandle: windowHandle
            ) {
                return matched
            }
            throw CLIError(message: "Pane not found in window")
        }

        let listed = try client.sendV2(method: "workspace.list", params: ["window_id": windowHandle])
        let workspaces = listed["workspaces"] as? [[String: Any]] ?? []
        for workspace in workspaces {
            guard let workspaceHandle = (workspace["id"] as? String) ?? (workspace["ref"] as? String) else {
                continue
            }
            if let matched = try matchingPaneHandleInWorkspace(
                paneHandle,
                client: client,
                workspaceHandle: workspaceHandle,
                windowHandle: windowHandle
            ) {
                return matched
            }
        }
        throw CLIError(message: "Pane not found in window")
    }

    private func matchingPaneHandleInWorkspace(
        _ paneHandle: String,
        client: SocketClient,
        workspaceHandle: String,
        windowHandle: String
    ) throws -> String? {
        let listed = try client.sendV2(
            method: "pane.list",
            params: [
                "workspace_id": workspaceHandle,
                "window_id": windowHandle,
            ]
        )
        let panes = listed["panes"] as? [[String: Any]] ?? []
        for pane in panes where paneHandleMatches(paneHandle, item: pane) {
            return (pane["id"] as? String) ?? (pane["ref"] as? String) ?? paneHandle
        }
        return nil
    }

    private func paneHandleMatches(_ handle: String, item: [String: Any]) -> Bool {
        guard let target = normalizedHandleValue(handle) else { return false }
        for candidate in [item["id"] as? String, item["ref"] as? String] {
            guard let candidate = normalizedHandleValue(candidate) else { continue }
            if handlesMatch(target, candidate) {
                return true
            }
        }
        return false
    }

    private func handlesMatch(_ lhs: String, _ rhs: String) -> Bool {
        if let lhsUUID = UUID(uuidString: lhs),
           let rhsUUID = UUID(uuidString: rhs) {
            return lhsUUID == rhsUUID
        }
        return lhs.lowercased() == rhs.lowercased()
    }

    func normalizeSurfaceHandle(
        _ raw: String?,
        client: SocketClient,
        workspaceHandle: String? = nil,
        windowHandle: String? = nil,
        allowFocused: Bool = false
    ) throws -> String? {
        guard let raw else {
            if !allowFocused { return nil }
            if workspaceHandle != nil { return nil }
            let params: [String: Any] = windowHandle.map { ["window_id": $0] } ?? [:]
            let ident = try client.sendV2(method: "system.identify", params: params)
            let focused = ident["focused"] as? [String: Any] ?? [:]
            return (focused["surface_id"] as? String) ?? (focused["surface_ref"] as? String)
        }

        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty { return nil }
        if isUUID(trimmed) || isHandleRef(trimmed) {
            if let windowHandle {
                return try validateSurfaceHandleInWindow(
                    trimmed,
                    client: client,
                    workspaceHandle: workspaceHandle,
                    windowHandle: windowHandle
                )
            }
            return trimmed
        }
        guard let wantedIndex = Int(trimmed) else {
            throw CLIError(message: "Invalid surface handle: \(trimmed) (expected UUID, ref like surface:1, or index)")
        }

        var params: [String: Any] = [:]
        if let windowHandle {
            params["window_id"] = windowHandle
        }
        if let workspaceHandle {
            params["workspace_id"] = workspaceHandle
        }
        let listed = try client.sendV2(method: "surface.list", params: params)
        let items = listed["surfaces"] as? [[String: Any]] ?? []
        for item in items where intFromAny(item["index"]) == wantedIndex {
            return (item["id"] as? String) ?? (item["ref"] as? String)
        }
        throw CLIError(message: "Surface index not found")
    }
    static func callerWorkspaceForSurfaceHandle(_ raw: String?, windowRaw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return windowRaw == nil && (trimmed.isEmpty || Int(trimmed) != nil) ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil
    }
    private func validateSurfaceHandleInWindow(
        _ surfaceHandle: String,
        client: SocketClient,
        workspaceHandle: String?,
        windowHandle: String
    ) throws -> String {
        if let workspaceHandle {
            if let matched = try matchingSurfaceHandleInWorkspace(
                surfaceHandle,
                client: client,
                workspaceHandle: workspaceHandle,
                windowHandle: windowHandle
            ) {
                return matched
            }
            throw CLIError(message: "Surface not found in window")
        }

        let listed = try client.sendV2(method: "workspace.list", params: ["window_id": windowHandle])
        let workspaces = listed["workspaces"] as? [[String: Any]] ?? []
        for workspace in workspaces {
            guard let workspaceHandle = (workspace["id"] as? String) ?? (workspace["ref"] as? String) else {
                continue
            }
            if let matched = try matchingSurfaceHandleInWorkspace(
                surfaceHandle,
                client: client,
                workspaceHandle: workspaceHandle,
                windowHandle: windowHandle
            ) {
                return matched
            }
        }
        throw CLIError(message: "Surface not found in window")
    }

    private func matchingSurfaceHandleInWorkspace(
        _ surfaceHandle: String,
        client: SocketClient,
        workspaceHandle: String,
        windowHandle: String
    ) throws -> String? {
        let listed = try client.sendV2(
            method: "surface.list",
            params: [
                "workspace_id": workspaceHandle,
                "window_id": windowHandle,
            ]
        )
        let surfaces = listed["surfaces"] as? [[String: Any]] ?? []
        for surface in surfaces where surfaceHandleMatches(surfaceHandle, item: surface) {
            return (surface["id"] as? String) ?? (surface["ref"] as? String) ?? surfaceHandle
        }
        return nil
    }

    private func surfaceHandleMatches(_ handle: String, item: [String: Any]) -> Bool {
        guard let target = normalizedHandleValue(handle) else { return false }
        for candidate in [item["id"] as? String, item["ref"] as? String] {
            guard let candidate = normalizedHandleValue(candidate) else { continue }
            if handlesMatch(target, candidate) {
                return true
            }
        }
        return false
    }

    private func canonicalSurfaceHandleFromTabInput(_ value: String) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        let pieces = trimmed.split(separator: ":", omittingEmptySubsequences: false)
        guard pieces.count == 2,
              String(pieces[0]).lowercased() == "tab",
              let ordinal = Int(String(pieces[1])) else {
            return trimmed
        }
        return "surface:\(ordinal)"
    }

    private func normalizeTabHandle(
        _ raw: String?,
        client: SocketClient,
        workspaceHandle: String? = nil,
        windowHandle: String? = nil,
        allowFocused: Bool = false
    ) throws -> String? {
        guard let raw else {
            return try normalizeSurfaceHandle(
                nil,
                client: client,
                workspaceHandle: workspaceHandle,
                windowHandle: windowHandle,
                allowFocused: allowFocused
            )
        }

        let canonical = canonicalSurfaceHandleFromTabInput(raw)
        return try normalizeSurfaceHandle(
            canonical,
            client: client,
            workspaceHandle: workspaceHandle,
            windowHandle: windowHandle,
            allowFocused: false
        )
    }

    private func displayTabHandle(_ raw: String?) -> String? {
        guard let raw else { return nil }
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        let pieces = trimmed.split(separator: ":", omittingEmptySubsequences: false)
        guard pieces.count == 2,
              String(pieces[0]).lowercased() == "surface",
              let ordinal = Int(String(pieces[1])) else {
            return trimmed
        }
        return "tab:\(ordinal)"
    }

    func formatHandle(_ payload: [String: Any], kind: String, idFormat: CLIIDFormat) -> String? {
        let id = payload["\(kind)_id"] as? String
        let ref = payload["\(kind)_ref"] as? String
        switch idFormat {
        case .refs:
            return ref ?? id
        case .uuids:
            return id ?? ref
        case .both:
            if let ref, let id {
                return "\(ref) (\(id))"
            }
            return ref ?? id
        }
    }

    private func formatTabHandle(_ payload: [String: Any], idFormat: CLIIDFormat) -> String? {
        let id = (payload["tab_id"] as? String) ?? (payload["surface_id"] as? String)
        let refRaw = (payload["tab_ref"] as? String) ?? (payload["surface_ref"] as? String)
        let ref = displayTabHandle(refRaw)
        switch idFormat {
        case .refs:
            return ref ?? id
        case .uuids:
            return id ?? ref
        case .both:
            if let ref, let id {
                return "\(ref) (\(id))"
            }
            return ref ?? id
        }
    }

    private func formatCreatedTabHandle(_ payload: [String: Any], idFormat: CLIIDFormat) -> String? {
        let id = (payload["created_tab_id"] as? String) ?? (payload["created_surface_id"] as? String)
        let refRaw = (payload["created_tab_ref"] as? String) ?? (payload["created_surface_ref"] as? String)
        let ref = displayTabHandle(refRaw)
        switch idFormat {
        case .refs:
            return ref ?? id
        case .uuids:
            return id ?? ref
        case .both:
            if let ref, let id {
                return "\(ref) (\(id))"
            }
            return ref ?? id
        }
    }

    func printV2Payload(
        _ payload: [String: Any],
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        fallbackText: String
    ) {
        if jsonOutput {
            print(jsonString(formatIDs(payload, mode: idFormat)))
        } else {
            print(fallbackText)
        }
    }

    private func runSurfaceCommand(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        guard let subcommand = commandArgs.first?.lowercased() else {
            throw CLIError(message: "surface requires a subcommand. Try: cmux surface resume show --json")
        }
        switch subcommand {
        case "resume":
            try runSurfaceResumeCommand(
                commandArgs: Array(commandArgs.dropFirst()),
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )
        default:
            throw CLIError(message: "Unsupported surface subcommand: \(subcommand)")
        }
    }

    private func runSurfaceResumeCommand(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        let subcommand = commandArgs.first?.lowercased() ?? "show"
        let rest = commandArgs.first == nil ? [] : Array(commandArgs.dropFirst())
        switch subcommand {
        case "set":
            try validateSurfaceResumeValueOptions(
                rest,
                optionNames: Self.surfaceResumeSetValueOptions,
                context: "surface resume set"
            )
            let target = try surfaceResumeTarget(rest, client: client, windowOverride: windowOverride)
            var params = target.params
            let splitRemaining = splitAtArgumentTerminator(target.remaining)
            let (name, rem1) = parseOption(splitRemaining.options, name: "--name")
            let (kind, rem2) = parseOption(rem1, name: "--kind")
            let (checkpoint, rem3) = parseOption(rem2, name: "--checkpoint")
            let (checkpointID, rem4) = parseOption(rem3, name: "--checkpoint-id")
            let (source, rem5) = parseOption(rem4, name: "--source")
            let (cwd, rem6) = parseOption(rem5, name: "--cwd")
            let (shellCommand, rem7) = parseOption(rem6, name: "--shell")

            if let name { params["name"] = name }
            if let kind { params["kind"] = kind }
            if let checkpoint = checkpointID ?? checkpoint { params["checkpoint_id"] = checkpoint }
            params["source"] = source ?? "cli"
            params["cwd"] = cwd ?? ProcessInfo.processInfo.environment["PWD"] ?? FileManager.default.currentDirectoryPath

            let commandText: String
            if let shellCommand {
                if let unexpected = (rem7 + (splitRemaining.argv ?? [])).first {
                    throw CLIError(message: "surface resume set: unexpected argument '\(unexpected)' after --shell. Quote the full shell command or use -- <argv...>")
                }
                commandText = shellCommand.trimmingCharacters(in: .whitespacesAndNewlines)
            } else {
                if splitRemaining.argv != nil, let unexpected = rem7.first {
                    throw CLIError(message: "surface resume set: unexpected argument '\(unexpected)' before --")
                }
                let argv = splitRemaining.argv ?? rem7
                guard !argv.isEmpty else {
                    throw CLIError(message: "surface resume set requires --shell <command> or -- <argv...>")
                }
                commandText = argv.map(cliShellQuote).joined(separator: " ")
            }
            guard !commandText.isEmpty else {
                throw CLIError(message: "surface resume set requires a non-empty command")
            }
            params["command"] = commandText

            let payload = try client.sendV2(method: "surface.resume.set", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: "OK")

        case "show", "get":
            try validateSurfaceResumeValueOptions(
                rest,
                optionNames: Self.surfaceResumeTargetValueOptions,
                context: "surface resume \(subcommand)"
            )
            let params = try surfaceResumeTarget(rest, client: client, windowOverride: windowOverride).params
            let payload = try client.sendV2(method: "surface.resume.get", params: params)
            if jsonOutput {
                print(jsonString(formatIDs(payload, mode: idFormat)))
            } else if let binding = payload["resume_binding"] as? [String: Any],
                      let command = binding["command"] as? String,
                      !command.isEmpty {
                print(command)
            } else {
                print("No resume binding")
            }

        case "clear":
            try validateSurfaceResumeValueOptions(
                rest,
                optionNames: Self.surfaceResumeClearValueOptions,
                context: "surface resume clear"
            )
            let target = try surfaceResumeTarget(rest, client: client, windowOverride: windowOverride)
            var params = target.params
            let (checkpoint, rem1) = parseOption(target.remaining, name: "--checkpoint")
            let (checkpointID, rem2) = parseOption(rem1, name: "--checkpoint-id")
            let (source, remaining) = parseOption(rem2, name: "--source")
            if let unexpected = remaining.first {
                throw CLIError(message: "surface resume clear: unexpected argument '\(unexpected)'")
            }
            if let checkpoint = checkpointID ?? checkpoint { params["checkpoint_id"] = checkpoint }
            if let source { params["source"] = source }
            let payload = try client.sendV2(method: "surface.resume.clear", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: "OK")

        default:
            throw CLIError(message: "Unsupported surface resume subcommand: \(subcommand)")
        }
    }

    private func validateSurfaceResumeCommandValueOptionsBeforeSocket(
        command: String,
        commandArgs: [String]
    ) throws {
        if command == "surface" {
            guard commandArgs.first?.lowercased() == "resume" else { return }
            try validateSurfaceResumeCommandValueOptions(Array(commandArgs.dropFirst()))
            return
        }
        if command == "surface-resume" {
            try validateSurfaceResumeCommandValueOptions(commandArgs)
        }
    }

    private func validateSurfaceResumeCommandValueOptions(_ commandArgs: [String]) throws {
        let subcommand = commandArgs.first?.lowercased() ?? "show"
        let rest = commandArgs.first == nil ? [] : Array(commandArgs.dropFirst())
        switch subcommand {
        case "set":
            try validateSurfaceResumeValueOptions(
                rest,
                optionNames: Self.surfaceResumeSetValueOptions,
                context: "surface resume set"
            )
            try validateSurfaceResumeSetCommandTokensBeforeSocket(rest)
        case "show", "get":
            try validateSurfaceResumeValueOptions(
                rest,
                optionNames: Self.surfaceResumeTargetValueOptions,
                context: "surface resume \(subcommand)"
            )
        case "clear":
            try validateSurfaceResumeValueOptions(
                rest,
                optionNames: Self.surfaceResumeClearValueOptions,
                context: "surface resume clear"
            )
        default:
            return
        }
    }

    private func validateSurfaceResumeSetCommandTokensBeforeSocket(_ args: [String]) throws {
        let splitArgs = splitAtArgumentTerminator(args)
        let (_, rem1) = parseOption(splitArgs.options, name: "--workspace")
        let (_, rem2) = parseOption(rem1, name: "--surface")
        let (_, rem3) = parseOption(rem2, name: "--window")
        let (_, rem4) = parseOption(rem3, name: "--name")
        let (_, rem5) = parseOption(rem4, name: "--kind")
        let (_, rem6) = parseOption(rem5, name: "--checkpoint")
        let (_, rem7) = parseOption(rem6, name: "--checkpoint-id")
        let (_, rem8) = parseOption(rem7, name: "--source")
        let (_, rem9) = parseOption(rem8, name: "--cwd")
        let (shellCommand, remaining) = parseOption(rem9, name: "--shell")

        if shellCommand != nil, let unexpected = (remaining + (splitArgs.argv ?? [])).first {
            throw CLIError(message: "surface resume set: unexpected argument '\(unexpected)' after --shell. Quote the full shell command or use -- <argv...>")
        }
        if splitArgs.argv != nil, let unexpected = remaining.first {
            throw CLIError(message: "surface resume set: unexpected argument '\(unexpected)' before --")
        }
    }

    private static let surfaceResumeTargetValueOptions: Set<String> = ["--workspace", "--surface", "--window"]
    private static let surfaceResumeSetValueOptions: Set<String> = surfaceResumeTargetValueOptions.union([
        "--name", "--kind", "--checkpoint", "--checkpoint-id", "--source", "--cwd", "--shell",
    ])
    private static let surfaceResumeClearValueOptions: Set<String> = surfaceResumeTargetValueOptions.union([
        "--checkpoint", "--checkpoint-id", "--source",
    ])

    private func validateSurfaceResumeValueOptions(
        _ args: [String],
        optionNames: Set<String>,
        context: String
    ) throws {
        var pastTerminator = false
        for (index, arg) in args.enumerated() {
            if pastTerminator {
                continue
            }
            if arg == "--" {
                pastTerminator = true
                continue
            }
            guard optionNames.contains(arg) else { continue }
            guard index + 1 < args.count else {
                throw CLIError(message: "\(context): \(arg) requires a value")
            }
            let value = args[index + 1]
            guard value != "--",
                  !optionNames.contains(value),
                  !value.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
                throw CLIError(message: "\(context): \(arg) requires a value")
            }
        }
    }

    private struct SurfaceResumeTarget {
        var params: [String: Any]
        var remaining: [String]
    }

    private func splitAtArgumentTerminator(_ args: [String]) -> (options: [String], argv: [String]?) {
        guard let delimiterIndex = args.firstIndex(of: "--") else {
            return (args, nil)
        }
        let argvStart = args.index(after: delimiterIndex)
        return (Array(args[..<delimiterIndex]), Array(args[argvStart...]))
    }

    private func surfaceResumeTarget(
        _ args: [String],
        client: SocketClient,
        windowOverride: String?
    ) throws -> SurfaceResumeTarget {
        let splitArgs = splitAtArgumentTerminator(args)
        let (workspaceOpt, rem1) = parseOption(splitArgs.options, name: "--workspace")
        let (surfaceOpt, rem2) = parseOption(rem1, name: "--surface")
        let (windowOpt, remaining) = parseOption(rem2, name: "--window")
        let windowRaw = windowOpt ?? windowOverride
        let env = ProcessInfo.processInfo.environment
        let usesImplicitSurface = surfaceOpt == nil
            && windowRaw == nil
            && env["CMUX_SURFACE_ID"]?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
        let shouldUseEnvWorkspace = surfaceOpt == nil
            && !usesImplicitSurface
            && windowRaw == nil
        let workspaceRaw = workspaceOpt ?? (shouldUseEnvWorkspace ? env["CMUX_WORKSPACE_ID"] : nil)
        let surfaceRaw = surfaceOpt ?? (workspaceOpt == nil && windowRaw == nil ? env["CMUX_SURFACE_ID"] : nil)
        var params: [String: Any] = [:]
        let windowHandle = try normalizeWindowHandle(windowRaw, client: client)
        if let windowHandle { params["window_id"] = windowHandle }
        let workspaceId = try normalizeWorkspaceHandle(workspaceRaw, client: client, windowHandle: windowHandle)
        if let workspaceId { params["workspace_id"] = workspaceId }
        let surfaceId = try normalizeSurfaceHandle(
            surfaceRaw,
            client: client,
            workspaceHandle: workspaceId,
            windowHandle: windowHandle
        )
        if let surfaceId { params["surface_id"] = surfaceId }
        let remainingWithArgv = remaining + (splitArgs.argv.map { ["--"] + $0 } ?? [])
        return SurfaceResumeTarget(params: params, remaining: remainingWithArgv)
    }

    private func cliShellQuote(_ value: String) -> String {
        "'" + value.replacingOccurrences(of: "'", with: "'\\''") + "'"
    }

    func debugString(_ value: Any?) -> String? {
        guard let value, !(value is NSNull) else { return nil }
        if let string = value as? String {
            return string
        }
        if let number = value as? NSNumber {
            return number.stringValue
        }
        return String(describing: value)
    }

    private func trimmedDebugString(_ value: Any?) -> String? {
        guard let string = debugString(value)?
            .trimmingCharacters(in: .whitespacesAndNewlines),
              !string.isEmpty else {
            return nil
        }
        return string
    }

    private func debugBool(_ value: Any?) -> Bool? {
        boolFromAny(value)
    }

    private func debugFlag(_ value: Any?) -> String {
        guard let bool = debugBool(value) else { return "nil" }
        return bool ? "1" : "0"
    }

    private func formatDebugRect(_ value: Any?) -> String? {
        guard let rect = value as? [String: Any],
              let x = doubleFromAny(rect["x"]),
              let y = doubleFromAny(rect["y"]),
              let width = doubleFromAny(rect["width"]),
              let height = doubleFromAny(rect["height"]) else {
            return nil
        }
        return String(format: "{%.1f,%.1f %.1fx%.1f}", x, y, width, height)
    }

    private func formatDebugPorts(_ value: Any?) -> String {
        guard let array = value as? [Any], !array.isEmpty else { return "[]" }
        let ports = array
            .compactMap { intFromAny($0) }
            .map(String.init)
        return ports.isEmpty ? "[]" : ports.joined(separator: ",")
    }

    private func formatDebugList(_ value: Any?) -> String? {
        guard let array = value as? [Any], !array.isEmpty else { return nil }
        let items = array.compactMap { item -> String? in
            if let string = item as? String {
                return string
            }
            return debugString(item)
        }
        guard !items.isEmpty else { return nil }
        return items.joined(separator: ">")
    }

    private func formatDebugAge(_ value: Any?) -> String? {
        guard let seconds = doubleFromAny(value) else { return nil }
        return String(format: "%.3fs", seconds)
    }

    private func formatDebugTerminalsPayload(_ payload: [String: Any], idFormat: CLIIDFormat) -> String {
        let terminals = payload["terminals"] as? [[String: Any]] ?? []
        guard !terminals.isEmpty else { return "No terminal surfaces" }

        return terminals.map { item in
            let index = intFromAny(item["index"]) ?? 0
            let surface = formatHandle(item, kind: "surface", idFormat: idFormat) ?? "?"
            let window = formatHandle(item, kind: "window", idFormat: idFormat) ?? "nil"
            let workspace = formatHandle(item, kind: "workspace", idFormat: idFormat) ?? "nil"
            let pane = formatHandle(item, kind: "pane", idFormat: idFormat) ?? "nil"
            let bonsplitTab = debugString(item["bonsplit_tab_id"]) ?? "nil"
            let lastKnownWorkspace = debugString(item["last_known_workspace_ref"]) ?? debugString(item["last_known_workspace_id"]) ?? "nil"
            let titleSuffix: String = {
                guard let title = debugString(item["surface_title"]), !title.isEmpty else { return "" }
                let escaped = title.replacingOccurrences(of: "\"", with: "\\\"")
                return " \"\(escaped)\""
            }()
            let branchLabel: String = {
                guard let branch = debugString(item["git_branch"]), !branch.isEmpty else { return "nil" }
                return debugBool(item["git_dirty"]) == true ? "\(branch)*" : branch
            }()
            let teardownLabel: String = {
                guard debugBool(item["teardown_requested"]) == true else { return "nil" }
                let reason = debugString(item["teardown_requested_reason"]) ?? "requested"
                let age = formatDebugAge(item["teardown_requested_age_seconds"]) ?? "unknown"
                return "\(reason)@\(age)"
            }()
            let portalHostLabel: String = {
                let hostId = debugString(item["portal_host_id"]) ?? "nil"
                let area = doubleFromAny(item["portal_host_area"]).map { String(format: "%.1f", $0) } ?? "nil"
                let inWindow = debugFlag(item["portal_host_in_window"])
                return "\(hostId)/win=\(inWindow)/area=\(area)"
            }()
            let windowMetaLabel: String = {
                let title = debugString(item["window_title"]) ?? "nil"
                let windowClass = debugString(item["window_class"]) ?? "nil"
                let controllerClass = debugString(item["window_controller_class"]) ?? "nil"
                let delegateClass = debugString(item["window_delegate_class"]) ?? "nil"
                return "title=\(title) class=\(windowClass) controller=\(controllerClass) delegate=\(delegateClass)"
            }()

            let line1 =
                "[\(index)] \(surface)\(titleSuffix) " +
                "mapped=\(debugFlag(item["mapped"])) tree=\(debugFlag(item["tree_visible"])) " +
                "window=\(window) workspace=\(workspace) pane=\(pane) bonsplitTab=\(bonsplitTab) " +
                "ctx=\(debugString(item["surface_context"]) ?? "nil")"

            let line2 =
                "    runtime=\(debugFlag(item["runtime_surface_ready"])) " +
                "focused=\(debugFlag(item["surface_focused"])) " +
                "selected=\(debugFlag(item["surface_selected_in_pane"])) " +
                "pinned=\(debugFlag(item["surface_pinned"])) " +
                "terminal=\(debugString(item["terminal_object_ptr"]) ?? "nil") " +
                "hosted=\(debugString(item["hosted_view_ptr"]) ?? "nil") " +
                "ghostty=\(debugString(item["ghostty_surface_ptr"]) ?? "nil") " +
                "portal=\(debugString(item["portal_binding_state"]) ?? "nil")#\(debugString(item["portal_binding_generation"]) ?? "nil") " +
                "teardown=\(teardownLabel)"

            let line3 =
                "    tty=\(debugString(item["tty"]) ?? "nil") " +
                "cwd=\(debugString(item["current_directory"]) ?? debugString(item["requested_working_directory"]) ?? "nil") " +
                "branch=\(branchLabel) " +
                "ports=\(formatDebugPorts(item["listening_ports"])) " +
                "visible=\(debugFlag(item["hosted_view_visible_in_ui"])) " +
                "inWindow=\(debugFlag(item["hosted_view_in_window"])) " +
                "superview=\(debugFlag(item["hosted_view_has_superview"])) " +
                "hidden=\(debugFlag(item["hosted_view_hidden"])) " +
                "ancestorHidden=\(debugFlag(item["hosted_view_hidden_or_ancestor_hidden"])) " +
                "firstResponder=\(debugFlag(item["surface_view_first_responder"])) " +
                "windowNum=\(debugString(item["window_number"]) ?? "nil") " +
                "windowKey=\(debugFlag(item["window_key"])) " +
                "frame=\(formatDebugRect(item["hosted_view_frame_in_window"]) ?? "nil")"

            let line4 =
                "    created=\(formatDebugAge(item["surface_age_seconds"]) ?? "nil") " +
                "runtimeCreated=\(formatDebugAge(item["runtime_surface_age_seconds"]) ?? "nil") " +
                "lastWorkspace=\(lastKnownWorkspace) " +
                "initialCommand=\(debugString(item["initial_command"]) ?? "nil") " +
                "portalHost=\(portalHostLabel)"

            let line5 =
                "    window=\(windowMetaLabel) " +
                "chain=\(formatDebugList(item["hosted_view_superview_chain"]) ?? "nil")"

            return [line1, line2, line3, line4, line5].joined(separator: "\n")
        }
        .joined(separator: "\n")
    }

    private func runReorderWorkspace(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        let workspaceRaw = optionValue(commandArgs, name: "--workspace") ?? commandArgs.first
        guard let workspaceRaw else {
            throw CLIError(message: "reorder-workspace requires --workspace <id|ref|index>")
        }

        let windowRaw = optionValue(commandArgs, name: "--window")
        let windowHandle = try normalizeWindowHandle(windowRaw, client: client)
        let workspaceHandle = try normalizeWorkspaceHandle(workspaceRaw, client: client, windowHandle: windowHandle)

        let beforeRaw = optionValue(commandArgs, name: "--before") ?? optionValue(commandArgs, name: "--before-workspace")
        let afterRaw = optionValue(commandArgs, name: "--after") ?? optionValue(commandArgs, name: "--after-workspace")
        let beforeHandle = try normalizeWorkspaceHandle(beforeRaw, client: client, windowHandle: windowHandle)
        let afterHandle = try normalizeWorkspaceHandle(afterRaw, client: client, windowHandle: windowHandle)

        var params: [String: Any] = [:]
        if let workspaceHandle { params["workspace_id"] = workspaceHandle }
        if let beforeHandle { params["before_workspace_id"] = beforeHandle }
        if let afterHandle { params["after_workspace_id"] = afterHandle }
        if let indexRaw = optionValue(commandArgs, name: "--index") {
            guard let index = Int(indexRaw) else {
                throw CLIError(message: "--index must be an integer")
            }
            params["index"] = index
        }
        if let windowHandle {
            params["window_id"] = windowHandle
        }
        let dryRun = hasFlag(commandArgs, name: "--dry-run")
        if dryRun {
            params["dry_run"] = true
        }

        let payload = try client.sendV2(method: "workspace.reorder", params: params)
        let summary = dryRun
            ? reorderResultLines(payload, idFormat: idFormat, dryRun: true).joined(separator: "\n")
            : "OK workspace=\(formatHandle(payload, kind: "workspace", idFormat: idFormat) ?? "unknown") window=\(formatHandle(payload, kind: "window", idFormat: idFormat) ?? "unknown") index=\(payload["index"] ?? "?")"
        printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: summary)
    }

    private func runReorderWorkspaces(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        guard let orderRaw = optionValue(commandArgs, name: "--order") else {
            throw CLIError(message: String(
                localized: "cli.reorderWorkspaces.error.missingOrder",
                defaultValue: "reorder-workspaces requires --order <id|ref|index>,<id|ref|index>,..."
            ))
        }

        let rawRefs = orderRaw
            .split(separator: ",", omittingEmptySubsequences: false)
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        guard !rawRefs.isEmpty else {
            throw CLIError(message: String(
                localized: "cli.reorderWorkspaces.error.emptyOrder",
                defaultValue: "reorder-workspaces requires at least one workspace in --order"
            ))
        }
        guard !rawRefs.contains(where: \.isEmpty) else {
            throw CLIError(message: String(
                localized: "cli.reorderWorkspaces.error.emptyOrderItem",
                defaultValue: "reorder-workspaces --order cannot contain empty workspace refs"
            ))
        }

        let windowRaw = optionValue(commandArgs, name: "--window")
        let windowHandle = try normalizeWindowHandle(windowRaw, client: client)
        let workspaceHandles = try rawRefs.map { rawRef in
            guard let workspaceHandle = try normalizeWorkspaceHandle(rawRef, client: client, windowHandle: windowHandle) else {
                let messageFormat = String(
                    localized: "cli.reorderWorkspaces.error.workspaceNotFound",
                    defaultValue: "Workspace not found: %@"
                )
                throw CLIError(message: String(format: messageFormat, rawRef))
            }
            return workspaceHandle
        }

        var params: [String: Any] = ["workspace_ids": workspaceHandles]
        if let windowHandle {
            params["window_id"] = windowHandle
        }
        let dryRun = hasFlag(commandArgs, name: "--dry-run")
        if dryRun {
            params["dry_run"] = true
        }

        let payload = try client.sendV2(method: "workspace.reorder_many", params: params)
        let summary = reorderResultLines(payload, idFormat: idFormat, dryRun: dryRun).joined(separator: "\n")
        printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: summary)
    }

    private func reorderResultLines(
        _ payload: [String: Any],
        idFormat: CLIIDFormat,
        dryRun: Bool
    ) -> [String] {
        let planItems = payload["plan"] as? [[String: Any]] ?? [payload]
        let lineFormat = dryRun
            ? String(
                localized: "cli.reorderWorkspaces.result.planLine",
                defaultValue: "OK plan workspace=%@ window=%@ index=%@"
            )
            : String(
                localized: "cli.reorderWorkspaces.result.appliedLine",
                defaultValue: "OK workspace=%@ window=%@ index=%@"
            )
        return planItems.map { item in
            let workspace = formatHandle(item, kind: "workspace", idFormat: idFormat) ?? "unknown"
            let window = formatHandle(item, kind: "window", idFormat: idFormat) ?? "unknown"
            let index = item["to_index"] ?? item["index"] ?? "?"
            return String(format: lineFormat, workspace, window, String(describing: index))
        }
    }

    private func runSimulateSidebarDrag(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        let windowRaw = optionValue(commandArgs, name: "--window")
        let windowHandle = try normalizeWindowHandle(windowRaw, client: client)
        guard let windowHandle else {
            throw CLIError(message: "simulate-sidebar-drag requires --window <id|ref|index>")
        }
        guard let fromRaw = optionValue(commandArgs, name: "--from") else {
            throw CLIError(message: "simulate-sidebar-drag requires --from <workspace id|ref|index>")
        }
        guard let toRaw = optionValue(commandArgs, name: "--to") else {
            throw CLIError(message: "simulate-sidebar-drag requires --to <workspace id|ref|index>")
        }
        let fromHandle = try normalizeWorkspaceHandle(fromRaw, client: client, windowHandle: windowHandle)
        let toHandle = try normalizeWorkspaceHandle(toRaw, client: client, windowHandle: windowHandle)
        guard let fromHandle, let toHandle else {
            throw CLIError(message: "simulate-sidebar-drag could not resolve --from / --to to workspace ids")
        }

        var params: [String: Any] = [
            "window_id": windowHandle,
            "from_tab_id": fromHandle,
            "to_tab_id": toHandle
        ]
        var requestedDurationMs = 1000  // matches server default
        var requestedSteps: Int?
        if let durationRaw = optionValue(commandArgs, name: "--duration-ms") {
            guard let duration = Int(durationRaw), duration > 0 else {
                throw CLIError(message: "--duration-ms must be a positive integer")
            }
            params["duration_ms"] = duration
            requestedDurationMs = duration
        }
        if let stepsRaw = optionValue(commandArgs, name: "--steps") {
            guard let steps = Int(stepsRaw), steps > 0 else {
                throw CLIError(message: "--steps must be a positive integer")
            }
            params["steps"] = steps
            requestedSteps = steps
        }

        // The handler blocks until the simulated drag completes
        // (duration_ms in the common path; longer when --steps > path
        // length because the per-step interval has a 1ms minimum). The
        // default 15s socket response timeout would abort long profiling
        // runs while the app keeps simulating. Allow generous slack.
        let stepBasedMinMs = (requestedSteps ?? 0)  // server enforces 1ms min interval
        let expectedRuntimeMs = max(requestedDurationMs, stepBasedMinMs)
        let responseTimeout = max(30.0, Double(expectedRuntimeMs) / 1000.0 + 10.0)

        let payload = try client.sendV2(
            method: "debug.sidebar.simulate_drag",
            params: params,
            responseTimeout: responseTimeout
        )
        let summary = "OK steps=\(payload["steps"] ?? "?") duration_ms=\(payload["duration_ms"] ?? "?") edge=\(payload["edge"] ?? "?")"
        printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: summary)
    }

    private func runWorkspaceAction(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        let (workspaceOpt, rem0) = parseOption(commandArgs, name: "--workspace")
        let (actionOpt, rem1) = parseOption(rem0, name: "--action")
        let (titleOpt, rem2) = parseOption(rem1, name: "--title")
        let (colorOpt, rem3) = parseOption(rem2, name: "--color")
        let (descriptionOpt, rem4) = parseOption(rem3, name: "--description")
        let (windowOpt, rem5) = parseOption(rem4, name: "--window")

        var positional = rem5
        let actionRaw: String
        if let actionOpt {
            actionRaw = actionOpt
        } else if let first = positional.first {
            actionRaw = first
            positional.removeFirst()
        } else {
            throw CLIError(message: "workspace-action requires --action <name>")
        }

        if let unknown = positional.first(where: { $0.hasPrefix("--") }) {
            throw CLIError(message: "workspace-action: unknown flag '\(unknown)'")
        }

        let action = actionRaw.lowercased().replacingOccurrences(of: "-", with: "_")
        let windowRaw = windowOpt ?? windowOverride
        let workspaceArg = workspaceOpt ?? (windowRaw == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)
        let windowHandle = try normalizeWindowHandle(windowRaw, client: client)
        let workspaceId = try normalizeWorkspaceHandle(
            workspaceArg,
            client: client,
            windowHandle: windowHandle,
            allowCurrent: true
        )

        let inferredPositionalRaw = positional.joined(separator: " ")
        let inferredPositional = inferredPositionalRaw.trimmingCharacters(in: .whitespacesAndNewlines)
        let title = (titleOpt ?? (action == "rename" && !inferredPositional.isEmpty ? inferredPositional : nil))?.trimmingCharacters(in: .whitespacesAndNewlines)

        if action == "rename", (title?.isEmpty ?? true) {
            throw CLIError(message: "workspace-action rename requires --title <text> (or a trailing title)")
        }

        let color = (
            colorOpt ?? (action == "set_color" ? (inferredPositional.isEmpty ? nil : inferredPositional) : nil)
        )?.trimmingCharacters(in: .whitespacesAndNewlines)
        if action == "set_color", (color?.isEmpty ?? true) {
            throw CLIError(message: "workspace-action set-color requires --color <name|#hex> (or a trailing color)")
        }

        let description = (
            descriptionOpt ?? (action == "set_description" && !inferredPositional.isEmpty ? inferredPositionalRaw : nil)
        )?.trimmingCharacters(in: .whitespacesAndNewlines)
        if action == "set_description", (description?.isEmpty ?? true) {
            throw CLIError(message: "workspace-action set-description requires --description <text> (or trailing text)")
        }

        var params: [String: Any] = ["action": action]
        if let windowHandle {
            params["window_id"] = windowHandle
        }
        if let workspaceId {
            params["workspace_id"] = workspaceId
        }
        if let title, !title.isEmpty {
            params["title"] = title
        }
        if let color, !color.isEmpty {
            params["color"] = color
        }
        if let description, !description.isEmpty {
            params["description"] = description
        }

        let payload = try client.sendV2(method: "workspace.action", params: params)
        var summaryParts = ["OK", "action=\(action)"]
        if let workspaceHandle = formatHandle(payload, kind: "workspace", idFormat: idFormat) {
            summaryParts.append("workspace=\(workspaceHandle)")
        }
        if let windowHandle = formatHandle(payload, kind: "window", idFormat: idFormat) {
            summaryParts.append("window=\(windowHandle)")
        }
        if let closed = payload["closed"] {
            summaryParts.append("closed=\(closed)")
        }
        if let index = payload["index"] {
            summaryParts.append("index=\(index)")
        }
        if let color = payload["color"] as? String {
            summaryParts.append("color=\(color)")
        }
        printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: summaryParts.joined(separator: " "))
    }

    func runTabAction(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        let (workspaceOpt, rem0) = parseOption(commandArgs, name: "--workspace")
        let (tabOpt, rem1) = parseOption(rem0, name: "--tab")
        let (surfaceOpt, rem2) = parseOption(rem1, name: "--surface")
        let (actionOpt, rem3) = parseOption(rem2, name: "--action")
        let (titleOpt, rem4) = parseOption(rem3, name: "--title")
        let (urlOpt, rem5) = parseOption(rem4, name: "--url")
        let (focusOpt, rem6) = parseOption(rem5, name: "--focus")
        let (windowOpt, rem7) = parseOption(rem6, name: "--window")

        var positional = rem7
        let actionRaw: String
        if let actionOpt {
            actionRaw = actionOpt
        } else if let first = positional.first {
            actionRaw = first
            positional.removeFirst()
        } else {
            throw CLIError(message: "tab-action requires --action <name>")
        }

        if let unknown = positional.first(where: { $0.hasPrefix("--") }) {
            throw CLIError(message: "tab-action: unknown flag '\(unknown)'")
        }

        let action = actionRaw.lowercased().replacingOccurrences(of: "-", with: "_")
        let windowRaw = windowOpt ?? windowOverride
        let workspaceArg = workspaceOpt ?? (windowRaw == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)
        let tabArg = tabOpt
            ?? surfaceOpt
            ?? (workspaceOpt == nil && windowRaw == nil
                ? (ProcessInfo.processInfo.environment["CMUX_TAB_ID"] ?? ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"])
                : nil)

        let windowHandle = try normalizeWindowHandle(windowRaw, client: client)
        let workspaceId = try normalizeWorkspaceHandle(
            workspaceArg,
            client: client,
            windowHandle: windowHandle,
            allowCurrent: true
        )
        // If a workspace is explicitly targeted and no tab/surface is provided, let server-side
        // tab.action resolve that workspace's focused tab instead of using global focus.
        let allowFocusedFallback = (workspaceId == nil)
        let surfaceId = try normalizeTabHandle(
            tabArg,
            client: client,
            workspaceHandle: workspaceId,
            windowHandle: windowHandle,
            allowFocused: allowFocusedFallback
        )

        let inferredTitle = positional.joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
        let title = (titleOpt ?? (inferredTitle.isEmpty ? nil : inferredTitle))?.trimmingCharacters(in: .whitespacesAndNewlines)

        if action == "rename", (title?.isEmpty ?? true) {
            throw CLIError(message: "tab-action rename requires --title <text> (or a trailing title)")
        }

        var params: [String: Any] = ["action": action]
        if let windowHandle {
            params["window_id"] = windowHandle
        }
        if let workspaceId {
            params["workspace_id"] = workspaceId
        }
        if let surfaceId {
            params["surface_id"] = surfaceId
        }
        if let title, !title.isEmpty {
            params["title"] = title
        }
        if let urlOpt, !urlOpt.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            params["url"] = urlOpt.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        try applyTabActionFocusOption(focusOpt, to: &params)
        let payload = try client.sendV2(method: "tab.action", params: params)
        var summaryParts = ["OK", "action=\(action)"]
        if let tabHandle = formatTabHandle(payload, idFormat: idFormat) { summaryParts.append("tab=\(tabHandle)") }
        if let workspaceHandle = formatHandle(payload, kind: "workspace", idFormat: idFormat) { summaryParts.append("workspace=\(workspaceHandle)") }
        if let closed = payload["closed"] { summaryParts.append("closed=\(closed)") }
        if let enabled = payload["full_width_tab_mode"] { summaryParts.append("full_width_tab_mode=\(enabled)") }
        if let created = formatCreatedTabHandle(payload, idFormat: idFormat) { summaryParts.append("created=\(created)") }
        appendCreatedWorkspaceSummaryParts(from: payload, idFormat: idFormat, to: &summaryParts)
        printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: summaryParts.joined(separator: " "))
    }
    private enum WorkspaceRenameCommandMode {
        case legacy
        case namespace
    }

    private func runWorkspaceListCommand(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        var params: [String: Any] = [:]
        try applyWindowOrCallerContext(
            to: &params,
            client: client,
            windowRaw: windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride)
        )
        let payload = try client.sendV2(method: "workspace.list", params: params)
        if jsonOutput {
            print(jsonString(formatIDs(payload, mode: idFormat)))
        } else {
            let workspaces = payload["workspaces"] as? [[String: Any]] ?? []
            if workspaces.isEmpty {
                print("No workspaces")
            } else {
                for ws in workspaces {
                    let selected = (ws["selected"] as? Bool) == true
                    let handle = textHandle(ws, idFormat: idFormat)
                    let title = (ws["title"] as? String) ?? ""
                    let remoteTag: String = {
                        guard let remote = ws["remote"] as? [String: Any],
                              (remote["enabled"] as? Bool) == true else {
                            return ""
                        }
                        let transport = (remote["transport"] as? String) ?? "remote"
                        let state = (remote["state"] as? String) ?? "unknown"
                        return "  [\(transport):\(state)]"
                    }()
                    let prefix = selected ? "* " : "  "
                    let selTag = selected ? "  [selected]" : ""
                    let titlePart = title.isEmpty ? "" : "  \(title)"
                    print("\(prefix)\(handle)\(titlePart)\(remoteTag)\(selTag)")
                }
            }
        }
    }

    private func runWorkspaceCreateCommand(
        commandName: String,
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?,
        honorJSONOutput: Bool
    ) throws {
        let (commandOpt, rem0) = parseOption(commandArgs, name: "--command")
        let (cwdOpt, rem1) = parseOption(rem0, name: "--cwd")
        let (nameOpt, rem2) = parseOption(rem1, name: "--name")
        let (descriptionOpt, rem3) = parseOption(rem2, name: "--description")
        let (layoutOpt, rem4) = parseOption(rem3, name: "--layout")
        let (windowOpt, rem5) = parseOption(rem4, name: "--window")
        let (focusOpt, rem6) = parseOption(rem5, name: "--focus")
        let (groupOpt, rem7) = parseOption(rem6, name: "--group")
        let (groupPlacementOpt, rem8) = parseOption(rem7, name: "--group-placement")
        let (groupReferenceOpt, rem9) = parseOption(rem8, name: "--group-reference")
        let (envFiles, envPairs, remaining) = parseWorkspaceEnvOptions(rem9)
        if remaining.last == "--env" {
            throw CLIError(message: String(
                format: String(
                    localized: "cli.workspace.create.error.envRequiresValue",
                    defaultValue: "%@: --env requires KEY=VALUE"
                ),
                locale: .current,
                commandName
            ))
        }
        if remaining.last == "--env-file" {
            throw CLIError(message: String(
                format: String(
                    localized: "cli.workspace.create.error.envFileRequiresValue",
                    defaultValue: "%@: --env-file requires <path>"
                ),
                locale: .current,
                commandName
            ))
        }
        if let unknown = remaining.first(where: { $0.hasPrefix("--") }) {
            throw CLIError(message: String(
                format: String(
                    localized: "cli.workspace.create.error.unknownFlag",
                    defaultValue: "%@: unknown flag '%@'. Known flags: --name <title>, --description <text>, --command <text>, --cwd <path>, --env KEY=VALUE, --env-file <path>, --layout <json>, --window <id|ref|index>, --focus <true|false>, --group <id|ref>, --group-placement <afterCurrent|top|end>, --group-reference <workspace>"
                ),
                locale: .current,
                commandName,
                unknown
            ))
        }
        var params: [String: Any] = [:]
        try applyWindowOrCallerContext(to: &params, client: client, windowRaw: windowOpt ?? windowOverride)
        if let cwdOpt {
            params["cwd"] = resolvePath(cwdOpt)
        }
        if let nameOpt { params["title"] = nameOpt }
        if let descriptionOpt { params["description"] = descriptionOpt }
        if let groupOpt { params["group_id"] = groupOpt }
        if let groupPlacementOpt { params["group_placement"] = groupPlacementOpt }
        if let groupReferenceOpt { params["group_reference_workspace_id"] = groupReferenceOpt }
        let workspaceEnv = try buildWorkspaceEnvironment(envFiles: envFiles, envPairs: envPairs, commandName: commandName)
        if !workspaceEnv.isEmpty {
            params["workspace_env"] = workspaceEnv
        }
        if let layoutOpt {
            guard let layoutData = layoutOpt.data(using: .utf8),
                  let layoutObj = try? JSONSerialization.jsonObject(with: layoutData) as? [String: Any] else {
                throw CLIError(message: "\(commandName): --layout value must be a valid JSON object")
            }
            params["layout"] = layoutObj
        }
        try applyFocusOption(focusOpt, defaultValue: false, to: &params)
        let response = try client.sendV2(method: "workspace.create", params: params)
        let wsId = (response["workspace_ref"] as? String) ?? (response["workspace_id"] as? String) ?? ""
        if jsonOutput && honorJSONOutput {
            print(jsonString(formatIDs(response, mode: idFormat)))
        } else {
            print("OK \(wsId)")
        }
        if layoutOpt == nil, let commandText = commandOpt, !wsId.isEmpty {
            let text = unescapeSendText(commandText + "\\n")
            let sendParams: [String: Any] = [
                "text": text,
                "workspace_id": wsId
            ]
            _ = try client.sendV2(method: "surface.send_text", params: sendParams)
        }
    }

    /// Parses repeatable `--env KEY=VALUE` / `--env=KEY=VALUE` and
    /// `--env-file PATH` / `--env-file=PATH` flags out of `args`, returning the
    /// ordered env-file paths, the ordered `KEY=VALUE` pairs, and the remaining
    /// unparsed args. Files are applied before pairs by the builder so an explicit
    /// `--env` overrides a value from a file.
    func parseWorkspaceEnvOptions(
        _ args: [String]
    ) -> (envFiles: [String], envPairs: [String], remaining: [String]) {
        var envFiles: [String] = []
        var envPairs: [String] = []
        var remaining: [String] = []
        var skipNext = false
        var pastTerminator = false
        for (idx, arg) in args.enumerated() {
            if skipNext {
                skipNext = false
                continue
            }
            if arg == "--" {
                pastTerminator = true
                remaining.append(arg)
                continue
            }
            if !pastTerminator {
                if arg == "--env", idx + 1 < args.count {
                    envPairs.append(args[idx + 1])
                    skipNext = true
                    continue
                }
                if arg.hasPrefix("--env=") {
                    envPairs.append(String(arg.dropFirst("--env=".count)))
                    continue
                }
                if arg == "--env-file", idx + 1 < args.count {
                    envFiles.append(args[idx + 1])
                    skipNext = true
                    continue
                }
                if arg.hasPrefix("--env-file=") {
                    envFiles.append(String(arg.dropFirst("--env-file=".count)))
                    continue
                }
            }
            remaining.append(arg)
        }
        return (envFiles, envPairs, remaining)
    }

    /// Builds the workspace environment dict from `--env-file` paths (applied
    /// first, in order) and `--env KEY=VALUE` pairs (applied after, so they
    /// override files). Env files use `KEY=VALUE` lines; blank lines and lines
    /// starting with `#` are ignored, an optional leading `export ` is stripped,
    /// and matching surrounding quotes on a file value are removed. Command-line
    /// `--env` values are taken verbatim (the shell already handled quoting).
    func buildWorkspaceEnvironment(
        envFiles: [String],
        envPairs: [String],
        commandName: String
    ) throws -> [String: String] {
        var env: [String: String] = [:]
        for path in envFiles {
            let resolved = resolvePath(path)
            let contents: String
            do {
                contents = try String(contentsOfFile: resolved, encoding: .utf8)
            } catch {
                throw CLIError(message: String(
                    format: String(
                        localized: "cli.workspace.envFile.error.readFailed",
                        defaultValue: "%@: could not read --env-file '%@': %@"
                    ),
                    locale: .current,
                    commandName,
                    path,
                    String(describing: error)
                ))
            }
            for rawLine in contents.split(omittingEmptySubsequences: false, whereSeparator: { $0.isNewline }) {
                var line = String(rawLine).trimmingCharacters(in: .whitespaces)
                if line.isEmpty || line.hasPrefix("#") { continue }
                if line.hasPrefix("export ") {
                    line = String(line.dropFirst("export ".count)).trimmingCharacters(in: .whitespaces)
                }
                let (key, value) = try parseEnvAssignment(line, source: "--env-file '\(path)'", commandName: commandName)
                env[key] = unquoteEnvValue(value)
            }
        }
        for pair in envPairs {
            let (key, value) = try parseEnvAssignment(pair, source: "--env", commandName: commandName)
            env[key] = value
        }
        return env
    }

    /// Splits a `KEY=VALUE` assignment on the first `=`. The key is trimmed and
    /// must be non-empty; the value is returned unmodified (callers decide whether
    /// to unquote).
    func parseEnvAssignment(
        _ raw: String,
        source: String,
        commandName: String
    ) throws -> (String, String) {
        guard let eq = raw.firstIndex(of: "=") else {
            throw CLIError(message: String(
                format: String(
                    localized: "cli.workspace.env.error.invalidAssignment",
                    defaultValue: "%@: %@ entry '%@' must be in KEY=VALUE form"
                ),
                locale: .current,
                commandName,
                source,
                raw
            ))
        }
        let key = String(raw[..<eq]).trimmingCharacters(in: .whitespaces)
        let value = String(raw[raw.index(after: eq)...])
        guard !key.isEmpty else {
            throw CLIError(message: String(
                format: String(
                    localized: "cli.workspace.env.error.emptyKey",
                    defaultValue: "%@: %@ entry '%@' has an empty key"
                ),
                locale: .current,
                commandName,
                source,
                raw
            ))
        }
        return (key, value)
    }

    /// Removes a single matching pair of surrounding single or double quotes from
    /// an env-file value.
    func unquoteEnvValue(_ value: String) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespaces)
        if trimmed.count >= 2,
           (trimmed.hasPrefix("\"") && trimmed.hasSuffix("\"")) ||
           (trimmed.hasPrefix("'") && trimmed.hasSuffix("'")) {
            return String(trimmed.dropFirst().dropLast())
        }
        return trimmed
    }

    /// Masks a secret env value for display. Short values are fully masked so a
    /// brief secret isn't mostly revealed; longer ones keep a 2-character hint.
    /// The mask is fixed-width so the value's length isn't leaked.
    static func maskedEnvValue(_ value: String) -> String {
        if value.isEmpty { return "" }
        guard value.count > 6 else { return "••••" }
        return "\(value.prefix(2))••••"
    }

    /// `cmux workspace env [<handle>] [--mask]` — print a workspace's configured
    /// environment variables (issue #5995). Resolves the positional/`--workspace`
    /// handle, falling back to the selected workspace. `--mask` redacts values so
    /// secrets aren't echoed in full.
    private func runWorkspaceEnvCommand(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        var rest = commandArgs
        let mask = rest.contains("--mask")
        rest.removeAll { $0 == "--mask" }

        let (workspaceArg, rem0) = parseOption(rest, name: "--workspace")
        let (_, rem1) = parseOption(rem0, name: "--window")
        if let unknown = rem1.first(where: { $0.hasPrefix("--") }) {
            throw CLIError(message: String(
                format: String(
                    localized: "cli.workspace.env.error.unknownFlag",
                    defaultValue: "workspace env: unknown flag '%@'. Known flags: --workspace <id|ref|index>, --window <id|ref|index>, --mask"
                ),
                locale: .current,
                unknown
            ))
        }
        let positional = rem1.first(where: { !$0.hasPrefix("--") })
        let windowRaw = windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride)
        // Match reconnect/disconnect: default to the caller's workspace
        // ($CMUX_WORKSPACE_ID) before the selected one, but only when no explicit
        // --window is given (the caller's workspace may live in another window).
        let target = workspaceArg
            ?? positional
            ?? (windowRaw == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)

        var params: [String: Any] = [:]
        let winId = try normalizeWindowHandle(windowRaw, client: client)
        if let winId { params["window_id"] = winId }
        let wsId = try normalizeWorkspaceHandle(target, client: client, windowHandle: winId)
        if let wsId { params["workspace_id"] = wsId }

        let payload = try client.sendV2(method: "workspace.env", params: params)
        let rawEnv = (payload["env"] as? [String: Any]) ?? [:]
        let envStrings: [String: String] = rawEnv.reduce(into: [:]) { result, pair in
            if let value = pair.value as? String { result[pair.key] = value }
        }
        let displayedEnv: [String: String] = mask
            ? envStrings.reduce(into: [String: String]()) { result, pair in
                result[pair.key] = Self.maskedEnvValue(pair.value)
            }
            : envStrings

        if jsonOutput {
            // Format only the envelope's id/ref metadata. The env map is arbitrary
            // user data, so running it through formatIDs (which strips `id` when
            // `ref` is present and `*_id` when a matching `*_ref` exists) could
            // silently drop a user variable; reinsert it verbatim after formatting.
            var envelope = payload
            envelope.removeValue(forKey: "env")
            var formatted = (formatIDs(envelope, mode: idFormat) as? [String: Any]) ?? envelope
            formatted["env"] = displayedEnv
            print(jsonString(formatted))
        } else if envStrings.isEmpty {
            print(String(localized: "cli.workspace.env.empty", defaultValue: "No environment variables"))
        } else {
            for key in envStrings.keys.sorted() {
                print("\(key)=\(displayedEnv[key] ?? "")")
            }
        }
    }

    private func runWorkspaceCloseCommand(
        commandName: String,
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?,
        requireWorkspaceFlag: Bool
    ) throws {
        let target: String?
        if requireWorkspaceFlag {
            guard let workspaceRaw = optionValue(commandArgs, name: "--workspace") else {
                throw CLIError(message: "\(commandName) requires --workspace")
            }
            target = workspaceRaw
        } else {
            let (workspaceArg, rem0) = parseOption(commandArgs, name: "--workspace")
            let (_, rem1) = parseOption(rem0, name: "--window")
            target = workspaceArg ?? rem1.first(where: { !$0.hasPrefix("--") })
        }

        var params: [String: Any] = [:]
        let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
        if let winId { params["window_id"] = winId }
        let wsId = try normalizeWorkspaceHandle(target, client: client, windowHandle: winId)
        if let wsId { params["workspace_id"] = wsId }
        let payload = try client.sendV2(method: "workspace.close", params: params)
        if let closedWorkspaceId = (payload["workspace_id"] as? String) ?? wsId {
            try? tmuxPruneCompatWorkspaceState(workspaceId: closedWorkspaceId)
        }
        printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["workspace"]))
    }

    private func runWorkspaceSelectCommand(
        commandName: String,
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?,
        requireWorkspaceFlag: Bool
    ) throws {
        let target: String?
        if requireWorkspaceFlag {
            guard let workspaceRaw = optionValue(commandArgs, name: "--workspace") else {
                throw CLIError(message: "\(commandName) requires --workspace")
            }
            target = workspaceRaw
        } else {
            let (workspaceArg, rem0) = parseOption(commandArgs, name: "--workspace")
            let (_, rem1) = parseOption(rem0, name: "--window")
            target = workspaceArg ?? rem1.first(where: { !$0.hasPrefix("--") })
        }

        var params: [String: Any] = [:]
        let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
        if let winId { params["window_id"] = winId }
        let wsId = try normalizeWorkspaceHandle(target, client: client, windowHandle: winId)
        if !requireWorkspaceFlag {
            guard let wsId else {
                throw CLIError(message: "\(commandName): could not resolve workspace handle")
            }
            params["workspace_id"] = wsId
        } else if let wsId {
            params["workspace_id"] = wsId
        }
        let payload = try client.sendV2(method: "workspace.select", params: params)
        printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["workspace"]))
    }

    private func runWorkspaceRenameCommand(
        commandName: String,
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?,
        mode: WorkspaceRenameCommandMode
    ) throws {
        let winId: String?
        let wsId: String
        let title: String

        switch mode {
        case .legacy:
            let (wsArg, rem0) = parseOption(commandArgs, name: "--workspace")
            let (windowOpt, rem1) = parseOption(rem0, name: "--window")
            let windowRaw = windowOpt ?? windowOverride
            let workspaceArg = wsArg ?? (windowRaw == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)
            let titleArgs = rem1.dropFirst(rem1.first == "--" ? 1 : 0)
            title = titleArgs.joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
            guard !title.isEmpty else {
                throw CLIError(message: "\(commandName) requires a title")
            }
            winId = try normalizeWindowHandle(windowRaw, client: client)
            wsId = try resolveWorkspaceId(workspaceArg, client: client, windowHandle: winId)

        case .namespace:
            let (titleOpt, rem0) = parseOption(commandArgs, name: "--title")
            let (workspaceArg, rem1) = parseOption(rem0, name: "--workspace")
            let (_, rem2) = parseOption(rem1, name: "--window")
            let positional = rem2.first(where: { !$0.hasPrefix("--") })
            let target = workspaceArg ?? positional
            guard let titleOpt else {
                throw CLIError(message: "\(commandName) requires --title <new>")
            }
            title = titleOpt
            winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
            guard let normalizedWorkspaceId = try normalizeWorkspaceHandle(target, client: client, windowHandle: winId) else {
                throw CLIError(message: "\(commandName): could not resolve workspace handle")
            }
            wsId = normalizedWorkspaceId
        }

        var params: [String: Any] = ["title": title, "workspace_id": wsId]
        if let winId { params["window_id"] = winId }
        let payload = try client.sendV2(method: "workspace.rename", params: params)
        printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["workspace"]))
    }

    /// Top-level `cmux workspace <subcommand>` namespace. Dispatches to the
    /// same v2 socket methods that legacy verbs use (`new-workspace`,
    /// `list-workspaces`, etc.) so behavior matches. Legacy verbs keep working
    /// unchanged for backwards compatibility.
    /// `cmux window default-display [<name>|--clear]` — read/write the shared,
    /// cross-tag default display that DEBUG cmux builds open new windows on.
    ///
    /// Persisted through ``CmuxSettings/JSONConfigStore`` in the shared
    /// `cmux.json` under `app.devWindowDisplay`, so it applies to every tagged
    /// dev build regardless of bundle id. No running app required: the value is
    /// read/written directly on disk via the store on this no-socket early path.
    private func runWindowDefaultDisplayCommand(commandArgs: [String], jsonOutput: Bool) throws {
        let store = JSONConfigStore(fileURL: CmuxConfigLocation().userConfigFile)
        let key = SettingCatalog().app.devWindowDisplay

        // Bridge the actor-backed store to this synchronous CLI: run the async
        // store call on the cooperative pool and block this thread until it
        // signals. The semaphore establishes the happens-before that makes the
        // `nonisolated(unsafe)` result hand-off race-free.
        func runBlocking<T: Sendable>(_ work: @escaping @Sendable () async throws -> T) throws -> T {
            let semaphore = DispatchSemaphore(value: 0)
            nonisolated(unsafe) var output: Result<T, Error>!
            Task {
                do { output = .success(try await work()) }
                catch { output = .failure(error) }
                semaphore.signal()
            }
            semaphore.wait()
            return try output.get()
        }

        func currentValue() throws -> String? {
            let trimmed = try runBlocking { await store.value(for: key) }
                .trimmingCharacters(in: .whitespacesAndNewlines)
            return trimmed.isEmpty ? nil : trimmed
        }

        if commandArgs.contains("--clear") {
            try runBlocking { try await store.reset(key) }
            if jsonOutput { print(jsonString(["default_display": NSNull()])) }
            else { print("Cleared dev window display default.") }
            return
        }

        let positional = commandArgs.filter { !$0.hasPrefix("-") }
        if let raw = positional.first {
            let name = raw.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !name.isEmpty else {
                throw CLIError(message: "window default-display requires a display name, or --clear")
            }
            try runBlocking { try await store.set(name, for: key) }
            if jsonOutput { print(jsonString(["default_display": name])) }
            else { print("Dev builds will open on \"\(name)\" (DEBUG builds, applied at window creation).") }
            return
        }

        let current = try currentValue()
        if jsonOutput {
            if let current {
                print(jsonString(["default_display": current]))
            } else {
                print(jsonString(["default_display": NSNull()]))
            }
        } else {
            print(current ?? "(unset)")
        }
    }

    private func runWindowNamespace(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        guard let sub = commandArgs.first?.lowercased() else {
            throw CLIError(message: "window requires a subcommand. Try: display, displays, default-display")
        }
        let rest = Array(commandArgs.dropFirst())
        switch sub {
        case "displays":
            try runWindowDisplaysCommand(client: client, jsonOutput: jsonOutput)
        case "display":
            try runWindowDisplayCommand(
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )
        default:
            throw CLIError(message: "Unknown window subcommand: \(sub). Try: display, displays")
        }
    }

    /// `cmux canvas <info|mode|set-frame|align|reveal|overview|set-viewport|new-pane|…>`
    /// — workspace canvas-layout control over the v2 `canvas.*` methods.
    private func runCanvasNamespace(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        guard let sub = commandArgs.first?.lowercased() else {
            throw CLIError(message: "canvas requires a subcommand. Try: info, mode, set-frame, align, reveal, overview, zoom, set-viewport, new-pane")
        }
        let rest = Array(commandArgs.dropFirst())
        // Split flags ("--name value") from bare positionals so a flag's
        // value is never mistaken for a positional argument.
        var positionals: [String] = []
        var index = 0
        while index < rest.count {
            let arg = rest[index]
            if arg.hasPrefix("--") {
                index += 2
            } else {
                positionals.append(arg)
                index += 1
            }
        }

        var params: [String: Any] = [:]
        if let workspaceRaw = optionValue(rest, name: "--workspace"),
           let wsId = try normalizeWorkspaceHandle(workspaceRaw, client: client) {
            params["workspace_id"] = wsId
        }

        func surfaceParam(positional: String?, required: Bool) throws {
            let raw = optionValue(rest, name: "--surface") ?? positional
            if let raw, let surfaceId = try normalizeSurfaceHandle(raw, client: client) {
                params["surface_id"] = surfaceId
            } else if required {
                throw CLIError(message: "canvas \(sub) requires a surface (positional or --surface <id|ref>)")
            }
        }

        let method: String
        switch sub {
        case "info":
            method = "canvas.info"
        case "mode":
            guard let mode = positionals.first?.lowercased(),
                  ["canvas", "splits", "toggle"].contains(mode) else {
                throw CLIError(message: "Usage: cmux canvas mode <canvas|splits|toggle>")
            }
            params["mode"] = mode
            method = "canvas.set_mode"
        case "set-frame":
            try surfaceParam(positional: positionals.first, required: true)
            for key in ["x", "y", "width", "height"] {
                guard let raw = optionValue(rest, name: "--\(key)"), let value = Double(raw) else {
                    throw CLIError(message: "canvas set-frame requires numeric --x --y --width --height")
                }
                params[key] = value
            }
            method = "canvas.set_frame"
        case "align":
            guard let command = positionals.first?.lowercased() else {
                throw CLIError(message: "Usage: cmux canvas align <tidy|align-left|align-right|align-top|align-bottom|equalize-widths|equalize-heights|distribute-horizontally|distribute-vertically>")
            }
            params["command"] = command
            method = "canvas.align"
        case "reveal":
            try surfaceParam(positional: positionals.first, required: false)
            method = "canvas.reveal"
        case "overview":
            method = "canvas.overview"
        case "zoom":
            guard let direction = positionals.first?.lowercased(),
                  ["in", "out", "reset"].contains(direction) else {
                throw CLIError(message: "Usage: cmux canvas zoom <in|out|reset>")
            }
            params["direction"] = direction
            method = "canvas.zoom"
        case "join":
            try surfaceParam(positional: positionals.first, required: true)
            guard let targetRaw = positionals.dropFirst().first ?? optionValue(rest, name: "--target"),
                  let targetId = try normalizeSurfaceHandle(targetRaw, client: client) else {
                throw CLIError(message: "Usage: cmux canvas join <surface> <target-surface>")
            }
            params["target_surface_id"] = targetId
            method = "canvas.join"
        case "break":
            try surfaceParam(positional: positionals.first, required: true)
            method = "canvas.break"
        case "select-tab":
            try surfaceParam(positional: positionals.first, required: true)
            method = "canvas.select_tab"
        case "set-viewport":
            for key in ["x", "y"] {
                guard let raw = optionValue(rest, name: "--\(key)"), let value = Double(raw) else {
                    throw CLIError(message: "canvas set-viewport requires numeric --x --y")
                }
                params[key] = value
            }
            if let raw = optionValue(rest, name: "--zoom") {
                guard let value = Double(raw) else {
                    throw CLIError(message: "canvas set-viewport --zoom must be numeric")
                }
                params["zoom"] = value
            }
            method = "canvas.set_viewport"
        case "new-pane":
            if let type = optionValue(rest, name: "--type")?.lowercased() {
                guard ["terminal", "browser"].contains(type) else {
                    throw CLIError(message: "Usage: cmux canvas new-pane [--type terminal|browser]")
                }
                params["type"] = type
            }
            method = "canvas.new_pane"
        default:
            throw CLIError(message: "Unknown canvas subcommand: \(sub). Try: info, mode, set-frame, align, reveal, overview, zoom, join, break, select-tab, set-viewport, new-pane")
        }

        let payload = try client.sendV2(method: method, params: params)
        printV2Payload(
            payload,
            jsonOutput: jsonOutput,
            idFormat: idFormat,
            fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["workspace", "surface"])
        )
    }

    /// `cmux window displays` — list connected displays (name + index).
    private func runWindowDisplaysCommand(client: SocketClient, jsonOutput: Bool) throws {
        let response = try client.sendV2(method: "window.displays")
        if jsonOutput {
            print(jsonString(response))
            return
        }
        let displays = (response["displays"] as? [[String: Any]]) ?? []
        if displays.isEmpty {
            print("No displays found.")
            return
        }
        for display in displays {
            let name = (display["name"] as? String) ?? "(unknown)"
            let index = (display["index"] as? Int) ?? -1
            let isMain = (display["main"] as? Bool) ?? false
            print("\(index): \(name)\(isMain ? "  (main)" : "")")
        }
    }

    /// `cmux window display "<name>"` — move this instance's window(s) onto the
    /// named display, preserving size. `--list` is an alias for `window displays`.
    private func runWindowDisplayCommand(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        if commandArgs.contains("--list") || commandArgs.contains("-l") {
            try runWindowDisplaysCommand(client: client, jsonOutput: jsonOutput)
            return
        }
        let positional = commandArgs.filter { !$0.hasPrefix("-") }
        guard let displayName = positional.first, !displayName.isEmpty else {
            throw CLIError(message: "window display requires a display name. Usage: cmux window display \"LG HDR 4K\"  (list names with: cmux window displays)")
        }
        var params: [String: Any] = ["display": displayName]
        if let windowOverride {
            let normalized = try normalizeWindowHandle(windowOverride, client: client) ?? windowOverride
            params["window_id"] = normalized
        }
        let response = try client.sendV2(method: "window.display", params: params)
        if jsonOutput {
            print(jsonString(formatIDs(response, mode: idFormat)))
            return
        }
        let resolvedDisplay = (response["display"] as? String) ?? displayName
        let movedCount = (response["moved"] as? [Any])?.count ?? 0
        print("Moved \(movedCount) window\(movedCount == 1 ? "" : "s") to \(resolvedDisplay).")
    }

    private func runWorkspaceNamespace(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        guard let sub = commandArgs.first?.lowercased() else {
            throw CLIError(message: String(
                localized: "cli.error.workspaceSubcommandRequired",
                defaultValue: "workspace requires a subcommand. Try: list, create, env, close, rename, select, status, reconnect, disconnect, loading, group"
            ))
        }
        let rest = Array(commandArgs.dropFirst())
        switch sub {
        case "group":
            try runWorkspaceGroup(
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )
        case "list":
            try runWorkspaceListCommand(
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )
        case "create":
            try runWorkspaceCreateCommand(
                commandName: "workspace create",
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride,
                honorJSONOutput: true
            )
        case "env":
            try runWorkspaceEnvCommand(
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )
        case "close":
            try runWorkspaceCloseCommand(
                commandName: "workspace close",
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride,
                requireWorkspaceFlag: false
            )
        case "rename":
            try runWorkspaceRenameCommand(
                commandName: "workspace rename",
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride,
                mode: .namespace
            )
        case "status":
            try runWorkspaceStatusCommand(
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )
        case "select":
            try runWorkspaceSelectCommand(
                commandName: "workspace select",
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride,
                requireWorkspaceFlag: false
            )
        case "reconnect":
            try runWorkspaceRemoteConnectionCommand(
                commandName: "workspace reconnect",
                method: "workspace.remote.reconnect",
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )
        case "disconnect":
            try runWorkspaceRemoteConnectionCommand(
                commandName: "workspace disconnect",
                method: "workspace.remote.disconnect",
                commandArgs: rest,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )
        case "loading":
            try runWorkspaceLoading(commandArgs: rest, client: client, windowId: windowOverride, jsonOutput: jsonOutput)
        default:
            throw CLIError(message: String(
                format: String(
                    localized: "cli.error.workspaceSubcommandUnknown",
                    defaultValue: "Unknown workspace subcommand: %@. Try: list, create, env, close, rename, select, status, reconnect, disconnect, loading, group"
                ),
                locale: .current,
                sub
            ))
        }
    }

    /// `cmux workspace reconnect|disconnect` — manual control over a remote
    /// (SSH) workspace's connection. Targets the positional/`--workspace`
    /// handle, then the caller's workspace, then the selected workspace.
    private func runWorkspaceRemoteConnectionCommand(
        commandName: String,
        method: String,
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        let (workspaceArg, rem0) = parseOption(commandArgs, name: "--workspace")
        let (_, rem1) = parseOption(rem0, name: "--window")
        let positional = rem1.first(where: { !$0.hasPrefix("--") })
        let windowRaw = windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride)
        // With an explicit --window and no workspace argument, target that
        // window's selected workspace on the server instead of the caller's
        // CMUX_WORKSPACE_ID, which may live in a different window.
        let target = workspaceArg
            ?? positional
            ?? (windowRaw == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)

        var params: [String: Any] = [:]
        let winId = try normalizeWindowHandle(windowRaw, client: client)
        if let winId { params["window_id"] = winId }
        if let wsId = try normalizeWorkspaceHandle(target, client: client, windowHandle: winId) {
            params["workspace_id"] = wsId
        }
        let payload = try client.sendV2(method: method, params: params)
        printV2Payload(
            payload,
            jsonOutput: jsonOutput,
            idFormat: idFormat,
            fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["workspace", "window"])
        )
    }

    /// Emit a `cmux workspace-group` mutation response: JSON when --json,
    /// otherwise a compact `OK`. Centralized so every mutating subcommand
    /// honors --json the same way the list/create paths do.
    private func printWorkspaceGroupResponse(
        _ response: [String: Any],
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) {
        if jsonOutput {
            print(jsonString(formatIDs(response, mode: idFormat)))
        } else {
            print("OK")
        }
    }

    /// Print a one-time deprecation hint to stderr for a legacy CLI verb that
    /// has a `cmux workspace <subcommand>` replacement. Honors CMUX_QUIET so
    /// scripts can opt out.
    private static let cliDeprecationNoticeShownKey = "CMUX_CLI_DEPRECATION_SHOWN"
    static func warnLegacyVerbDeprecated(_ legacy: String, replacement: String) {
        if ProcessInfo.processInfo.environment["CMUX_QUIET"] != nil { return }
        if getenv(cliDeprecationNoticeShownKey) != nil { return }
        cliWriteStderr("cmux: '\(legacy)' is now an alias for '\(replacement)'. The legacy form keeps working indefinitely; set CMUX_QUIET=1 to silence this notice.\n")
        setenv(cliDeprecationNoticeShownKey, "1", 1)
    }

    private func runWorkspaceGroup(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        guard let sub = commandArgs.first?.lowercased() else {
            throw CLIError(message: "workspace-group requires a subcommand. Try: list, create, ungroup, delete, rename, collapse, expand, pin, unpin, add, remove, set-anchor, new-workspace, set-color, set-icon, move, focus")
        }
        let rest = Array(commandArgs.dropFirst())
        var params: [String: Any] = [:]
        try applyWindowOrCallerContext(to: &params, client: client, windowRaw: windowFromArgsOrOverride(rest, windowOverride: windowOverride))

        func resolveGroupId(in rest: [String]) throws -> String {
            let (gidOpt, rem0) = parseOption(rest, name: "--group")
            if let gidOpt { return gidOpt }
            // Strip --window before scanning for a positional so a `--window
            // <value>` pair never gets parsed as the group id.
            let (_, rem1) = parseOption(rem0, name: "--window")
            for arg in rem1 where !arg.hasPrefix("--") {
                return arg
            }
            throw CLIError(message: "workspace-group \(sub) requires a group id or --group <id>")
        }

        switch sub {
        case "list":
            let payload = try client.sendV2(method: "workspace.group.list", params: params)
            if jsonOutput {
                print(jsonString(formatIDs(payload, mode: idFormat)))
            } else {
                let groups = payload["groups"] as? [[String: Any]] ?? []
                if groups.isEmpty {
                    print("No groups")
                } else {
                    for g in groups {
                        let handle = textHandle(g, idFormat: idFormat)
                        let name = (g["name"] as? String) ?? ""
                        let count = (g["member_count"] as? Int) ?? 0
                        let pin = (g["is_pinned"] as? Bool) == true ? " [pinned]" : ""
                        let coll = (g["is_collapsed"] as? Bool) == true ? " [collapsed]" : ""
                        print("\(handle)  \(name)  (\(count) members)\(pin)\(coll)")
                    }
                }
            }

        case "create":
            let (nameOpt, rem0) = parseOption(rest, name: "--name")
            let (cwdOpt, rem1) = parseOption(rem0, name: "--cwd")
            let (fromOpt, rem2) = parseOption(rem1, name: "--from")
            let (_, rem3) = parseOption(rem2, name: "--window")
            // Use the remainder AFTER every named option is stripped so the
            // positional name lookup can't pick up --from/--window values.
            let resolvedName = nameOpt ?? rem3.first(where: { !$0.hasPrefix("--") }) ?? ""
            params["name"] = resolvedName
            if let cwdOpt { params["cwd"] = resolvePath(cwdOpt) }
            if let fromOpt {
                let ids = fromOpt.split(separator: ",").map { String($0).trimmingCharacters(in: .whitespaces) }
                params["child_workspace_ids"] = ids
            }
            let response = try client.sendV2(method: "workspace.group.create", params: params)
            if jsonOutput {
                print(jsonString(formatIDs(response, mode: idFormat)))
            } else if let group = response["group"] as? [String: Any] {
                print("OK \(textHandle(group, idFormat: idFormat))")
            } else {
                print("OK")
            }

        case "ungroup":
            params["group_id"] = try resolveGroupId(in: rest)
            let resp = try client.sendV2(method: "workspace.group.ungroup", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "delete":
            // Destructive: closes every workspace inside the group. Use
            // `ungroup` instead if you want to keep the workspaces.
            params["group_id"] = try resolveGroupId(in: rest)
            let resp = try client.sendV2(method: "workspace.group.delete", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "rename":
            let (nameOpt, rem0) = parseOption(rest, name: "--name")
            let gid = try resolveGroupId(in: rem0)
            params["group_id"] = gid
            let positional = rem0.filter { !$0.hasPrefix("--") && $0 != gid }
            guard let newName = nameOpt ?? positional.first else {
                throw CLIError(message: "rename requires --name <name>")
            }
            params["name"] = newName
            let resp = try client.sendV2(method: "workspace.group.rename", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "collapse", "expand":
            params["group_id"] = try resolveGroupId(in: rest)
            let resp = try client.sendV2(method: "workspace.group.\(sub)", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "pin", "unpin":
            params["group_id"] = try resolveGroupId(in: rest)
            let resp = try client.sendV2(method: "workspace.group.\(sub)", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "add":
            let (groupOpt, rem0) = parseOption(rest, name: "--group")
            let (wsOpt, _) = parseOption(rem0, name: "--workspace")
            guard let gid = groupOpt, let wsId = wsOpt else {
                throw CLIError(message: "add requires --group <id> --workspace <id>")
            }
            params["group_id"] = gid
            params["workspace_id"] = wsId
            let resp = try client.sendV2(method: "workspace.group.add", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "remove":
            let (wsOpt, rem0) = parseOption(rest, name: "--workspace")
            // Strip --window before scanning for a positional so a `--window
            // <value>` pair never gets parsed as the workspace id.
            let (_, rem1) = parseOption(rem0, name: "--window")
            guard let wsId = wsOpt ?? rem1.first(where: { !$0.hasPrefix("--") }) else {
                throw CLIError(message: "remove requires --workspace <id>")
            }
            params["workspace_id"] = wsId
            let resp = try client.sendV2(method: "workspace.group.remove", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "set-anchor":
            let (groupOpt, rem0) = parseOption(rest, name: "--group")
            let (wsOpt, _) = parseOption(rem0, name: "--workspace")
            guard let gid = groupOpt, let wsId = wsOpt else {
                throw CLIError(message: "set-anchor requires --group <id> --workspace <id>")
            }
            params["group_id"] = gid
            params["workspace_id"] = wsId
            let resp = try client.sendV2(method: "workspace.group.set_anchor", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "new-workspace":
            let (placementOpt, rem0) = parseOption(rest, name: "--placement")
            params["group_id"] = try resolveGroupId(in: rem0)
            if let placementOpt {
                params["placement"] = placementOpt
            }
            let response = try client.sendV2(method: "workspace.group.new_workspace", params: params)
            if jsonOutput {
                print(jsonString(formatIDs(response, mode: idFormat)))
            } else if let wsId = response["workspace_ref"] as? String {
                print("OK \(wsId)")
            } else {
                print("OK")
            }

        case "set-color":
            let (hexOpt, rem0) = parseOption(rest, name: "--hex")
            params["group_id"] = try resolveGroupId(in: rem0)
            // Treat --hex with no value (or `--hex ""`) as a clear.
            params["hex"] = hexOpt ?? ""
            let resp = try client.sendV2(method: "workspace.group.set_color", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "set-icon":
            let (symbolOpt, rem0) = parseOption(rest, name: "--symbol")
            params["group_id"] = try resolveGroupId(in: rem0)
            params["symbol"] = symbolOpt ?? ""
            let resp = try client.sendV2(method: "workspace.group.set_icon", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "move":
            let (toIndexOpt, rem0) = parseOption(rest, name: "--to-index")
            let (beforeOpt, rem1) = parseOption(rem0, name: "--before")
            let (afterOpt, rem2) = parseOption(rem1, name: "--after")
            // Resolve the source group from rem2, which has every
            // move-position flag stripped — otherwise the positional scan
            // could pick up the value of --to-index/--before/--after.
            params["group_id"] = try resolveGroupId(in: rem2)
            if let toIndexOpt {
                guard let n = Int(toIndexOpt) else {
                    throw CLIError(message: "move --to-index must be an integer")
                }
                params["to_index"] = n
            } else if let beforeOpt {
                params["before_group_id"] = beforeOpt
            } else if let afterOpt {
                params["after_group_id"] = afterOpt
            } else {
                throw CLIError(message: "move requires --to-index <n>, --before <group>, or --after <group>")
            }
            let resp = try client.sendV2(method: "workspace.group.move", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        case "focus":
            params["group_id"] = try resolveGroupId(in: rest)
            let resp = try client.sendV2(method: "workspace.group.focus", params: params)
            printWorkspaceGroupResponse(resp, jsonOutput: jsonOutput, idFormat: idFormat)

        default:
            throw CLIError(message: "Unknown workspace-group subcommand: \(sub)")
        }
    }

    private func runRenameTab(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        let (workspaceOpt, rem0) = parseOption(commandArgs, name: "--workspace")
        let (tabOpt, rem1) = parseOption(rem0, name: "--tab")
        let (surfaceOpt, rem2) = parseOption(rem1, name: "--surface")
        let (titleOpt, rem3) = parseOption(rem2, name: "--title")
        let (windowOpt, rem4) = parseOption(rem3, name: "--window")

        if rem4.contains("--action") {
            throw CLIError(message: "rename-tab does not accept --action (it always performs rename)")
        }
        if let unknown = rem4.first(where: { $0.hasPrefix("--") && $0 != "--" }) {
            throw CLIError(message: "rename-tab: unknown flag '\(unknown)'")
        }

        let inferredTitle = rem4
            .dropFirst(rem4.first == "--" ? 1 : 0)
            .joined(separator: " ")
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let title = (titleOpt ?? (inferredTitle.isEmpty ? nil : inferredTitle))?
            .trimmingCharacters(in: .whitespacesAndNewlines)

        guard let title, !title.isEmpty else {
            throw CLIError(message: "rename-tab requires a title")
        }

        var forwarded: [String] = ["--action", "rename", "--title", title]
        if let workspaceOpt {
            forwarded += ["--workspace", workspaceOpt]
        }
        if let tabOpt {
            forwarded += ["--tab", tabOpt]
        } else if let surfaceOpt {
            forwarded += ["--surface", surfaceOpt]
        }
        if let windowOpt {
            forwarded += ["--window", windowOpt]
        }

        try runTabAction(
            commandArgs: forwarded,
            client: client,
            jsonOutput: jsonOutput,
            idFormat: idFormat,
            windowOverride: windowOverride
        )
    }
    struct SSHCommandOptions {
        let destination: String
        let displayDestination: String
        let port: Int?
        let identityFile: String?
        let workspaceName: String?
        let windowRaw: String?
        let noFocus: Bool
        let sshOptions: [String]
        let extraArguments: [String]
        let agentSocketPath: String?
        let passwordCredential: String?
        let localSocketPath: String
        let remoteRelayPort: Int
        let pinWorkspaceToTop: Bool
        let daemonWebSocketEndpoint: VMDaemonWebSocketEndpoint?
        /// True when the remote is a cloud VM with cmuxd-remote pre-baked in the image.
        /// Set by `cmux vm new/shell/attach`; false for plain `cmux ssh`.
        let skipDaemonBootstrap: Bool

        init(
            destination: String,
            displayDestination: String? = nil,
            port: Int?,
            identityFile: String?,
            workspaceName: String?,
            windowRaw: String? = nil,
            noFocus: Bool,
            sshOptions: [String],
            extraArguments: [String],
            agentSocketPath: String? = nil,
            passwordCredential: String? = nil,
            localSocketPath: String,
            remoteRelayPort: Int,
            pinWorkspaceToTop: Bool = false,
            daemonWebSocketEndpoint: VMDaemonWebSocketEndpoint? = nil,
            skipDaemonBootstrap: Bool = false
        ) {
            self.destination = destination
            self.displayDestination = displayDestination ?? destination
            self.port = port
            self.identityFile = identityFile
            self.workspaceName = workspaceName
            self.windowRaw = windowRaw
            self.noFocus = noFocus
            self.sshOptions = sshOptions
            self.extraArguments = extraArguments
            self.agentSocketPath = agentSocketPath
            self.passwordCredential = passwordCredential
            self.localSocketPath = localSocketPath
            self.remoteRelayPort = remoteRelayPort
            self.pinWorkspaceToTop = pinWorkspaceToTop
            self.daemonWebSocketEndpoint = daemonWebSocketEndpoint
            self.skipDaemonBootstrap = skipDaemonBootstrap
        }
    }

    private struct VMPtyWebSocketEndpoint {
        let url: String
        let headers: [String: String]
        let token: String
        let sessionId: String
        let attachmentId: String
        let expiresAtUnix: Int64
        let daemon: VMDaemonWebSocketEndpoint?
    }

    struct VMDaemonWebSocketEndpoint {
        let url: String
        let headers: [String: String]
        let token: String
        let sessionId: String
        let expiresAtUnix: Int64
    }

    private struct VMPtyWebSocketConfig: Codable {
        let url: String
        let headers: [String: String]
        let token: String
        let sessionId: String
        let attachmentId: String
    }

    private struct TerminalSize {
        let cols: Int
        let rows: Int
    }

    private struct RemoteDaemonManifest: Decodable {
        struct Entry: Decodable {
            let goOS: String
            let goArch: String
            let assetName: String
            let downloadURL: String
            let sha256: String
        }

        let schemaVersion: Int
        let appVersion: String
        let releaseTag: String
        let releaseURL: String
        let checksumsAssetName: String
        let checksumsURL: String
        let entries: [Entry]

        func entry(goOS: String, goArch: String) -> Entry? {
            entries.first { $0.goOS == goOS && $0.goArch == goArch }
        }
    }

    private func generateRemoteRelayPort() -> Int {
        // Random port in the ephemeral range (49152-65535)
        Int.random(in: 49152...65535)
    }

    private func randomHex(byteCount: Int) throws -> String {
        var bytes = [UInt8](repeating: 0, count: byteCount)
        let status = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        guard status == errSecSuccess else {
            throw CLIError(message: "failed to generate SSH relay credential")
        }
        return bytes.map { String(format: "%02x", $0) }.joined()
    }

    private func runSSH(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        // Use the socket path from this invocation (supports --socket overrides).
        let localSocketPath = client.socketPath
        let remoteRelayPort = generateRemoteRelayPort()
        let relayID = UUID().uuidString.lowercased()
        let relayToken = try randomHex(byteCount: 32)
        let sshOptions = try parseSSHCommandOptions(
            commandArgs,
            localSocketPath: localSocketPath,
            remoteRelayPort: remoteRelayPort,
            windowOverride: windowOverride
        )
        try runSSHWithOptions(
            sshOptions,
            relayID: relayID,
            relayToken: relayToken,
            client: client,
            jsonOutput: jsonOutput,
            idFormat: idFormat
        )
    }

    /// Mirrors a remote host's tmux sessions; interactive SSH authentication runs
    /// inline in the caller's terminal before retrying over the shared master.
    private func runRemoteTmux(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool
    ) throws {
        var destination: String?
        var port: Int?
        var identityFile: String?
        var noFocus = false
        var newWindow = false

        // Intentional subset of parseSSHCommandOptions: ssh-tmux has no relay,
        // passthrough, --ssh-option, --name, or --window support.
        var index = 0
        while index < commandArgs.count {
            let arg = commandArgs[index]
            switch arg {
            case "--port":
                guard index + 1 < commandArgs.count else {
                    throw CLIError(message: "ssh-tmux: --port requires a value")
                }
                guard let parsed = Int(commandArgs[index + 1]), parsed > 0, parsed <= 65535 else {
                    throw CLIError(message: "ssh-tmux: --port must be 1-65535")
                }
                port = parsed
                index += 2
            case "--identity":
                guard index + 1 < commandArgs.count else {
                    throw CLIError(message: "ssh-tmux: --identity requires a path")
                }
                identityFile = commandArgs[index + 1]
                index += 2
            case "--no-focus":
                noFocus = true
                index += 1
            case "--new-window":
                newWindow = true
                index += 1
            default:
                if arg.hasPrefix("-") {
                    throw CLIError(
                        message: "ssh-tmux: destination must be <user@host> or an ssh alias. Use --port/--identity for SSH flags."
                    )
                }
                if destination == nil {
                    destination = arg
                } else {
                    throw CLIError(message: "ssh-tmux: unexpected extra argument '\(arg)'")
                }
                index += 1
            }
        }

        guard let destination else {
            throw CLIError(message: "ssh-tmux requires a destination (example: cmux ssh-tmux user@host)")
        }

        var params: [String: Any] = ["host": destination]
        if let port { params["port"] = port }
        if let identityFile, !identityFile.isEmpty { params["identity_file"] = identityFile }
        params["activate"] = !noFocus
        if !newWindow {
            try applyWindowOrCallerContext(to: &params, client: client, windowRaw: nil)
        }
        // BatchMode discovery can take a couple of seconds; show progress.
        if !jsonOutput {
            print("Connecting to \(destination)…")
        }

        // Retry interactive authentication once; never spin on auth-required.
        let method = newWindow ? "remote.tmux.window" : "remote.tmux.mirror"
        var didAuthenticate = false
        while true {
            let result = try client.sendV2(
                method: method,
                params: params,
                responseTimeout: 75  // > the app-side 60s timeout, so the app's result/error always arrives first
            )
            if (result["mirrored"] as? Bool) == true {
                if jsonOutput {
                    print(jsonString(result))
                } else {
                    let windowId = (result["window_id"] as? String) ?? ""
                    let count = (result["workspace_ids"] as? [Any])?.count ?? 0
                    print("OK host=\(destination) workspaces=\(count) window=\(windowId)")
                }
                return
            }
            if (result["auth_required"] as? Bool) == true {
                guard !didAuthenticate else {
                    throw CLIError(
                        message: "ssh-tmux: authentication did not open the connection to \(destination)"
                    )
                }
                guard let sshArgv = result["ssh_argv"] as? [String], !sshArgv.isEmpty else {
                    throw CLIError(
                        message: "ssh-tmux: cmux did not return an ssh command for authentication"
                    )
                }
                try runInteractiveAuthSSH(sshArgv: sshArgv, destination: destination)
                didAuthenticate = true
                // Retry while the just-opened ControlMaster is warm.
                if !jsonOutput {
                    print("Authenticated; opening remote tmux mirror for \(destination)…")
                }
                continue
            }
            throw CLIError(message: "ssh-tmux: unexpected response from cmux")
        }
    }

    /// Runs an `ssh` argv interactively in the user's terminal so password /
    /// host-key / MFA / FIDO prompts work as in a normal SSH. The spawned ssh is
    /// made the terminal's foreground process group (Foundation otherwise spawns it
    /// backgrounded, where its tty read would be SIGTTIN-stopped and hang with no
    /// prompt).
    ///
    /// The argv is supplied by the app over the authenticated control socket, but
    /// as defense in depth the executable is required to be an `ssh` binary — the
    /// CLI never execs an arbitrary command handed back from a socket response.
    private func runInteractiveAuthSSH(sshArgv: [String], destination: String) throws {
        // Interactive auth needs a controlling tty to prompt on. In a non-tty
        // context (script, pipe, URL handler) ssh can't prompt and would hang or
        // fail opaquely, so refuse early with an actionable message.
        guard isatty(STDIN_FILENO) == 1 else {
            throw CLIError(
                message: "ssh-tmux: \(destination) needs interactive authentication, which requires a terminal. Run `cmux ssh-tmux \(destination)` directly from an interactive shell."
            )
        }
        // The app builds this argv with a hardcoded /usr/bin/ssh; require exactly
        // that. A basename check would accept a planted /tmp/ssh — pin the full
        // path so the CLI never execs an arbitrary command returned over the socket.
        let allowedSSHPaths: Set<String> = ["/usr/bin/ssh"]
        guard let executable = sshArgv.first, allowedSSHPaths.contains(executable) else {
            throw CLIError(message: "ssh-tmux: refusing to run a non-standard ssh path for authentication")
        }
        let process = Process()
        process.executableURL = URL(fileURLWithPath: executable)
        process.arguments = Array(sshArgv.dropFirst())
        process.standardInput = FileHandle.standardInput
        process.standardOutput = FileHandle.standardOutput
        process.standardError = FileHandle.standardError

        // Foundation spawns the child in its OWN process group, so ssh starts as a
        // BACKGROUND job of the terminal. ssh's password / host-key / MFA prompt
        // reads from the controlling tty, and a background tty read raises SIGTTIN,
        // which STOPS ssh — it hangs forever with no prompt (cert/agent hosts never
        // read the tty, so they were unaffected). Hand the terminal's foreground
        // process group to the child (and SIGCONT it in case it already stopped) so
        // it can prompt, exactly as the other interactive-child CLI paths do; the
        // `defer` reclaims the foreground for this CLI when ssh exits.
        let originalForegroundProcessGroup = tcgetpgrp(STDIN_FILENO)
        var didForegroundChild = false
        do {
            try cliRunProcess(process)
        } catch {
            throw CLIError(message: "ssh-tmux: failed to launch ssh: \(String(describing: error))")
        }
        if originalForegroundProcessGroup > 0 {
            let childProcessGroup = getpgid(process.processIdentifier)
            if childProcessGroup > 0 && childProcessGroup != originalForegroundProcessGroup {
                do {
                    try setTerminalForegroundProcessGroup(childProcessGroup)
                } catch {
                    // The handoff is required: without the terminal foreground, ssh's
                    // prompt SIGTTIN-stops and waitUntilExit() below hangs forever (the
                    // exact bug this dance prevents). Continue the child in case it
                    // already stopped, kill it, and fail loudly instead of hanging.
                    _ = Darwin.kill(-childProcessGroup, SIGCONT)
                    process.terminate()
                    throw CLIError(
                        message: "ssh-tmux: couldn't hand the terminal to ssh for \(destination); aborting to avoid a hang (\(String(describing: error)))"
                    )
                }
                _ = Darwin.kill(-childProcessGroup, SIGCONT)
                didForegroundChild = true
            }
        }
        defer {
            if didForegroundChild {
                try? setTerminalForegroundProcessGroup(originalForegroundProcessGroup)
            }
        }
        process.waitUntilExit()
        guard process.terminationStatus == 0 else {
            throw CLIError(
                message: "ssh-tmux: ssh authentication to \(destination) failed (exit \(process.terminationStatus))"
            )
        }
    }

    /// Generic "open a workspace, SSH into the remote, bootstrap cmuxd-remote, forward socket,
    /// drop the user in a shell" pipeline. The inner loop of `cmux ssh`; also called from
    /// `cmux vm new`/`shell`/`attach` so cloud VMs reuse the exact same bootstrap.
    private func runSSHWithOptions(
        _ sshOptions: SSHCommandOptions,
        relayID: String,
        relayToken: String,
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        vmIDForSplitAttach: String? = nil
    ) throws {
        let sshStartedAt = Date()
        func logSSHTiming(_ stage: String, extra: String = "") {
            let elapsedMs = Int(Date().timeIntervalSince(sshStartedAt) * 1000)
            let suffix = extra.isEmpty ? "" : " \(extra)"
            cliDebugLog(
                "cli.ssh.timing target=\(sshOptions.displayDestination) relayPort=\(sshOptions.remoteRelayPort) " +
                "stage=\(stage) elapsedMs=\(elapsedMs)\(suffix)"
            )
        }

        logSSHTiming("parsed")
        let terminfoSource = localXtermGhosttyTerminfoSource()
        cliDebugLog(
            "cli.ssh.timing target=\(sshOptions.displayDestination) relayPort=\(sshOptions.remoteRelayPort) " +
            "stage=terminfo elapsedMs=0 mode=deferred term=xterm-256color " +
            "source=\(terminfoSource == nil ? 0 : 1)"
        )
        let shellFeaturesValue = scopedGhosttyShellFeaturesValue()
        let remoteSSHOptions = effectiveSSHOptions(
            sshOptions.sshOptions,
            remoteRelayPort: sshOptions.remoteRelayPort
        )
        let controlPathPreflightShellFunction = sshControlPathPreflightShellFunction(options: sshOptions)
        let initialSSHCommand = buildSSHCommandText(sshOptions)
        // For VM workspaces (Freestyle), skip the interactive bootstrap script: the russh
        // gateway forwards shell-request PTYs but stalls on exec-channel I/O, and the bootstrap
        // script is only meaningful if cmuxd-remote is participating. Let ssh open a plain
        // interactive shell instead.
        let remoteTerminalBootstrapScript: String?
        if sshOptions.skipDaemonBootstrap {
            remoteTerminalBootstrapScript = nil
        } else {
            remoteTerminalBootstrapScript = sshOptions.extraArguments.isEmpty
                ? buildInteractiveRemoteShellScript(
                    remoteRelayPort: sshOptions.remoteRelayPort,
                    shellFeatures: shellFeaturesValue,
                    terminfoSource: terminfoSource
                )
                : nil
        }
        let remoteTerminalSSHCommand = buildSSHCommandText(
            sshOptions,
            remoteBootstrapScript: remoteTerminalBootstrapScript
        )
        let deferredRemoteReconnectToken = UUID().uuidString.lowercased()
        let deferredRemoteReconnectCommandScript = deferredRemoteReconnectLocalCommandScript(
            in: remoteSSHOptions,
            localCLIPath: resolvedExecutableURL()?.path,
            foregroundAuthToken: deferredRemoteReconnectToken
        )
        let sshConnectionTimingCommandScript = sshConnectionTimingLocalCommandScript(
            target: sshOptions.displayDestination,
            relayPort: sshOptions.remoteRelayPort
        )
        let combinedLocalCommandScript = combinedLocalShellScript([
            deferredRemoteReconnectCommandScript,
            sshConnectionTimingCommandScript,
        ])
        let configuredForegroundAuthToken = deferredRemoteReconnectCommandScript == nil
            ? nil
            : deferredRemoteReconnectToken
        let usesPersistentFreestyleCloud =
            sshOptions.skipDaemonBootstrap &&
            sshOptions.pinWorkspaceToTop &&
            vmIDForSplitAttach != nil
        let usesPersistentSSHPTY =
            !sshOptions.skipDaemonBootstrap &&
            sshOptions.extraArguments.isEmpty &&
            remoteTerminalBootstrapScript?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false &&
            deferredRemoteReconnectCommandScript != nil
        let persistentDaemonSlot = usesPersistentSSHPTY
            ? "ssh-\(UUID().uuidString.lowercased())"
            : (usesPersistentFreestyleCloud ? Self.persistentCloudVMSlotID : nil)
        let startupInitialSSHCommand = buildSSHCommandText(
            sshOptions,
            localCommandScript: combinedLocalCommandScript
        )
        let startupRemoteTerminalSSHCommand = buildSSHCommandText(
            sshOptions,
            remoteBootstrapScript: remoteTerminalBootstrapScript,
            localCommandScript: combinedLocalCommandScript
        )
        var initialSSHStartupCommand: String
        var remoteTerminalSSHStartupCommand: String
        if let remoteTerminalBootstrapScript, !remoteTerminalBootstrapScript.isEmpty {
            initialSSHStartupCommand = try buildBootstrapSSHStartupCommand(
                options: sshOptions,
                remoteBootstrapScript: remoteTerminalBootstrapScript,
                shellFeatures: shellFeaturesValue,
                remoteRelayPort: sshOptions.remoteRelayPort,
                localCommandScript: combinedLocalCommandScript,
                passwordCredential: sshOptions.passwordCredential,
                controlPathPreflightShellFunction: controlPathPreflightShellFunction
            )
            remoteTerminalSSHStartupCommand = buildReusableBootstrapSSHStartupCommand(
                options: sshOptions,
                remoteBootstrapScript: remoteTerminalBootstrapScript,
                shellFeatures: shellFeaturesValue,
                remoteRelayPort: sshOptions.remoteRelayPort,
                localCommandScript: combinedLocalCommandScript,
                passwordCredential: sshOptions.passwordCredential,
                controlPathPreflightShellFunction: controlPathPreflightShellFunction
            )
        } else {
            initialSSHStartupCommand = try buildSSHStartupCommand(
                sshCommand: startupInitialSSHCommand,
                shellFeatures: "",
                remoteRelayPort: sshOptions.remoteRelayPort,
                passwordCredential: sshOptions.passwordCredential,
                controlPathPreflightShellFunction: controlPathPreflightShellFunction
            )
            remoteTerminalSSHStartupCommand = buildReusableSSHStartupCommand(
                sshCommand: startupRemoteTerminalSSHCommand,
                shellFeatures: shellFeaturesValue,
                remoteRelayPort: sshOptions.remoteRelayPort,
                passwordCredential: sshOptions.passwordCredential,
                controlPathPreflightShellFunction: controlPathPreflightShellFunction
            )
        }
        if usesPersistentSSHPTY,
           let remoteTerminalBootstrapScript {
            let ptyStartupCommand = buildReusableForegroundAuthThenSSHPTYAttachStartupCommand(
                options: sshOptions,
                remoteShellCommand: remoteTerminalBootstrapScript,
                localCommandScript: combinedLocalCommandScript,
                passwordCredential: sshOptions.passwordCredential,
                controlPathPreflightShellFunction: controlPathPreflightShellFunction
            )
            initialSSHStartupCommand = ptyStartupCommand
            remoteTerminalSSHStartupCommand = ptyStartupCommand
        }
        let reusableTerminalStartupCommand: String
        if let vmIDForSplitAttach,
           sshOptions.skipDaemonBootstrap {
            let executablePath = resolvedExecutableURL()?.path ?? (args.first ?? "cmux")
            if usesPersistentFreestyleCloud {
                let splitAttachCommand = defaultFreestyleCloudSSHAttachLoopCommand(
                    vmID: vmIDForSplitAttach,
                    executablePath: executablePath
                )
                reusableTerminalStartupCommand = splitAttachCommand
                initialSSHStartupCommand = reusableTerminalStartupCommand; remoteTerminalSSHStartupCommand = reusableTerminalStartupCommand
            } else {
                let splitAttachCommand = [
                    "env",
                    "CMUX_SSH_RECONNECT_LIMIT=${CMUX_SSH_RECONNECT_LIMIT:-86400}",
                    "CMUX_SSH_RECONNECT_DELAY_SECONDS=${CMUX_SSH_RECONNECT_DELAY_SECONDS:-2}",
                    shellQuote(executablePath),
                    "vm",
                    "ssh-attach",
                    "--id",
                    shellQuote(vmIDForSplitAttach),
                    "--default-freestyle-sshd",
                ].joined(separator: " ")
                reusableTerminalStartupCommand = buildReusableSSHStartupCommand(
                    sshCommand: splitAttachCommand,
                    shellFeatures: shellFeaturesValue,
                    remoteRelayPort: 0,
                    reconnectLimitDefault: 86400
                )
            }
        } else {
            reusableTerminalStartupCommand = remoteTerminalSSHStartupCommand
        }
        cliDebugLog(
            "cli.ssh.start target=\(sshOptions.displayDestination) port=\(sshOptions.port.map(String.init) ?? "nil") " +
            "relayPort=\(sshOptions.remoteRelayPort) localSocket=\(sshOptions.localSocketPath) " +
            "controlPath=\(sshOptionValue(named: "ControlPath", in: remoteSSHOptions) ?? "nil") " +
            "workspaceName=\(sshOptions.workspaceName?.replacingOccurrences(of: " ", with: "_") ?? "nil") " +
            "extraArgs=\(sshOptions.extraArguments.count)"
        )

        let normalizedWorkspaceName = sshOptions.workspaceName?.trimmingCharacters(in: .whitespacesAndNewlines)
        let existingPinnedWorkspace = sshOptions.pinWorkspaceToTop
            ? try reusableNamedWorkspace(
                named: normalizedWorkspaceName,
                windowRaw: sshOptions.windowRaw,
                expectedManagedCloudVMID: usesPersistentFreestyleCloud ? vmIDForSplitAttach : nil,
                expectedPersistentDaemonSlot: usesPersistentFreestyleCloud ? persistentDaemonSlot : nil,
                client: client
            )
            : nil
        let workspaceId: String
        let workspaceWindowId: String?
        var workspaceInitialSurfaceId: String?
        let didCreateWorkspace: Bool
        if let existingPinnedWorkspace {
            workspaceId = existingPinnedWorkspace.workspaceId
            workspaceWindowId = existingPinnedWorkspace.windowId
            didCreateWorkspace = false
            cliDebugLog(
                "cli.ssh.workspace.reused workspace=\(String(workspaceId.prefix(8))) " +
                "window=\(workspaceWindowId.map { String($0.prefix(8)) } ?? "nil")"
            )
        } else {
            var workspaceCreateParams: [String: Any] = [
                "initial_command": initialSSHStartupCommand,
            ]
            if let agentSocketPath = sshOptions.agentSocketPath {
                workspaceCreateParams["initial_env"] = [
                    "SSH_AUTH_SOCK": agentSocketPath,
                ]
            }
            try applyWindowOrCallerContext(to: &workspaceCreateParams, client: client, windowRaw: sshOptions.windowRaw)

            let workspaceCreateStartedAt = Date()
            let workspaceCreate = try client.sendV2(method: "workspace.create", params: workspaceCreateParams)
            guard let createdWorkspaceId = workspaceCreate["workspace_id"] as? String, !createdWorkspaceId.isEmpty else {
                throw CLIError(message: "workspace.create did not return workspace_id")
            }
            workspaceId = createdWorkspaceId
            let rawWorkspaceInitialSurfaceId = (workspaceCreate["surface_id"] as? String)?
                .trimmingCharacters(in: .whitespacesAndNewlines)
            workspaceInitialSurfaceId = rawWorkspaceInitialSurfaceId?.isEmpty == false
                ? rawWorkspaceInitialSurfaceId
                : nil
            if usesPersistentSSHPTY && workspaceInitialSurfaceId == nil {
                do {
                    workspaceInitialSurfaceId = try resolveSurfaceId(nil, workspaceId: workspaceId, client: client)
                } catch {
                    do {
                        _ = try client.sendV2(method: "workspace.close", params: ["workspace_id": workspaceId])
                    } catch {
                        let warning = "Warning: failed to rollback workspace \(workspaceId): \(error)\n"
                        cliWriteStderr(warning)
                    }
                    throw CLIError(
                        message: "cmux could not resolve the initial terminal surface for persistent SSH PTY startup"
                    )
                }
            }
            workspaceWindowId = (workspaceCreate["window_id"] as? String)?
                .trimmingCharacters(in: .whitespacesAndNewlines)
            didCreateWorkspace = true
            cliDebugLog(
                "cli.ssh.workspace.created workspace=\(String(workspaceId.prefix(8))) " +
                "window=\(workspaceWindowId.map { String($0.prefix(8)) } ?? "nil")"
            )
            cliDebugLog(
                "cli.ssh.timing target=\(sshOptions.displayDestination) relayPort=\(sshOptions.remoteRelayPort) " +
                "workspace=\(String(workspaceId.prefix(8))) stage=workspace.create elapsedMs=\(Int(Date().timeIntervalSince(workspaceCreateStartedAt) * 1000))"
            )
        }
        let configuredPayload: [String: Any]
        do {
            if didCreateWorkspace,
               let workspaceName = normalizedWorkspaceName,
               !workspaceName.isEmpty {
                _ = try client.sendV2(method: "workspace.rename", params: [
                    "workspace_id": workspaceId,
                    "title": workspaceName,
                ])
            }
            if sshOptions.pinWorkspaceToTop {
                try pinWorkspaceToTop(workspaceId: workspaceId, windowId: workspaceWindowId, client: client)
            }

            var configureParams: [String: Any] = [
                "workspace_id": workspaceId,
                "destination": sshOptions.destination,
                "auto_connect": deferredRemoteReconnectCommandScript == nil,
            ]
            if let configuredForegroundAuthToken {
                configureParams["foreground_auth_token"] = configuredForegroundAuthToken
            }
            if let port = sshOptions.port {
                configureParams["port"] = port
            }
            if let identityFile = normalizedSSHIdentityPath(sshOptions.identityFile) {
                configureParams["identity_file"] = identityFile
            }
            if !remoteSSHOptions.isEmpty {
                configureParams["ssh_options"] = remoteSSHOptions
            }
            if let agentSocketPath = sshOptions.agentSocketPath {
                configureParams["ssh_auth_sock"] = agentSocketPath
            }
            if sshOptions.remoteRelayPort > 0 {
                configureParams["relay_port"] = sshOptions.remoteRelayPort
                configureParams["relay_id"] = relayID
                configureParams["relay_token"] = relayToken
                configureParams["local_socket_path"] = sshOptions.localSocketPath
            }
            if let daemon = sshOptions.daemonWebSocketEndpoint {
                configureParams["daemon_websocket_url"] = daemon.url
                configureParams["daemon_websocket_headers"] = daemon.headers
                configureParams["daemon_websocket_token"] = daemon.token
                configureParams["daemon_websocket_session_id"] = daemon.sessionId
                configureParams["daemon_websocket_expires_at_unix"] = daemon.expiresAtUnix
                configureParams["local_socket_path"] = sshOptions.localSocketPath
            }
            if let vmIDForSplitAttach {
                configureParams["managed_cloud_vm_id"] = vmIDForSplitAttach
            }
            configureParams["terminal_startup_command"] = reusableTerminalStartupCommand
            if sshOptions.skipDaemonBootstrap {
                configureParams["skip_daemon_bootstrap"] = true
            }
            if let persistentDaemonSlot {
                configureParams["preserve_after_terminal_exit"] = true
                configureParams["persistent_daemon_slot"] = persistentDaemonSlot
            }

            cliDebugLog(
                "cli.ssh.remote.configure workspace=\(String(workspaceId.prefix(8))) " +
                "target=\(sshOptions.displayDestination) relayPort=\(sshOptions.remoteRelayPort) " +
                "controlPath=\(sshOptionValue(named: "ControlPath", in: remoteSSHOptions) ?? "nil") " +
                "deferredReconnect=\(deferredRemoteReconnectCommandScript == nil ? 0 : 1) " +
                "sshOptions=\(remoteSSHOptions.joined(separator: "|"))"
            )
            let configureStartedAt = Date()
            configuredPayload = try client.sendV2(method: "workspace.remote.configure", params: configureParams)
            var selectParams: [String: Any] = ["workspace_id": workspaceId]
            if let workspaceWindowId, !workspaceWindowId.isEmpty {
                selectParams["window_id"] = workspaceWindowId
            }
            if !sshOptions.noFocus {
                let selectStartedAt = Date()
                _ = try client.sendV2(method: "workspace.select", params: selectParams)
                cliDebugLog(
                    "cli.ssh.timing target=\(sshOptions.displayDestination) relayPort=\(sshOptions.remoteRelayPort) " +
                    "workspace=\(String(workspaceId.prefix(8))) stage=workspace.select elapsedMs=\(Int(Date().timeIntervalSince(selectStartedAt) * 1000))"
                )
            }
            if !didCreateWorkspace,
               sshOptions.pinWorkspaceToTop {
                let surfaceId = try resolveSurfaceId(nil, workspaceId: workspaceId, client: client)
                let reconnectStartedAt = Date()
                _ = try client.sendV2(method: "workspace.remote.reconnect", params: [
                    "workspace_id": workspaceId,
                    "surface_id": surfaceId,
                ])
                cliDebugLog(
                    "cli.ssh.timing target=\(sshOptions.displayDestination) relayPort=\(sshOptions.remoteRelayPort) " +
                    "workspace=\(String(workspaceId.prefix(8))) surface=\(String(surfaceId.prefix(8))) " +
                    "stage=workspace.remote.reconnect elapsedMs=\(Int(Date().timeIntervalSince(reconnectStartedAt) * 1000))"
                )
            }
            let remoteState = ((configuredPayload["remote"] as? [String: Any])?["state"] as? String) ?? "unknown"
            cliDebugLog(
                "cli.ssh.remote.configure.ok workspace=\(String(workspaceId.prefix(8))) state=\(remoteState)"
            )
            cliDebugLog(
                "cli.ssh.timing target=\(sshOptions.displayDestination) relayPort=\(sshOptions.remoteRelayPort) " +
                "workspace=\(String(workspaceId.prefix(8))) stage=workspace.remote.configure elapsedMs=\(Int(Date().timeIntervalSince(configureStartedAt) * 1000))"
            )
        } catch {
            cliDebugLog(
                "cli.ssh.remote.configure.error workspace=\(String(workspaceId.prefix(8))) error=\(String(describing: error))"
            )
            if didCreateWorkspace {
                do {
                    _ = try client.sendV2(method: "workspace.close", params: ["workspace_id": workspaceId])
                } catch {
                    let warning = "Warning: failed to rollback workspace \(workspaceId): \(error)\n"
                    cliWriteStderr(Data(warning.utf8))
                }
            }
            throw error
        }

        var payload = configuredPayload

        let redactsCommandPayload = sshOptions.destination != sshOptions.displayDestination || sshOptions.passwordCredential?.isEmpty == false
        if redactsCommandPayload {
            payload["ssh_command"] = "<redacted>"
            payload["ssh_terminal_command"] = "<redacted>"
            payload["ssh_startup_command"] = "<redacted>"
            payload["ssh_terminal_startup_command"] = "<redacted>"
        } else {
            payload["ssh_command"] = initialSSHCommand
            payload["ssh_terminal_command"] = remoteTerminalSSHCommand
            payload["ssh_startup_command"] = initialSSHStartupCommand
            payload["ssh_terminal_startup_command"] = reusableTerminalStartupCommand
        }
        payload["ssh_env_overrides"] = [
            "GHOSTTY_SHELL_FEATURES": shellFeaturesValue,
        ]
        payload["remote_relay_port"] = sshOptions.remoteRelayPort
        if usesPersistentSSHPTY, let workspaceInitialSurfaceId {
            payload["ssh_pty_session_id"] = "ssh-\(workspaceId)-\(workspaceInitialSurfaceId)"
        }
        if let persistentDaemonSlot {
            payload["persistent_daemon_slot"] = persistentDaemonSlot
        }
        logSSHTiming("complete", extra: "workspace=\(String(workspaceId.prefix(8)))")
        if jsonOutput {
            print(jsonString(formatIDs(payload, mode: idFormat)))
        } else {
            let workspaceHandle = formatHandle(payload, kind: "workspace", idFormat: idFormat) ?? workspaceId
            let remote = payload["remote"] as? [String: Any]
            let state = (remote?["state"] as? String) ?? "unknown"
            print("OK workspace=\(workspaceHandle) target=\(sshOptions.displayDestination) state=\(state)")
        }
    }

    private func reusableNamedWorkspace(
        named rawName: String?,
        windowRaw: String?,
        expectedManagedCloudVMID: String? = nil,
        expectedPersistentDaemonSlot: String? = nil,
        client: SocketClient
    ) throws -> (workspaceId: String, windowId: String?)? {
        guard let name = rawName, !name.isEmpty else { return nil }
        var params: [String: Any] = [:]
        try applyWindowOrCallerContext(to: &params, client: client, windowRaw: windowRaw)
        let payload = try client.sendV2(method: "workspace.list", params: params)
        let workspaces = payload["workspaces"] as? [[String: Any]] ?? []
        var firstMatch: [String: Any]?
        var firstPinnedMatch: [String: Any]?
        let requiresRemoteIdentity = expectedManagedCloudVMID != nil || expectedPersistentDaemonSlot != nil
        for workspace in workspaces {
            guard (workspace["title"] as? String)?.trimmingCharacters(in: .whitespacesAndNewlines) == name else {
                continue
            }
            if requiresRemoteIdentity {
                let remote = workspace["remote"] as? [String: Any]
                guard expectedManagedCloudVMID == normalizedOptionalWorkspaceString(remote?["managed_cloud_vm_id"]),
                      expectedPersistentDaemonSlot == normalizedOptionalWorkspaceString(remote?["persistent_daemon_slot"]) else {
                    continue
                }
            }
            if firstMatch == nil {
                firstMatch = workspace
            }
            if firstPinnedMatch == nil, workspaceIsPinned(workspace) {
                firstPinnedMatch = workspace
            }
            if firstPinnedMatch != nil {
                break
            }
        }
        let match = firstPinnedMatch ?? firstMatch
        guard let workspaceId = match?["id"] as? String, !workspaceId.isEmpty else {
            return nil
        }
        let windowId = (match?["window_id"] as? String)?.trimmingCharacters(in: .whitespacesAndNewlines)
        return (workspaceId, windowId?.isEmpty == false ? windowId : nil)
    }

    private func workspaceIsPinned(_ workspace: [String: Any]) -> Bool {
        (workspace["pinned"] as? Bool) == true || (workspace["is_pinned"] as? Bool) == true
    }

    private func normalizedOptionalWorkspaceString(_ value: Any?) -> String? {
        let trimmed = (value as? String)?.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed?.isEmpty == false ? trimmed : nil
    }

    private func pinWorkspaceToTop(workspaceId: String, windowId: String?, client: SocketClient) throws {
        var params: [String: Any] = ["workspace_id": workspaceId]
        if let windowId, !windowId.isEmpty {
            params["window_id"] = windowId
        }

        var pinParams = params
        pinParams["action"] = "pin"
        _ = try client.sendV2(method: "workspace.action", params: pinParams)

        var moveParams = params
        moveParams["action"] = "move_top"
        _ = try client.sendV2(method: "workspace.action", params: moveParams)
    }

    private func parseSSHCommandOptions(
        _ commandArgs: [String],
        localSocketPath: String = "",
        remoteRelayPort: Int = 0,
        windowOverride: String? = nil
    ) throws -> SSHCommandOptions {
        var destination: String?
        var port: Int?
        var identityFile: String?
        var workspaceName: String?
        var windowRaw: String?
        var noFocus = false
        var sshOptions: [String] = []
        var extraArguments: [String] = []
        var forwardAgentOverride: Bool?

        var passthrough = false
        var index = 0
        while index < commandArgs.count {
            let arg = commandArgs[index]
            if passthrough {
                extraArguments.append(arg)
                index += 1
                continue
            }

            switch arg {
            case "--":
                passthrough = true
                index += 1
            case "--port":
                guard index + 1 < commandArgs.count else {
                    throw CLIError(message: "ssh: --port requires a value")
                }
                guard let parsed = Int(commandArgs[index + 1]), parsed > 0, parsed <= 65535 else {
                    throw CLIError(message: "ssh: --port must be 1-65535")
                }
                port = parsed
                index += 2
            case "--identity":
                guard index + 1 < commandArgs.count else {
                    throw CLIError(message: "ssh: --identity requires a path")
                }
                identityFile = commandArgs[index + 1]
                index += 2
            case "--name":
                guard index + 1 < commandArgs.count else {
                    throw CLIError(message: "ssh: --name requires a workspace title")
                }
                workspaceName = commandArgs[index + 1]
                index += 2
            case "--window":
                guard index + 1 < commandArgs.count else {
                    throw CLIError(message: "ssh: --window requires a window id")
                }
                windowRaw = commandArgs[index + 1]
                index += 2
            case "--no-focus":
                noFocus = true
                index += 1
            case "-A", "--forward-agent":
                forwardAgentOverride = true
                index += 1
            case "-a", "--no-forward-agent":
                forwardAgentOverride = false
                index += 1
            case "--ssh-option":
                guard index + 1 < commandArgs.count else {
                    throw CLIError(message: "ssh: --ssh-option requires a value")
                }
                let value = commandArgs[index + 1].trimmingCharacters(in: .whitespacesAndNewlines)
                if !value.isEmpty {
                    sshOptions.append(value)
                }
                index += 2
            default:
                if arg.hasPrefix("--") {
                    throw CLIError(message: "ssh: unknown flag '\(arg)'")
                }
                if destination == nil {
                    if arg.hasPrefix("-") {
                        throw CLIError(
                            message: "ssh: destination must be <user@host>. Use --port/--identity/--ssh-option for SSH flags and `--` for remote command args."
                        )
                    }
                    destination = arg
                } else {
                    extraArguments.append(arg)
                }
                index += 1
            }
        }

        guard let destination else {
            throw CLIError(message: "ssh requires a destination (example: cmux ssh user@host)")
        }
        let agentForwarding = resolvedSSHAgentForwarding(
            sshOptions: sshOptions,
            override: forwardAgentOverride
        )
        return SSHCommandOptions(
            destination: destination,
            port: port,
            identityFile: identityFile,
            workspaceName: workspaceName,
            windowRaw: windowRaw ?? windowOverride,
            noFocus: noFocus,
            sshOptions: agentForwarding.sshOptions,
            extraArguments: extraArguments,
            agentSocketPath: agentForwarding.agentSocketPath,
            localSocketPath: localSocketPath,
            remoteRelayPort: remoteRelayPort
        )
    }

    private func resolvedSSHAgentForwarding(
        sshOptions: [String],
        override: Bool?
    ) -> (sshOptions: [String], agentSocketPath: String?) {
        let forwardAgentValue: String?
        var resolvedOptions = sshOptions

        if let override {
            resolvedOptions = sshOptionsRemovingForwardAgent(resolvedOptions)
            resolvedOptions.append("ForwardAgent=\(override ? "yes" : "no")")
            forwardAgentValue = override ? "yes" : nil
        } else if let explicitForwardAgent = sshForwardAgentValue(in: resolvedOptions) {
            forwardAgentValue = explicitForwardAgent
        } else {
            forwardAgentValue = nil
        }

        let resolver = SSHAgentSocketResolver()
        let explicitAgentSocketPath = forwardAgentValue
            .flatMap(resolver.agentSocketPath(forForwardAgentValue:))
            .flatMap(existingSSHAgentSocketPath)
        let agentSocketPath = explicitAgentSocketPath
            ?? existingSSHAgentSocketPath(ProcessInfo.processInfo.environment["SSH_AUTH_SOCK"])
        return (resolvedOptions, agentSocketPath)
    }

    private func sshOptionsRemovingForwardAgent(_ options: [String]) -> [String] {
        SSHAgentSocketResolver().removingOptions(named: "ForwardAgent", from: options)
    }

    private func sshForwardAgentValue(in options: [String]) -> String? {
        SSHAgentSocketResolver().optionValue(named: "ForwardAgent", in: options)
    }

    /// Returns a normalized agent socket path only when it currently exists.
    private func existingSSHAgentSocketPath(_ value: String?) -> String? {
        guard let path = SSHAgentSocketResolver().normalizedAgentSocketPath(value),
              FileManager.default.fileExists(atPath: path) else {
            return nil
        }
        return path
    }

    func buildSSHCommandText(
        _ options: SSHCommandOptions,
        remoteBootstrapScript: String? = nil,
        localCommandScript: String? = nil
    ) -> String {
        buildSSHCommandArguments(
            options,
            remoteBootstrapScript: remoteBootstrapScript,
            localCommandScript: localCommandScript
        )
        .map(shellQuote)
        .joined(separator: " ")
    }

    private func buildSSHCommandArguments(
        _ options: SSHCommandOptions,
        remoteBootstrapScript: String? = nil,
        localCommandScript: String? = nil
    ) -> [String] {
        var parts = baseSSHArguments(options, localCommandScript: localCommandScript)
        let trimmedRemoteBootstrap = remoteBootstrapScript?
            .trimmingCharacters(in: .whitespacesAndNewlines)

        if options.extraArguments.isEmpty {
            if let trimmedRemoteBootstrap, !trimmedRemoteBootstrap.isEmpty {
                let remoteCommand = openSSHRemoteCommandValue(
                    shellScript: encodedRemoteBootstrapCommand(
                        trimmedRemoteBootstrap,
                        remoteRelayPort: options.remoteRelayPort
                    )
                )
                parts += ["-o", "RemoteCommand=\(remoteCommand)"]
            }
            if !hasSSHOptionKey(options.sshOptions, key: "RequestTTY") {
                parts.append("-tt")
            }
            parts.append(options.destination)
        } else {
            parts = sshArgumentsOverridingHostRemoteCommand(parts) + [options.destination]
            parts.append(contentsOf: options.extraArguments)
        }
        return parts
    }

    func buildBootstrapSSHStartupCommand(
        options: SSHCommandOptions,
        remoteBootstrapScript: String,
        shellFeatures: String,
        remoteRelayPort: Int,
        localCommandScript: String? = nil,
        passwordCredential: String? = nil,
        controlPathPreflightShellFunction: String? = nil
    ) throws -> String {
        let commandSnippet = buildSSHBootstrapCommandSnippet(
            options: options,
            remoteBootstrapScript: remoteBootstrapScript,
            localCommandScript: localCommandScript
        )
        return try buildSSHStartupCommand(
            sshCommand: commandSnippet,
            shellFeatures: shellFeatures,
            remoteRelayPort: remoteRelayPort,
            isShellSnippet: true,
            passwordCredential: passwordCredential,
            controlPathPreflightShellFunction: controlPathPreflightShellFunction
        )
    }

    func buildReusableBootstrapSSHStartupCommand(
        options: SSHCommandOptions,
        remoteBootstrapScript: String,
        shellFeatures: String,
        remoteRelayPort: Int,
        localCommandScript: String? = nil,
        passwordCredential: String? = nil,
        controlPathPreflightShellFunction: String? = nil
    ) -> String {
        let commandSnippet = buildSSHBootstrapCommandSnippet(
            options: options,
            remoteBootstrapScript: remoteBootstrapScript,
            localCommandScript: localCommandScript
        )
        return buildReusableSSHStartupCommand(
            sshCommand: commandSnippet,
            shellFeatures: shellFeatures,
            remoteRelayPort: remoteRelayPort,
            isShellSnippet: true,
            passwordCredential: passwordCredential,
            controlPathPreflightShellFunction: controlPathPreflightShellFunction
        )
    }

    private func buildSSHBootstrapCommandSnippet(
        options: SSHCommandOptions,
        remoteBootstrapScript: String,
        localCommandScript: String? = nil
    ) -> String {
        let encodedBootstrapScript = Data(remoteBootstrapScript.utf8).base64EncodedString()
        let installSSHPrefix = sshArgumentsOverridingHostRemoteCommand(baseSSHArguments(options, localCommandScript: localCommandScript)).map(shellQuote).joined(separator: " ")
        let sessionSSHPrefix = baseSSHArguments(options).map(shellQuote).joined(separator: " ")
        let remoteCommandTemplate = openSSHRemoteCommandValue(
            shellScript: stagedRemoteBootstrapCommandShell(
                remoteRelayPort: options.remoteRelayPort
            )
        )
        let remoteBootstrapInstallCommand = posixShellCommand(
            remoteBootstrapInstallShell(remoteRelayPort: options.remoteRelayPort)
        )
        var lines: [String] = [
            "cmux_workspace_id=\"${CMUX_WORKSPACE_ID:-}\"",
            "cmux_surface_id=\"${CMUX_SURFACE_ID:-}\"",
            "cmux_remote_bootstrap_b64=\(shellQuote(encodedBootstrapScript))",
            "cmux_remote_bootstrap=\"$(printf %s \"$cmux_remote_bootstrap_b64\" | base64 -d 2>/dev/null || printf %s \"$cmux_remote_bootstrap_b64\" | base64 -D 2>/dev/null)\"",
            "cmux_remote_bootstrap=\"$(printf '%s' \"$cmux_remote_bootstrap\" | sed \"s/__CMUX_WORKSPACE_ID__/$cmux_workspace_id/g; s/__CMUX_SURFACE_ID__/$cmux_surface_id/g\")\"",
            "printf '%s' \"$cmux_remote_bootstrap\" | command \(installSSHPrefix) -T \(shellQuote(options.destination)) \(shellQuote(remoteBootstrapInstallCommand))",
            "cmux_remote_install_status=$?",
            "if [ \"$cmux_remote_install_status\" -ne 0 ]; then",
            "  exit \"$cmux_remote_install_status\"",
            "fi",
            "cmux_remote_command_template=\(shellQuote(remoteCommandTemplate))",
            "cmux_remote_command=\"$(printf '%s' \"$cmux_remote_command_template\" | sed \"s/__CMUX_WORKSPACE_ID__/$cmux_workspace_id/g; s/__CMUX_SURFACE_ID__/$cmux_surface_id/g\")\"",
        ]

        var sshInvocation = "command \(sessionSSHPrefix) -o \"RemoteCommand=$cmux_remote_command\""
        if !hasSSHOptionKey(options.sshOptions, key: "RequestTTY") {
            sshInvocation += " -tt"
        }
        sshInvocation += " " + shellQuote(options.destination)
        lines.append(sshInvocation)
        return lines.joined(separator: "\n")
    }

    private func stagedRemoteBootstrapCommandShell(
        remoteRelayPort: Int
    ) -> String {
        var lines = remoteBootstrapTTYCaptureLines(remoteRelayPort: remoteRelayPort, includeRelayRPC: true)
        lines.append("/bin/sh \"$HOME/.cmux/relay/\(remoteRelayPort).bootstrap.sh\"")
        return lines.joined(separator: "\n")
    }

    private func remoteBootstrapInstallShell(remoteRelayPort: Int) -> String {
        [
            "set -eu",
            "umask 077",
            "cmux_bootstrap_path=\"$HOME/.cmux/relay/\(remoteRelayPort).bootstrap.sh\"",
            "mkdir -p \"$HOME/.cmux/relay\"",
            "cat > \"$cmux_bootstrap_path\"",
            "chmod 700 \"$cmux_bootstrap_path\" >/dev/null 2>&1 || true",
        ].joined(separator: "\n")
    }

    private func runtimeEncodedRemoteBootstrapCommandShell(
        base64Placeholder: String,
        remoteRelayPort: Int
    ) -> String {
        var lines = remoteBootstrapTTYCaptureLines(remoteRelayPort: remoteRelayPort, includeRelayRPC: false)
        lines += [
            "cmux_tmp=$(mktemp \"${TMPDIR:-/tmp}/cmux-ssh-bootstrap.XXXXXX\") || exit 1",
            "(printf %s '\(base64Placeholder)' | base64 -d 2>/dev/null || printf %s '\(base64Placeholder)' | base64 -D 2>/dev/null) > \"$cmux_tmp\" || { rm -f \"$cmux_tmp\"; exit 1; }",
            "chmod 700 \"$cmux_tmp\" >/dev/null 2>&1 || true",
            "/bin/sh \"$cmux_tmp\"",
            "cmux_status=$?",
            "rm -f \"$cmux_tmp\"",
            "exit $cmux_status",
        ]
        return lines.joined(separator: "\n")
    }

    private func remoteBootstrapTTYCaptureLines(
        remoteRelayPort: Int,
        includeRelayRPC: Bool
    ) -> [String] {
        guard remoteRelayPort > 0 else { return [] }

        var lines: [String] = [
            "cmux_bootstrap_tty=\"$(tty 2>/dev/null || true)\"",
            "cmux_bootstrap_tty=\"${cmux_bootstrap_tty##*/}\"",
            "if [ -n \"$cmux_bootstrap_tty\" ] && [ \"$cmux_bootstrap_tty\" != \"not a tty\" ]; then",
            "  mkdir -p \"$HOME/.cmux/relay\" >/dev/null 2>&1 || true",
            "  printf '%s' \"$cmux_bootstrap_tty\" > \"$HOME/.cmux/relay/\(remoteRelayPort).tty\" 2>/dev/null || true",
            "  export CMUX_BOOTSTRAP_TTY=\"$cmux_bootstrap_tty\"",
        ]

        if includeRelayRPC {
            lines += [
                "  cmux_relay_cli=\"$HOME/.cmux/bin/cmux\"",
                "  if [ ! -x \"$cmux_relay_cli\" ]; then cmux_relay_cli=\"$(command -v cmux 2>/dev/null || true)\"; fi",
                "  if [ -n \"$cmux_relay_cli\" ]; then",
                "    ( cmux_relay_report_tty='{\"workspace_id\":\"__CMUX_WORKSPACE_ID__\",\"tty_name\":\"'$cmux_bootstrap_tty'\"}'",
                "      cmux_relay_ports_kick='{\"workspace_id\":\"__CMUX_WORKSPACE_ID__\",\"reason\":\"command\"}'",
                "      if [ -n \"__CMUX_SURFACE_ID__\" ]; then",
                "        cmux_relay_report_tty='{\"workspace_id\":\"__CMUX_WORKSPACE_ID__\",\"surface_id\":\"__CMUX_SURFACE_ID__\",\"tty_name\":\"'$cmux_bootstrap_tty'\"}'",
                "        cmux_relay_ports_kick='{\"workspace_id\":\"__CMUX_WORKSPACE_ID__\",\"surface_id\":\"__CMUX_SURFACE_ID__\",\"reason\":\"command\"}'",
                "      fi",
                "      env -u CMUX_SOCKET CMUX_SOCKET_PATH=\"127.0.0.1:\(remoteRelayPort)\" \"$cmux_relay_cli\" rpc surface.report_tty \"$cmux_relay_report_tty\" >/dev/null 2>&1 || true",
                "      env -u CMUX_SOCKET CMUX_SOCKET_PATH=\"127.0.0.1:\(remoteRelayPort)\" \"$cmux_relay_cli\" rpc surface.ports_kick \"$cmux_relay_ports_kick\" >/dev/null 2>&1 || true",
                "    ) </dev/null >/dev/null 2>&1 & unset cmux_relay_cli",
                "  fi",
            ]
        }

        lines.append("fi")
        return lines
    }

    private func effectiveSSHOptions(_ options: [String], remoteRelayPort: Int? = nil) -> [String] {
        var merged = sshOptionsWithControlSocketDefaults(options, remoteRelayPort: remoteRelayPort)
        if !hasSSHOptionKey(merged, key: "StrictHostKeyChecking") {
            merged.append("StrictHostKeyChecking=accept-new")
        }
        return merged
    }

    private func sshControlPathPreflightShellFunction(options: SSHCommandOptions) -> String? {
        let effectiveOptions = effectiveSSHOptions(
            options.sshOptions,
            remoteRelayPort: options.remoteRelayPort
        )
        guard let controlMaster = sshOptionValue(named: "ControlMaster", in: effectiveOptions)?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased(),
              !["no", "false", "off"].contains(controlMaster),
              let controlPath = sshOptionValue(named: "ControlPath", in: effectiveOptions)?
                .trimmingCharacters(in: .whitespacesAndNewlines),
              !controlPath.isEmpty,
              controlPath.lowercased() != "none" else {
            return nil
        }

        let sshPrefix = baseSSHArguments(options).map(shellQuote).joined(separator: " ")
        let destination = shellQuote(options.destination)
        return [
            "cmux_ssh_preflight_control_path() {",
            #"  cmux_ssh_control_path="$(command \#(sshPrefix) -G \#(destination) 2>/dev/null | awk 'tolower($1) == "controlpath" { $1 = ""; sub(/^[[:space:]]+/, ""); print; exit }')" "#,
            "  case \"${cmux_ssh_control_path:-}\" in",
            "    /tmp/cmux-ssh-*|\"$HOME\"/.cmux/control/*)",
            "      if ! command \(sshPrefix) -S \"$cmux_ssh_control_path\" -O check \(destination) >/dev/null 2>&1; then",
            "        rm -f -- \"$cmux_ssh_control_path\" 2>/dev/null || true",
            "      fi",
            "      ;;",
            "  esac",
            "  unset cmux_ssh_control_path",
            "}",
        ].joined(separator: "\n")
    }

    func buildInteractiveRemoteShellScript(
        remoteRelayPort: Int,
        shellFeatures: String,
        terminfoSource: String? = nil
    ) -> String {
        // Share the single terminfo-install implementation with the app-side SSH
        // PTY bootstrap so the two entrypoints can never drift (the synchronous
        // install that fixes #6352 lives only in the builder).
        let remoteTerminalLines = RemoteInteractiveShellBootstrapBuilder.terminalSetupLines(
            terminfoSource: terminfoSource
        )
        let remoteLocaleLines = RemoteShellEnvironment.utf8LocaleSetupLines()
        let remoteEnvExportLines = interactiveRemoteShellExportLines(shellFeatures: shellFeatures)
        let shellStateDir = shellStateDirForRemoteRelayPort(remoteRelayPort)
        let remoteCallerExportLines = [
            "if [ -n '__CMUX_WORKSPACE_ID__' ]; then export CMUX_WORKSPACE_ID='__CMUX_WORKSPACE_ID__'; fi",
            "if [ -n '__CMUX_WORKSPACE_ID__' ]; then export CMUX_TAB_ID='__CMUX_WORKSPACE_ID__'; fi",
            "if [ -n '__CMUX_SURFACE_ID__' ]; then export CMUX_SURFACE_ID='__CMUX_SURFACE_ID__'; export CMUX_PANEL_ID='__CMUX_SURFACE_ID__'; fi",
        ]
        let relaySocket = remoteRelayPort > 0 ? "127.0.0.1:\(remoteRelayPort)" : nil
        var commonShellExportLines = remoteTerminalLines
        commonShellExportLines.append(contentsOf: remoteLocaleLines)
        commonShellExportLines.append(contentsOf: remoteEnvExportLines)
        commonShellExportLines.append("export PATH=\"$HOME/.cmux/bin:$PATH\"")
        commonShellExportLines.append("export CMUX_BUNDLED_CLI_PATH=\"$HOME/.cmux/bin/cmux\"")
        commonShellExportLines.append("export CMUX_SHELL_INTEGRATION_DIR=\"\(shellStateDir)\"")
        if let relaySocket {
            commonShellExportLines.append("export CMUX_SOCKET_PATH=\(relaySocket)")
        }
        commonShellExportLines.append(contentsOf: remoteCallerExportLines)
        commonShellExportLines.append(contentsOf: [
            "hash -r >/dev/null 2>&1 || true",
            "rehash >/dev/null 2>&1 || true",
        ])
        var zshShellLines = commonShellExportLines
        zshShellLines.append(
            #"if [ "${CMUX_SHELL_INTEGRATION:-1}" != "0" ] && [ -r "${CMUX_SHELL_INTEGRATION_DIR}/cmux-zsh-integration.zsh" ]; then . "${CMUX_SHELL_INTEGRATION_DIR}/cmux-zsh-integration.zsh"; fi"#
        )
        var bashShellLines = commonShellExportLines
        bashShellLines.append(
            #"if [ "${CMUX_SHELL_INTEGRATION:-1}" != "0" ] && [ -r "${CMUX_SHELL_INTEGRATION_DIR}/cmux-bash-integration.bash" ]; then . "${CMUX_SHELL_INTEGRATION_DIR}/cmux-bash-integration.bash"; fi"#
        )
        let zshBootstrap = RemoteRelayZshBootstrap(shellStateDir: shellStateDir)
        let zshEnvLines = zshBootstrap.zshEnvLines
        let zshProfileLines = zshBootstrap.zshProfileLines
        let zshRCLines = zshBootstrap.zshRCLines(commonShellLines: zshShellLines)
        let zshLoginLines = zshBootstrap.zshLoginLines
        let bundledZshIntegration = bundledShellIntegrationScript(named: "cmux-zsh-integration.zsh")
        let bundledBashIntegration = bundledShellIntegrationScript(named: "cmux-bash-integration.bash")
        let bashRCLines = [
            "if [ -f \"$HOME/.bash_profile\" ]; then . \"$HOME/.bash_profile\"; elif [ -f \"$HOME/.bash_login\" ]; then . \"$HOME/.bash_login\"; elif [ -f \"$HOME/.profile\" ]; then . \"$HOME/.profile\"; fi",
            "[ -f \"$HOME/.bashrc\" ] && . \"$HOME/.bashrc\"",
        ] + bashShellLines
        let relayWarmupLines = interactiveRemoteRelayWarmupLines(remoteRelayPort: remoteRelayPort)

        var outerLines: [String] = [
            "mkdir -p \"$HOME/.cmux/relay\"",
            "cmux_shell_dir=\"\(shellStateDir)\"",
            "mkdir -p \"$cmux_shell_dir\"",
        ]
        if let bundledZshIntegration {
            outerLines += [
                "cat > \"$cmux_shell_dir/cmux-zsh-integration.zsh\" <<'CMUXCMUXZSH'",
                bundledZshIntegration,
                "CMUXCMUXZSH",
            ]
        }
        if let bundledBashIntegration {
            outerLines += [
                "cat > \"$cmux_shell_dir/cmux-bash-integration.bash\" <<'CMUXCMUXBASH'",
                bundledBashIntegration,
                "CMUXCMUXBASH",
            ]
        }
        outerLines.append(contentsOf: commonShellExportLines)
        outerLines += [
            "CMUX_LOGIN_SHELL=\"${SHELL:-/bin/zsh}\"",
            "case \"${CMUX_LOGIN_SHELL##*/}\" in",
            "  zsh)",
            "    cat > \"$cmux_shell_dir/.zshenv\" <<'CMUXZSHENV'",
        ]
        outerLines.append(contentsOf: zshEnvLines)
        outerLines += [
            "CMUXZSHENV",
            "    cat > \"$cmux_shell_dir/.zprofile\" <<'CMUXZSHPROFILE'",
        ]
        outerLines.append(contentsOf: zshProfileLines)
        outerLines += [
            "CMUXZSHPROFILE",
            "    cat > \"$cmux_shell_dir/.zshrc\" <<'CMUXZSHRC'",
        ]
        outerLines.append(contentsOf: zshRCLines)
        outerLines += [
            "CMUXZSHRC",
            "    cat > \"$cmux_shell_dir/.zlogin\" <<'CMUXZSHLOGIN'",
        ]
        outerLines.append(contentsOf: zshLoginLines)
        outerLines += [
            "CMUXZSHLOGIN",
            "    chmod 600 \"$cmux_shell_dir/.zshenv\" \"$cmux_shell_dir/.zprofile\" \"$cmux_shell_dir/.zshrc\" \"$cmux_shell_dir/.zlogin\" >/dev/null 2>&1 || true",
        ]
        outerLines.append(contentsOf: relayWarmupLines.map { "    " + $0 })
        outerLines += [
            "    export CMUX_REAL_ZDOTDIR=\"${ZDOTDIR:-$HOME}\"",
            "    export ZDOTDIR=\"$cmux_shell_dir\"",
            "    exec \"$CMUX_LOGIN_SHELL\" -il",
            "    ;;",
            "  bash)",
            "    cat > \"$cmux_shell_dir/.bashrc\" <<'CMUXBASHRC'",
        ]
        outerLines.append(contentsOf: bashRCLines)
        outerLines += [
            "CMUXBASHRC",
            "    chmod 600 \"$cmux_shell_dir/.bashrc\" >/dev/null 2>&1 || true",
        ]
        outerLines.append(contentsOf: relayWarmupLines.map { "    " + $0 })
        outerLines += [
            "    exec \"$CMUX_LOGIN_SHELL\" --rcfile \"$cmux_shell_dir/.bashrc\" -i",
            "    ;;",
            "  *)",
        ]
        outerLines.append(contentsOf: commonShellExportLines)
        outerLines.append(contentsOf: relayWarmupLines)
        outerLines += [
            "exec \"$CMUX_LOGIN_SHELL\" -i",
            ";;",
            "esac",
        ]

        return outerLines.joined(separator: "\n")
    }

    private func shellStateDirForRemoteRelayPort(_ remoteRelayPort: Int) -> String {
        "$HOME/.cmux/relay/\(max(remoteRelayPort, 0)).shell"
    }

    private func bundledShellIntegrationScript(named fileName: String) -> String? {
        let fileManager = FileManager.default
        var candidates: [URL] = []

        if let executableURL = resolvedExecutableURL() {
            var current = executableURL.deletingLastPathComponent().standardizedFileURL
            while true {
                if current.lastPathComponent == "Contents" {
                    candidates.append(
                        current
                            .appendingPathComponent("Resources", isDirectory: true)
                            .appendingPathComponent("shell-integration", isDirectory: true)
                            .appendingPathComponent(fileName, isDirectory: false)
                    )
                }

                let projectMarker = current.appendingPathComponent("cmux.xcodeproj/project.pbxproj", isDirectory: false)
                if fileManager.fileExists(atPath: projectMarker.path) {
                    candidates.append(
                        current
                            .appendingPathComponent("Resources", isDirectory: true)
                            .appendingPathComponent("shell-integration", isDirectory: true)
                            .appendingPathComponent(fileName, isDirectory: false)
                    )
                    break
                }

                guard let parent = parentSearchURL(for: current) else {
                    break
                }
                current = parent
            }
        }

        if let resourceURL = Bundle.main.resourceURL {
            candidates.append(
                resourceURL
                    .appendingPathComponent("shell-integration", isDirectory: true)
                    .appendingPathComponent(fileName, isDirectory: false)
            )
        }

        for url in candidates {
            guard fileManager.fileExists(atPath: url.path),
                  let data = try? Data(contentsOf: url),
                  let contents = String(data: data, encoding: .utf8) else {
                continue
            }
            return contents
        }

        return nil
    }

    func buildInteractiveRemoteShellCommand(
        remoteRelayPort: Int,
        shellFeatures: String,
        terminfoSource: String? = nil
    ) -> String {
        let script = buildInteractiveRemoteShellScript(
            remoteRelayPort: remoteRelayPort,
            shellFeatures: shellFeatures,
            terminfoSource: terminfoSource
        )
        return posixShellCommand(script)
    }

    private func interactiveRemoteShellExportLines(shellFeatures: String) -> [String] {
        let environment = ProcessInfo.processInfo.environment
        let colorTerm = Self.normalizedEnvValue(environment["COLORTERM"]) ?? "truecolor"
        let termProgram = Self.normalizedEnvValue(environment["TERM_PROGRAM"]) ?? "ghostty"
        let termProgramVersion = Self.normalizedEnvValue(environment["TERM_PROGRAM_VERSION"])
            ?? (Bundle.main.object(forInfoDictionaryKey: "CFBundleShortVersionString") as? String)
            ?? ""
        let trimmedShellFeatures = shellFeatures.trimmingCharacters(in: .whitespacesAndNewlines)

        var exports: [String] = [
            "export COLORTERM=\(shellQuote(colorTerm))",
            "export TERM_PROGRAM=\(shellQuote(termProgram))",
        ]
        if !termProgramVersion.isEmpty {
            exports.append("export TERM_PROGRAM_VERSION=\(shellQuote(termProgramVersion))")
        }
        if !trimmedShellFeatures.isEmpty {
            exports.append("export GHOSTTY_SHELL_FEATURES=\(shellQuote(trimmedShellFeatures))")
        }
        return exports
    }

    private func interactiveRemoteRelayWarmupLines(remoteRelayPort: Int) -> [String] {
        guard remoteRelayPort > 0 else {
            return []
        }
        return [
            "cmux_relay_cli=\"${CMUX_BUNDLED_CLI_PATH:-$HOME/.cmux/bin/cmux}\"",
            "if [ ! -x \"$cmux_relay_cli\" ]; then cmux_relay_cli=\"$(command -v cmux 2>/dev/null || true)\"; fi",
            "cmux_relay_tty=\"${CMUX_BOOTSTRAP_TTY:-}\"",
            "if [ -z \"$cmux_relay_tty\" ]; then cmux_relay_tty=\"$(tty 2>/dev/null || true)\"; fi",
            "cmux_relay_tty=\"${cmux_relay_tty##*/}\"",
            "if [ -n \"$cmux_relay_tty\" ] && [ \"$cmux_relay_tty\" != \"not a tty\" ]; then",
            "  mkdir -p \"$HOME/.cmux/relay\" >/dev/null 2>&1 || true",
            "  printf '%s' \"$cmux_relay_tty\" > \"$HOME/.cmux/relay/\(remoteRelayPort).tty\" 2>/dev/null || true",
            "fi",
            "if [ -n \"$cmux_relay_cli\" ] && [ -n \"$CMUX_WORKSPACE_ID\" ] && [ -n \"$cmux_relay_tty\" ] && [ \"$cmux_relay_tty\" != \"not a tty\" ]; then",
            "  ( cmux_relay_report_tty=\"{\\\"workspace_id\\\":\\\"$CMUX_WORKSPACE_ID\\\",\\\"tty_name\\\":\\\"$cmux_relay_tty\\\"}\"",
            "    cmux_relay_ports_kick=\"{\\\"workspace_id\\\":\\\"$CMUX_WORKSPACE_ID\\\",\\\"reason\\\":\\\"command\\\"}\"",
            "    if [ -n \"$CMUX_SURFACE_ID\" ]; then",
            "      cmux_relay_report_tty=\"{\\\"workspace_id\\\":\\\"$CMUX_WORKSPACE_ID\\\",\\\"surface_id\\\":\\\"$CMUX_SURFACE_ID\\\",\\\"tty_name\\\":\\\"$cmux_relay_tty\\\"}\"",
            "      cmux_relay_ports_kick=\"{\\\"workspace_id\\\":\\\"$CMUX_WORKSPACE_ID\\\",\\\"surface_id\\\":\\\"$CMUX_SURFACE_ID\\\",\\\"reason\\\":\\\"command\\\"}\"",
            "    fi",
            "    \"$cmux_relay_cli\" rpc surface.report_tty \"$cmux_relay_report_tty\" >/dev/null 2>&1 || true",
            "    \"$cmux_relay_cli\" rpc surface.ports_kick \"$cmux_relay_ports_kick\" >/dev/null 2>&1 || true",
            "  ) </dev/null >/dev/null 2>&1 & fi",
            "unset CMUX_BOOTSTRAP_TTY cmux_relay_cli cmux_relay_tty cmux_relay_report_tty cmux_relay_ports_kick",
        ]
    }

    private func baseSSHArguments(_ options: SSHCommandOptions, localCommandScript: String? = nil) -> [String] {
        let effectiveSSHOptions = effectiveSSHOptions(
            options.sshOptions,
            remoteRelayPort: options.remoteRelayPort
        )
        var parts: [String] = ["ssh"]
        if !hasSSHOptionKey(effectiveSSHOptions, key: "ConnectTimeout") {
            parts += ["-o", "ConnectTimeout=6"]
        }
        if !hasSSHOptionKey(effectiveSSHOptions, key: "ServerAliveInterval") {
            parts += ["-o", "ServerAliveInterval=20"]
        }
        if !hasSSHOptionKey(effectiveSSHOptions, key: "ServerAliveCountMax") {
            parts += ["-o", "ServerAliveCountMax=2"]
        }
        if !hasSSHOptionKey(effectiveSSHOptions, key: "SetEnv") {
            parts += ["-o", "SetEnv COLORTERM=truecolor"]
        }
        if !hasSSHOptionKey(effectiveSSHOptions, key: "SendEnv") {
            parts += ["-o", "SendEnv TERM_PROGRAM TERM_PROGRAM_VERSION"]
        }
        if let port = options.port {
            parts += ["-p", String(port)]
        }
        if let identityFile = normalizedSSHIdentityPath(options.identityFile) {
            parts += ["-i", identityFile]
        }
        for option in effectiveSSHOptions {
            parts += ["-o", option]
        }
        if let escapedLocalCommand = openSSHLocalCommandValue(shellScript: localCommandScript) {
            parts += ["-o", "PermitLocalCommand=yes"]
            parts += ["-o", "LocalCommand=\(escapedLocalCommand)"]
        }
        return parts
    }

    private func localXtermGhosttyTerminfoSource() -> String? {
        let result = runProcess(
            executablePath: "/usr/bin/infocmp",
            arguments: ["-0", "-x", "xterm-ghostty"]
        )
        guard result.status == 0 else { return nil }
        let output = result.stdout.trimmingCharacters(in: .whitespacesAndNewlines)
        return output.isEmpty ? nil : output
    }

    private func sshOptionsWithControlSocketDefaults(
        _ options: [String],
        remoteRelayPort: Int? = nil
    ) -> [String] {
        var merged: [String] = []
        for option in options {
            let trimmed = option.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty else { continue }
            merged.append(trimmed)
        }
        let controlMaster = sshOptionValue(named: "ControlMaster", in: merged)?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        let controlMasterDisabled = ["no", "false", "off"].contains(controlMaster ?? "")
        if controlMaster == nil {
            merged.append("ControlMaster=auto")
        }
        if !controlMasterDisabled {
            if !hasSSHOptionKey(merged, key: "ControlPersist") {
                merged.append("ControlPersist=600")
            }
            if !hasSSHOptionKey(merged, key: "ControlPath") {
                merged.append("ControlPath=\(defaultSSHControlPathTemplate(remoteRelayPort: remoteRelayPort))")
            }
        }
        return merged
    }

    private func scopedGhosttyShellFeaturesValue() -> String {
        let rawExisting = ProcessInfo.processInfo.environment["GHOSTTY_SHELL_FEATURES"] ?? ""
        var seen: Set<String> = []
        var merged: [String] = []

        for token in rawExisting.split(separator: ",") {
            let feature = token.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !feature.isEmpty else { continue }
            if seen.insert(feature).inserted {
                merged.append(feature)
            }
        }

        for required in ["ssh-env", "ssh-terminfo"] {
            if seen.insert(required).inserted {
                merged.append(required)
            }
        }

        return merged.joined(separator: ",")
    }

    func encodedRemoteBootstrapCommand(
        _ remoteBootstrapScript: String,
        remoteRelayPort: Int
    ) -> String {
        let encodedScript = Data(remoteBootstrapScript.utf8).base64EncodedString()
        let encodedLiteral = shellQuote(encodedScript)
        var lines = remoteBootstrapTTYCaptureLines(remoteRelayPort: remoteRelayPort, includeRelayRPC: false)
        lines += [
            "cmux_tmp=$(mktemp \"${TMPDIR:-/tmp}/cmux-ssh-bootstrap.XXXXXX\") || exit 1",
            "(printf %s \(encodedLiteral) | base64 -d 2>/dev/null || printf %s \(encodedLiteral) | base64 -D 2>/dev/null) > \"$cmux_tmp\" || { rm -f \"$cmux_tmp\"; exit 1; }",
            "chmod 700 \"$cmux_tmp\" >/dev/null 2>&1 || true",
            "/bin/sh \"$cmux_tmp\"",
            "cmux_status=$?",
            "rm -f \"$cmux_tmp\"",
            "exit $cmux_status",
        ]
        return lines.joined(separator: "\n")
    }

    private func buildReusableForegroundAuthThenSSHPTYAttachStartupCommand(
        options: SSHCommandOptions,
        remoteShellCommand: String,
        localCommandScript: String?,
        passwordCredential: String?,
        controlPathPreflightShellFunction: String?
    ) -> String {
        var authArguments = sshArgumentsOverridingHostRemoteCommand(baseSSHArguments(options, localCommandScript: localCommandScript))
        authArguments += ["-T", options.destination, "true"]
        let authCommand = authArguments.map(shellQuote).joined(separator: " ")
        let attachScript = buildSSHPTYAttachScriptBody(
            remoteShellCommand: remoteShellCommand
        )
        let authScript = [
            "command \(authCommand) <&0",
            "cmux_auth_status=$?",
            "if [ \"$cmux_auth_status\" -ne 0 ]; then exit \"$cmux_auth_status\"; fi",
        ]
            .joined(separator: "\n")
        return buildReusableSSHStartupCommand(
            sshCommand: attachScript,
            shellFeatures: "",
            remoteRelayPort: options.remoteRelayPort,
            isShellSnippet: true,
            passwordCredential: passwordCredential,
            controlPathPreflightShellFunction: controlPathPreflightShellFunction,
            oneTimeCommand: authScript,
            retryPTYAttachStatus: true
        )
    }

    /// Open an interactive cmux-managed shell on a cloud VM. The managed Cloud VM path requires
    /// cmuxd-remote WebSocket attach so reconnects, mobile attach, and notification fanout all
    /// use the same session primitive. SSH remains an explicit manual fallback.
    private func logVMTiming(
        _ stage: String,
        vmID: String,
        provider: String? = nil,
        transport: String? = nil,
        startedAt: Date,
        extra: String = ""
    ) {
        let elapsedMs = Int(Date().timeIntervalSince(startedAt) * 1000)
        var parts = [
            "cli.vm.timing",
            "vm=\(String(vmID.prefix(8)))",
            "stage=\(stage)",
            "elapsedMs=\(elapsedMs)",
        ]
        if let provider, !provider.isEmpty {
            parts.append("provider=\(provider)")
        }
        if let transport, !transport.isEmpty {
            parts.append("transport=\(transport)")
        }
        if !extra.isEmpty {
            parts.append(extra)
        }
        cliDebugLog(parts.joined(separator: " "))
    }

    private func vmOpenShell(
        id: String,
        workspaceName: String?,
        windowRaw: String?,
        targetWorkspaceId: String? = nil,
        sessionID: String? = nil,
        forceSSH: Bool,
        shouldPinWorkspaceToTop: Bool,
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        if forceSSH {
            let sshInfoStartedAt = Date()
            let response = try client.sendV2(
                method: "vm.ssh_info",
                params: ["id": id],
                responseTimeout: Self.vmAttachResponseTimeoutSeconds
            )
            logVMTiming("ssh_info", vmID: id, transport: "ssh", startedAt: sshInfoStartedAt)
            let options = try vmSSHOptions(
                fromAttachInfo: response,
                workspaceName: workspaceName,
                windowRaw: windowRaw,
                client: client,
                remoteRelayPort: generateRemoteRelayPort(),
                pinWorkspaceToTop: shouldPinWorkspaceToTop
            )
            let relayID = UUID().uuidString.lowercased()
            let relayToken = try randomHex(byteCount: 32)
            try runSSHWithOptions(
                options,
                relayID: relayID,
                relayToken: relayToken,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                vmIDForSplitAttach: id
            )
            return
        }

        let attachInfoStartedAt = Date()
        let response = try defaultFreestyleAttachInfoWithRetryIfNeeded(
            vmID: id,
            usesDefaultFreestyleSSHD: true,
            client: client,
            sessionID: sessionID
        )
        let transport = (response["transport"] as? String)?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased() ?? "ssh"
        logVMTiming("attach_info", vmID: id, transport: transport, startedAt: attachInfoStartedAt)
        if transport == "websocket" {
            let endpoint = try parseVMPtyWebSocketEndpoint(response)
            guard endpoint.daemon != nil else {
                throw CLIError(
                    message: """
                        This Cloud VM image does not support interactive attach in this cmux build.

                        What to do:
                          Update cmux, then create a fresh VM with `cmux vm new`.
                          If this keeps happening, contact support with the VM id.

                        Details:
                          Interactive attach is not available for this VM image.
                        """
                )
            }
            try runVMPtyWebSocketWorkspace(
                id: id,
                endpoint: endpoint,
                workspaceName: workspaceName,
                windowRaw: windowRaw,
                targetWorkspaceId: targetWorkspaceId,
                shouldPinWorkspaceToTop: shouldPinWorkspaceToTop,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat
            )
            return
        }
        let options = try vmSSHOptions(
            fromAttachInfo: response,
            workspaceName: workspaceName,
            windowRaw: windowRaw,
            client: client,
            remoteRelayPort: generateRemoteRelayPort(),
            pinWorkspaceToTop: shouldPinWorkspaceToTop
        )
        let relayID = UUID().uuidString.lowercased()
        let relayToken = try randomHex(byteCount: 32)
        try runSSHWithOptions(
            options,
            relayID: relayID,
            relayToken: relayToken,
            client: client,
            jsonOutput: jsonOutput,
            idFormat: idFormat,
            vmIDForSplitAttach: id
        )
    }

    private func runPersistentBaseOpenCommand(
        args: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowId: String?
    ) throws {
        let (targetWorkspaceOpt, rem0) = parseOption(args, name: "--workspace")
        let (windowOpt, rem1) = parseOption(rem0, name: "--window")
        let (sessionOpt, rem2) = parseOption(rem1, name: "--session")
        let detach = hasFlag(rem2, name: "--detach") || hasFlag(rem2, name: "-d")
        let remaining = rem2.filter { $0 != "--detach" && $0 != "-d" }
        if let unknown = remaining.first(where: { Self.isUnknownFlagToken($0, allowedShortFlags: ["-d"]) }) {
            throw CLIError(message: """
                vm base open: unknown flag '\(unknown)'.

                Known flags:
                  --workspace <workspace-id>
                  --window <id|ref|index>
                  --session <session-id>
                  --detach, -d
                """)
        }
        if let extra = remaining.first(where: { !Self.isFlagToken($0) }) {
            throw CLIError(message: """
                vm base open: unexpected argument '\(extra)'.

                Base is a single persistent cloud workspace. Use `cmux vm new`
                when you want a brand new VM.
                """)
        }

        let targetWindow = try validatedWindowHandle(windowOpt ?? windowId, client: client)
        let sessionID = try Self.validatedVMSessionIdentifier(sessionOpt, flag: "--session")
        let vmCreateStartedAt = Date()
        let response = try client.sendV2(
            method: "vm.base_open",
            params: [:],
            responseTimeout: Self.vmCreateResponseTimeoutSeconds
        )
        logVMTiming(
            "base.open",
            vmID: (response["id"] as? String) ?? "?",
            provider: (response["provider"] as? String) ?? "freestyle",
            startedAt: vmCreateStartedAt
        )

        if jsonOutput {
            print(jsonString(response))
            return
        }

        let id = (response["id"] as? String) ?? "?"
        let provider = (response["provider"] as? String) ?? "freestyle"
        let image = (response["image"] as? String) ?? "?"
        let base = response["base"] as? [String: Any]
        let generation = (base?["generation"] as? Int) ?? (base?["generation"] as? NSNumber)?.intValue
        if detach {
            print("OK \(id)")
            print("  provider: \(provider)")
            print("  image:    \(image)")
            print("  base:     true")
            if let generation {
                print("  gen:      \(generation)")
            }
            return
        }

        print("Opened Base \(id)")
        if let generation {
            print("Base generation \(generation).")
        }
        try vmOpenShell(
            id: id,
            workspaceName: Self.persistentCloudVMWorkspaceName,
            windowRaw: targetWindow,
            targetWorkspaceId: targetWorkspaceOpt,
            sessionID: sessionID,
            forceSSH: false,
            shouldPinWorkspaceToTop: true,
            client: client,
            jsonOutput: jsonOutput,
            idFormat: idFormat
        )
    }

    private func runPersistentBaseResetCommand(
        args: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowId: String?
    ) throws {
        let (reasonOpt, rem0) = parseOption(args, name: "--reason")
        let (targetWorkspaceOpt, rem1) = parseOption(rem0, name: "--workspace")
        let (windowOpt, rem2) = parseOption(rem1, name: "--window")
        let detach = hasFlag(rem2, name: "--detach") || hasFlag(rem2, name: "-d")
        let remaining = rem2.filter { $0 != "--detach" && $0 != "-d" }
        if let unknown = remaining.first(where: { Self.isUnknownFlagToken($0, allowedShortFlags: ["-d"]) }) {
            throw CLIError(message: """
                vm base reset: unknown flag '\(unknown)'.

                Known flags:
                  --reason <text>
                  --workspace <workspace-id>
                  --window <id|ref|index>
                  --detach, -d
                """)
        }
        if let extra = remaining.first(where: { !Self.isFlagToken($0) }) {
            throw CLIError(message: """
                vm base reset: unexpected argument '\(extra)'.

                Reset creates a new Base generation and retains the old VM.
                """)
        }

        let targetWindow = try validatedWindowHandle(windowOpt ?? windowId, client: client)
        var params: [String: Any] = [:]
        if let reasonOpt, !reasonOpt.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            params["reason"] = reasonOpt
        }
        let vmCreateStartedAt = Date()
        let response = try client.sendV2(
            method: "vm.base_reset",
            params: params,
            responseTimeout: Self.vmCreateResponseTimeoutSeconds
        )
        logVMTiming(
            "base.reset",
            vmID: (response["id"] as? String) ?? "?",
            provider: (response["provider"] as? String) ?? "freestyle",
            startedAt: vmCreateStartedAt
        )

        if jsonOutput {
            print(jsonString(response))
            return
        }

        let id = (response["id"] as? String) ?? "?"
        let provider = (response["provider"] as? String) ?? "freestyle"
        let image = (response["image"] as? String) ?? "?"
        let base = response["base"] as? [String: Any]
        let generation = (base?["generation"] as? Int) ?? (base?["generation"] as? NSNumber)?.intValue
        let retainedProviderVmId = base?["retainedProviderVmId"] as? String
        if detach {
            print("OK \(id)")
            print("  provider: \(provider)")
            print("  image:    \(image)")
            print("  base:     true")
            print("  reset:    true")
            if let generation {
                print("  gen:      \(generation)")
            }
            if let retainedProviderVmId, !retainedProviderVmId.isEmpty {
                print("  retained: \(retainedProviderVmId)")
            }
            return
        }

        print("Reset Base \(id)")
        if let generation {
            print("Base generation \(generation).")
        }
        if let retainedProviderVmId, !retainedProviderVmId.isEmpty {
            print("Previous Base generation was retained as \(retainedProviderVmId).")
        } else {
            print("Previous Base generation was retained.")
        }
        try vmOpenShell(
            id: id,
            workspaceName: Self.persistentCloudVMWorkspaceName,
            windowRaw: targetWindow,
            targetWorkspaceId: targetWorkspaceOpt,
            forceSSH: false,
            shouldPinWorkspaceToTop: true,
            client: client,
            jsonOutput: jsonOutput,
            idFormat: idFormat
        )
    }

    private func vmSSHOptions(
        fromAttachInfo response: [String: Any],
        workspaceName: String?,
        windowRaw: String?,
        client: SocketClient,
        remoteRelayPort: Int,
        pinWorkspaceToTop: Bool = false
    ) throws -> SSHCommandOptions {
        guard (response["transport"] as? String) == "ssh",
              let host = response["host"] as? String,
              let port = response["port"] as? Int,
              let username = response["username"] as? String,
              let cred = response["credential"] as? [String: Any],
              let kind = cred["kind"] as? String
        else {
            throw CLIError(message: """
                cmux could not read the attach information for this Cloud VM.

                What to do:
                  Retry `cmux vm ssh <id>`.
                  If it keeps failing, recreate the VM with `cmux vm new` and share the details below.

                Details:
                  Cloud VM attach details were incomplete.
                """)
        }
        guard kind == "password" else {
            if kind == "authorizedKey" {
                throw CLIError(
                    message: """
                        This Cloud VM does not support interactive SSH attach in this cmux build.

                        What to do:
                          Update cmux and retry.
                          If this keeps happening, contact support with the VM id.

                        Details:
                          Interactive SSH attach is unavailable for this VM.
                        """
                )
            }
            throw CLIError(message: """
                cmux could not use the attach information for this Cloud VM.

                What to do:
                  Retry `cmux vm ssh <id>`.
                  If it keeps failing, recreate the VM with `cmux vm new`.

                Details:
                  Interactive SSH attach is unavailable for this VM.
                """)
        }
        guard let token = cred["value"] as? String,
              !token.isEmpty else {
            throw CLIError(message: """
                cmux could not open an interactive SSH session for this Cloud VM.

                What to do:
                  Retry `cmux vm ssh <id>`.
                  If it keeps failing, recreate the VM with `cmux vm new`.

                Details:
                  Cloud VM attach details were incomplete.
                """)
        }

        // Freestyle gateway has a fresh host key per session and we re-mint per attach,
        // so skip the StrictHostKeyChecking prompt and known_hosts caching.
        //
        // IdentitiesOnly=yes + IdentityFile=/dev/null is load-bearing: the gateway
        // authenticates via the short-lived password credential. If OpenSSH offers
        // local pubkeys first, the gateway rejects before password auth can run.
        //
        // Each VM pane needs an independent gateway session. Reusing OpenSSH control sockets
        // can make a new split disturb the original shell.
        let sshOptionStrings = [
            "StrictHostKeyChecking=no",
            "UserKnownHostsFile=/dev/null",
            "LogLevel=QUIET",
            "IdentitiesOnly=yes",
            "IdentityFile=/dev/null",
            "PreferredAuthentications=none,password",
            "NumberOfPasswordPrompts=1",
            "ControlMaster=no",
        ]
        let destination = "\(username)@\(host)"
        let displayDestination = pinWorkspaceToTop
            ? String(localized: "cli.cloud.managedDisplayTarget", defaultValue: "cloud VM")
            : destination
        return SSHCommandOptions(
            destination: destination,
            displayDestination: displayDestination,
            port: port,
            identityFile: nil,
            workspaceName: workspaceName,
            windowRaw: windowRaw,
            noFocus: false,
            sshOptions: sshOptionStrings,
            extraArguments: [],
            passwordCredential: token,
            localSocketPath: client.socketPath,
            remoteRelayPort: remoteRelayPort,
            pinWorkspaceToTop: pinWorkspaceToTop,
            daemonWebSocketEndpoint: parseVMDaemonWebSocketEndpoint(response["daemon"]),
            skipDaemonBootstrap: true
        )
    }

    private func printVMSSHInfo(id vmID: String, command: String, client: SocketClient, jsonOutput: Bool) throws {
        let response = try client.sendV2(method: "vm.ssh_info", params: ["id": vmID], responseTimeout: 60)
        if jsonOutput {
            print(jsonString(response))
            return
        }
        let host = (response["host"] as? String) ?? "?"
        let port = (response["port"] as? Int) ?? 22
        let username = (response["username"] as? String) ?? "?"
        let cred = (response["credential"] as? [String: Any]) ?? [:]
        let credKind = (cred["kind"] as? String) ?? "?"
        if credKind == "password" {
            print("ssh \(username)@\(host) -p \(port)")
            print("")
            print("  host:      \(host)")
            print("  port:      \(port)")
            print("  username:  \(username)")
            print("  password:  <redacted; run `cmux \(command) ssh \(vmID)` to connect>")
        } else {
            print("This Cloud VM does not support `cmux \(command) ssh-info` in this cmux build.")
            print("")
            print("What to do:")
            print("  Update cmux and retry.")
            print("  If this keeps happening, contact support with the VM id.")
        }
    }

    private func runVMSSHAttach(commandArgs: [String], client: SocketClient) throws {
        let (vmIDOpt, remaining) = parseOption(commandArgs, name: "--id")
        let usesDefaultFreestyleSSHD = hasFlag(remaining, name: "--default-freestyle-sshd")
        let filteredRemaining = remaining.filter { $0 != "--default-freestyle-sshd" }
        if let unknown = filteredRemaining.first(where: { Self.isFlagToken($0) }) {
            throw CLIError(message: "vm ssh-attach: unknown flag '\(unknown)'. Use `cmux vm ssh-attach --id <vm-id>`.")
        }
        guard filteredRemaining.isEmpty else {
            throw CLIError(message: "Usage: cmux vm ssh-attach --id <vm-id>")
        }
        guard var vmID = vmIDOpt?.trimmingCharacters(in: .whitespacesAndNewlines),
              !vmID.isEmpty else {
            throw CLIError(message: "Usage: cmux vm ssh-attach --id <vm-id>")
        }

        let attachInfoStartedAt = Date()
        let response = try defaultFreestyleSSHInfoWithRetryIfNeeded(
            vmID: &vmID,
            usesDefaultFreestyleSSHD: usesDefaultFreestyleSSHD,
            client: client
        )
        if ProcessInfo.processInfo.environment["CMUX_CLOUD_RECONNECT_ATTEMPT"] == nil {
            bootstrapFreestyleZshEnvironmentIfPossible(vmID: vmID, username: "cmux", client: client)
        }
        logVMTiming("ssh_info", vmID: vmID, transport: "ssh", startedAt: attachInfoStartedAt)
        let options = try vmSSHOptions(
            fromAttachInfo: response,
            workspaceName: nil,
            windowRaw: nil,
            client: client,
            remoteRelayPort: 0
        )
        let sshArguments = buildSSHCommandArguments(
            options,
            remoteBootstrapScript: Self.freestyleInteractiveShellScript(
                suppressWelcome: ProcessInfo.processInfo.environment["CMUX_CLOUD_RECONNECT_ATTEMPT"] != nil,
                workspaceID: ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"],
                surfaceID: ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"]
            )
        )
        guard let launchPath = sshArguments.first else {
            throw CLIError(message: "vm ssh-attach could not construct an ssh command. Retry `cmux vm ssh <id>` from a normal cmux shell.")
        }
        client.close()
        if let passwordCredential = options.passwordCredential, !passwordCredential.isEmpty {
            let askpassRunner = try prepareSSHAskpassRunner(passwordCredential: passwordCredential)
            try execInteractiveProgram(
                launchPath: "/bin/sh",
                arguments: [askpassRunner, launchPath] + Array(sshArguments.dropFirst())
            )
        }
        try execInteractiveProgram(
            launchPath: launchPath,
            arguments: Array(sshArguments.dropFirst())
        )
    }

    private func prepareSSHAskpassRunner(passwordCredential: String) throws -> String {
        let fileManager = FileManager.default
        let tempRoot = URL(fileURLWithPath: NSTemporaryDirectory(), isDirectory: true)
        let dirURL = tempRoot.appendingPathComponent("cmux-ssh-askpass.\(UUID().uuidString)", isDirectory: true)
        let passwordURL = dirURL.appendingPathComponent("password", isDirectory: false)
        let runnerURL = dirURL.appendingPathComponent("run", isDirectory: false)
        try fileManager.createDirectory(at: dirURL, withIntermediateDirectories: false)
        _ = chmod(dirURL.path, S_IRWXU)
        guard let passwordData = passwordCredential.data(using: .utf8) else {
            throw CLIError(message: "vm ssh-attach could not encode the Cloud VM credential.")
        }
        try passwordData.write(to: passwordURL, options: .atomic)
        _ = chmod(passwordURL.path, S_IRUSR | S_IWUSR)
        let runner = sshAskpassExecShellScript(passwordFilePath: passwordURL.path, cleanupDirectory: dirURL.path)
        try runner.write(to: runnerURL, atomically: true, encoding: .utf8)
        _ = chmod(runnerURL.path, S_IRWXU)
        return runnerURL.path
    }

    private func defaultFreestyleCloudSSHAttachLoopCommand(vmID: String, executablePath: String) -> String {
        let quotedCLI = shellQuote(executablePath)
        let quotedVMID = shellQuote(vmID)
        let lines = [
            "cmux_freestyle_cli=\(quotedCLI)",
            "CMUX_SSH_RECONNECT_LIMIT=\"${CMUX_SSH_RECONNECT_LIMIT:-86400}\"",
            "CMUX_SSH_RECONNECT_DELAY_SECONDS=\"${CMUX_SSH_RECONNECT_DELAY_SECONDS:-2}\"",
            "CMUX_DEFAULT_FREESTYLE_ATTACH_RETRY_LIMIT=\"${CMUX_DEFAULT_FREESTYLE_ATTACH_RETRY_LIMIT:-$CMUX_SSH_RECONNECT_LIMIT}\"",
            "CMUX_DEFAULT_FREESTYLE_ATTACH_RETRY_DELAY_SECONDS=\"${CMUX_DEFAULT_FREESTYLE_ATTACH_RETRY_DELAY_SECONDS:-$CMUX_SSH_RECONNECT_DELAY_SECONDS}\"",
            "export CMUX_SSH_RECONNECT_LIMIT CMUX_SSH_RECONNECT_DELAY_SECONDS",
            "export CMUX_DEFAULT_FREESTYLE_ATTACH_RETRY_LIMIT CMUX_DEFAULT_FREESTYLE_ATTACH_RETRY_DELAY_SECONDS",
            "cmux_freestyle_attach() {",
            "  if [ -n \"${CMUX_SOCKET_PATH:-}\" ]; then",
            "    \"$cmux_freestyle_cli\" --socket \"$CMUX_SOCKET_PATH\" vm-pty-attach --id \(quotedVMID) --default-freestyle-sshd",
            "  else",
            "    \"$cmux_freestyle_cli\" vm-pty-attach --id \(quotedVMID) --default-freestyle-sshd",
            "  fi",
            "}",
            "cmux_freestyle_retry=0",
            "while :; do",
            "  if [ \"$cmux_freestyle_retry\" -gt 0 ]; then",
            "    export CMUX_CLOUD_RECONNECT_ATTEMPT=\"$cmux_freestyle_retry\"",
            "  else",
            "    unset CMUX_CLOUD_RECONNECT_ATTEMPT",
            "  fi",
            "  cmux_freestyle_attach",
            "  cmux_freestyle_status=$?",
            "  case \"$cmux_freestyle_status\" in 254|255) ;; *) exit \"$cmux_freestyle_status\" ;; esac",
            "  if [ \"$cmux_freestyle_retry\" -ge \"$CMUX_SSH_RECONNECT_LIMIT\" ]; then exit \"$cmux_freestyle_status\"; fi",
            "  cmux_freestyle_retry=$((cmux_freestyle_retry + 1))",
            "  sleep \"$CMUX_SSH_RECONNECT_DELAY_SECONDS\"",
            "done",
        ]
        return "/bin/sh -c \(shellQuote(lines.joined(separator: "\n")))"
    }

    private static func isVMNotFoundError(_ error: Error) -> Bool {
        let message = String(describing: error).lowercased()
        return message.contains("vm_not_found") || message.contains("was not found")
    }

    private func defaultFreestyleSSHInfoWithRetryIfNeeded(
        vmID: inout String,
        usesDefaultFreestyleSSHD: Bool,
        client: SocketClient
    ) throws -> [String: Any] {
        var attempt = 0
        var printedRetryNotice = false
        let isReconnectAttach = ProcessInfo.processInfo.environment["CMUX_CLOUD_RECONNECT_ATTEMPT"] != nil
        let retryLimit = Self.defaultFreestyleAttachRetryLimit()
        let retryDelaySeconds = Self.defaultFreestyleAttachRetryDelaySeconds()
        while true {
            do {
                let response = try client.sendV2(
                    method: "vm.ssh_info",
                    params: ["id": vmID],
                    responseTimeout: Self.vmAttachResponseTimeoutSeconds
                )
                if !isReconnectAttach, printedRetryNotice {
                    Self.writeStderr(Self.clearTerminalLinePrefix)
                }
                return response
            } catch {
                if usesDefaultFreestyleSSHD, Self.isVMNotFoundError(error) {
                    throw CLIError(message: """
                        The Cloud VM attached to this workspace no longer exists.

                        What to do:
                          Close this workspace and open a fresh Cloud VM workspace with the cloud button or `cmux vm new`.

                        Details:
                          cmux will not recreate the VM from inside an attached terminal because that would leave the workspace's saved Cloud VM id stale.
                        """)
                }
                guard usesDefaultFreestyleSSHD,
                      Self.isRetryableCloudVMServiceError(error),
                      attempt < retryLimit else {
                    if !isReconnectAttach, printedRetryNotice {
                        Self.writeStderrLine("")
                    }
                    throw error
                }
                let retryAttempt = attempt + 1
                if !isReconnectAttach {
                    Self.writeStderr(
                        Self.clearTerminalLinePrefix + Self.defaultFreestyleAttachRetryNotice(
                            error: error,
                            attempt: retryAttempt,
                            retryLimit: retryLimit,
                            retryDelaySeconds: retryDelaySeconds
                        )
                    )
                    printedRetryNotice = true
                }
                cliDebugLog(
                    "cli.vm.ssh_info.retry vm=\(String(vmID.prefix(8))) attempt=\(retryAttempt) retry_in_seconds=\(retryDelaySeconds) error=\(String(describing: error))"
                )
                attempt += 1
                if retryDelaySeconds > 0 {
                    usleep(useconds_t(retryDelaySeconds * 1_000_000))
                }
            }
        }
    }

    private static func defaultFreestyleAttachRetryLimit() -> Int {
        let environment = ProcessInfo.processInfo.environment
        let raw = environment["CMUX_CLOUD_ATTACH_RETRY_LIMIT"]
            ?? environment["CMUX_DEFAULT_FREESTYLE_ATTACH_RETRY_LIMIT"]
            ?? ""
        guard let parsed = Int(raw), parsed >= 0 else {
            return 120
        }
        return parsed
    }

    private static func defaultFreestyleAttachRetryDelaySeconds() -> Double {
        let environment = ProcessInfo.processInfo.environment
        let raw = environment["CMUX_CLOUD_ATTACH_RETRY_DELAY_SECONDS"]
            ?? environment["CMUX_DEFAULT_FREESTYLE_ATTACH_RETRY_DELAY_SECONDS"]
            ?? ""
        guard let parsed = Double(raw), parsed >= 0 else {
            return 2
        }
        return parsed
    }

    private static let clearTerminalLinePrefix = "\r\u{001B}[2K"

    private static func defaultFreestyleAttachRetryNotice(
        error: Error,
        attempt: Int,
        retryLimit: Int,
        retryDelaySeconds: Double
    ) -> String {
        let retryText = String(
            localized: "cli.vm.sshInfo.retry.status",
            defaultValue: "Retrying in \(Self.retryDelayLabel(retryDelaySeconds)) (\(Self.retryAttemptLabel(attempt: attempt, retryLimit: retryLimit)))."
        )
        let errorText = String(describing: error)
        if Self.isLocalCloudVMServiceUnreachable(errorText),
           let url = Self.firstHTTPURL(in: errorText) {
            let reason = String(
                localized: "cli.vm.sshInfo.retry.localServerOffline",
                defaultValue: "Waiting for the local cmux web server"
            )
            return "[cmux] \(reason) at \(url). \(retryText)"
        }
        if errorText.lowercased().contains("provider control plane") {
            let reason = String(
                localized: "cli.vm.sshInfo.retry.cloudProviderControlPlaneUnavailable",
                defaultValue: "Waiting for the Cloud VM control plane"
            )
            return "[cmux] \(reason). \(retryText)"
        }
        let reason = String(
            localized: "cli.vm.sshInfo.retry.cloudServiceUnavailable",
            defaultValue: "Waiting for the Cloud VM service"
        )
        return "[cmux] \(reason). \(retryText)"
    }

    private static func retryAttemptLabel(attempt: Int, retryLimit: Int) -> String {
        if retryLimit >= 86_400 {
            return "attempt \(attempt)"
        }
        return "attempt \(attempt)/\(retryLimit)"
    }

    private static func retryDelayLabel(_ seconds: Double) -> String {
        if seconds <= 0 {
            return String(localized: "cli.vm.sshInfo.retry.now", defaultValue: "now")
        }
        if seconds.rounded(.towardZero) == seconds {
            return "\(Int(seconds))s"
        }
        return String(format: "%.1fs", seconds)
    }

    private static func isLocalCloudVMServiceUnreachable(_ message: String) -> Bool {
        let lowercased = message.lowercased()
        let mentionsLocalURL = lowercased.contains("http://localhost:") ||
            lowercased.contains("http://127.0.0.1:") ||
            lowercased.contains("http://[::1]:")
        let mentionsConnectionFailure = lowercased.contains("cannot reach") ||
            lowercased.contains("could not connect") ||
            lowercased.contains("connection refused") ||
            lowercased.contains("failed to connect")
        return mentionsLocalURL && mentionsConnectionFailure
    }

    private static func firstHTTPURL(in text: String) -> String? {
        guard let regex = try? NSRegularExpression(pattern: #"https?://[^\s)\]]+"#) else {
            return nil
        }
        let range = NSRange(text.startIndex..<text.endIndex, in: text)
        guard let match = regex.firstMatch(in: text, range: range),
              let matchRange = Range(match.range, in: text) else {
            return nil
        }
        return String(text[matchRange]).trimmingCharacters(in: CharacterSet(charactersIn: ".,;:"))
    }

    private static func isRetryableCloudVMServiceError(_ error: Error) -> Bool {
        let message = String(describing: error).lowercased()
        return message.contains("http 502") ||
            message.contains("http 503") ||
            message.contains("returned 502") ||
            message.contains("returned 503") ||
            message.contains("service unavailable") ||
            message.contains("temporarily unavailable") ||
            message.contains("vm_cloud_state_unavailable") ||
            message.contains("provider control plane") ||
            message.contains("cannot reach the cmux cloud vm service") ||
            message.contains("local cmux web server is offline") ||
            message.contains("connection refused") ||
            message.contains("failed to connect") ||
            message.contains("could not connect to the server") ||
            message.contains("cmuxd websocket health check failed") ||
            message.contains("operation was aborted") ||
            message.contains("timed out") ||
            message.contains("timeout") ||
            message.contains("requires a cmuxd rpc endpoint")
    }

    private static func writeStderr(_ text: String) {
        FileHandle.standardError.write(Data(text.utf8))
    }

    private static func writeStderrLine(_ text: String) {
        FileHandle.standardError.write(Data((text + "\n").utf8))
    }

    private func bootstrapFreestyleZshEnvironmentIfPossible(
        vmID: String,
        username: String,
        client: SocketClient
    ) {
        let command = "/bin/sh -lc \(shellQuote(freestyleZshBootstrapScript(username: username)))"
        do {
            _ = try client.sendV2(
                method: "vm.exec",
                params: ["id": vmID, "command": command],
                responseTimeout: 180
            )
        } catch {
            cliDebugLog(
                "cli.vm.zsh_bootstrap.warning vm=\(String(vmID.prefix(8))) error=\(String(describing: error))"
            )
        }
    }

    private static func normalizedCloudContextValue(_ rawValue: String?) -> String? {
        guard let rawValue else { return nil }
        let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? nil : trimmed
    }

    private static func shellSingleQuote(_ value: String) -> String {
        "'" + value.replacingOccurrences(of: "'", with: "'\"'\"'") + "'"
    }

    private static func freestyleCloudContextExports(workspaceID: String?, surfaceID: String?) -> String {
        var lines: [String] = []
        if let workspaceID = normalizedCloudContextValue(workspaceID) {
            lines.append("export CMUX_WORKSPACE_ID=\(shellSingleQuote(workspaceID))")
            lines.append("export CMUX_TAB_ID=\"$CMUX_WORKSPACE_ID\"")
        }
        if let surfaceID = normalizedCloudContextValue(surfaceID) {
            lines.append("export CMUX_SURFACE_ID=\(shellSingleQuote(surfaceID))")
            lines.append("export CMUX_PANEL_ID=\"$CMUX_SURFACE_ID\"")
        }
        return lines.isEmpty ? ":" : lines.joined(separator: "\n")
    }

    private static func freestyleInteractiveShellScript(
        suppressWelcome: Bool = false,
        workspaceID: String? = nil,
        surfaceID: String? = nil
    ) -> String {
        """
        \(suppressWelcome ? "export CMUX_CLOUD_WELCOME=0" : ":")
        \(freestyleCloudContextExports(workspaceID: workspaceID, surfaceID: surfaceID))
        export PATH="/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin:${PATH:-}"
        hash -r 2>/dev/null || true
        if command -v zsh >/dev/null 2>&1; then
          touch "$HOME/.hushlogin" 2>/dev/null || true
          if [ ! -e "$HOME/.zshrc" ] || grep -q "cmux-managed zsh defaults" "$HOME/.zshrc" 2>/dev/null; then
            cat > "$HOME/.zshrc" <<'CMUX_USER_ZSHRC'
        # cmux-managed zsh defaults. Edit ~/.zshrc.local for personal overrides.
        mkdir -p "$HOME/.cmux" 2>/dev/null || true
        printf '%s' '/tmp/cmux-cloud-cli.sock' > "$HOME/.cmux/socket_addr" 2>/dev/null || true
        export CMUX_SOCKET_PATH="${CMUX_SOCKET_PATH:-/tmp/cmux-cloud-cli.sock}"
        if [ -r /etc/cmux/zshrc ]; then
          source /etc/cmux/zshrc
        else
          export SHELL="$(command -v zsh)"
          autoload -Uz colors 2>/dev/null && colors
          setopt prompt_subst interactivecomments no_beep hist_ignore_dups share_history 2>/dev/null || true
          PROMPT_EOL_MARK=''
          unsetopt prompt_sp 2>/dev/null || true
          HISTFILE="${HISTFILE:-$HOME/.zsh_history}"
          HISTSIZE="${HISTSIZE:-50000}"
          SAVEHIST="${SAVEHIST:-50000}"
          bindkey -e 2>/dev/null || true
          if [ -r /usr/share/zsh-autosuggestions/zsh-autosuggestions.zsh ]; then
            source /usr/share/zsh-autosuggestions/zsh-autosuggestions.zsh
            ZSH_AUTOSUGGEST_HIGHLIGHT_STYLE="${ZSH_AUTOSUGGEST_HIGHLIGHT_STYLE:-fg=8}"
          fi
          : ${CMUX_PROMPT_USER:=cmux-cloud}
          : ${CMUX_PROMPT_CHAR:=$'\\u03bb'}
          PROMPT='%F{magenta}${CMUX_PROMPT_USER}%f in %F{green}%~%f ${CMUX_PROMPT_CHAR} '
        fi
        [ -r "$HOME/.zshrc.local" ] && source "$HOME/.zshrc.local"
        if [ "${CMUX_CLOUD_WELCOME:-1}" != "0" ] && [ -z "${CMUX_CLOUD_WELCOME_SHOWN:-}" ] && [ -t 1 ]; then
          export CMUX_CLOUD_WELCOME_SHOWN=1
          printf '\\033[38;2;0;212;255m  ::\\033[0m\\n'
          printf '\\033[38;2;24;181;250m    ::::              \\033[38;2;0;212;255mc\\033[38;2;24;181;250mm\\033[38;2;48;150;245mu\\033[38;2;124;58;237mx cloud\\033[0m\\n'
          printf '\\033[38;2;48;150;245m      ::::::\\033[0m\\n'
          printf '\\033[38;2;72;119;241m        ::::::\\033[0m        \\033[38;2;130;130;140mpersistent cloud VM\\033[0m\\n'
          printf '\\033[38;2;96;88;239m      ::::::\\033[0m          \\033[38;2;130;130;140mready for coding agents\\033[0m\\n'
          printf '\\033[38;2;110;73;238m    ::::\\033[0m\\n'
          printf '\\033[38;2;124;58;237m  ::\\033[0m\\n'
          printf '\\n'
        fi
        CMUX_USER_ZSHRC
          fi
          if [ ! -e "$HOME/.zshrc.local" ]; then
            cat > "$HOME/.zshrc.local" <<'CMUX_LOCAL_ZSHRC'
        # Personal zsh overrides for this cloud VM.
        # Examples:
        #   CMUX_CLOUD_WELCOME=0
        #   CMUX_PROMPT_USER='cmux-cloud'
        #   CMUX_PROMPT_CHAR='>'
        #   PROMPT='%F{cyan}%n%f:%F{green}%~%f %# '
        CMUX_LOCAL_ZSHRC
          fi
          if command -v tmux >/dev/null 2>&1; then
            cmux_cloud_tty_scope="${CMUX_WORKSPACE_ID:-workspace}-${CMUX_SURFACE_ID:-surface}"
            if [ "$cmux_cloud_tty_scope" = "workspace-surface" ]; then
              cmux_cloud_tty_scope="default"
            fi
            cmux_cloud_tty_scope="$(printf '%s' "$cmux_cloud_tty_scope" | tr -c 'A-Za-z0-9_.-' '-')"
            cmux_cloud_tty_scope="${cmux_cloud_tty_scope#-}"
            cmux_cloud_tty_scope="${cmux_cloud_tty_scope%-}"
            [ -n "$cmux_cloud_tty_scope" ] || cmux_cloud_tty_scope=default
            if [ "$cmux_cloud_tty_scope" != default ] && [ "${CMUX_CLOUD_TMUX_SESSION:-}" = "cmux-cloud" ]; then
              unset CMUX_CLOUD_TMUX_SESSION
            fi
            if [ "$cmux_cloud_tty_scope" = default ]; then
              export CMUX_CLOUD_TMUX_SESSION="${CMUX_CLOUD_TMUX_SESSION:-cmux-cloud}"
            else
              export CMUX_CLOUD_TMUX_SESSION="${CMUX_CLOUD_TMUX_SESSION:-cmux-cloud-$cmux_cloud_tty_scope}"
            fi
            if ! tmux has-session -t "$CMUX_CLOUD_TMUX_SESSION" >/dev/null 2>&1; then
              tmux new-session -d -s "$CMUX_CLOUD_TMUX_SESSION" "exec zsh -l" >/dev/null 2>&1 || unset CMUX_CLOUD_TMUX_SESSION
            fi
            if [ -n "${CMUX_CLOUD_TMUX_SESSION:-}" ] && tmux has-session -t "$CMUX_CLOUD_TMUX_SESSION" >/dev/null 2>&1; then
              tmux set-option -t "$CMUX_CLOUD_TMUX_SESSION" status off >/dev/null 2>&1 || true
              tmux attach-session -t "$CMUX_CLOUD_TMUX_SESSION"
              cmux_tmux_status=$?
              [ "$cmux_tmux_status" -eq 0 ] && exit 0
            fi
          fi
          exec zsh -l
        fi
        exec "${SHELL:-/bin/sh}" -l
        """
    }

    private func freestyleZshBootstrapScript(username: String) -> String {
        let quotedUsername = shellQuote(username)
        return """
        set -u
        export PATH="/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin:${PATH:-}"
        cmux_user=\(quotedUsername)
        cmux_home="$(getent passwd "$cmux_user" 2>/dev/null | awk -F: '{print $6}')"
        if [ -z "$cmux_home" ]; then
          cmux_home="/home/$cmux_user"
        fi

        if [ ! -f /etc/cmux/zsh-bootstrap-v5 ] || ! command -v gh >/dev/null 2>&1 || ! command -v htop >/dev/null 2>&1 || ! command -v btop >/dev/null 2>&1 || ! command -v tmux >/dev/null 2>&1 || ! command -v cmux >/dev/null 2>&1; then
          if command -v apt-get >/dev/null 2>&1; then
            apt-get update >/dev/null 2>&1 || true
            DEBIAN_FRONTEND=noninteractive apt-get install -y zsh zsh-autosuggestions gh htop btop tmux >/dev/null 2>&1 || true
          fi
        fi

        if [ ! -x /usr/local/bin/cmux ] && [ -x /usr/local/bin/cmuxd-remote ]; then
          ln -sf /usr/local/bin/cmuxd-remote /usr/local/bin/cmux >/dev/null 2>&1 || true
        fi
        hash -r 2>/dev/null || true

        mkdir -p /etc/cmux "$cmux_home/.config/cmux"
        cat > /etc/cmux/zshrc <<'CMUX_ZSHRC'
        # cmux default zsh profile. Put personal overrides in ~/.zshrc.local.
        export PATH="/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin:${PATH:-}"
        export SHELL="$(command -v zsh)"
        mkdir -p "$HOME/.cmux" 2>/dev/null || true
        printf '%s' '/tmp/cmux-cloud-cli.sock' > "$HOME/.cmux/socket_addr" 2>/dev/null || true
        export CMUX_SOCKET_PATH="${CMUX_SOCKET_PATH:-/tmp/cmux-cloud-cli.sock}"
        autoload -Uz colors 2>/dev/null && colors
        setopt prompt_subst interactivecomments no_beep hist_ignore_dups share_history 2>/dev/null || true
        PROMPT_EOL_MARK=''
        unsetopt prompt_sp 2>/dev/null || true
        HISTFILE="${HISTFILE:-$HOME/.zsh_history}"
        HISTSIZE="${HISTSIZE:-50000}"
        SAVEHIST="${SAVEHIST:-50000}"
        bindkey -e 2>/dev/null || true

        if [ -r /usr/share/zsh-autosuggestions/zsh-autosuggestions.zsh ]; then
          source /usr/share/zsh-autosuggestions/zsh-autosuggestions.zsh
          ZSH_AUTOSUGGEST_HIGHLIGHT_STYLE="${ZSH_AUTOSUGGEST_HIGHLIGHT_STYLE:-fg=8}"
        fi

        : ${CMUX_PROMPT_USER:=cmux-cloud}
        : ${CMUX_PROMPT_CHAR:=$'\\u03bb'}
        PROMPT='%F{magenta}${CMUX_PROMPT_USER}%f in %F{green}%~%f ${CMUX_PROMPT_CHAR} '
        CMUX_ZSHRC

        if [ ! -e "$cmux_home/.zshrc" ] || grep -q "cmux-managed zsh defaults" "$cmux_home/.zshrc" 2>/dev/null; then
          cat > "$cmux_home/.zshrc" <<'CMUX_USER_ZSHRC'
        # cmux-managed zsh defaults. Edit ~/.zshrc.local for personal overrides.
        mkdir -p "$HOME/.cmux" 2>/dev/null || true
        printf '%s' '/tmp/cmux-cloud-cli.sock' > "$HOME/.cmux/socket_addr" 2>/dev/null || true
        export CMUX_SOCKET_PATH="${CMUX_SOCKET_PATH:-/tmp/cmux-cloud-cli.sock}"
        [ -r /etc/cmux/zshrc ] && source /etc/cmux/zshrc
        [ -r "$HOME/.zshrc.local" ] && source "$HOME/.zshrc.local"
        if [ "${CMUX_CLOUD_WELCOME:-1}" != "0" ] && [ -z "${CMUX_CLOUD_WELCOME_SHOWN:-}" ] && [ -t 1 ]; then
          export CMUX_CLOUD_WELCOME_SHOWN=1
          printf '\\033[38;2;0;212;255m  ::\\033[0m\\n'
          printf '\\033[38;2;24;181;250m    ::::              \\033[38;2;0;212;255mc\\033[38;2;24;181;250mm\\033[38;2;48;150;245mu\\033[38;2;124;58;237mx cloud\\033[0m\\n'
          printf '\\033[38;2;48;150;245m      ::::::\\033[0m\\n'
          printf '\\033[38;2;72;119;241m        ::::::\\033[0m        \\033[38;2;130;130;140mpersistent cloud VM\\033[0m\\n'
          printf '\\033[38;2;96;88;239m      ::::::\\033[0m          \\033[38;2;130;130;140mready for coding agents\\033[0m\\n'
          printf '\\033[38;2;110;73;238m    ::::\\033[0m\\n'
          printf '\\033[38;2;124;58;237m  ::\\033[0m\\n'
          printf '\\n'
        fi
        CMUX_USER_ZSHRC
        fi

        if [ ! -e "$cmux_home/.zshrc.local" ]; then
          cat > "$cmux_home/.zshrc.local" <<'CMUX_LOCAL_ZSHRC'
        # Personal zsh overrides for this cloud VM.
        # Examples:
        #   CMUX_CLOUD_WELCOME=0
        #   CMUX_PROMPT_USER='cmux-cloud'
        #   CMUX_PROMPT_CHAR='>'
        #   PROMPT='%F{cyan}%n%f:%F{green}%~%f %# '
        CMUX_LOCAL_ZSHRC
        fi

        if command -v zsh >/dev/null 2>&1; then
          chsh -s "$(command -v zsh)" "$cmux_user" >/dev/null 2>&1 || true
          touch /etc/cmux/zsh-bootstrap-v1 /etc/cmux/zsh-bootstrap-v2 /etc/cmux/zsh-bootstrap-v3 /etc/cmux/zsh-bootstrap-v4 /etc/cmux/zsh-bootstrap-v5 2>/dev/null || true
        fi
        touch "$cmux_home/.hushlogin" 2>/dev/null || true
        chown "$cmux_user:$cmux_user" "$cmux_home/.zshrc" "$cmux_home/.zshrc.local" 2>/dev/null || true
        chown "$cmux_user:$cmux_user" "$cmux_home/.hushlogin" 2>/dev/null || true
        mkdir -p "$cmux_home/.config" 2>/dev/null || true
        chown "$cmux_user:$cmux_user" "$cmux_home/.config" 2>/dev/null || true
        chown -R "$cmux_user:$cmux_user" "$cmux_home/.config/cmux" 2>/dev/null || true
        """
    }

    private func parseVMPtyWebSocketEndpoint(_ response: [String: Any]) throws -> VMPtyWebSocketEndpoint {
        func parseHeaders(_ value: Any?) -> [String: String] {
            guard let raw = value as? [String: Any] else { return [:] }
            return raw.reduce(into: [String: String]()) { result, pair in
                if let headerValue = pair.value as? String {
                    result[pair.key] = headerValue
                }
            }
        }
        guard let url = response["url"] as? String,
              let token = response["token"] as? String,
              let sessionId = response["session_id"] as? String else {
            throw CLIError(message: """
                cmux could not read the attach information for this Cloud VM.

                What to do:
                  Retry `cmux vm ssh <id>`.
                  If it keeps failing, recreate the VM with `cmux vm new`.

                Details:
                  Cloud VM attach details were incomplete.
                """)
        }
        let attachmentId = ((response["attachment_id"] as? String)?
            .trimmingCharacters(in: .whitespacesAndNewlines))
            .flatMap { $0.isEmpty ? nil : $0 }
            ?? UUID().uuidString.lowercased()
        let headers = parseHeaders(response["headers"])
        let expiresAtUnix = (response["expires_at_unix"] as? Int64)
            ?? Int64((response["expires_at_unix"] as? Double) ?? 0)
        let daemon = parseVMDaemonWebSocketEndpoint(response["daemon"])
        return VMPtyWebSocketEndpoint(
            url: url,
            headers: headers,
            token: token,
            sessionId: sessionId,
            attachmentId: attachmentId,
            expiresAtUnix: expiresAtUnix,
            daemon: daemon
        )
    }

    private func parseVMDaemonWebSocketEndpoint(_ value: Any?) -> VMDaemonWebSocketEndpoint? {
        func parseHeaders(_ value: Any?) -> [String: String] {
            guard let raw = value as? [String: Any] else { return [:] }
            return raw.reduce(into: [String: String]()) { result, pair in
                if let headerValue = pair.value as? String {
                    result[pair.key] = headerValue
                }
            }
        }
        guard let daemonResponse = value as? [String: Any],
              let daemonURL = daemonResponse["url"] as? String,
              let daemonToken = daemonResponse["token"] as? String,
              let daemonSessionID = (daemonResponse["session_id"] as? String) ?? (daemonResponse["sessionId"] as? String) else {
            return nil
        }
        let daemonHeaders = parseHeaders(daemonResponse["headers"])
        let daemonExpiresAtUnix = (daemonResponse["expires_at_unix"] as? Int64)
            ?? (daemonResponse["expiresAtUnix"] as? Int64)
            ?? Int64((daemonResponse["expires_at_unix"] as? Double)
                ?? ((daemonResponse["expiresAtUnix"] as? Double) ?? 0))
        return VMDaemonWebSocketEndpoint(
            url: daemonURL,
            headers: daemonHeaders,
            token: daemonToken,
            sessionId: daemonSessionID,
            expiresAtUnix: daemonExpiresAtUnix
        )
    }

    private func runVMPtyWebSocketWorkspace(
        id: String,
        endpoint: VMPtyWebSocketEndpoint,
        workspaceName: String?,
        windowRaw: String?,
        targetWorkspaceId: String? = nil,
        shouldPinWorkspaceToTop: Bool,
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        let startedAt = Date()
        let configURL = try writeVMPtyWebSocketConfig(endpoint)
        let executablePath = resolvedExecutableURL()?.path ?? (args.first ?? "cmux")
        let initialStartupCommand = "\(shellQuote(executablePath)) vm-pty-connect --config \(shellQuote(configURL.path)) --id \(shellQuote(id))"
        let splitStartupCommand = "\(shellQuote(executablePath)) vm-pty-attach --id \(shellQuote(id))"
        var params: [String: Any] = [
            "initial_command": initialStartupCommand,
            "remote_pty_session_id": endpoint.sessionId,
        ]
        if let workspaceName = workspaceName?.trimmingCharacters(in: .whitespacesAndNewlines),
           !workspaceName.isEmpty {
            params["title"] = workspaceName
        }
        let normalizedTargetWorkspaceId = targetWorkspaceId?.trimmingCharacters(in: .whitespacesAndNewlines)
        let workspaceCreate: [String: Any]
        let workspaceId: String
        let didCreateWorkspace: Bool
        if let normalizedTargetWorkspaceId, !normalizedTargetWorkspaceId.isEmpty {
            workspaceId = normalizedTargetWorkspaceId
            didCreateWorkspace = false
            var precreatedWorkspacePayload: [String: Any] = [
                "workspace_id": workspaceId,
                "workspace_ref": workspaceId,
            ]
            if let windowRaw, !windowRaw.isEmpty {
                precreatedWorkspacePayload["window_id"] = windowRaw
                precreatedWorkspacePayload["window_ref"] = windowRaw
            }
            workspaceCreate = precreatedWorkspacePayload
            logVMTiming(
                "workspace.precreated",
                vmID: id,
                transport: "websocket",
                startedAt: startedAt,
                extra: "workspace=\(String(workspaceId.prefix(8)))"
            )
        } else {
            try applyWindowOrCallerContext(to: &params, client: client, windowRaw: windowRaw)
            let workspaceCreateStartedAt = Date()
            workspaceCreate = try client.sendV2(method: "workspace.create", params: params)
            guard let createdWorkspaceId = workspaceCreate["workspace_id"] as? String, !createdWorkspaceId.isEmpty else {
                throw CLIError(message: "workspace.create did not return workspace_id")
            }
            workspaceId = createdWorkspaceId
            didCreateWorkspace = true
            logVMTiming(
                "workspace.create",
                vmID: id,
                transport: "websocket",
                startedAt: workspaceCreateStartedAt,
                extra: "workspace=\(String(workspaceId.prefix(8)))"
            )
        }

        let target = URL(string: endpoint.url)?.host ?? "websocket"
        let configureStartedAt = Date()
        var configureParams: [String: Any] = [
            "workspace_id": workspaceId,
            "destination": target,
            "transport": "websocket",
            "auto_connect": endpoint.daemon != nil,
            "terminal_startup_command": splitStartupCommand,
            "skip_daemon_bootstrap": true,
            "local_socket_path": client.socketPath,
            "managed_cloud_vm_id": id,
        ]
        if let daemon = endpoint.daemon {
            configureParams["daemon_websocket_url"] = daemon.url
            configureParams["daemon_websocket_headers"] = daemon.headers
            configureParams["daemon_websocket_token"] = daemon.token
            configureParams["daemon_websocket_session_id"] = daemon.sessionId
            configureParams["daemon_websocket_expires_at_unix"] = daemon.expiresAtUnix
        }
        let configuredPayload: [String: Any]
        do {
            if shouldPinWorkspaceToTop {
                let workspaceWindowId = (workspaceCreate["window_id"] as? String)?
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                try pinWorkspaceToTop(workspaceId: workspaceId, windowId: workspaceWindowId, client: client)
            }
            configuredPayload = try client.sendV2(method: "workspace.remote.configure", params: configureParams)
            logVMTiming(
                "workspace.remote.configure",
                vmID: id,
                transport: "websocket",
                startedAt: configureStartedAt,
                extra: "workspace=\(String(workspaceId.prefix(8)))"
            )

            if normalizedTargetWorkspaceId?.isEmpty == false {
                let readyStartedAt = Date()
                _ = try client.sendV2(
                    method: "workspace.cloud_vm_terminal_ready",
                    params: [
                        "workspace_id": workspaceId,
                        "initial_command": initialStartupCommand,
                        "remote_pty_session_id": endpoint.sessionId,
                        "focus": true,
                    ]
                )
                logVMTiming(
                    "workspace.cloud_vm_terminal_ready",
                    vmID: id,
                    transport: "websocket",
                    startedAt: readyStartedAt,
                    extra: "workspace=\(String(workspaceId.prefix(8)))"
                )
            }

            var selectParams: [String: Any] = ["workspace_id": workspaceId]
            if let workspaceWindowId = (workspaceCreate["window_id"] as? String)?
                .trimmingCharacters(in: .whitespacesAndNewlines),
               !workspaceWindowId.isEmpty {
                selectParams["window_id"] = workspaceWindowId
            }
            let selectStartedAt = Date()
            _ = try client.sendV2(method: "workspace.select", params: selectParams)
            logVMTiming(
                "workspace.select",
                vmID: id,
                transport: "websocket",
                startedAt: selectStartedAt,
                extra: "workspace=\(String(workspaceId.prefix(8)))"
            )
        } catch {
            if didCreateWorkspace {
                do {
                    _ = try client.sendV2(method: "workspace.close", params: ["workspace_id": workspaceId])
                } catch {
                    let warning = "Warning: failed to rollback workspace \(workspaceId): \(error)\n"
                    cliWriteStderr(Data(warning.utf8))
                }
            }
            throw error
        }

        var payload = configuredPayload
        payload["workspace_id"] = workspaceId
        payload["workspace_ref"] = workspaceCreate["workspace_ref"] ?? payload["workspace_ref"] ?? NSNull()
        payload["window_id"] = workspaceCreate["window_id"] ?? payload["window_id"] ?? NSNull()
        payload["window_ref"] = workspaceCreate["window_ref"] ?? payload["window_ref"] ?? NSNull()
        payload["vm_id"] = id
        payload["transport"] = "websocket"
        payload["target"] = target
        payload["expires_at_unix"] = endpoint.expiresAtUnix
        logVMTiming(
            "complete",
            vmID: id,
            transport: "websocket",
            startedAt: startedAt,
            extra: "workspace=\(String(workspaceId.prefix(8)))"
        )

        if jsonOutput {
            print(jsonString(formatIDs(payload, mode: idFormat)))
        } else {
            let workspaceHandle = formatHandle(payload, kind: "workspace", idFormat: idFormat) ?? workspaceId
            print("OK workspace=\(workspaceHandle) target=\(target) transport=websocket")
        }
    }

    private func writeVMPtyWebSocketConfig(_ endpoint: VMPtyWebSocketEndpoint) throws -> URL {
        let config = VMPtyWebSocketConfig(
            url: endpoint.url,
            headers: endpoint.headers,
            token: endpoint.token,
            sessionId: endpoint.sessionId,
            attachmentId: endpoint.attachmentId
        )
        let data = try JSONEncoder().encode(config)
        let url = FileManager.default.temporaryDirectory
            .appendingPathComponent("cmux-vm-pty-\(UUID().uuidString.lowercased()).json")
        try data.write(to: url, options: .atomic)
        try FileManager.default.setAttributes([.posixPermissions: 0o600], ofItemAtPath: url.path)
        return url
    }

    private func runVMPtyConnect(commandArgs: [String]) throws {
        let (configPath, rem0) = parseOption(commandArgs, name: "--config")
        let (vmIDOpt, remaining) = parseOption(rem0, name: "--id")
        if let unknown = remaining.first(where: { $0.hasPrefix("--") }) {
            throw CLIError(message: "vm-pty-connect: unknown flag '\(unknown)'")
        }
        guard let configPath else {
            throw CLIError(message: "Usage: cmux vm-pty-connect --config <path>")
        }
        let configURL = URL(fileURLWithPath: (configPath as NSString).expandingTildeInPath)
        let data = try Data(contentsOf: configURL)
        try? FileManager.default.removeItem(at: configURL)
        let config = try JSONDecoder().decode(VMPtyWebSocketConfig.self, from: data)
        let vmID = vmIDOpt?.trimmingCharacters(in: .whitespacesAndNewlines)
        let startedAt = Date()
        let debugEvent: ((String) -> Void)? = {
            guard let vmID, !vmID.isEmpty else { return nil }
            return { [self] stage in
                logVMTiming(stage, vmID: vmID, transport: "websocket", startedAt: startedAt)
            }
        }()
        try VMPtyWebSocketBridge(config: config, debugEvent: debugEvent).run()
    }

    private func runVMPtyAttach(commandArgs: [String], client: SocketClient) throws {
        let (vmIDOpt, rem0) = parseOption(commandArgs, name: "--id")
        let (sessionIDOpt, rem1) = parseOption(rem0, name: "--session")
        let (attachmentIDOpt, remaining) = parseOption(rem1, name: "--attachment")
        let usesDefaultFreestyleSSHD = hasFlag(remaining, name: "--default-freestyle-sshd")
        let filteredRemaining = remaining.filter { $0 != "--default-freestyle-sshd" }
        if let unknown = filteredRemaining.first(where: { Self.isFlagToken($0) }) {
            throw CLIError(message: "vm-pty-attach: unknown flag '\(unknown)'. Use `cmux vm-pty-attach --id <vm-id> [--session <session-id>]`.")
        }
        guard filteredRemaining.isEmpty else {
            throw CLIError(message: "Usage: cmux vm-pty-attach --id <vm-id> [--session <session-id>]")
        }
        guard let vmID = vmIDOpt?.trimmingCharacters(in: .whitespacesAndNewlines),
              !vmID.isEmpty else {
            throw CLIError(message: "Usage: cmux vm-pty-attach --id <vm-id> [--session <session-id>]")
        }
        let sessionID = try Self.validatedVMSessionIdentifier(
            sessionIDOpt ?? ProcessInfo.processInfo.environment["CMUX_REMOTE_PTY_SESSION_ID"],
            flag: "--session"
        )
        let attachmentID = try Self.validatedVMSessionIdentifier(attachmentIDOpt, flag: "--attachment")

        let startedAt = Date()
        func log(_ stage: String, extra: String = "") {
            logVMTiming(stage, vmID: vmID, transport: "websocket", startedAt: startedAt, extra: extra)
        }

        let attachInfoStartedAt = Date()
        let response = try defaultFreestyleAttachInfoWithRetryIfNeeded(
            vmID: vmID,
            usesDefaultFreestyleSSHD: usesDefaultFreestyleSSHD,
            client: client,
            sessionID: sessionID,
            attachmentID: attachmentID
        )
        logVMTiming("attach_info", vmID: vmID, transport: "websocket", startedAt: attachInfoStartedAt)
        let endpoint = try parseVMPtyWebSocketEndpoint(response)
        let config = VMPtyWebSocketConfig(
            url: endpoint.url,
            headers: endpoint.headers,
            token: endpoint.token,
            sessionId: endpoint.sessionId,
            attachmentId: endpoint.attachmentId
        )
        try VMPtyWebSocketBridge(config: config, debugEvent: { stage in
            log(stage)
        }).run()
    }

    private func defaultFreestyleAttachInfoWithRetryIfNeeded(
        vmID: String,
        usesDefaultFreestyleSSHD: Bool,
        client: SocketClient,
        sessionID: String? = nil,
        attachmentID: String? = nil
    ) throws -> [String: Any] {
        let method: String
        var params: [String: Any]
        if let sessionID {
            method = "vm.session_attach_info"
            params = [
                "id": vmID,
                "session_id": sessionID,
                "attachment_id": attachmentID ?? "attach-\(UUID().uuidString.lowercased())",
            ]
        } else {
            method = "vm.attach_info"
            params = usesDefaultFreestyleSSHD
                ? ["id": vmID, "require_daemon": true]
                : ["id": vmID]
        }
        var attempt = 0
        var printedRetryNotice = false
        let isReconnectAttach = ProcessInfo.processInfo.environment["CMUX_CLOUD_RECONNECT_ATTEMPT"] != nil
        let retryLimit = Self.defaultFreestyleAttachRetryLimit()
        let retryDelaySeconds = Self.defaultFreestyleAttachRetryDelaySeconds()
        while true {
            do {
                let rawResponse = try client.sendV2(
                    method: method,
                    params: params,
                    responseTimeout: Self.vmAttachResponseTimeoutSeconds
                )
                if !isReconnectAttach, printedRetryNotice {
                    Self.writeStderr(Self.clearTerminalLinePrefix)
                }
                if sessionID != nil {
                    guard let endpoint = rawResponse["endpoint"] as? [String: Any] else {
                        throw CLIError(message: """
                            cmux could not read the session attach information for this Cloud VM.

                            What to do:
                              Close and reopen this Base terminal.

                            Details:
                              Cloud VM session attach details were incomplete.
                            """)
                    }
                    return endpoint
                }
                let response = rawResponse
                return response
            } catch {
                if usesDefaultFreestyleSSHD, Self.isVMNotFoundError(error) {
                    throw CLIError(message: """
                        The Cloud VM attached to this workspace no longer exists.

                        What to do:
                          Close this workspace and open a fresh Cloud VM workspace with the cloud button or `cmux vm new`.

                        Details:
                          cmux will not recreate the VM from inside an attached terminal because that would leave the workspace's saved Cloud VM id stale.
                        """)
                }
                guard usesDefaultFreestyleSSHD,
                      Self.isRetryableCloudVMServiceError(error),
                      attempt < retryLimit else {
                    if !isReconnectAttach, printedRetryNotice {
                        Self.writeStderrLine("")
                    }
                    throw error
                }
                let retryAttempt = attempt + 1
                if !isReconnectAttach {
                    Self.writeStderr(
                        Self.clearTerminalLinePrefix + Self.defaultFreestyleAttachRetryNotice(
                            error: error,
                            attempt: retryAttempt,
                            retryLimit: retryLimit,
                            retryDelaySeconds: retryDelaySeconds
                        )
                    )
                    printedRetryNotice = true
                }
                cliDebugLog(
                    "cli.vm.attach_info.retry vm=\(String(vmID.prefix(8))) attempt=\(retryAttempt) retry_in_seconds=\(retryDelaySeconds) error=\(String(describing: error))"
                )
                attempt += 1
                if retryDelaySeconds > 0 {
                    usleep(useconds_t(retryDelaySeconds * 1_000_000))
                }
            }
        }
    }

    private final class VMPtyWebSocketBridgeDelegate: NSObject, URLSessionWebSocketDelegate {
        private let openSemaphore = DispatchSemaphore(value: 0)
        private let lock = NSLock()
        private var opened = false
        private var closed = false

        func urlSession(
            _ session: URLSession,
            webSocketTask: URLSessionWebSocketTask,
            didOpenWithProtocol protocol: String?
        ) {
            lock.lock()
            opened = true
            lock.unlock()
            openSemaphore.signal()
        }

        func urlSession(
            _ session: URLSession,
            webSocketTask: URLSessionWebSocketTask,
            didCloseWith closeCode: URLSessionWebSocketTask.CloseCode,
            reason: Data?
        ) {
            lock.lock()
            closed = true
            lock.unlock()
            openSemaphore.signal()
        }

        func waitForOpen(timeout: TimeInterval) -> Bool {
            if openSemaphore.wait(timeout: .now() + timeout) != .success {
                return false
            }
            lock.lock()
            defer { lock.unlock() }
            return opened && !closed
        }

        var isClosed: Bool {
            lock.lock()
            defer { lock.unlock() }
            return closed
        }
    }

    private final class VMPtyWebSocketBridge {
        private static let keepaliveInterval: TimeInterval = 5.0
        private let config: VMPtyWebSocketConfig
        private let debugEvent: ((String) -> Void)?
        private let sendQueue = DispatchQueue(label: "com.cmux.vm-pty.websocket.send")
        private let stopLock = NSLock()
        private var stopped = false
        private var task: URLSessionWebSocketTask?
        private var keepaliveTimer: DispatchSourceTimer?
        private var keepaliveTimeoutWorkItem: DispatchWorkItem?
        private var keepaliveInFlight = false

        init(config: VMPtyWebSocketConfig, debugEvent: ((String) -> Void)? = nil) {
            self.config = config
            self.debugEvent = debugEvent
        }

        func run() throws {
            guard let url = URL(string: config.url),
                  url.scheme == "wss" || url.scheme == "ws" else {
                throw CLIError(message: "vm-pty-connect: invalid websocket url")
            }
            var request = URLRequest(url: url)
            for (key, value) in config.headers {
                request.setValue(value, forHTTPHeaderField: key)
            }

            let delegate = VMPtyWebSocketBridgeDelegate()
            let session = URLSession(configuration: .default, delegate: delegate, delegateQueue: nil)
            let task = session.webSocketTask(with: request)
            self.task = task
            defer {
                markStopped()
                task.cancel(with: .normalClosure, reason: nil)
                session.invalidateAndCancel()
            }
            task.resume()
            guard delegate.waitForOpen(timeout: 15) else {
                throw CLIError(message: "vm-pty-connect: timed out opening websocket")
            }
            debugEvent?("websocket.open")

            try sendAuthFrame()
            debugEvent?("websocket.auth")
            try waitForReady(delegate: delegate)
            debugEvent?("websocket.ready")

            let rawMode = TerminalRawMode()
            defer { rawMode?.restore() }
            let resizeSource = startResizeSource()
            defer { resizeSource.cancel() }
            startKeepalive()
            defer { stopKeepalive() }
            startInputPump()
            try receiveOutputLoop(delegate: delegate)
        }

        private func sendAuthFrame() throws {
            let size = Self.currentTerminalSize()
            let auth: [String: Any] = [
                "type": "auth",
                "token": config.token,
                "session_id": config.sessionId,
                "attachment_id": config.attachmentId,
                "cols": size.cols,
                "rows": size.rows,
            ]
            let data = try JSONSerialization.data(withJSONObject: auth, options: [])
            let text = String(data: data, encoding: .utf8) ?? "{}"
            try sendSync(.string(text))
        }

        private func waitForReady(delegate: VMPtyWebSocketBridgeDelegate) throws {
            while true {
                guard let message = try receiveSync(delegate: delegate) else {
                    throw CLIError(message: "vm-pty-connect: websocket closed before ready")
                }
                if case .string(let text) = message, text.contains("\"ready\"") {
                    return
                }
            }
        }

        private func startResizeSource() -> DispatchSourceSignal {
            signal(SIGWINCH, SIG_IGN)
            let source = DispatchSource.makeSignalSource(
                signal: SIGWINCH,
                queue: DispatchQueue(label: "com.cmux.vm-pty.resize")
            )
            source.setEventHandler { [weak self] in
                guard let self else { return }
                let size = Self.currentTerminalSize()
                let payload: [String: Any] = ["type": "resize", "cols": size.cols, "rows": size.rows]
                guard let data = try? JSONSerialization.data(withJSONObject: payload, options: []),
                      let text = String(data: data, encoding: .utf8) else {
                    return
                }
                self.sendAsync(.string(text))
            }
            source.resume()
            return source
        }

        private static func currentTerminalSize() -> TerminalSize {
            var size = winsize()
            if ioctl(STDIN_FILENO, TIOCGWINSZ, &size) == 0,
               size.ws_col > 0,
               size.ws_row > 0 {
                return TerminalSize(cols: Int(size.ws_col), rows: Int(size.ws_row))
            }
            return TerminalSize(cols: 80, rows: 24)
        }

        private func startInputPump() {
            DispatchQueue.global(qos: .userInteractive).async { [weak self] in
                guard let self else { return }
                var buffer = [UInt8](repeating: 0, count: 8192)
                while !self.isStopped {
                    let count = Darwin.read(STDIN_FILENO, &buffer, buffer.count)
                    if count > 0 {
                        self.sendAsync(.data(Data(buffer.prefix(count))))
                    } else if count == 0 {
                        self.task?.cancel(with: .normalClosure, reason: nil)
                        return
                    } else if errno != EINTR {
                        self.task?.cancel(with: .goingAway, reason: nil)
                        return
                    }
                }
            }
        }

        private func receiveOutputLoop(delegate: VMPtyWebSocketBridgeDelegate) throws {
            while let message = try receiveSync(delegate: delegate) {
                switch message {
                case .data(let data):
                    cliWriteStdout(data)
                case .string:
                    continue
                @unknown default:
                    continue
                }
            }
        }

        private func receiveSync(delegate: VMPtyWebSocketBridgeDelegate) throws -> URLSessionWebSocketTask.Message? {
            guard let task else { throw CLIError(message: "vm-pty-connect: websocket task missing") }
            let semaphore = DispatchSemaphore(value: 0)
            var received: Result<URLSessionWebSocketTask.Message, Error>?
            task.receive { result in
                received = result
                semaphore.signal()
            }
            semaphore.wait()
            switch received {
            case .success(let message):
                return message
            case .failure(let error):
                if delegate.isClosed || isStopped {
                    return nil
                }
                throw error
            case nil:
                return nil
            }
        }

        private func startKeepalive() {
            sendQueue.async { [weak self] in
                guard let self else { return }
                self.keepaliveTimer?.cancel()
                self.keepaliveInFlight = false
                let timer = DispatchSource.makeTimerSource(queue: self.sendQueue)
                timer.schedule(deadline: .now() + Self.keepaliveInterval, repeating: Self.keepaliveInterval)
                timer.setEventHandler { [weak self] in
                    self?.sendKeepalive()
                }
                self.keepaliveTimer = timer
                timer.resume()
            }
        }

        private func stopKeepalive() {
            sendQueue.async { [weak self] in
                guard let self else { return }
                self.keepaliveTimer?.cancel()
                self.keepaliveTimer = nil
                self.keepaliveTimeoutWorkItem?.cancel()
                self.keepaliveTimeoutWorkItem = nil
                self.keepaliveInFlight = false
            }
        }

        private func sendKeepalive() {
            guard !isStopped, let task else {
                keepaliveTimer?.cancel()
                keepaliveTimer = nil
                keepaliveTimeoutWorkItem?.cancel()
                keepaliveTimeoutWorkItem = nil
                keepaliveInFlight = false
                return
            }

            if keepaliveInFlight {
                return
            }
            keepaliveInFlight = true
            let timeoutWorkItem = DispatchWorkItem { [weak self] in
                guard let self, !self.isStopped, self.keepaliveInFlight else { return }
                self.debugEvent?("websocket.keepalive.timeout")
                self.markStopped()
                self.task?.cancel(with: .goingAway, reason: nil)
            }
            keepaliveTimeoutWorkItem?.cancel()
            keepaliveTimeoutWorkItem = timeoutWorkItem
            sendQueue.asyncAfter(deadline: .now() + Self.keepaliveInterval, execute: timeoutWorkItem)

            task.sendPing { [weak self] error in
                self?.sendQueue.async {
                    guard let self, !self.isStopped else { return }
                    self.keepaliveTimeoutWorkItem?.cancel()
                    self.keepaliveTimeoutWorkItem = nil
                    self.keepaliveInFlight = false
                    if let error {
                        self.debugEvent?("websocket.keepalive.failed")
                        self.markStopped()
                        self.task?.cancel(with: .goingAway, reason: Data(error.localizedDescription.utf8))
                    }
                }
            }
        }

        private func sendAsync(_ message: URLSessionWebSocketTask.Message) {
            sendQueue.async { [weak self] in
                try? self?.sendSync(message)
            }
        }

        private func sendSync(_ message: URLSessionWebSocketTask.Message) throws {
            guard let task else { throw CLIError(message: "vm-pty-connect: websocket task missing") }
            let semaphore = DispatchSemaphore(value: 0)
            var sendError: Error?
            task.send(message) { error in
                sendError = error
                semaphore.signal()
            }
            semaphore.wait()
            if let sendError {
                throw sendError
            }
        }

        private var isStopped: Bool {
            stopLock.lock()
            defer { stopLock.unlock() }
            return stopped
        }

        private func markStopped() {
            stopLock.lock()
            stopped = true
            stopLock.unlock()
        }
    }

    private final class TerminalRawMode {
        private var original = termios()
        private var restored = false

        init?() {
            guard tcgetattr(STDIN_FILENO, &original) == 0 else {
                return nil
            }
            var raw = original
            cfmakeraw(&raw)
            guard tcsetattr(STDIN_FILENO, TCSANOW, &raw) == 0 else {
                return nil
            }
        }

        deinit {
            restore()
        }

        func restore() {
            guard !restored else { return }
            tcsetattr(STDIN_FILENO, TCSANOW, &original)
            restored = true
        }
    }

    private func runSSHSessionList(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        let (workspaceOpt, rem0) = parseOption(commandArgs, name: "--workspace")
        let allWorkspaces = rem0.contains("--all-workspaces")
        let remaining = rem0.filter { $0 != "--all-workspaces" }
        if let unknown = remaining.first(where: { Self.isFlagToken($0) }) {
            throw CLIError(message: "ssh-session-list: unknown flag '\(unknown)'. Known flags: --workspace <workspace>, --all-workspaces")
        }
        guard remaining.isEmpty else {
            throw CLIError(message: "Usage: cmux ssh-session-list [--workspace <workspace> | --all-workspaces]")
        }
        if allWorkspaces, workspaceOpt != nil {
            throw CLIError(message: "ssh-session-list: --all-workspaces cannot be combined with --workspace")
        }

        let params = try sshSessionTargetParams(
            commandName: "ssh-session-list",
            workspaceOpt: workspaceOpt,
            allWorkspaces: allWorkspaces,
            client: client
        )

        let response = try client.sendV2(method: "workspace.remote.pty_sessions", params: params)
        let sessions = response["sessions"] as? [[String: Any]] ?? []
        let errors = response["errors"] as? [[String: Any]] ?? []
        if jsonOutput {
            print(jsonString(formatIDs(response, mode: idFormat)))
            if !errors.isEmpty {
                throw CLIError(message: sshSessionListFailureMessage(errors))
            }
            return
        }

        if sessions.isEmpty, errors.isEmpty {
            print("No persisted SSH PTY sessions")
            return
        }
        for session in sessions {
            let sessionID = (session["session_id"] as? String) ?? "unknown"
            let workspaceLabel = debugString(session["workspace_ref"])
                ?? (debugString(session["workspace_id"])?.prefix(8).description)
                ?? "workspace:?"
            let workspaceTitle = debugString(session["workspace_title"]) ?? ""
            let effectiveCols = debugString(session["effective_cols"]) ?? "?"
            let effectiveRows = debugString(session["effective_rows"]) ?? "?"
            let scrollbackBytes = debugString(session["scrollback_bytes"]) ?? "0"
            let attachments = session["attachments"] as? [[String: Any]] ?? []
            let workspacePrefix = allWorkspaces
                ? "\(workspaceLabel)\(workspaceTitle.isEmpty ? "" : " \(workspaceTitle)") "
                : ""
            print("\(workspacePrefix)\(sessionID) attachments=\(attachments.count) size=\(effectiveCols)x\(effectiveRows) scrollback_bytes=\(scrollbackBytes)")
        }
        if !errors.isEmpty {
            throw CLIError(message: sshSessionListFailureMessage(errors))
        }
    }

    func sshSessionListFailureMessage(_ errors: [[String: Any]]) -> String {
        let count = errors.count
        let summary = "ssh-session-list failed for \(count) remote workspace\(count == 1 ? "" : "s")"
        let details = errors.map { error in
            let workspace = debugString(error["workspace_ref"])
                ?? debugString(error["workspace_id"])
                ?? "workspace:?"
            let message = userFacingRemotePTYErrorMessage(error["error"])
            return "- \(workspace): \(message)"
        }
        return ([summary] + details).joined(separator: "\n")
    }

    private func runSSHSessionCleanup(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        let (workspaceOpt, rem0) = parseOption(commandArgs, name: "--workspace")
        let (sessionIDOpt, rem1) = parseOption(rem0, name: "--session-id")
        let closeAll = rem1.contains("--all")
        let allWorkspaces = rem1.contains("--all-workspaces")
        let remaining = rem1.filter { $0 != "--all" && $0 != "--all-workspaces" }
        if let unknown = remaining.first(where: { Self.isFlagToken($0) }) {
            throw CLIError(message: "ssh-session-cleanup: unknown flag '\(unknown)'. Known flags: --workspace <workspace>, --session-id <id>, --all, --all-workspaces")
        }
        guard remaining.isEmpty else {
            throw CLIError(message: "Usage: cmux ssh-session-cleanup [--workspace <workspace> | --all-workspaces] (--session-id <id> | --all)")
        }
        if closeAll == (sessionIDOpt != nil) {
            throw CLIError(message: "ssh-session-cleanup requires exactly one of --session-id <id> or --all")
        }
        if allWorkspaces, workspaceOpt != nil {
            throw CLIError(message: "ssh-session-cleanup: --all-workspaces cannot be combined with --workspace")
        }

        let baseParams = try sshSessionTargetParams(
            commandName: "ssh-session-cleanup",
            workspaceOpt: workspaceOpt,
            allWorkspaces: allWorkspaces,
            client: client
        )

        var closed: [String] = []
        var closedSet = Set<String>()
        let recordClosedSession: (String, String?) -> Void = { sessionID, workspaceID in
            let workspaceKey = workspaceID?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let dedupeKey = "\(workspaceKey.count):\(workspaceKey)\u{0}\(sessionID)"
            if closedSet.insert(dedupeKey).inserted {
                closed.append(sessionID)
            }
        }
        var errors: [[String: Any]] = []
        if closeAll {
            let listResponse = try client.sendV2(method: "workspace.remote.pty_sessions", params: baseParams)
            errors.append(contentsOf: sshSessionCleanupListErrors(listResponse["errors"] as? [[String: Any]] ?? []))
            let sessions = listResponse["sessions"] as? [[String: Any]] ?? []
            for session in sessions {
                guard let sessionID = trimmedDebugString(session["session_id"]) else {
                    errors.append(sshSessionCleanupMissingSessionIDError(session: session))
                    continue
                }
                guard let workspaceID = trimmedDebugString(session["workspace_id"])
                    ?? trimmedDebugString(baseParams["workspace_id"]) else {
                    errors.append(sshSessionCleanupMissingWorkspaceError(sessionID: sessionID, session: session))
                    continue
                }
                let params: [String: Any] = [
                    "workspace_id": workspaceID,
                    "session_id": sessionID,
                ]
                do {
                    _ = try client.sendV2(method: "workspace.remote.pty_close", params: params)
                    recordClosedSession(sessionID, workspaceID)
                } catch {
                    errors.append([
                        "session_id": sessionID,
                        "workspace_id": params["workspace_id"] ?? NSNull(),
                        "error": self.userFacingRemotePTYErrorMessage(error),
                    ])
                }
            }
        } else if let sessionID = sessionIDOpt?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !sessionID.isEmpty {
            if allWorkspaces {
                let listResponse = try client.sendV2(method: "workspace.remote.pty_sessions", params: baseParams)
                errors.append(contentsOf: sshSessionCleanupListErrors(
                    listResponse["errors"] as? [[String: Any]] ?? [],
                    sessionID: sessionID
                ))
                let sessions = (listResponse["sessions"] as? [[String: Any]] ?? []).filter {
                    trimmedDebugString($0["session_id"]) == sessionID
                }
                if sessions.isEmpty {
                    errors.append([
                        "session_id": sessionID,
                        "workspace_id": NSNull(),
                        "error": "persistent SSH PTY session is no longer running",
                    ])
                }
                for session in sessions {
                    guard let workspaceID = trimmedDebugString(session["workspace_id"]) else {
                        errors.append(sshSessionCleanupMissingWorkspaceError(sessionID: sessionID, session: session))
                        continue
                    }
                    do {
                        _ = try client.sendV2(method: "workspace.remote.pty_close", params: [
                            "workspace_id": workspaceID,
                            "session_id": sessionID,
                        ])
                        recordClosedSession(sessionID, workspaceID)
                    } catch {
                        errors.append([
                            "session_id": sessionID,
                            "workspace_id": workspaceID,
                            "error": self.userFacingRemotePTYErrorMessage(error),
                        ])
                    }
                }
            } else {
                var params = baseParams
                params["session_id"] = sessionID
                _ = try client.sendV2(method: "workspace.remote.pty_close", params: params)
                recordClosedSession(sessionID, trimmedDebugString(params["workspace_id"]))
            }
        } else {
            throw CLIError(message: "ssh-session-cleanup: --session-id requires a value")
        }

        let payload: [String: Any] = [
            "closed": closed,
            "count": closed.count,
            "errors": errors,
        ]
        if jsonOutput {
            print(jsonString(formatIDs(payload, mode: idFormat)))
            if !errors.isEmpty {
                throw CLIError(message: sshSessionCleanupFailureMessage(errors))
            }
        } else if !errors.isEmpty {
            if !closed.isEmpty {
                print("Closed \(closed.count) persisted SSH PTY session\(closed.count == 1 ? "" : "s")")
            }
            throw CLIError(message: sshSessionCleanupFailureMessage(errors))
        } else if closed.isEmpty {
            print("No persisted SSH PTY sessions closed")
        } else {
            print("Closed \(closed.count) persisted SSH PTY session\(closed.count == 1 ? "" : "s")")
        }
    }

    private func sshSessionCleanupMissingWorkspaceError(sessionID: String, session: [String: Any]) -> [String: Any] {
        var error: [String: Any] = [
            "session_id": sessionID,
            "workspace_id": NSNull(),
            "error": "missing workspace_id in SSH PTY session list response",
        ]
        if let workspaceRef = trimmedDebugString(session["workspace_ref"]) {
            error["workspace_ref"] = workspaceRef
        }
        return error
    }

    private func sshSessionCleanupMissingSessionIDError(session: [String: Any]) -> [String: Any] {
        var error: [String: Any] = [
            "session_id": "unknown",
            "workspace_id": trimmedDebugString(session["workspace_id"]) ?? NSNull(),
            "error": "missing session_id in SSH PTY session list response",
        ]
        if let workspaceRef = trimmedDebugString(session["workspace_ref"]) {
            error["workspace_ref"] = workspaceRef
        }
        return error
    }

    private func sshSessionCleanupListErrors(_ listErrors: [[String: Any]], sessionID: String? = nil) -> [[String: Any]] {
        listErrors.map { error in
            let workspaceValue: Any
            if let workspace = debugString(error["workspace_ref"]) ?? debugString(error["workspace_id"]) {
                workspaceValue = workspace
            } else {
                workspaceValue = NSNull()
            }
            let payload: [String: Any] = [
                "session_id": sessionID ?? debugString(error["session_id"]) ?? "workspace-query",
                "workspace_id": workspaceValue,
                "error": userFacingRemotePTYErrorMessage(error["error"]),
            ]
            return payload
        }
    }

    private func sshSessionCleanupFailureMessage(_ errors: [[String: Any]]) -> String {
        let count = errors.count
        let summary = "ssh-session-cleanup failed for \(count) persisted SSH PTY session\(count == 1 ? "" : "s")"
        let details = errors.map { error in
            let sessionID = debugString(error["session_id"]) ?? "unknown"
            let workspaceID = (debugString(error["workspace_ref"]) ?? debugString(error["workspace_id"]))
                .map { " workspace=\($0)" } ?? ""
            let message = userFacingRemotePTYErrorMessage(error["error"])
            return "- \(sessionID)\(workspaceID): \(message)"
        }
        return ([summary] + details).joined(separator: "\n")
    }

    private func runSSHSessionAttach(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        let (workspaceOpt, rem0) = parseOption(commandArgs, name: "--workspace")
        let (sessionIDOpt, rem1) = parseOption(rem0, name: "--session-id")
        let (paneOpt, rem2) = parseOption(rem1, name: "--pane")
        let (surfaceOpt, rem3) = parseOption(rem2, name: "--surface")
        let (splitOpt, rem4) = parseOption(rem3, name: "--split")
        let (focusOpt, remaining) = parseOption(rem4, name: "--focus")
        if let unknown = remaining.first(where: { Self.isFlagToken($0) }) {
            throw CLIError(message: "ssh-session-attach: unknown flag '\(unknown)'. Known flags: --workspace <workspace>, --session-id <id>, --pane <pane>, --surface <surface>, --split <direction>, --focus <true|false>")
        }
        guard remaining.isEmpty else {
            throw CLIError(message: "Usage: cmux ssh-session-attach --session-id <id> [--workspace <workspace>] [--pane <pane> | --split <left|right|up|down> [--surface <surface>]]")
        }
        guard let sessionID = sessionIDOpt?.trimmingCharacters(in: .whitespacesAndNewlines),
              !sessionID.isEmpty else {
            throw CLIError(message: "ssh-session-attach requires --session-id <id>")
        }
        if workspaceOpt?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == true { throw CLIError(message: String(localized: "cli.error.sshSessionAttachWorkspaceRequiresValue", defaultValue: "ssh-session-attach: --workspace requires a value")) }
        if paneOpt != nil, splitOpt != nil {
            throw CLIError(message: "ssh-session-attach: --pane cannot be combined with --split")
        }
        let workspaceRaw = workspaceOpt ?? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"]
        let workspaceID = try normalizeWorkspaceHandle(workspaceRaw, client: client)
        let initialCommand = sshSessionAttachStartupCommand(sessionID: sessionID)
        var params: [String: Any] = [
            "initial_command": initialCommand,
            "remote_pty_session_id": sessionID,
        ]
        if let workspaceID {
            params["workspace_id"] = workspaceID
        }
        try applyFocusOption(focusOpt, defaultValue: true, to: &params)

        let payload: [String: Any]
        if let split = splitOpt?.trimmingCharacters(in: .whitespacesAndNewlines),
           !split.isEmpty {
            params["direction"] = split
            let surfaceID = try normalizeSurfaceHandle(
                surfaceOpt ?? (workspaceOpt == nil ? ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"] : nil),
                client: client,
                workspaceHandle: workspaceID
            )
            if let surfaceID {
                params["surface_id"] = surfaceID
            }
            payload = try client.sendV2(method: "surface.split", params: params)
        } else {
            let paneID = try normalizePaneHandle(paneOpt, client: client, workspaceHandle: workspaceID)
            if let paneID {
                params["pane_id"] = paneID
            }
            payload = try client.sendV2(method: "surface.create", params: params)
        }

        var output = payload
        output["session_id"] = sessionID
        printV2Payload(
            output,
            jsonOutput: jsonOutput,
            idFormat: idFormat,
            fallbackText: v2CreationSummary(output, idFormat: idFormat, kinds: ["surface", "pane", "workspace"])
        )
    }

    private func sshSessionAttachStartupCommand(sessionID: String) -> String {
        let quotedSessionID = shellQuote(sessionID)
        let currentExecutable = shellQuote(resolvedExecutableURL()?.path ?? (args.first ?? "cmux"))
        let attachCommand = "\"$cmux_ssh_attach_cli\" --socket \"$CMUX_SOCKET_PATH\" ssh-pty-attach --wait --require-existing --workspace \"$CMUX_WORKSPACE_ID\" --session-id \(quotedSessionID) --lifecycle-id \"$cmux_ssh_attach_lifecycle_id\" --attachment-id \"${CMUX_SURFACE_ID:-}\""
        let script = ([
            "cmux_ssh_attach_cli=\"${CMUX_BUNDLED_CLI_PATH:-}\"",
            "if [ -z \"$cmux_ssh_attach_cli\" ] || [ ! -x \"$cmux_ssh_attach_cli\" ]; then cmux_ssh_attach_cli=\(currentExecutable); fi",
            "if [ -z \"$cmux_ssh_attach_cli\" ] || [ ! -x \"$cmux_ssh_attach_cli\" ]; then cmux_ssh_attach_cli=\"$(command -v cmux 2>/dev/null || true)\"; fi",
            "if [ -z \"$cmux_ssh_attach_cli\" ]; then printf '%s\\n' '[cmux] bundled CLI not found for SSH PTY attach.' >&2; exit 127; fi",
            "if [ -z \"${CMUX_SOCKET_PATH:-}\" ]; then printf '%s\\n' '[cmux] required configuration missing for SSH PTY attach.' >&2; exit 1; fi",
            "if [ -z \"${CMUX_WORKSPACE_ID:-}\" ]; then printf '%s\\n' '[cmux] required workspace context missing for SSH PTY attach.' >&2; exit 1; fi",
            "cmux_ssh_attach_lifecycle_id=$(/usr/bin/uuidgen | /usr/bin/tr '[:upper:]' '[:lower:]') || exit 1",
            "cmux_ssh_attach_lifecycle_ended=0",
            "cmux_ssh_attach_lifecycle_end() { if [ \"$cmux_ssh_attach_lifecycle_ended\" = 1 ]; then return; fi; cmux_ssh_attach_lifecycle_ended=1; \"$cmux_ssh_attach_cli\" --socket \"$CMUX_SOCKET_PATH\" ssh-session-end --lifecycle-only --workspace \"$CMUX_WORKSPACE_ID\" --surface \"${CMUX_SURFACE_ID:-}\" --session-id \(quotedSessionID) --lifecycle-id \"$cmux_ssh_attach_lifecycle_id\" >/dev/null 2>&1 || true; }",
            "cmux_ssh_attach_signal_exit() { cmux_ssh_attach_signal_status=\"$1\"; trap - EXIT HUP INT TERM; cmux_ssh_attach_lifecycle_end; exit \"$cmux_ssh_attach_signal_status\"; }",
            "trap 'cmux_ssh_attach_lifecycle_end' EXIT",
            "trap 'cmux_ssh_attach_signal_exit 129' HUP",
            "trap 'cmux_ssh_attach_signal_exit 130' INT",
            "trap 'cmux_ssh_attach_signal_exit 143' TERM",
        ] + sshPTYAttachRetryLoopLines(command: attachCommand)).joined(separator: "\n")
        return "/bin/sh -c \(shellQuote(script))"
    }

    private func sshPTYAttachRetryLoopLines(command: String) -> [String] {
        // Retryable 254|255 is owned by SSHPTYAttachExitCode; keep in sync with SSHPTYAttachStartupCommandBuilder.retryingAttachLines.
        [
            "cmux_ssh_attach_reconnect_limit=\"${CMUX_SSH_RECONNECT_LIMIT:-}\"\ncase \"$cmux_ssh_attach_reconnect_limit\" in '') cmux_ssh_attach_reconnect_limit='∞'; cmux_ssh_attach_reconnect_unbounded=1 ;; *[!0-9]*) cmux_ssh_attach_reconnect_limit=20; cmux_ssh_attach_reconnect_unbounded=0 ;; *) cmux_ssh_attach_reconnect_unbounded=0 ;; esac",
            "cmux_ssh_attach_reconnect_delay=\"${CMUX_SSH_RECONNECT_DELAY_SECONDS:-2}\"\ncase \"$cmux_ssh_attach_reconnect_delay\" in ''|*[!0-9]*|0*) cmux_ssh_attach_reconnect_delay=2 ;; esac",
            "cmux_ssh_attach_reconnect_max_delay=\"${CMUX_SSH_RECONNECT_MAX_DELAY_SECONDS:-30}\"\ncase \"$cmux_ssh_attach_reconnect_max_delay\" in ''|*[!0-9]*|0*) cmux_ssh_attach_reconnect_max_delay=30 ;; esac",
            "if [ \"$cmux_ssh_attach_reconnect_delay\" -gt \"$cmux_ssh_attach_reconnect_max_delay\" ]; then cmux_ssh_attach_reconnect_delay=\"$cmux_ssh_attach_reconnect_max_delay\"; fi",
            "cmux_ssh_attach_reconnect_initial_delay=\"$cmux_ssh_attach_reconnect_delay\"",
            "cmux_ssh_attach_retry=0",
            "while :; do",
            "  if [ \"$cmux_ssh_attach_reconnect_unbounded\" -eq 1 ] || [ \"$cmux_ssh_attach_retry\" -lt \"$cmux_ssh_attach_reconnect_limit\" ]; then cmux_ssh_attach_can_retry=1; else cmux_ssh_attach_can_retry=0; fi\n  CMUX_SSH_PTY_ATTACH_WRAPPER_CAN_RETRY=\"$cmux_ssh_attach_can_retry\" \(command)",
            "  cmux_ssh_attach_status=$?",
            "  case \"$cmux_ssh_attach_status\" in 254) cmux_ssh_attach_reconnect_delay=\"$cmux_ssh_attach_reconnect_initial_delay\" ;; 255) ;; *) exit \"$cmux_ssh_attach_status\" ;; esac\n  if [ \"$cmux_ssh_attach_reconnect_unbounded\" -eq 0 ] && [ \"$cmux_ssh_attach_retry\" -ge \"$cmux_ssh_attach_reconnect_limit\" ]; then exit \"$cmux_ssh_attach_status\"; fi",
            "  cmux_ssh_attach_retry=$((cmux_ssh_attach_retry + 1))",
            "  if [ -t 2 ]; then printf '\\n\\033[33m[cmux] remote PTY bridge closed; reattaching (attempt %s/%s).\\033[0m\\n' \"$cmux_ssh_attach_retry\" \"$cmux_ssh_attach_reconnect_limit\" >&2 || true; fi",
            "  if [ \"$cmux_ssh_attach_reconnect_delay\" -gt 0 ]; then sleep \"$cmux_ssh_attach_reconnect_delay\"; fi",
            "  if [ \"$cmux_ssh_attach_reconnect_delay\" -lt \"$cmux_ssh_attach_reconnect_max_delay\" ]; then cmux_ssh_attach_reconnect_delay=$((cmux_ssh_attach_reconnect_delay * 2)); if [ \"$cmux_ssh_attach_reconnect_delay\" -gt \"$cmux_ssh_attach_reconnect_max_delay\" ]; then cmux_ssh_attach_reconnect_delay=\"$cmux_ssh_attach_reconnect_max_delay\"; fi; fi",
            "done",
        ]
    }

    private func sshSessionTargetParams(
        commandName: String,
        workspaceOpt: String?,
        allWorkspaces: Bool,
        client: SocketClient
    ) throws -> [String: Any] {
        if allWorkspaces {
            return ["all_workspaces": true]
        }
        let workspaceRaw = workspaceOpt ?? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"]
        guard let workspaceRaw,
              !workspaceRaw.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            return [:]
        }
        guard let workspaceId = try normalizeWorkspaceHandle(workspaceRaw, client: client) else {
            throw CLIError(message: "\(commandName): workspace not found")
        }
        return ["workspace_id": workspaceId]
    }

    private func runSSHPTYAttach(commandArgs: [String], client: SocketClient, explicitPassword: String?) throws {
        let (workspaceOpt, rem0) = parseOption(commandArgs, name: "--workspace")
        let (sessionIDOpt, rem1) = parseOption(rem0, name: "--session-id")
        let (lifecycleIDOpt, rem2) = parseOption(rem1, name: "--lifecycle-id")
        let (attachmentIDOpt, rem3) = parseOption(rem2, name: "--attachment-id")
        let (commandB64Opt, rem4) = parseOption(rem3, name: "--command-b64")
        let waitForReady = rem4.contains("--wait")
        let requireExisting = rem4.contains("--require-existing")
        let remaining = rem4.filter { $0 != "--wait" && $0 != "--require-existing" }
        if let unknown = remaining.first(where: { Self.isFlagToken($0) }) {
            throw CLIError(message: "ssh-pty-attach: unknown flag '\(unknown)'")
        }
        guard remaining.isEmpty,
              let lifecycleID = lifecycleIDOpt?.trimmingCharacters(in: .whitespacesAndNewlines),
              !lifecycleID.isEmpty else {
            throw CLIError(message: "Usage: cmux ssh-pty-attach --workspace <workspace> --session-id <id> [--attachment-id <id>] [--command-b64 <base64>] [--require-existing]")
        }
        let workspaceRaw = workspaceOpt ?? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"]
        guard let workspaceRaw,
              let workspaceId = try normalizeWorkspaceHandle(workspaceRaw, client: client),
              !workspaceId.isEmpty else {
            throw CLIError(message: "ssh-pty-attach requires --workspace or CMUX_WORKSPACE_ID")
        }
        guard let sessionID = sessionIDOpt?.trimmingCharacters(in: .whitespacesAndNewlines),
              !sessionID.isEmpty else {
            throw CLIError(message: "ssh-pty-attach requires --session-id <id>")
        }
        let environmentSurfaceID = Self.normalizedEnvValue(ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"])
        let explicitAttachmentID = Self.normalizedEnvValue(attachmentIDOpt)
        let surfaceID = environmentSurfaceID ?? (explicitAttachmentID.flatMap { UUID(uuidString: $0) == nil ? nil : $0 })
        let attachmentID = explicitAttachmentID ?? environmentSurfaceID ?? UUID().uuidString.lowercased()
        let command: String? = try commandB64Opt.flatMap { encoded in
            guard let data = Data(base64Encoded: encoded),
                  var decoded = String(data: data, encoding: .utf8) else {
                throw CLIError(message: "ssh-pty-attach: --command-b64 must be valid UTF-8 base64")
            }
            decoded = decoded
                .replacingOccurrences(of: "__CMUX_WORKSPACE_ID__", with: workspaceId)
                .replacingOccurrences(
                    of: "__CMUX_SURFACE_ID__",
                    with: ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"] ?? ""
                )
            return decoded
        }
        var bridgeReachedReady = false
        var sessionLostWillRespawn = false
        var wrapperWillRetrySameSurface = false
        var attachFinished = false
        var attachmentToken = ""
        func reconcileBridgeEnd(intentionalOnly: Bool) throws -> Bool {
            do {
                return try reconcileSSHPTYBridgeEnd(
                    client: client, workspaceId: workspaceId, surfaceID: surfaceID,
                    sessionID: sessionID, lifecycleID: lifecycleID, intentionalOnly: intentionalOnly
                )
            } catch let error as CLIError {
                if SSHPTYAttachExitCode(rawValue: error.exitCode)?.isWrapperRetryable == true,
                   sshPTYAttachWrapperRetryPending() {
                    wrapperWillRetrySameSurface = true
                }
                throw error
            }
        }
        defer {
            if !attachFinished {
                cleanupFailedSSHPTYAttach(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceID: surfaceID,
                    sessionID: sessionID,
                    lifecycleID: lifecycleID,
                    attachmentID: attachmentID,
                    attachmentToken: attachmentToken,
                    retireLifecycle: !sessionLostWillRespawn && !wrapperWillRetrySameSurface,
                    clearLocalSurface: !bridgeReachedReady && !sessionLostWillRespawn
                        && !wrapperWillRetrySameSurface
                )
            }
        }

        let bridge: [String: Any]
        do {
            var bridgeParams = sshPTYBridgeParams(
                workspaceId: workspaceId,
                surfaceID: surfaceID,
                sessionID: sessionID,
                lifecycleID: lifecycleID,
                attachmentID: attachmentID,
                command: command,
                requireExisting: requireExisting
            )
            if waitForReady {
                bridgeParams["wait_for_ready"] = true
            }
            bridge = try client.sendV2(
                method: "workspace.remote.pty_bridge",
                params: bridgeParams,
                responseTimeout: waitForReady ? 185 : nil
            )
        } catch {
            // Prefer the structured v2 error code over description matching so a
            // message-format change cannot silently turn a retryable failure fatal.
            let exitCode: SSHPTYAttachExitCode
            if let cliError = error as? CLIError, let code = cliError.v2Code {
                exitCode = SSHPTYAttachExitCode.classifyBridgeEstablishmentFailure(
                    code: code,
                    message: cliError.message
                )
            } else {
                exitCode = SSHPTYAttachExitCode.classifyBridgeEstablishmentFailure(String(describing: error))
            }
            let closedGeneration = (error as? CLIError)?.v2Code == "pty_lifecycle_closed"
            if !closedGeneration, exitCode.isWrapperRetryable, sshPTYAttachWrapperRetryPending() {
                wrapperWillRetrySameSurface = true
            }
            if closedGeneration {
                if (try? reconcileBridgeEnd(intentionalOnly: true)) == true {
                    attachFinished = true
                    return
                }
                cleanupFailedSSHPTYAttach(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceID: surfaceID,
                    sessionID: sessionID,
                    lifecycleID: lifecycleID,
                    attachmentID: attachmentID,
                    attachmentToken: attachmentToken,
                    retireLifecycle: true,
                    clearLocalSurface: true
                )
                attachFinished = true
                return
            }
            if exitCode.isWrapperRetryable {
                if try reconcileBridgeEnd(intentionalOnly: true) {
                    attachFinished = true
                    return
                }
            }
            if requireExisting && exitCode == .sessionNotFound {
                // Match the bridge-status path below: keep surface tracking intact before respawn.
                sessionLostWillRespawn = true
            }
            throw CLIError(
                message: "ssh-pty-attach: \(userFacingRemotePTYErrorMessage(error))",
                exitCode: exitCode
            )
        }
        var connectedFD: Int32?
        var bridgeHandshakeSize = Self.currentCLITerminalSize()
        do {
            let host = (bridge["host"] as? String) ?? "127.0.0.1"
            guard let port = cliStrictInt(bridge["port"]), port > 0, port <= 65535 else {
                throw CLIError(message: "ssh-pty-attach: bridge did not return a valid port")
            }
            guard let token = bridge["token"] as? String, !token.isEmpty else {
                throw CLIError(message: "ssh-pty-attach: bridge did not return a token")
            }

            connectedFD = try connectLoopbackTCP(host: host, port: port)
            let fd = connectedFD!
            let size = Self.currentCLITerminalSize()
            bridgeHandshakeSize = size
            var handshakeData = try JSONSerialization.data(withJSONObject: [
                "token": token,
                "cols": size.cols,
                "rows": size.rows,
                "client_pid": Int(getpid()),
            ], options: [])
            handshakeData.append(0x0A)
            try Self.writeAll(fd: fd, data: handshakeData)
            attachmentToken = try readSSHPTYBridgeReady(fd: fd)
            bridgeReachedReady = true
        } catch {
            let sessionNotFound = requireExisting &&
                (error as? CLIError)?.exitCode == SSHPTYAttachExitCode.sessionNotFound.rawValue
            if sessionNotFound {
                sessionLostWillRespawn = true
            }
            let preReadyRetryable = (error as? CLIError)
                .flatMap { SSHPTYAttachExitCode(rawValue: $0.exitCode) }?.isWrapperRetryable == true
            if preReadyRetryable, sshPTYAttachWrapperRetryPending() {
                wrapperWillRetrySameSurface = true
            }
            if let connectedFD { Darwin.close(connectedFD) }
            if !sessionNotFound, preReadyRetryable,
               try reconcileBridgeEnd(intentionalOnly: true) {
                attachFinished = true
                return
            }
            throw error
        }
        let fd = connectedFD!
        defer { Darwin.close(fd) }

        let rawMode = TerminalRawMode()
        defer { rawMode?.restore() }
        let resizeMonitor = SSHPTYResizeMonitor(
            socketPath: client.socketPath,
            explicitPassword: explicitPassword,
            workspaceId: workspaceId,
            surfaceID: surfaceID,
            sessionID: sessionID,
            attachmentID: attachmentID,
            attachmentToken: attachmentToken,
            initialSize: bridgeHandshakeSize
        )
        defer { resizeMonitor.cancel() }

        // Reconcile the remote PTY size once now that the SIGWINCH source is
        // armed. The handshake captured the terminal size before the source
        // existed; any SIGWINCH that arrived in that window was delivered with
        // SIGWINCH's default disposition (ignore) and lost, with no later
        // correction.
        resizeMonitor.requestCurrentResize()

        let reconnectInputFilterControl: SSHPTYAttachReconnectInputFilterControl?
        do {
            reconnectInputFilterControl = try SSHPTYAttachReconnectInputFilter.startStdinPump(
                fd: fd,
                filterEnabled: requireExisting && command == nil && isatty(STDIN_FILENO) == 1,
                beforeForwardingInput: { [resizeMonitor] in
                    await resizeMonitor.resizeBeforeInputIfNeeded()
                }
            )
        } catch {
            throw CLIError(message: "ssh-pty-attach: bridge write failed")
        }
        var reconnectInputFilterStopRequested = false

        var outputBuffer = [UInt8](repeating: 0, count: 32768)
        while true {
            let count = Darwin.read(fd, &outputBuffer, outputBuffer.count)
            if count > 0 {
                reconnectInputFilterControl?.stopFilteringBeforeFirstOutput(unlessAlreadyRequested: &reconnectInputFilterStopRequested)
                cliWriteStdout(Data(outputBuffer.prefix(count)))
            } else if count == 0 {
                resizeMonitor.cancel()
                _ = try reconcileBridgeEnd(intentionalOnly: false)
                attachFinished = true
                return
            } else if errno != EINTR {
                if sshPTYBridgeReadErrorIsEOF(errno) {
                    resizeMonitor.cancel()
                    _ = try reconcileBridgeEnd(intentionalOnly: false)
                    attachFinished = true
                    return
                }
                throw CLIError(message: "ssh-pty-attach: bridge read failed")
            }
        }
    }

    private func sshPTYBridgeReadErrorIsEOF(_ errnoValue: Int32) -> Bool {
        switch errnoValue {
        case ECONNRESET, ECONNABORTED, ENOTCONN:
            return true
        default:
            return false
        }
    }

    private func cliStrictInt(_ value: Any?) -> Int? {
        if let int = value as? Int { return int }
        if let number = value as? NSNumber {
            let double = number.doubleValue
            guard double.rounded(.towardZero) == double else { return nil }
            return number.intValue
        }
        return nil
    }

    private static func writeAll(fd: Int32, data: Data) throws {
        try data.withUnsafeBytes { rawBuffer in
            guard let base = rawBuffer.bindMemory(to: UInt8.self).baseAddress else { return }
            var remaining = rawBuffer.count
            var cursor = base
            while remaining > 0 {
                let written = Darwin.write(fd, cursor, remaining)
                if written > 0 {
                    remaining -= written
                    cursor = cursor.advanced(by: written)
                } else if written < 0 && errno == EINTR {
                    continue
                } else {
                    throw CLIError(
                        message: "ssh-pty-attach: bridge write failed",
                        exitCode: SSHPTYAttachExitCode.retryableTransient
                    )
                }
            }
        }
    }

    private func runSSHSessionEnd(commandArgs: [String], client: SocketClient) throws {
        let lifecycleOnly = commandArgs.contains("--lifecycle-only")
        let relayPort: Int?
        if let relayPortRaw = optionValue(commandArgs, name: "--relay-port") {
            guard let parsedRelayPort = Int(relayPortRaw), parsedRelayPort > 0 else {
                throw CLIError(message: "ssh-session-end requires --relay-port <port>")
            }
            relayPort = parsedRelayPort
        } else {
            guard lifecycleOnly else {
                throw CLIError(message: "ssh-session-end requires --relay-port <port>")
            }
            relayPort = nil
        }
        let workspaceRaw = optionValue(commandArgs, name: "--workspace") ?? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"]
        let surfaceRaw = optionValue(commandArgs, name: "--surface") ?? ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"]
        guard let workspaceRaw,
              let workspaceId = try normalizeWorkspaceHandle(workspaceRaw, client: client),
              !workspaceId.isEmpty else {
            throw CLIError(message: "ssh-session-end requires --workspace or CMUX_WORKSPACE_ID")
        }
        guard let surfaceRaw,
              let surfaceId = try normalizeSurfaceHandle(surfaceRaw, client: client, workspaceHandle: workspaceId),
              !surfaceId.isEmpty else {
            throw CLIError(message: "ssh-session-end requires --surface or CMUX_SURFACE_ID")
        }
        let sessionID = Self.normalizedEnvValue(optionValue(commandArgs, name: "--session-id"))
        let lifecycleID = Self.normalizedEnvValue(optionValue(commandArgs, name: "--lifecycle-id"))
        var params: [String: Any] = [
            "workspace_id": workspaceId,
            "surface_id": surfaceId,
            "lifecycle_only": lifecycleOnly,
        ]
        if let relayPort { params["relay_port"] = relayPort }
        if let sessionID, let lifecycleID {
            params["session_id"] = sessionID
            params["lifecycle_id"] = lifecycleID
        }
        _ = try client.sendV2(method: "workspace.remote.terminal_session_end", params: params)
    }

    private func runRemoteDaemonStatus(commandArgs: [String], jsonOutput: Bool) throws {
        let requestedOS = optionValue(commandArgs, name: "--os")?.trimmingCharacters(in: .whitespacesAndNewlines)
        let requestedArch = optionValue(commandArgs, name: "--arch")?.trimmingCharacters(in: .whitespacesAndNewlines)
        let info = resolvedVersionInfo()
        let manifest = remoteDaemonManifest()
        let platform = defaultRemoteDaemonPlatform(requestedOS: requestedOS, requestedArch: requestedArch)
        let cacheURL = remoteDaemonCacheURL(version: manifest?.appVersion ?? remoteDaemonVersionString(from: info), goOS: platform.goOS, goArch: platform.goArch)
        let cacheExists = FileManager.default.fileExists(atPath: cacheURL.path)
        let cacheSHA = cacheExists ? try? sha256Hex(forFile: cacheURL) : nil
        let entry = manifest?.entry(goOS: platform.goOS, goArch: platform.goArch)
        let cacheVerified = (entry != nil && cacheSHA?.lowercased() == entry?.sha256.lowercased())
        let releaseTag = manifest?.releaseTag ?? "unknown"
        let assetName = entry?.assetName ?? "unknown"
        let downloadURL = entry?.downloadURL ?? "unknown"
        let checksumsAssetName = manifest?.checksumsAssetName ?? "unknown"
        let checksumsURL = manifest?.checksumsURL ?? "unknown"
        let downloadCommand = "gh release download \(releaseTag) --repo manaflow-ai/cmux --pattern \(assetName)"
        let downloadChecksumsCommand = "gh release download \(releaseTag) --repo manaflow-ai/cmux --pattern \(checksumsAssetName)"
        let checksumVerifyCommand = "shasum -a 256 -c \(checksumsAssetName) --ignore-missing"
        let signerWorkflow = releaseTag == "nightly"
            ? "manaflow-ai/cmux/.github/workflows/nightly.yml"
            : "manaflow-ai/cmux/.github/workflows/release.yml"
        let verifyCommand = "gh attestation verify ./\(assetName) --repo manaflow-ai/cmux --signer-workflow \(signerWorkflow)"

        let payload: [String: Any] = [
            "app_version": remoteDaemonVersionString(from: info),
            "build": info["CFBundleVersion"] ?? NSNull(),
            "commit": info["CMUXCommit"] ?? NSNull(),
            "manifest_present": manifest != nil,
            "release_tag": releaseTag,
            "release_url": manifest?.releaseURL ?? NSNull(),
            "target_goos": platform.goOS,
            "target_goarch": platform.goArch,
            "asset_name": assetName,
            "download_url": downloadURL,
            "checksums_asset_name": checksumsAssetName,
            "checksums_url": checksumsURL,
            "expected_sha256": entry?.sha256 ?? NSNull(),
            "cache_path": cacheURL.path,
            "cache_exists": cacheExists,
            "cache_sha256": cacheSHA ?? NSNull(),
            "cache_verified": cacheVerified,
            "dev_local_build_fallback": ProcessInfo.processInfo.environment["CMUX_REMOTE_DAEMON_ALLOW_LOCAL_BUILD"] == "1",
            "download_command": downloadCommand,
            "download_checksums_command": downloadChecksumsCommand,
            "checksum_verify_command": checksumVerifyCommand,
            "attestation_verify_command": verifyCommand,
        ]

        if jsonOutput {
            print(jsonString(payload))
            return
        }

        print("app version: \(payload["app_version"] as? String ?? "unknown")")
        if let build = payload["build"] as? String {
            print("build: \(build)")
        }
        if let commit = payload["commit"] as? String {
            print("commit: \(commit)")
        }
        print("manifest: \(manifest != nil ? "present" : "missing")")
        print("platform: \(platform.goOS)/\(platform.goArch)")
        print("release: \(releaseTag)")
        print("asset: \(assetName)")
        print("download url: \(downloadURL)")
        print("checksums asset: \(checksumsAssetName)")
        print("checksums: \(checksumsURL)")
        if let expectedSHA = entry?.sha256 {
            print("expected sha256: \(expectedSHA)")
        }
        print("cache: \(cacheURL.path)")
        print("cache exists: \(cacheExists ? "yes" : "no")")
        if let cacheSHA {
            print("cache sha256: \(cacheSHA)")
        }
        print("cache verified: \(cacheVerified ? "yes" : "no")")
        print("download command: \(downloadCommand)")
        print("download checksums: \(downloadChecksumsCommand)")
        print("verify checksum: \(checksumVerifyCommand)")
        print("attestation verify: \(verifyCommand)")
        if manifest == nil {
            print("note: this build has no embedded remote daemon manifest. Set CMUX_REMOTE_DAEMON_ALLOW_LOCAL_BUILD=1 only for dev builds.")
        }
    }

    private func defaultRemoteDaemonPlatform(requestedOS: String?, requestedArch: String?) -> (goOS: String, goArch: String) {
        let normalizedOS = requestedOS?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        let normalizedArch = requestedArch?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        let goOS = (normalizedOS?.isEmpty == false ? normalizedOS! : hostGoOS())
        let goArch = (normalizedArch?.isEmpty == false ? normalizedArch! : hostGoArch())
        return (goOS, goArch)
    }

    private func hostGoOS() -> String {
#if os(macOS)
        return "darwin"
#elseif os(Linux)
        return "linux"
#else
        return "unknown"
#endif
    }

    private func hostGoArch() -> String {
#if arch(arm64)
        return "arm64"
#elseif arch(x86_64)
        return "amd64"
#else
        return "unknown"
#endif
    }

    private func remoteDaemonManifest() -> RemoteDaemonManifest? {
        for plistURL in candidateInfoPlistURLs() {
            guard let raw = NSDictionary(contentsOf: plistURL) as? [String: Any],
                  let rawManifest = raw["CMUXRemoteDaemonManifestJSON"] as? String,
                  let data = rawManifest.trimmingCharacters(in: .whitespacesAndNewlines).data(using: .utf8),
                  let manifest = try? JSONDecoder().decode(RemoteDaemonManifest.self, from: data) else {
                continue
            }
            return manifest
        }
        return nil
    }

    private func remoteDaemonVersionString(from info: [String: String]) -> String {
        info["CFBundleShortVersionString"] ?? "dev"
    }

    private func remoteDaemonCacheURL(version: String, goOS: String, goArch: String) -> URL {
        // Cache under the non-TCC cmux state directory rather than Application
        // Support: the separately-signed CLI downloads these on `cmux ssh`, and a
        // cross-identity reach into the app's Application Support data triggers the
        // macOS Sequoia "access data from other apps" prompt
        // (https://github.com/manaflow-ai/cmux/issues/5146). The app's
        // RemoteDaemonManifestRepository.cachedBinaryURL resolves the same path. The CLI is
        // a composition root, so it names the concrete `FileManager.default` here.
        return CmuxStateDirectory.url(homeDirectory: FileManager.default.homeDirectoryForCurrentUser)
            .appendingPathComponent("remote-daemons", isDirectory: true)
            .appendingPathComponent(version, isDirectory: true)
            .appendingPathComponent("\(goOS)-\(goArch)", isDirectory: true)
            .appendingPathComponent("cmuxd-remote", isDirectory: false)
    }

    private func sha256Hex(forFile url: URL) throws -> String {
        let data = try Data(contentsOf: url)
        let digest = SHA256.hash(data: data)
        return digest.map { String(format: "%02x", $0) }.joined()
    }

    private func hasSSHOptionKey(_ options: [String], key: String) -> Bool {
        SSHAgentSocketResolver().hasOptionKey(options, key: key)
    }

    private func deferredRemoteReconnectLocalCommandScript(
        in options: [String],
        localCLIPath: String?,
        foregroundAuthToken: String
    ) -> String? {
        guard shouldDeferRemoteReconnect(in: options) else { return nil }
        let preferredCLIPath = localCLIPath?.trimmingCharacters(in: .whitespacesAndNewlines)
        let quotedForegroundAuthToken = shellQuote(foregroundAuthToken)
        return [
            preferredCLIPath.map { "cmux_reconnect_cli=\(shellQuote($0));" } ?? "cmux_reconnect_cli=\"\";",
            "cmux_reconnect_socket=\"${CMUX_SOCKET_PATH:-${CMUX_SOCKET:-}}\";",
            "if [ -z \"$cmux_reconnect_cli\" ] && [ -n \"${CMUX_BUNDLED_CLI_PATH:-}\" ]; then cmux_reconnect_cli=\"$CMUX_BUNDLED_CLI_PATH\"; fi;",
            "if [ ! -x \"$cmux_reconnect_cli\" ]; then cmux_reconnect_cli=\"$(command -v cmux 2>/dev/null || true)\"; fi;",
            "if [ -n \"${CMUX_WORKSPACE_ID:-}\" ]; then",
            "if [ -z \"$cmux_reconnect_socket\" ]; then printf '%s\\n' 'cmux: deferred SSH reconnect skipped, local cmux socket not found' >&2;",
            "elif [ -z \"$cmux_reconnect_cli\" ] || [ ! -x \"$cmux_reconnect_cli\" ]; then printf '%s\\n' 'cmux: deferred SSH reconnect skipped, local cmux CLI not found' >&2;",
            "else",
            "cmux_reconnect_token=\(quotedForegroundAuthToken);",
            "cmux_reconnect_payload=\"{\\\"workspace_id\\\":\\\"$CMUX_WORKSPACE_ID\\\",\\\"foreground_auth_token\\\":\\\"$cmux_reconnect_token\\\"}\";",
            "\"$cmux_reconnect_cli\" --socket \"$cmux_reconnect_socket\" rpc workspace.remote.foreground_auth_ready \"$cmux_reconnect_payload\" >/dev/null 2>&1 || true;",
            "unset cmux_reconnect_payload cmux_reconnect_token;",
            "fi;",
            "fi;",
            "unset cmux_reconnect_socket cmux_reconnect_cli;",
        ].joined(separator: " ")
    }

    private func sshConnectionTimingLocalCommandScript(target: String, relayPort: Int) -> String {
        let escapedTarget = target
            .replacingOccurrences(of: "\\", with: "\\\\")
            .replacingOccurrences(of: "\"", with: "\\\"")
        return [
            "cmux_ssh_log_path=\"\";",
            "if [ -r /tmp/cmux-last-debug-log-path ]; then cmux_ssh_log_path=\"$(tr -d '\\r\\n' < /tmp/cmux-last-debug-log-path 2>/dev/null || true)\"; fi;",
            "if [ -n \"$cmux_ssh_log_path\" ]; then",
            "cmux_ssh_ts=\"$(python3 -c 'from datetime import datetime, timezone; print(datetime.now(timezone.utc).isoformat(timespec=\"milliseconds\").replace(\"+00:00\", \"Z\"))' 2>/dev/null || date -u +%Y-%m-%dT%H:%M:%SZ)\";",
            "printf '%s [cmux-cli] cli.ssh.handshake target=\(escapedTarget) relayPort=\(relayPort) stage=ssh.connected workspace=%s surface=%s\\n' \"$cmux_ssh_ts\" \"${CMUX_WORKSPACE_ID:-nil}\" \"${CMUX_SURFACE_ID:-nil}\" >> \"$cmux_ssh_log_path\";",
            "fi;",
            "unset cmux_ssh_log_path cmux_ssh_ts;",
        ].joined(separator: " ")
    }

    private func shouldDeferRemoteReconnect(in options: [String]) -> Bool {
        sshOptionsSupportReusableForegroundAuth(options)
    }

    internal func sshOptionsSupportReusableForegroundAuth(_ options: [String]) -> Bool {
        guard !hasSSHOptionKey(options, key: "LocalCommand"),
              !hasSSHOptionKey(options, key: "PermitLocalCommand") else {
            return false
        }

        guard let controlPath = sshOptionValue(named: "ControlPath", in: options)?
            .trimmingCharacters(in: .whitespacesAndNewlines),
              !controlPath.isEmpty,
              controlPath.lowercased() != "none" else {
            return false
        }

        let controlMaster = sshOptionValue(named: "ControlMaster", in: options)?
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if sshOptionValueIsDisabled(controlMaster) {
            return false
        }

        let controlPersist = sshOptionValue(named: "ControlPersist", in: options)?
            .trimmingCharacters(in: .whitespacesAndNewlines)
        return !sshOptionValueIsDisabled(controlPersist, zeroIsDisabled: false)
    }

    private func sshOptionValueIsDisabled(_ rawValue: String?, zeroIsDisabled: Bool = true) -> Bool {
        let normalized = rawValue?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        guard let normalized else { return false }
        return ["no", "false", "off"].contains(normalized) || (zeroIsDisabled && normalized == "0")
    }

    private func defaultSSHControlPathTemplate(remoteRelayPort: Int? = nil) -> String {
        if let remoteRelayPort, remoteRelayPort > 0 {
            return "/tmp/cmux-ssh-\(getuid())-\(remoteRelayPort)-%C"
        }
        return "/tmp/cmux-ssh-\(getuid())-%C"
    }

    private func normalizedSSHIdentityPath(_ rawPath: String?) -> String? {
        guard let rawPath else { return nil }
        let trimmed = rawPath.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }
        if trimmed.hasPrefix("~") {
            let expanded = (trimmed as NSString).expandingTildeInPath
            if !expanded.isEmpty {
                return expanded
            }
        }
        return trimmed
    }

    func shellQuote(_ value: String) -> String {
        let safePattern = "^[A-Za-z0-9_@%+=:,./-]+$"
        if value.range(of: safePattern, options: .regularExpression) != nil {
            return value
        }
        return "'" + value.replacingOccurrences(of: "'", with: "'\"'\"'") + "'"
    }

    private func execInteractiveProgram(
        launchPath: String,
        arguments: [String]
    ) throws -> Never {
        var argv = ([launchPath] + arguments).map { strdup($0) }
        defer {
            for item in argv {
                free(item)
            }
        }
        argv.append(nil)

        let code = cliExecFailureErrno {
            if launchPath.contains("/") {
                execv(launchPath, &argv)
            } else {
                execvp(launchPath, &argv)
            }
        }
        throw CLIError(message: "Failed to launch \(launchPath): \(String(cString: strerror(code)))")
    }

    private func sshOptionValue(named key: String, in options: [String]) -> String? {
        SSHAgentSocketResolver().optionValue(named: key, in: options)
    }

    private func cliDebugLog(_ message: @autoclosure () -> String) {
#if DEBUG
        let trimmedExplicit = ProcessInfo.processInfo.environment["CMUX_DEBUG_LOG"]?
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let path: String? = {
            if let trimmedExplicit, !trimmedExplicit.isEmpty {
                return trimmedExplicit
            }
            guard let marker = try? String(contentsOfFile: "/tmp/cmux-last-debug-log-path", encoding: .utf8) else {
                return nil
            }
            let trimmedMarker = marker.trimmingCharacters(in: .whitespacesAndNewlines)
            return trimmedMarker.isEmpty ? nil : trimmedMarker
        }()
        guard let path else { return }
        let timestamp = ISO8601DateFormatter().string(from: Date())
        let line = "\(timestamp) [cmux-cli] \(message())\n"
        guard let data = line.data(using: .utf8) else { return }
        if !FileManager.default.fileExists(atPath: path) {
            FileManager.default.createFile(atPath: path, contents: nil)
        }
        guard let handle = FileHandle(forWritingAtPath: path) else { return }
        defer { try? handle.close() }
        do {
            try handle.seekToEnd()
            try handle.write(contentsOf: data)
        } catch {
            return
        }
#endif
    }

    private func runProcess(
        executablePath: String,
        arguments: [String],
        stdinText: String? = nil,
        timeout: TimeInterval? = nil
    ) -> (status: Int32, stdout: String, stderr: String) {
        let result = CLIProcessRunner.runProcess(
            executablePath: executablePath,
            arguments: arguments,
            stdinText: stdinText,
            timeout: timeout
        )
        return (result.status, result.stdout, result.stderr)
    }

    private func runBrowserCommand(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat
    ) throws {
        guard !commandArgs.isEmpty else {
            throw CLIError(message: "browser requires a subcommand")
        }

        var effectiveJSONOutput = jsonOutput
        var effectiveIDFormat = idFormat
        var browserArgs = commandArgs

        // Browser-skill examples often place output flags at the end of the command.
        // Strip trailing display flags so they don't become part of a URL or selector.
        while !browserArgs.isEmpty {
            if browserArgs.last == "--json" {
                effectiveJSONOutput = true
                browserArgs.removeLast()
                continue
            }

            if browserArgs.count >= 2,
               browserArgs[browserArgs.count - 2] == "--id-format" {
                let raw = browserArgs.last!
                guard let parsed = try CLIIDFormat.parse(raw) else {
                    throw CLIError(message: "--id-format must be one of: refs, uuids, both")
                }
                effectiveIDFormat = parsed
                browserArgs.removeLast(2)
                continue
            }

            break
        }

        let (surfaceOpt, argsWithoutSurfaceFlag) = parseOption(browserArgs, name: "--surface")
        var surfaceRaw = surfaceOpt
        var args = argsWithoutSurfaceFlag

        let verbsWithoutSurface: Set<String> = ["open", "open-split", "new", "identify", "import", "profile", "profiles", "react-grab", "reactgrab", "devtools", "dev-tools", "focus-mode", "zoom", "history"]
        if surfaceRaw == nil, let first = args.first {
            if !first.hasPrefix("-") && !verbsWithoutSurface.contains(first.lowercased()) {
                surfaceRaw = first
                args = Array(args.dropFirst())
            }
        }

        guard let subcommandRaw = args.first else {
            throw CLIError(message: "browser requires a subcommand")
        }
        let subcommand = subcommandRaw.lowercased()
        let subArgs = Array(args.dropFirst())
        let browserValueTextFormatter = BrowserValueTextFormatter()

        // A post-action snapshot can spend 3s in document readiness, 10s in the
        // requested action, 10s in snapshot JavaScript, and 2.5s in recovery.
        // Keep transport headroom beyond that 25.5s app-side maximum.
        func sendBrowserAutomationRequest(method: String, params: [String: Any]) throws -> [String: Any] {
            let responseTimeout: TimeInterval = (params["snapshot_after"] as? Bool) == true ? 30 : 20
            return try client.sendV2(method: method, params: params, responseTimeout: responseTimeout)
        }

        func requireSurface() throws -> String {
            guard let raw = surfaceRaw else {
                throw CLIError(message: "browser \(subcommand) requires a surface handle (use: browser <surface> \(subcommand) ... or --surface)")
            }
            guard let resolved = try normalizeSurfaceHandle(raw, client: client) else {
                throw CLIError(message: "Invalid surface handle")
            }
            return resolved
        }

        func output(_ payload: [String: Any], fallback: String) {
            if effectiveJSONOutput {
                print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
                return
            }
            print(fallback)
            if let snapshot = payload["post_action_snapshot"] as? String,
               !snapshot.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                print(snapshot)
            }
        }

        func displaySnapshotText(_ payload: [String: Any]) -> String {
            let snapshotText = (payload["snapshot"] as? String) ?? "Empty page"
            guard snapshotText.contains("\n- (empty)") else {
                return snapshotText
            }

            let url = ((payload["url"] as? String) ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let readyState = ((payload["ready_state"] as? String) ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            var lines = [snapshotText]

            if !url.isEmpty {
                lines.append("url: \(url)")
            }
            if !readyState.isEmpty {
                lines.append("ready_state: \(readyState)")
            }
            if url.isEmpty || url == "about:blank" {
                lines.append("hint: run 'cmux browser <surface> get url' to verify navigation")
            }

            return lines.joined(separator: "\n")
        }

        func displayBrowserLogItems(_ value: Any?) -> String? {
            guard let items = value as? [Any], !items.isEmpty else {
                return nil
            }

            let lines = items.map { item -> String in
                guard let dict = item as? [String: Any] else {
                    return browserValueTextFormatter.string(from: item)
                }

                let text = (dict["text"] as? String)?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                let levelRaw = (dict["level"] as? String)?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                let level = levelRaw.isEmpty ? "log" : levelRaw

                if text.isEmpty {
                    if let message = (dict["message"] as? String)?.trimmingCharacters(in: .whitespacesAndNewlines),
                       !message.isEmpty {
                        return "[error] \(message)"
                    }
                    return browserValueTextFormatter.string(from: dict)
                }
                return "[\(level)] \(text)"
            }

            return lines.joined(separator: "\n")
        }
        func nonFlagArgs(_ values: [String]) -> [String] {
            values.filter { !$0.hasPrefix("-") }
        }

        func optionValues(_ values: [String], names: Set<String>) throws -> [String] {
            var result: [String] = []
            var index = 0
            while index < values.count {
                let value = values[index]
                if names.contains(value) {
                    guard index + 1 < values.count,
                          !values[index + 1].hasPrefix("-"),
                          !names.contains(values[index + 1]) else {
                        throw CLIError(message: "\(value) requires a value")
                    }
                    result.append(values[index + 1])
                    index += 2
                    continue
                }
                index += 1
            }
            return result
        }

        func firstOptionValue(_ values: [String], names: Set<String>) throws -> String? {
            try optionValues(values, names: names).first
        }

        func intPayloadValue(_ value: Any?) -> Int {
            if let intValue = value as? Int { return intValue }
            if let number = value as? NSNumber { return number.intValue }
            return 0
        }

        func stringPayloadValue(_ value: Any?) -> String? {
            (value as? String)?.trimmingCharacters(in: .whitespacesAndNewlines)
        }

        func browserProfileLine(_ raw: Any) -> String? {
            guard let profile = raw as? [String: Any],
                  let name = stringPayloadValue(profile["name"]),
                  let slug = stringPayloadValue(profile["slug"]),
                  let id = stringPayloadValue(profile["id"]) else {
                return nil
            }
            var markers: [String] = []
            if (profile["current"] as? Bool) == true {
                markers.append("current")
            }
            if (profile["built_in_default"] as? Bool) == true {
                markers.append("default")
            }
            let suffix = markers.isEmpty ? "" : " (\(markers.joined(separator: ", ")))"
            return "\(slug)\t\(name)\t\(id)\(suffix)"
        }

        func printBrowserProfiles(_ payload: [String: Any]) {
            guard let profiles = payload["profiles"] as? [Any], !profiles.isEmpty else {
                print("No browser profiles")
                return
            }
            for profile in profiles {
                if let line = browserProfileLine(profile) {
                    print(line)
                }
            }
        }

        if subcommand == "identify" {
            let surface = try normalizeSurfaceHandle(surfaceRaw, client: client, allowFocused: true)
            var payload = try client.sendV2(method: "system.identify")
            if let surface {
                let urlPayload = try client.sendV2(method: "browser.url.get", params: ["surface_id": surface])
                let titlePayload = try client.sendV2(method: "browser.get.title", params: ["surface_id": surface])
                var browser: [String: Any] = [:]
                browser["surface"] = surface
                browser["url"] = urlPayload["url"] ?? ""
                browser["title"] = titlePayload["title"] ?? ""
                payload["browser"] = browser
            }
            output(payload, fallback: "OK")
            return
        }

        if subcommand == "profile" || subcommand == "profiles" {
            let profileVerb = subArgs.first?.lowercased() ?? "list"
            let profileArgs = subArgs.first != nil ? Array(subArgs.dropFirst()) : []
            let normalizedVerb: String
            switch profileVerb {
            case "ls":
                normalizedVerb = "list"
            case "add", "new":
                normalizedVerb = "create"
            case "remove", "rm":
                normalizedVerb = "delete"
            default:
                normalizedVerb = profileVerb
            }

            switch normalizedVerb {
            case "list":
                let payload = try client.sendV2(method: "browser.profiles.list")
                if effectiveJSONOutput {
                    print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
                } else {
                    printBrowserProfiles(payload)
                }
            case "create":
                let (nameOpt, remaining) = parseOption(profileArgs, name: "--name")
                let name = nameOpt ?? nonFlagArgs(remaining).joined(separator: " ")
                guard !name.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
                    throw CLIError(message: "browser profiles \(profileVerb) requires a name")
                }
                let payload = try client.sendV2(method: "browser.profiles.create", params: ["name": name])
                if effectiveJSONOutput {
                    print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
                } else if let profileDict = payload["profile"] as? [String: Any],
                          let profile = browserProfileLine(profileDict) {
                    print("Created browser profile \(profile)")
                } else {
                    print("Created browser profile")
                }
            case "rename":
                let (profileOpt, rem1) = parseOption(profileArgs, name: "--profile")
                let (nameOpt, rem2) = parseOption(rem1, name: "--name")
                let positional = nonFlagArgs(rem2)
                let profile = profileOpt ?? positional.first
                let newName = nameOpt ?? (positional.count > 1 ? positional.dropFirst().joined(separator: " ") : nil)
                guard let profile, !profile.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
                    throw CLIError(message: "browser profiles \(profileVerb) requires a profile")
                }
                guard let newName, !newName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
                    throw CLIError(message: "browser profiles \(profileVerb) requires a new name")
                }
                let payload = try client.sendV2(
                    method: "browser.profiles.rename",
                    params: ["profile": profile, "new_name": newName]
                )
                if effectiveJSONOutput {
                    print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
                } else if let renamed = stringPayloadValue((payload["profile"] as? [String: Any])?["name"]) {
                    print("Renamed browser profile to \(renamed).")
                } else {
                    print("Renamed browser profile.")
                }
            case "clear":
                let (profileOpt, rem1) = parseOption(profileArgs, name: "--profile")
                let positional = nonFlagArgs(rem1)
                var params: [String: Any] = [:]
                if hasFlag(profileArgs, name: "--all") {
                    params["all"] = true
                } else if let profile = profileOpt ?? positional.first {
                    params["profile"] = profile
                } else {
                    throw CLIError(message: "browser profiles \(profileVerb) requires a profile or --all")
                }
                if hasFlag(profileArgs, name: "--force") {
                    params["force"] = true
                }
                let payload = try client.sendV2(method: "browser.profiles.clear", params: params, responseTimeout: 120)
                if effectiveJSONOutput {
                    print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
                } else {
                    let count = intPayloadValue(payload["count"])
                    print("Cleared \(count) browser profile\(count == 1 ? "" : "s").")
                }
            case "delete":
                let (profileOpt, rem1) = parseOption(profileArgs, name: "--profile")
                let profile = profileOpt ?? nonFlagArgs(rem1).first
                guard let profile, !profile.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
                    throw CLIError(message: "browser profiles \(profileVerb) requires a profile")
                }
                let payload = try client.sendV2(
                    method: "browser.profiles.delete",
                    params: ["profile": profile],
                    responseTimeout: 120
                )
                if effectiveJSONOutput {
                    print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
                } else if let deleted = stringPayloadValue((payload["profile"] as? [String: Any])?["name"]) {
                    print("Deleted browser profile \(deleted).")
                } else {
                    print("Deleted browser profile.")
                }
            default:
                throw CLIError(message: "Unsupported browser profiles subcommand: \(profileVerb)")
            }
            return
        }

        if subcommand == "import" {
            let importArgs = subArgs
            let importValueOptions: Set<String> = [
                "--from",
                "--browser",
                "--source",
                "--profile",
                "--source-profile",
                "--to",
                "--to-profile",
                "--destination-profile",
                "--domain",
                "--domains",
            ]
            let importFlags: Set<String> = [
                "--interactive",
                "--non-interactive",
                "--noninteractive",
                "--yes",
                "-y",
                "--all-profiles",
                "--create-profile",
                "--create-destination-profile",
            ]
            func importPositionals(_ values: [String]) -> [String] {
                var result: [String] = []
                var index = 0
                var pastTerminator = false
                while index < values.count {
                    let value = values[index]
                    if pastTerminator {
                        result.append(value)
                        index += 1
                        continue
                    }
                    if value == "--" {
                        pastTerminator = true
                        index += 1
                        continue
                    }
                    if importValueOptions.contains(value) {
                        index += index + 1 < values.count ? 2 : 1
                        continue
                    }
                    if importFlags.contains(value) || value.hasPrefix("-") {
                        index += 1
                        continue
                    }
                    result.append(value)
                    index += 1
                }
                return result
            }
            let unsupportedPositionals = importPositionals(importArgs)
            if let first = unsupportedPositionals.first {
                let normalized = first.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
                if normalized == "cookie" || normalized == "cookies" {
                    throw CLIError(message: "browser import no longer takes a data type; use 'cmux browser import'")
                }
                throw CLIError(message: "browser import does not accept positional arguments")
            }
            let forceInteractive = hasFlag(importArgs, name: "--interactive")
            let forceNonInteractive = hasFlag(importArgs, name: "--non-interactive") ||
                hasFlag(importArgs, name: "--noninteractive") ||
                hasFlag(importArgs, name: "--yes") ||
                hasFlag(importArgs, name: "-y")
            if forceInteractive && forceNonInteractive {
                throw CLIError(message: "browser import cannot use both --interactive and --non-interactive")
            }

            let shouldRunNonInteractive = forceNonInteractive ||
                (!forceInteractive && Self.isCodingAgentEnvironment(ProcessInfo.processInfo.environment))

            var params: [String: Any] = shouldRunNonInteractive ? ["scope": "cookiesOnly"] : [:]
            if let browser = try firstOptionValue(importArgs, names: ["--from", "--browser", "--source"]) {
                params["browser"] = browser
            }
            let sourceProfiles = try optionValues(importArgs, names: ["--profile", "--source-profile"])
            if !sourceProfiles.isEmpty {
                params["source_profiles"] = sourceProfiles
            }
            if let destination = try firstOptionValue(importArgs, names: ["--to", "--to-profile", "--destination-profile"]) {
                params["destination_profile"] = destination
            }
            let domainFilters = try optionValues(importArgs, names: ["--domain", "--domains"])
            if !domainFilters.isEmpty {
                params["domain_filters"] = domainFilters
            }
            if hasFlag(importArgs, name: "--all-profiles") {
                params["all_profiles"] = true
            }
            if hasFlag(importArgs, name: "--create-profile") ||
                hasFlag(importArgs, name: "--create-destination-profile") {
                params["create_destination_profile"] = true
            }

            if shouldRunNonInteractive {
                let payload = try client.sendV2(
                    method: "browser.import.cookies",
                    params: params,
                    responseTimeout: 10 * 60
                )
                if effectiveJSONOutput {
                    print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
                    return
                }

                let browserName = (payload["browser"] as? String) ?? "browser"
                let importedCount = intPayloadValue(payload["imported_cookies"])
                let skippedCount = intPayloadValue(payload["skipped_cookies"])
                print("Imported \(importedCount) cookies from \(browserName).")
                if skippedCount > 0 {
                    print("Skipped \(skippedCount) cookies.")
                }
                if let warnings = payload["warnings"] as? [String], !warnings.isEmpty {
                    for warning in warnings {
                        print("Warning: \(warning)")
                    }
                }
            } else {
                let payload = try client.sendV2(method: "browser.import.dialog", params: params, responseTimeout: 10 * 60)
                output(payload, fallback: "OK")
            }
            return
        }

        if subcommand == "open" || subcommand == "open-split" || subcommand == "new" {
            // Parse routing flags before URL assembly so they never leak into the URL string.
            let (workspaceOpt, argsAfterWorkspace) = parseOption(subArgs, name: "--workspace")
            let (windowOpt, argsAfterWindow) = parseOption(argsAfterWorkspace, name: "--window")
            let (focusOpt, urlArgs) = parseOption(argsAfterWindow, name: "--focus")
            // Reject unrecognized flags instead of folding them into the URL, where they
            // would silently produce an unparseable URL (blank page) or a search query.
            if let strayFlag = urlArgs.first(where: { $0.hasPrefix("--") }) {
                throw CLIError(message: "browser \(subcommand) does not support \(strayFlag)")
            }
            let url = urlArgs.joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
            let respectExternalOpenRules: Bool = {
                guard let raw = ProcessInfo.processInfo.environment["CMUX_RESPECT_EXTERNAL_OPEN_RULES"] else {
                    return false
                }
                switch raw.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
                case "1", "true", "yes", "on":
                    return true
                default:
                    return false
                }
            }()

            if surfaceRaw != nil, subcommand == "open" {
                // Treat `browser <surface> open <url>` as navigate for agent-browser ergonomics.
                let sid = try requireSurface()
                guard !url.isEmpty else {
                    throw CLIError(message: "browser <surface> open requires a URL")
                }
                let payload = try client.sendV2(method: "browser.navigate", params: ["surface_id": sid, "url": url])
                output(payload, fallback: "OK")
                return
            }

            var params: [String: Any] = [:]
            if !url.isEmpty {
                params["url"] = url
            }
            if let sourceSurface = try normalizeSurfaceHandle(surfaceRaw, client: client) {
                params["surface_id"] = sourceSurface
            }
            let workspaceRaw = workspaceOpt ?? (windowOpt == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)
            if let workspaceRaw {
                if let workspace = try normalizeWorkspaceHandle(workspaceRaw, client: client) {
                    params["workspace_id"] = workspace
                }
            }
            if respectExternalOpenRules {
                params["respect_external_open_rules"] = true
            }
            if let windowRaw = windowOpt {
                if let window = try normalizeWindowHandle(windowRaw, client: client) {
                    params["window_id"] = window
                }
            }
            try applyFocusOption(focusOpt, defaultValue: false, to: &params)
            let payload = try client.sendV2(method: "browser.open_split", params: params)
            let surfaceText = formatHandle(payload, kind: "surface", idFormat: effectiveIDFormat) ?? "unknown"
            let paneText = formatHandle(payload, kind: "pane", idFormat: effectiveIDFormat) ?? "unknown"
            let placement = ((payload["created_split"] as? Bool) == true) ? "split" : "reuse"
            output(payload, fallback: "OK surface=\(surfaceText) pane=\(paneText) placement=\(placement)")
            return
        }

        if subcommand == "goto" || subcommand == "navigate" {
            let sid = try requireSurface()
            // Accept --snapshot-after at any position, then reject any other flag instead
            // of folding it into the URL, where it would silently turn into a search query.
            let urlArgs = subArgs.filter { $0 != "--snapshot-after" }
            let snapshotAfter = urlArgs.count != subArgs.count
            if let strayFlag = urlArgs.first(where: { $0.hasPrefix("--") }) {
                throw CLIError(message: "browser \(subcommand) does not support \(strayFlag)")
            }
            let url = urlArgs.joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
            guard !url.isEmpty else {
                throw CLIError(message: "browser \(subcommand) requires a URL")
            }
            var params: [String: Any] = ["surface_id": sid, "url": url]
            if snapshotAfter {
                params["snapshot_after"] = true
            }
            let payload = try sendBrowserAutomationRequest(method: "browser.navigate", params: params)
            output(payload, fallback: "OK")
            return
        }

        if subcommand == "back" || subcommand == "forward" || subcommand == "reload" {
            let sid = try requireSurface()
            let methodMap: [String: String] = [
                "back": "browser.back",
                "forward": "browser.forward",
                "reload": "browser.reload",
            ]
            var params: [String: Any] = ["surface_id": sid]
            if hasFlag(subArgs, name: "--snapshot-after") {
                params["snapshot_after"] = true
            }
            let payload = try sendBrowserAutomationRequest(method: methodMap[subcommand]!, params: params)
            output(payload, fallback: "OK")
            return
        }

        // Routing scope for resolving an INDEXED --return-to handle. It must match the scope
        // optionalSurfaceParams() uses for the (optional) explicit --surface: an explicit surface is
        // scoped to explicit --workspace/--window only and does NOT inherit the env-default
        // workspace (it may legitimately target a different workspace than the caller's terminal),
        // while an implicit surface falls back to the caller's CMUX_WORKSPACE_ID. Scoping a return
        // handle to the env workspace when the browser lives in another workspace would index the
        // wrong terminal.
        func returnToRoutingHandles() throws -> (workspace: String?, window: String?) {
            let (workspaceOpt, _) = parseOption(subArgs, name: "--workspace")
            let (windowOpt, _) = parseOption(subArgs, name: "--window")
            let windowHandle = try windowOpt.flatMap { try normalizeWindowHandle($0, client: client) }
            let workspaceRaw = surfaceRaw != nil
                ? workspaceOpt
                : (workspaceOpt ?? (windowOpt == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil))
            let workspaceHandle = try workspaceRaw.flatMap {
                try normalizeWorkspaceHandle($0, client: client, windowHandle: windowHandle)
            }
            return (workspaceHandle, windowHandle)
        }

        // The verb/mode/direction is the first POSITIONAL token; routing flags may appear before or
        // after it, e.g. `browser devtools --workspace ws` or `browser zoom --window w in`.
        func browserActionVerbArgs() -> [String] {
            var rest = subArgs
            for name in ["--workspace", "--window", "--return-to"] {
                (_, rest) = parseOption(rest, name: name)
            }
            return rest.filter { !$0.hasPrefix("--") }
        }

        // Optional browser surface: an explicit --surface (or positional handle) targets that
        // browser; otherwise the app acts on the focused browser of the CALLER's workspace.
        // When no surface is given we still scope to the invoking workspace so a background agent
        // never acts on whatever workspace happens to be selected in the foreground.
        func optionalSurfaceParams() throws -> [String: Any] {
            let (workspaceOpt, _) = parseOption(subArgs, name: "--workspace")
            let (windowOpt, _) = parseOption(subArgs, name: "--window")
            let windowHandle = try windowOpt.flatMap { try normalizeWindowHandle($0, client: client) }
            let explicitWorkspace = try workspaceOpt.flatMap {
                try normalizeWorkspaceHandle($0, client: client, windowHandle: windowHandle)
            }
            if let raw = surfaceRaw {
                // Explicit surface: scope index resolution to explicit routing, and carry explicit
                // routing so the server rejects a surface/workspace mismatch. Do NOT add the
                // env-default workspace; an explicit surface handle may legitimately reference a
                // different workspace than the caller's terminal.
                guard let resolved = try normalizeSurfaceHandle(
                    raw, client: client, workspaceHandle: explicitWorkspace, windowHandle: windowHandle
                ) else {
                    throw CLIError(message: "Invalid surface handle")
                }
                var params: [String: Any] = ["surface_id": resolved]
                if let windowHandle { params["window_id"] = windowHandle }
                if let explicitWorkspace { params["workspace_id"] = explicitWorkspace }
                return params
            }
            var params: [String: Any] = [:]
            if let windowHandle { params["window_id"] = windowHandle }
            let workspaceRaw = workspaceOpt ?? (windowOpt == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)
            if let workspaceHandle = try workspaceRaw.flatMap({
                try normalizeWorkspaceHandle($0, client: client, windowHandle: windowHandle)
            }) {
                params["workspace_id"] = workspaceHandle
            }
            return params
        }

        if subcommand == "react-grab" || subcommand == "reactgrab" {
            let verb = browserActionVerbArgs().first?.lowercased() ?? "toggle"
            guard verb == "toggle" else {
                throw CLIError(message: "Unsupported browser react-grab subcommand: \(verb) (expected: toggle)")
            }
            var params = try optionalSurfaceParams()
            let routing = try returnToRoutingHandles()
            let (returnOpt, _) = parseOption(subArgs, name: "--return-to")
            if let returnRaw = returnOpt {
                // A supplied-but-unresolvable --return-to is an error, never a silent
                // pasteback drop: mirror the explicit-surface guard in optionalSurfaceParams().
                guard let resolvedReturn = try normalizeSurfaceHandle(
                    returnRaw, client: client,
                    workspaceHandle: routing.workspace, windowHandle: routing.window
                ) else {
                    throw CLIError(message: "Invalid --return-to surface handle")
                }
                params["return_to"] = resolvedReturn
            }
            let payload = try client.sendV2(method: "browser.react_grab.toggle", params: params)
            output(payload, fallback: "OK")
            return
        }

        if subcommand == "devtools" || subcommand == "dev-tools" {
            let verb = browserActionVerbArgs().first?.lowercased() ?? "toggle"
            let method: String
            switch verb {
            case "toggle": method = "browser.devtools.toggle"
            case "console": method = "browser.console.show"
            default:
                throw CLIError(message: "Unsupported browser devtools subcommand: \(verb) (expected: toggle, console)")
            }
            let payload = try client.sendV2(method: method, params: try optionalSurfaceParams())
            output(payload, fallback: "OK")
            return
        }

        if subcommand == "focus-mode" {
            let mode = browserActionVerbArgs().first?.lowercased() ?? "toggle"
            guard ["enter", "exit", "toggle", "on", "off"].contains(mode) else {
                throw CLIError(message: "browser focus-mode requires one of: enter, exit, toggle, on, off")
            }
            var params = try optionalSurfaceParams()
            params["mode"] = mode
            let payload = try client.sendV2(method: "browser.focus_mode.set", params: params)
            output(payload, fallback: "OK")
            return
        }

        if subcommand == "zoom" {
            guard let direction = browserActionVerbArgs().first?.lowercased(), ["in", "out", "reset"].contains(direction) else {
                throw CLIError(message: "browser zoom requires one of: in, out, reset")
            }
            var params = try optionalSurfaceParams()
            params["direction"] = direction
            let payload = try client.sendV2(method: "browser.zoom.set", params: params)
            output(payload, fallback: "OK")
            return
        }

        if subcommand == "history" {
            let verb = browserActionVerbArgs().first?.lowercased() ?? "clear"
            guard verb == "clear" else {
                throw CLIError(message: "Unsupported browser history subcommand: \(verb) (expected: clear)")
            }
            guard hasFlag(subArgs, name: "--force") || hasFlag(subArgs, name: "--yes") else {
                throw CLIError(message: "browser history clear permanently deletes the default browser profile's history (same as the View menu's Clear Browser History); pass --force to confirm")
            }
            let payload = try client.sendV2(method: "browser.history.clear", params: ["force": true])
            output(payload, fallback: "OK")
            return
        }

        if subcommand == "url" || subcommand == "get-url" {
            let sid = try requireSurface()
            let payload = try client.sendV2(method: "browser.url.get", params: ["surface_id": sid])
            if effectiveJSONOutput {
                print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
            } else {
                print((payload["url"] as? String) ?? "")
            }
            return
        }

        if ["focus-webview", "focus_webview"].contains(subcommand) {
            let sid = try requireSurface()
            let payload = try client.sendV2(method: "browser.focus_webview", params: ["surface_id": sid])
            output(payload, fallback: "OK")
            return
        }

        if ["is-webview-focused", "is_webview_focused"].contains(subcommand) {
            let sid = try requireSurface()
            let payload = try client.sendV2(method: "browser.is_webview_focused", params: ["surface_id": sid])
            if effectiveJSONOutput {
                print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
            } else {
                print((payload["focused"] as? Bool) == true ? "true" : "false")
            }
            return
        }

        if subcommand == "snapshot" {
            let sid = try requireSurface()
            let (selectorOpt, rem1) = parseOption(subArgs, name: "--selector")
            let (depthOpt, _) = parseOption(rem1, name: "--max-depth")

            var params: [String: Any] = ["surface_id": sid]
            if let selectorOpt {
                params["selector"] = selectorOpt
            }
            if hasFlag(subArgs, name: "--interactive") || hasFlag(subArgs, name: "-i") {
                params["interactive"] = true
            }
            if hasFlag(subArgs, name: "--cursor") {
                params["cursor"] = true
            }
            if hasFlag(subArgs, name: "--compact") {
                params["compact"] = true
            }
            if let depthOpt {
                guard let depth = Int(depthOpt), depth >= 0 else {
                    throw CLIError(message: "--max-depth must be a non-negative integer")
                }
                params["max_depth"] = depth
            }

            let payload = try sendBrowserAutomationRequest(method: "browser.snapshot", params: params)
            if effectiveJSONOutput {
                print(jsonString(formatIDs(payload, mode: effectiveIDFormat)))
            } else {
                print(displaySnapshotText(payload))
            }
            return
        }

        if subcommand == "eval" {
            let sid = try requireSurface()
            let script = optionValue(subArgs, name: "--script") ?? subArgs.joined(separator: " ")
            let trimmed = script.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty else {
                throw CLIError(message: "browser eval requires a script")
            }
            let payload = try sendBrowserAutomationRequest(method: "browser.eval", params: ["surface_id": sid, "script": trimmed])
            let fallback: String
            if let value = payload["value"] {
                fallback = browserValueTextFormatter.string(from: value)
            } else {
                fallback = "OK"
            }
            output(payload, fallback: fallback)
            return
        }

        if subcommand == "wait" {
            let sid = try requireSurface()
            var params: [String: Any] = ["surface_id": sid]

            let (selectorOpt, rem1) = parseOption(subArgs, name: "--selector")
            let (textOpt, rem2) = parseOption(rem1, name: "--text")
            let (urlContainsOptA, rem3) = parseOption(rem2, name: "--url-contains")
            let (urlContainsOptB, rem4) = parseOption(rem3, name: "--url")
            let (loadStateOpt, rem5) = parseOption(rem4, name: "--load-state")
            let (functionOpt, rem6) = parseOption(rem5, name: "--function")
            let (timeoutOptMs, rem7) = parseOption(rem6, name: "--timeout-ms")
            let (timeoutOptSec, rem8) = parseOption(rem7, name: "--timeout")

            if let selector = selectorOpt ?? rem8.first {
                params["selector"] = selector
            }
            if let textOpt {
                params["text_contains"] = textOpt
            }
            if let urlContains = urlContainsOptA ?? urlContainsOptB {
                params["url_contains"] = urlContains
            }
            if let loadStateOpt {
                params["load_state"] = loadStateOpt
            }
            if let functionOpt {
                params["function"] = functionOpt
            }
            if let timeoutOptMs {
                guard let ms = Int(timeoutOptMs) else {
                    throw CLIError(message: "--timeout-ms must be an integer")
                }
                params["timeout_ms"] = ms
            } else if let timeoutOptSec {
                guard let seconds = Double(timeoutOptSec) else {
                    throw CLIError(message: "--timeout must be a number")
                }
                params["timeout_ms"] = max(1, Int(seconds * 1000.0))
            }

            // Give the socket response timeout headroom beyond the wait deadline so long
            // waits are reported by the app handler instead of dying at the socket layer.
            let waitMs = (params["timeout_ms"] as? Int) ?? 5_000
            let responseTimeout = max(15.0, Double(waitMs) / 1000.0 + 8.0)
            let payload = try client.sendV2(method: "browser.wait", params: params, responseTimeout: responseTimeout)
            output(payload, fallback: "OK")
            return
        }

        if ["click", "dblclick", "hover", "focus", "check", "uncheck", "scrollintoview", "scrollinto", "scroll-into-view"].contains(subcommand) {
            let sid = try requireSurface()
            let (selectorOpt, rem1) = parseOption(subArgs, name: "--selector")
            let selector = selectorOpt ?? rem1.first
            guard let selector else {
                throw CLIError(message: "browser \(subcommand) requires a selector")
            }
            let methodMap: [String: String] = [
                "click": "browser.click",
                "dblclick": "browser.dblclick",
                "hover": "browser.hover",
                "focus": "browser.focus",
                "check": "browser.check",
                "uncheck": "browser.uncheck",
                "scrollintoview": "browser.scroll_into_view",
                "scrollinto": "browser.scroll_into_view",
                "scroll-into-view": "browser.scroll_into_view",
            ]
            var params: [String: Any] = ["surface_id": sid, "selector": selector]
            if hasFlag(subArgs, name: "--snapshot-after") {
                params["snapshot_after"] = true
            }
            let payload = try sendBrowserAutomationRequest(method: methodMap[subcommand]!, params: params)
            output(payload, fallback: "OK")
            return
        }

        if ["type", "fill"].contains(subcommand) {
            let sid = try requireSurface()
            let (selectorOpt, rem1) = parseOption(subArgs, name: "--selector")
            let (textOpt, rem2) = parseOption(rem1, name: "--text")
            let selector = selectorOpt ?? rem2.first
            guard let selector else {
                throw CLIError(message: "browser \(subcommand) requires a selector")
            }

            let positional = selectorOpt != nil ? rem2 : Array(rem2.dropFirst())
            let hasExplicitText = textOpt != nil || !positional.isEmpty
            let text: String
            if let textOpt {
                text = textOpt
            } else {
                text = positional.joined(separator: " ")
            }
            if subcommand == "type" {
                guard hasExplicitText, !text.isEmpty else {
                    throw CLIError(message: "browser type requires text")
                }
            }

            let method = (subcommand == "type") ? "browser.type" : "browser.fill"
            var params: [String: Any] = ["surface_id": sid, "selector": selector, "text": text]
            if hasFlag(subArgs, name: "--snapshot-after") {
                params["snapshot_after"] = true
            }
            let payload = try sendBrowserAutomationRequest(method: method, params: params)
            output(payload, fallback: "OK")
            return
        }

        if ["press", "key", "keydown", "keyup"].contains(subcommand) {
            let sid = try requireSurface()
            let (keyOpt, rem1) = parseOption(subArgs, name: "--key")
            let key = keyOpt ?? rem1.first
            guard let key else {
                throw CLIError(message: "browser \(subcommand) requires a key")
            }
            let methodMap: [String: String] = [
                "press": "browser.press",
                "key": "browser.press",
                "keydown": "browser.keydown",
                "keyup": "browser.keyup",
            ]
            var params: [String: Any] = ["surface_id": sid, "key": key]
            if hasFlag(subArgs, name: "--snapshot-after") {
                params["snapshot_after"] = true
            }
            let payload = try sendBrowserAutomationRequest(method: methodMap[subcommand]!, params: params)
            output(payload, fallback: "OK")
            return
        }

        if subcommand == "select" {
            let sid = try requireSurface()
            let (selectorOpt, rem1) = parseOption(subArgs, name: "--selector")
            let (valueOpt, rem2) = parseOption(rem1, name: "--value")
            let selector = selectorOpt ?? rem2.first
            guard let selector else {
                throw CLIError(message: "browser select requires a selector")
            }
            let value = valueOpt ?? (selectorOpt != nil ? rem2.first : rem2.dropFirst().first)
            guard let value else {
                throw CLIError(message: "browser select requires a value")
            }
            var params: [String: Any] = ["surface_id": sid, "selector": selector, "value": value]
            if hasFlag(subArgs, name: "--snapshot-after") {
                params["snapshot_after"] = true
