    private func runClaudeTeamsTmuxCompat(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        let (command, rawArgs) = try splitTmuxCommand(commandArgs)

        switch command {
        case "new-session", "new":
            let parsed = try parseTmuxArguments(
                rawArgs,
                valueFlags: ["-c", "-F", "-n", "-s"],
                boolFlags: ["-A", "-d", "-P"]
            )
            if parsed.hasFlag("-A") {
                throw CLIError(message: "new-session -A is not supported in cmux claude-teams mode")
            }
            var params: [String: Any] = ["focus": false]
            if let cwd = parsed.value("-c") {
                params["cwd"] = resolvePath(cwd)
            }
            let created = try client.sendV2(method: "workspace.create", params: params)
            guard let workspaceId = created["workspace_id"] as? String else {
                throw CLIError(message: "workspace.create did not return workspace_id")
            }
            if let title = parsed.value("-n") ?? parsed.value("-s"),
               !title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                _ = try client.sendV2(method: "workspace.rename", params: [
                    "workspace_id": workspaceId,
                    "title": title
                ])
            }
            if let text = tmuxShellCommandText(commandTokens: parsed.positional, cwd: parsed.value("-c")) {
                let surfaceId = try resolveSurfaceId(nil, workspaceId: workspaceId, client: client)
                _ = try client.sendV2(method: "surface.send_text", params: [
                    "workspace_id": workspaceId,
                    "surface_id": surfaceId,
                    "text": text
                ])
            }
            if parsed.hasFlag("-P") {
                let context = try tmuxFormatContext(workspaceId: workspaceId, client: client)
                print(tmuxRenderFormat(parsed.value("-F"), context: context, fallback: "@\(workspaceId)"))
            }

        case "new-window", "neww":
            let parsed = try parseTmuxArguments(
                rawArgs,
                valueFlags: ["-c", "-F", "-n", "-t"],
                boolFlags: ["-d", "-P"]
            )
            if parsed.value("-t") != nil {
                throw CLIError(message: "new-window -t is not supported in cmux claude-teams mode")
            }
            var params: [String: Any] = ["focus": false]
            if let cwd = parsed.value("-c") {
                params["cwd"] = resolvePath(cwd)
            }
            let created = try client.sendV2(method: "workspace.create", params: params)
            guard let workspaceId = created["workspace_id"] as? String else {
                throw CLIError(message: "workspace.create did not return workspace_id")
            }
            if let title = parsed.value("-n"),
               !title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                _ = try client.sendV2(method: "workspace.rename", params: [
                    "workspace_id": workspaceId,
                    "title": title
                ])
            }
            if let text = tmuxShellCommandText(commandTokens: parsed.positional, cwd: parsed.value("-c")) {
                let surfaceId = try resolveSurfaceId(nil, workspaceId: workspaceId, client: client)
                _ = try client.sendV2(method: "surface.send_text", params: [
                    "workspace_id": workspaceId,
                    "surface_id": surfaceId,
                    "text": text
                ])
            }
            if parsed.hasFlag("-P") {
                let context = try tmuxFormatContext(workspaceId: workspaceId, client: client)
                print(tmuxRenderFormat(parsed.value("-F"), context: context, fallback: "@\(workspaceId)"))
            }

        case "split-window", "splitw":
            let parsed = try parseTmuxArguments(
                rawArgs,
                valueFlags: ["-c", "-F", "-l", "-t"],
                boolFlags: ["-P", "-b", "-d", "-f", "-h", "-v"]
            )
            let isOMXHud = tmuxCommandLooksLikeOMXHud(parsed.positional)
            if isOMXHud && tmuxOMXHudConfigDisablesHud(cwd: parsed.value("-c")) {
                tmuxWriteDebugDiagnostic(
                    "OMX HUD disabled by config; cwd=\(parsed.value("-c") ?? "<default>") command=\(parsed.positional.joined(separator: " "))"
                )
                return
            }

            var target = try tmuxResolveSurfaceTarget(parsed.value("-t"), client: client)
            var direction: String
            var anchoredCallerSurfaceId: String?
            if parsed.hasFlag("-h") {
                direction = parsed.hasFlag("-b") ? "left" : "right"
            } else {
                direction = parsed.hasFlag("-b") ? "up" : "down"
            }

            // Claude's agent teams targets arbitrary panes (from list-panes),
            // not necessarily the leader pane from TMUX_PANE. Override the
            // target to anchor all teammate splits to the leader surface.
            // Only apply caller anchoring when the caller's workspace resolves
            // successfully. Falling back to target.workspaceId would pair
            // the caller's surface with a different workspace, creating an
            // invalid cross-workspace split.
            if parsed.hasFlag("-h"),
               let callerWorkspace = tmuxCallerWorkspaceHandle(),
               let wsId = try? resolveWorkspaceId(callerWorkspace, client: client),
               let anchoredTarget = tmuxAnchoredSplitTarget(workspaceId: wsId, client: client) {
                target = (wsId, nil, anchoredTarget.targetSurfaceId)
                direction = anchoredTarget.direction
                anchoredCallerSurfaceId = anchoredTarget.callerSurfaceId
            }

            // Keep the leader pane focused while agents spawn beside it.
            // -d explicitly means "don't focus the new pane".
            let focusNewPane = !parsed.hasFlag("-d")
            var splitParams: [String: Any] = [
                "workspace_id": target.workspaceId,
                "surface_id": target.surfaceId,
                "direction": direction,
                "focus": focusNewPane
            ]
            if let cwd = parsed.value("-c")?.trimmingCharacters(in: .whitespacesAndNewlines),
               !cwd.isEmpty {
                splitParams["working_directory"] = resolvePath(cwd)
            }
            let startupScript = isOMXHud
                ? tmuxStartupScript(commandTokens: parsed.positional, cwd: parsed.value("-c"))
                : nil
            if let startupScript {
                splitParams["initial_command"] = startupScript
            }
            if let startCommand = tmuxStartCommand(commandTokens: parsed.positional) {
                splitParams["tmux_start_command"] = startCommand
            }
            if parsed.hasFlag("-P") { splitParams["remote_tmux_unsupported_options"] = ["-P"] }
            let sizeTargetPaneId = target.paneId
                ?? (try? tmuxResolvePaneTarget(parsed.value("-t"), client: client).paneId)
                ?? (try? tmuxPaneIdForSurface(
                    workspaceId: target.workspaceId,
                    surfaceId: target.surfaceId,
                    client: client
                ))
            if let targetPaneId = sizeTargetPaneId,
               let targetCells = tmuxSplitSizeCells(parsed.value("-l")),
               let dividerPosition = try? tmuxInitialDividerPosition(
                    workspaceId: target.workspaceId,
                    paneId: targetPaneId,
                    newPaneDirection: direction,
                    targetCells: targetCells,
                    client: client
               ) {
                splitParams["initial_divider_position"] = dividerPosition
            }
            let created = try client.sendV2(method: "surface.split", params: splitParams)
            if (created["accepted"] as? Bool) == true {
                // Routed to a remote tmux mirror: the split was applied to the
                // remote tmux session and the pane arrives asynchronously.
                // Option-carrying requests (command, cwd, sizing) are rejected
                // server-side BEFORE the remote mutation, so reaching here
                // means a plain split: succeed quietly (tmux split-window
                // prints nothing without -P) and skip local layout tracking.
                // Erroring here would invite retries that duplicate the
                // already-created remote pane. Current apps reject -P before
                // routing; if an older app still accepts it, the split already happened.
                break
            }
            guard let surfaceId = created["surface_id"] as? String else {
                throw CLIError(message: "surface.split did not return surface_id")
            }
            let paneId = created["pane_id"] as? String

            // Track the newly created pane for main-vertical layout.
            if !isOMXHud {
                var updatedStore = loadTmuxCompatStore()
                updatedStore.lastSplitSurface[target.workspaceId] = surfaceId
                if updatedStore.mainVerticalLayouts[target.workspaceId] != nil {
                    updatedStore.mainVerticalLayouts[target.workspaceId]?.lastColumnSurfaceId = surfaceId
                } else if direction == "right", let anchoredCallerSurfaceId {
                    // First right split created the column; seed main-vertical
                    // state so subsequent splits stack downward.
                    updatedStore.mainVerticalLayouts[target.workspaceId] = MainVerticalState(
                        mainSurfaceId: anchoredCallerSurfaceId,
                        lastColumnSurfaceId: surfaceId
                    )
                }
                try saveTmuxCompatStore(updatedStore)

                // Equalize vertical splits so teammate panes are evenly distributed.
                // Use orientation: "vertical" to only equalize the agent column,
                // preserving the leader/column horizontal divider position.
                _ = try? client.sendV2(method: "workspace.equalize_splits", params: [
                    "workspace_id": target.workspaceId,
                    "orientation": "vertical"
                ])
            }

            if startupScript == nil,
               let text = tmuxShellCommandText(commandTokens: parsed.positional, cwd: parsed.value("-c")) {
                _ = try client.sendV2(method: "surface.send_text", params: [
                    "workspace_id": target.workspaceId,
                    "surface_id": surfaceId,
                    "text": text
                ])
            }
            if parsed.hasFlag("-P") {
                let context = try tmuxFormatContext(
                    workspaceId: target.workspaceId,
                    paneId: paneId,
                    surfaceId: surfaceId,
                    client: client
                )
                let fallback = context["pane_id"] ?? surfaceId
                print(tmuxRenderFormat(parsed.value("-F"), context: context, fallback: fallback))
            }

        case "select-window", "selectw":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-t"], boolFlags: [])
            let workspaceId = try tmuxResolveWorkspaceTarget(parsed.value("-t"), client: client)
            _ = try client.sendV2(method: "workspace.select", params: ["workspace_id": workspaceId])

        case "select-pane", "selectp":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-P", "-T", "-t"], boolFlags: [])
            if parsed.value("-P") != nil || parsed.value("-T") != nil {
                return
            }
            let target = try tmuxResolvePaneTarget(parsed.value("-t"), client: client)
            _ = try client.sendV2(method: "pane.focus", params: [
                "workspace_id": target.workspaceId,
                "pane_id": target.paneId
            ])

        case "kill-window", "killw":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-t"], boolFlags: [])
            let workspaceId = try tmuxResolveWorkspaceTarget(parsed.value("-t"), client: client)
            _ = try client.sendV2(method: "workspace.close", params: ["workspace_id": workspaceId])
            try? tmuxPruneCompatWorkspaceState(workspaceId: workspaceId)

        case "kill-pane", "killp":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-t"], boolFlags: [])
            let target = try tmuxResolveSurfaceTarget(parsed.value("-t"), client: client)
            _ = try client.sendV2(method: "surface.close", params: [
                "workspace_id": target.workspaceId,
                "surface_id": target.surfaceId
            ])
            try? tmuxPruneCompatSurfaceState(
                workspaceId: target.workspaceId,
                surfaceId: target.surfaceId,
                client: client
            )
            // Re-equalize the agent column after removing a pane
            _ = try? client.sendV2(method: "workspace.equalize_splits", params: [
                "workspace_id": target.workspaceId,
                "orientation": "vertical"
            ])

        case "respawn-pane", "respawnp":
            let parsed = try parseTmuxArguments(
                rawArgs,
                valueFlags: ["-c", "-t"],
                boolFlags: ["-k"]
            )
            guard parsed.hasFlag("-k") else {
                throw CLIError(message: String(
                    localized: "cli.tmuxCompat.respawnPane.requiresForce",
                    defaultValue: "respawn-pane requires -k in cmux tmux compatibility mode"
                ))
            }
            let target = try tmuxResolveSurfaceTarget(parsed.value("-t"), client: client)
            let commandText: String
            if let explicitCommand = tmuxStartCommand(commandTokens: parsed.positional) {
                commandText = explicitCommand
            } else {
                commandText = try tmuxStoredStartCommand(
                    workspaceId: target.workspaceId,
                    surfaceId: target.surfaceId,
                    client: client
                ) ?? "exec ${SHELL:-/bin/sh} -l"
            }
            var params: [String: Any] = [
                "workspace_id": target.workspaceId,
                "surface_id": target.surfaceId,
                "command": tmuxRespawnStartCommand(commandText, prependEnv: tmuxClaudeTeamsRespawnEnvironment()),
                "tmux_start_command": commandText
            ]
            if let cwd = parsed.value("-c")?.trimmingCharacters(in: .whitespacesAndNewlines),
               !cwd.isEmpty {
                params["working_directory"] = resolvePath(cwd)
            }
            _ = try client.sendV2(method: "surface.respawn", params: params)

        case "send-keys", "send":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-t"], boolFlags: ["-l"])
            let target = try tmuxResolveSurfaceTarget(parsed.value("-t"), client: client)
            let text = tmuxSendKeysText(from: parsed.positional, literal: parsed.hasFlag("-l"))
            if !text.isEmpty {
                _ = try client.sendV2(method: "surface.send_text", params: [
                    "workspace_id": target.workspaceId,
                    "surface_id": target.surfaceId,
                    "text": text
                ])
            }

        case "capture-pane", "capturep":
            let parsed = try parseTmuxArguments(
                rawArgs,
                valueFlags: ["-E", "-S", "-t"],
                boolFlags: ["-J", "-N", "-p"]
            )
            let target = try tmuxResolveSurfaceTarget(parsed.value("-t"), client: client)
            var params: [String: Any] = [
                "workspace_id": target.workspaceId,
                "surface_id": target.surfaceId,
                "scrollback": true
            ]
            if let start = parsed.value("-S"), let lines = Int(start), lines < 0 {
                params["lines"] = abs(lines)
            }
            let payload = try client.sendV2(method: "surface.read_text", params: params)
            let text = (payload["text"] as? String) ?? ""
            if parsed.hasFlag("-p") {
                print(text)
            } else {
                var store = loadTmuxCompatStore()
                store.buffers["default"] = text
                try saveTmuxCompatStore(store)
            }

        case "display-message", "display", "displayp":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-F", "-t"], boolFlags: ["-p"])
            let target = try tmuxResolveSurfaceTarget(parsed.value("-t"), client: client)
            var context = try tmuxFormatContext(
                workspaceId: target.workspaceId,
                paneId: target.paneId,
                surfaceId: target.surfaceId,
                client: client
            )
            // Enrich with geometry for format strings like #{pane_width},#{window_width}
            let panePayload = try client.sendV2(method: "pane.list", params: ["workspace_id": target.workspaceId])
            let panesList = panePayload["panes"] as? [[String: Any]] ?? []
            let containerFrame = panePayload["container_frame"] as? [String: Any]
            if let targetPaneId = target.paneId,
               let matchingPane = panesList.first(where: { ($0["id"] as? String) == targetPaneId }) {
                tmuxEnrichContextWithGeometry(&context, pane: matchingPane, containerFrame: containerFrame)
            } else if let firstPane = panesList.first(where: { boolFromAny($0["focused"]) == true }) ?? panesList.first {
                tmuxEnrichContextWithGeometry(&context, pane: firstPane, containerFrame: containerFrame)
            }
            let format = parsed.positional.isEmpty ? parsed.value("-F") : parsed.positional.joined(separator: " ")
            let rendered = tmuxRenderFormat(format, context: context, fallback: "")
            if parsed.hasFlag("-p") || !rendered.isEmpty {
                print(rendered)
            }

        case "list-windows", "lsw":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-F", "-t"], boolFlags: [])
            let items = try tmuxWorkspaceItems(client: client)
            for item in items {
                guard let workspaceId = item["id"] as? String else { continue }
                let context = try tmuxFormatContext(workspaceId: workspaceId, client: client)
                let fallback = [
                    context["window_index"] ?? "?",
                    context["window_name"] ?? workspaceId
                ].joined(separator: " ")
                print(tmuxRenderFormat(parsed.value("-F"), context: context, fallback: fallback))
            }

        case "list-panes", "lsp":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-F", "-t"], boolFlags: [])
            // Resolve target: can be a pane (%uuid) or workspace. In tmux,
            // list-panes -t %<pane> lists all panes in the window containing that pane.
            let workspaceId: String
            if let target = parsed.value("-t"), tmuxPaneSelector(from: target) != nil {
                let paneTarget = try tmuxResolvePaneTarget(target, client: client)
                workspaceId = paneTarget.workspaceId
            } else {
                workspaceId = try tmuxResolveWorkspaceTarget(parsed.value("-t"), client: client)
            }
            let payload = try client.sendV2(method: "pane.list", params: ["workspace_id": workspaceId])
            let panes = payload["panes"] as? [[String: Any]] ?? []
            let containerFrame = payload["container_frame"] as? [String: Any]
            for pane in panes {
                guard let paneId = pane["id"] as? String else { continue }
                var context = try tmuxFormatContext(workspaceId: workspaceId, paneId: paneId, client: client)
                tmuxEnrichContextWithGeometry(&context, pane: pane, containerFrame: containerFrame)
                if tmuxFormatRequestsPaneCommand(parsed.value("-F")),
                   context["pane_start_command"] == nil,
                   let surfaceId = context["surface_id"],
                   let legacyHudStartCommand = tmuxLegacyOMXHudStartCommand(
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        client: client
                   ) {
                    context["pane_start_command"] = legacyHudStartCommand
                    context["pane_current_command"] = tmuxCurrentCommandName(from: legacyHudStartCommand)
                }
                let fallback = context["pane_id"] ?? paneId
                print(tmuxRenderFormat(parsed.value("-F"), context: context, fallback: fallback))
            }

        case "rename-window", "renamew":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-t"], boolFlags: [])
            let title = parsed.positional.joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
            guard !title.isEmpty else {
                throw CLIError(message: "rename-window requires a title")
            }
            let workspaceId = try tmuxResolveWorkspaceTarget(parsed.value("-t"), client: client)
            _ = try client.sendV2(method: "workspace.rename", params: [
                "workspace_id": workspaceId,
                "title": title
            ])

        case "resize-pane", "resizep":
            let parsed = try parseTmuxArguments(
                rawArgs,
                valueFlags: ["-t", "-x", "-y"],
                boolFlags: ["-D", "-L", "-R", "-U"]
            )
            let hasDirectionalFlags = parsed.hasFlag("-L")
                || parsed.hasFlag("-R")
                || parsed.hasFlag("-U")
                || parsed.hasFlag("-D")
            let target = try tmuxResolvePaneTarget(parsed.value("-t"), client: client)
            let isAbsoluteHeightOnlyResize = !hasDirectionalFlags
                && parsed.value("-x") == nil
                && parsed.value("-y") != nil
            if isAbsoluteHeightOnlyResize,
               tmuxPaneLooksLikeOMXHud(
                    workspaceId: target.workspaceId,
                    paneId: target.paneId,
                    client: client
               ) {
                return
            }

            if !hasDirectionalFlags, let absWidth = parsed.value("-x") {
                try tmuxResizePaneToSize(
                    workspaceId: target.workspaceId,
                    paneId: target.paneId,
                    targetSize: absWidth,
                    absoluteAxis: "horizontal",
                    client: client
                )
            } else if !hasDirectionalFlags, let absHeight = parsed.value("-y") {
                try tmuxResizePaneToSize(
                    workspaceId: target.workspaceId,
                    paneId: target.paneId,
                    targetSize: absHeight,
                    absoluteAxis: "vertical",
                    client: client
                )
            } else if hasDirectionalFlags {
                let directionFlag = ["-L", "-U", "-D", "-R"]
                    .first(where: parsed.hasFlag) ?? "-R"
                let direction: String = switch directionFlag {
                case "-L": "left"
                case "-U": "up"
                case "-D": "down"
                default: "right"
                }
                let firstPositional = parsed.positional.first
                let attachedAmount = firstPositional.flatMap { raw in
                    raw.hasPrefix(directionFlag) && raw.count > directionFlag.count
                        ? String(raw.dropFirst(directionFlag.count)) : nil
                }
                let rawAmount = (attachedAmount ?? firstPositional ?? parsed.value("-x") ?? parsed.value("-y") ?? "1")
                    .replacingOccurrences(of: "%", with: "")
                let amount = Int(rawAmount) ?? 1
                try tmuxResizePaneByCells(
                    workspaceId: target.workspaceId,
                    paneId: target.paneId,
                    direction: direction,
                    amountCells: max(1, amount),
                    client: client
                )
            }

        case "wait-for":
            try runTmuxCompatCommand(
                command: "wait-for",
                commandArgs: rawArgs,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )

        case "last-pane":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-t"], boolFlags: [])
            let workspaceId = try tmuxResolveWorkspaceTarget(parsed.value("-t"), client: client)
            _ = try client.sendV2(method: "pane.last", params: ["workspace_id": workspaceId])

        case "show-buffer", "showb":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-b"], boolFlags: [])
            let name = parsed.value("-b") ?? "default"
            let store = loadTmuxCompatStore()
            if let buffer = store.buffers[name] {
                print(buffer)
            }

        case "show-options", "show-option", "show":
            let parsed = try parseTmuxArguments(
                rawArgs,
                valueFlags: ["-t"],
                boolFlags: ["-g", "-q", "-s", "-v", "-w"]
            )
            let optionName = parsed.positional.last ?? ""
            guard optionName == "extended-keys" else {
                throw CLIError(message: "Unsupported tmux compatibility command: \(command) \(optionName)")
            }
            let value = "on"
            if parsed.hasFlag("-v") {
                print(value)
            } else {
                print("\(optionName) \(value)")
            }

        case "save-buffer", "saveb":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-b"], boolFlags: [])
            let name = parsed.value("-b") ?? "default"
            let store = loadTmuxCompatStore()
            guard let buffer = store.buffers[name] else {
                throw CLIError(message: "Buffer not found: \(name)")
            }
            if let outputPath = parsed.positional.last, !outputPath.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                try buffer.write(toFile: resolvePath(outputPath), atomically: true, encoding: .utf8)
            } else {
                print(buffer)
            }

        case "last-window", "next-window", "previous-window", "set-hook", "set-buffer", "list-buffers":
            try runTmuxCompatCommand(
                command: command,
                commandArgs: rawArgs,
                client: client,
                jsonOutput: jsonOutput,
                idFormat: idFormat,
                windowOverride: windowOverride
            )

        case "has-session", "has":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-t"], boolFlags: [])
            _ = try tmuxResolveWorkspaceTarget(parsed.value("-t"), client: client)

        case "select-layout":
            let parsed = try parseTmuxArguments(rawArgs, valueFlags: ["-t"], boolFlags: [])
            let layoutName = parsed.positional.first ?? ""
            // select-layout -t accepts pane targets (e.g. %1) in real tmux.
            // Try pane target first, then workspace target. Only fall back to
            // the caller's current workspace when no -t was provided; an
            // explicit -t that fails to resolve should error, not silently
            // apply to the wrong workspace.
            let workspaceId: String = {
                if let target = parsed.value("-t") {
                    if let resolved = try? tmuxResolvePaneTarget(target, client: client) {
                        return resolved.workspaceId
                    }
                    return (try? tmuxResolveWorkspaceTarget(target, client: client)) ?? ""
                }
                return (try? tmuxResolveWorkspaceTarget(nil, client: client)) ?? ""
            }()
            guard !workspaceId.isEmpty else {
                throw CLIError(message: "Could not resolve workspace for select-layout")
            }
            if layoutName == "main-vertical" || layoutName == "main-horizontal" {
                // For main-* layouts, only equalize the agent column (vertical splits),
                // not the top-level horizontal split between main and agents.
                let orientation = layoutName == "main-vertical" ? "vertical" : "horizontal"
                _ = try? client.sendV2(method: "workspace.equalize_splits", params: [
                    "workspace_id": workspaceId,
                    "orientation": orientation
                ])
            } else {
                // For tiled/even-* layouts, equalize everything
                _ = try? client.sendV2(method: "workspace.equalize_splits", params: ["workspace_id": workspaceId])
            }
            if layoutName == "main-vertical" {
                if let callerSurface = tmuxCallerSurfaceHandle() {
                    var store = loadTmuxCompatStore()
                    let existingColumn = store.mainVerticalLayouts[workspaceId]?.lastColumnSurfaceId
                    let seedColumn = existingColumn ?? store.lastSplitSurface[workspaceId]
                    store.mainVerticalLayouts[workspaceId] = MainVerticalState(
                        mainSurfaceId: callerSurface,
                        lastColumnSurfaceId: seedColumn
                    )
                    try saveTmuxCompatStore(store)
                }
            } else if !layoutName.isEmpty {
                // Non-main-vertical layout selected: clear stale state so
                // future splits don't incorrectly redirect to the old column.
                try tmuxPruneCompatWorkspaceState(workspaceId: workspaceId)
            }

        case "set-option", "set", "set-window-option", "setw", "source-file", "refresh-client", "attach-session", "detach-client":
            return

        case "-V", "-v":
            print("tmux 3.4")
            return

        default:
            throw CLIError(message: "Unsupported tmux compatibility command: \(command)")
        }
    }

    private struct MainVerticalState: Codable {
        /// The surface ID of the "main" (leader) pane on the left side.
        var mainSurfaceId: String
        /// The surface ID of the bottom-most pane in the right column.
        /// Subsequent teammate splits target this pane with direction "down".
        var lastColumnSurfaceId: String?
    }

    private struct TmuxCompatStore: Codable {
        var buffers: [String: String] = [:]
        var hooks: [String: String] = [:]
        /// Tracks main-vertical layout state per workspace, keyed by workspace ID.
        var mainVerticalLayouts: [String: MainVerticalState] = [:]
        /// Tracks the last surface created by split-window per workspace.
        /// Used to seed lastColumnSurfaceId when select-layout main-vertical
        /// is called after the first split.
        var lastSplitSurface: [String: String] = [:]

        /// Custom decoder so older store files missing newer keys
        /// (mainVerticalLayouts, lastSplitSurface) decode gracefully
        /// instead of throwing and resetting the entire store.
        init(from decoder: Decoder) throws {
            let container = try decoder.container(keyedBy: CodingKeys.self)
            buffers = try container.decodeIfPresent([String: String].self, forKey: .buffers) ?? [:]
            hooks = try container.decodeIfPresent([String: String].self, forKey: .hooks) ?? [:]
            mainVerticalLayouts = try container.decodeIfPresent([String: MainVerticalState].self, forKey: .mainVerticalLayouts) ?? [:]
            lastSplitSurface = try container.decodeIfPresent([String: String].self, forKey: .lastSplitSurface) ?? [:]
        }

        init() {}
    }

    private func tmuxCompatStoreURL() -> URL {
        let homePath = ProcessInfo.processInfo.environment["HOME"]
            ?? NSString(string: "~").expandingTildeInPath
        return URL(fileURLWithPath: homePath)
            .appendingPathComponent(".cmuxterm")
            .appendingPathComponent("tmux-compat-store.json")
    }

    private func loadTmuxCompatStore() -> TmuxCompatStore {
        let url = tmuxCompatStoreURL()
        guard let data = try? Data(contentsOf: url),
              let decoded = try? JSONDecoder().decode(TmuxCompatStore.self, from: data) else {
            return TmuxCompatStore()
        }
        return decoded
    }

    private func saveTmuxCompatStore(_ store: TmuxCompatStore) throws {
        let url = tmuxCompatStoreURL()
        let parent = url.deletingLastPathComponent()
        try FileManager.default.createDirectory(at: parent, withIntermediateDirectories: true, attributes: nil)
        let data = try JSONEncoder().encode(store)
        try data.write(to: url, options: .atomic)
    }

    private func tmuxPruneCompatWorkspaceState(workspaceId: String) throws {
        var store = loadTmuxCompatStore()
        let removedLayout = store.mainVerticalLayouts.removeValue(forKey: workspaceId) != nil
        let removedSplit = store.lastSplitSurface.removeValue(forKey: workspaceId) != nil
        if removedLayout || removedSplit {
            try saveTmuxCompatStore(store)
        }
    }

    private func tmuxCompatPaneAnchorSurfaceId(_ pane: [String: Any]) -> String? {
        if let selected = pane["selected_surface_id"] as? String, !selected.isEmpty {
            return selected
        }
        let surfaceIds = pane["surface_ids"] as? [String] ?? []
        return surfaceIds.first
    }

    private func tmuxCompatPanePixelFrame(_ pane: [String: Any]) -> (x: Double, y: Double)? {
        guard let frame = pane["pixel_frame"] as? [String: Any],
              let x = doubleFromAny(frame["x"]),
              let y = doubleFromAny(frame["y"]) else {
            return nil
        }
        return (x, y)
    }

    private func tmuxReplacementColumnSurfaceId(
        workspaceId: String,
        layout: MainVerticalState,
        client: SocketClient
    ) -> String? {
        guard let payload = try? client.sendV2(method: "pane.list", params: ["workspace_id": workspaceId]) else {
            return nil
        }
        let panes = payload["panes"] as? [[String: Any]] ?? []
        guard !panes.isEmpty else { return nil }

        guard let mainPane = panes.first(where: { pane in
            let surfaceIds = pane["surface_ids"] as? [String] ?? []
            if surfaceIds.contains(layout.mainSurfaceId) {
                return true
            }
            return (pane["selected_surface_id"] as? String) == layout.mainSurfaceId
        }) else {
            return nil
        }

        let mainPaneId = mainPane["id"] as? String
        let nonMainPanes = panes.filter { ($0["id"] as? String) != mainPaneId }
        guard !nonMainPanes.isEmpty else { return nil }

        let candidatePanes: [[String: Any]]
        if let mainFrame = tmuxCompatPanePixelFrame(mainPane) {
            let rightColumn = nonMainPanes.filter { pane in
                guard let frame = tmuxCompatPanePixelFrame(pane) else { return false }
                return frame.x > mainFrame.x + 0.5
            }
            candidatePanes = rightColumn.isEmpty ? nonMainPanes : rightColumn
        } else {
            candidatePanes = nonMainPanes
        }

        let bottomMostPane = candidatePanes.max { lhs, rhs in
            let lhsFrame = tmuxCompatPanePixelFrame(lhs)
            let rhsFrame = tmuxCompatPanePixelFrame(rhs)
            switch (lhsFrame, rhsFrame) {
            case let (.some(lhsFrame), .some(rhsFrame)):
                if lhsFrame.y == rhsFrame.y {
                    return lhsFrame.x < rhsFrame.x
                }
                return lhsFrame.y < rhsFrame.y
            case (.none, .some):
                return true
            case (.some, .none):
                return false
            case (.none, .none):
                return false
            }
        }

        return bottomMostPane.flatMap { tmuxCompatPaneAnchorSurfaceId($0) }
    }

    private func tmuxPruneCompatSurfaceState(
        workspaceId: String,
        surfaceId: String,
        client: SocketClient
    ) throws {
        var store = loadTmuxCompatStore()
        var changed = false

        if store.lastSplitSurface[workspaceId] == surfaceId {
            store.lastSplitSurface.removeValue(forKey: workspaceId)
            changed = true
        }

        if let layout = store.mainVerticalLayouts[workspaceId] {
            if layout.mainSurfaceId == surfaceId {
                store.mainVerticalLayouts.removeValue(forKey: workspaceId)
                store.lastSplitSurface.removeValue(forKey: workspaceId)
                changed = true
            } else if layout.lastColumnSurfaceId == surfaceId {
                var updatedLayout = layout
                let replacementSurfaceId = tmuxReplacementColumnSurfaceId(
                    workspaceId: workspaceId,
                    layout: layout,
                    client: client
                )
                updatedLayout.lastColumnSurfaceId = replacementSurfaceId
                store.mainVerticalLayouts[workspaceId] = updatedLayout
                if let replacementSurfaceId {
                    store.lastSplitSurface[workspaceId] = replacementSurfaceId
                } else {
                    store.lastSplitSurface.removeValue(forKey: workspaceId)
                }
                changed = true
            }
        }

        if changed {
            try saveTmuxCompatStore(store)
        }
    }

    private func runShellCommand(_ command: String, stdinText: String) throws -> (status: Int32, stdout: String, stderr: String) {
        let process = Process()
        process.executableURL = URL(fileURLWithPath: "/bin/zsh")
        process.arguments = ["-lc", command]

        let stdinPipe = Pipe()
        let stdoutPipe = Pipe()
        let stderrPipe = Pipe()
        process.standardInput = stdinPipe
        process.standardOutput = stdoutPipe
        process.standardError = stderrPipe

        try cliRunProcess(process)
        if let data = stdinText.data(using: .utf8) {
            _ = cliWrite(data, to: stdinPipe.fileHandleForWriting, onBrokenPipe: .ignore)
        }
        try? stdinPipe.fileHandleForWriting.close()
        process.waitUntilExit()

        let stdoutData = stdoutPipe.fileHandleForReading.readDataToEndOfFileOrEmpty()
        let stderrData = stderrPipe.fileHandleForReading.readDataToEndOfFileOrEmpty()
        let stdout = String(data: stdoutData, encoding: .utf8) ?? ""
        let stderr = String(data: stderrData, encoding: .utf8) ?? ""
        return (process.terminationStatus, stdout, stderr)
    }

    private func tmuxWaitForSignalURL(name: String) -> URL {
        let allowed = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "._-"))
        let sanitized = name.unicodeScalars.map { allowed.contains($0) ? Character($0) : "_" }
        return URL(fileURLWithPath: "/tmp/cmux-wait-for-\(String(sanitized)).sig")
    }

    private func runTmuxCompatCommand(
        command: String,
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool,
        idFormat: CLIIDFormat,
        windowOverride: String?
    ) throws {
        switch command {
        case "capture-pane":
            let (wsArg, rem0) = parseOption(commandArgs, name: "--workspace")
            let (sfArg, rem1) = parseOption(rem0, name: "--surface")
            let (windowOpt, rem2) = parseOption(rem1, name: "--window")
            let (linesArg, rem3) = parseOption(rem2, name: "--lines")
            let windowRaw = windowOpt ?? windowOverride
            let workspaceArg = wsArg ?? Self.callerWorkspaceForSurfaceHandle(sfArg, windowRaw: windowRaw)
            let surfaceArg = sfArg ?? (wsArg == nil && windowRaw == nil ? ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"] : nil)

            var params: [String: Any] = [:]
            let winId = try normalizeWindowHandle(windowRaw, client: client)
            if let winId { params["window_id"] = winId }
            let wsId = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId)
            if let wsId { params["workspace_id"] = wsId }
            let sfId = try normalizeSurfaceHandle(surfaceArg, client: client, workspaceHandle: wsId, windowHandle: winId)
            if let sfId { params["surface_id"] = sfId }

            let includeScrollback = rem3.contains("--scrollback")
            if includeScrollback {
                params["scrollback"] = true
            }
            if let linesArg {
                guard let lineCount = Int(linesArg), lineCount > 0 else {
                    throw CLIError(message: "--lines must be greater than 0")
                }
                params["lines"] = lineCount
                params["scrollback"] = true
            }

            let payload = try client.sendV2(method: "surface.read_text", params: params)
            if jsonOutput {
                print(jsonString(payload))
            } else {
                print((payload["text"] as? String) ?? "")
            }

        case "resize-pane":
            let workspaceArg = workspaceFromArgsOrEnv(commandArgs, windowOverride: windowOverride)
            let paneArg = optionValue(commandArgs, name: "--pane")
            let amountArg = optionValue(commandArgs, name: "--amount")
            let amount = Int(amountArg ?? "1") ?? 1
            if amount <= 0 {
                throw CLIError(message: "--amount must be greater than 0")
            }

            let direction: String = {
                if commandArgs.contains("-L") { return "left" }
                if commandArgs.contains("-R") { return "right" }
                if commandArgs.contains("-U") { return "up" }
                if commandArgs.contains("-D") { return "down" }
                return "right"
            }()

            var params: [String: Any] = ["direction": direction, "amount": amount]
            let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
            if let winId { params["window_id"] = winId }
            let wsId = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId)
            if let wsId { params["workspace_id"] = wsId }
            let paneId = try normalizePaneHandle(paneArg, client: client, workspaceHandle: wsId, windowHandle: winId, allowFocused: true)
            if let paneId { params["pane_id"] = paneId }
            let payload = try client.sendV2(method: "pane.resize", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["pane"]))

        case "pipe-pane":
            let (workspaceOpt, pipeRem0) = parseOption(commandArgs, name: "--workspace")
            let (surfaceArg, pipeRem1) = parseOption(pipeRem0, name: "--surface")
            let (windowOpt, pipeRem2) = parseOption(pipeRem1, name: "--window")
            let (cmdOpt, pipeRem3) = parseOption(pipeRem2, name: "--command")
            let effectiveWindowRaw = windowOpt ?? windowOverride
            let workspaceArg = workspaceOpt ?? Self.callerWorkspaceForSurfaceHandle(surfaceArg, windowRaw: effectiveWindowRaw)
            let commandText: String = {
                if let cmdOpt { return cmdOpt }
                let trimmed = pipeRem3.dropFirst(pipeRem3.first == "--" ? 1 : 0).joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
                return trimmed
            }()
            guard !commandText.isEmpty else {
                throw CLIError(message: "pipe-pane requires --command <shell-command>")
            }
            var params: [String: Any] = ["scrollback": true]
            let winId = try normalizeWindowHandle(effectiveWindowRaw, client: client)
            if let winId { params["window_id"] = winId }
            let allowCurrentWorkspace = winId == nil && (surfaceArg.map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }.map { $0.isEmpty || Int($0) != nil } ?? true)
            let wsId = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId, allowCurrent: allowCurrentWorkspace)
            if let wsId { params["workspace_id"] = wsId }
            let sfId = try normalizeSurfaceHandle(surfaceArg, client: client, workspaceHandle: wsId, windowHandle: winId, allowFocused: true)
            if let sfId { params["surface_id"] = sfId }
            let payload = try client.sendV2(method: "surface.read_text", params: params)
            let text = (payload["text"] as? String) ?? ""
            let shell = try runShellCommand(commandText, stdinText: text)
            if shell.status != 0 {
                throw CLIError(message: "pipe-pane command failed (\(shell.status)): \(shell.stderr)")
            }
            if jsonOutput {
                print(jsonString([
                    "ok": true,
                    "status": shell.status,
                    "stdout": shell.stdout,
                    "stderr": shell.stderr
                ]))
            } else {
                if !shell.stdout.isEmpty {
                    print(shell.stdout, terminator: "")
                }
                print("OK")
            }

        case "wait-for":
            let signal = commandArgs.contains("-S") || commandArgs.contains("--signal")
            let timeoutRaw = optionValue(commandArgs, name: "--timeout")
            let timeout = timeoutRaw.flatMap { Double($0) } ?? 30.0
            let name = commandArgs.first(where: { !$0.hasPrefix("-") }) ?? ""
            guard !name.isEmpty else {
                throw CLIError(message: "wait-for requires a name")
            }
            let signalURL = tmuxWaitForSignalURL(name: name)
            if signal {
                FileManager.default.createFile(atPath: signalURL.path, contents: Data())
                print("OK")
                return
            }
            let deadline = Date().addingTimeInterval(timeout)
            do {
                try SocketClient.waitForFilesystemPath(signalURL.path, timeout: max(0, deadline.timeIntervalSinceNow))
                try? FileManager.default.removeItem(at: signalURL)
                print("OK")
                return
            } catch {
                if FileManager.default.fileExists(atPath: signalURL.path) {
                    try? FileManager.default.removeItem(at: signalURL)
                    print("OK")
                    return
                }
            }
            throw CLIError(message: "wait-for timed out waiting for '\(name)'")

        case "swap-pane":
            let workspaceArg = workspaceFromArgsOrEnv(commandArgs, windowOverride: windowOverride)
            guard let sourcePaneRaw = optionValue(commandArgs, name: "--pane") else {
                throw CLIError(message: "swap-pane requires --pane")
            }
            guard let targetPaneRaw = optionValue(commandArgs, name: "--target-pane") else {
                throw CLIError(message: "swap-pane requires --target-pane")
            }
            let focusRaw = optionValue(commandArgs, name: "--focus")
            var params: [String: Any] = [:]
            let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
            if let winId { params["window_id"] = winId }
            let wsId = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId)
            if let wsId { params["workspace_id"] = wsId }
            let sourcePane = try normalizePaneHandle(sourcePaneRaw, client: client, workspaceHandle: wsId, windowHandle: winId)
            let targetPane = try normalizePaneHandle(targetPaneRaw, client: client, workspaceHandle: wsId, windowHandle: winId)
            if let sourcePane { params["pane_id"] = sourcePane }
            if let targetPane { params["target_pane_id"] = targetPane }
            try applyFocusOption(focusRaw, defaultValue: false, to: &params)
            let payload = try client.sendV2(method: "pane.swap", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: "OK")

        case "break-pane":
            let workspaceArg = workspaceFromArgsOrEnv(commandArgs, windowOverride: windowOverride)
            let paneArg = optionValue(commandArgs, name: "--pane")
            let surfaceArg = optionValue(commandArgs, name: "--surface")
            let focusRaw = optionValue(commandArgs, name: "--focus")
            try rejectConflictingFocusFlags(commandArgs)
            var params: [String: Any] = [:]
            try applyFocusOption(focusRaw, defaultValue: false, to: &params)
            if commandArgs.contains("--no-focus") {
                params["focus"] = false
            }
            let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
            if let winId { params["window_id"] = winId }
            let wsId = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId)
            if let wsId { params["workspace_id"] = wsId }
            let paneId = try normalizePaneHandle(paneArg, client: client, workspaceHandle: wsId, windowHandle: winId)
            if let paneId { params["pane_id"] = paneId }
            let surfaceId = try normalizeSurfaceHandle(surfaceArg, client: client, workspaceHandle: wsId, windowHandle: winId)
            if let surfaceId { params["surface_id"] = surfaceId }
            let payload = try client.sendV2(method: "pane.break", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: "OK")

        case "join-pane":
            let workspaceArg = workspaceFromArgsOrEnv(commandArgs, windowOverride: windowOverride)
            let sourcePaneArg = optionValue(commandArgs, name: "--pane")
            let surfaceArg = optionValue(commandArgs, name: "--surface")
            guard let targetPaneArg = optionValue(commandArgs, name: "--target-pane") else {
                throw CLIError(message: "join-pane requires --target-pane")
            }
            let focusRaw = optionValue(commandArgs, name: "--focus")
            try rejectConflictingFocusFlags(commandArgs)
            var params: [String: Any] = [:]
            try applyFocusOption(focusRaw, defaultValue: false, to: &params)
            if commandArgs.contains("--no-focus") {
                params["focus"] = false
            }
            let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
            if let winId { params["window_id"] = winId }
            let wsId = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId)
            if let wsId { params["workspace_id"] = wsId }
            let sourcePaneId = try normalizePaneHandle(sourcePaneArg, client: client, workspaceHandle: wsId, windowHandle: winId)
            if let sourcePaneId { params["pane_id"] = sourcePaneId }
            let targetPaneId = try normalizePaneHandle(targetPaneArg, client: client, workspaceHandle: wsId, windowHandle: winId)
            if let targetPaneId { params["target_pane_id"] = targetPaneId }
            let surfaceId = try normalizeSurfaceHandle(surfaceArg, client: client, workspaceHandle: wsId, windowHandle: winId)
            if let surfaceId { params["surface_id"] = surfaceId }
            let payload = try client.sendV2(method: "pane.join", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: "OK")

        case "last-window":
            var params: [String: Any] = [:]
            if let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client) {
                params["window_id"] = winId
            }
            let payload = try client.sendV2(method: "workspace.last", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["workspace"]))

        case "next-window":
            var params: [String: Any] = [:]
            if let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client) {
                params["window_id"] = winId
            }
            let payload = try client.sendV2(method: "workspace.next", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["workspace"]))

        case "previous-window":
            var params: [String: Any] = [:]
            if let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client) {
                params["window_id"] = winId
            }
            let payload = try client.sendV2(method: "workspace.previous", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["workspace"]))

        case "last-pane":
            let workspaceArg = workspaceFromArgsOrEnv(commandArgs, windowOverride: windowOverride)
            var params: [String: Any] = [:]
            let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
            if let winId { params["window_id"] = winId }
            let wsId = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId)
            if let wsId { params["workspace_id"] = wsId }
            let payload = try client.sendV2(method: "pane.last", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat, kinds: ["pane"]))

        case "find-window":
            let includeContent = commandArgs.contains("--content")
            let shouldSelect = commandArgs.contains("--select")
            let (windowOpt, queryArgs) = parseOption(commandArgs, name: "--window")
            let query = queryArgs
                .filter { !$0.hasPrefix("-") }
                .joined(separator: " ")
                .trimmingCharacters(in: .whitespacesAndNewlines)

            var listParams: [String: Any] = [:]
            if let winId = try normalizeWindowHandle(windowOpt ?? windowOverride, client: client) {
                listParams["window_id"] = winId
            }
            let listPayload = try client.sendV2(method: "workspace.list", params: listParams)
            let workspaces = listPayload["workspaces"] as? [[String: Any]] ?? []

            var matches: [[String: Any]] = []
            for ws in workspaces {
                let title = (ws["title"] as? String) ?? ""
                let titleMatch = query.isEmpty || title.localizedCaseInsensitiveContains(query)
                var contentMatch = false
                if includeContent && !query.isEmpty, let wsId = ws["id"] as? String {
                    let textPayload = try? client.sendV2(method: "surface.read_text", params: ["workspace_id": wsId])
                    let text = (textPayload?["text"] as? String) ?? ""
                    contentMatch = text.localizedCaseInsensitiveContains(query)
                }
                if titleMatch || contentMatch {
                    matches.append(ws)
                }
            }

            if shouldSelect, let first = matches.first, let wsId = first["id"] as? String {
                var selectParams: [String: Any] = ["workspace_id": wsId]
                if let windowId = listParams["window_id"] {
                    selectParams["window_id"] = windowId
                }
                _ = try client.sendV2(method: "workspace.select", params: selectParams)
            }

            if jsonOutput {
                let formatted = formatIDs(["matches": matches], mode: idFormat) as? [String: Any]
                print(jsonString(["matches": formatted?["matches"] ?? []]))
            } else if matches.isEmpty {
                print("No matches")
            } else {
                for item in matches {
                    let handle = textHandle(item, idFormat: idFormat)
                    let title = (item["title"] as? String) ?? ""
                    print("\(handle)  \"\(title)\"")
                }
            }

        case "clear-history":
            let workspaceArg = workspaceFromArgsOrEnv(commandArgs, windowOverride: windowOverride)
            let surfaceArg = optionValue(commandArgs, name: "--surface")
            var params: [String: Any] = [:]
            let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
            if let winId { params["window_id"] = winId }
            let wsId = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId)
            if let wsId { params["workspace_id"] = wsId }
            let sfId = try normalizeSurfaceHandle(surfaceArg, client: client, workspaceHandle: wsId, windowHandle: winId, allowFocused: true)
            if let sfId { params["surface_id"] = sfId }
            let payload = try client.sendV2(method: "surface.clear_history", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: v2OKSummary(payload, idFormat: idFormat))

        case "set-hook":
            var store = loadTmuxCompatStore()
            if commandArgs.contains("--list") {
                if jsonOutput {
                    print(jsonString(["hooks": store.hooks]))
                } else if store.hooks.isEmpty {
                    print("No hooks configured")
                } else {
                    for (event, hookCmd) in store.hooks.sorted(by: { $0.key < $1.key }) {
                        print("\(event) -> \(hookCmd)")
                    }
                }
                return
            }
            if commandArgs.contains("--unset") {
                guard let event = commandArgs.last else {
                    throw CLIError(message: "set-hook --unset requires an event name")
                }
                store.hooks.removeValue(forKey: event)
                try saveTmuxCompatStore(store)
                print("OK")
                return
            }
            guard let event = commandArgs.first(where: { !$0.hasPrefix("-") }) else {
                throw CLIError(message: "set-hook requires <event> <command>")
            }
            let commandText = commandArgs.drop(while: { $0 != event }).dropFirst().joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
            guard !commandText.isEmpty else {
                throw CLIError(message: "set-hook requires <event> <command>")
            }
            store.hooks[event] = commandText
            try saveTmuxCompatStore(store)
            print("OK")

        case "popup":
            throw CLIError(message: "popup is not supported yet in cmux CLI parity mode")

        case "bind-key", "unbind-key", "copy-mode":
            throw CLIError(message: "\(command) is not supported yet in cmux CLI parity mode")

        case "set-buffer":
            let (nameArg, rem0) = parseOption(commandArgs, name: "--name")
            let name = (nameArg?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false) ? nameArg! : "default"
            let content = rem0.dropFirst(rem0.first == "--" ? 1 : 0).joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
            guard !content.isEmpty else {
                throw CLIError(message: "set-buffer requires text")
            }
            var store = loadTmuxCompatStore()
            store.buffers[name] = content
            try saveTmuxCompatStore(store)
            print("OK")

        case "list-buffers":
            let store = loadTmuxCompatStore()
            if jsonOutput {
                let payload = store.buffers.map { key, value in ["name": key, "size": value.count] }
                print(jsonString(["buffers": payload.sorted { ($0["name"] as? String ?? "") < ($1["name"] as? String ?? "") }]))
            } else if store.buffers.isEmpty {
                print("No buffers")
            } else {
                for key in store.buffers.keys.sorted() {
                    let size = store.buffers[key]?.count ?? 0
                    print("\(key)\t\(size)")
                }
            }

        case "paste-buffer":
            let workspaceArg = workspaceFromArgsOrEnv(commandArgs, windowOverride: windowOverride)
            let surfaceArg = optionValue(commandArgs, name: "--surface")
            let name = optionValue(commandArgs, name: "--name") ?? "default"
            let store = loadTmuxCompatStore()
            guard let buffer = store.buffers[name] else {
                throw CLIError(message: "Buffer not found: \(name)")
            }
            var params: [String: Any] = ["text": buffer]
            let winId = try normalizeWindowHandle(windowFromArgsOrOverride(commandArgs, windowOverride: windowOverride), client: client)
            if let winId { params["window_id"] = winId }
            let wsId = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId, allowCurrent: winId == nil)
            if let wsId { params["workspace_id"] = wsId }
            let sfId = try normalizeSurfaceHandle(surfaceArg, client: client, workspaceHandle: wsId, windowHandle: winId, allowFocused: true)
            if let sfId { params["surface_id"] = sfId }
            let payload = try client.sendV2(method: "surface.send_text", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: "OK")

        case "respawn-pane":
            let (workspaceOpt, respawnRem0) = parseOption(commandArgs, name: "--workspace")
            let (surfaceArg, respawnRem1) = parseOption(respawnRem0, name: "--surface")
            let (windowOpt, respawnRem2) = parseOption(respawnRem1, name: "--window")
            let (commandOpt, respawnRem3) = parseOption(respawnRem2, name: "--command")
            let effectiveWindowRaw = windowOpt ?? windowOverride
            let workspaceArg = workspaceOpt ?? (effectiveWindowRaw == nil ? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"] : nil)
            let commandText = (commandOpt ?? respawnRem3.dropFirst(respawnRem3.first == "--" ? 1 : 0).joined(separator: " ")).trimmingCharacters(in: .whitespacesAndNewlines)
            let finalCommand = commandText.isEmpty ? "exec ${SHELL:-/bin/zsh} -l" : commandText
            var params: [String: Any] = [
                "command": tmuxShellInvokedStartCommand(finalCommand),
                "tmux_start_command": finalCommand
            ]
            let winId = try normalizeWindowHandle(effectiveWindowRaw, client: client)
            if let winId { params["window_id"] = winId }
            let wsHandle = try normalizeWorkspaceHandle(workspaceArg, client: client, windowHandle: winId, allowCurrent: winId == nil)
            let wsId = try wsHandle.map { try resolveWorkspaceId($0, client: client, windowHandle: winId) }
            if let wsId { params["workspace_id"] = wsId }
            let sfHandle = try normalizeSurfaceHandle(surfaceArg, client: client, workspaceHandle: wsId, windowHandle: winId, allowFocused: true)
            if let sfHandle {
                if let wsId {
                    params["surface_id"] = try resolveSurfaceId(sfHandle, workspaceId: wsId, client: client)
                } else {
                    params["surface_id"] = sfHandle
                }
            }
            let payload = try client.sendV2(method: "surface.respawn", params: params)
            printV2Payload(payload, jsonOutput: jsonOutput, idFormat: idFormat, fallbackText: "OK")

        case "display-message":
            let printOnly = commandArgs.contains("-p") || commandArgs.contains("--print")
            let message = commandArgs
                .filter { !$0.hasPrefix("-") }
                .joined(separator: " ")
                .trimmingCharacters(in: .whitespacesAndNewlines)
            guard !message.isEmpty else {
                throw CLIError(message: "display-message requires text")
            }
            if printOnly {
                print(message)
                return
            }
            let payload = try client.sendV2(method: "notification.create", params: ["title": "cmux", "body": message])
            if jsonOutput {
                print(jsonString(payload))
            } else {
                print(message)
            }

        default:
            throw CLIError(message: "Unsupported tmux compatibility command: \(command)")
        }
    }

    private func runClaudeHook(
        commandArgs: [String],
        client: SocketClient,
        telemetry: CLISocketSentryTelemetry,
        socketPassword: String? = nil
    ) throws {
        let subcommand = commandArgs.first?.lowercased() ?? "help"
        let hookArgs = Array(commandArgs.dropFirst())
        let hookWsFlag = optionValue(hookArgs, name: "--workspace")
        let workspaceArg = hookWsFlag ?? ProcessInfo.processInfo.environment["CMUX_WORKSPACE_ID"]
        let hookSurfaceFlag = optionValue(hookArgs, name: "--surface")
        let surfaceArg = hookSurfaceFlag ?? (hookWsFlag == nil ? ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"] : nil)
        let preferCallerTTYRouting = hookWsFlag == nil && hookSurfaceFlag == nil
        var callerTTYBindingCache: CallerTerminalBinding?
        var didResolveCallerTTYBinding = false
        func callerTTYBinding() -> CallerTerminalBinding? {
            if !didResolveCallerTTYBinding {
                didResolveCallerTTYBinding = true
                let ttyBinding = uniqueCallerTerminalBindingByTTY(
                    client: client,
                    includeAmbientTTY: workspaceArg == nil && surfaceArg == nil
                )
                if let ttyBinding,
                   claudeHookSurfaceIsListed(ttyBinding.surfaceId, workspaceId: ttyBinding.workspaceId, client: client) {
                    callerTTYBindingCache = ttyBinding
                } else {
                    let processBinding = resolveAgentProcessTerminalBinding(
                        pid: claudeAgentPID(from: ProcessInfo.processInfo.environment),
                        socketPath: client.socketPath,
                        socketPassword: socketPassword
                    )
                    if let processBinding,
                       claudeHookSurfaceIsListed(
                           processBinding.surfaceId,
                           workspaceId: processBinding.workspaceId,
                           client: client
                       ) {
                        callerTTYBindingCache = processBinding
                    }
                }
            }
            return callerTTYBindingCache
        }
        let callerTTYBindingProvider: (() -> CallerTerminalBinding?)? = preferCallerTTYRouting ? callerTTYBinding : nil
        let hookRouting = ClaudeHookRoutingContext(
            workspaceArg: workspaceArg,
            surfaceArg: surfaceArg,
            surfaceFlagIsExplicit: hookSurfaceFlag != nil,
            preferCallerTTYRouting: preferCallerTTYRouting,
            callerTerminalBinding: callerTTYBindingProvider,
            agentPid: claudeAgentPID(from: ProcessInfo.processInfo.environment)
        )
        let rawInput = String(data: FileHandle.standardInput.readDataToEndOfFile(), encoding: .utf8) ?? ""
        let parsedInput = parseClaudeHookInput(rawInput: rawInput)
        let sessionStore = ClaudeHookSessionStore()
        // Record the hook-observed permission mode (shift+tab auto-accept, plan
        // mode, bypass toggle): it is runtime state that never appears in the
        // captured launch argv, and session restore re-applies it as
        // `--permission-mode`. Read from rawObject — the compacted hook object
        // keeps only an allowlist of keys and does not retain permission_mode.
        // https://github.com/manaflow-ai/cmux/issues/8066
        let observedHookPermissionMode = (parsedInput.rawObject?["permission_mode"] as? String)
            ?? (parsedInput.rawObject?["permissionMode"] as? String)
        if let hookSessionId = parsedInput.sessionId,
           let observedHookPermissionMode {
            try? sessionStore.updateLastPermissionMode(
                sessionId: hookSessionId,
                permissionMode: observedHookPermissionMode
            )
        }
        telemetry.breadcrumb(
            "claude-hook.input",
            data: [
                "subcommand": subcommand,
                "has_session_id": parsedInput.sessionId != nil,
                "has_workspace_flag": hookWsFlag != nil,
                "has_surface_flag": optionValue(hookArgs, name: "--surface") != nil
            ]
        )
        var didSendFeedTelemetry = false
        func sendClaudeFeedTelemetry(workspaceId: String? = nil, surfaceId: String? = nil) {
            didSendFeedTelemetry = true
            sendFeedTelemetry(
                client: client,
                source: "claude",
                subcommand: subcommand,
                parsedInput: parsedInput,
                workspaceId: workspaceId ?? workspaceArg, surfaceId: surfaceId,
                socketPassword: socketPassword
            )
        }
        defer {
            if !didSendFeedTelemetry {
                sendClaudeFeedTelemetry()
            }
        }

        switch subcommand {
        case "session-start", "active":
            telemetry.breadcrumb("claude-hook.session-start")
            guard let resolvedTarget = try resolveClaudeHookDeliveryTarget(
                mappedSession: nil,
                routing: hookRouting,
                client: client
            ) else {
                didSendFeedTelemetry = true
                telemetry.breadcrumb("claude-hook.session-start.unresolved")
                printClaudeHookAck()
                return
            }
            let workspaceId = resolvedTarget.workspaceId
            let resolvedSurface = resolvedTarget
            let surfaceId = resolvedSurface.surfaceId
            sendClaudeFeedTelemetry(workspaceId: workspaceId, surfaceId: surfaceId)
            let claudePid = claudeAgentPID(from: ProcessInfo.processInfo.environment)
            let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(
                currentAgentPID: claudePid,
                env: ProcessInfo.processInfo.environment
            )
            let launchCommand = agentLaunchCommandFromEnvironment(
                ProcessInfo.processInfo.environment,
                fallbackPID: claudePid,
                fallbackKind: "claude",
                cwd: parsedInput.cwd
            )
            // `claude --resume <parent> --fork-session` fires SessionStart with the
            // PARENT session id — the forked session id is only minted at the first
            // UserPromptSubmit. Upserting here would steal the parent record's
            // surface/pid/launch command from the pane that still owns that
            // conversation, so fork launches leave the store untouched; the forked
            // session is recorded once its own id appears on prompt-submit.
            // https://github.com/manaflow-ai/cmux/issues/5908
            let isForkSessionLaunch = isClaudeForkSessionLaunch(
                env: ProcessInfo.processInfo.environment,
                fallbackPID: claudePid
            )
            let isClearSessionStart = isClaudeClearSessionStart(parsedInput)
            let canReplaceStoppedSession = shouldReplaceStoppedClaudeSession(
                sessionStore: sessionStore,
                parsedInput: parsedInput,
                workspaceId: workspaceId,
                surfaceId: resolvedSurface.isAuthoritative ? surfaceId : nil,
                telemetry: telemetry
            )
            let shouldPromoteActiveSession = !isForkSessionLaunch && (isClearSessionStart || canReplaceStoppedSession)
            if let sessionId = parsedInput.sessionId, !isForkSessionLaunch {
                // Non-clear SessionStart can arrive late from startup/resume/compact
                // after /clear, so only /clear or replacement of a stopped owner
                // establishes a new active boundary.
                try? sessionStore.upsert(
                    sessionId: sessionId,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    cwd: parsedInput.cwd,
                    transcriptPath: parsedInput.transcriptPath,
                    pid: claudePid,
                    launchCommand: launchCommand,
                    isRestorable: false,
                    agentLifecycle: shouldPromoteActiveSession ? .running : .unknown,
                    markActive: shouldPromoteActiveSession,
                    turnId: parsedInput.turnId
                )
                if shouldPromoteActiveSession {
                    publishAgentSurfaceResumeBinding(
                        client: client,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        kind: "claude",
                        displayName: String(localized: "cli.claude-hook.notification.title", defaultValue: "Claude Code"),
                        sessionId: sessionId,
                        cwd: parsedInput.cwd,
                        launchCommand: launchCommand,
                        observedPermissionMode: observedHookPermissionMode
                    )
                }
            }
            // Register PID for stale-session detection and OSC suppression.
            // Startup/resume SessionStart remains non-visible; /clear is a
            // new active boundary and must keep the sidebar Running before
            // any late pre-clear Stop can write Idle.
            // Fork launches register their PID only with an authoritative
            // surface: the hook reports the PARENT session id (which is often
            // the workspace-active session), and the pre-prompt fork SessionEnd
            // cleanup clears only authoritative targets, so a fallback-pane
            // registration would leave a stale agent PID on a pane the fork
            // never owned.
            let shouldRegisterPID = isForkSessionLaunch
                ? resolvedSurface.isAuthoritative
                : shouldPromoteActiveSession ||
                    shouldApplyClaudeHookVisibleMutation(
                        sessionStore: sessionStore,
                        parsedInput: parsedInput,
                        workspaceId: workspaceId,
                        surfaceId: resolvedSurface.isAuthoritative ? surfaceId : nil,
                        telemetry: telemetry
                    )
            if shouldRegisterPID, let claudePid, !suppressVisibleMutations {
                _ = try? sendV1Command(
                    "set_agent_pid \(Self.claudeCodeStatusKey) \(claudePid) --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
            }
            if isClearSessionStart, !suppressVisibleMutations {
                _ = try? sendV1Command("clear_notifications --tab=\(workspaceId)\(socketPanelOption(surfaceId))", client: client)
                setAgentLifecycle(
                    client: client,
                    key: Self.claudeCodeStatusKey,
                    lifecycle: .running,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId
                )
                try setClaudeStatus(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    value: "Running",
                    icon: "bolt.fill",
                    color: "#4C8DFF",
                    pid: claudePid
                )
            }
            printClaudeHookAck()

        case "stop", "idle":
            telemetry.breadcrumb("claude-hook.stop")
            do {
                // Turn ended. Don't consume session or clear PID — Claude is still alive.
                // Notification hook handles user-facing notifications; SessionEnd handles cleanup.
                let mappedSession = parsedInput.sessionId.flatMap { try? sessionStore.lookup(sessionId: $0) }
                guard let resolvedTarget = try resolveClaudeHookDeliveryTarget(
                    mappedSession: mappedSession,
                    routing: hookRouting,
                    client: client
                ) else {
                    didSendFeedTelemetry = true
                    telemetry.breadcrumb("claude-hook.stop.unresolved")
                    printClaudeHookAck()
                    return
                }
                let workspaceId = resolvedTarget.workspaceId
                let resolvedSurface = resolvedTarget
                let surfaceId = resolvedSurface.surfaceId
                let claudePid = mappedSession?.pid ?? claudeAgentPID(from: ProcessInfo.processInfo.environment)
                let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(
                    currentAgentPID: claudePid,
                    env: ProcessInfo.processInfo.environment
                )
                sendClaudeFeedTelemetry(workspaceId: workspaceId, surfaceId: surfaceId)

                guard shouldApplyClaudeHookVisibleMutation(
                    sessionStore: sessionStore,
                    parsedInput: parsedInput,
                    workspaceId: workspaceId,
                    surfaceId: resolvedSurface.isAuthoritative ? surfaceId : nil,
                    telemetry: telemetry
                ) else {
                    telemetry.breadcrumb("claude-hook.stop.stale")
                    printClaudeHookAck()
                    return
                }

                guard !suppressVisibleMutations else {
                    telemetry.breadcrumb("claude-hook.stop.nested-suppressed")
                    printClaudeHookAck()
                    return
                }

                // Whether this turn ended with unfinished background work (a running
                // background task or a pending cron). Cached on the session record so
                // the ~60s-later idle_prompt Notification can consult it, and forwarded
                // to the app so it can suppress the done-ping until work truly drains.
                let hasPendingBackgroundWork = hasActiveClaudeBackgroundWork(parsedInput)

                // Update session with transcript summary and send completion notification.
                let completion = summarizeClaudeHookStop(
                    parsedInput: parsedInput,
                    sessionRecord: mappedSession
                )
                if let sessionId = parsedInput.sessionId {
                    try? sessionStore.upsert(
                        sessionId: sessionId,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        cwd: parsedInput.cwd,
                        transcriptPath: parsedInput.transcriptPath,
                        isRestorable: true,
                        // Pending background work keeps the pane out of the
                        // hibernatable .idle state so the planner cannot SIGTERM
                        // a live task (mirrors the antigravity fullyIdle flip).
                        agentLifecycle: hasPendingBackgroundWork ? .running : .idle,
                        lastSubtitle: completion?.subtitle,
                        lastBody: completion?.body,
                        hadPendingBackgroundWorkAtStop: hasPendingBackgroundWork,
                        markActive: true,
                        allowsNewSessionReplacement: true
                    )
                    publishAgentSurfaceResumeBinding(
                        client: client,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        kind: "claude",
                        displayName: String(localized: "cli.claude-hook.notification.title", defaultValue: "Claude Code"),
                        sessionId: sessionId,
                        cwd: parsedInput.cwd ?? mappedSession?.cwd,
                        launchCommand: mappedSession?.launchCommand,
                        observedPermissionMode: observedHookPermissionMode
                            ?? mappedSession?.lastPermissionMode
                    )
                }

                setAgentLifecycle(
                    client: client,
                    key: Self.claudeCodeStatusKey,
                    lifecycle: hasPendingBackgroundWork ? .running : .idle,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId
                )
                if hasPendingBackgroundWork {
                    // The turn ended but a background task or scheduled wakeup is
                    // still live, so the pane is not idle — show it as still
                    // running rather than the misleading "Idle". Reuse the shared
                    // generic-agent status strings so the pill stays localized.
                    try? setClaudeStatus(
                        client: client,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        value: String(localized: "agent.generic.status.running", defaultValue: "Running"),
                        icon: "bolt.fill",
                        color: "#4C8DFF"
                    )
                } else {
                    try? setClaudeStatus(
                        client: client,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        value: String(localized: "agent.generic.notification.status.idle", defaultValue: "Idle"),
                        icon: "pause.circle.fill",
                        color: "#8E8E93"
                    )
                }
                if let completion {
                    let title = String(
                        localized: "cli.claude-hook.notification.title",
                        defaultValue: "Claude Code"
                    )
                    let payload = notificationPayload(
                        title: title,
                        subtitle: completion.subtitle,
                        body: completion.body,
                        meta: AgentHookNotifyCategory.turnComplete.metaSegment(pending: hasPendingBackgroundWork)
                    )
                    _ = try? sendV1Command("notify_target_async \(workspaceId) \(surfaceId) \(payload)", client: client)
                }
                printClaudeHookAck()
            } catch {
                if shouldIgnoreClaudeHookTeardownError(error) {
                    telemetry.breadcrumb("claude-hook.stop.ignored", data: ["error": String(describing: error)])
                    printClaudeHookAck()
                    return
                }
                throw error
            }

        case "prompt-submit":
            telemetry.breadcrumb("claude-hook.prompt-submit")
            let mappedSession = parsedInput.sessionId.flatMap { try? sessionStore.lookup(sessionId: $0) }
            guard let resolvedTarget = try resolveClaudeHookDeliveryTarget(
                mappedSession: mappedSession,
                routing: hookRouting,
                client: client
            ) else {
                didSendFeedTelemetry = true
                telemetry.breadcrumb("claude-hook.prompt-submit.unresolved")
                printClaudeHookAck()
                return
            }
            let workspaceId = resolvedTarget.workspaceId
            let resolvedSurface = resolvedTarget
            let surfaceId = resolvedSurface.surfaceId
            let claudePid = mappedSession?.pid ?? claudeAgentPID(from: ProcessInfo.processInfo.environment)
            let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(
                currentAgentPID: claudePid,
                env: ProcessInfo.processInfo.environment
            )
            sendClaudeFeedTelemetry(workspaceId: workspaceId, surfaceId: surfaceId)
            let shouldApplyPromptSubmit =
                shouldApplyClaudeHookVisibleMutation(
                    sessionStore: sessionStore,
                    parsedInput: parsedInput,
                    workspaceId: workspaceId,
                    surfaceId: resolvedSurface.isAuthoritative ? surfaceId : nil,
                    telemetry: telemetry
                ) ||
                shouldReplaceStoppedClaudeSession(
                    sessionStore: sessionStore,
                    parsedInput: parsedInput,
                    workspaceId: workspaceId,
                    surfaceId: resolvedSurface.isAuthoritative ? surfaceId : nil,
                    telemetry: telemetry
                )
            guard shouldApplyPromptSubmit else {
                telemetry.breadcrumb("claude-hook.prompt-submit.stale")
                printClaudeHookAck()
                return
            }
            guard !suppressVisibleMutations else {
                telemetry.breadcrumb("claude-hook.prompt-submit.nested-suppressed")
                printClaudeHookAck()
                return
            }
            if let sessionId = parsedInput.sessionId {
                // A forked session's first hook is this prompt-submit — its
                // SessionStart fired under the parent session id — so capture the
                // pane's pid and launch command here the way session-start does for
                // normal launches. Only on first sighting, so an established
                // record's richer capture is never overwritten.
                // https://github.com/manaflow-ai/cmux/issues/5908
                let firstSightingLaunchCommand = mappedSession == nil
                    ? agentLaunchCommandFromEnvironment(
                        ProcessInfo.processInfo.environment,
                        fallbackPID: claudePid,
                        fallbackKind: "claude",
                        cwd: parsedInput.cwd
                    )
                    : nil
                try? sessionStore.upsert(
                    sessionId: sessionId,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    cwd: parsedInput.cwd,
                    transcriptPath: parsedInput.transcriptPath,
                    pid: mappedSession == nil ? claudePid : nil,
                    launchCommand: firstSightingLaunchCommand,
                    isRestorable: true,
                    agentLifecycle: .running,
                    markActive: true,
                    turnId: parsedInput.turnId
                )
                publishAgentSurfaceResumeBinding(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    kind: "claude",
                    displayName: String(localized: "cli.claude-hook.notification.title", defaultValue: "Claude Code"),
                    sessionId: sessionId,
                    cwd: parsedInput.cwd ?? mappedSession?.cwd,
                    launchCommand: mappedSession?.launchCommand ?? firstSightingLaunchCommand,
                    observedPermissionMode: observedHookPermissionMode
                        ?? mappedSession?.lastPermissionMode
                )
            }
            _ = try sendV1Command("clear_notifications --tab=\(workspaceId)\(socketPanelOption(surfaceId))", client: client)
            setAgentLifecycle(
                client: client,
                key: Self.claudeCodeStatusKey,
                lifecycle: .running,
                workspaceId: workspaceId,
                surfaceId: surfaceId
            )
            try setClaudeStatus(
                client: client,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                value: "Running",
                icon: "bolt.fill",
                color: "#4C8DFF"
            )
            printClaudeHookAck()

        case "auto-name":
            telemetry.breadcrumb("claude-hook.auto-name")
            // Auto-naming emits no feed events of its own; the sync Stop hook
            // already covers turn telemetry for this turn.
            didSendFeedTelemetry = true
            do {
                let mappedSession = parsedInput.sessionId.flatMap { try? sessionStore.lookup(sessionId: $0) }
                guard let workspaceId = try resolvePreferredWorkspaceIdForClaudeHook(
                    preferred: mappedSession?.workspaceId,
                    fallback: workspaceArg,
                    preferCallerTTYOverFallback: preferCallerTTYRouting,
                    callerTerminalBinding: callerTTYBindingProvider,
                    client: client
                ) else {
                    telemetry.breadcrumb("claude-hook.auto-name.unresolved")
                    printClaudeHookAck()
                    return
                }
                let surfaceId = try resolvePreferredSurfaceIdForClaudeHook(
                    preferred: mappedSession?.surfaceId,
                    fallback: surfaceArg,
                    fallbackIsExplicit: hookSurfaceFlag != nil,
                    workspaceId: workspaceId,
                    callerTerminalBinding: callerTTYBindingProvider,
                    client: client
                )
                runClaudeAutoNameHook(
                    parsedInput: parsedInput,
                    mappedSession: mappedSession,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    sessionStore: sessionStore,
                    client: client,
                    telemetry: telemetry
                )
            } catch {
                telemetry.breadcrumb("claude-hook.auto-name.error")
            }
            printClaudeHookAck()

        case "notification", "notify":
            telemetry.breadcrumb("claude-hook.notification")
            var summary = summarizeClaudeHookNotification(parsedInput: parsedInput)
            // The classifier's subtitle is a stable internal literal ("Permission",
            // "Waiting", "Error", "Completed", "Attention" — see
            // classifyClaudeNotification). Capture it before the saved-body swap
            // below so payloads without a notification_type field (older claude
            // clients, nested payloads) can still gate under the right setting.
            let classifiedSubtitle = summary.subtitle

            let mappedSession = parsedInput.sessionId.flatMap { try? sessionStore.lookup(sessionId: $0) }
            guard let resolvedTarget = try resolveClaudeHookDeliveryTarget(
                mappedSession: mappedSession,
                routing: hookRouting,
                client: client
            ) else {
                didSendFeedTelemetry = true
                telemetry.breadcrumb("claude-hook.notification.unresolved")
                printClaudeHookAck()
                return
            }
            let workspaceId = resolvedTarget.workspaceId
            let claudePid = mappedSession?.pid ?? claudeAgentPID(from: ProcessInfo.processInfo.environment)
            let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(
                currentAgentPID: claudePid,
                env: ProcessInfo.processInfo.environment
            )
            let resolvedSurface = resolvedTarget
            let surfaceId = resolvedSurface.surfaceId
            sendClaudeFeedTelemetry(workspaceId: workspaceId, surfaceId: surfaceId)
            guard shouldApplyClaudeHookVisibleMutation(
                sessionStore: sessionStore,
                parsedInput: parsedInput,
                workspaceId: workspaceId,
                surfaceId: resolvedSurface.isAuthoritative ? surfaceId : nil,
                telemetry: telemetry
            ) else {
                telemetry.breadcrumb("claude-hook.notification.stale")
                printClaudeHookAck()
                return
            }
            guard !suppressVisibleMutations else {
                telemetry.breadcrumb("claude-hook.notification.nested-suppressed")
                printClaudeHookAck()
                return
            }
            if let mappedSession,
               let savedBody = mappedSession.lastBody, !savedBody.isEmpty,
               summary.body.contains("needs your attention") || summary.body.contains("needs your input") {
                summary = (subtitle: mappedSession.lastSubtitle ?? summary.subtitle, body: savedBody)
            }

            let title = String(
                localized: "cli.claude-hook.notification.title",
                defaultValue: "Claude Code"
            )

            // Classify the Notification so the app can gate it by user config.
            // `permission_prompt` = Claude is blocked on the user (always worth a
            // ping); `idle_prompt` = the ~60s idle nag, which fires even while a
            // background task runs — its payload lacks `background_tasks`, so read
            // the pending flag cached by the most recent Stop.
            let notificationType = parsedInput.rawObject.flatMap {
                firstString(in: $0, keys: ["notification_type"])
            }
            let notifyCategory: AgentHookNotifyCategory
            let notifyPending: Bool
            switch notificationType {
            case "permission_prompt":
                notifyCategory = .needsPermission
                notifyPending = false
            case "idle_prompt":
                notifyCategory = .idleReminder
                // The cached Stop-time flag is not stale in practice: a completed
                // background task re-invokes claude (new turn -> fresh Stop with
                // empty background_tasks refreshes the cache before any later
                // idle_prompt), and no fresh Stop means the work is still running,
                // so pending=true is correct. Deliberately no freshness heuristic;
                // permission_prompt is never gated by this flag.
                notifyPending = (mappedSession?.hadPendingBackgroundWorkAtStop == true)
            default:
                // No (or unknown) notification_type: fall back to the summarizer's
                // cue classification so older clients still gate under the right
                // setting. Unclassified alerts stay .other and always deliver.
                switch classifiedSubtitle {
                case "Permission":
                    notifyCategory = .needsPermission
                    notifyPending = false
                case "Waiting":
                    notifyCategory = .idleReminder
                    notifyPending = (mappedSession?.hadPendingBackgroundWorkAtStop == true)
                case "Completed":
                    notifyCategory = .turnComplete
                    notifyPending = (mappedSession?.hadPendingBackgroundWorkAtStop == true)
                default:
                    notifyCategory = .other
                    notifyPending = false
                }
            }

            // An idle reminder while background work is still pending is not a
            // real "waiting for input" state: the pane is still running (the Stop
            // hook set it to Running) and the app suppresses this banner. Skip the
            // "Needs input" pill/lifecycle so the idle nag can't undo the Running
            // status; the app still gates the (tagged) notification itself.
            let suppressNeedsInputState = (notifyCategory == .idleReminder && notifyPending)

            // `.other` means "ungated, always deliver" — identical to an untagged
            // payload, so don't put it on the wire: the app parser accepts only
            // the three known category literals, keeping the reserved suffix
            // grammar as narrow as possible.
            let payload = notificationPayload(
                title: title,
                subtitle: summary.subtitle,
                body: summary.body,
                meta: notifyCategory.metaSegment(pending: notifyPending)
            )

            if let sessionId = parsedInput.sessionId, !suppressNeedsInputState {
                try? sessionStore.upsert(
                    sessionId: sessionId,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    cwd: parsedInput.cwd,
                    transcriptPath: parsedInput.transcriptPath,
                    agentLifecycle: .needsInput,
                    lastSubtitle: summary.subtitle,
                    lastBody: summary.body
                )
            }

            if !suppressNeedsInputState {
                setAgentLifecycle(
                    client: client,
                    key: Self.claudeCodeStatusKey,
                    lifecycle: .needsInput,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId
                )
                _ = try? setClaudeStatus(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    value: "Needs input",
                    icon: "bell.fill",
                    color: "#4C8DFF", pid: claudePid
                )
            }
            _ = try sendV1Command("notify_target_async \(workspaceId) \(surfaceId) \(payload)", client: client)
            printClaudeHookAck()
        case "push-notification": try runClaudePushNotificationHook(client: client, telemetry: telemetry, parsedInput: parsedInput, sessionStore: sessionStore, routing: hookRouting, markFeedTelemetryHandled: { didSendFeedTelemetry = true }, sendFeedTelemetry: sendClaudeFeedTelemetry)
        case "session-end":
            telemetry.breadcrumb("claude-hook.session-end")
            // A fork launch that exits before its first prompt fires SessionEnd
            // with the PARENT session id (the forked id is only minted at the
            // first UserPromptSubmit). Consuming it would delete the parent
            // pane's restore record and clear its resume binding even though
            // that pane still owns the conversation. Post-prompt fork exits
            // report the forked id and consume normally.
            // https://github.com/manaflow-ai/cmux/issues/5908
            if let reportedSessionId = parsedInput.sessionId?.trimmingCharacters(in: .whitespacesAndNewlines),
               !reportedSessionId.isEmpty,
               let forkParentSessionId = claudeForkSessionParentId(
                   env: ProcessInfo.processInfo.environment,
                   fallbackPID: claudeAgentPID(from: ProcessInfo.processInfo.environment)
               ),
               reportedSessionId == forkParentSessionId {
                telemetry.breadcrumb("claude-hook.session-end.fork-parent-skipped")
                // The fork pane's claude still exited: clear the agent PID/status
                // that the fork SessionStart registered for this pane, but leave
                // the parent record, its resume binding, and the workspace's
                // notifications alone.
                let forkClaudePid = claudeAgentPID(from: ProcessInfo.processInfo.environment)
                let suppressForkVisibleMutations = shouldSuppressNestedAgentVisibleMutations(
                    currentAgentPID: forkClaudePid,
                    env: ProcessInfo.processInfo.environment
                )
                // Resolve through the live target resolver so the cleanup
                // follows the fork pane even after a pane move (live pid
                // probe, then legacy chain, then identity-surface re-home).
                if !suppressForkVisibleMutations,
                   let forkTarget = try? resolveClaudeHookDeliveryTarget(
                       mappedSession: nil,
                       routing: hookRouting,
                       client: client
                   ),
                   forkTarget.isAuthoritative {
                    _ = try? sendV1Command(
                        "clear_agent_pid \(Self.claudeCodeStatusKey) --tab=\(forkTarget.workspaceId)\(socketPanelOption(forkTarget.surfaceId)) --clear-status",
                        client: client
                    )
                }
                printClaudeHookAck()
                return
            }
            // Final cleanup when Claude process exits.
            // Only clear when we are the primary cleanup path (Stop didn't fire first).
            // If Stop already consumed the session, consumedSession is nil and we skip
            // to avoid wiping the completion notification that Stop just delivered.
            let mappedSession = parsedInput.sessionId.flatMap { try? sessionStore.lookup(sessionId: $0) }
            // Resolve the pane's CURRENT owner before consuming the record:
            // SessionEnd can be the only hook after a pane move (Ctrl-C exit
            // with no later Stop/Notification to heal the record), and cleanup
            // must clear status/notifications where the pane lives NOW.
            // Clearing the record's stale workspace instead leaves the moved
            // pane stuck and `clear_notifications --tab=` would wipe unrelated
            // panes' notifications in the old workspace.
            guard let liveEndTarget = try? resolveClaudeHookDeliveryTarget(
                mappedSession: mappedSession,
                routing: hookRouting,
                client: client
            ) else {
                // Keep the persisted route so a later authoritative cleanup
                // can still clear the visible state this attempt could not.
                didSendFeedTelemetry = true
                telemetry.breadcrumb("claude-hook.session-end.unresolved")
                printClaudeHookAck()
                return
            }
            let consumedSession = try? sessionStore.consume(
                sessionId: parsedInput.sessionId,
                workspaceId: liveEndTarget.workspaceId,
                surfaceId: liveEndTarget.surfaceId,
                turnId: parsedInput.turnId
            )
            // consume() calls clearActiveSessionIfMatching before returning
            // consumedSession, so isCurrent can treat consumedSession.sessionId
            // as current only when the consumed session was the active one.
            if let consumedSession {
                // App-visible cleanup targets the live owner of the session's
                // pane when the resolver answered authoritatively; the
                // consumed record's address is the fallback. Store-side calls
                // keep the record's own address.
                let workspaceId: String
                let cleanupSurfaceId: String
                if liveEndTarget.isAuthoritative {
                    workspaceId = liveEndTarget.workspaceId
                    cleanupSurfaceId = liveEndTarget.surfaceId
                } else {
                    workspaceId = consumedSession.workspaceId
                    cleanupSurfaceId = consumedSession.surfaceId
                }
                clearAgentSurfaceResumeBinding(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceId: cleanupSurfaceId,
                    sessionId: consumedSession.sessionId
                )
                if cleanupSurfaceId != consumedSession.surfaceId {
                    clearAgentSurfaceResumeBinding(
                        client: client,
                        workspaceId: consumedSession.workspaceId,
                        surfaceId: consumedSession.surfaceId,
                        sessionId: consumedSession.sessionId
                    )
                }
                sendClaudeFeedTelemetry(workspaceId: workspaceId, surfaceId: cleanupSurfaceId)
                // Staleness is judged on the pane being CLEANED: gating on a
                // polluted record surface (#7391) could false-skip cleanup of
                // the real pane, stranding its ring/status after exit.
                let shouldClearVisibleState = shouldApplyClaudeHookVisibleMutation(
                    sessionStore: sessionStore,
                    sessionId: consumedSession.sessionId,
                    turnId: parsedInput.turnId,
                    workspaceId: workspaceId,
                    surfaceId: cleanupSurfaceId,
                    telemetry: telemetry
                )
                let claudePid = consumedSession.pid ?? claudeAgentPID(from: ProcessInfo.processInfo.environment)
                let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(
                    currentAgentPID: claudePid,
                    env: ProcessInfo.processInfo.environment
                )
                if shouldClearVisibleState, !suppressVisibleMutations {
                    _ = try? sendV1Command(
                        "clear_agent_pid \(Self.claudeCodeStatusKey) --tab=\(workspaceId)\(socketPanelOption(cleanupSurfaceId)) --clear-status",
                        client: client
                    )
                    try? sessionStore.clearAgentLifecycleIfPresent(
                        sessionId: consumedSession.sessionId,
                        workspaceId: consumedSession.workspaceId,
                        surfaceId: consumedSession.surfaceId
                    )
                    // Lifecycle cleanup is always pane-scoped: a workspace can
                    // host multiple agents whose notifications are independent.
                    _ = try? sendV1Command(
                        "clear_notifications --tab=\(workspaceId)\(socketPanelOption(cleanupSurfaceId))",
                        client: client
                    )
                } else {
                    telemetry.breadcrumb("claude-hook.session-end.stale")
                }
            }
            printClaudeHookAck()

        case "cron-create-guard":
            telemetry.breadcrumb("claude-hook.cron-create-guard")
            let guardResponse = claudeCronCreateGuardResponse(parsedInput.rawObject)
            didSendFeedTelemetry = guardResponse == "{}"
            print(guardResponse)
            fflush(stdout)

        case "pre-tool-use":
            telemetry.breadcrumb("claude-hook.pre-tool-use")
            // Clears "Needs input" status and notification when Claude resumes work
            // (e.g. after permission grant). Runs async so it doesn't block tool execution.
            let mappedSession = parsedInput.sessionId.flatMap { try? sessionStore.lookup(sessionId: $0) }
            // Skip only the pid/tty scan per tool call; the cheap
            // `{surface_id}` re-home probe stays enabled so a mid-turn pane
            // move cannot make this hook mutate (and re-record) the old
            // workspace's focused pane.
            var preToolUseRouting = hookRouting
            preToolUseRouting.allowsPidProbe = false
            guard let resolvedTarget = try resolveClaudeHookDeliveryTarget(
                mappedSession: mappedSession,
                routing: preToolUseRouting,
                client: client
            ) else {
                didSendFeedTelemetry = true
                telemetry.breadcrumb("claude-hook.pre-tool-use.unresolved")
                printClaudeHookAck()
                return
            }
            let workspaceId = resolvedTarget.workspaceId
            let resolvedSurface = resolvedTarget
            let surfaceId = resolvedSurface.surfaceId
            sendClaudeFeedTelemetry(workspaceId: workspaceId, surfaceId: surfaceId)
            let claudePid = mappedSession?.pid ?? claudeAgentPID(from: ProcessInfo.processInfo.environment)
            let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(
                currentAgentPID: claudePid,
                env: ProcessInfo.processInfo.environment
            )
            guard shouldApplyClaudeHookVisibleMutation(
                sessionStore: sessionStore,
                parsedInput: parsedInput,
                workspaceId: workspaceId,
                surfaceId: resolvedSurface.isAuthoritative ? surfaceId : nil,
                telemetry: telemetry
            ) else {
                telemetry.breadcrumb("claude-hook.pre-tool-use.stale")
                printClaudeHookAck()
                return
            }
            guard !suppressVisibleMutations else {
                telemetry.breadcrumb("claude-hook.pre-tool-use.nested-suppressed")
                printClaudeHookAck()
                return
            }

            // AskUserQuestion and ExitPlanMode are blocking "needs input" tools:
            // Claude renders an interactive menu / plan-approval prompt and waits for
            // the user. With --dangerously-skip-permissions (permission_mode
            // "bypassPermissions") Claude fires NEITHER PermissionRequest NOR
            // Notification for them, so this async PreToolUse is the only needs-input
            // signal — flag Needs input here and return early instead of falling
            // through to the generic ".running" tail (which would leave a tab blocked
            // on a question / plan approval looking busy and silent).
            // https://github.com/manaflow-ai/cmux/issues/6606
            if let toolName = parsedInput.object?["tool_name"] as? String,
               toolName == "AskUserQuestion" || toolName == "ExitPlanMode",
               let sessionId = parsedInput.sessionId {
                // Save the question / plan summary in the session so the Notification
                // handler (when it does fire) reuses it instead of the generic
                // "Claude Code needs your attention". The question / plan text is
                // dynamic agent output; only the fallbacks are fixed strings, and
                // those reuse the shared localized waiting keys.
                let waitingSubtitle = String(
                    localized: "agent.generic.notification.subtitle.waiting",
                    defaultValue: "Waiting"
                )
                let waitingBody = String(
                    localized: "agent.generic.notification.body.waitingForInput",
                    defaultValue: "Waiting for input"
                )
                let needsInputBody: String
                if toolName == "AskUserQuestion" {
                    needsInputBody = describeAskUserQuestion(parsedInput.object) ?? waitingBody
                } else {
                    needsInputBody = describeExitPlanMode(parsedInput.object) ?? waitingBody
                }
                // An authoritative live resolution outranks the persisted
                // session surface (stale after a pane move); re-preferring it
                // would re-pollute the record and pin the blocking prompt on
                // the wrong pane. A focused-guess resolution keeps the
                // recorded surface ("" would overwrite it and misroute).
                let existingSurfaceId = resolvedSurface.isAuthoritative
                    ? surfaceId
                    : (nonEmptyClaudeHookIdentifier(mappedSession?.surfaceId) ?? surfaceId)
                try? sessionStore.upsert(
                    sessionId: sessionId,
                    workspaceId: workspaceId,
                    surfaceId: existingSurfaceId,
                    cwd: parsedInput.cwd,
                    transcriptPath: parsedInput.transcriptPath,
                    agentLifecycle: .needsInput,
                    lastSubtitle: waitingSubtitle,
                    lastBody: needsInputBody
                )
                setAgentLifecycle(
                    client: client,
                    key: Self.claudeCodeStatusKey,
                    lifecycle: .needsInput,
                    workspaceId: workspaceId,
                    surfaceId: existingSurfaceId
                )
                // In bypassPermissions (--dangerously-skip-permissions) mode no
                // PermissionRequest or Notification hook follows, so this handler must
                // publish the FULL needs-input state (status + bell) itself. In every
                // other mode that following hook owns the status/bell and converges on
                // the same needs-input state, so we only set the lifecycle here —
                // doing both would double-ring the notification.
                //
                // Read permission_mode from rawObject: the compacted `object`
                // (compactClaudeHookObject) keeps only an allowlist of keys and does
                // not retain permission_mode.
                let permissionMode = (parsedInput.rawObject?["permission_mode"] as? String)
                    ?? (parsedInput.rawObject?["permissionMode"] as? String)
                if permissionMode == "bypassPermissions" {
                    // Reuse the same localized "Needs input" value the in-app feed
                    // overlay sets (FeedCoordinator.needsInputStatusValue) so the two
                    // needs-input paths stay locale-consistent.
                    _ = try? setClaudeStatus(
                        client: client,
                        workspaceId: workspaceId,
                        surfaceId: existingSurfaceId,
                        value: String(localized: "feed.status.needsInput", defaultValue: "Needs input"),
                        icon: "bell.fill",
                        color: "#4C8DFF",
                        pid: claudePid
                    )
                    let title = String(
                        localized: "cli.claude-hook.notification.title",
                        defaultValue: "Claude Code"
                    )
                    // A question/plan-approval prompt blocks the agent on the user's
                    // decision, so it gates under "Agent Needs Permission" like the
                    // interactive permission_prompt path.
                    let payload = notificationPayload(
                        title: title,
                        subtitle: waitingSubtitle,
                        body: needsInputBody,
                        meta: AgentHookNotifyCategory.needsPermission.metaSegment(pending: false)
                    )
                    _ = try? sendV1Command(
                        "notify_target_async \(workspaceId) \(existingSurfaceId) \(payload)",
                        client: client
                    )
                }
                printClaudeHookAck()
                return
            }

            if let sessionId = parsedInput.sessionId {
                try? sessionStore.upsert(
                    sessionId: sessionId,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    cwd: parsedInput.cwd,
                    transcriptPath: parsedInput.transcriptPath,
                    agentLifecycle: .running
                )
            }
            _ = try? sendV1Command("clear_notifications --tab=\(workspaceId)\(socketPanelOption(surfaceId))", client: client)
            setAgentLifecycle(
                client: client,
                key: Self.claudeCodeStatusKey,
                lifecycle: .running,
                workspaceId: workspaceId,
                surfaceId: surfaceId
            )

            let statusValue: String
            if UserDefaults.standard.bool(forKey: "claudeCodeVerboseStatus"),
               let toolStatus = describeToolUse(parsedInput.object) {
                statusValue = toolStatus
            } else {
                statusValue = "Running"
            }
            try setClaudeStatus(
                client: client,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                value: statusValue,
                icon: "bolt.fill",
                color: "#4C8DFF",
                pid: claudePid
            )
            printClaudeHookAck()

        case "help", "--help", "-h":
            telemetry.breadcrumb("claude-hook.help")
            print(
                """
                cmux claude-hook <session-start|stop|session-end|notification|push-notification|prompt-submit|pre-tool-use> [--workspace <id|index>] [--surface <id|index>]
                """
            )

        default:
            throw CLIError(message: "Unknown claude-hook subcommand: \(subcommand)")
        }
    }

    private func claudeCronCreateGuardResponse(_ object: [String: Any]?) -> String {
        guard let object,
              object["tool_name"] as? String == "CronCreate",
              let input = object["tool_input"] as? [String: Any],
              claudeCronCreateDurableRequested(input["durable"]) else {
            return "{}"
        }

        return jsonString([
            "hookSpecificOutput": [
                "hookEventName": "PreToolUse",
                "permissionDecision": "deny",
                "permissionDecisionReason": "cmux does not support durable Claude Code cron jobs. CronCreate durable:true would be silently downgraded to session-only in this environment, so cmux denied the tool call instead. Re-run with durable:false for a session-only job, or use an external scheduler or state-file resume path for persistence."
            ]
        ])
    }

    private func claudeCronCreateDurableRequested(_ value: Any?) -> Bool {
        if let value = value as? Bool {
            return value
        }
        if let value = value as? NSNumber {
            return value.boolValue
        }
        if let value = value as? String {
            switch value.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
            case "1", "true", "yes":
                return true
            default:
                return false
            }
        }
        return false
    }

    private func setClaudeStatus(
        client: SocketClient,
        workspaceId: String,
        surfaceId: String? = nil,
        value: String,
        icon: String,
        color: String,
        pid: Int? = nil
    ) throws {
        var cmd = "set_status \(Self.claudeCodeStatusKey) \(value) --icon=\(icon) --color=\(color) --tab=\(workspaceId)\(socketPanelOption(surfaceId))"
        if let pid {
            cmd += " --pid=\(pid)"
        }
        _ = try client.send(command: cmd)
    }

    private func setAgentLifecycle(
        client: SocketClient,
        key: String,
        lifecycle: AgentHibernationLifecycleState,
        workspaceId: String,
        surfaceId: String?
    ) {
        guard Self.allowedAgentLifecycleStatusKeys.contains(key) else {
            cliWriteStderr("Warning: unsupported agent lifecycle key\n")
            return
        }
        do {
            _ = try sendV1Command(
                "set_agent_lifecycle \(key) \(lifecycle.rawValue) --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                client: client
            )
        } catch {
            cliWriteStderr("Warning: failed to set agent lifecycle\n")
        }
    }

    private func runAgentHibernation(
        commandArgs: [String],
        client: SocketClient,
        jsonOutput: Bool
    ) throws {
        guard let subcommand = commandArgs.first?.lowercased() else {
            throw CLIError(message: "Usage: cmux agent-hibernation <on|off> [--json]")
        }
        let response: String
        switch subcommand {
        case "on", "enable":
            response = try sendV1Command("agent_hibernation on", client: client)
        case "off", "disable":
            response = try sendV1Command("agent_hibernation off", client: client)
        default:
            throw CLIError(message: "Usage: cmux agent-hibernation <on|off> [--json]")
        }

        if jsonOutput {
            let ok = response == "OK"
            var fallback: [String: Any] = ["ok": ok]
            if !ok {
                fallback["message"] = response
            }
            print(jsonString(fallback))
        } else {
            print(response)
        }
    }

    func shouldApplyClaudeHookVisibleMutation(
        sessionStore: ClaudeHookSessionStore,
        parsedInput: ClaudeHookParsedInput,
        workspaceId: String,
        surfaceId: String?,
        telemetry: CLISocketSentryTelemetry
    ) -> Bool {
        shouldApplyClaudeHookVisibleMutation(
            sessionStore: sessionStore,
            sessionId: parsedInput.sessionId,
            turnId: parsedInput.turnId,
            workspaceId: workspaceId,
            surfaceId: surfaceId,
            telemetry: telemetry
        )
    }

    func shouldApplyClaudeHookVisibleMutation(
        sessionStore: ClaudeHookSessionStore,
        sessionId: String?,
        turnId: String?,
        workspaceId: String,
        surfaceId: String?,
        telemetry: CLISocketSentryTelemetry
    ) -> Bool {
        do {
            return try sessionStore.isCurrent(
                sessionId: sessionId,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                turnId: turnId
            )
        } catch {
            telemetry.breadcrumb(
                "claude-hook.is-current.error",
                data: [
                    "error": String(describing: error),
                    "session_id": sessionId ?? "",
                    "workspace_id": workspaceId,
                    "turn_id": turnId ?? "",
                ]
            )
            return true
        }
    }

    private func shouldReplaceStoppedClaudeSession(
        sessionStore: ClaudeHookSessionStore,
        parsedInput: ClaudeHookParsedInput,
        workspaceId: String,
        surfaceId: String?,
        telemetry: CLISocketSentryTelemetry
    ) -> Bool {
        do {
            return try sessionStore.canReplaceActiveSession(
                sessionId: parsedInput.sessionId,
                workspaceId: workspaceId,
                surfaceId: surfaceId
            )
        } catch {
            telemetry.breadcrumb(
                "claude-hook.can-replace-active.error",
                data: [
                    "error": String(describing: error),
                    "session_id": parsedInput.sessionId ?? "",
                    "workspace_id": workspaceId,
                ]
            )
            return false
        }
    }

    private func isClaudeClearSessionStart(_ parsedInput: ClaudeHookParsedInput) -> Bool {
        guard let source = parsedInput.object?["source"] as? String else {
            return false
        }
        return source.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() == "clear"
    }

    private func socketPanelOption(_ surfaceId: String?) -> String {
        guard let surfaceId = surfaceId?.trimmingCharacters(in: .whitespacesAndNewlines),
              !surfaceId.isEmpty,
              UUID(uuidString: surfaceId) != nil else {
            return ""
        }
        return " --panel=\(surfaceId)"
    }

    private func resolvePreferredSurfaceIdForClaudeHook(
        preferred: String?,
        fallback: String?,
        fallbackIsExplicit: Bool = false,
        workspaceId: String,
        callerTerminalBinding: (() -> CallerTerminalBinding?)? = nil,
        client: SocketClient
    ) throws -> String {
        try resolvePreferredSurfaceForClaudeHookDetailed(
            preferred: preferred,
            fallback: fallback,
            fallbackIsExplicit: fallbackIsExplicit,
            workspaceId: workspaceId,
            callerTerminalBinding: callerTerminalBinding,
            client: client
        ).surfaceId
    }

    /// Like `resolvePreferredSurfaceIdForClaudeHook`, but also reports whether the
    /// surface came from the hook's own identity (the session record's surface,
    /// the --surface/CMUX_SURFACE_ID value, or the calling process's tty binding)
    /// or from the focused/first-surface fallback. Only an identity-derived
    /// surface may participate in cross-surface staleness decisions — a borrowed
    /// fallback surface must not let a stale hook masquerade as another pane's.
    /// https://github.com/manaflow-ai/cmux/issues/5908
    func resolvePreferredSurfaceForClaudeHookDetailed(
        preferred: String?,
        fallback: String?,
        fallbackIsExplicit: Bool = false,
        workspaceId: String,
        callerTerminalBinding: (() -> CallerTerminalBinding?)? = nil,
        client: SocketClient
    ) throws -> ClaudeHookResolvedSurface {
        if fallbackIsExplicit, let fallback = nonEmptyClaudeHookIdentifier(fallback) {
            do {
                return try resolveStrictSurfaceForClaudeHookDetailed(
                    fallback,
                    workspaceId: workspaceId,
                    client: client
                )
            } catch {
                guard let preferred = nonEmptyClaudeHookIdentifier(preferred) else {
                    throw error
                }
                return try resolveStrictSurfaceForClaudeHookDetailed(
                    preferred,
                    workspaceId: workspaceId,
                    client: client
                )
            }
        }
        if let preferred = nonEmptyClaudeHookIdentifier(preferred) {
            return try resolveSurfaceAllowingFallbackDetailed(
                preferred,
                workspaceId: workspaceId,
                client: client,
                preferCallerTTYOverRaw: false,
                callerTerminalBinding: callerTerminalBinding
            )
        }
        if let fallback = nonEmptyClaudeHookIdentifier(fallback) {
            return try resolveSurfaceAllowingFallbackDetailed(
                fallback,
                workspaceId: workspaceId,
                client: client,
                preferCallerTTYOverRaw: !fallbackIsExplicit,
                callerTerminalBinding: callerTerminalBinding
            )
        }
        return try resolveSurfaceAllowingFallbackDetailed(
            nil,
            workspaceId: workspaceId,
            client: client,
            callerTerminalBinding: callerTerminalBinding
        )
    }

    private func resolveStrictSurfaceForClaudeHookDetailed(
        _ raw: String,
        workspaceId: String,
        client: SocketClient
    ) throws -> ClaudeHookResolvedSurface {
        let candidate: String
        if isUUID(raw) {
            candidate = raw
        } else if isHandleRef(raw) || Int(raw) != nil {
            candidate = try resolveSurfaceId(raw, workspaceId: workspaceId, client: client)
        } else {
            throw CLIError(message: String(
                localized: "cli.claude-hook.error.invalidSurface",
                defaultValue: "Invalid surface handle: \(raw)"
            ))
        }
        guard claudeHookSurfaceIsListed(candidate, workspaceId: workspaceId, client: client) else {
            throw CLIError(message: String(
                localized: "cli.claude-hook.error.surfaceNotFound",
                defaultValue: "Surface not found: \(raw)"
            ))
        }
        return ClaudeHookResolvedSurface(surfaceId: candidate, isAuthoritative: true)
    }

    private func shouldIgnoreClaudeHookTeardownError(_ error: Error) -> Bool {
        let message = String(describing: error).lowercased()
        let benignFragments = [
            "tabmanager not available",
            "no workspace selected",
            "workspace not found",
            "workspace ref not found",
            "workspace index not found",
            "surface not found",
            "surface ref not found",
            "surface index not found",
            "unable to resolve surface id",
            "panel not found",
            "tab not found",
            "failed to write to socket",
            "socket read error",
            "not connected"
        ]
        return benignFragments.contains { message.contains($0) }
    }

    private func describeAskUserQuestion(_ object: [String: Any]?) -> String? {
        guard let object,
              let input = object["tool_input"] as? [String: Any],
              let questions = input["questions"] as? [[String: Any]],
              let first = questions.first else { return nil }

        var parts: [String] = []

        if let question = first["question"] as? String, !question.isEmpty {
            parts.append(question)
        } else if let header = first["header"] as? String, !header.isEmpty {
            parts.append(header)
        }

        if let options = first["options"] as? [[String: Any]] {
            let labels = options.compactMap { $0["label"] as? String }
            if !labels.isEmpty {
                parts.append(labels.map { "[\($0)]" }.joined(separator: " "))
            }
        }

        if parts.isEmpty { return "Asking a question" }
        return parts.joined(separator: "\n")
    }

    private func describeExitPlanMode(_ object: [String: Any]?) -> String? {
        guard let object,
              let input = object["tool_input"] as? [String: Any],
              let plan = input["plan"] as? String else { return nil }

        // Summarize the plan with its first non-empty line (minus leading Markdown
        // heading markers) so the needs-input notification body stays concise.
        let firstLine = plan
            .split(whereSeparator: \.isNewline)
            .map { $0.trimmingCharacters(in: .whitespaces) }
            .first(where: { !$0.isEmpty })
        guard var summary = firstLine, !summary.isEmpty else { return nil }
        while summary.hasPrefix("#") {
            summary.removeFirst()
        }
        summary = summary.trimmingCharacters(in: .whitespaces)
        guard !summary.isEmpty else { return nil }
        return truncate(summary, maxLength: 180)
    }

    private func describeToolUse(_ object: [String: Any]?) -> String? {
        guard let object, let toolName = object["tool_name"] as? String else { return nil }
        let input = object["tool_input"] as? [String: Any]

        switch toolName {
        case "Read":
            if let path = input?["file_path"] as? String {
                return "Reading \(shortenPath(path))"
            }
            return "Reading file"
        case "Edit":
            if let path = input?["file_path"] as? String {
                return "Editing \(shortenPath(path))"
            }
            return "Editing file"
        case "Write":
            if let path = input?["file_path"] as? String {
                return "Writing \(shortenPath(path))"
            }
            return "Writing file"
        case "Bash":
            if let cmd = input?["command"] as? String {
                let first = cmd.components(separatedBy: .whitespacesAndNewlines).first ?? cmd
                let short = String(first.prefix(30))
                return "Running \(short)"
            }
            return "Running command"
        case "Glob":
            if let pattern = input?["pattern"] as? String {
                return "Searching \(String(pattern.prefix(30)))"
            }
            return "Searching files"
        case "Grep":
            if let pattern = input?["pattern"] as? String {
                return "Grep \(String(pattern.prefix(30)))"
            }
            return "Searching code"
        case "Agent":
            if let desc = input?["description"] as? String {
                return String(desc.prefix(40))
            }
            return "Subagent"
        case "WebFetch":
            return "Fetching URL"
        case "WebSearch":
            if let query = input?["query"] as? String {
                return "Search: \(String(query.prefix(30)))"
            }
            return "Web search"
        default:
            return toolName
        }
    }

    private func shortenPath(_ path: String) -> String {
        let url = URL(fileURLWithPath: path)
        let name = url.lastPathComponent
        return name.isEmpty ? String(path.suffix(30)) : name
    }

    private func resolveSurfaceIdForClaudeHook(
        _ raw: String?,
        workspaceId: String,
        client: SocketClient
    ) throws -> String {
        try resolveSurfaceIdAllowingFallback(raw, workspaceId: workspaceId, client: client)
    }

    private func resolveWorkspaceIdAllowingFallback(
        _ raw: String?,
        client: SocketClient
    ) throws -> String {
        if let raw,
           !raw.isEmpty,
           let candidate = try? resolveWorkspaceId(raw, client: client),
           (try? client.sendV2(method: "surface.list", params: ["workspace_id": candidate])) != nil {
            return candidate
        }
        if let callerWorkspaceId = resolveCallerWorkspaceIdForClaudeHook(client: client) {
            return callerWorkspaceId
        }
        return try resolveWorkspaceId(nil, client: client)
    }

    struct ClaudeHookResolvedSurface {
        let surfaceId: String
        /// Resolved from the hook's own identity (the supplied surface value or
        /// the calling process's tty binding) rather than the focused/first-
        /// surface fallback.
        let isAuthoritative: Bool
    }

    private func resolveSurfaceIdAllowingFallback(
        _ raw: String?,
        workspaceId: String,
        client: SocketClient
    ) throws -> String {
        try resolveSurfaceAllowingFallbackDetailed(raw, workspaceId: workspaceId, client: client).surfaceId
    }

    private func resolveSurfaceAllowingFallbackDetailed(
        _ raw: String?,
        workspaceId: String,
        client: SocketClient,
        preferCallerTTYOverRaw: Bool = false,
        callerTerminalBinding: (() -> CallerTerminalBinding?)? = nil
    ) throws -> ClaudeHookResolvedSurface {
        let rawCandidate: String? = if let raw,
            !raw.isEmpty,
            let candidate = try? resolveSurfaceId(raw, workspaceId: workspaceId, client: client),
            claudeHookSurfaceIsListed(candidate, workspaceId: workspaceId, client: client) {
            candidate
        } else {
            nil
        }
        if preferCallerTTYOverRaw,
           let callerSurfaceId = resolveCallerSurfaceIdByTTY(
               workspaceId: workspaceId,
               callerTerminalBinding: callerTerminalBinding,
               client: client
           ),
           claudeHookSurfaceIsListed(callerSurfaceId, workspaceId: workspaceId, client: client) {
            return ClaudeHookResolvedSurface(surfaceId: callerSurfaceId, isAuthoritative: true)
        }
        if let rawCandidate {
            return ClaudeHookResolvedSurface(surfaceId: rawCandidate, isAuthoritative: true)
        }
        if let callerSurfaceId = resolveCallerSurfaceIdByTTY(
            workspaceId: workspaceId,
            callerTerminalBinding: callerTerminalBinding,
            client: client
        ),
           claudeHookSurfaceIsListed(callerSurfaceId, workspaceId: workspaceId, client: client) {
            return ClaudeHookResolvedSurface(surfaceId: callerSurfaceId, isAuthoritative: true)
        }
        return ClaudeHookResolvedSurface(
            surfaceId: try resolveSurfaceId(nil, workspaceId: workspaceId, client: client),
            isAuthoritative: false
        )
    }

    func claudeHookSurfaceIsListed(
        _ candidate: String,
        workspaceId: String,
        client: SocketClient
    ) -> Bool {
        guard let listed = try? client.sendV2(method: "surface.list", params: ["workspace_id": workspaceId]) else {
            return false
        }
        let items = listed["surfaces"] as? [[String: Any]] ?? []
        return items.contains(where: {
            ($0["id"] as? String) == candidate || ($0["ref"] as? String) == candidate
        })
    }

    struct CallerTerminalBinding {
        let workspaceId: String
        let surfaceId: String
    }

    private func resolveCallerWorkspaceIdForClaudeHook(
        callerTerminalBinding: (() -> CallerTerminalBinding?)? = nil,
        client: SocketClient
    ) -> String? {
        let binding: CallerTerminalBinding?
        if let callerTerminalBinding {
            binding = callerTerminalBinding()
        } else {
            binding = resolveCallerTerminalBindingByTTY(client: client)
        }
        guard let binding,
              claudeHookSurfaceIsListed(binding.surfaceId, workspaceId: binding.workspaceId, client: client) else {
            return nil
        }
        return binding.workspaceId
    }

    private func resolveCallerSurfaceIdByTTY(
        workspaceId: String,
        callerTerminalBinding: (() -> CallerTerminalBinding?)? = nil,
        client: SocketClient
    ) -> String? {
        let binding: CallerTerminalBinding?
        if let callerTerminalBinding {
            binding = callerTerminalBinding()
        } else {
            binding = uniqueCallerTerminalBindingByTTY(client: client)
        }
        guard binding?.workspaceId == workspaceId else {
            return nil
        }
        return binding?.surfaceId
    }

    private func resolveCallerTerminalBindingByTTY(client: SocketClient, includeAmbientTTY: Bool = true) -> CallerTerminalBinding? {
        guard let ttyName = resolveCallerTTYName(includeAmbientTTY: includeAmbientTTY) else {
            return nil
        }
        return resolveTerminalBinding(ttyName: ttyName, client: client)
    }

    private func resolveAgentProcessTerminalBinding(pid: Int?, client: SocketClient) -> CallerTerminalBinding? {
        guard let pid else { return nil }
        guard let payload = try? client.sendV2(
            method: "system.top",
            params: ["all_windows": true, "include_processes": true],
            responseTimeout: 2.0
        ) else {
            return nil
        }
        let windows = payload["windows"] as? [[String: Any]] ?? []
        for window in windows {
            let workspaces = window["workspaces"] as? [[String: Any]] ?? []
            for workspace in workspaces {
                guard let workspaceId = normalizedHandleValue(workspace["id"] as? String)
                    ?? normalizedHandleValue(workspace["ref"] as? String) else {
                    continue
                }
                let panes = workspace["panes"] as? [[String: Any]] ?? []
                for pane in panes {
                    let surfaces = pane["surfaces"] as? [[String: Any]] ?? []
                    for surface in surfaces {
                        guard let surfaceId = normalizedHandleValue(surface["id"] as? String)
                            ?? normalizedHandleValue(surface["ref"] as? String) else {
                            continue
                        }
                        let topLevelPIDs = (surface["top_level_pids"] as? [Any] ?? [])
                            .compactMap { Self.intValue($0) }
                        if topLevelPIDs.contains(pid) {
                            return CallerTerminalBinding(workspaceId: workspaceId, surfaceId: surfaceId)
                        }
                        let processes = surface["processes"] as? [[String: Any]] ?? []
                        if topProcessTreeContainsPID(processes, pid: pid) {
                            return CallerTerminalBinding(workspaceId: workspaceId, surfaceId: surfaceId)
                        }
                    }
                }
            }
        }
        return nil
    }

    private func resolveAgentProcessTerminalBinding(pid: Int?, socketPath: String, socketPassword: String?) -> CallerTerminalBinding? {
        guard pid != nil else { return nil }
        let client = SocketClient(path: socketPath)
        defer { client.close() }
        do {
            try client.connect()
            try authenticateClientIfNeeded(
                client,
                explicitPassword: socketPassword,
                socketPath: socketPath,
                responseTimeout: 2.0
            )
        } catch {
            return nil
        }
        return resolveAgentProcessTerminalBinding(pid: pid, client: client)
    }

    private func topProcessTreeContainsPID(_ processes: [[String: Any]], pid: Int) -> Bool {
        for process in processes {
            if Self.intValue(process["pid"]) == pid {
                return true
            }
            if let resources = process["resources"] as? [String: Any],
               (resources["pids"] as? [Any] ?? []).compactMap({ Self.intValue($0) }).contains(pid) {
                return true
            }
            if let children = process["children"] as? [[String: Any]],
               topProcessTreeContainsPID(children, pid: pid) {
                return true
            }
        }
        return false
    }

    private func resolveTerminalBinding(ttyName: String, client: SocketClient) -> CallerTerminalBinding? {
        guard let payload = try? client.sendV2(method: "debug.terminals") else {
            return nil
        }
        let terminals = payload["terminals"] as? [[String: Any]] ?? []
        for terminal in terminals {
            guard normalizedTTYName(terminal["tty"] as? String) == ttyName,
                  let workspaceId = normalizedHandleValue(terminal["workspace_id"] as? String),
                  let surfaceId = normalizedHandleValue(terminal["surface_id"] as? String) else {
                continue
            }
            return CallerTerminalBinding(workspaceId: workspaceId, surfaceId: surfaceId)
        }
        return nil
    }

    func resolveCallerTTYName(includeAmbientTTY: Bool = true) -> String? {
        let env = ProcessInfo.processInfo.environment
        for key in includeAmbientTTY ? ["CMUX_CLI_TTY_NAME", "CMUX_TTY_NAME", "TTY", "SSH_TTY"] : ["CMUX_CLI_TTY_NAME", "CMUX_TTY_NAME"] {
            if let ttyName = normalizedTTYName(env[key]) {
                return ttyName
            }
        }
        for fileDescriptor in [STDIN_FILENO, STDOUT_FILENO, STDERR_FILENO] {
            if let rawTTYName = ttyname(fileDescriptor),
               let ttyName = normalizedTTYName(String(cString: rawTTYName)) {
                return ttyName
            }
        }
        return nil
    }

    func normalizedTTYName(_ raw: String?) -> String? {
        guard let trimmed = normalizedHandleValue(raw == "not a tty" ? nil : raw) else {
            return nil
        }
        let components = trimmed.split(separator: "/")
        if let last = components.last, !last.isEmpty {
            return String(last)
        }
        return trimmed
    }

    func normalizedHandleValue(_ raw: String?) -> String? {
        guard let raw = raw?.trimmingCharacters(in: .whitespacesAndNewlines),
              !raw.isEmpty else {
            return nil
        }
        return raw
    }

    private func summarizeClaudeHookStop(
        parsedInput: ClaudeHookParsedInput,
        sessionRecord: ClaudeHookSessionRecord?
    ) -> (subtitle: String, body: String)? {
        let cwd = parsedInput.cwd ?? sessionRecord?.cwd
        let transcriptPath = parsedInput.transcriptPath

        let projectName: String? = {
            guard let cwd = cwd, !cwd.isEmpty else { return nil }
            let path = NSString(string: cwd).expandingTildeInPath
            let tail = URL(fileURLWithPath: path).lastPathComponent
            return tail.isEmpty ? path : tail
        }()
        let completedSubtitle: String = {
            guard let projectName, !projectName.isEmpty else {
                return String(localized: "agent.claude.completion.subtitle.completed", defaultValue: "Completed")
            }
            return String.localizedStringWithFormat(
                String(localized: "agent.claude.completion.subtitle.completedInProject", defaultValue: "Completed in %@"),
                projectName
            )
        }()

        if let assistantMessage = claudeAssistantMessageFromHookPayload(parsedInput.object) {
            return (completedSubtitle, truncate(assistantMessage, maxLength: 200))
        }

        // Try reading the transcript JSONL for a richer summary.
        let transcript = transcriptPath.flatMap { readTranscriptSummary(path: $0) }

        if let lastMsg = transcript?.lastAssistantMessage {
            return (completedSubtitle, truncate(lastMsg, maxLength: 200))
        }

        // Fallback: use session record data.
        let lastMessage = sessionRecord?.lastBody ?? sessionRecord?.lastSubtitle
        let hasContext = cwd != nil || lastMessage != nil
        guard hasContext else { return nil }

        var body = "Claude session completed"
        if let projectName, !projectName.isEmpty {
            body += " in \(projectName)"
        }
        if let lastMessage, !lastMessage.isEmpty {
            body += ". Last: \(lastMessage)"
        }
        return ("Completed", body)
    }

    private func claudeAssistantMessageFromHookPayload(_ object: [String: Any]?) -> String? {
        guard let object else { return nil }
        let keys = [
            "last_assistant_message",
            "lastAssistantMessage",
            "assistantPreamble",
            "assistant_preamble",
            "assistant_response",
            "assistantResponse",
        ]
        let extra = (object["extra"] as? [String: Any]) ?? [:]
        let message = firstString(in: object, keys: keys)
            ?? firstString(in: extra, keys: keys)
        guard let message else { return nil }
        let normalized = normalizedSingleLine(message)
        return normalized.isEmpty ? nil : normalized
    }

    private struct TranscriptSummary {
        let lastAssistantMessage: String?
    }

    private func readTranscriptSummary(path: String) -> TranscriptSummary? {
        guard let lines = readRecentTextFileLines(path: path, maxBytes: 1_048_576) else { return nil }

        var lastAssistantMessage: String?

        for line in lines {
            let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty,
                  let lineData = trimmed.data(using: .utf8),
                  let obj = try? JSONSerialization.jsonObject(with: lineData) as? [String: Any],
                  let message = obj["message"] as? [String: Any],
                  let role = message["role"] as? String,
                  role == "assistant" else {
                continue
            }

            let text = extractMessageText(from: message)
            guard let text, !text.isEmpty else { continue }
            lastAssistantMessage = truncate(normalizedSingleLine(text), maxLength: 120)
        }

        guard lastAssistantMessage != nil else { return nil }
        return TranscriptSummary(lastAssistantMessage: lastAssistantMessage)
    }

    private struct CodexHookFailureSummary {
        let statusValue: String
        let subtitle: String
        let body: String
    }

    private struct CodexHookFailureCandidate {
        let message: String
        let codexErrorInfo: String?
        let additionalDetails: String?
        let isStreamError: Bool
    }

    private struct CodexHookUserInputCandidate {
        let callId: String
        let question: String?
    }

    private struct CodexTranscriptSubagentSignals {
        var isSubagentSession = false
        var hasSubagentNotificationRelay = false
    }

    private enum CodexTranscriptFailureReadResult {
        case unavailable
        case pending
        case healthy
        case failure(CodexHookFailureCandidate)
    }

    private enum CodexMonitorOwnerState {
        case alive
        case gone
        case unknown
    }

    private func summarizeCodexHookFailure(
        parsedInput: ClaudeHookParsedInput,
        sessionId: String,
        env: [String: String]
    ) -> CodexHookFailureSummary? {
        if let candidate = codexHookFailureCandidate(from: parsedInput.object) {
            return summarizeCodexHookFailureCandidate(candidate)
        }

        let payloadHasAssistantMessage = codexHookStopPayloadHasAssistantMessage(parsedInput.object)
        let providedTranscriptPath = normalizedHookValue(parsedInput.transcriptPath)
        var checkedTranscriptPaths: Set<String> = []
        let readTranscriptFailure: (String) -> CodexTranscriptFailureReadResult = { path in
            checkedTranscriptPaths.insert(path)
            return readCodexTranscriptFailure(
                path: path,
                turnId: parsedInput.turnId,
                requireTerminalCompletion: false
            )
        }

        if let transcriptPath = providedTranscriptPath
            ?? findCodexTranscriptPath(sessionId: sessionId, env: env) {
            switch readTranscriptFailure(transcriptPath) {
            case .failure(let failure):
                return summarizeCodexHookFailureCandidate(failure)
            case .healthy:
                return nil
            case .pending, .unavailable:
                break
            }
        }

        if providedTranscriptPath != nil,
           let resolvedTranscriptPath = findCodexTranscriptPath(sessionId: sessionId, env: env),
           !checkedTranscriptPaths.contains(resolvedTranscriptPath) {
            switch readTranscriptFailure(resolvedTranscriptPath) {
            case .failure(let failure):
                return summarizeCodexHookFailureCandidate(failure)
            case .healthy:
                return nil
            case .pending, .unavailable:
                break
            }
        }

        if payloadHasAssistantMessage {
            return nil
        }
        if let fallback = parsedInput.rawFallback, !fallback.isEmpty {
            return summarizeCodexHookFailureCandidate(
                CodexHookFailureCandidate(
                    message: fallback,
                    codexErrorInfo: nil,
                    additionalDetails: nil,
                    isStreamError: false
                )
            )
        }
        return nil
    }

    private func readCodexTranscriptFailure(
        path: String,
        turnId: String? = nil,
        requireTerminalCompletion: Bool = false
    ) -> CodexTranscriptFailureReadResult {
        guard let lines = readRecentTextFileLines(path: path, maxBytes: 512 * 1024) else {
            return .unavailable
        }

        var candidate: CodexHookFailureCandidate?
        var candidateCanPublishBeforeTerminal = false
        var sawAssistantMessage = false
        var sawTerminalTurn = false
        var sawRelevantTurn = turnId == nil
        for line in lines {
            let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty,
                  let data = trimmed.data(using: .utf8),
                  let object = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: Any] else {
                continue
            }

            if (turnId == nil || sawRelevantTurn) && codexTranscriptLineHasAssistantMessage(object) {
                sawAssistantMessage = true
                candidate = nil
                candidateCanPublishBeforeTerminal = false
            }

            guard (object["type"] as? String) == "event_msg",
                  let payload = object["payload"] as? [String: Any],
                  let eventType = payload["type"] as? String else {
                continue
            }

            switch eventType {
            case "task_started":
                let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                if let turnId {
                    guard payloadTurnId == turnId else {
                        continue
                    }
                }
                sawRelevantTurn = true
                candidate = nil
                candidateCanPublishBeforeTerminal = false
            case "error":
                let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                if let turnId, let payloadTurnId {
                    guard payloadTurnId == turnId else {
                        continue
                    }
                    sawRelevantTurn = true
                }
                if let failure = codexHookFailureCandidate(
                    from: payload,
                    isStreamError: false,
                    requireFailureSignal: false
                ) {
                    candidate = failure
                    candidateCanPublishBeforeTerminal = turnId == nil || payloadTurnId == turnId || sawRelevantTurn
                }
            case "stream_error":
                let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                if let turnId, let payloadTurnId {
                    guard payloadTurnId == turnId else {
                        continue
                    }
                    sawRelevantTurn = true
                }
                if let failure = codexHookFailureCandidate(
                    from: payload,
                    isStreamError: true,
                    requireFailureSignal: false
                ) {
                    candidate = failure
                    candidateCanPublishBeforeTerminal = turnId == nil || payloadTurnId == turnId || sawRelevantTurn
                }
            case "task_complete", "turn_complete":
                let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                if let turnId {
                    guard payloadTurnId == turnId else {
                        continue
                    }
                }
                sawRelevantTurn = true
                sawTerminalTurn = true
                if let lastMessage = payload["last_agent_message"] as? String,
                   !lastMessage.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                    sawAssistantMessage = true
                    candidate = nil
                    candidateCanPublishBeforeTerminal = false
                } else if candidate == nil && !sawAssistantMessage {
                    candidate = CodexHookFailureCandidate(
                        message: String(
                            localized: "agent.codex.error.noFinalResponse",
                            defaultValue: "Codex ended before sending a final response"
                        ),
                        codexErrorInfo: nil,
                        additionalDetails: nil,
                        isStreamError: false
                    )
                    candidateCanPublishBeforeTerminal = false
                }
            default:
                break
            }
        }

        if let candidate, candidateCanPublishBeforeTerminal {
            return .failure(candidate)
        }
        if candidate != nil, turnId != nil, !sawRelevantTurn {
            return .pending
        }
        if requireTerminalCompletion, !sawTerminalTurn {
            return .pending
        }
        if let candidate {
            return .failure(candidate)
        }
        if !sawTerminalTurn, !sawAssistantMessage {
            return .pending
        }
        return .healthy
    }

    private func codexTranscriptTerminalTurnIds(path: String, turnIds: Set<String>) -> Set<String> {
        let expectedTurnIds = Set(turnIds.compactMap { normalizedHookValue($0) })
        guard !expectedTurnIds.isEmpty,
              let lines = readRecentTextFileLines(path: path, maxBytes: 512 * 1024) else {
            return []
        }

        var terminalTurnIds = Set<String>()
        var currentTurnId: String?
        for line in lines {
            let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty,
                  let data = trimmed.data(using: .utf8),
                  let object = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: Any],
                  let objectType = object["type"] as? String else {
                continue
            }

            if objectType == "turn_context",
               let payload = object["payload"] as? [String: Any] {
                currentTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                continue
            }

            guard objectType == "event_msg",
                  let payload = object["payload"] as? [String: Any],
                  let eventType = payload["type"] as? String else {
                continue
            }

            if eventType == "task_started" {
                currentTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                continue
            }

            switch eventType {
            case "task_complete", "turn_complete", "turn_aborted":
                let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"]) ?? currentTurnId
                if let payloadTurnId, expectedTurnIds.contains(payloadTurnId) {
                    terminalTurnIds.insert(payloadTurnId)
                }
            default:
                break
            }
        }

        return terminalTurnIds
    }

    private func readCodexTranscriptUserInput(
        path: String,
        turnId: String?,
        excluding publishedCallIds: Set<String>
    ) -> CodexHookUserInputCandidate? {
        guard let lines = readRecentTextFileLines(path: path, maxBytes: 512 * 1024) else {
            return nil
        }

        var sawRelevantTurn = turnId == nil
        var candidate: CodexHookUserInputCandidate?
        for line in lines {
            let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty,
                  let data = trimmed.data(using: .utf8),
                  let object = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: Any],
                  let objectType = object["type"] as? String else {
                continue
            }

            if objectType == "turn_context",
               let payload = object["payload"] as? [String: Any] {
                let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                if let turnId {
                    sawRelevantTurn = payloadTurnId == turnId
                } else {
                    sawRelevantTurn = true
                }
                continue
            }

            if objectType == "response_item",
               let payload = object["payload"] as? [String: Any],
               let userInput = codexUserInputFunctionCallCandidate(
                   from: payload,
                   turnId: turnId,
                   sawRelevantTurn: sawRelevantTurn,
                   excluding: publishedCallIds
               ) {
                candidate = userInput
                continue
            }

            guard objectType == "event_msg",
                  let payload = object["payload"] as? [String: Any],
                  let eventType = payload["type"] as? String else {
                continue
            }

            switch eventType {
            case "task_started":
                let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                if let turnId {
                    sawRelevantTurn = payloadTurnId == turnId
                } else {
                    sawRelevantTurn = true
                }

            case "request_user_input":
                if let userInput = codexUserInputEventCandidate(
                    from: payload,
                    turnId: turnId,
                    sawRelevantTurn: sawRelevantTurn,
                    excluding: publishedCallIds
                ) {
                    candidate = userInput
                }

            case "task_complete", "turn_complete":
                let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                if let turnId {
                    guard payloadTurnId == turnId else { continue }
                }
                sawRelevantTurn = true
                candidate = nil

            default:
                break
            }
        }

        return candidate
    }

    private func readCodexTranscriptSubagentSignals(
        path: String,
        turnId: String?
    ) -> CodexTranscriptSubagentSignals {
        guard let lines = readRecentTextFileLines(path: path, maxBytes: 512 * 1024) else {
            return CodexTranscriptSubagentSignals()
        }

        let normalizedTurnId = normalizedHookValue(turnId)
        var signals = CodexTranscriptSubagentSignals()
        var currentTurnId: String?
        var currentTurnRelevant = normalizedTurnId == nil

        for line in lines {
            let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty,
                  let data = trimmed.data(using: .utf8),
                  let object = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: Any],
                  let objectType = object["type"] as? String else {
                continue
            }

            if objectType == "session_meta",
               let payload = object["payload"] as? [String: Any],
               codexTranscriptSessionMetaIsSubagent(payload) {
                signals.isSubagentSession = true
            }

            if objectType == "turn_context",
               let payload = object["payload"] as? [String: Any] {
                let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                currentTurnId = payloadTurnId
                currentTurnRelevant = normalizedTurnId.map { $0 == payloadTurnId } ?? true
                continue
            }

            if objectType == "event_msg",
               let payload = object["payload"] as? [String: Any],
               let eventType = payload["type"] as? String {
                switch eventType {
                case "task_started":
                    let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                    currentTurnId = payloadTurnId
                    currentTurnRelevant = normalizedTurnId.map { $0 == payloadTurnId } ?? true
                case "task_complete", "turn_complete":
                    let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
                    if let payloadTurnId {
                        currentTurnId = payloadTurnId
                    }
                    if let normalizedTurnId {
                        if payloadTurnId == normalizedTurnId || (payloadTurnId == nil && currentTurnRelevant) {
                            currentTurnRelevant = false
                        }
                    } else {
                        currentTurnRelevant = false
                    }
                default:
                    break
                }
                continue
            }

            guard currentTurnRelevant || currentTurnId == nil else {
                continue
            }
            guard codexTranscriptLineHasSubagentNotification(object) else {
                continue
            }
            signals.hasSubagentNotificationRelay = true
        }

        return signals
    }

    private func codexTranscriptSessionMetaIsSubagent(_ payload: [String: Any]) -> Bool {
        if firstString(in: payload, keys: ["thread_source", "threadSource"])?.lowercased() == "subagent" {
            return true
        }
        if let source = payload["source"] as? [String: Any],
           source["subagent"] != nil {
            return true
        }
        return false
    }

    private func codexTranscriptLineHasSubagentNotification(_ object: [String: Any]) -> Bool {
        guard (object["type"] as? String) == "response_item",
              let payload = object["payload"] as? [String: Any],
              (payload["type"] as? String) == "message",
              (payload["role"] as? String) == "user" else {
            return false
        }
        return codexTranscriptMessageText(payload)
            .map { $0.contains("<subagent_notification>") }
            ?? false
    }

    private func codexTranscriptMessageText(_ payload: [String: Any]) -> String? {
        if let content = payload["content"] as? String {
            let normalized = content.trimmingCharacters(in: .whitespacesAndNewlines)
            return normalized.isEmpty ? nil : normalized
        }
        guard let content = payload["content"] as? [[String: Any]] else {
            return nil
        }
        let parts = content.compactMap { block -> String? in
            let text = (block["text"] as? String) ?? (block["input_text"] as? String)
            let normalized = text?.trimmingCharacters(in: .whitespacesAndNewlines)
            return normalized?.isEmpty == false ? normalized : nil
        }
        let joined = parts.joined(separator: "\n")
        return joined.isEmpty ? nil : joined
    }

    private func codexUserInputEventCandidate(
        from payload: [String: Any],
        turnId: String?,
        sawRelevantTurn: Bool,
        excluding publishedCallIds: Set<String>
    ) -> CodexHookUserInputCandidate? {
        let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
        if let turnId {
            if let payloadTurnId {
                guard payloadTurnId == turnId else { return nil }
            } else {
                guard sawRelevantTurn else { return nil }
            }
        }
        return codexUserInputCandidate(
            from: payload,
            payloadTurnId: payloadTurnId,
            turnId: turnId,
            excluding: publishedCallIds
        )
    }

    private func codexUserInputFunctionCallCandidate(
        from payload: [String: Any],
        turnId: String?,
        sawRelevantTurn: Bool,
        excluding publishedCallIds: Set<String>
    ) -> CodexHookUserInputCandidate? {
        guard (payload["type"] as? String) == "function_call",
              (payload["name"] as? String) == "request_user_input" else {
            return nil
        }

        let arguments = codexFunctionCallArgumentsObject(from: payload)
        let payloadTurnId = firstString(in: payload, keys: ["turn_id", "turnId"])
            ?? arguments.flatMap { firstString(in: $0, keys: ["turn_id", "turnId"]) }
        if let turnId {
            if let payloadTurnId {
                guard payloadTurnId == turnId else { return nil }
            } else {
                guard sawRelevantTurn else { return nil }
            }
        }

        return codexUserInputCandidate(
            from: arguments ?? payload,
            payloadTurnId: payloadTurnId,
            turnId: turnId,
            fallbackCallId: firstString(in: payload, keys: ["call_id", "callId"]),
            excluding: publishedCallIds
        )
    }

    private func codexFunctionCallArgumentsObject(from payload: [String: Any]) -> [String: Any]? {
        if let arguments = payload["arguments"] as? [String: Any] {
            return arguments
        }
        guard let rawArguments = payload["arguments"] as? String,
              let data = rawArguments.data(using: .utf8),
              let arguments = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: Any] else {
            return nil
        }
        return arguments
    }

    private func codexUserInputCandidate(
        from payload: [String: Any],
        payloadTurnId: String?,
        turnId: String?,
        fallbackCallId: String? = nil,
        excluding publishedCallIds: Set<String>
    ) -> CodexHookUserInputCandidate? {
        let question = codexUserInputQuestionText(from: payload)
        let rawCallId = firstString(in: payload, keys: ["call_id", "callId"]) ?? fallbackCallId
        let callId = rawCallId?.trimmingCharacters(in: .whitespacesAndNewlines)
            ?? "\(payloadTurnId ?? turnId ?? "session"):\(question ?? "request_user_input")"
        guard !publishedCallIds.contains(callId) else { return nil }
        return CodexHookUserInputCandidate(callId: callId, question: question)
    }

    private func codexUserInputQuestionText(from payload: [String: Any]) -> String? {
        guard let questions = payload["questions"] as? [[String: Any]] else {
            return nil
        }
        for question in questions {
            let text = firstString(in: question, keys: ["question", "header", "id"])
            let normalized = text.map(normalizedSingleLine)?.trimmingCharacters(in: .whitespacesAndNewlines)
            if let normalized, !normalized.isEmpty {
                return truncate(normalized, maxLength: 220)
            }
        }
        return nil
    }

    private func codexHookStopPayloadHasAssistantMessage(_ object: [String: Any]?) -> Bool {
        guard let object,
              let message = firstString(in: object, keys: ["last_assistant_message", "lastAssistantMessage"]) else {
            return false
        }
        return !message.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    private func codexTranscriptLineHasAssistantMessage(_ object: [String: Any]) -> Bool {
        guard (object["type"] as? String) == "response_item",
              let payload = object["payload"] as? [String: Any],
              (payload["type"] as? String) == "message",
              (payload["role"] as? String) == "assistant",
              let content = payload["content"] as? [[String: Any]] else {
            return false
        }
        return content.contains { block in
            guard let text = block["text"] as? String else { return false }
            return !text.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        }
    }

    private func codexHookFailureCandidate(
        from object: [String: Any]?,
        isStreamError: Bool = false,
        requireFailureSignal: Bool = true
    ) -> CodexHookFailureCandidate? {
        guard let object else { return nil }
        let message = firstString(in: object, keys: ["message", "error", "body", "text", "description"])
        let additionalDetails = codexHookStringValue(object["additional_details"] ?? object["additionalDetails"])
        let codexErrorInfo = codexHookStringValue(object["codex_error_info"] ?? object["codexErrorInfo"])
        let eventType = firstString(in: object, keys: ["type", "kind"])?.lowercased()
        let typedFailure = eventType == "error" || eventType == "stream_error"
        let hasExplicitErrorField = object["error"].map { !($0 is NSNull) } ?? false
        let signal = [message, additionalDetails, codexErrorInfo]
            .compactMap { $0 }
            .joined(separator: " ")
            .lowercased()
        guard !requireFailureSignal ||
              typedFailure ||
              hasExplicitErrorField ||
              codexErrorInfo != nil ||
              signal.contains("error") ||
              signal.contains("failed") ||
              signal.contains("exception") ||
              signal.contains("usage limit") ||
              signal.contains("rate limit") ||
              signal.contains("stream disconnected") ||
              signal.contains("connection") ||
              signal.contains("unauthorized") else {
            return nil
        }
        return CodexHookFailureCandidate(
            message: message ?? additionalDetails ?? codexErrorInfo ?? String(
                localized: "agent.codex.error.defaultMessage",
                defaultValue: "Codex reported an error"
            ),
            codexErrorInfo: codexErrorInfo,
            additionalDetails: additionalDetails,
            isStreamError: isStreamError || eventType == "stream_error"
        )
    }

    private func summarizeCodexHookFailureCandidate(_ candidate: CodexHookFailureCandidate) -> CodexHookFailureSummary {
        let signal = [
            candidate.message,
            candidate.codexErrorInfo,
            candidate.additionalDetails,
            candidate.isStreamError ? "stream_error" : nil
        ]
            .compactMap { $0 }
            .joined(separator: " ")
            .lowercased()

        let subtitle: String
        let statusValue: String
        if signal.contains("usage_limit") ||
            signal.contains("usage limit") ||
            signal.contains("rate_limit") ||
            signal.contains("rate limit") ||
            signal.contains("credits") {
            subtitle = String(localized: "agent.codex.error.subtitle.rateLimit", defaultValue: "Rate limit")
            statusValue = String(localized: "agent.codex.error.status.rateLimit", defaultValue: "Codex rate limit")
        } else if signal.contains("unauthorized") ||
                    signal.contains("auth") ||
                    signal.contains("access token") ||
                    signal.contains("sign in") ||
                    signal.contains("login") {
            subtitle = String(localized: "agent.codex.error.subtitle.auth", defaultValue: "Auth error")
            statusValue = String(localized: "agent.codex.error.status.auth", defaultValue: "Codex auth error")
        } else if signal.contains("response_stream") ||
                    signal.contains("stream disconnected") ||
                    signal.contains("connection") ||
                    signal.contains("network") ||
                    signal.contains("offline") ||
                    signal.contains("timed out") ||
                    signal.contains("timeout") {
            subtitle = String(localized: "agent.codex.error.subtitle.network", defaultValue: "Network error")
            statusValue = String(localized: "agent.codex.error.status.network", defaultValue: "Codex network error")
        } else {
            subtitle = String(localized: "agent.codex.error.subtitle.generic", defaultValue: "Error")
            statusValue = String(localized: "agent.codex.error.status.generic", defaultValue: "Codex error")
        }

        let detail = candidate.additionalDetails ?? candidate.message
        return CodexHookFailureSummary(
            statusValue: statusValue,
            subtitle: subtitle,
            body: truncate(normalizedSingleLine(detail), maxLength: 220)
        )
    }

    private func codexHookStringValue(_ rawValue: Any?) -> String? {
        if let string = rawValue as? String {
            let trimmed = normalizedSingleLine(string)
            return trimmed.isEmpty ? nil : trimmed
        }
        guard let rawValue,
              JSONSerialization.isValidJSONObject(rawValue),
              let data = try? JSONSerialization.data(withJSONObject: rawValue, options: [.sortedKeys]),
              let string = String(data: data, encoding: .utf8) else {
            return nil
        }
        let trimmed = normalizedSingleLine(string)
        return trimmed.isEmpty ? nil : trimmed
    }

    func findCodexTranscriptPath(sessionId: String, env: [String: String]) -> String? {
        let normalizedSessionId = sessionId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedSessionId.isEmpty else { return nil }

        let codexHome = normalizedHookValue(env["CODEX_HOME"]) ?? "~/.codex"
        let sessionsURL = URL(fileURLWithPath: NSString(string: codexHome).expandingTildeInPath, isDirectory: true)
            .appendingPathComponent("sessions", isDirectory: true)
        let fileManager = FileManager.default
        var newest: URL?
        var newestModificationDate: Date?
        for directoryURL in recentCodexSessionDirectories(sessionsURL: sessionsURL, fileManager: fileManager) {
            guard let urls = try? fileManager.contentsOfDirectory(
                at: directoryURL,
                includingPropertiesForKeys: [.contentModificationDateKey],
                options: [.skipsHiddenFiles]
            ) else {
                continue
            }

            for url in urls {
                guard url.pathExtension == "jsonl",
                      url.lastPathComponent.contains(normalizedSessionId) else {
                    continue
                }
                let modificationDate = (try? url.resourceValues(forKeys: [.contentModificationDateKey]).contentModificationDate) ?? .distantPast
                if newest == nil || modificationDate > (newestModificationDate ?? .distantPast) {
                    newest = url
                    newestModificationDate = modificationDate
                }
            }
        }
        return newest?.path
    }

    private func recentCodexSessionDirectories(sessionsURL: URL, fileManager: FileManager) -> [URL] {
        var directories: [URL] = []
        var seenPaths = Set<String>()

        func appendIfDirectory(_ url: URL) {
            guard seenPaths.insert(url.path).inserted else { return }
            var isDirectory: ObjCBool = false
            guard fileManager.fileExists(atPath: url.path, isDirectory: &isDirectory),
                  isDirectory.boolValue else {
                return
            }
            directories.append(url)
        }

        appendIfDirectory(sessionsURL)

        var utcCalendar = Calendar(identifier: .gregorian)
        utcCalendar.timeZone = TimeZone(secondsFromGMT: 0) ?? .current
        for calendar in [Calendar.current, utcCalendar] {
            for dayOffset in -14...1 {
                guard let date = calendar.date(byAdding: .day, value: dayOffset, to: Date()) else {
                    continue
                }
                let components = calendar.dateComponents([.year, .month, .day], from: date)
                guard let year = components.year,
                      let month = components.month,
                      let day = components.day else {
                    continue
                }
                appendIfDirectory(
                    sessionsURL
                        .appendingPathComponent(String(format: "%04d", year), isDirectory: true)
                        .appendingPathComponent(String(format: "%02d", month), isDirectory: true)
                        .appendingPathComponent(String(format: "%02d", day), isDirectory: true)
                )
            }
        }

        return directories
    }

    private static let codexMonitorLeaseDirectoryName = "codex-monitor-leases"
    private static let codexMonitorLeaseMaxAgeSeconds: TimeInterval = 4 * 60 * 60
    private static let codexMonitorRetiredLeaseMaxAgeSeconds: TimeInterval = 2 * 60
    private static let codexMonitorOwnerCheckIntervalSeconds: TimeInterval = 60
    private static let codexMonitorOwnerCheckTimeoutSeconds: TimeInterval = 1

    private func codexMonitorLeaseDirectory(env: [String: String]) -> URL {
        let statePath = NSString(
            string: agentHookStatePath(sessionStoreSuffix: "codex", env: env)
        ).expandingTildeInPath
        return URL(fileURLWithPath: statePath, isDirectory: false)
            .deletingLastPathComponent()
            .appendingPathComponent(Self.codexMonitorLeaseDirectoryName, isDirectory: true)
    }

    private func codexMonitorLeasePath(leaseId: String, env: [String: String]) -> String {
        return codexMonitorLeaseDirectory(env: env)
            .appendingPathComponent("\(leaseId).json", isDirectory: false)
            .path
    }

    private func writeCodexMonitorLease(_ record: CodexMonitorLeaseRecord, to path: String) throws {
        let url = URL(fileURLWithPath: path, isDirectory: false)
        try FileManager.default.createDirectory(
            at: url.deletingLastPathComponent(),
            withIntermediateDirectories: true,
            attributes: nil
        )
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
        let data = try encoder.encode(record)
        try data.write(to: url, options: .atomic)
    }

    private func readCodexMonitorLease(path: String) -> CodexMonitorLeaseRecord? {
        guard let data = try? Data(contentsOf: URL(fileURLWithPath: path, isDirectory: false)) else {
            return nil
        }
        return try? JSONDecoder().decode(CodexMonitorLeaseRecord.self, from: data)
    }

    private func createCodexMonitorLease(
        sessionId: String,
        turnId: String?,
        workspaceId: String,
        surfaceId: String?,
        env: [String: String]
    ) -> String? {
        let leaseId = UUID().uuidString.lowercased()
        let path = codexMonitorLeasePath(leaseId: leaseId, env: env)
        let normalizedSessionId = sessionId.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedTurnId = turnId?.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedSessionId.isEmpty else { return nil }
        let record = CodexMonitorLeaseRecord(
            leaseId: leaseId,
            sessionId: normalizedSessionId,
            turnId: normalizedTurnId?.isEmpty == false ? normalizedTurnId : nil,
            workspaceId: workspaceId,
            surfaceId: surfaceId,
            createdAt: Date().timeIntervalSince1970,
            retiredAt: nil
        )
        try? pruneExpiredCodexMonitorLeases(env: env)
        do {
            try writeCodexMonitorLease(record, to: path)
            return path
        } catch {
            return nil
        }
    }

    private func retireCodexMonitorLeases(
        sessionId: String,
        turnId: String?,
        preservingLeasePath: String? = nil,
        env: [String: String]
    ) {
        let normalizedSessionId = sessionId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedSessionId.isEmpty else { return }

        let fileManager = FileManager.default
        let now = Date().timeIntervalSince1970
        let normalizedTurnId = turnId?.trimmingCharacters(in: .whitespacesAndNewlines)
        let shouldMatchTurn = normalizedTurnId?.isEmpty == false
        let preservingPath = preservingLeasePath.map {
            URL(fileURLWithPath: $0, isDirectory: false).standardizedFileURL.path
        }
        let directory = codexMonitorLeaseDirectory(env: env)
        let targetPaths = ((try? fileManager.contentsOfDirectory(
            at: directory,
            includingPropertiesForKeys: nil,
            options: [.skipsHiddenFiles]
        )) ?? []).map(\.path)

        for path in targetPaths {
            let standardizedPath = URL(fileURLWithPath: path, isDirectory: false).standardizedFileURL.path
            guard preservingPath == nil || standardizedPath != preservingPath else {
                continue
            }
            guard var record = readCodexMonitorLease(path: path),
                  record.sessionId == normalizedSessionId,
                  !shouldMatchTurn || record.turnId == normalizedTurnId,
                  record.retiredAt == nil else {
                continue
            }
            record.retiredAt = now
            try? writeCodexMonitorLease(record, to: path)
        }
        try? pruneExpiredCodexMonitorLeases(env: env)
    }

    private func pruneExpiredCodexMonitorLeases(env: [String: String]) throws {
        let fileManager = FileManager.default
        let directory = codexMonitorLeaseDirectory(env: env)
        guard fileManager.fileExists(atPath: directory.path) else { return }
        let now = Date().timeIntervalSince1970
        let activeLeaseCutoff = now - Self.codexMonitorLeaseMaxAgeSeconds
        let retiredLeaseCutoff = now - Self.codexMonitorRetiredLeaseMaxAgeSeconds
        let urls = try fileManager.contentsOfDirectory(
            at: directory,
            includingPropertiesForKeys: nil,
            options: [.skipsHiddenFiles]
        )
        for url in urls {
            guard let record = readCodexMonitorLease(path: url.path) else {
                continue
            }
            let activeLeaseExpired = record.createdAt < activeLeaseCutoff
            let retiredLeaseExpired = record.retiredAt.map { $0 < retiredLeaseCutoff } ?? false
            if activeLeaseExpired || retiredLeaseExpired {
                try? fileManager.removeItem(at: url)
            }
        }
    }

    private func isCodexMonitorLeaseRetired(path: String?) -> Bool {
        guard let path, !path.isEmpty else { return false }
        guard let record = readCodexMonitorLease(path: path) else {
            return !FileManager.default.fileExists(atPath: path)
        }
        return record.retiredAt != nil
    }

    private func removeCodexMonitorLease(path: String?) {
        guard let path, !path.isEmpty else { return }
        try? FileManager.default.removeItem(atPath: path)
    }

    private func codexMonitorOwnerState(workspaceId: String, surfaceId: String?, client: SocketClient) -> CodexMonitorOwnerState {
        guard client.connectionAppearsOpen() else { return client.isRelayBacked ? .unknown : .gone }
        guard let payload = try? client.sendV2(
            method: "surface.list",
            params: ["workspace_id": workspaceId],
            responseTimeout: Self.codexMonitorOwnerCheckTimeoutSeconds
        ) else {
            return .unknown
        }
        let surfaces = payload["surfaces"] as? [[String: Any]] ?? []
        guard let surfaceId, !surfaceId.isEmpty else { return surfaces.isEmpty ? .gone : .alive }
        let ownerFound = surfaces.contains { surface in
            (surface["id"] as? String) == surfaceId || (surface["ref"] as? String) == surfaceId
        }
        return ownerFound ? .alive : .gone
    }

    private func startCodexTranscriptMonitor(
        sessionId: String,
        turnId: String?,
        transcriptPath: String?,
        cwd: String?,
        workspaceId: String,
        surfaceId: String?,
        leasePath: String?,
        env: [String: String],
        telemetry: CLISocketSentryTelemetry
    ) {
        guard !sessionId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
              !workspaceId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            return
        }

        let monitorTelemetry: [String: Any] = [
            "has_lease": normalizedHookValue(leasePath) != nil,
            "has_turn_id": normalizedHookValue(turnId) != nil,
            "has_transcript": normalizedHookValue(transcriptPath) != nil,
            "has_surface_id": normalizedHookValue(surfaceId) != nil,
        ]
        telemetry.breadcrumb("codex-hook.monitor.start", data: monitorTelemetry)

        let executablePath = resolvedExecutableURL()?.path ?? args.first ?? "cmux"
        let process = Process()
        process.executableURL = URL(fileURLWithPath: executablePath)
        var monitorArgs = [
            "hooks", "codex",
            "monitor",
            "--workspace",
            workspaceId,
            "--session",
            sessionId,
        ]
        if let surfaceId, !surfaceId.isEmpty {
            monitorArgs += ["--surface", surfaceId]
        }
        if let turnId, !turnId.isEmpty {
            monitorArgs += ["--turn", turnId]
        }
        if let transcriptPath, !transcriptPath.isEmpty {
            monitorArgs += ["--transcript", transcriptPath]
        }
        if let cwd, !cwd.isEmpty {
            monitorArgs += ["--cwd", cwd]
        }
        if let leasePath, !leasePath.isEmpty {
            monitorArgs += ["--lease", leasePath]
        }
        process.arguments = monitorArgs
        process.environment = env.merging(["CMUX_CLI_SENTRY_DISABLED": "1"], uniquingKeysWith: { _, new in new })
        process.standardInput = FileHandle.nullDevice
        process.standardOutput = FileHandle.nullDevice
        process.standardError = FileHandle.nullDevice
        do {
            try cliRunProcess(process)
            telemetry.breadcrumb("codex-hook.monitor.started", data: monitorTelemetry)
        } catch {
            telemetry.captureError(stage: "codex-monitor-start", error: error, data: monitorTelemetry)
        }
    }

    private func runCodexTranscriptMonitor(commandArgs: [String], client: SocketClient) throws {
        let env = ProcessInfo.processInfo.environment
        let workspaceId = optionValue(commandArgs, name: "--workspace") ?? env["CMUX_WORKSPACE_ID"] ?? ""
        let surfaceId = optionValue(commandArgs, name: "--surface") ?? env["CMUX_SURFACE_ID"]
        let sessionId = optionValue(commandArgs, name: "--session")
            ?? env["CMUX_CODEX_SESSION_ID"]
            ?? env["CODEX_SESSION_ID"]
            ?? env["CMUX_AGENT_SESSION_ID"]
            ?? ""
        let turnId = optionValue(commandArgs, name: "--turn")
        var transcriptPath = optionValue(commandArgs, name: "--transcript")
        let leasePath = optionValue(commandArgs, name: "--lease")

        guard !workspaceId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
              !sessionId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            return
        }

        defer { removeCodexMonitorLease(path: leasePath) }
        let deadline = Date().addingTimeInterval(4 * 60 * 60)
        var nextOwnerCheck = Date.distantPast
        var publishedUserInputCallIds = Set<String>()
        while Date() < deadline {
            if isCodexMonitorLeaseRetired(path: leasePath) {
                return
            }
            let now = Date()
            if now >= nextOwnerCheck {
                nextOwnerCheck = now.addingTimeInterval(Self.codexMonitorOwnerCheckIntervalSeconds)
                if codexMonitorOwnerState(workspaceId: workspaceId, surfaceId: surfaceId, client: client) == .gone {
                    return
                }
            }

            if transcriptPath == nil {
                transcriptPath = findCodexTranscriptPath(sessionId: sessionId, env: env)
            }

            if let currentTranscriptPath = transcriptPath {
                if let userInput = readCodexTranscriptUserInput(
                    path: currentTranscriptPath,
                    turnId: turnId,
                    excluding: publishedUserInputCallIds
                ) {
                    publishedUserInputCallIds.insert(userInput.callId)
                    publishCodexMonitorUserInput(
                        userInput,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        client: client
                    )
                }

                switch readCodexTranscriptFailure(
                    path: currentTranscriptPath,
                    turnId: turnId,
                    requireTerminalCompletion: true
                ) {
                case .failure(let failure):
                    publishCodexMonitorFailure(
                        failure,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        client: client
                    )
                    return
                case .healthy:
                    return
                case .pending:
                    break
                case .unavailable:
                    let unavailableTranscriptPath = currentTranscriptPath
                    transcriptPath = nil
                    if let resolvedTranscriptPath = findCodexTranscriptPath(sessionId: sessionId, env: env) {
                        transcriptPath = resolvedTranscriptPath
                        if resolvedTranscriptPath != unavailableTranscriptPath {
                            continue
                        }
                    }
                }
            }

            let remaining = deadline.timeIntervalSinceNow
            guard remaining > 0 else { return }
            waitForCodexTranscriptChange(path: transcriptPath, leasePath: leasePath, timeout: min(30, remaining))
        }
    }

    private func publishCodexMonitorUserInput(
        _ userInput: CodexHookUserInputCandidate,
        workspaceId: String,
        surfaceId: String?,
        client: SocketClient
    ) {
        let subtitle = String(localized: "agent.codex.input.subtitle.waiting", defaultValue: "Waiting")
        let body = userInput.question ?? String(
            localized: "agent.codex.input.body.needsInput",
            defaultValue: "Codex is asking a question"
        )
        if let surfaceId, !surfaceId.isEmpty {
            let payload = "Codex|\(sanitizeNotificationField(subtitle))|\(sanitizeNotificationField(body))"
            _ = try? sendV1Command("notify_target \(workspaceId) \(surfaceId) \(payload)", client: client)
        }
        let statusValue = String(localized: "agent.codex.input.status.needsInput", defaultValue: "Codex needs input")
        _ = try? sendV1Command(
            "set_status codex \(statusValue) --icon=bell.fill --color=#4C8DFF --priority=100 --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
            client: client
        )
    }

    private func publishCodexMonitorFailure(
        _ failure: CodexHookFailureCandidate,
        workspaceId: String,
        surfaceId: String?,
        client: SocketClient
    ) {
        let summary = summarizeCodexHookFailureCandidate(failure)
        if let surfaceId, !surfaceId.isEmpty {
            let payload = "Codex|\(sanitizeNotificationField(summary.subtitle))|\(sanitizeNotificationField(summary.body))"
            _ = try? sendV1Command("notify_target \(workspaceId) \(surfaceId) \(payload)", client: client)
        }
        _ = try? sendV1Command(
            "set_status codex \(summary.statusValue) --icon=exclamationmark.triangle.fill --color=#FF453A --priority=100 --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
            client: client
        )
    }

    private func waitForCodexTranscriptChange(path: String?, leasePath: String?, timeout: TimeInterval) {
        guard timeout > 0 else { return }

        let semaphore = DispatchSemaphore(value: 0)
        var sources: [DispatchSourceFileSystemObject] = []

        func addFileSource(path: String?, eventMask: DispatchSource.FileSystemEvent) {
            guard let path, !path.isEmpty else { return }
            let expandedPath = NSString(string: path).expandingTildeInPath
            let fd = open(expandedPath, O_EVTONLY)
            guard fd >= 0 else { return }
            let source = DispatchSource.makeFileSystemObjectSource(
                fileDescriptor: fd,
                eventMask: eventMask,
                queue: DispatchQueue.global(qos: .utility)
            )
            source.setEventHandler {
                semaphore.signal()
            }
            source.setCancelHandler {
                close(fd)
            }
            source.resume()
            sources.append(source)
        }

        addFileSource(path: path, eventMask: [.write, .extend, .delete, .rename])
        addFileSource(path: leasePath, eventMask: [.write, .delete, .rename])

        guard !sources.isEmpty else {
            _ = DispatchSemaphore(value: 0).wait(timeout: .now() + timeout)
            return
        }

        _ = semaphore.wait(timeout: .now() + timeout)
        sources.forEach { $0.cancel() }
    }

    private func extractMessageText(from message: [String: Any]) -> String? {
        if let content = message["content"] as? String {
            return content.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        if let contentArray = message["content"] as? [[String: Any]] {
            let texts = contentArray.compactMap { block -> String? in
                guard (block["type"] as? String) == "text",
                      let text = block["text"] as? String else { return nil }
                return text.trimmingCharacters(in: .whitespacesAndNewlines)
            }
            let joined = texts.joined(separator: " ")
            return joined.isEmpty ? nil : joined
        }
        return nil
    }

    private func summarizeClaudeHookNotification(parsedInput: ClaudeHookParsedInput) -> (subtitle: String, body: String) {
        guard let object = parsedInput.object else {
            if let fallback = parsedInput.rawFallback, !fallback.isEmpty {
                return classifyClaudeNotification(signal: fallback, message: fallback)
            }
            return ("Waiting", "Claude is waiting for your input")
        }

        let nested = (object["notification"] as? [String: Any]) ?? (object["data"] as? [String: Any]) ?? [:]
        let signalParts = [
            firstString(in: object, keys: ["event", "event_name", "hook_event_name", "type", "kind"]),
            firstString(in: object, keys: ["notification_type", "matcher", "reason"]),
            firstString(in: nested, keys: ["type", "kind", "reason"])
        ]
        let messageCandidates = [
            firstString(in: object, keys: ["message", "body", "text", "prompt", "error", "description"]),
            firstString(in: nested, keys: ["message", "body", "text", "prompt", "error", "description"])
        ]
        let message = messageCandidates.compactMap { $0 }.first ?? "Claude needs your input"
        let normalizedMessage = normalizedSingleLine(message)
        let signal = signalParts.compactMap { $0 }.joined(separator: " ")
        var classified = classifyClaudeNotification(signal: signal, message: normalizedMessage)

        classified.body = truncate(classified.body, maxLength: 180)
        return classified
    }

    private func summarizeAgentHookNotification(
        def: AgentHookDef,
        parsedInput: ClaudeHookParsedInput,
        cwd: String?,
        env: [String: String],
        sessionId: String?
    ) -> AgentHookNotificationSummary {
        guard let object = parsedInput.object else {
            if let fallback = parsedInput.rawFallback, !fallback.isEmpty {
                return classifyAgentHookNotification(
                    def: def,
                    signal: fallback,
                    message: fallback,
                    isFallback: false
                )
            }
            let body = String.localizedStringWithFormat(
                String(localized: "agent.generic.notification.body.sentNotification", defaultValue: "%@ sent a notification"),
                def.displayName
            )
            return classifyAgentHookNotification(def: def, signal: "", message: body, isFallback: true)
        }

        let nested = (object["notification"] as? [String: Any]) ?? (object["data"] as? [String: Any]) ?? [:]
        let extra = (object["extra"] as? [String: Any]) ?? [:]
        let signalParts = [
            firstString(in: object, keys: ["event", "event_name", "hook_event_name", "hookEventName", "type", "kind"]),
            firstString(in: object, keys: ["notification_type", "notificationType", "matcher", "reason"]),
            firstString(in: nested, keys: ["type", "kind", "reason"]),
        ]
        let messageCandidates = [
            firstString(in: object, keys: ["message", "body", "text", "prompt", "summary", "description", "error", "title"]),
            firstString(in: nested, keys: ["message", "body", "text", "prompt", "summary", "description", "error", "title"]),
            firstString(in: extra, keys: ["message", "body", "text", "prompt", "summary", "description", "error", "title"]),
        ]
        let fallbackBody = String.localizedStringWithFormat(
            String(localized: "agent.generic.notification.body.sentNotification", defaultValue: "%@ sent a notification"),
            def.displayName
        )
        let message = messageCandidates.compactMap { $0 }.first ?? fallbackBody
        let signal = signalParts.compactMap { $0 }.joined(separator: " ")
        let normalizedMessage = normalizedSingleLine(message)
        if let hermesApprovalMessage = hermesAgentApprovalNotificationMessage(def: def, object: object) {
            return classifyAgentHookNotification(
                def: def,
                signal: signal,
                message: normalizedSingleLine(hermesApprovalMessage),
                isFallback: false
            )
        }
        if let campfireSummary = summarizeCampfireObserverNotification(def: def, object: object) { return campfireSummary }
        if let grokSummary = summarizeGrokAssistantCompletionNotification(
            def: def,
            message: normalizedMessage,
            cwd: cwd,
            env: env,
            sessionId: sessionId,
            matchesMessage: isGrokGenericTurnCompletion
        ) {
            return grokSummary
        }
        if def.name == "grok", isGrokGenericTurnCompletion(normalizedMessage) {
            return AgentHookNotificationSummary(
                subtitle: String(localized: "agent.generic.notification.subtitle.completed", defaultValue: "Completed"),
                body: String(localized: "agent.generic.notification.body.taskCompleted", defaultValue: "Task completed"),
                status: .idle,
                isFallback: false,
                notifyCategory: .turnComplete
            )
        }
        return classifyAgentHookNotification(
            def: def,
            signal: signal,
            message: normalizedMessage,
            isFallback: message == fallbackBody
        )
    }

    private func summarizeGrokAssistantCompletionNotification(
        def: AgentHookDef,
        message: String,
        cwd: String?,
        env: [String: String],
        sessionId: String?,
        matchesMessage: (String) -> Bool
    ) -> AgentHookNotificationSummary? {
        guard def.name == "grok",
              matchesMessage(message),
              let body = latestGrokAssistantMessage(
                cwd: cwd,
                sessionId: sessionId,
                env: env
              ) else {
            return nil
        }
        return AgentHookNotificationSummary(
            subtitle: String(localized: "agent.generic.notification.subtitle.completed", defaultValue: "Completed"),
            body: truncate(normalizedSingleLine(body), maxLength: 180),
            status: .idle,
            isFallback: false,
            notifyCategory: .turnComplete
        )
    }

    private func hermesAgentApprovalNotificationMessage(def: AgentHookDef, object: [String: Any]) -> String? {
        guard def.name == "hermes-agent" else { return nil }
        let event = firstString(in: object, keys: ["hook_event_name", "hookEventName", "event", "event_name"])
        guard event == "pre_approval_request" else { return nil }
        let extra = (object["extra"] as? [String: Any]) ?? [:]
        let command = firstString(in: extra, keys: ["command"])
        let description = firstString(in: extra, keys: ["description", "pattern_key", "patternKey"])

        switch (description, command) {
        case let (description?, command?):
            return String.localizedStringWithFormat(
                String(
                    localized: "agent.hermes.notification.body.approvalCommand",
                    defaultValue: "%1$@: %2$@"
                ),
                description,
                command
            )
        case let (description?, nil):
            return description
        case let (nil, command?):
            return command
        default:
            return nil
        }
    }

    private func normalizedAgentHookNotificationMessage(parsedInput: ClaudeHookParsedInput) -> String? {
        guard let object = parsedInput.object else {
            return parsedInput.rawFallback.map(normalizedSingleLine)
        }
        let nested = (object["notification"] as? [String: Any]) ?? (object["data"] as? [String: Any]) ?? [:]
        let extra = (object["extra"] as? [String: Any]) ?? [:]
        let messageCandidates = [
            firstString(in: object, keys: ["message", "body", "text", "prompt", "summary", "description", "error", "title"]),
            firstString(in: nested, keys: ["message", "body", "text", "prompt", "summary", "description", "error", "title"]),
            firstString(in: extra, keys: ["message", "body", "text", "prompt", "summary", "description", "error", "title"]),
        ]
        return messageCandidates.compactMap { $0 }.first.map(normalizedSingleLine)
    }

    private func isGrokInternalSessionNotification(_ message: String) -> Bool {
        AgentHookNotificationClassifier.isGrokInternalSessionNotification(message)
    }

    private func isGrokGenericTurnCompletion(_ message: String) -> Bool {
        AgentHookNotificationClassifier.isGrokGenericTurnCompletion(message)
    }

    private func latestGrokAssistantMessage(
        cwd: String?,
        sessionId: String?,
        env: [String: String]
    ) -> String? {
        guard let sessionURL = grokSessionDirectory(cwd: cwd, sessionId: sessionId, env: env) else {
            return nil
        }
        let historyURL = sessionURL.appendingPathComponent("chat_history.jsonl", isDirectory: false)
        guard let lines = readRecentTextFileLines(path: historyURL.path, maxBytes: 256 * 1024) else {
            return nil
        }

        for line in lines.reversed() {
            guard let data = line.data(using: .utf8),
                  let object = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  (object["type"] as? String) == "assistant",
                  let text = extractMessageText(from: object) else {
                continue
            }
            let normalized = normalizedSingleLine(text)
            if !normalized.isEmpty {
                return normalized
            }
        }
        return nil
    }

    func grokSessionDirectory(
        cwd: String?,
        sessionId: String?,
        env: [String: String]
    ) -> URL? {
        guard let cwd = cwd?.trimmingCharacters(in: .whitespacesAndNewlines),
              !cwd.isEmpty else {
            return nil
        }
        let sessionsRoot = grokSessionsRoot(env: env)
        let fileManager = FileManager.default
        let projectURLs = grokEncodedSessionCWDs(cwd).compactMap { encodedCWD -> URL? in
            let projectURL = sessionsRoot.appendingPathComponent(encodedCWD, isDirectory: true)
            var isDirectory = ObjCBool(false)
            guard fileManager.fileExists(atPath: projectURL.path, isDirectory: &isDirectory),
                  isDirectory.boolValue else {
                return nil
            }
            return projectURL
        }
        guard !projectURLs.isEmpty else {
            return nil
        }

        if let sessionId = sessionId?.trimmingCharacters(in: .whitespacesAndNewlines),
           !sessionId.isEmpty {
            for projectURL in projectURLs {
                let sessionURL = projectURL.appendingPathComponent(sessionId, isDirectory: true)
                var isDirectory = ObjCBool(false)
                if fileManager.fileExists(atPath: sessionURL.path, isDirectory: &isDirectory),
                   isDirectory.boolValue {
                    return sessionURL
                }
            }
            return nil
        }

        return projectURLs.compactMap { projectURL -> URL? in
            guard let sessionURLs = try? fileManager.contentsOfDirectory(
                at: projectURL,
                includingPropertiesForKeys: [.contentModificationDateKey, .isDirectoryKey],
                options: [.skipsHiddenFiles]
            ) else {
                return nil
            }
            return sessionURLs
                .filter { url in
                    ((try? url.resourceValues(forKeys: [.isDirectoryKey]).isDirectory) ?? false)
                        && fileManager.fileExists(atPath: url.appendingPathComponent("chat_history.jsonl").path)
                }
                .max { lhs, rhs in
                    grokHistoryModifiedDate(lhs) < grokHistoryModifiedDate(rhs)
                }
        }.max { lhs, rhs in
            grokHistoryModifiedDate(lhs) < grokHistoryModifiedDate(rhs)
        }
    }

    private func grokHistoryModifiedDate(_ sessionURL: URL) -> Date {
        (try? sessionURL
            .appendingPathComponent("chat_history.jsonl")
            .resourceValues(forKeys: [.contentModificationDateKey])
            .contentModificationDate) ?? .distantPast
    }

    private func grokEncodedSessionCWDs(_ cwd: String) -> [String] {
        guard let rawCwd = grokNormalizedHookPath(cwd) else {
            return []
        }
        var seen = Set<String>()
        return [rawCwd, (rawCwd as NSString).standardizingPath]
            .map(grokEncodedSessionCWD)
            .filter { seen.insert($0).inserted }
    }

    private func grokNormalizedHookPath(_ value: String?) -> String? {
        let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let trimmed, !trimmed.isEmpty else {
            return nil
        }
        return trimmed
    }

    private func grokSessionsRoot(env: [String: String]) -> URL {
        let rawHome = normalizedHookValue(env["GROK_HOME"]) ?? "~/.grok"
        return URL(fileURLWithPath: NSString(string: rawHome).expandingTildeInPath, isDirectory: true)
            .appendingPathComponent("sessions", isDirectory: true)
    }

    private func grokEncodedSessionCWD(_ cwd: String) -> String {
        var encoded = ""
        for byte in cwd.utf8 {
            let isUnreserved = (byte >= 0x41 && byte <= 0x5A)
                || (byte >= 0x61 && byte <= 0x7A)
                || (byte >= 0x30 && byte <= 0x39)
                || byte == 0x2D
                || byte == 0x2E
                || byte == 0x5F
                || byte == 0x7E
            if isUnreserved {
                encoded.append(Character(UnicodeScalar(byte)))
            } else {
                encoded.append(String(format: "%%%02X", byte))
            }
        }
        return encoded
    }

    private func classifyAgentHookNotification(
        def: AgentHookDef,
        signal: String,
        message: String,
        isFallback: Bool
    ) -> AgentHookNotificationSummary {
        AgentHookNotificationClassifier.classify(
            displayName: def.displayName,
            signal: signal,
            message: message,
            isFallback: isFallback
        )
    }

    private func classifyClaudeNotification(signal: String, message: String) -> (subtitle: String, body: String) {
        let lower = "\(signal) \(message)".lowercased()
        if lower.contains("permission") || lower.contains("approve") || lower.contains("approval") || lower.contains("permission_prompt") {
            let body = message.isEmpty ? "Approval needed" : message
            return ("Permission", body)
        }
        if lower.contains("error") || lower.contains("failed") || lower.contains("exception") {
            let body = message.isEmpty ? "Claude reported an error" : message
            return ("Error", body)
        }
        if AgentHookNotificationClassifier.containsCompletionCue(lower) {
            let body = message.isEmpty ? "Task completed" : message
            return ("Completed", body)
        }
        if AgentHookNotificationClassifier.containsWaitingCue(lower) {
            let body = message.isEmpty ? "Waiting for input" : message
            return ("Waiting", body)
        }
        // Use the message directly if it's meaningful (not a generic placeholder).
        if !message.isEmpty, message != "Claude needs your input" {
            return ("Attention", message)
        }
        return ("Attention", "Claude needs your attention")
    }

    private func sanitizeNotificationField(_ value: String) -> String {
        return normalizedSingleLine(value)
            .replacingOccurrences(of: "|", with: "¦")
    }

    func notificationPayload(
        title: String,
        subtitle: String,
        body: String,
        meta: String? = nil
    ) -> String {
        let base = "\(sanitizeNotificationField(title))|\(sanitizeNotificationField(subtitle))|\(sanitizeNotificationField(body))"
        // `meta` is a structured, delimiter-safe tag: it has no
        // "|" or spaces, so it is NOT sanitized and rides as a 4th pipe segment.
        // Omitting it reproduces the exact 3-field payload every legacy caller sends.
        guard let meta, !meta.isEmpty else { return base }
        return base + "|" + meta
    }

    /// True when a Claude `Stop`/`Notification` payload reports unfinished
    /// background work: any `background_tasks` entry still `running`, or a
    /// non-empty `session_crons`. A `nil` rawObject or absent keys (claude
    /// < 2.1.145) yield `false`, so older clients behave exactly as before.
    /// Pure over `rawObject` so both the notify gate and the hibernation
    /// lifecycle decision can share it (mirrors `hasActiveAntigravityBackgroundWork`).
    func hasActiveClaudeBackgroundWork(_ parsedInput: ClaudeHookParsedInput) -> Bool {
        guard let obj = parsedInput.rawObject else { return false }
        if let crons = obj["session_crons"] as? [Any], !crons.isEmpty { return true }
        if let tasks = obj["background_tasks"] as? [[String: Any]] {
            return tasks.contains { ($0["status"] as? String) == "running" }
        }
        return false
    }

    private func mergedNodeOptions(existing: String?, restoreModulePath: String) -> String {
        let requireOption = "--require=\(restoreModulePath)"
        let memoryOption = "--max-old-space-size=4096"
        let cleanedExisting = cleanedNodeOptions(existing)
        guard !cleanedExisting.isEmpty else {
            return "\(requireOption) \(memoryOption)"
        }
        return "\(requireOption) \(memoryOption) \(cleanedExisting)"
    }

    private func cleanedNodeOptions(_ existing: String?) -> String {
        let tokens = (existing ?? "")
            .split(whereSeparator: \.isWhitespace)
            .map(String.init)
        guard !tokens.isEmpty else { return "" }

        var filtered: [String] = []
        var index = 0
        while index < tokens.count {
            let token = tokens[index]
            if token == "--max-old-space-size" {
                index += min(2, tokens.count - index)
                continue
            }
            if token.hasPrefix("--max-old-space-size=") {
                index += 1
                continue
            }
            filtered.append(token)
            index += 1
        }
        return filtered.joined(separator: " ")
    }

    private func normalizedNodeOptionsForRestore(_ existing: String) -> String {
        let tokens = existing
            .split(whereSeparator: \.isWhitespace)
            .map(String.init)
        guard !tokens.isEmpty else { return "" }

        var normalized: [String] = []
        var index = 0
        while index < tokens.count {
            let token = tokens[index]
            if token == "--max-old-space-size", index + 1 < tokens.count {
                normalized.append("--max-old-space-size=\(tokens[index + 1])")
                index += 2
                continue
            }
            normalized.append(token)
            index += 1
        }
        return normalized.joined(separator: " ")
    }

    // MARK: - Codex hooks

    /// The hooks.json content that cmux installs into ~/.codex/.
    /// Each hook calls `cmux hooks codex <event>` which gracefully no-ops
    /// when not running inside cmux. The command checks for cmux on PATH
    /// first so it silently succeeds even when cmux is not installed
    /// (e.g. user opened codex in a non-cmux terminal).

    // MARK: - Agent PID inference

    private func agentPIDFromHookEnvironment(agentName: String, env: [String: String]) -> Int? {
        let envKey: String
        switch agentName {
        case "claude": envKey = "CMUX_CLAUDE_PID"
        case "codex": envKey = "CMUX_CODEX_PID"
        case "cursor": envKey = "CMUX_CURSOR_PID"
        case "gemini": envKey = "CMUX_GEMINI_PID"
        case "antigravity": envKey = "CMUX_ANTIGRAVITY_PID"
        case "rovodev": envKey = "CMUX_ROVODEV_PID"
        case "hermes-agent": envKey = "CMUX_HERMES_AGENT_PID"
        case "copilot": envKey = "CMUX_COPILOT_PID"
        case "kiro": envKey = "CMUX_KIRO_PID"
        default: return nil
        }
        guard let raw = env[envKey]?.trimmingCharacters(in: .whitespacesAndNewlines),
              let pid = Int(raw),
              pid > 0 else {
            return nil
        }
        return pid
    }

    private func inferredAgentPID() -> Int? {
        var candidate = getppid()
        var remainingWrapperSkips = 8

        while candidate > 1, remainingWrapperSkips > 0 {
            guard let processName = processName(for: candidate) else { break }
            if !agentHookWrapperProcessNames.contains(processName) {
                break
            }
            let next = parentPID(of: candidate)
            guard next > 1, next != candidate else { break }
            candidate = next
            remainingWrapperSkips -= 1
        }

        return candidate > 1 ? Int(candidate) : nil
    }

    func claudeAgentPID(from env: [String: String]) -> Int? {
        guard let raw = env["CMUX_CLAUDE_PID"]?
            .trimmingCharacters(in: .whitespacesAndNewlines),
            let pid = Int(raw),
            pid > 0 else {
            return nil
        }
        return pid
    }

    func shouldSuppressNestedAgentVisibleMutations(
        currentAgentPID: Int?,
        nestedPromptEvent: Bool = false,
        transcriptSubagentSession: Bool = false,
        env: [String: String]
    ) -> Bool {
        if let override = normalizedHookValue(env["CMUX_AGENT_HOOK_SUPPRESS_VISIBLE_MUTATIONS"])?.lowercased(),
           Self.parseHookBoolean(override) == true {
            return true
        }

        guard subagentNotificationSuppressionEnabled(env: env) else {
            return false
        }

        if nestedPromptEvent {
            return true
        }

        if managedSubagentVisibleMutationSuppressionRequested(env: env) {
            return true
        }

        if transcriptSubagentSession {
            return true
        }

        guard let currentAgentPID, currentAgentPID > 1 else {
            return false
        }

        var candidate = pid_t(currentAgentPID)
        var agentProcessCount = 0
        var remainingAncestors = 32
        while candidate > 1, remainingAncestors > 0 {
            if nativeProcessDescribesKnownAgent(for: candidate) {
                agentProcessCount += 1
                if agentProcessCount >= 2 {
                    return true
                }
            }
            let next = parentPID(of: candidate)
            guard next > 1, next != candidate else {
                break
            }
            candidate = next
            remainingAncestors -= 1
        }
        return false
    }

    private func managedSubagentVisibleMutationSuppressionRequested(env: [String: String]) -> Bool {
        guard let raw = normalizedHookValue(env[managedSubagentEnvironmentKey]),
              let parsed = Self.parseHookBoolean(raw) else {
            return false
        }
        return parsed
    }

    private func subagentNotificationSuppressionEnabled(env: [String: String]) -> Bool {
        if let raw = normalizedHookValue(env[suppressSubagentNotificationsEnvironmentKey]),
           let parsed = Self.parseHookBoolean(raw) {
            return parsed
        }
        for defaults in appDefaultsCandidates(env: env) {
            if defaults.object(forKey: suppressSubagentNotificationsDefaultsKey) != nil {
                return defaults.bool(forKey: suppressSubagentNotificationsDefaultsKey)
            }
        }
        return true
    }

    private func appDefaultsCandidates(env: [String: String]) -> [UserDefaults] {
        var candidates: [UserDefaults] = []
        if let bundleId = normalizedHookValue(env["CMUX_BUNDLE_ID"]),
           let defaults = UserDefaults(suiteName: bundleId) {
            candidates.append(defaults)
        }
        candidates.append(.standard)
        return candidates
    }

    private static func parseHookBoolean(_ rawValue: String) -> Bool? {
        switch rawValue.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
        case "1", "true", "yes", "on", "enabled":
            return true
        case "0", "false", "no", "off", "disabled":
            return false
        default:
            return nil
        }
    }

    private func nativeProcessDescribesKnownAgent(for pid: pid_t) -> Bool {
        AgentLaunchCaptureTrust.nativeProcessDescribesKnownAgent(
            processName: processName(for: pid),
            arguments: processArguments(for: pid) ?? []
        )
    }

    private func parentPID(of pid: pid_t) -> pid_t {
        var info = kinfo_proc()
        var size = MemoryLayout<kinfo_proc>.size
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, pid]
        guard sysctl(&mib, 4, &info, &size, nil, 0) == 0 else {
            return -1
        }
        return info.kp_eproc.e_ppid
    }

    private func processName(for pid: pid_t) -> String? {
        let process = Process()
        let stdout = Pipe()
        process.executableURL = URL(fileURLWithPath: "/bin/ps")
        process.arguments = ["-p", String(pid), "-o", "comm="]
        process.standardOutput = stdout
        process.standardError = FileHandle.nullDevice

        do {
            try cliRunProcess(process)
        } catch {
            return nil
        }
        process.waitUntilExit()
        guard process.terminationStatus == 0 else { return nil }

        let data = stdout.fileHandleForReading.readDataToEndOfFileOrEmpty()
        guard let output = String(data: data, encoding: .utf8)?
            .trimmingCharacters(in: .whitespacesAndNewlines),
            !output.isEmpty else {
            return nil
        }
        return URL(fileURLWithPath: output).lastPathComponent.lowercased()
    }

    private func processArguments(for pid: pid_t) -> [String]? {
        var argMax: Int32 = 0
        var argMaxSize = MemoryLayout<Int32>.size
        var argMaxMib: [Int32] = [CTL_KERN, KERN_ARGMAX]
        guard sysctl(&argMaxMib, UInt32(argMaxMib.count), &argMax, &argMaxSize, nil, 0) == 0,
              argMax > 0 else {
            return nil
        }

        var buffer = [UInt8](repeating: 0, count: Int(argMax))
        var size = buffer.count
        var mib: [Int32] = [CTL_KERN, KERN_PROCARGS2, pid]
        let status = buffer.withUnsafeMutableBytes { rawBuffer in
            sysctl(&mib, UInt32(mib.count), rawBuffer.baseAddress, &size, nil, 0)
        }
        guard status == 0, size > MemoryLayout<Int32>.size else {
            return nil
        }

        var argc: Int32 = 0
        withUnsafeMutableBytes(of: &argc) { argcBytes in
            for offset in 0..<MemoryLayout<Int32>.size {
                argcBytes[offset] = buffer[offset]
            }
        }
        guard argc > 0 else { return nil }

        var index = MemoryLayout<Int32>.size
        while index < size, buffer[index] != 0 {
            index += 1
        }
        while index < size, buffer[index] == 0 {
            index += 1
        }

        var arguments: [String] = []
        for _ in 0..<argc {
            guard index < size else { break }
            let start = index
            while index < size, buffer[index] != 0 {
                index += 1
            }
            guard index > start else { break }
            if let value = String(bytes: buffer[start..<index], encoding: .utf8) {
                arguments.append(value)
            }
            while index < size, buffer[index] == 0 {
                index += 1
            }
        }

        return arguments.isEmpty ? nil : arguments
    }

    /// Whether the Claude process this hook fired from was launched with
    /// `--fork-session`. Such launches report the PARENT session id in
    /// SessionStart (the forked id is only minted at the first UserPromptSubmit),
    /// so hook state keyed by the reported id must not be rebound to the fork
    /// pane. Reads the raw launch argv — the sanitized launch-command record
    /// strips `--fork-session`. https://github.com/manaflow-ai/cmux/issues/5908
    private func isClaudeForkSessionLaunch(env: [String: String], fallbackPID: Int?) -> Bool {
        guard let arguments = claudeRawLaunchArguments(env: env, fallbackPID: fallbackPID) else {
            return false
        }
        return claudeLaunchArgumentsContainForkSession(arguments)
    }

    /// Accept the same flag forms the launch sanitizer strips: bare
    /// `--fork-session` and `--fork-session=<value>` (unless explicitly false).
    private func claudeLaunchArgumentsContainForkSession(_ arguments: [String]) -> Bool {
        arguments.contains { argument in
            if argument == "--fork-session" { return true }
            guard argument.hasPrefix("--fork-session=") else { return false }
            let value = argument.dropFirst("--fork-session=".count)
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .lowercased()
            return !["false", "0", "no", "off"].contains(value)
        }
    }

    /// The parent session id a `--resume <parent> --fork-session` launch was
    /// forked from, or nil when this hook's process is not a fork launch. Hook
    /// payloads carrying this id (SessionStart before the forked id is minted,
    /// and SessionEnd when the fork exits before its first prompt) describe a
    /// conversation another pane still owns and must not mutate or consume its
    /// record. https://github.com/manaflow-ai/cmux/issues/5908
    private func claudeForkSessionParentId(env: [String: String], fallbackPID: Int?) -> String? {
        guard let arguments = claudeRawLaunchArguments(env: env, fallbackPID: fallbackPID),
              claudeLaunchArgumentsContainForkSession(arguments) else {
            return nil
        }
        for (index, argument) in arguments.enumerated() {
            if argument == "--resume" || argument == "-r" {
                guard index + 1 < arguments.count else { return nil }
                return normalizedHookValue(arguments[index + 1])
            }
            if argument.hasPrefix("--resume=") {
                return normalizedHookValue(String(argument.dropFirst("--resume=".count)))
            }
        }
        return nil
    }

    private func claudeRawLaunchArguments(env: [String: String], fallbackPID: Int?) -> [String]? {
        decodeNULSeparatedBase64(env["CMUX_AGENT_LAUNCH_ARGV_B64"])
            ?? fallbackPID.flatMap { self.processArguments(for: pid_t($0)) }
    }

    private func agentLaunchCommandFromEnvironment(
        _ env: [String: String],
        fallbackPID: Int?,
        fallbackKind: String,
        cwd: String?
    ) -> AgentHookLaunchCommandRecord? {
        // `CMUX_AGENT_LAUNCH_*` leaks to every descendant of an agent process, so an
        // agent started from inside another agent's session inherits the ANCESTOR's
        // launch capture (codex under claude carries claude's argv). Trust the env
        // capture only when its launcher describes this hook's agent kind; otherwise
        // fall back to the agent's own process argv and kind.
        let envLauncher = normalizedHookValue(env["CMUX_AGENT_LAUNCH_KIND"])
        let envCaptureIsTrusted = AgentLaunchCaptureTrust.launcherDescribesKind(
            envLauncher,
            kind: fallbackKind
        )
        let envArguments = envCaptureIsTrusted
            ? decodeNULSeparatedBase64(env["CMUX_AGENT_LAUNCH_ARGV_B64"])
            : nil
        var processArguments = fallbackPID.flatMap { fallbackPID -> [String]? in
            let pid = pid_t(fallbackPID)
            let candidate = self.processArguments(for: pid)
            guard AgentLaunchCaptureTrust.nativeProcessDescribesKind(
                processName: processName(for: pid),
                arguments: candidate,
                kind: fallbackKind
            ) else { return nil }
            return candidate
        }
        if let candidate = processArguments,
           AgentLaunchCaptureTrust.argvLooksLikeShellWrapper(candidate) {
            // The PID fallback resolved to a shell dispatcher (e.g. the hook's own
            // `sh -c …` wrapper), not the agent. That argv is not a launch.
            processArguments = nil
        }
        let arguments = envArguments ?? processArguments
        let launcher = envCaptureIsTrusted ? (envLauncher ?? fallbackKind) : fallbackKind
        let workingDirectory = (envCaptureIsTrusted ? normalizedHookValue(env["CMUX_AGENT_LAUNCH_CWD"]) : nil)
            ?? normalizedHookValue(cwd)
            ?? normalizedHookValue(env["PWD"])
        let environment = selectedAgentLaunchEnvironment(from: env, kind: launcher)

        // Fallback when the launch argv is genuinely UNAVAILABLE: plain `codex` with no cmux launcher
        // (no CMUX_AGENT_LAUNCH_ARGV_B64) and an unresolved/exited PID, so processArguments returns nil.
        // The argv is gone, but the agent's launch env may still carry a non-default home that
        // resume/fork MUST reproduce or the session won't be found — above all CODEX_HOME when codex
        // runs under the subrouter account manager (~/.codex-accounts/<account>), also CLAUDE_CONFIG_DIR
        // for Claude. AgentResumeCommandBuilder then prefixes it ahead of the kind's fallback verb
        // (`CODEX_HOME=<home> codex resume <id>`), while launcher/kind resolution still gates whether a
        // resume command is produced (omx/omc and unknown kinds stay non-resumable). Empty selected env
        // keeps the historical nil. This deliberately does NOT cover a captured-but-rejected argv (see
        // the sanitizer guard below), so non-restorable invocations stay non-resumable.
        func environmentOnlyRecord() -> AgentHookLaunchCommandRecord? {
            guard !environment.isEmpty else {
                return fallbackKind == "codex" ? AgentHookLaunchCommandRecord(launcher: launcher, executablePath: nil, arguments: [], workingDirectory: workingDirectory, environment: nil, capturedAt: Date().timeIntervalSince1970, source: "default") : nil
            }
            return AgentHookLaunchCommandRecord(
                launcher: launcher,
                executablePath: nil,
                arguments: [],
                workingDirectory: workingDirectory,
                environment: environment,
                capturedAt: Date().timeIntervalSince1970,
                source: "environment"
            )
        }

        guard let arguments, !arguments.isEmpty else {
            return environmentOnlyRecord()
        }

        let executablePath = (envCaptureIsTrusted ? normalizedHookValue(env["CMUX_AGENT_LAUNCH_EXECUTABLE"]) : nil)
            ?? arguments.first
        guard let sanitizedArguments = sanitizedAgentLaunchArguments(
            arguments,
            launcher: launcher,
            fallbackKind: fallbackKind
        ) else {
            // Sanitized-away argv means a non-restorable invocation. Do not
            // replace it with an env-only fallback.
            return AgentHookLaunchCommandRecord(launcher: launcher, executablePath: executablePath, arguments: [], workingDirectory: workingDirectory, environment: nil, capturedAt: Date().timeIntervalSince1970, source: "rejected")
        }
        let source = envArguments == nil ? "process" : "environment"

        return AgentHookLaunchCommandRecord(
            launcher: launcher,
            executablePath: executablePath,
            arguments: sanitizedArguments,
            workingDirectory: workingDirectory,
            environment: environment.isEmpty ? nil : environment,
            capturedAt: Date().timeIntervalSince1970,
            source: source
        )
    }

    private func publishAgentSurfaceResumeBinding(
        client: SocketClient,
        workspaceId: String,
        surfaceId: String,
        kind: String,
        displayName: String,
        sessionId: String,
        cwd: String?,
        launchCommand: AgentHookLaunchCommandRecord?,
        observedPermissionMode: String? = nil
    ) {
        if !agentHookSessionHasDurableResumeEvidence(kind: kind, launchCommand: launchCommand) {
            clearAgentSurfaceResumeBinding(client: client, workspaceId: workspaceId, surfaceId: surfaceId, sessionId: sessionId)
            return
        }
        let resumeEnvironment = agentSurfaceResumeEnvironment(kind: kind, environment: launchCommand?.environment)
        // Pin to the launch directory, not drift-prone runtime cwd.
        let resumeWorkingDirectory = AgentResumeWorkingDirectory().resolve(
            kind: kind,
            runtimeCwd: cwd,
            launchWorkingDirectory: launchCommand?.workingDirectory
        )
        guard let command = agentSurfaceResumeCommand(
            kind: kind,
            sessionId: sessionId,
            launchCommand: launchCommand,
            workingDirectory: resumeWorkingDirectory,
            environment: resumeEnvironment,
            observedPermissionMode: observedPermissionMode
        ) else {
            clearAgentSurfaceResumeBinding(
                client: client,
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                sessionId: sessionId
            )
            return
        }
        var params: [String: Any] = [
            "workspace_id": workspaceId,
            "surface_id": surfaceId,
            "name": displayName,
            "kind": kind,
            "checkpoint_id": sessionId,
            "source": "agent-hook",
            "command": command,
            "auto_resume": true
        ]
        if let resumeWorkingDirectory {
            params["cwd"] = resumeWorkingDirectory
        }
        if let resumeEnvironment, !resumeEnvironment.isEmpty {
            params["environment"] = resumeEnvironment
        }
        _ = try? client.sendV2(method: "surface.resume.set", params: params)
    }

    private func clearAgentSurfaceResumeBinding(
        client: SocketClient,
        workspaceId: String,
        surfaceId: String,
        sessionId: String?
    ) {
        let normalizedSessionId = normalizedHookValue(sessionId)
        var params: [String: Any] = [
            "surface_id": surfaceId,
            "source": "agent-hook"
        ]
        if let normalizedSessionId {
            params["checkpoint_id"] = normalizedSessionId
        }
        _ = try? client.sendV2(method: "surface.resume.clear", params: params)
    }

    private func agentSurfaceResumeCommand(
        kind: String,
        sessionId: String,
        launchCommand: AgentHookLaunchCommandRecord?,
        workingDirectory: String?,
        environment: [String: String]?,
        observedPermissionMode: String? = nil
    ) -> String? {
        let normalizedSessionId = normalizedHookValue(sessionId)
        guard let normalizedSessionId else { return nil }

        let argv: [String]?
        switch AgentResumeArgv().launcherResolution(
            launcher: launchCommand?.launcher,
            sessionId: normalizedSessionId,
            executablePath: launchCommand?.executablePath,
            arguments: launchCommand?.arguments ?? []
        ) {
        case .resolved(let resolved):
            // Wrapper launchers include the claude-teams orphan-respawn path,
            // which must never regain permission state a restored teammate did
            // not explicitly opt into; observed mode applies only below.
            argv = resolved
        case .passthrough:
            argv = AgentResumeArgv().builtInKind(
                kind: kind,
                sessionId: normalizedSessionId,
                executablePath: launchCommand?.executablePath,
                arguments: launchCommand?.arguments ?? [],
                observedPermissionMode: observedPermissionMode
            )
        }

        guard let argv, !argv.isEmpty else { return nil }
        return agentSurfaceResumeShellCommand(
            argv: argv,
            workingDirectory: workingDirectory ?? launchCommand?.workingDirectory,
            kind: kind,
            environment: environment
        )
    }

    private func agentSurfaceResumeShellCommand(
        argv: [String],
        workingDirectory: String?,
        kind: String,
        environment: [String: String]?
    ) -> String {
        var commandParts: [String] = []
        commandParts.append(contentsOf: argv)

        let cwd = normalizedHookValue(workingDirectory)
        let sanitizedCommandParts = AgentLaunchSanitizer.removingSavedWorkingDirectoryOptions(
            from: commandParts,
            workingDirectory: cwd
        )
        let resumeCommandParts = kind == "hermes-agent"
            ? hermesAgentArgumentsByReplacingOpenAICodexProvider(sanitizedCommandParts)
            : sanitizedCommandParts
        // Route the claude executable through the wrapper shim token so the executed
        // command re-injects cmux hooks even when run via the `$SHELL -lic` restore
        // launcher (where the integration's PATH shim / `claude()` function are not
        // active). The token is POSIX-only and the launcher dispatches through the
        // user's shell (fish/csh/tcsh included), so token-bearing commands are wrapped
        // in `/bin/sh -c '…'` to parse everywhere; the cwd guard below stays outside so
        // cd-prefix rewriting keeps composing. https://github.com/manaflow-ai/cmux/issues/5639
        var command = kind == "claude"
            ? AgentResumeArgv.renderedPortableClaudeResumeShellCommand(parts: resumeCommandParts, quote: cliShellQuote)
            : resumeCommandParts.map(cliShellQuote).joined(separator: " ")
        if kind == "hermes-agent" {
            command = hermesAgentSubrouterResumeCommand(
                command,
                arguments: resumeCommandParts,
                environment: environment
            )
        }
        if let cwd {
            let quotedCwd = cliShellQuote(cwd)
            // No POSIX `{ …; }` grouping: the binding runs verbatim in the login shell,
            // which may be fish (no brace grouping — issue #6285). `&&`/`||` are an
            // equal-precedence left-associative AND-OR list in sh/bash/zsh/fish, so this
            // is equivalent to the braced form in every shell.
            return "cd -- \(quotedCwd) 2>/dev/null || [ ! -d \(quotedCwd) ] && \(command)"
        }
        return command
    }

    private func hermesAgentSubrouterResumeCommand(
        _ command: String,
        arguments: [String],
        environment: [String: String]?
    ) -> String {
        guard !hermesAgentArgumentsSetModelAPIMode(arguments),
              hermesAgentArgumentsAllowCodexBootstrap(arguments),
              let environment,
              let baseURL = normalizedHookValue(environment[HermesAgentCodexEnvironment.customBaseURLEnvironmentKey]) else {
            return command
        }
        let hermesExecutable = normalizedHookValue(arguments.first) ?? "hermes"

        var bootstrap = [
            "\(cliShellQuote(hermesExecutable)) config set model.provider \(cliShellQuote(HermesAgentCodexEnvironment.defaultProvider)) >/dev/null",
            "\(cliShellQuote(hermesExecutable)) config set model.base_url \(cliShellQuote(baseURL)) >/dev/null",
            "\(cliShellQuote(hermesExecutable)) config set model.api_mode \(cliShellQuote(HermesAgentCodexEnvironment.codexResponsesAPIMode)) >/dev/null"
        ]
        if let model = HermesAgentCodexEnvironment.defaultCodexModel(
            environment: environment,
            ambientEnvironment: ProcessInfo.processInfo.environment
        ) {
            bootstrap.append("\(cliShellQuote(hermesExecutable)) config set model.default \(cliShellQuote(model)) >/dev/null")
        }
        return bootstrap.joined(separator: " && ") + " && " + command
    }

    private func hermesAgentArgumentsByReplacingOpenAICodexProvider(_ arguments: [String]) -> [String] {
        var result: [String] = []
        var index = 0
        while index < arguments.count {
            let argument = arguments[index]
            if argument == "--provider", index + 1 < arguments.count {
                result.append(argument)
                let provider = arguments[index + 1]
                result.append(provider == "openai-codex" ? HermesAgentCodexEnvironment.defaultProvider : provider)
                index += 2
                continue
            }
            if argument == "--provider=openai-codex" {
                result.append("--provider=\(HermesAgentCodexEnvironment.defaultProvider)")
            } else {
                result.append(argument)
            }
            index += 1
        }
        return result
    }

    private func hermesAgentArgumentsSetModelAPIMode(_ arguments: [String]) -> Bool {
        arguments.contains { $0.contains("model.api_mode") }
    }

    private func hermesAgentArgumentsAllowCodexBootstrap(_ arguments: [String]) -> Bool {
        guard let provider = hermesAgentProviderArgument(arguments) else {
            return true
        }
        return provider == HermesAgentCodexEnvironment.defaultProvider || provider == "openai-codex"
    }

    private func hermesAgentProviderArgument(_ arguments: [String]) -> String? {
        var index = 0
        while index < arguments.count {
            let argument = arguments[index]
            if argument == "--provider", index + 1 < arguments.count {
                return arguments[index + 1]
            }
            if argument.hasPrefix("--provider=") {
                return String(argument.dropFirst("--provider=".count))
            }
            index += 1
        }
        return nil
    }

    private func agentSurfaceResumeEnvironment(
        kind: String,
        environment: [String: String]?
    ) -> [String: String]? {
        guard let environment else { return nil }
        let selected = selectedAgentLaunchEnvironment(from: environment, kind: kind)
        guard !selected.isEmpty else { return nil }

        let claudeAuthKeys: Set<String> = [
            "ANTHROPIC_API_KEY",
            "ANTHROPIC_AUTH_TOKEN",
            "ANTHROPIC_BASE_URL",
            "ANTHROPIC_MODEL",
            "ANTHROPIC_SMALL_FAST_MODEL",
            "CLAUDE_CODE_USE_BEDROCK",
            "CLAUDE_CODE_USE_VERTEX",
            "CLAUDE_CONFIG_DIR"
        ]
        var resolved = selected
        if kind == "claude" {
            let preservedClaudeKeys = selected.keys.sorted().filter { claudeAuthKeys.contains($0) }
            if !preservedClaudeKeys.isEmpty {
                resolved["CMUX_PRESERVE_CLAUDE_AUTH_SELECTION_ENV"] = "1"
                resolved["CMUX_PRESERVE_CLAUDE_AUTH_SELECTION_ENV_KEYS"] = preservedClaudeKeys.joined(separator: ",")
            }
        }
        return resolved
    }

    private func decodeNULSeparatedBase64(_ rawValue: String?) -> [String]? {
        guard let rawValue = normalizedHookValue(rawValue),
              let data = Data(base64Encoded: rawValue) else {
            return nil
        }
        var parts: [String] = []
        var start = data.startIndex
        var index = data.startIndex
        while index < data.endIndex {
            if data[index] == 0 {
                guard let value = String(data: data[start..<index], encoding: .utf8) else {
                    return nil
                }
                parts.append(value)
                start = data.index(after: index)
            }
            index = data.index(after: index)
        }
        if start < data.endIndex {
            guard let value = String(data: data[start..<data.endIndex], encoding: .utf8) else {
                return nil
            }
            parts.append(value)
        }
        return parts.isEmpty ? nil : parts
    }

    private func selectedAgentLaunchEnvironment(from env: [String: String], kind: String? = nil) -> [String: String] {
        var selected = AgentLaunchEnvironmentPolicy().selectedEnvironment(from: env, kind: kind)
        if kind == "hermes-agent" {
            selected = HermesAgentCodexEnvironment.applyingDefaultCodexBaseURL(
                to: selected,
                ambientEnvironment: env
            )
        }
        return selected
    }

    func normalizedHookValue(_ value: String?) -> String? {
        guard let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines),
              !trimmed.isEmpty else {
            return nil
        }
        return trimmed
    }

    func agentHookStatePath(sessionStoreSuffix: String, env: [String: String]) -> String {
        let filename = "\(sessionStoreSuffix)-hook-sessions.json"
        guard let overrideDirectory = normalizedHookValue(env["CMUX_AGENT_HOOK_STATE_DIR"]) else {
            return "~/.cmuxterm/\(filename)"
        }
        return URL(fileURLWithPath: NSString(string: overrideDirectory).expandingTildeInPath, isDirectory: true)
            .appendingPathComponent(filename, isDirectory: false)
            .path
    }

    private func sanitizedAgentLaunchArguments(
        _ arguments: [String],
        launcher: String,
        fallbackKind: String
    ) -> [String]? {
        AgentLaunchSanitizer.sanitizedLaunchArguments(
            arguments,
            launcher: launcher,
            fallbackKind: fallbackKind
        )
    }

    // MARK: Generic hook install/uninstall
    func hookCommand(for def: AgentHookDef, event: AgentHookDef.HookEvent) -> String {
        Self.hookCommandString(for: def, event: event)
    }

    /// Shell command the agent runs for a Feed bridge event. 120s timeout
    /// inside the shell is applied via the agent's `timeout` field in the
    /// nested hook config (see `buildHooksDict`); the shell command
    /// itself just dispatches.
    func feedHookCommand(for def: AgentHookDef, agentEvent: String) -> String {
        Self.feedHookCommandString(for: def, agentEvent: agentEvent)
    }

    private func buildHooksDict(for def: AgentHookDef) -> [String: Any] {
        var result: [String: Any] = [:]
        for event in def.events {
            let cmd = hookCommand(for: def, event: event)
            switch def.format {
            case .flat:
                var entries = result[event.agentEvent] as? [[String: Any]] ?? []
                entries.append(["command": cmd])
                result[event.agentEvent] = entries
            case .kiroAgentJSON(let timeoutMs):
                var entries = result[event.agentEvent] as? [[String: Any]] ?? []
                entries.append([
                    "command": cmd,
                    "timeout_ms": max(timeoutMs, 1),
                ] as [String: Any])
                result[event.agentEvent] = entries
            case .nested(let timeoutMs):
                var groups = result[event.agentEvent] as? [[String: Any]] ?? []
                let timeout = nestedHookTimeout(timeoutMs, for: def)
                groups.append([
                    "hooks": [["type": "command", "command": cmd, "timeout": timeout] as [String: Any]]
                ] as [String: Any])
                result[event.agentEvent] = groups
            case .antigravityJSON(let timeoutSeconds):
                var entries = result[event.agentEvent] as? [[String: Any]] ?? []
                entries.append(Self.antigravityHookEntry(
                    command: cmd,
                    timeoutSeconds: timeoutSeconds,
                    eventName: event.agentEvent
                ))
                result[event.agentEvent] = entries
            case .rovoDevYAML, .hermesAgentYAML, .tomlArrayTable:
                break
            }
        }
        // Layer in Feed bridge entries. Blocking approval bridges get a long
        // timeout; Codex telemetry stays short so it never delays Codex's own
        // approval reviewer. Most nested agents use milliseconds. Codex, Grok,
        // and Antigravity hook schemas use seconds, so normalize before writing.
        for agentEvent in def.feedHookEvents {
            let feedCmd = feedHookCommand(for: def, agentEvent: agentEvent)
            let feedTimeoutMs = feedHookTimeoutMs(for: def, agentEvent: agentEvent)
            switch def.format {
            case .flat:
                var entries = result[agentEvent] as? [[String: Any]] ?? []
                entries.append(["command": feedCmd])
                result[agentEvent] = entries
            case .kiroAgentJSON:
                var entries = result[agentEvent] as? [[String: Any]] ?? []
                entries.append([
                    "command": feedCmd,
                    "timeout_ms": feedTimeoutMs,
                ] as [String: Any])
                result[agentEvent] = entries
            case .nested:
                var groups = result[agentEvent] as? [[String: Any]] ?? []
                let timeout = nestedFeedHookTimeout(feedTimeoutMs, for: def)
                groups.append([
                    "hooks": [["type": "command", "command": feedCmd, "timeout": timeout] as [String: Any]]
                ] as [String: Any])
                result[agentEvent] = groups
            case .antigravityJSON:
                var entries = result[agentEvent] as? [[String: Any]] ?? []
                entries.append(Self.antigravityHookEntry(
                    command: feedCmd,
                    timeoutSeconds: Self.timeoutSecondsFromMilliseconds(feedTimeoutMs),
                    eventName: agentEvent
                ))
                result[agentEvent] = entries
            case .rovoDevYAML, .hermesAgentYAML, .tomlArrayTable:
                break
            }
        }
        return result
    }

    private func nestedHookTimeout(_ timeoutMs: Int, for def: AgentHookDef) -> Int {
        guard def.name == "grok" else { return max(timeoutMs, 1) }
        return Self.timeoutSecondsFromMilliseconds(timeoutMs)
    }

    private func nestedFeedHookTimeout(_ timeoutMs: Int, for def: AgentHookDef) -> Int {
        guard def.name == "codex" || def.name == "grok" else { return max(timeoutMs, 1) }
        return Self.timeoutSecondsFromMilliseconds(timeoutMs)
    }

    private func feedHookTimeoutMs(for def: AgentHookDef, agentEvent _: String) -> Int {
        if def.name == "codex" {
            return 5_000
        }
        return 120_000
    }

    private static func timeoutSecondsFromMilliseconds(_ timeoutMs: Int) -> Int {
        let positiveTimeoutMs = max(timeoutMs, 1)
        return ((positiveTimeoutMs - 1) / 1000) + 1
    }

    private static func antigravityHookEntry(
        command: String,
        timeoutSeconds: Int,
        eventName: String
    ) -> [String: Any] {
        let hook: [String: Any] = [
            "type": "command",
            "command": command,
            "timeout": max(timeoutSeconds, 1),
        ]
        switch eventName {
        case "PreToolUse", "PostToolUse":
            return [
                "matcher": "*",
                "hooks": [hook],
            ]
        default:
            return hook
        }
    }

    private static let openCodeSessionPluginMarker = "cmux-opencode-session-plugin-marker"
    private static let openCodeSessionPluginFilename = "cmux-session.js"
    private static let openCodeSessionPluginSource = #"""
// cmux-opencode-session-plugin-marker v1
// Bridges OpenCode session lifecycle events into cmux's restorable session store.
// Installed by `cmux hooks opencode install` or `cmux hooks setup`.
// DO NOT EDIT MANUALLY. cmux upgrades this file in place.

import { spawnSync } from "node:child_process";
import * as fs from "node:fs";
import * as path from "node:path";

const CMUX_PLUGIN_INSTALLED_KEY = Symbol.for("cmux.session.restore.plugin.installed");
const MAX_TRACKED_SESSIONS = 100;
const messageRoles = new Map();
const sessions = new Map();

function firstString(...values) {
  for (const value of values) {
    if (typeof value === "string" && value.trim().length > 0) return value.trim();
  }
  return null;
}

function eventProperties(event) {
  return (event && typeof event === "object" && event.properties) || {};
}

function normalizeText(value, max = 1000) {
  if (typeof value !== "string") return null;
  const normalized = value.replace(/\s+/g, " ").trim();
  if (!normalized) return null;
  return normalized.length > max ? `${normalized.slice(0, max - 3)}...` : normalized;
}

function sessionState(sessionId) {
  const key = sessionId || "unknown";
  if (!sessions.has(key)) {
    sessions.set(key, {
      lastUserMessage: null,
      assistantPreamble: null,
      cwd: null,
      updatedAt: Date.now(),
    });
  }
  const state = sessions.get(key);
  state.updatedAt = Date.now();
  pruneSessions();
  return state;
}

function pruneSessions() {
  while (sessions.size > MAX_TRACKED_SESSIONS) {
    let oldestKey = null;
    let oldestUpdatedAt = Infinity;
    for (const [key, state] of sessions.entries()) {
      const updatedAt = Number(state && state.updatedAt) || 0;
      if (updatedAt < oldestUpdatedAt) {
        oldestUpdatedAt = updatedAt;
        oldestKey = key;
      }
    }
    if (!oldestKey) break;
    dropSession(oldestKey);
  }
}

function dropSession(sessionId) {
  const key = sessionId || "unknown";
  sessions.delete(key);
  for (const [messageId, meta] of messageRoles.entries()) {
    if (meta && meta.sessionId === key) {
      messageRoles.delete(messageId);
    }
  }
}

function contextForSession(sessionId) {
  const state = sessionState(sessionId);
  const context = {};
  if (state.lastUserMessage) context.lastUserMessage = state.lastUserMessage;
  if (state.assistantPreamble) context.assistantPreamble = state.assistantPreamble;
  return Object.keys(context).length > 0 ? context : undefined;
}

function sessionIdFor(event) {
  const props = eventProperties(event);
  return firstString(
    props.info && props.info.id,
    props.sessionID,
    props.sessionId,
    props.session_id,
    props.session && props.session.id,
    event && event.sessionID,
    event && event.sessionId,
    event && event.id
  );
}

function cwdFor(ctx, event) {
  const props = eventProperties(event);
  return firstString(
    props.info && props.info.directory,
    props.cwd,
    props.directory,
    ctx && ctx.directory,
    process.cwd()
  );
}

function resolveExecutable(name) {
  const pathEnv = process.env.PATH || "";
  for (const dir of pathEnv.split(path.delimiter)) {
    if (!dir) continue;
    const candidate = path.join(dir, name);
    try {
      fs.accessSync(candidate, fs.constants.X_OK);
      return candidate;
    } catch (_) {}
  }
  return name;
}

function looksLikeOpenCodeScript(value) {
  if (!value) return false;
  const lower = String(value).toLowerCase();
  return lower.includes("opencode") || lower.includes("open-code");
}

function isOpenCodeInternalWorkerArg(value) {
  if (!value) return false;
  const normalized = String(value).replaceAll("\\", "/");
  return normalized.includes("/$bunfs/") && normalized.endsWith("/tui/worker.js");
}

function withoutOpenCodeInternalWorkerArgs(argv) {
  const result = [];
  for (let i = 0; i < argv.length; i += 1) {
    const value = argv[i];
    if (i > 0 && isOpenCodeInternalWorkerArg(value)) continue;
    result.push(value);
  }
  return result.length > 0 ? result : [resolveExecutable("opencode")];
}

function normalizedLaunchArgv() {
  const raw = Array.isArray(process.argv) ? process.argv.map((value) => String(value)) : [];
  if (raw.length === 0) return [resolveExecutable("opencode")];

  const firstBase = path.basename(raw[0]).toLowerCase();
  if (looksLikeOpenCodeScript(firstBase)) return withoutOpenCodeInternalWorkerArgs(raw);

  let tail = raw.slice(1);
  if (tail.length > 0 && looksLikeOpenCodeScript(tail[0])) {
    tail = tail.slice(1);
  }
  return withoutOpenCodeInternalWorkerArgs([resolveExecutable("opencode"), ...tail]);
}

function base64NulSeparated(values) {
  const bytes = [];
  for (const value of values) {
    bytes.push(Buffer.from(String(value), "utf8"));
    bytes.push(Buffer.from([0]));
  }
  return Buffer.concat(bytes).toString("base64");
}

function hookEnvironment(cwd) {
  const env = { ...process.env };
  delete env.AMP_API_KEY;
  if (!env.CMUX_AGENT_LAUNCH_ARGV_B64) {
    const argv = normalizedLaunchArgv();
    env.CMUX_AGENT_LAUNCH_KIND = "opencode";
    env.CMUX_AGENT_LAUNCH_EXECUTABLE = argv[0] || resolveExecutable("opencode");
    env.CMUX_AGENT_LAUNCH_ARGV_B64 = base64NulSeparated(argv);
    env.CMUX_AGENT_LAUNCH_CWD = cwd || process.cwd();
  }
  return env;
}

function sendHook(subcommand, ctx, event, extra = {}) {
  if (process.env.CMUX_OPENCODE_HOOKS_DISABLED === "1") return;
  if (!process.env.CMUX_SURFACE_ID) return;

  const sessionId = sessionIdFor(event);
  if (!sessionId) return;

  const cwd = cwdFor(ctx, event);
  const state = sessionState(sessionId);
  state.cwd = cwd || state.cwd;
  const payload = {
    session_id: sessionId,
    cwd,
    event: event && event.type,
    hook_event_name: event && event.type,
    ...extra,
  };
  const context = extra.context || contextForSession(sessionId);
  if (context) payload.context = context;
  const cmux = process.env.CMUX_OPENCODE_CMUX_BIN || "cmux";
  try {
    spawnSync(cmux, ["hooks", "opencode", subcommand], {
      input: JSON.stringify(payload),
      encoding: "utf8",
      env: hookEnvironment(cwd),
      stdio: ["pipe", "ignore", "ignore"],
      timeout: 5000,
    });
  } catch (_) {}
}

function trackMessage(event) {
  const props = eventProperties(event);
  if (event && event.type === "message.updated") {
    const info = props.info || props.message || {};
    const messageId = info.id || props.messageID;
    const sessionId = info.sessionID || props.sessionID;
    const role = info.role || props.role;
    if (messageId && sessionId && role) {
      messageRoles.set(messageId, { sessionId, role });
      if (messageRoles.size > 300) {
        messageRoles.delete(messageRoles.keys().next().value);
      }
    }
    return;
  }

  if (!event || event.type !== "message.part.updated") return;
  const part = props.part || {};
  if (part.type !== "text" || !part.messageID) return;
  const meta = messageRoles.get(part.messageID);
  if (!meta) return;
  const text = normalizeText(part.text || part.textDelta || part.content);
  if (!text) return;
  const state = sessionState(meta.sessionId);
  if (meta.role === "user") {
    state.lastUserMessage = text;
  } else if (meta.role === "assistant") {
    state.assistantPreamble = text;
  }
}

const CMUXSessionRestore = async (ctx) => {
  if (globalThis[CMUX_PLUGIN_INSTALLED_KEY]) return {};
  globalThis[CMUX_PLUGIN_INSTALLED_KEY] = true;
  return {
    event: async ({ event }) => {
      trackMessage(event);
      const props = eventProperties(event);
      switch (event && event.type) {
        case "session.created":
          sendHook("session-start", ctx, event);
          break;
        case "session.updated":
          if (props.info && props.info.time && props.info.time.archived) {
            sendHook("session-end", ctx, event);
            dropSession(sessionIdFor(event));
          } else {
            sendHook("session-start", ctx, event);
          }
          break;
        case "session.status":
          if (props.status && props.status.type === "idle") {
            sendHook("stop", ctx, event);
          }
          break;
        case "session.idle":
          sendHook("stop", ctx, event);
          break;
        case "session.deleted":
          sendHook("session-end", ctx, event);
          dropSession(sessionIdFor(event));
          break;
        default:
          break;
      }
    },
  };
};

export { CMUXSessionRestore };
export default CMUXSessionRestore;
"""#

    private func openCodeSessionPluginURL(for def: AgentHookDef) -> URL {
        URL(fileURLWithPath: def.resolvedConfigDir(), isDirectory: true)
            .appendingPathComponent("plugins", isDirectory: true)
            .appendingPathComponent(Self.openCodeSessionPluginFilename, isDirectory: false)
    }

    private func writeOpenCodeSessionPlugin(in configDir: URL) throws {
        let pluginURL = configDir
            .appendingPathComponent("plugins", isDirectory: true)
            .appendingPathComponent(Self.openCodeSessionPluginFilename, isDirectory: false)
        let fm = FileManager.default
        try fm.createDirectory(at: pluginURL.deletingLastPathComponent(), withIntermediateDirectories: true)
        try Self.openCodeSessionPluginSource.write(to: pluginURL, atomically: true, encoding: .utf8)
    }

    private static func openCodePluginListContains(
        _ plugins: [Any],
        spec: String,
        allowVersionSuffix: Bool = false
    ) -> Bool {
        plugins.contains { entry in
            let value: String?
            if let string = entry as? String {
                value = string
            } else if let tuple = entry as? [Any], let string = tuple.first as? String {
                value = string
            } else {
                value = nil
            }
            guard let value else { return false }
            if value == spec { return true }
            if allowVersionSuffix, value.hasPrefix("\(spec)@") { return true }
            if spec == Self.openCodeSessionPluginConfigSpec {
                return value == "./plugins/\(Self.openCodeSessionPluginFilename)"
                    || value.hasSuffix("/plugins/\(Self.openCodeSessionPluginFilename)")
                    || value.hasSuffix("/\(Self.openCodeSessionPluginFilename)")
            }
            return false
        }
    }

    private static func openCodePluginEntryName(_ entry: Any) -> String? {
        if let string = entry as? String {
            return string
        }
        if let tuple = entry as? [Any], let string = tuple.first as? String {
            return string
        }
        return nil
    }

    private static func openCodePluginSpecIsPackage(_ value: String, packageName: String) -> Bool {
        value == packageName || value.hasPrefix("\(packageName)@")
    }

    private static func openCodePluginSpecIsPinnedPackage(_ value: String, packageName: String) -> Bool {
        value.hasPrefix("\(packageName)@")
    }

    private static func openCodePluginEntryReplacingPackage(
        _ entry: Any,
        packageName: String,
        replacementPackageName: String
    ) -> Any {
        guard let name = openCodePluginEntryName(entry),
              openCodePluginSpecIsPackage(name, packageName: packageName)
        else {
            return entry
        }

        let replacementName = "\(replacementPackageName)\(name.dropFirst(packageName.count))"
        if entry is String {
            return replacementName
        }
        if var tuple = entry as? [Any] {
            tuple[0] = replacementName
            return tuple
        }
        return entry
    }

    private static func openCodePluginEntryIsOMOPackage(_ entry: Any) -> Bool {
        guard let name = openCodePluginEntryName(entry) else { return false }
        return openCodePluginSpecIsPackage(name, packageName: omoPluginName)
            || openCodePluginSpecIsPackage(name, packageName: legacyOmoPluginName)
    }

    private static func preferredOMOPluginEntry(from plugins: [Any]) -> Any? {
        var currentPinnedEntry: Any?
        var currentEntry: Any?
        var legacyEntry: Any?

        for entry in plugins {
            guard let name = openCodePluginEntryName(entry) else { continue }
            if openCodePluginSpecIsPackage(name, packageName: omoPluginName) {
                if openCodePluginSpecIsPinnedPackage(name, packageName: omoPluginName) {
                    if currentPinnedEntry == nil {
                        currentPinnedEntry = entry
                    }
                } else if currentEntry == nil {
                    currentEntry = entry
                }
                continue
            }

            if legacyEntry == nil,
               openCodePluginSpecIsPackage(name, packageName: legacyOmoPluginName) {
                legacyEntry = openCodePluginEntryReplacingPackage(
                    entry,
                    packageName: legacyOmoPluginName,
                    replacementPackageName: omoPluginName
                )
            }
        }

        return currentPinnedEntry ?? currentEntry ?? legacyEntry
    }

    private static func openCodePluginListNormalizingOMOPlugin(_ plugins: [Any]) -> [Any] {
        guard let preferredEntry = preferredOMOPluginEntry(from: plugins) else {
            return plugins
        }

        var insertedOMOPlugin = false
        var normalized: [Any] = []
        for entry in plugins {
            if openCodePluginEntryIsOMOPackage(entry) {
                if !insertedOMOPlugin {
                    normalized.append(preferredEntry)
                    insertedOMOPlugin = true
                }
            } else {
                normalized.append(entry)
            }
        }
        return normalized
    }

    private static func openCodePluginListRemovingSessionPlugin(_ plugins: [Any]) -> [Any] {
        plugins.filter { entry in
            guard let value = (entry as? String) ?? ((entry as? [Any])?.first as? String) else {
                return true
            }
            return value != Self.openCodeSessionPluginConfigSpec
                && value != "cmux-session"
                && value != "./plugins/\(Self.openCodeSessionPluginFilename)"
                && !value.hasSuffix("/plugins/\(Self.openCodeSessionPluginFilename)")
                && !value.hasSuffix("/\(Self.openCodeSessionPluginFilename)")
        }
    }

    private func updateOpenCodePluginRegistration(configDir: URL, shouldInstall: Bool) throws -> Bool {
        let configURL = configDir.appendingPathComponent("opencode.json", isDirectory: false); let existingData = try? Data(contentsOf: configURL)
        var config: [String: Any]
        if let data = existingData {
            guard let decoded = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else { throw CLIError(message: "Failed to parse \(configURL.path). Fix the JSON syntax and retry.") }
            config = decoded
        } else {
            config = [:]
        }
        var plugins = Self.openCodePluginListRemovingSessionPlugin((config["plugin"] as? [Any]) ?? [])
        if shouldInstall, !Self.openCodePluginListContains(plugins, spec: Self.openCodeSessionPluginConfigSpec) { plugins.append(Self.openCodeSessionPluginConfigSpec) }
        config["plugin"] = plugins
        let output = try JSONSerialization.data(withJSONObject: config, options: [.prettyPrinted, .sortedKeys])
        if existingData == output { return false }
        try FileManager.default.createDirectory(at: configDir, withIntermediateDirectories: true)
        try output.write(to: configURL, options: .atomic)
        return true
    }

    private func installOpenCodePluginHooks(_ def: AgentHookDef) throws {
        let pluginURL = openCodeSessionPluginURL(for: def)
        let skipConfirm = ProcessInfo.processInfo.arguments.contains("--yes") || ProcessInfo.processInfo.arguments.contains("-y")
        let existing = (try? String(contentsOf: pluginURL, encoding: .utf8)) ?? ""
        let configDir = URL(fileURLWithPath: def.resolvedConfigDir(), isDirectory: true)
        if existing == Self.openCodeSessionPluginSource {
            print(try updateOpenCodePluginRegistration(configDir: configDir, shouldInstall: true) ? "OpenCode hooks installed at \(pluginURL.path)" : "OpenCode hooks already up to date at \(pluginURL.path)")
            return
        }
        if !existing.isEmpty, !existing.contains(Self.openCodeSessionPluginMarker) { throw CLIError(message: "\(pluginURL.path) exists and is not a cmux plugin; leaving it alone") }
        if !skipConfirm {
            print("Will write OpenCode cmux plugin to \(pluginURL.path):")
            print(Self.openCodeSessionPluginSource)
            print("\nProceed? [y/N] ", terminator: "")
            guard readLine()?.lowercased().hasPrefix("y") == true else {
                print("Aborted.")
                return
            }
        }
        try writeOpenCodeSessionPlugin(in: configDir)
        _ = try updateOpenCodePluginRegistration(configDir: configDir, shouldInstall: true)
        print("OpenCode hooks installed at \(pluginURL.path)")
    }

    private func uninstallOpenCodePluginHooks(_ def: AgentHookDef) throws {
        let fm = FileManager.default
        let pluginURL = openCodeSessionPluginURL(for: def)
        guard fm.fileExists(atPath: pluginURL.path) else {
            print("No OpenCode cmux plugin found at \(pluginURL.path)")
            return
        }
        let existing = (try? String(contentsOf: pluginURL, encoding: .utf8)) ?? ""
        guard existing.contains(Self.openCodeSessionPluginMarker) else {
            print("Refusing to remove \(pluginURL.path): missing cmux marker")
            return
        }
        try fm.removeItem(at: pluginURL)
        _ = try updateOpenCodePluginRegistration(
            configDir: URL(fileURLWithPath: def.resolvedConfigDir(), isDirectory: true),
            shouldInstall: false
        )
        print("Removed OpenCode cmux plugin from \(pluginURL.path)")
    }

    func readAgentHookConfig(filePath: String, displayName: String) throws -> String {
        let fm = FileManager.default
        guard fm.fileExists(atPath: filePath) else { return "" }
        do {
            return try String(contentsOfFile: filePath, encoding: .utf8)
        } catch {
            throw CLIError(message: "\(filePath) exists but could not be read. Fix permissions or remove it before installing \(displayName) hooks.")
        }
    }

    private static let antigravityHookGroupName = "cmux"

    private func installAntigravityHooks(_ def: AgentHookDef) throws {
        let fm = FileManager.default
        let configDir = def.resolvedConfigDir()
        let filePath = "\(configDir)/\(def.configFile)"
        let skipConfirm = ProcessInfo.processInfo.arguments.contains("--yes")
            || ProcessInfo.processInfo.arguments.contains("-y")

        let configDirectoryFileError = String.localizedStringWithFormat(
            String(
                localized: "cli.hooks.error.configDirectoryIsFile",
                defaultValue: "cmux could not create the hooks directory: a file exists at %@; remove or rename the conflicting file and re-run `cmux hooks setup`"
            ),
            configDir
        )
        var isConfigDirectory = ObjCBool(false)
        let configPathExists = fm.fileExists(atPath: configDir, isDirectory: &isConfigDirectory)
        if configPathExists, !isConfigDirectory.boolValue {
            throw CLIError(message: configDirectoryFileError)
        }
        if !configPathExists {
            do {
                try fm.createDirectory(atPath: configDir, withIntermediateDirectories: true)
            } catch {
                throw CLIError(message: configDirectoryFileError)
            }
        }

        var existing: [String: Any] = [:]
        if let data = fm.contents(atPath: filePath) {
            guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
                throw CLIError(message: String.localizedStringWithFormat(
                    String(
                        localized: "cli.hooks.antigravity.error.invalidJSON",
                        defaultValue: "%@ exists but is not valid JSON. Fix or remove it before installing hooks."
                    ),
                    filePath
                ))
            }
            existing = json
        }

        let newGroup = buildHooksDict(for: def)
        existing[Self.antigravityHookGroupName] = newGroup

        let newData = try JSONSerialization.data(withJSONObject: existing, options: [.prettyPrinted, .sortedKeys])
        let newString = String(data: newData, encoding: .utf8) ?? "{}"
        let oldString: String = {
            guard let data = fm.contents(atPath: filePath),
                  let json = try? JSONSerialization.jsonObject(with: data),
                  let pretty = try? JSONSerialization.data(withJSONObject: json, options: [.prettyPrinted, .sortedKeys]),
                  let string = String(data: pretty, encoding: .utf8) else {
                return ""
            }
            return string
        }()

        if oldString == newString {
            print(String.localizedStringWithFormat(
                String(
                    localized: "cli.hooks.antigravity.alreadyUpToDate",
                    defaultValue: "%@ hooks already up to date at %@"
                ),
                def.displayName,
                filePath
            ))
            return
        }
        if !skipConfirm {
            Self.printInstallPreview(
                path: filePath,
                oldContent: oldString,
                newContent: newString,
                fallbackContent: newString
            )
            print(String(
                localized: "cli.hooks.antigravity.confirmProceed",
                defaultValue: "\nProceed? [y/N] "
            ), terminator: "")
            guard readLine()?.lowercased().hasPrefix("y") == true else {
                print(String(
                    localized: "cli.hooks.antigravity.aborted",
                    defaultValue: "Aborted."
                ))
                return
            }
        }
        try newData.write(to: URL(fileURLWithPath: filePath), options: .atomic)
        print(String.localizedStringWithFormat(
            String(
                localized: "cli.hooks.antigravity.installed",
                defaultValue: "%@ hooks installed at %@"
            ),
            def.displayName,
            filePath
        ))
    }

    private func uninstallAntigravityHooks(_ def: AgentHookDef) throws {
        let filePath = "\(def.resolvedConfigDir())/\(def.configFile)"
        let fm = FileManager.default
        guard let data = fm.contents(atPath: filePath) else {
            print(String.localizedStringWithFormat(
                String(
                    localized: "cli.hooks.antigravity.noneFound",
                    defaultValue: "No %@ found at %@"
                ),
                def.configFile,
                filePath
            ))
            return
        }
        let jsonObject: Any?
        let malformedJSON: Bool
        do {
            jsonObject = try JSONSerialization.jsonObject(with: data)
            malformedJSON = false
        } catch {
            print(String.localizedStringWithFormat(
                String(
                    localized: "cli.hooks.antigravity.malformedJSON",
                    defaultValue: "Malformed %@ at %@. Fix or remove it before uninstalling hooks."
                ),
                def.configFile,
                filePath
            ))
            jsonObject = nil
            malformedJSON = true
        }
        var json = jsonObject as? [String: Any] ?? [:]

        guard let group = json[Self.antigravityHookGroupName],
              Self.jsonHookValueContainsCmuxOwnedCommand(group, for: def) else {
            if !malformedJSON {
                print(String.localizedStringWithFormat(
                    String(
                        localized: "cli.hooks.antigravity.removedZero",
                        defaultValue: "Removed 0 cmux hook(s) from %@"
                    ),
                    filePath
                ))
            }
            return
        }

        json.removeValue(forKey: Self.antigravityHookGroupName)
        let newData = try JSONSerialization.data(withJSONObject: json, options: [.prettyPrinted, .sortedKeys])
        try newData.write(to: URL(fileURLWithPath: filePath), options: .atomic)
        print(String.localizedStringWithFormat(
            String(
                localized: "cli.hooks.antigravity.removed",
                defaultValue: "Removed Antigravity cmux hooks from %@"
            ),
            filePath
        ))
    }

    private static func jsonHookValueContainsCmuxOwnedCommand(_ value: Any, for def: AgentHookDef) -> Bool {
        if let command = value as? String {
            return isCmuxOwnedHookCommand(command, for: def)
        }
        if let array = value as? [Any] {
            return array.contains { jsonHookValueContainsCmuxOwnedCommand($0, for: def) }
        }
        if let object = value as? [String: Any] {
            if let command = object["command"] as? String,
               isCmuxOwnedHookCommand(command, for: def) {
                return true
            }
            return object.values.contains { jsonHookValueContainsCmuxOwnedCommand($0, for: def) }
        }
        return false
    }

    private func installAgentHooks(_ def: AgentHookDef) throws {
        if def.name == "opencode" { try installOpenCodePluginHooks(def); return }
        if def.name == "pi" { try installPiExtensionHooks(def); return }
        if def.name == "omp" { try installOmpExtensionHooks(def); return }
        if def.name == "campfire" { try installCampfireExtensionHooks(def); return }
        if def.name == "amp" {
            try installAmpExtensionHooks(def)
            return
        }
        if def.name == "rovodev" {
            try installRovoDevHooks(def)
            return
        }
        if def.name == "hermes-agent" {
            try installHermesAgentHooks(def)
            return
        }
        if case .antigravityJSON = def.format {
            try installAntigravityHooks(def)
            return
        }
        if case .tomlArrayTable = def.format {
            try installKimiHooks(def)
            return
        }

        let fm = FileManager.default
        let configDir = def.resolvedConfigDir()
        let filePath = "\(configDir)/\(def.configFile)"
        let skipConfirm = ProcessInfo.processInfo.arguments.contains("--yes")
            || ProcessInfo.processInfo.arguments.contains("-y")

        let configDirectoryFileError = String.localizedStringWithFormat(
            String(
                localized: "cli.hooks.error.configDirectoryIsFile",
                defaultValue: "cmux could not create the hooks directory: a file exists at %@; remove or rename the conflicting file and re-run `cmux hooks setup`"
            ),
            configDir
        )
        var isConfigDirectory: ObjCBool = false
        let configPathExists = fm.fileExists(atPath: configDir, isDirectory: &isConfigDirectory)
        if configPathExists, !isConfigDirectory.boolValue {
            if def.createConfigDirIfMissing {
                throw CLIError(message: configDirectoryFileError)
            }
            print("Required agent configuration is missing. Run `cmux hooks setup` after installing your agent CLI.")
            return
        }
        if !configPathExists {
            if def.createConfigDirIfMissing {
                do {
                    try fm.createDirectory(atPath: configDir, withIntermediateDirectories: true)
                } catch {
                    throw CLIError(message: configDirectoryFileError)
                }
            } else {
                print("Required agent configuration is missing. Run `cmux hooks setup` after installing your agent CLI.")
                return
            }
        }

        var existing: [String: Any] = [:]
        if let data = fm.contents(atPath: filePath) {
            guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
                throw CLIError(message: "\(filePath) exists but is not valid JSON. Fix or remove it before installing hooks.")
            }
            existing = json
        }

        var hooks = existing["hooks"] as? [String: Any] ?? [:]
        let newHooks = buildHooksDict(for: def)

        // Remove existing cmux-owned entries (both the per-agent hook
        // dispatcher and the Feed bridge). Non-cmux entries are
        // always preserved, even when the user mixed them into the
        // same group as a cmux hook, we only prune our own entries
        // within that group so the user's stays put.
        let isCmuxOwnedCommand: (String) -> Bool = { cmd in
            Self.isCmuxOwnedHookCommand(cmd, for: def)
        }
        var cmuxInsertionIndexes: [String: [Int]] = [:]
        for (event, value) in hooks {
            switch def.format {
            case .flat, .kiroAgentJSON:
                guard let entries = value as? [[String: Any]] else { continue }
                var rewrittenEntries: [[String: Any]] = []
                for entry in entries {
                    if isCmuxOwnedCommand(entry["command"] as? String ?? "") {
                        Self.appendCmuxHookInsertionIndex(
                            rewrittenEntries.count,
                            for: event,
                            to: &cmuxInsertionIndexes
                        )
                        continue
                    }
                    rewrittenEntries.append(entry)
                }
                if rewrittenEntries.isEmpty {
                    hooks.removeValue(forKey: event)
                } else {
                    hooks[event] = rewrittenEntries
                }
            case .nested:
                guard let groups = value as? [[String: Any]] else { continue }
                var rewrittenGroups: [[String: Any]] = []
                for var group in groups {
                    guard var hookList = group["hooks"] as? [[String: Any]] else {
                        // Unknown shape: preserve verbatim so we don't
                        // accidentally mutate user custom data.
                        rewrittenGroups.append(group)
                        continue
                    }
                    if hookList.contains(where: { isCmuxOwnedCommand($0["command"] as? String ?? "") }) {
                        Self.appendCmuxHookInsertionIndex(
                            rewrittenGroups.count,
                            for: event,
                            to: &cmuxInsertionIndexes
                        )
                    }
                    hookList.removeAll { isCmuxOwnedCommand($0["command"] as? String ?? "") }
                    if hookList.isEmpty {
                        // Fully cmux-owned group, drop it entirely.
                        continue
                    }
                    group["hooks"] = hookList
                    rewrittenGroups.append(group)
                }
                if rewrittenGroups.isEmpty {
                    hooks.removeValue(forKey: event)
                } else {
                    hooks[event] = rewrittenGroups
                }
            case .antigravityJSON, .rovoDevYAML, .hermesAgentYAML, .tomlArrayTable:
                break
            }
        }

        // Add new cmux entries
        for (event, value) in newHooks {
            switch def.format {
            case .flat, .kiroAgentJSON:
                var entries = hooks[event] as? [[String: Any]] ?? []
                if let newEntries = value as? [[String: Any]] {
                    if let insertionIndexes = cmuxInsertionIndexes[event], !insertionIndexes.isEmpty {
                        Self.insertCmuxHookValues(newEntries, into: &entries, atOriginalIndexes: insertionIndexes)
                    } else {
                        entries.append(contentsOf: newEntries)
                    }
                }
                hooks[event] = entries
            case .nested:
                var groups = hooks[event] as? [[String: Any]] ?? []
                if let newGroups = value as? [[String: Any]] {
                    if let insertionIndexes = cmuxInsertionIndexes[event], !insertionIndexes.isEmpty {
                        Self.insertCmuxHookValues(newGroups, into: &groups, atOriginalIndexes: insertionIndexes)
                    } else {
                        groups.append(contentsOf: newGroups)
                    }
                }
                hooks[event] = groups
            case .antigravityJSON, .rovoDevYAML, .hermesAgentYAML, .tomlArrayTable:
                break
            }
        }

        existing["hooks"] = hooks
        if case .flat = def.format { existing["version"] = 1 }
        if case .kiroAgentJSON = def.format {
            if existing["name"] == nil {
                existing["name"] = "cmux"
            }
            if existing["description"] == nil {
                existing["description"] = "CMUX notification and Feed bridge hooks for Kiro CLI."
            }
            if existing["tools"] == nil {
                // Grant the full tool set so `kiro-cli chat --agent cmux` is
                // actually usable. A Kiro custom agent with no `tools` field is
                // restricted to no tools, so the model can't run anything and the
                // preToolUse/postToolUse Feed-approval hooks would never fire
                // (verified against kiro-cli 2.5.0). Only defaulted on fresh
                // install; an existing user `tools` list is preserved.
                existing["tools"] = ["*"]
            }
        }
        let codexHookTrustEntries = Self.codexHookTrustEntries(
            hooks: hooks,
            hooksFilePath: filePath,
            def: def
        )
        let codexHookTrustEscapedKeyPrefixes = Self.codexHookTrustEscapedKeyPrefixes(
            hooksFilePath: filePath,
            def: def
        )
        let codexLegacyHookTrustHashes = Self.codexLegacyHookTrustHashes(def: def)

        let newData = try JSONSerialization.data(withJSONObject: existing, options: [.prettyPrinted, .sortedKeys])
        let newString = String(data: newData, encoding: .utf8) ?? "{}"
        let oldString: String = {
            if let data = fm.contents(atPath: filePath),
               let json = try? JSONSerialization.jsonObject(with: data),
               let pretty = try? JSONSerialization.data(
                    withJSONObject: json, options: [.prettyPrinted, .sortedKeys]
               ),
               let s = String(data: pretty, encoding: .utf8)
            {
                return s
            }
            return ""
        }()

        if oldString == newString {
            // No-op install; skip the write and the prompt entirely.
            print("\(def.displayName) hooks already up to date at \(filePath)")
        } else {
            if !skipConfirm {
                Self.printInstallPreview(
                    path: filePath,
                    oldContent: oldString,
                    newContent: newString,
                    fallbackContent: newString
                )
                print("\nProceed? [y/N] ", terminator: "")
                guard readLine()?.lowercased().hasPrefix("y") == true else {
                    print("Aborted.")
                    return
                }
            }
            try newData.write(to: URL(fileURLWithPath: filePath), options: .atomic)
            print("\(def.displayName) hooks installed at \(filePath)")
        }

        if let note = def.postInstallNote {
            print(note)
        }

        try pruneLegacyGrokHookFileIfNeeded(def: def, configDir: configDir, primaryFilePath: filePath)

        // Post-install actions
        if let action = def.postInstallAction {
            switch action {
            case .codexConfigToml:
                let configPath = "\(configDir)/config.toml"
                let existingContent: String
                if fm.fileExists(atPath: configPath) {
                    existingContent = try String(contentsOfFile: configPath, encoding: .utf8)
                } else {
                    existingContent = ""
                }
                let trustClean = Self.codexConfigTomlRemovingHookTrust(
                    in: existingContent,
                    entries: codexHookTrustEntries,
                    removingEscapedKeyPrefixes: codexHookTrustEscapedKeyPrefixes,
                    removingTrustedHashes: codexLegacyHookTrustHashes
                )
                let featureContent = Self.codexConfigTomlInstallingHooksFeature(in: trustClean)
                let trustInstall = Self.codexConfigTomlInstallingHookTrust(
                    in: featureContent,
                    entries: codexHookTrustEntries,
                    removingEscapedKeyPrefixes: codexHookTrustEscapedKeyPrefixes,
                    removingTrustedHashes: codexLegacyHookTrustHashes
                )
                let newContent = trustInstall.content
                if newContent != existingContent {
                    if !skipConfirm {
                        Self.printInstallPreview(
                            path: configPath,
                            oldContent: existingContent,
                            newContent: newContent,
                            fallbackContent: newContent
                        )
                        print("\nProceed? [y/N] ", terminator: "")
                        guard readLine()?.lowercased().hasPrefix("y") == true else {
                            print("Aborted (\(configPath) unchanged).")
                            return
                        }
                    }
                    try newContent.write(toFile: configPath, atomically: true, encoding: .utf8)
                    if def.name == "codex", !codexHookTrustEntries.isEmpty, trustInstall.installedTrust {
                        print("Enabled hooks and approved cmux hooks in \(configPath)")
                    } else {
                        print("Enabled hooks in \(configPath)")
                    }
                }
            }
        }
    }

    private func pruneLegacyGrokHookFileIfNeeded(
        def: AgentHookDef,
        configDir: String,
        primaryFilePath: String
    ) throws {
        guard def.name == "grok" else { return }
        let legacyURL = URL(fileURLWithPath: configDir, isDirectory: true)
            .appendingPathComponent("cmux.json", isDirectory: false)
        guard legacyURL.path != primaryFilePath,
              FileManager.default.fileExists(atPath: legacyURL.path),
              let data = FileManager.default.contents(atPath: legacyURL.path),
              var json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              var hooks = json["hooks"] as? [String: Any] else {
            return
        }

        let isCmuxOwnedCommand: (String) -> Bool = { cmd in
            Self.isCmuxOwnedHookCommand(cmd, for: def)
        }
        var removed = 0
        for (event, value) in hooks {
            guard var entries = value as? [[String: Any]] else { continue }
            let containsNestedGroups = entries.contains { $0["hooks"] is [[String: Any]] }
            if !containsNestedGroups {
                let before = entries.count
                entries.removeAll { isCmuxOwnedCommand($0["command"] as? String ?? "") }
                removed += before - entries.count
                if entries.isEmpty {
                    hooks.removeValue(forKey: event)
                } else {
                    hooks[event] = entries
                }
                continue
            }
            var rewrittenGroups: [[String: Any]] = []
            for var group in entries {
                guard var hookList = group["hooks"] as? [[String: Any]] else {
                    rewrittenGroups.append(group)
                    continue
                }
                let before = hookList.count
                hookList.removeAll { isCmuxOwnedCommand($0["command"] as? String ?? "") }
                removed += before - hookList.count
                guard !hookList.isEmpty else { continue }
                group["hooks"] = hookList
                rewrittenGroups.append(group)
            }
            if rewrittenGroups.isEmpty {
                hooks.removeValue(forKey: event)
            } else {
                hooks[event] = rewrittenGroups
            }
        }

        guard removed > 0 else { return }
        if hooks.isEmpty {
            json.removeValue(forKey: "hooks")
            if json.isEmpty {
                try FileManager.default.removeItem(at: legacyURL)
                print("Removed legacy \(def.displayName) hooks at \(legacyURL.path)")
                return
            }
        } else {
            json["hooks"] = hooks
        }
        let newData = try JSONSerialization.data(withJSONObject: json, options: [.prettyPrinted, .sortedKeys])
        try newData.write(to: legacyURL, options: .atomic)
        print("Removed \(removed) legacy \(def.displayName) cmux hook(s) from \(legacyURL.path)")
    }

    private func uninstallAgentHooks(_ def: AgentHookDef) throws {
        if def.name == "opencode" { try uninstallOpenCodePluginHooks(def); return }
        if def.name == "pi" { try uninstallPiExtensionHooks(def); return }
        if def.name == "omp" { try uninstallOmpExtensionHooks(def); return }
        if def.name == "campfire" { try uninstallCampfireExtensionHooks(def); return }
        if def.name == "amp" {
            try uninstallAmpExtensionHooks(def)
            return
        }
        if def.name == "rovodev" {
            try uninstallRovoDevHooks(def)
            return
        }
        if def.name == "hermes-agent" {
            try uninstallHermesAgentHooks(def)
            return
        }
        if case .antigravityJSON = def.format {
            try uninstallAntigravityHooks(def)
            return
        }
        if case .tomlArrayTable = def.format {
            try uninstallKimiHooks(def)
            return
        }

        let fm = FileManager.default
        let configDir = def.resolvedConfigDir()
        let filePath = "\(configDir)/\(def.configFile)"

        guard let data = fm.contents(atPath: filePath),
              var json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            print("No \(def.configFile) found at \(filePath)")
            return
        }

        var hooks = json["hooks"] as? [String: Any] ?? [:]
        let codexHookTrustEntriesToRemove = Self.codexHookTrustEntries(
            hooks: hooks,
            hooksFilePath: filePath,
            def: def,
            includeLegacyOwnedCommands: true
        )
        let codexStaleHookTrustHashesToRemove = Set(Self.codexHookTrustEntries(
            hooks: buildHooksDict(for: def),
            hooksFilePath: filePath,
            def: def
        ).map(\.trustedHash)).union(Self.codexLegacyHookTrustHashes(def: def))
        let codexHookTrustEscapedKeyPrefixesToRemove = Self.codexHookTrustEscapedKeyPrefixes(
            hooksFilePath: filePath,
            def: def
        )
        var removed = 0

        let isCmuxOwnedCommand: (String) -> Bool = { cmd in
            Self.isCmuxOwnedHookCommand(cmd, for: def)
        }
        for (event, value) in hooks {
            switch def.format {
            case .flat, .kiroAgentJSON:
                guard var entries = value as? [[String: Any]] else { continue }
                let before = entries.count
                entries.removeAll { isCmuxOwnedCommand($0["command"] as? String ?? "") }
                removed += before - entries.count
                if entries.isEmpty {
                    hooks.removeValue(forKey: event)
                } else {
                    hooks[event] = entries
                }
            case .nested:
                guard let groups = value as? [[String: Any]] else { continue }
                var rewrittenGroups: [[String: Any]] = []
                for var group in groups {
                    guard var hookList = group["hooks"] as? [[String: Any]] else {
                        rewrittenGroups.append(group)
                        continue
                    }
                    let before = hookList.count
                    hookList.removeAll { isCmuxOwnedCommand($0["command"] as? String ?? "") }
                    removed += before - hookList.count
                    if hookList.isEmpty { continue }
                    group["hooks"] = hookList
                    rewrittenGroups.append(group)
                }
                if rewrittenGroups.isEmpty {
                    hooks.removeValue(forKey: event)
                } else {
                    hooks[event] = rewrittenGroups
                }
            case .antigravityJSON, .rovoDevYAML, .hermesAgentYAML, .tomlArrayTable:
                break
            }
        }

        json["hooks"] = hooks
        let newData = try JSONSerialization.data(withJSONObject: json, options: [.prettyPrinted, .sortedKeys])
        try newData.write(to: URL(fileURLWithPath: filePath), options: .atomic)
        print("Removed \(removed) cmux hook(s) from \(filePath)")

        // Post-uninstall actions
        if let action = def.postInstallAction {
            switch action {
            case .codexConfigToml:
                let configPath = "\(configDir)/config.toml"
                guard fm.fileExists(atPath: configPath) else { return }
                let content: String
                do {
                    content = try String(contentsOfFile: configPath, encoding: .utf8)
                } catch {
                    throw CLIError(message: "\(configPath) exists but could not be read. Fix permissions or remove it before uninstalling \(def.displayName) hooks. \(String(describing: error))")
                }
                let newContent = Self.codexConfigTomlUninstallingHooksFeature(
                    from: content,
                    removingHookTrustEntries: codexHookTrustEntriesToRemove,
                    removingEscapedKeyPrefixes: codexHookTrustEscapedKeyPrefixesToRemove,
                    removingTrustedHashes: codexStaleHookTrustHashesToRemove
                )
                if newContent != content {
                    try newContent.write(toFile: configPath, atomically: true, encoding: .utf8)
                    print("Removed Codex hooks feature from \(configPath)")
                }
            }
        }
    }

    private static func appendCmuxHookInsertionIndex(
        _ index: Int,
        for event: String,
        to indexes: inout [String: [Int]]
    ) {
        if indexes[event]?.isEmpty == false { return }
        indexes[event, default: []].append(index)
    }

    private static func insertCmuxHookValues<T>(_ values: [T], into target: inout [T], atOriginalIndexes indexes: [Int]) {
        var insertedCount = 0
        for originalIndex in indexes {
            let insertionIndex = min(max(originalIndex + insertedCount, 0), target.count)
            target.insert(contentsOf: values, at: insertionIndex)
            insertedCount += values.count
        }
    }

    private static let cmuxCodexHooksFeatureBegin =
        "# cmux-codex-hooks-feature-78f1e4ba-66df-4d35-93c1-67fdf1cbb7df begin"
    private static let cmuxCodexHooksFeatureEnd =
        "# cmux-codex-hooks-feature-78f1e4ba-66df-4d35-93c1-67fdf1cbb7df end"
    private static let cmuxCodexHooksFeaturePreviousLinePrefix =
        "# cmux-codex-hooks-feature-78f1e4ba-66df-4d35-93c1-67fdf1cbb7df previous line: "
    private static let legacyCmuxCodexHooksFeatureBegin = "# cmux hooks codex feature begin"
    private static let legacyCmuxCodexHooksFeatureEnd = "# cmux hooks codex feature end"
    private static let legacyCmuxCodexHooksFeaturePreviousLinePrefix =
        "# cmux hooks codex feature previous line: "
    private static let cmuxCodexHookTrustBegin =
        "# cmux-codex-hook-trust-f5cc24da-7a09-4b20-a756-89e7786f6738 begin"
    private static let cmuxCodexHookTrustEnd =
        "# cmux-codex-hook-trust-f5cc24da-7a09-4b20-a756-89e7786f6738 end"
    private static let codexHookTrustTableHeaderRegex = try! NSRegularExpression(
        pattern: #"^\s*\[\s*hooks\s*\.\s*state\s*\.\s*"((?:[^"\\\n]|\\.)*)"\s*\]\s*(#.*)?$"#
    )

    struct CodexHookTrustEntry: Equatable {
        let key: String
        let trustedHash: String
    }

    private struct CodexHookTrustInstallResult: Equatable {
        let content: String
        let installedTrust: Bool
    }

    private enum CodexHookTrustBlockRemovalResult {
        case notFound
        case removed
        case malformed
    }

    static func codexConfigTomlInstallingHooksFeature(in existingContent: String) -> String {
        var lines = tomlLines(from: existingContent)
        removeCmuxCodexHooksFeatureBlock(from: &lines)
        lines.removeAll { tomlLineDefinesKey("codex_hooks", line: $0) }
        lines.removeAll { tomlLineDefinesDottedFeaturesKey("codex_hooks", line: $0) }

        let insertedLines = [
            cmuxCodexHooksFeatureBegin,
            "hooks = true",
            cmuxCodexHooksFeatureEnd,
        ]
        let insertedDottedLines = [
            cmuxCodexHooksFeatureBegin,
            "features.hooks = true",
            cmuxCodexHooksFeatureEnd,
        ]

        if let featuresStart = lines.firstIndex(where: { tomlLineIsTable("features", line: $0) }) {
            let featuresEnd = tomlTableEndIndex(in: lines, after: featuresStart)
            if featuresStart + 1 < featuresEnd,
               let hooksIndex = (featuresStart + 1..<featuresEnd)
                .first(where: { tomlLineDefinesKey("hooks", line: lines[$0]) })
            {
                if !tomlLineDefinesTrueKey("hooks", line: lines[hooksIndex]) {
                    let previousLine = lines[hooksIndex]
                    lines.replaceSubrange(
                        hooksIndex...hooksIndex,
                        with: codexHooksFeatureLines(settingLine: "hooks = true", previousLine: previousLine)
                    )
                }
            } else {
                lines.insert(contentsOf: insertedLines, at: featuresStart + 1)
            }
        } else if let dottedHooksIndex = lines.firstIndex(where: { tomlLineDefinesDottedFeaturesKey("hooks", line: $0) }) {
            if !tomlLineDefinesDottedFeaturesTrueKey("hooks", line: lines[dottedHooksIndex]) {
                let previousLine = lines[dottedHooksIndex]
                lines.replaceSubrange(
                    dottedHooksIndex...dottedHooksIndex,
                    with: codexHooksFeatureLines(settingLine: "features.hooks = true", previousLine: previousLine)
                )
            }
        } else if let firstDottedFeaturesIndex = lines.firstIndex(where: { tomlLineDefinesAnyDottedFeaturesKey($0) }) {
            lines.insert(contentsOf: insertedDottedLines, at: firstDottedFeaturesIndex)
        } else {
            if !lines.isEmpty, lines.last?.isEmpty == false {
                lines.append("")
            }
            lines.append("[features]")
            lines.append(contentsOf: insertedLines)
        }

        return tomlContent(from: lines)
    }

    private static func codexHooksFeatureLines(settingLine: String, previousLine: String? = nil) -> [String] {
        var lines = [cmuxCodexHooksFeatureBegin]
        if let previousLine {
            lines.append(cmuxCodexHooksFeaturePreviousLinePrefix + previousLine)
        }
        lines.append(settingLine)
        lines.append(cmuxCodexHooksFeatureEnd)
        return lines
    }

    static func codexConfigTomlUninstallingHooksFeature(
        from existingContent: String,
        removingHookTrustEntries entries: [CodexHookTrustEntry] = [],
        removingEscapedKeyPrefixes escapedKeyPrefixes: Set<String> = [],
        removingTrustedHashes additionalTrustedHashes: Set<String> = []
    ) -> String {
        var lines = tomlLines(from: existingContent)
        let escapedKeys = Set(entries.map { tomlBasicStringContent($0.key) })
        let trustedHashes = Set(entries.map(\.trustedHash)).union(additionalTrustedHashes)
        removeCmuxCodexHooksFeatureBlock(from: &lines)
        if removeCmuxCodexHookTrustBlock(
            from: &lines,
            removingEscapedKeys: escapedKeys,
            removingEscapedKeyPrefixes: escapedKeyPrefixes,
            removingTrustedHashes: trustedHashes
        ) == .malformed {
            stripMalformedCmuxCodexHookTrustMarker(from: &lines)
        }
        removeCodexHookTrustTables(withEscapedKeys: escapedKeys, from: &lines)
        lines.removeAll { tomlLineDefinesKey("codex_hooks", line: $0) }
        lines.removeAll { tomlLineDefinesDottedFeaturesKey("codex_hooks", line: $0) }
        removeEmptyFeaturesTable(from: &lines)
        return tomlContent(from: lines)
    }

    private static func codexConfigTomlRemovingHookTrust(
        in existingContent: String,
        entries: [CodexHookTrustEntry],
        removingEscapedKeyPrefixes escapedKeyPrefixes: Set<String>,
        removingTrustedHashes additionalTrustedHashes: Set<String> = []
    ) -> String {
        var lines = tomlLines(from: existingContent)
        let escapedKeys = Set(entries.map { tomlBasicStringContent($0.key) })
        let trustedHashes = Set(entries.map(\.trustedHash)).union(additionalTrustedHashes)
        let removalResult = removeCmuxCodexHookTrustBlock(
            from: &lines,
            removingEscapedKeys: escapedKeys,
            removingEscapedKeyPrefixes: escapedKeyPrefixes,
            removingTrustedHashes: trustedHashes
        )
        if removalResult == .malformed {
            stripMalformedCmuxCodexHookTrustMarker(from: &lines)
        }
        removeCodexHookTrustTables(withEscapedKeys: escapedKeys, from: &lines)
        return tomlContent(from: lines)
    }

    private static func codexConfigTomlInstallingHookTrust(
        in existingContent: String,
        entries: [CodexHookTrustEntry],
        removingEscapedKeyPrefixes escapedKeyPrefixes: Set<String> = [],
        removingTrustedHashes additionalTrustedHashes: Set<String> = []
    ) -> CodexHookTrustInstallResult {
        var lines = tomlLines(from: existingContent)
        let escapedKeys = Set(entries.map { tomlBasicStringContent($0.key) })
        let trustedHashes = Set(entries.map(\.trustedHash)).union(additionalTrustedHashes)
        let removalResult = removeCmuxCodexHookTrustBlock(
            from: &lines,
            removingEscapedKeys: escapedKeys,
            removingEscapedKeyPrefixes: escapedKeyPrefixes,
            removingTrustedHashes: trustedHashes
        )
        if removalResult == .malformed {
            stripMalformedCmuxCodexHookTrustMarker(from: &lines)
        }
        guard !entries.isEmpty else {
            return CodexHookTrustInstallResult(content: tomlContent(from: lines), installedTrust: false)
        }
        removeCodexHookTrustTables(withEscapedKeys: escapedKeys, from: &lines)

        if !lines.isEmpty, lines.last?.isEmpty == false {
            lines.append("")
        }
        lines.append(cmuxCodexHookTrustBegin)
        for entry in entries {
            lines.append("[hooks.state.\"\(tomlBasicStringContent(entry.key))\"]")
            lines.append("trusted_hash = \"\(tomlBasicStringContent(entry.trustedHash))\"")
        }
        lines.append(cmuxCodexHookTrustEnd)
        return CodexHookTrustInstallResult(content: tomlContent(from: lines), installedTrust: true)
    }

    static func codexHookTrustEntries(
        hooks: [String: Any],
        hooksFilePath: String,
        def: AgentHookDef,
        includeLegacyOwnedCommands: Bool = false
    ) -> [CodexHookTrustEntry] {
        guard def.name == "codex" else { return [] }
        let isOwnedCommand: (String) -> Bool = { command in
            isCmuxOwnedHookCommand(command, for: def, includeLegacy: includeLegacyOwnedCommands)
        }
        var entries: [CodexHookTrustEntry] = []
        let keySource = codexNormalizedHookSourcePath(hooksFilePath)

        for eventName in codexHookEventNames {
            guard let groups = hooks[eventName] as? [[String: Any]],
                  let eventLabel = codexHookEventLabel(eventName) else {
                continue
            }
            for (groupIndex, group) in groups.enumerated() {
                guard let hookList = group["hooks"] as? [[String: Any]] else { continue }
                let matcher = codexHookEventUsesMatcher(eventName) ? group["matcher"] as? String : nil
                for (handlerIndex, hook) in hookList.enumerated() {
                    guard let command = hook["command"] as? String,
                          isOwnedCommand(command) else {
                        continue
                    }
                    let timeoutMs = max(intValue(hook["timeout"]) ?? 600, 1)
                    let statusMessage = hook["statusMessage"] as? String
                    let key = "\(keySource):\(eventLabel):\(groupIndex):\(handlerIndex)"
                    let trustedHash = codexCommandHookHash(
                        eventLabel: eventLabel,
                        matcher: matcher,
                        command: command,
                        timeoutMs: timeoutMs,
                        statusMessage: statusMessage
                    )
                    entries.append(CodexHookTrustEntry(key: key, trustedHash: trustedHash))
                }
            }
        }

        return entries
    }

    private static func codexHookTrustEscapedKeyPrefixes(
        hooksFilePath: String,
        def: AgentHookDef
    ) -> Set<String> {
        guard def.name == "codex" else { return [] }
        return [tomlBasicStringContent("\(codexNormalizedHookSourcePath(hooksFilePath)):")]
    }

    private static func codexLegacyHookTrustHashes(def: AgentHookDef) -> Set<String> {
        guard def.name == "codex" else { return [] }
        let hookTimeoutMs: Int
        if case .nested(let timeoutMs) = def.format {
            hookTimeoutMs = timeoutMs
        } else {
            hookTimeoutMs = 600
        }

        var hashes = Set<String>()
        func insertHashes(eventLabel: String, command: String, timeouts: [Int]) {
            let commands = [
                command,
                "[ -n \"$CMUX_SURFACE_ID\" ] && [ \"$\(def.disableEnvVar)\" != \"1\" ] && command -v cmux >/dev/null 2>&1 && \(command) || echo '{}'",
            ]
            for command in commands {
                for timeout in timeouts {
                    hashes.insert(codexCommandHookHash(
                        eventLabel: eventLabel,
                        matcher: nil,
                        command: command,
                        timeoutMs: timeout,
                        statusMessage: nil
                    ))
                }
            }
        }

        for event in def.events {
            guard let eventLabel = codexHookEventLabel(event.agentEvent) else { continue }
            insertHashes(
                eventLabel: eventLabel,
                command: Self.hookCommandString(for: def, event: event),
                timeouts: [5_000, 600]
            )
            insertHashes(
                eventLabel: eventLabel,
                command: "cmux codex-hook \(event.cmuxSubcommand)",
                timeouts: [hookTimeoutMs, 600]
            )
        }

        for agentEvent in def.feedHookEvents {
            guard let eventLabel = codexHookEventLabel(agentEvent) else { continue }
            insertHashes(
                eventLabel: eventLabel,
                command: Self.feedHookCommandString(for: def, agentEvent: agentEvent),
                timeouts: [120_000, 120, 600]
            )
            insertHashes(
                eventLabel: eventLabel,
                command: "cmux feed-hook --source \(def.name) --event \(agentEvent)",
                timeouts: [120_000, 600]
            )
        }
        return hashes
    }

    private static func codexNormalizedHookSourcePath(_ path: String) -> String {
        let url = URL(fileURLWithPath: path).standardizedFileURL
        if let resolved = realPath(url.path) {
            return resolved
        }
        let parent = url.deletingLastPathComponent()
        if let resolvedParent = realPath(parent.path) {
            return URL(fileURLWithPath: resolvedParent, isDirectory: true)
                .appendingPathComponent(url.lastPathComponent)
                .path
        }
        return url.path
    }

    private static func realPath(_ path: String) -> String? {
        var buffer = [CChar](repeating: 0, count: Int(PATH_MAX))
        guard realpath(path, &buffer) != nil else { return nil }
        return String(cString: buffer)
    }

    private static let codexHookEventNames = [
        "PreToolUse",
        "PermissionRequest",
        "PostToolUse",
        "PreCompact",
        "PostCompact",
        "SessionStart",
        "SubagentStart",
        "SubagentStop",
        "UserPromptSubmit",
        "Stop",
    ]

    private static func codexHookEventLabel(_ eventName: String) -> String? {
        switch eventName {
        case "PreToolUse": return "pre_tool_use"
        case "PermissionRequest": return "permission_request"
        case "PostToolUse": return "post_tool_use"
        case "PreCompact": return "pre_compact"
        case "PostCompact": return "post_compact"
        case "SessionStart": return "session_start"
        case "SubagentStart": return "subagent_start"
        case "SubagentStop": return "subagent_stop"
        case "UserPromptSubmit": return "user_prompt_submit"
        case "Stop": return "stop"
        default: return nil
        }
    }

    private static func codexHookEventUsesMatcher(_ eventName: String) -> Bool {
        switch eventName {
        case "PreToolUse",
             "PermissionRequest",
             "PostToolUse",
             "PreCompact",
             "PostCompact",
             "SessionStart",
             "SubagentStart",
             "SubagentStop":
            return true
        default:
            return false
        }
    }

    private static func codexCommandHookHash(
        eventLabel: String,
        matcher: String?,
        command: String,
        timeoutMs: Int,
        statusMessage: String?
    ) -> String {
        let normalizedTimeoutMs = max(timeoutMs, 1)
        var handler: [String: Any] = [
            "async": false,
            "command": command,
            "timeout": normalizedTimeoutMs,
            "type": "command",
        ]
        if let statusMessage {
            handler["statusMessage"] = statusMessage
        }
        var identity: [String: Any] = [
            "event_name": eventLabel,
            "hooks": [handler],
        ]
        if let matcher {
            identity["matcher"] = matcher
        }

        let data = (try? JSONSerialization.data(
            withJSONObject: identity,
            options: [.sortedKeys, .withoutEscapingSlashes]
        )) ?? Data()
        let digest = SHA256.hash(data: data)
            .map { String(format: "%02x", $0) }
            .joined()
        return "sha256:\(digest)"
    }

    private static func intValue(_ value: Any?) -> Int? {
        if let intValue = value as? Int {
            return intValue
        }
        if let number = value as? NSNumber {
            return number.intValue
        }
        return nil
    }

    private static func boolValue(_ value: Any?) -> Bool {
        if let boolValue = value as? Bool {
            return boolValue
        }
        if let number = value as? NSNumber {
            return number.boolValue
        }
        if let string = value as? String {
            return ["1", "true", "yes"].contains(string.trimmingCharacters(in: .whitespacesAndNewlines).lowercased())
        }
        return false
    }

    private static func tomlBasicStringContent(_ value: String) -> String {
        var escaped = ""
        escaped.reserveCapacity(value.count)

        for scalar in value.unicodeScalars {
            switch scalar.value {
            case 0x08:
                escaped += "\\b"
            case 0x09:
                escaped += "\\t"
            case 0x0A:
                escaped += "\\n"
            case 0x0C:
                escaped += "\\f"
            case 0x0D:
                escaped += "\\r"
            case 0x22:
                escaped += "\\\""
            case 0x5C:
                escaped += "\\\\"
            case 0x00...0x1F, 0x7F...0x9F:
                if scalar.value <= 0xFFFF {
                    escaped += String(format: "\\u%04X", scalar.value)
                } else {
                    escaped += String(format: "\\U%08X", scalar.value)
                }
            default:
                escaped.unicodeScalars.append(scalar)
            }
        }

        return escaped
    }

    private static func tomlLines(from content: String) -> [String] {
        guard !content.isEmpty else { return [] }
        var lines = content.components(separatedBy: "\n")
        if content.hasSuffix("\n"), lines.last == "" {
            lines.removeLast()
        }
        return lines
    }

    private static func tomlContent(from lines: [String]) -> String {
        guard !lines.isEmpty else { return "" }
        return lines.joined(separator: "\n") + "\n"
    }

    private static func tomlLineDefinesKey(_ key: String, line: String) -> Bool {
        let escapedKey = NSRegularExpression.escapedPattern(for: key)
        return line.range(
            of: #"^\s*"# + escapedKey + #"\s*="#,
            options: .regularExpression
        ) != nil
    }

    private static func tomlLineDefinesTrueKey(_ key: String, line: String) -> Bool {
        let escapedKey = NSRegularExpression.escapedPattern(for: key)
        return line.range(
            of: #"^\s*"# + escapedKey + #"\s*=\s*true\s*(#.*)?$"#,
            options: .regularExpression
        ) != nil
    }

    private static func tomlLineDefinesDottedFeaturesKey(_ key: String, line: String) -> Bool {
        let escapedKey = NSRegularExpression.escapedPattern(for: key)
        return line.range(
            of: #"^\s*features\s*\.\s*"# + escapedKey + #"\s*="#,
            options: .regularExpression
        ) != nil
    }

    private static func tomlLineDefinesDottedFeaturesTrueKey(_ key: String, line: String) -> Bool {
        let escapedKey = NSRegularExpression.escapedPattern(for: key)
        return line.range(
            of: #"^\s*features\s*\.\s*"# + escapedKey + #"\s*=\s*true\s*(#.*)?$"#,
            options: .regularExpression
        ) != nil
    }

    private static func tomlLineDefinesAnyDottedFeaturesKey(_ line: String) -> Bool {
        line.range(
            of: #"^\s*features\s*\.\s*[^=\s]+\s*="#,
            options: .regularExpression
        ) != nil
    }

    private static func tomlLineIsTable(_ name: String, line: String) -> Bool {
        let escapedName = NSRegularExpression.escapedPattern(for: name)
        return line.range(
            of: #"^\s*\[\s*"# + escapedName + #"\s*\]\s*(#.*)?$"#,
            options: .regularExpression
        ) != nil
    }

    private static func tomlLineIsAnyTableHeader(_ line: String) -> Bool {
        let tomlKey = "(?:[A-Za-z0-9_-]+|\"[^\"\\n]*\"|'[^'\\n]*')"
        let tomlKeyPath = tomlKey + "(?:\\s*\\.\\s*" + tomlKey + ")*"
        let pattern = "^\\s*(?:\\[\\s*" + tomlKeyPath + "\\s*\\]|\\[\\[\\s*" + tomlKeyPath
            + "\\s*\\]\\])\\s*(#.*)?$"
        return line.range(
            of: pattern,
            options: .regularExpression
        ) != nil
    }

    private static func tomlTableEndIndex(in lines: [String], after tableStart: Int) -> Int {
        var index = tableStart + 1
        while index < lines.count {
            if tomlLineIsAnyTableHeader(lines[index]) {
                return index
            }
            index += 1
        }
        return lines.count
    }

    private static func removeCmuxCodexHooksFeatureBlock(from lines: inout [String]) {
        var index = 0
        while index < lines.count {
            guard tomlLineIsCodexHooksFeatureBegin(lines[index]) else {
                index += 1
                continue
            }

            if let endIndex = lines[index...].firstIndex(where: {
                tomlLineIsCodexHooksFeatureEnd($0)
            }) {
                let previousLines = lines[index...endIndex].compactMap { line -> String? in
                    tomlCodexHooksFeaturePreviousLine(from: line)
                }
                lines.replaceSubrange(index...endIndex, with: previousLines)
            } else {
                var blockEnd = index + 1
                var previousLines: [String] = []
                if blockEnd < lines.count,
                   let previousLine = tomlCodexHooksFeaturePreviousLine(from: lines[blockEnd])
                {
                    previousLines.append(previousLine)
                    blockEnd += 1
                }
                if blockEnd < lines.count, tomlLineIsCodexHooksFeatureSetting(lines[blockEnd]) {
                    blockEnd += 1
                }
                lines.replaceSubrange(index..<blockEnd, with: previousLines)
            }
        }
    }

    @discardableResult
    private static func removeCmuxCodexHookTrustBlock(
        from lines: inout [String],
        removingEscapedKeys escapedKeys: Set<String> = [],
        removingEscapedKeyPrefixes escapedKeyPrefixes: Set<String> = [],
        removingTrustedHashes trustedHashes: Set<String> = []
    ) -> CodexHookTrustBlockRemovalResult {
        var replacements: [(range: ClosedRange<Int>, lines: [String])] = []
        var index = 0
        while index < lines.count {
            guard lines[index] == cmuxCodexHookTrustBegin else {
                index += 1
                continue
            }

            guard let endIndex = lines[index...].firstIndex(of: cmuxCodexHookTrustEnd) else {
                return .malformed
            }
            let preservedLines = codexHookTrustBlockUnownedLines(
                from: lines[(index + 1)..<endIndex],
                removingEscapedKeys: escapedKeys,
                removingEscapedKeyPrefixes: escapedKeyPrefixes,
                removingTrustedHashes: trustedHashes
            )
            replacements.append((index...endIndex, preservedLines))
            index = endIndex + 1
        }

        for replacement in replacements.reversed() {
            lines.replaceSubrange(replacement.range, with: replacement.lines)
        }
        return replacements.isEmpty ? .notFound : .removed
    }

    private static func codexHookTrustBlockUnownedLines(
        from lines: ArraySlice<String>,
        removingEscapedKeys escapedKeys: Set<String>,
        removingEscapedKeyPrefixes escapedKeyPrefixes: Set<String>,
        removingTrustedHashes trustedHashes: Set<String>
    ) -> [String] {
        var preserved: [String] = []
        var index = lines.startIndex
        while index < lines.endIndex {
            if let escapedKey = codexHookTrustTableEscapedKey(from: lines[index]) {
                let tableStart = index
                index += 1
                while index < lines.endIndex, !tomlLineIsCodexHookTrustBlockTableBoundary(lines[index]) {
                    index += 1
                }
                if !codexHookTrustEscapedKeyIsRemoved(
                    escapedKey,
                    trustedHash: codexHookTrustTrustedHash(from: lines[tableStart..<index]),
                    removingEscapedKeys: escapedKeys,
                    removingEscapedKeyPrefixes: escapedKeyPrefixes,
                    removingTrustedHashes: trustedHashes
                ) {
                    preserved.append(contentsOf: lines[tableStart..<index])
                }
                continue
            }

            guard tomlLineIsAnyTableHeader(lines[index]) else {
                // Marker drift can capture user config lines; only cmux-owned
                // hook trust tables are safe to discard.
                preserved.append(lines[index])
                index += 1
                continue
            }
            let tableStart = index
            index += 1
            while index < lines.endIndex, !tomlLineIsCodexHookTrustBlockTableBoundary(lines[index]) {
                index += 1
            }
            preserved.append(contentsOf: lines[tableStart..<index])
        }
        return preserved
    }

    private static func codexHookTrustEscapedKeyIsRemoved(
        _ escapedKey: String,
        trustedHash: String?,
        removingEscapedKeys escapedKeys: Set<String>,
        removingEscapedKeyPrefixes escapedKeyPrefixes: Set<String>,
        removingTrustedHashes trustedHashes: Set<String>
    ) -> Bool {
        if escapedKeys.contains(escapedKey) {
            return true
        }
        guard let trustedHash, trustedHashes.contains(trustedHash) else {
            return false
        }
        return escapedKeyPrefixes.contains { escapedKey.hasPrefix($0) }
    }

    private static func codexHookTrustTrustedHash(from lines: ArraySlice<String>) -> String? {
        for line in lines {
            let trimmed = line.trimmingCharacters(in: .whitespaces)
            guard let equalsIndex = trimmed.firstIndex(of: "=") else { continue }
            let key = String(trimmed[..<equalsIndex]).trimmingCharacters(in: .whitespaces)
            guard key == "trusted_hash" else { continue }
            let valueStart = trimmed.index(after: equalsIndex)
            let value = String(trimmed[valueStart...]).trimmingCharacters(in: .whitespaces)
            guard value.hasPrefix("\""), value.hasSuffix("\""), value.count >= 2 else { continue }
            return String(value.dropFirst().dropLast())
        }
        return nil
    }

    private static func stripMalformedCmuxCodexHookTrustMarker(from lines: inout [String]) {
        lines.removeAll { $0 == cmuxCodexHookTrustBegin }
    }

    private static func removeCodexHookTrustTables(withEscapedKeys keys: Set<String>, from lines: inout [String]) {
        guard !keys.isEmpty else { return }
        var index = 0
        while index < lines.count {
            guard let escapedKey = codexHookTrustTableEscapedKey(from: lines[index]),
                  keys.contains(escapedKey) else {
                index += 1
                continue
            }
            let endIndex = codexHookTrustTableEndIndex(in: lines, after: index)
            lines.removeSubrange(index..<endIndex)
        }
    }

    private static func codexHookTrustTableEndIndex(in lines: [String], after tableStart: Int) -> Int {
        var index = tableStart + 1
        while index < lines.count {
            if tomlLineIsCodexHookTrustBlockTableBoundary(lines[index]) {
                return index
            }
            index += 1
        }
        return lines.count
    }

    private static func codexHookTrustTableEscapedKey(from line: String) -> String? {
        let range = NSRange(line.startIndex..<line.endIndex, in: line)
        guard let match = codexHookTrustTableHeaderRegex.firstMatch(in: line, range: range),
              let keyRange = Range(match.range(at: 1), in: line) else {
            return nil
        }
        return String(line[keyRange])
    }

    private static func tomlLineIsCodexHookTrustBlockTableBoundary(_ line: String) -> Bool {
        codexHookTrustTableEscapedKey(from: line) != nil || tomlLineIsAnyTableHeader(line)
    }

    private static func tomlLineIsCodexHooksFeatureBegin(_ line: String) -> Bool {
        line == cmuxCodexHooksFeatureBegin || line == legacyCmuxCodexHooksFeatureBegin
    }

    private static func tomlLineIsCodexHooksFeatureEnd(_ line: String) -> Bool {
        line == cmuxCodexHooksFeatureEnd || line == legacyCmuxCodexHooksFeatureEnd
    }

    private static func tomlCodexHooksFeaturePreviousLine(from line: String) -> String? {
        if line.hasPrefix(cmuxCodexHooksFeaturePreviousLinePrefix) {
            return String(line.dropFirst(cmuxCodexHooksFeaturePreviousLinePrefix.count))
        }
        if line.hasPrefix(legacyCmuxCodexHooksFeaturePreviousLinePrefix) {
            return String(line.dropFirst(legacyCmuxCodexHooksFeaturePreviousLinePrefix.count))
        }
        return nil
    }

    private static func tomlLineIsCodexHooksFeatureSetting(_ line: String) -> Bool {
        tomlLineDefinesTrueKey("hooks", line: line)
            || tomlLineDefinesDottedFeaturesTrueKey("hooks", line: line)
    }

    private static func removeEmptyFeaturesTable(from lines: inout [String]) {
        guard let featuresStart = lines.firstIndex(where: { tomlLineIsTable("features", line: $0) }) else {
            return
        }
        let featuresEnd = tomlTableEndIndex(in: lines, after: featuresStart)
        let bodyRange = featuresStart + 1..<featuresEnd
        let hasContent = bodyRange.contains { index in
            let trimmed = lines[index].trimmingCharacters(in: .whitespaces)
            return !trimmed.isEmpty && !trimmed.hasPrefix("#")
        }
        if !hasContent {
            lines.removeSubrange(featuresStart..<featuresEnd)
            if featuresStart == lines.count, featuresStart > 0,
               lines[featuresStart - 1].trimmingCharacters(in: .whitespaces).isEmpty
            {
                lines.remove(at: featuresStart - 1)
            } else if featuresStart > 0, featuresStart < lines.count,
                      lines[featuresStart - 1].trimmingCharacters(in: .whitespaces).isEmpty,
                      lines[featuresStart].trimmingCharacters(in: .whitespaces).isEmpty
            {
                lines.remove(at: featuresStart)
            }
        }
    }

    // MARK: Generic hook handler

    private func resolvedAgentHookSessionId(
        def: AgentHookDef,
        input: ClaudeHookParsedInput,
        env: [String: String],
        cwd: String?
    ) -> String {
        if let sessionId = normalizedHookValue(input.sessionId) {
            return sessionId
        }
        if def.name == "rovodev" {
            return RovoDevSessionResolver.inferredRovoDevSessionId(cwd: cwd, env: env) ?? ""
        }
        return normalizedHookValue(env["CMUX_SURFACE_ID"]) ?? ""
    }

    private func runGenericAgentHook(
        def: AgentHookDef,
        commandArgs: [String],
        client: SocketClient,
        telemetry: CLISocketSentryTelemetry,
        socketPassword: String? = nil
    ) throws {
        let env = ProcessInfo.processInfo.environment
        let subcommand = commandArgs.first?.lowercased() ?? ""
        let hookArgs = Array(commandArgs.dropFirst())
        telemetry.breadcrumb("\(def.name)-hook.\(subcommand)")

        if def.name == "codex", subcommand == "monitor" {
            try runCodexTranscriptMonitor(commandArgs: hookArgs, client: client)
            return
        }

        if subcommand == "auto-name", autoNamingSource(for: def) != nil {
            // Detached re-invocation spawned from the codex Stop hook (see
            // spawnDetachedAgentAutoName): runs the full naming pass without
            // blocking the short sync hook budget.
            if def.name == "codex" {
                runCodexAutoNameHook(
                    commandArgs: hookArgs,
                    client: client,
                    telemetry: telemetry,
                    env: env
                )
            } else {
                runGenericAgentAutoNameHook(
                    def: def,
                    commandArgs: hookArgs,
                    client: client,
                    telemetry: telemetry,
                    env: env
                )
            }
            print("OK")
            return
        }

        // Workspace/surface resolution: prefer --workspace/--surface flags,
        // then env, then the caller process. Grok strips CMUX_* from hook
        // subprocesses, so PID attribution is the only reliable live binding.
        let inferredPID = agentPIDFromHookEnvironment(agentName: def.name, env: env) ?? inferredAgentPID()
        let hookWsFlag = optionValue(hookArgs, name: "--workspace")
        let directWorkspaceArg = hookWsFlag ?? normalizedHookValue(env["CMUX_WORKSPACE_ID"])
        let explicitSurfaceFlag = optionValue(hookArgs, name: "--surface")
        let directSurfaceArg = explicitSurfaceFlag
            ?? (hookWsFlag == nil ? normalizedHookValue(env["CMUX_SURFACE_ID"]) : nil)
        func resolveAccessibleWorkspaceId(_ raw: String?) -> String? {
            guard let raw = nonEmptyClaudeHookIdentifier(raw) else {
                return nil
            }
            guard let candidate = try? resolveWorkspaceId(raw, client: client),
                  (try? client.sendV2(method: "surface.list", params: ["workspace_id": candidate])) != nil else {
                return nil
            }
            return candidate
        }
        func resolveAccessibleSurfaceId(_ raw: String?, workspaceId: String) -> String? {
            guard let raw = nonEmptyClaudeHookIdentifier(raw),
                  let candidate = try? resolveSurfaceId(raw, workspaceId: workspaceId, client: client),
                  let listed = try? client.sendV2(method: "surface.list", params: ["workspace_id": workspaceId]) else {
                return nil
            }
            let items = listed["surfaces"] as? [[String: Any]] ?? []
            return items.contains(where: {
                ($0["id"] as? String) == candidate || ($0["ref"] as? String) == candidate
            }) ? candidate : nil
        }
        func resolveDefaultSurfaceId(workspaceId: String) -> String? {
            try? resolveSurfaceId(nil, workspaceId: workspaceId, client: client)
        }
        let resolvedDirectWorkspaceArg = resolveAccessibleWorkspaceId(directWorkspaceArg)
        // Only an EXPLICIT --workspace flag that fails to resolve is a hard, hook-dropping error. A
        // stale/invalid AMBIENT CMUX_WORKSPACE_ID must not abort routing — treated as absent, it falls
        // through to the PID/TTY binding below, which is ground truth.
        let hasInvalidDirectWorkspaceArg = hookWsFlag != nil && resolvedDirectWorkspaceArg == nil
        var processBindingCache: CallerTerminalBinding?
        var didResolveProcessBinding = false
        func processBinding() -> CallerTerminalBinding? {
            if !didResolveProcessBinding {
                didResolveProcessBinding = true
                // Always resolve the agent process's own terminal binding (TTY first, then PID), even
                // when env supplies both ids. Historically this was suppressed whenever both env ids
                // were present, which made a leaked/stale CMUX_SURFACE_ID impossible to correct — the
                // codex jumble class, where a session routes to the wrong surface and the no-pid-gate
                // resume binding persists it across reload. resolveAgentHookTarget now uses this
                // binding to OVERRIDE a disagreeing ambient-env surface; the binding stays nil (env
                // trusted) under remote/SSH where no local TTY maps to a surface.
                processBindingCache = resolveCallerTerminalBindingByTTY(client: client)
                    ?? resolveAgentProcessTerminalBinding(pid: inferredPID, client: client)
            }
            return processBindingCache
        }
#if DEBUG
        func processBindingDebugState() -> String {
            guard didResolveProcessBinding else { return "deferred" }
            return processBindingCache == nil ? "nil" : "resolved"
        }
#endif
        let resolvedDirectSurfaceArg: String? = {
            guard let directSurfaceArg else { return nil }
            guard let workspaceId = resolvedDirectWorkspaceArg ?? processBinding()?.workspaceId else { return nil }
            return resolveAccessibleSurfaceId(directSurfaceArg, workspaceId: workspaceId)
        }()
        // Same asymmetry for the surface: an explicit --surface flag that fails to resolve is a hard
        // error, but a stale/invalid ambient CMUX_SURFACE_ID (a surface that was closed, or belongs to
        // another workspace) must fall through to the PID/TTY binding instead of dropping the hook —
        // that is the stale-env variant of the codex jumble.
        let hasInvalidDirectSurfaceArg = explicitSurfaceFlag != nil && resolvedDirectSurfaceArg == nil
        let hasUnusableDirectBinding = hasInvalidDirectWorkspaceArg || hasInvalidDirectSurfaceArg
        func workspaceArg() -> String? {
            resolvedDirectWorkspaceArg ?? processBinding()?.workspaceId
        }

        let rawInput = String(data: FileHandle.standardInput.readDataToEndOfFile(), encoding: .utf8) ?? ""
        let input = parseClaudeHookInput(rawInput: rawInput)

        let store = ClaudeHookSessionStore(
            processEnv: env.merging(
                ["CMUX_CLAUDE_HOOK_STATE_PATH": agentHookStatePath(sessionStoreSuffix: def.sessionStoreSuffix, env: env)],
                uniquingKeysWith: { _, new in new }
            )
        )

        let hookCwd = input.cwd
            ?? normalizedHookValue(env["CMUX_AGENT_LAUNCH_CWD"])
            ?? normalizedHookValue(env["PWD"]) ?? (def.name == "codex" ? normalizedHookValue(FileManager.default.currentDirectoryPath) : nil)
        let sessionId = resolvedAgentHookSessionId(def: def, input: input, env: env, cwd: hookCwd)
        let action = Self.subcommandActions[subcommand] ?? .noop
#if DEBUG
        agentHookDebugLog(
            "agentHook.start agent=\(def.name) subcommand=\(subcommand) session=\(agentHookDebugShort(sessionId)) inputSession=\(agentHookDebugShort(input.sessionId)) rawBytes=\(rawInput.utf8.count) hasCwd=\(hookCwd == nil ? 0 : 1) envWorkspace=\(env["CMUX_WORKSPACE_ID"] == nil ? 0 : 1) envSurface=\(env["CMUX_SURFACE_ID"] == nil ? 0 : 1) directWorkspace=\(directWorkspaceArg == nil ? 0 : 1) directSurface=\(directSurfaceArg == nil ? 0 : 1) invalidDirect=\(hasUnusableDirectBinding ? 1 : 0) processBinding=\(processBindingDebugState()) socketName=\(agentHookDebugSocketName(client.socketPath))",
            socketPath: client.socketPath,
            env: env
        )
#endif
        let pidKey = "\(def.statusKey).\(sessionId.isEmpty ? "default" : sessionId)"
        var didSendFeedTelemetry = false
        // Destructive session teardown shared by a genuine (non-turn-boundary)
        // `session-end` and the dedicated `session-finalize` action: consume the
        // restore record, clear the surface resume binding, and clear PID routing.
        func performAgentSessionTeardown() {
            guard let mapped = sessionId.isEmpty ? nil : (try? store.lookup(sessionId: sessionId)) else { return }
            sendAgentFeedTelemetry(workspaceId: mapped.workspaceId)
            let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(currentAgentPID: mapped.pid, env: env)
            if suppressVisibleMutations {
                telemetry.breadcrumb("\(def.name)-hook.session-end.nested-suppressed")
            } else if let consumed = try? store.consume(sessionId: sessionId, workspaceId: nil, surfaceId: nil) {
                clearAgentSurfaceResumeBinding(
                    client: client,
                    workspaceId: consumed.workspaceId,
                    surfaceId: consumed.surfaceId,
                    sessionId: consumed.sessionId
                )
                _ = try? sendV1Command(
                    "clear_agent_pid \(pidKey) --tab=\(consumed.workspaceId)\(socketPanelOption(consumed.surfaceId)) --clear-status",
                    client: client
                )
            }
        }
        func runtimeStatus(for notificationStatus: AgentHookNotificationStatus?) -> AgentHookRuntimeStatus? {
            switch notificationStatus {
            case .idle?:
                return .idle
            case .needsInput?:
                return .needsInput
            case .error?:
                return .error
            case nil:
                return nil
            }
        }
        func agentLifecycle(for notificationStatus: AgentHookNotificationStatus?) -> AgentHibernationLifecycleState? {
            switch notificationStatus {
            case .idle?:
                return .idle
            case .needsInput?, .error?:
                return .needsInput
            case nil:
                return nil
            }
        }
        func hasNewerRunningSession(workspaceId: String, surfaceId: String) -> Bool {
            (try? store.hasRunningSession(
                workspaceId: workspaceId,
                surfaceId: surfaceId,
                excludingSessionId: sessionId,
                onlyNewerThanExcludedSession: true,
                requireLiveProcess: true
            )) == true
        }
        func hasOtherRunningSession(workspaceId: String) -> Bool {
            (try? store.hasRunningSession(
                workspaceId: workspaceId,
                surfaceId: nil,
                excludingSessionId: sessionId,
                requireLiveProcess: true
            )) == true
        }
        func setIdleStatusUnlessAnotherSessionIsRunning(workspaceId: String, surfaceId: String) {
            if hasOtherRunningSession(workspaceId: workspaceId) {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.status.keepRunning agent=\(def.name) session=\(agentHookDebugShort(sessionId)) workspace=\(agentHookDebugShort(workspaceId)) surface=\(agentHookDebugShort(surfaceId))",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                return
            }
            let idleStatus = String(localized: "agent.generic.notification.status.idle", defaultValue: "Idle")
            _ = try? sendV1Command(
                "set_status \(def.statusKey) \(idleStatus) --icon=pause.circle.fill --color=#8E8E93 --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                client: client
            )
        }
        func sendAgentFeedTelemetry(workspaceId: String? = nil, surfaceId: String? = nil) {
            didSendFeedTelemetry = true
            sendFeedTelemetry(
                client: client,
                source: def.name,
                subcommand: subcommand,
                parsedInput: input,
                workspaceId: workspaceId ?? workspaceArg(),
                surfaceId: surfaceId,
                socketPassword: socketPassword
            )
        }
        func shouldSuppressGenericFeedTelemetry() -> Bool {
            guard def.name == "hermes-agent",
                  let event = input.object.flatMap({
                      firstString(in: $0, keys: ["hook_event_name", "hookEventName", "event", "event_name"])
                  }) ?? input.rawObject.flatMap({
                      firstString(in: $0, keys: ["hook_event_name", "hookEventName", "event", "event_name"])
                  })
            else {
                return false
            }
            return def.feedHookEvents.contains(event)
        }
        func sendAgentFeedTelemetryUnlessSuppressed(workspaceId: String? = nil, surfaceId: String? = nil) {
            if shouldSuppressGenericFeedTelemetry() {
                didSendFeedTelemetry = true
            } else {
                sendAgentFeedTelemetry(workspaceId: workspaceId, surfaceId: surfaceId)
            }
        }
        func notificationDedupeFingerprint(
            status: AgentHookNotificationStatus?,
            category: AgentHookNotifyCategory,
            body: String
        ) -> String? {
            AgentHookNotificationPolicy.dedupeFingerprint(
                agentName: def.name,
                sessionId: sessionId,
                status: status,
                category: category,
                body: body
            )
        }
        func hasActiveAntigravityBackgroundWork() -> Bool {
            def.name == "antigravity" && (input.rawObject?["fullyIdle"] as? Bool) == false
        }
        func shouldSendNotification(fingerprint: String?) -> Bool {
            guard let fingerprint else { return true }
            return (try? store.recentlyEmittedNotification(sessionId: sessionId, fingerprint: fingerprint)) != true
        }
        func markNotificationSent(fingerprint: String?) {
            guard let fingerprint else { return }
            try? store.markNotificationEmitted(sessionId: sessionId, fingerprint: fingerprint)
        }
        func resolveAgentHookTarget(mapped: ClaudeHookSessionRecord?) -> (workspaceId: String, surfaceId: String)? {
            guard !hasUnusableDirectBinding else {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.target.nil agent=\(def.name) subcommand=\(subcommand) session=\(agentHookDebugShort(sessionId)) reason=invalidDirectBinding mapped=\(mapped == nil ? 0 : 1)",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                return nil
            }
            func resolveTarget(
                workspaceId: String,
                preferredSurfaceId: String?,
                mapped: ClaudeHookSessionRecord?
            ) -> (workspaceId: String, surfaceId: String)? {
                if let preferredSurfaceId = nonEmptyClaudeHookIdentifier(preferredSurfaceId),
                   let surfaceId = resolveAccessibleSurfaceId(preferredSurfaceId, workspaceId: workspaceId) {
                    return (workspaceId, surfaceId)
                }

                if let mappedSurface = nonEmptyClaudeHookIdentifier(mapped?.surfaceId),
                   let surfaceId = resolveAccessibleSurfaceId(mappedSurface, workspaceId: workspaceId) {
                    return (workspaceId, surfaceId)
                }

                guard let surfaceId = resolveDefaultSurfaceId(workspaceId: workspaceId) else {
                    return nil
                }
                return (workspaceId, surfaceId)
            }

            // G3 (codex jumble defense-in-depth): the surface id can arrive from the ambient env
            // (CMUX_SURFACE_ID), which a launcher or an inherited subprocess can leak as the operator's
            // FOCUSED pane rather than the agent's own pane. When the agent process's controlling TTY
            // (or PID) is bound to a DIFFERENT, accessible surface inside this same workspace, that
            // binding is ground truth — prefer it. Returns the env surface unchanged when there is no
            // env surface to correct, when it came from an explicit --surface flag (operator intent),
            // or when the TTY/PID binding is unavailable (remote/SSH) or already agrees. Stays within
            // the env workspace so a flaky binding can never cross-route to a different workspace.
            func correctedDirectSurfaceId(workspaceId: String) -> String? {
                guard let envSurface = resolvedDirectSurfaceArg else { return nil }
                guard hookWsFlag == nil, explicitSurfaceFlag == nil else { return envSurface }
                guard let binding = processBinding(),
                      let boundSurfaceRaw = nonEmptyClaudeHookIdentifier(binding.surfaceId),
                      let boundWorkspaceRaw = nonEmptyClaudeHookIdentifier(binding.workspaceId),
                      resolveAccessibleWorkspaceId(boundWorkspaceRaw) == workspaceId,
                      let boundSurface = resolveAccessibleSurfaceId(boundSurfaceRaw, workspaceId: workspaceId),
                      boundSurface != envSurface else {
                    return envSurface
                }
#if DEBUG
                agentHookDebugLog(
                    "agentHook.surface.correct agent=\(def.name) subcommand=\(subcommand) session=\(agentHookDebugShort(sessionId)) env=\(agentHookDebugShort(envSurface)) tty=\(agentHookDebugShort(boundSurface))",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                return boundSurface
            }

            if let workspaceId = resolvedDirectWorkspaceArg {
                let preferredSurfaceId = correctedDirectSurfaceId(workspaceId: workspaceId)
                    ?? (hookWsFlag == nil ? processBinding()?.surfaceId : nil)
                let target = resolveTarget(workspaceId: workspaceId, preferredSurfaceId: preferredSurfaceId, mapped: mapped)
#if DEBUG
                agentHookDebugLog(
                    "agentHook.target.\(target == nil ? "nil" : "resolved") agent=\(def.name) subcommand=\(subcommand) session=\(agentHookDebugShort(sessionId)) source=direct workspace=\(agentHookDebugShort(target?.workspaceId ?? workspaceId)) surface=\(agentHookDebugShort(target?.surfaceId)) mapped=\(mapped == nil ? 0 : 1)",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                return target
            }

            let binding = processBinding()
            if let workspaceId = resolveAccessibleWorkspaceId(binding?.workspaceId),
               let target = resolveTarget(
                   workspaceId: workspaceId,
                   preferredSurfaceId: binding?.surfaceId,
                   mapped: mapped
               ) {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.target.resolved agent=\(def.name) subcommand=\(subcommand) session=\(agentHookDebugShort(sessionId)) source=process workspace=\(agentHookDebugShort(target.workspaceId)) surface=\(agentHookDebugShort(target.surfaceId)) mapped=\(mapped == nil ? 0 : 1)",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                return target
            }
            guard let workspaceId = resolveAccessibleWorkspaceId(mapped?.workspaceId) else {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.target.nil agent=\(def.name) subcommand=\(subcommand) session=\(agentHookDebugShort(sessionId)) reason=noWorkspace mapped=\(mapped == nil ? 0 : 1)",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                return nil
            }
            let target = resolveTarget(workspaceId: workspaceId, preferredSurfaceId: nil, mapped: mapped)
#if DEBUG
            agentHookDebugLog(
                "agentHook.target.\(target == nil ? "nil" : "resolved") agent=\(def.name) subcommand=\(subcommand) session=\(agentHookDebugShort(sessionId)) source=mapped workspace=\(agentHookDebugShort(target?.workspaceId ?? workspaceId)) surface=\(agentHookDebugShort(target?.surfaceId)) mapped=\(mapped == nil ? 0 : 1)",
                socketPath: client.socketPath,
                env: env
            )
#endif
            return target
        }
        defer {
            if !didSendFeedTelemetry, !shouldSuppressGenericFeedTelemetry() {
                sendAgentFeedTelemetry()
            }
        }

        switch action {
        case .sessionStart:
            let mapped = sessionId.isEmpty ? nil : (try? store.lookup(sessionId: sessionId))
            guard let target = resolveAgentHookTarget(mapped: mapped) else {
                didSendFeedTelemetry = true
                print("{}")
                return
            }
            let workspaceId = target.workspaceId
            let surfaceId = target.surfaceId
            let pid = inferredPID
            let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(currentAgentPID: pid, env: env)
            let launchCommand = agentLaunchCommandFromEnvironment(
                env,
                fallbackPID: pid,
                fallbackKind: def.name,
                cwd: hookCwd ?? mapped?.cwd
            )
            func codexSessionStartWentStaleAfterAccept() -> Bool {
                def.name == "codex" && ((try? store.codexSessionStartIsStale(
                    sessionId: sessionId,
                    incomingPID: pid,
                    includeTerminalPromptTurnIds: false
                )) == true)
            }
            if !sessionId.isEmpty {
                let acceptedSessionStart: Bool
                if def.name == "codex" {
                    acceptedSessionStart = (try? store.upsertCodexSessionStartIfFresh(
                        sessionId: sessionId,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        cwd: preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped),
                        transcriptPath: input.transcriptPath ?? mapped?.transcriptPath,
                        pid: pid,
                        launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped),
                        agentLifecycle: .unknown,
                        runtimeStatus: suppressVisibleMutations ? nil : .running,
                        updateRuntimeStatus: !suppressVisibleMutations
                    )) ?? false
                } else {
                    try? store.upsert(
                        sessionId: sessionId,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        cwd: preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped),
                        transcriptPath: input.transcriptPath ?? mapped?.transcriptPath,
                        pid: pid,
                        launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped),
                        agentLifecycle: .unknown,
                        runtimeStatus: suppressVisibleMutations ? nil : .running,
                        updateRuntimeStatus: !suppressVisibleMutations
                    )
                    acceptedSessionStart = true
                }
                if !acceptedSessionStart {
                    telemetry.breadcrumb("\(def.name)-hook.session-start.stale-after-turn")
                    didSendFeedTelemetry = true
                    print("{}")
                    return
                }
            }
            if codexSessionStartWentStaleAfterAccept() {
                telemetry.breadcrumb("\(def.name)-hook.session-start.stale-after-turn")
                didSendFeedTelemetry = true
                print("{}")
                return
            }
            sendAgentFeedTelemetryUnlessSuppressed(workspaceId: workspaceId, surfaceId: surfaceId)
            if !suppressVisibleMutations {
                if codexSessionStartWentStaleAfterAccept() {
                    telemetry.breadcrumb("\(def.name)-hook.session-start.stale-after-turn")
                    didSendFeedTelemetry = true
                    print("{}")
                    return
                }
                try? recordAgentTurnDiffBaseline(
                    agent: def.name,
                    sessionId: sessionId,
                    turnId: input.turnId,
                    cwd: hookCwd ?? mapped?.cwd,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    env: env,
                    preserveExistingTurnBaseline: true
                )
            }
            if !sessionId.isEmpty {
                if suppressVisibleMutations {
                    telemetry.breadcrumb("\(def.name)-hook.session-start.nested-suppressed")
                } else {
                    if codexSessionStartWentStaleAfterAccept() {
                        telemetry.breadcrumb("\(def.name)-hook.session-start.stale-after-turn")
                        didSendFeedTelemetry = true
                        print("{}")
                        return
                    }
                    if !AgentHookNotificationPolicy.preservesDedupeAcrossSessionStart(agentName: def.name) {
                        try? store.clearNotificationEmission(sessionId: sessionId)
                    }
                    publishAgentSurfaceResumeBinding(
                        client: client,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        kind: def.name,
                        displayName: def.displayName,
                        sessionId: sessionId,
                        cwd: preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped),
                        launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped)
                    )
                }
            }
            if codexSessionStartWentStaleAfterAccept() {
                telemetry.breadcrumb("\(def.name)-hook.session-start.stale-after-turn")
                didSendFeedTelemetry = true
                print("{}")
                return
            }
            if let pid, !suppressVisibleMutations {
                _ = try? sendV1Command(
                    "set_agent_pid \(pidKey) \(pid) --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
            }
            setAgentLifecycle(
                client: client,
                key: def.statusKey,
                lifecycle: .unknown,
                workspaceId: workspaceId,
                surfaceId: surfaceId
            )

        case .promptSubmit:
            let mapped = sessionId.isEmpty ? nil : (try? store.lookup(sessionId: sessionId))
            guard let target = resolveAgentHookTarget(mapped: mapped) else {
                didSendFeedTelemetry = true
                print("{}")
                return
            }
            let workspaceId = target.workspaceId
            let surfaceId = target.surfaceId
            let pid = mapped?.pid ?? inferredPID
            let launchCommand = agentLaunchCommandFromEnvironment(
                env,
                fallbackPID: pid,
                fallbackKind: def.name,
                cwd: hookCwd ?? mapped?.cwd
            )
            let transcriptPathForStore = input.transcriptPath ?? mapped?.transcriptPath
            let activePromptTurnStack = mapped?.activePromptTurnIds?
                .compactMap({ normalizedHookValue($0) }) ?? []
            let activePromptTurnId = activePromptTurnStack.last ?? normalizedHookValue(mapped?.activePromptTurnId)
            let activePromptDepth = max(mapped?.activePromptDepth ?? 0, activePromptTurnStack.count)
            let incomingTurnId = normalizedHookValue(input.turnId)
            let terminalPromptTurnIds = Set((mapped?.terminalPromptTurnIds ?? []).compactMap { normalizedHookValue($0) })
            let incomingCodexTurnIsTerminal = def.name == "codex" &&
                (incomingTurnId.map { terminalPromptTurnIds.contains($0) } ?? false)
            func codexPromptTurnWentTerminal() -> Bool {
                def.name == "codex"
                    && ((try? store.codexPromptTurnIsTerminal(sessionId: sessionId, turnId: input.turnId)) == true)
            }
            func restoreCodexPromptVisibleStateFromStore() {
                guard def.name == "codex",
                      let latest = try? store.lookup(sessionId: sessionId) else {
                    setIdleStatusUnlessAnotherSessionIsRunning(workspaceId: workspaceId, surfaceId: surfaceId)
                    return
                }
                publishAgentSurfaceResumeBinding(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    kind: def.name,
                    displayName: def.displayName,
                    sessionId: sessionId,
                    cwd: latest.cwd,
                    launchCommand: latest.launchCommand
                )
                if let lifecycle = latest.agentLifecycle {
                    setAgentLifecycle(
                        client: client,
                        key: def.statusKey,
                        lifecycle: lifecycle,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId
                    )
                }
                switch latest.runtimeStatus {
                case .running?:
                    setAgentLifecycle(
                        client: client,
                        key: def.statusKey,
                        lifecycle: .running,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId
                    )
                    let runningStatus = String(localized: "agent.generic.status.running", defaultValue: "Running")
                    _ = try? sendV1Command(
                        "set_status \(def.statusKey) \(runningStatus) --icon=bolt.fill --color=#4C8DFF --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                        client: client
                    )
                case .idle?:
                    if !hasNewerRunningSession(workspaceId: workspaceId, surfaceId: surfaceId) {
                        setAgentLifecycle(
                            client: client,
                            key: def.statusKey,
                            lifecycle: .idle,
                            workspaceId: workspaceId,
                            surfaceId: surfaceId
                        )
                    }
                    setIdleStatusUnlessAnotherSessionIsRunning(workspaceId: workspaceId, surfaceId: surfaceId)
                case .needsInput?:
                    setAgentLifecycle(
                        client: client,
                        key: def.statusKey,
                        lifecycle: .needsInput,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId
                    )
                    let statusValue = String.localizedStringWithFormat(
                        String(localized: "agent.generic.notification.status.needsInput", defaultValue: "%@ needs input"),
                        def.displayName
                    )
                    _ = try? sendV1Command(
                        "set_status \(def.statusKey) \(statusValue) --icon=bell.fill --color=#4C8DFF --priority=100 --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                        client: client
                    )
                case .error?:
                    setAgentLifecycle(
                        client: client,
                        key: def.statusKey,
                        lifecycle: .needsInput,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId
                    )
                    let statusValue = String.localizedStringWithFormat(
                        String(localized: "agent.generic.notification.status.error", defaultValue: "%@ error"),
                        def.displayName
                    )
                    _ = try? sendV1Command(
                        "set_status \(def.statusKey) \(statusValue) --icon=exclamationmark.triangle.fill --color=#FF453A --priority=100 --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                        client: client
                    )
                case nil:
                    break
                }
            }
            func stopStaleCodexPromptSubmit(restoreVisibleState: Bool = false) {
                if restoreVisibleState {
                    restoreCodexPromptVisibleStateFromStore()
                }
                telemetry.breadcrumb("\(def.name)-hook.prompt-submit.stale-terminal-turn")
                didSendFeedTelemetry = true
                print("{}")
            }
            let terminalActivePromptTurnIds: Set<String>
            let previousActivePromptTurnIsTerminal: Bool
            if def.name == "codex",
               let incomingTurnId,
               let activeTurnId = activePromptTurnId,
               activeTurnId != incomingTurnId,
               let transcriptPath = normalizedHookValue(transcriptPathForStore)
                   ?? findCodexTranscriptPath(sessionId: sessionId, env: env) {
                let activeTurnIds = activePromptTurnStack.isEmpty ? [activeTurnId] : activePromptTurnStack
                terminalActivePromptTurnIds = codexTranscriptTerminalTurnIds(
                    path: transcriptPath,
                    turnIds: Set(activeTurnIds)
                )
                previousActivePromptTurnIsTerminal = terminalActivePromptTurnIds.contains(activeTurnId)
            } else {
                terminalActivePromptTurnIds = []
                previousActivePromptTurnIsTerminal = false
            }
            let nestedPromptSubmit: Bool
            if !sessionId.isEmpty {
                if incomingCodexTurnIsTerminal {
                    nestedPromptSubmit = false
                } else {
                    let recordResult = (try? store.recordPromptSubmit(
                        sessionId: sessionId,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        cwd: preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped),
                        transcriptPath: transcriptPathForStore,
                        turnId: input.turnId,
                        previousActivePromptTurnIsTerminal: previousActivePromptTurnIsTerminal,
                        terminalActivePromptTurnIds: terminalActivePromptTurnIds,
                        pid: pid,
                        launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped),
                        agentLifecycle: .running,
                        autoNameMessages: autoNamingMessages(
                            for: def,
                            parsedInput: input,
                            client: client,
                            workspaceId: workspaceId
                        ),
                        rejectTerminalTurn: def.name == "codex"
                    )) ?? (staleTerminalTurn: false, nested: false)
                    if recordResult.staleTerminalTurn {
                        stopStaleCodexPromptSubmit()
                        return
                    }
                    nestedPromptSubmit = recordResult.nested
                }
            } else {
                nestedPromptSubmit = false
            }
            let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(
                currentAgentPID: pid,
                nestedPromptEvent: nestedPromptSubmit,
                env: env
            )
            if !suppressVisibleMutations && !incomingCodexTurnIsTerminal {
                if codexPromptTurnWentTerminal() {
                    stopStaleCodexPromptSubmit()
                    return
                }
                try? recordAgentTurnDiffBaseline(
                    agent: def.name,
                    sessionId: sessionId,
                    turnId: input.turnId,
                    cwd: hookCwd ?? mapped?.cwd,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    env: env,
                    preserveExistingTurnBaseline: activePromptDepth > 0 &&
                        (normalizedHookValue(input.turnId).map { $0 == activePromptTurnId } ?? false)
                )
            }
            if incomingCodexTurnIsTerminal || codexPromptTurnWentTerminal() {
                stopStaleCodexPromptSubmit()
                return
            }
            sendAgentFeedTelemetryUnlessSuppressed(workspaceId: workspaceId, surfaceId: surfaceId)
            if !sessionId.isEmpty, !suppressVisibleMutations {
                let acceptedRunningUpdate: Bool
                if def.name == "codex" {
                    acceptedRunningUpdate = (try? store.upsertCodexPromptRunningIfFresh(
                        sessionId: sessionId,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        cwd: preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped),
                        transcriptPath: input.transcriptPath ?? mapped?.transcriptPath,
                        turnId: input.turnId,
                        pid: pid,
                        launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped)
                    )) ?? false
                } else {
                    try? store.upsert(
                        sessionId: sessionId,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        cwd: preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped),
                        transcriptPath: input.transcriptPath ?? mapped?.transcriptPath,
                        pid: pid,
                        launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped),
                        agentLifecycle: .running,
                        runtimeStatus: .running,
                        updateRuntimeStatus: true
                    )
                    acceptedRunningUpdate = true
                }
                if !acceptedRunningUpdate || codexPromptTurnWentTerminal() {
                    stopStaleCodexPromptSubmit()
                    return
                }
                try? store.clearNotificationEmission(sessionId: sessionId)
                publishAgentSurfaceResumeBinding(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    kind: def.name,
                    displayName: def.displayName,
                    sessionId: sessionId,
                    cwd: preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped),
                    launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped)
                )
                if codexPromptTurnWentTerminal() {
                    stopStaleCodexPromptSubmit(restoreVisibleState: true)
                    return
                }
            }
            if codexPromptTurnWentTerminal() {
                stopStaleCodexPromptSubmit()
                return
            }
            if let pid, !suppressVisibleMutations {
                _ = try? sendV1Command(
                    "set_agent_pid \(pidKey) \(pid) --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
                if codexPromptTurnWentTerminal() {
                    stopStaleCodexPromptSubmit(restoreVisibleState: true)
                    return
                }
            }
            if !suppressVisibleMutations {
                if codexPromptTurnWentTerminal() {
                    stopStaleCodexPromptSubmit()
                    return
                }
                setAgentLifecycle(
                    client: client,
                    key: def.statusKey,
                    lifecycle: .running,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId
                )
                if codexPromptTurnWentTerminal() {
                    stopStaleCodexPromptSubmit(restoreVisibleState: true)
                    return
                }
                _ = try? sendV1Command(
                    "clear_notifications --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
                let runningStatus = String(localized: "agent.generic.status.running", defaultValue: "Running")
                _ = try sendV1Command(
                    "set_status \(def.statusKey) \(runningStatus) --icon=bolt.fill --color=#4C8DFF --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
                if codexPromptTurnWentTerminal() {
                    stopStaleCodexPromptSubmit(restoreVisibleState: true)
                    return
                }
            } else {
                telemetry.breadcrumb("\(def.name)-hook.prompt-submit.nested-suppressed")
            }
            if def.name == "codex", !sessionId.isEmpty, !suppressVisibleMutations {
                if codexPromptTurnWentTerminal() {
                    stopStaleCodexPromptSubmit(restoreVisibleState: true)
                    return
                }
                let leasePath = createCodexMonitorLease(
                    sessionId: sessionId,
                    turnId: input.turnId,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    env: env
                )
                if leasePath == nil {
                    telemetry.breadcrumb(
                        "codex-hook.monitor.lease-unavailable",
                        data: ["has_turn_id": normalizedHookValue(input.turnId) != nil]
                    )
                } else {
                    retireCodexMonitorLeases(
                        sessionId: sessionId,
                        turnId: nil,
                        preservingLeasePath: leasePath,
                        env: env
                    )
                }
                startCodexTranscriptMonitor(
                    sessionId: sessionId,
                    turnId: input.turnId,
                    transcriptPath: normalizedHookValue(input.transcriptPath),
                    cwd: hookCwd ?? mapped?.cwd,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    leasePath: leasePath,
                    env: env,
                    telemetry: telemetry
                )
            }

        case .stop:
            if def.name == "codex", !sessionId.isEmpty {
                let stopTurnId = input.turnId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                if !stopTurnId.isEmpty {
                    retireCodexMonitorLeases(sessionId: sessionId, turnId: stopTurnId, env: env)
                }
            }
            let mapped = sessionId.isEmpty ? nil : (try? store.lookup(sessionId: sessionId))
            guard let target = resolveAgentHookTarget(mapped: mapped) else {
                didSendFeedTelemetry = true
                print("{}")
                return
            }
            let workspaceId = target.workspaceId
            let surfaceId = target.surfaceId
            sendAgentFeedTelemetry(workspaceId: workspaceId, surfaceId: surfaceId)
            let pid = mapped?.pid ?? inferredPID
            let codexFailure: CodexHookFailureSummary?
            let codexSubagentSignals: CodexTranscriptSubagentSignals
            if def.name == "codex" {
                codexFailure = summarizeCodexHookFailure(parsedInput: input, sessionId: sessionId, env: env)
                if subagentNotificationSuppressionEnabled(env: env),
                   let transcriptPath = normalizedHookValue(input.transcriptPath)
                    ?? findCodexTranscriptPath(sessionId: sessionId, env: env) {
                    codexSubagentSignals = readCodexTranscriptSubagentSignals(
                        path: transcriptPath,
                        turnId: input.turnId
                    )
                } else {
                    codexSubagentSignals = CodexTranscriptSubagentSignals()
                }
            } else {
                codexFailure = nil
                codexSubagentSignals = CodexTranscriptSubagentSignals()
            }
            let antigravityFailure: AgentHookNotificationSummary? = {
                guard def.name == "antigravity", let rawObject = input.rawObject else { return nil }
                let signal = firstString(in: rawObject, keys: ["terminationReason", "reason", "type", "kind"]) ?? ""
                let message = firstString(in: rawObject, keys: ["error", "message", "description"]) ?? signal
                let summary = classifyAgentHookNotification(
                    def: def,
                    signal: signal,
                    message: message,
                    isFallback: false
                )
                return summary.status == .error ? summary : nil
            }()

            let rawCwd = hookCwd ?? mapped?.cwd
            let launchCommand = agentLaunchCommandFromEnvironment(env, fallbackPID: pid, fallbackKind: def.name, cwd: rawCwd)
            let cwd = preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped)
            let grokAssistantMessage: String? = {
                guard def.name == "grok" else { return nil }
                return latestGrokAssistantMessage(
                    cwd: cwd,
                    sessionId: input.sessionId ?? sessionId,
                    env: env
                )
            }()
            let lastMsg = claudeAssistantMessageFromHookPayload(input.object)
            let projectName: String? = {
                guard let cwd, !cwd.isEmpty else { return nil }
                return URL(fileURLWithPath: NSString(string: cwd).expandingTildeInPath).lastPathComponent
            }()
            var subtitle = codexFailure?.subtitle ?? String(
                localized: "agent.codex.completion.subtitle.completed",
                defaultValue: "Completed"
            )
            if let antigravityFailure {
                subtitle = antigravityFailure.subtitle
            }
            if codexFailure == nil, antigravityFailure == nil, let projectName, !projectName.isEmpty {
                subtitle = String.localizedStringWithFormat(
                    String(
                        localized: "agent.codex.completion.subtitle.completedInProject",
                        defaultValue: "Completed in %@"
                    ),
                    projectName
                )
            }
            let body = codexFailure?.body
                ?? antigravityFailure?.body
                ?? lastMsg.map { truncate(normalizedSingleLine($0), maxLength: 200) }
                ?? grokAssistantMessage.map { truncate(normalizedSingleLine($0), maxLength: 200) }
                ?? String.localizedStringWithFormat(
                    String(
                        localized: "agent.codex.completion.body.sessionCompleted",
                        defaultValue: "%@ session completed"
                    ),
                    def.displayName
            )
            let antigravityHasActiveBackgroundWork = hasActiveAntigravityBackgroundWork()
            let stopNotificationStatus: AgentHookNotificationStatus = (codexFailure == nil && antigravityFailure == nil) ? .idle : .error
            let lifecycleAfterStop: AgentHibernationLifecycleState = {
                if antigravityHasActiveBackgroundWork && stopNotificationStatus == .idle {
                    return .running
                }
                return stopNotificationStatus == .idle ? .idle : .needsInput
            }()
            let staleIdleStopHasNewerRunningSession = lifecycleAfterStop == .idle &&
                hasNewerRunningSession(workspaceId: workspaceId, surfaceId: surfaceId)
            let terminalActivePromptTurnIdsForStop: Set<String>
            if !staleIdleStopHasNewerRunningSession,
               def.name == "codex",
               let incomingTurnId = normalizedHookValue(input.turnId) {
                let activePromptTurnStack = mapped?.activePromptTurnIds?
                    .compactMap({ normalizedHookValue($0) }) ?? []
                let activePromptTurnId = activePromptTurnStack.last ?? normalizedHookValue(mapped?.activePromptTurnId)
                let activeTurnIds = activePromptTurnStack.isEmpty
                    ? activePromptTurnId.map { [$0] } ?? []
                    : activePromptTurnStack
                let activeTurnIdsToCheck = activeTurnIds.filter { $0 != incomingTurnId }
                if !activeTurnIdsToCheck.isEmpty,
                   let transcriptPath = normalizedHookValue(input.transcriptPath ?? mapped?.transcriptPath)
                       ?? findCodexTranscriptPath(sessionId: sessionId, env: env) {
                    terminalActivePromptTurnIdsForStop = codexTranscriptTerminalTurnIds(
                        path: transcriptPath,
                        turnIds: Set(activeTurnIdsToCheck)
                    )
                } else {
                    terminalActivePromptTurnIdsForStop = []
                }
            } else {
                terminalActivePromptTurnIdsForStop = []
            }
            let nestedPromptStop: Bool
            if !sessionId.isEmpty, !staleIdleStopHasNewerRunningSession {
                nestedPromptStop = (try? store.recordPromptStop(
                    sessionId: sessionId,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    cwd: cwd,
                    transcriptPath: input.transcriptPath ?? mapped?.transcriptPath,
                    turnId: input.turnId,
                    terminalActivePromptTurnIds: terminalActivePromptTurnIdsForStop,
                    pid: pid,
                    launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped),
                    agentLifecycle: lifecycleAfterStop,
                    lastSubtitle: nil,
                    lastBody: nil,
                    autoNameMessages: autoNamingMessages(
                        for: def,
                        parsedInput: input,
                        client: client,
                        workspaceId: workspaceId
                    )
                )) ?? false
            } else {
                nestedPromptStop = false
            }
            let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(
                currentAgentPID: pid,
                nestedPromptEvent: nestedPromptStop,
                transcriptSubagentSession: codexSubagentSignals.isSubagentSession,
                env: env
            ) || staleIdleStopHasNewerRunningSession
            let suppressCompletionNotification = suppressVisibleMutations
                || codexSubagentSignals.hasSubagentNotificationRelay

            if !sessionId.isEmpty, !suppressVisibleMutations {
                try? store.upsert(sessionId: sessionId, workspaceId: workspaceId, surfaceId: surfaceId, cwd: cwd,
                                  transcriptPath: input.transcriptPath ?? mapped?.transcriptPath,
                                  pid: pid,
                                  launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped),
                                  agentLifecycle: lifecycleAfterStop,
                                  lastSubtitle: subtitle,
                                  lastBody: body,
                                  lastNotificationStatus: stopNotificationStatus,
                                  updateLastNotificationStatus: true,
                                  runtimeStatus: (antigravityHasActiveBackgroundWork && stopNotificationStatus == .idle) ? .running : runtimeStatus(for: stopNotificationStatus),
                                  updateRuntimeStatus: true)
                publishAgentSurfaceResumeBinding(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    kind: def.name,
                    displayName: def.displayName,
                    sessionId: sessionId,
                    cwd: cwd,
                    launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped)
                )
            }
            if let pid, !suppressVisibleMutations {
                _ = try? sendV1Command(
                    "set_agent_pid \(pidKey) \(pid) --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
            }

            let notificationFingerprint = notificationDedupeFingerprint(
                status: stopNotificationStatus,
                category: stopNotificationStatus == .idle ? .turnComplete : .other,
                body: body
            )
            let stopNotificationAlreadyRouted = (input.rawObject?["cmux_notification_routed"] as? Bool) == true
                || (input.object?["cmux_notification_routed"] as? Bool) == true
            // Antigravity's integration defines a stop with active background work
            // (fullyIdle=false) as an intermediate event, not a completed turn: its
            // completion ping arrives at the later fullyIdle stop. Deliberately NOT
            // routed through the app-side agentTurnComplete gate — publishing here
            // would mark the dedupe fingerprint and swallow the real final ping.
            let shouldPublishStopNotification = def.publishesStopNotification
                && !stopNotificationAlreadyRouted
                && (!antigravityHasActiveBackgroundWork || stopNotificationStatus == .error)
            let hasGrokTranscriptContext = def.name == "grok" && normalizedHookValue(cwd) != nil
            let shouldPublishGrokStopFallbackNotification = def.name == "grok"
                && stopNotificationStatus == .idle
                && (grokAssistantMessage != nil || !hasGrokTranscriptContext)
            let shouldPublishStopAlert = (shouldPublishStopNotification || shouldPublishGrokStopFallbackNotification)
                && !suppressCompletionNotification
            if suppressVisibleMutations {
                telemetry.breadcrumb(
                    staleIdleStopHasNewerRunningSession
                        ? "\(def.name)-hook.stop.stale-idle-suppressed"
                        : "\(def.name)-hook.stop.nested-suppressed"
                )
            } else if suppressCompletionNotification {
                telemetry.breadcrumb("\(def.name)-hook.stop.subagent-notification-suppressed")
            }
            if shouldPublishStopAlert, shouldSendNotification(fingerprint: notificationFingerprint) {
                // Tag successful turn-end pings so the app's "Agent Finished"
                // setting covers every built-in agent, not just Claude. Error
                // alerts stay untagged and always deliver.
                let stopMeta: String? = stopNotificationStatus == .idle
                    ? AgentHookNotifyCategory.turnComplete.metaSegment(pending: antigravityHasActiveBackgroundWork)
                    : nil
                let payload = notificationPayload(title: def.displayName, subtitle: subtitle, body: body, meta: stopMeta)
                let notifyCommand = "notify_target_async \(workspaceId) \(surfaceId) \(payload)"
#if DEBUG
                agentHookDebugLog(
                    "agentHook.stop.notify agent=\(def.name) session=\(agentHookDebugShort(sessionId)) fallback=\(shouldPublishGrokStopFallbackNotification ? 1 : 0) workspace=\(agentHookDebugShort(workspaceId)) surface=\(agentHookDebugShort(surfaceId)) subtitleLen=\(subtitle.count) bodyLen=\(body.count)",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                do {
                    let response = try sendV1Command(notifyCommand, client: client)
#if DEBUG
                    agentHookDebugLog(
                        "agentHook.stop.notify.sent agent=\(def.name) session=\(agentHookDebugShort(sessionId)) response=\(response)",
                        socketPath: client.socketPath,
                        env: env
                    )
#endif
                    markNotificationSent(fingerprint: notificationFingerprint)
                } catch {
#if DEBUG
                    agentHookDebugLog(
                        "agentHook.stop.notify.error agent=\(def.name) session=\(agentHookDebugShort(sessionId)) error=\(String(describing: error))",
                        socketPath: client.socketPath,
                        env: env
                    )
#endif
                }
            } else if shouldPublishStopAlert {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.stop.notify.skipDuplicate agent=\(def.name) session=\(agentHookDebugShort(sessionId)) fallback=\(shouldPublishGrokStopFallbackNotification ? 1 : 0) fingerprint=\(agentHookDebugShort(notificationFingerprint))",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
            }
            if !suppressVisibleMutations {
                if let codexFailure {
                    setAgentLifecycle(
                        client: client,
                        key: def.statusKey,
                        lifecycle: .needsInput,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId
                    )
                    _ = try? sendV1Command(
                        "set_status \(def.statusKey) \(codexFailure.statusValue) --icon=exclamationmark.triangle.fill --color=#FF453A --priority=100 --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                        client: client
                    )
                } else if antigravityFailure != nil {
                    setAgentLifecycle(
                        client: client,
                        key: def.statusKey,
                        lifecycle: .needsInput,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId
                    )
                    let statusValue = String.localizedStringWithFormat(
                        String(localized: "agent.generic.notification.status.error", defaultValue: "%@ error"),
                        def.displayName
                    )
                    _ = try? sendV1Command(
                        "set_status \(def.statusKey) \(statusValue) --icon=exclamationmark.triangle.fill --color=#FF453A --priority=100 --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                        client: client
                    )
                } else if antigravityHasActiveBackgroundWork {
                    setAgentLifecycle(
                        client: client,
                        key: def.statusKey,
                        lifecycle: .running,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId
                    )
                    let runningStatus = String(localized: "agent.generic.status.running", defaultValue: "Running")
                    _ = try? sendV1Command(
                        "set_status \(def.statusKey) \(runningStatus) --icon=bolt.fill --color=#4C8DFF --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                        client: client
                    )
                } else {
                    setAgentLifecycle(
                        client: client,
                        key: def.statusKey,
                        lifecycle: .idle,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId
                    )
                    setIdleStatusUnlessAnotherSessionIsRunning(workspaceId: workspaceId, surfaceId: surfaceId)
                }
            }

            // Opt-in auto-naming for generic-agent sessions: a detached pass so the
            // summarization subprocess never blocks this short sync hook.
            // Gate the fork on the live setting (one cheap socket probe) so a
            // disabled feature spawns nothing extra on turn end; the detached
            // process re-probes to honor a toggle that lands mid-pass.
            if autoNamingSource(for: def) != nil, !suppressVisibleMutations, !sessionId.isEmpty,
               let autoNameProbe = try? client.sendV2(
                   method: "workspace.set_auto_title",
                   params: ["probe": true, "workspace_id": workspaceId]
               ),
               autoNameProbe["enabled"] as? Bool == true,
               autoNameProbe["workspace_user_owned"] as? Bool != true {
                spawnDetachedAgentAutoName(
                    def: def,
                    sessionId: sessionId,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    transcriptPath: normalizedHookValue(input.transcriptPath ?? mapped?.transcriptPath),
                    cwd: cwd,
                    env: env,
                    telemetry: telemetry
                )
            }

        case .approvalResponse:
            let mapped = sessionId.isEmpty ? nil : (try? store.lookup(sessionId: sessionId))
            guard let target = resolveAgentHookTarget(mapped: mapped) else {
                didSendFeedTelemetry = true
                print("{}")
                return
            }
            let workspaceId = target.workspaceId
            let surfaceId = target.surfaceId
            sendAgentFeedTelemetryUnlessSuppressed(workspaceId: workspaceId, surfaceId: surfaceId)
            let pid = mapped?.pid ?? inferredPID
            let launchCommand = agentLaunchCommandFromEnvironment(
                env,
                fallbackPID: pid,
                fallbackKind: def.name,
                cwd: hookCwd ?? mapped?.cwd
            )
            let suppressVisibleMutations = shouldSuppressNestedAgentVisibleMutations(currentAgentPID: pid, env: env)
            if !sessionId.isEmpty, !suppressVisibleMutations {
                try? store.markNotificationResolved(
                    sessionId: sessionId,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    cwd: preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped),
                    transcriptPath: input.transcriptPath ?? mapped?.transcriptPath,
                    pid: pid,
                    launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped),
                    agentLifecycle: .running,
                    runtimeStatus: .running
                )
                publishAgentSurfaceResumeBinding(
                    client: client,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId,
                    kind: def.name,
                    displayName: def.displayName,
                    sessionId: sessionId,
                    cwd: preferredAgentHookResumeWorkingDirectory(kind: def.name, current: launchCommand, currentCwd: hookCwd, mapped: mapped),
                    launchCommand: preferredAgentHookResumeLaunchCommand(kind: def.name, current: launchCommand, mapped: mapped)
                )
            }
            if let pid, !suppressVisibleMutations {
                _ = try? sendV1Command(
                    "set_agent_pid \(pidKey) \(pid) --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
            }
            if !suppressVisibleMutations {
                setAgentLifecycle(
                    client: client,
                    key: def.statusKey,
                    lifecycle: .running,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId
                )
                _ = try? sendV1Command(
                    "clear_notifications --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
                let runningStatus = String(localized: "agent.generic.status.running", defaultValue: "Running")
                _ = try? sendV1Command(
                    "set_status \(def.statusKey) \(runningStatus) --icon=bolt.fill --color=#4C8DFF --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
            } else {
                telemetry.breadcrumb("\(def.name)-hook.approval-response.nested-suppressed")
            }

        case .notification:
            let mapped = sessionId.isEmpty ? nil : (try? store.lookup(sessionId: sessionId))
            guard let target = resolveAgentHookTarget(mapped: mapped) else {
                didSendFeedTelemetry = true
                print("{}")
                return
            }
            let workspaceId = target.workspaceId
            let surfaceId = target.surfaceId

            let notificationCwd = hookCwd ?? mapped?.cwd
#if DEBUG
            agentHookDebugLog(
                "agentHook.notification.target agent=\(def.name) session=\(agentHookDebugShort(sessionId)) workspace=\(agentHookDebugShort(workspaceId)) surface=\(agentHookDebugShort(surfaceId)) mapped=\(mapped == nil ? 0 : 1) hasCwd=\(notificationCwd == nil ? 0 : 1)",
                socketPath: client.socketPath,
                env: env
            )
#endif
            if def.name == "grok",
               let notificationMessage = normalizedAgentHookNotificationMessage(parsedInput: input) {
                if isGrokInternalSessionNotification(notificationMessage) {
#if DEBUG
                    agentHookDebugLog(
                        "agentHook.notification.skip agent=\(def.name) session=\(agentHookDebugShort(sessionId)) reason=internalSessionNotification messageLen=\(notificationMessage.count)",
                        socketPath: client.socketPath,
                        env: env
                    )
#endif
                    print("{}")
                    return
                }
            }

            var summary = summarizeAgentHookNotification(
                def: def,
                parsedInput: input,
                cwd: notificationCwd,
                env: env,
                sessionId: input.sessionId ?? sessionId
            )
            if summary.isFallback, let savedBody = mapped?.lastBody, !savedBody.isEmpty {
                // Rebuilt from the stored session record: a stale .idle status is
                // still a completion re-notification, so keep it under the
                // "Agent Finished" gate. A stale non-idle status cannot
                // distinguish permission from waiting; the fresh permission
                // alert already delivered, so re-notifications gate as waiting.
                summary = AgentHookNotificationSummary(
                    subtitle: mapped?.lastSubtitle ?? summary.subtitle,
                    body: savedBody,
                    status: mapped?.lastNotificationStatus,
                    isFallback: false,
                    notifyCategory: mapped?.lastNotificationStatus == .idle ? .turnComplete : .idleReminder
                )
            }
            let antigravitySuppressDuplicateIdleWhileBackgroundWork = def.name == "antigravity"
                && summary.status == .idle
                && mapped?.runtimeStatus == .running
                && mapped?.lastNotificationStatus == .idle
                && hasActiveAntigravityBackgroundWork()

            // A waiting/idle nag while background work is still live is not a real
            // "needs input" state (same invariant as the Claude pending idle_prompt):
            // the banner is gated app-side (p=1) and the pane must stay Running
            // rather than flipping to "needs input".
            let suppressPendingWaitingState = summary.notifyCategory == .idleReminder
                && hasActiveAntigravityBackgroundWork()

#if DEBUG
            agentHookDebugLog(
                "agentHook.notification.summary agent=\(def.name) session=\(agentHookDebugShort(sessionId)) status=\(summary.status?.rawValue ?? "nil") fallback=\(summary.isFallback ? 1 : 0) subtitleLen=\(summary.subtitle.count) bodyLen=\(summary.body.count)",
                socketPath: client.socketPath,
                env: env
            )
#endif

            if def.name == "grok", summary.status == nil {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.notification.skip agent=\(def.name) session=\(agentHookDebugShort(sessionId)) reason=nonTerminalNotification subtitleLen=\(summary.subtitle.count) bodyLen=\(summary.body.count)",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                print("{}")
                return
            }

            if antigravitySuppressDuplicateIdleWhileBackgroundWork {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.notification.skip agent=\(def.name) session=\(agentHookDebugShort(sessionId)) reason=backgroundWorkIdleDuplicate",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                sendAgentFeedTelemetryUnlessSuppressed(workspaceId: workspaceId, surfaceId: surfaceId)
                print("{}")
                return
            }

            // A turn-complete notification while Antigravity still reports active
            // background work (fullyIdle=false) is an intermediate event, not a
            // turn boundary — the same invariant the stop lane enforces. Skip the
            // send AND the dedupe fingerprint: sending a gated payload here would
            // mark the idle fingerprint and swallow the real fullyIdle completion.
            if summary.notifyCategory == .turnComplete, hasActiveAntigravityBackgroundWork() {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.notification.skip agent=\(def.name) session=\(agentHookDebugShort(sessionId)) reason=backgroundWorkPendingTurnComplete",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                sendAgentFeedTelemetryUnlessSuppressed(workspaceId: workspaceId, surfaceId: surfaceId)
                print("{}")
                return
            }

            let staleIdleNotificationHasNewerRunningSession = summary.status == .idle &&
                hasNewerRunningSession(workspaceId: workspaceId, surfaceId: surfaceId)
            if staleIdleNotificationHasNewerRunningSession {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.notification.skip agent=\(def.name) session=\(agentHookDebugShort(sessionId)) reason=staleIdleNewerRunning workspace=\(agentHookDebugShort(workspaceId)) surface=\(agentHookDebugShort(surfaceId))",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                sendAgentFeedTelemetryUnlessSuppressed(workspaceId: workspaceId, surfaceId: surfaceId)
                print("{}")
                return
            }

            if !sessionId.isEmpty {
                let pid = mapped?.pid ?? inferredPID
                let launchCommand = agentLaunchCommandFromEnvironment(
                    env,
                    fallbackPID: pid,
                    fallbackKind: def.name,
                    cwd: hookCwd ?? mapped?.cwd
                )
                let lifecycle = suppressPendingWaitingState ? .running : agentLifecycle(for: summary.status)
                let storedRuntimeStatus: AgentHookRuntimeStatus? = suppressPendingWaitingState ? .running : runtimeStatus(for: summary.status)
                // These agents use completion notifications as turn boundaries;
                // keep the route but close nested prompt depth.
                if (def.name == "grok" || def.name == "antigravity"),
                   summary.status == .idle || summary.status == .error {
                    _ = try? store.recordPromptStop(
                        sessionId: sessionId,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        cwd: notificationCwd,
                        transcriptPath: input.transcriptPath ?? mapped?.transcriptPath,
                        pid: pid,
                        launchCommand: launchCommand,
                        agentLifecycle: lifecycle,
                        lastSubtitle: summary.subtitle,
                        lastBody: summary.body,
                        lastNotificationStatus: summary.status,
                        updateLastNotificationStatus: true,
                        runtimeStatus: storedRuntimeStatus,
                        updateRuntimeStatus: true,
                        autoNameMessages: autoNamingMessages(
                            for: def,
                            parsedInput: input,
                            client: client,
                            workspaceId: workspaceId
                        )
                    )
                } else {
                    try? store.upsert(
                        sessionId: sessionId,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId,
                        cwd: notificationCwd,
                        transcriptPath: input.transcriptPath ?? mapped?.transcriptPath,
                        pid: pid,
                        launchCommand: launchCommand,
                        agentLifecycle: lifecycle,
                        lastSubtitle: summary.subtitle,
                        lastBody: summary.body,
                        lastNotificationStatus: summary.status,
                        updateLastNotificationStatus: true,
                        runtimeStatus: storedRuntimeStatus,
                        updateRuntimeStatus: summary.status != nil
                    )
                }
            }

            let notificationFingerprint = notificationDedupeFingerprint(
                status: summary.status,
                category: summary.notifyCategory,
                body: summary.body
            )
            if shouldSendNotification(fingerprint: notificationFingerprint) {
                // Tag by the classifier's category so the app's agent notification
                // settings cover every built-in agent: approval prompts gate under
                // "Agent Needs Permission", waiting-for-input cues under "Agent
                // Waiting for Input", turn-boundary completions (grok and
                // antigravity route them through this hook) under "Agent
                // Finished". Errors and unclassified alerts stay untagged.
                // Completions AND waiting nags are both "pending" while
                // background work is live, so a fullyIdle=false Antigravity
                // waiting cue doesn't deliver a false "waiting for input".
                let notificationMeta = summary.notifyCategory.metaSegment(
                    pending: (summary.notifyCategory == .turnComplete || summary.notifyCategory == .idleReminder)
                        && hasActiveAntigravityBackgroundWork()
                )
                let payload = notificationPayload(title: def.displayName, subtitle: summary.subtitle, body: summary.body, meta: notificationMeta)
                let notifyCommand = "notify_target_async \(workspaceId) \(surfaceId) \(payload)"
#if DEBUG
                agentHookDebugLog(
                    "agentHook.notification.notify agent=\(def.name) session=\(agentHookDebugShort(sessionId)) workspace=\(agentHookDebugShort(workspaceId)) surface=\(agentHookDebugShort(surfaceId))",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                do {
                    let response = try sendV1Command(notifyCommand, client: client)
#if DEBUG
                    agentHookDebugLog(
                        "agentHook.notification.notify.sent agent=\(def.name) session=\(agentHookDebugShort(sessionId)) response=\(response)",
                        socketPath: client.socketPath,
                        env: env
                    )
#endif
                    markNotificationSent(fingerprint: notificationFingerprint)
                } catch {
#if DEBUG
                    agentHookDebugLog(
                        "agentHook.notification.notify.error agent=\(def.name) session=\(agentHookDebugShort(sessionId)) error=\(String(describing: error))",
                        socketPath: client.socketPath,
                        env: env
                    )
#endif
                }
            } else {
#if DEBUG
                agentHookDebugLog(
                    "agentHook.notification.notify.skipDuplicate agent=\(def.name) session=\(agentHookDebugShort(sessionId)) fingerprint=\(agentHookDebugShort(notificationFingerprint))",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
            }

            switch summary.status {
            case .needsInput? where suppressPendingWaitingState:
                // Suppressed pending waiting cue: leave the Running pill and
                // lifecycle in place; the fullyIdle turn boundary reconciles.
                break
            case .needsInput?:
                setAgentLifecycle(
                    client: client,
                    key: def.statusKey,
                    lifecycle: .needsInput,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId
                )
                let statusValue = String.localizedStringWithFormat(
                    String(localized: "agent.generic.notification.status.needsInput", defaultValue: "%@ needs input"),
                    def.displayName
                )
                _ = try? sendV1Command(
                    "set_status \(def.statusKey) \(statusValue) --icon=bell.fill --color=#4C8DFF --priority=100 --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
            case .error?:
                setAgentLifecycle(
                    client: client,
                    key: def.statusKey,
                    lifecycle: .needsInput,
                    workspaceId: workspaceId,
                    surfaceId: surfaceId
                )
                let statusValue = String.localizedStringWithFormat(
                    String(localized: "agent.generic.notification.status.error", defaultValue: "%@ error"),
                    def.displayName
                )
                _ = try? sendV1Command(
                    "set_status \(def.statusKey) \(statusValue) --icon=exclamationmark.triangle.fill --color=#FF453A --priority=100 --tab=\(workspaceId)\(socketPanelOption(surfaceId))",
                    client: client
                )
            case .idle?:
                if !hasNewerRunningSession(workspaceId: workspaceId, surfaceId: surfaceId) {
                    setAgentLifecycle(
                        client: client,
                        key: def.statusKey,
                        lifecycle: .idle,
                        workspaceId: workspaceId,
                        surfaceId: surfaceId
                    )
                }
                setIdleStatusUnlessAnotherSessionIsRunning(workspaceId: workspaceId, surfaceId: surfaceId)
            case nil:
                break
            }
            sendAgentFeedTelemetryUnlessSuppressed(workspaceId: workspaceId, surfaceId: surfaceId)

        case .sessionEnd:
            if def.name == "codex", !sessionId.isEmpty {
                retireCodexMonitorLeases(sessionId: sessionId, turnId: nil, env: env)
            }
            if def.sessionEndIsTurnBoundary {
                if let mapped = sessionId.isEmpty ? nil : (try? store.lookup(sessionId: sessionId)) {
                    sendAgentFeedTelemetry(workspaceId: mapped.workspaceId, surfaceId: mapped.surfaceId)
                    _ = try? store.recordPromptStop(
                        sessionId: sessionId,
                        workspaceId: mapped.workspaceId,
                        surfaceId: mapped.surfaceId,
                        cwd: hookCwd ?? mapped.cwd,
                        transcriptPath: input.transcriptPath ?? mapped.transcriptPath,
                        pid: mapped.pid,
                        launchCommand: mapped.launchCommand,
                        lastSubtitle: nil,
                        lastBody: nil,
                        autoNameMessages: autoNamingMessages(
                            for: def,
                            parsedInput: input,
                            client: client,
                            workspaceId: mapped.workspaceId
                        )
                    )
                }
#if DEBUG
                agentHookDebugLog(
                    "agentHook.sessionEnd.keep agent=\(def.name) session=\(agentHookDebugShort(sessionId)) reason=turnBoundary",
                    socketPath: client.socketPath,
                    env: env
                )
#endif
                break
            }
            // A non-turn-boundary session-end is a genuine teardown.
            performAgentSessionTeardown()

        case .sessionFinalize:
            performAgentSessionTeardown()

        case .noop:
            break
        }

        print("{}")
    }

    // MARK: - Feed telemetry helper

    /// Best-effort `feed.push` call used by the per-agent hook handlers
    /// so session-start / prompt-submit / stop events show up in Feed's
    /// "All" view even when no permission/plan/question event fires.
    /// Failures are swallowed.
    private func sendBestEffortFeedTelemetry(socketPath: String, line: String, socketPassword: String?) {
        let oneWayClient = SocketClient(path: socketPath)
        defer { oneWayClient.close() }
        do {
            try oneWayClient.connectWithoutRetry(responseTimeout: 0.05)
            try authenticateClientIfNeeded(
                oneWayClient,
                explicitPassword: socketPassword,
                socketPath: socketPath,
                responseTimeout: 0.05
            )
            try oneWayClient.sendOneWay(command: line, writeTimeout: 0.05)
        } catch {
            return
        }
    }

    private func sendFeedTelemetry(
        client: SocketClient,
        source: String,
        subcommand: String,
        parsedInput: ClaudeHookParsedInput,
        workspaceId: String? = nil,
        surfaceId: String? = nil,
        socketPassword: String? = nil
    ) {
        let hookEventName = Self.feedEventName(forClaudeSubcommand: subcommand)
        guard !hookEventName.isEmpty else { return }
        let promptText = hookEventName == "UserPromptSubmit"
            ? (feedPromptText(from: parsedInput.object) ?? parsedInput.rawFallback)
            : nil
        let fallbackObject = parsedInput.rawObject ?? parsedInput.object ?? [:]
        let agentPid = agentPidForFeedSource(source)
        let sessionId = parsedInput.sessionId ?? stableFallbackFeedSessionId(
            source: source,
            rawObject: fallbackObject,
            agentPid: agentPid
        )
        var event: [String: Any] = [
            "session_id": "\(source)-\(sessionId)",
            "hook_event_name": hookEventName,
            "_source": source,
            "_ppid": agentPid,
        ]
        if let workspaceId = feedWorkspaceId(rawObject: parsedInput.object, fallback: workspaceId) {
            event["workspace_id"] = workspaceId
        }
        if let surfaceId, !surfaceId.isEmpty {
            event["surface_id"] = surfaceId
        }
        if let transcriptPath = parsedInput.transcriptPath, !transcriptPath.isEmpty {
            event["transcript_path"] = transcriptPath
        }
        if let cwd = parsedInput.cwd { event["cwd"] = cwd }
        let toolName = parsedInput.object?["tool_name"] as? String
        if let toolName, !toolName.isEmpty {
            event["tool_name"] = toolName
        }
        if let toolInput = parsedInput.object?["tool_input"] {
            event["tool_input"] = toolInput
        }
        if let context = feedContextForEvent(
            source: source,
            hookEventName: hookEventName,
            toolName: toolName,
            toolInput: event["tool_input"],
            rawObject: parsedInput.object,
            transcriptPath: parsedInput.transcriptPath
        ) {
            event["context"] = context
        }
        enrichUserPromptSubmitFeedEvent(
            &event,
            hookEventName: hookEventName,
            promptText: promptText
        )
        event["_opencode_request_id"] = "\(source)-\(sessionId)-\(hookEventName)-\(Int(Date().timeIntervalSince1970 * 1000))"

        let frame: [String: Any] = [
            "method": "feed.push",
            "params": [
                "event": event,
                "wait_timeout_seconds": 0,
            ],
        ]
        guard let data = try? JSONSerialization.data(withJSONObject: frame),
              let line = String(data: data, encoding: .utf8)
        else { return }
        sendBestEffortFeedTelemetry(socketPath: client.socketPath, line: line, socketPassword: socketPassword)
    }

    private func feedContextForEvent(
        source: String,
        hookEventName: String,
        toolName: String?,
        toolInput: Any?,
        rawObject: [String: Any]?,
        transcriptPath: String?
    ) -> [String: Any]? {
        var context: [String: Any] = [:]

        if let rawContext = rawObject?["context"] as? [String: Any] {
            mergeFeedContext(&context, feedContext(from: rawContext))
        }

        if hookEventName == "UserPromptSubmit" {
            setFeedContext(
                &context,
                key: "lastUserMessage",
                value: feedPromptText(from: rawObject),
                maxLength: 1_000
            )
        }

        if let rawObject {
            setFeedContext(
                &context,
                key: "permissionMode",
                value: firstString(in: rawObject, keys: ["permissionMode", "permission_mode"]),
                maxLength: 80
            )
            setFeedContext(
                &context,
                key: "assistantPreamble",
                value: firstString(
                    in: rawObject,
                    keys: ["assistantPreamble", "assistant_preamble", "last_assistant_message", "lastAssistantMessage"]
                ),
                maxLength: 1_000
            )
        }

        if source == "claude",
           let transcriptPath,
           shouldReadTranscriptForFeedContext(hookEventName: hookEventName),
           let transcriptContext = readClaudeFeedContext(
                path: transcriptPath,
                matchingToolName: toolName
           ) {
            mergeFeedContext(&context, transcriptContext)
        }

        if let planContext = feedPlanContext(from: toolInput) {
            mergeFeedContext(&context, planContext, preferIncoming: true)
        }
        if let toolContext = feedToolContext(toolName: toolName, toolInput: toolInput) {
            mergeFeedContext(&context, toolContext)
        }

        return context.isEmpty ? nil : context
    }

    private func shouldReadTranscriptForFeedContext(hookEventName: String) -> Bool {
        switch hookEventName {
        case "PermissionRequest", "ExitPlanMode", "AskUserQuestion", "PreToolUse":
            return true
        default:
            return false
        }
    }

    private func feedPromptText(from object: [String: Any]?) -> String? {
        guard let object else { return nil }
        if let direct = firstString(in: object, keys: ["prompt", "text", "message", "body"]) {
            return direct
        }
        for key in ["notification", "data"] {
            if let nested = object[key] as? [String: Any],
               let nestedPrompt = firstString(in: nested, keys: ["prompt", "text", "message", "body"]) {
                return nestedPrompt
            }
        }
        return nil
    }

    private func feedWorkspaceId(rawObject: [String: Any]?, fallback: String?) -> String? {
        if let fallback {
            let trimmed = fallback.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty {
                return trimmed
            }
        }
        if let rawObject,
           let direct = firstString(
                in: rawObject,
                keys: ["workspace_id", "workspaceId", "workspace_ref", "workspaceRef"]
           ) {
            return direct
        }
        return nil
    }

    private func agentPidForFeedSource(
        _ source: String,
        env: [String: String] = ProcessInfo.processInfo.environment
    ) -> Int {
        let envKey: String
        switch source {
        case "claude": envKey = "CMUX_CLAUDE_PID"
        case "codex": envKey = "CMUX_CODEX_PID"
        case "cursor": envKey = "CMUX_CURSOR_PID"
        case "gemini": envKey = "CMUX_GEMINI_PID"
        case "antigravity": envKey = "CMUX_ANTIGRAVITY_PID"
        case "rovodev": envKey = "CMUX_ROVODEV_PID"
        case "hermes-agent": envKey = "CMUX_HERMES_AGENT_PID"
        case "copilot": envKey = "CMUX_COPILOT_PID"
        case "kiro": envKey = "CMUX_KIRO_PID"
        default: envKey = ""
        }
        if !envKey.isEmpty,
           let rawPid = env[envKey],
           let pid = Int(rawPid),
           pid > 0 {
            return pid
        }
        return Int(getppid())
    }

    private func stableFallbackFeedSessionId(
        source: String,
        rawObject: [String: Any],
        agentPid: Int
    ) -> String {
        var components = [
            "source=\(source)",
            "pid=\(max(agentPid, 0))",
        ]
        if let workspaceId = feedWorkspaceId(rawObject: rawObject, fallback: nil) {
            components.append("workspace=\(workspaceId)")
        }
        if let cwd = extractClaudeHookCWD(from: rawObject) {
            components.append("cwd=\(cwd)")
        }
        if let transcriptPath = extractHookTranscriptPath(from: rawObject) {
            components.append("transcript=\(transcriptPath)")
        }

        let seed = components.joined(separator: "\n")
        let digest = SHA256.hash(data: Data(seed.utf8))
            .map { String(format: "%02x", $0) }
            .joined()
        return "fallback-\(String(digest.prefix(16)))"
    }

    private func enrichUserPromptSubmitFeedEvent(
        _ event: inout [String: Any],
        hookEventName: String,
        promptText: String?
    ) {
        guard hookEventName == "UserPromptSubmit",
              let promptText else { return }
        if var toolInput = event["tool_input"] as? [String: Any] {
            toolInput["prompt"] = promptText
            event["tool_input"] = toolInput
        } else {
            event["tool_input"] = ["prompt": promptText]
        }
        var context = event["context"] as? [String: Any] ?? [:]
        if context["lastUserMessage"] == nil {
            setFeedContext(
                &context,
                key: "lastUserMessage",
                value: promptText,
                maxLength: 1_000
            )
        }
        if !context.isEmpty {
            event["context"] = context
        }
    }

    private func feedContext(from raw: [String: Any]) -> [String: Any] {
        var context: [String: Any] = [:]
        setFeedContext(
            &context,
            key: "lastUserMessage",
            value: firstString(in: raw, keys: ["lastUserMessage", "last_user_message", "userPrompt", "prompt"]),
            maxLength: 1_000
        )
        setFeedContext(
            &context,
            key: "assistantPreamble",
            value: firstString(in: raw, keys: ["assistantPreamble", "assistant_preamble", "lastAssistantMessage", "last_assistant_message"]),
            maxLength: 1_000
        )
        setFeedContext(
            &context,
            key: "planSummary",
            value: firstString(in: raw, keys: ["planSummary", "plan_summary"]),
            maxLength: 600
        )
        setFeedContext(
            &context,
            key: "toolSummary",
            value: firstString(in: raw, keys: ["toolSummary", "tool_summary"]),
            maxLength: 600
        )
        setFeedContext(
            &context,
            key: "permissionMode",
            value: firstString(in: raw, keys: ["permissionMode", "permission_mode"]),
            maxLength: 80
        )
        let allowed = feedAllowedPrompts(from: raw["allowedPrompts"] ?? raw["allowed_prompts"])
        if !allowed.isEmpty {
            context["allowedPrompts"] = allowed
        }
        return context
    }

    private func readClaudeFeedContext(
        path: String,
        matchingToolName: String?
    ) -> [String: Any]? {
        guard let lines = readRecentTextFileLines(path: path, maxBytes: 1_048_576) else { return nil }

        var lastUserMessage: String?
        var lastAssistantText: String?
        var permissionMode: String?
        var matchedContext: [String: Any]?

        for line in lines {
            let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty,
                  let lineData = trimmed.data(using: .utf8),
                  let obj = try? JSONSerialization.jsonObject(with: lineData) as? [String: Any]
            else {
                continue
            }

            if let mode = firstString(in: obj, keys: ["permissionMode", "permission_mode"]) {
                permissionMode = mode
            }
            if let attachment = obj["attachment"] as? [String: Any],
               (attachment["type"] as? String) == "plan_mode" {
                permissionMode = "plan"
            }

            guard let message = obj["message"] as? [String: Any],
                  let role = message["role"] as? String
            else {
                continue
            }

            if role == "user" {
                if let text = extractMessageText(from: message) {
                    lastUserMessage = truncate(normalizedSingleLine(text), maxLength: 1_000)
                }
                continue
            }

            guard role == "assistant" else { continue }
            var messageText: String?
            if let text = extractMessageText(from: message) {
                messageText = truncate(normalizedSingleLine(text), maxLength: 1_000)
                lastAssistantText = messageText
            }

            guard let blocks = message["content"] as? [[String: Any]] else { continue }
            for block in blocks {
                guard (block["type"] as? String) == "tool_use" else { continue }
                let blockToolName = block["name"] as? String
                if let matchingToolName, blockToolName != matchingToolName {
                    continue
                }

                var context: [String: Any] = [:]
                setFeedContext(
                    &context,
                    key: "lastUserMessage",
                    value: lastUserMessage,
                    maxLength: 1_000
                )
                setFeedContext(
                    &context,
                    key: "assistantPreamble",
                    value: messageText ?? lastAssistantText,
                    maxLength: 1_000
                )
                setFeedContext(
                    &context,
                    key: "permissionMode",
                    value: permissionMode,
                    maxLength: 80
                )
                if let input = block["input"], let planContext = feedPlanContext(from: input) {
                    mergeFeedContext(&context, planContext, preferIncoming: true)
                }
                matchedContext = context
            }
        }

        if let matchedContext, !matchedContext.isEmpty {
            return matchedContext
        }

        var fallback: [String: Any] = [:]
        setFeedContext(&fallback, key: "lastUserMessage", value: lastUserMessage, maxLength: 1_000)
        setFeedContext(&fallback, key: "assistantPreamble", value: lastAssistantText, maxLength: 1_000)
        setFeedContext(&fallback, key: "permissionMode", value: permissionMode, maxLength: 80)
        return fallback.isEmpty ? nil : fallback
    }

    private func feedPlanContext(from rawToolInput: Any?) -> [String: Any]? {
        guard let dict = feedToolInputDictionary(rawToolInput),
              let plan = firstString(in: dict, keys: ["plan"])
        else {
            return nil
        }

        var context: [String: Any] = [:]
        setFeedContext(
            &context,
            key: "planSummary",
            value: feedPlanSummary(from: plan),
            maxLength: 600
        )
        let allowed = feedAllowedPrompts(from: dict["allowedPrompts"])
        if !allowed.isEmpty {
            context["allowedPrompts"] = allowed
        }
        return context.isEmpty ? nil : context
    }

    private func feedToolContext(toolName: String?, toolInput: Any?) -> [String: Any]? {
        guard let toolName, let dict = feedToolInputDictionary(toolInput) else { return nil }
        let lower = toolName.lowercased()
        var summary: String?
        if lower == "bash" {
            summary = firstString(in: dict, keys: ["description", "command"])
        } else if lower == "run_command" || lower == "execute_bash" || lower == "shell" {
            summary = firstString(in: dict, keys: ["CommandLine", "commandLine", "command", "Cwd", "cwd"])
        } else if ["write", "edit", "multiedit", "read", "fs_read", "fs_write"].contains(lower) {
            summary = firstString(in: dict, keys: ["file_path", "path"]) ?? firstOperationPath(in: dict)
        } else if ["view_file", "write_to_file", "replace_file_content", "multi_replace_file_content"].contains(lower) {
            summary = firstString(in: dict, keys: ["AbsolutePath", "TargetFile", "SearchPath", "DirectoryPath", "path"])
        } else if lower == "askuserquestion" || lower == "ask_question" {
            if let questions = dict["questions"] as? [[String: Any]],
               let first = questions.first {
                summary = firstString(in: first, keys: ["question", "prompt", "header"])
            } else {
                summary = firstString(in: dict, keys: ["question", "prompt"])
            }
        }
        guard let summary else { return nil }
        var context: [String: Any] = [:]
        setFeedContext(&context, key: "toolSummary", value: summary, maxLength: 600)
        return context.isEmpty ? nil : context
    }

    private func firstOperationPath(in dict: [String: Any]) -> String? {
        guard let operations = dict["operations"] as? [[String: Any]] else { return nil }
        for operation in operations {
            if let path = firstString(in: operation, keys: ["path", "file_path", "filePath"]) {
                return path
            }
        }
        return nil
    }

    private func feedToolInputDictionary(_ raw: Any?) -> [String: Any]? {
        if let dict = raw as? [String: Any] {
            return dict
        }
        if let json = raw as? String,
           let data = json.data(using: .utf8),
           let dict = try? JSONSerialization.jsonObject(
                with: data,
                options: [.fragmentsAllowed]
           ) as? [String: Any] {
            return dict
        }
        return nil
    }

    private func feedAllowedPrompts(from raw: Any?) -> [[String: String]] {
        guard let raw else { return [] }
        if let rows = raw as? [[String: Any]] {
            return rows.compactMap { row in
                guard let prompt = firstString(in: row, keys: ["prompt", "description", "text"]) else {
                    return nil
                }
                var out = ["prompt": truncate(normalizedSingleLine(prompt), maxLength: 260)]
                if let tool = firstString(in: row, keys: ["tool", "toolName"]) {
                    out["tool"] = truncate(normalizedSingleLine(tool), maxLength: 80)
                }
                return out
            }
        }
        if let rows = raw as? [Any] {
            return rows.compactMap { row in
                if let text = row as? String {
                    let prompt = truncate(normalizedSingleLine(text), maxLength: 260)
                    return prompt.isEmpty ? nil : ["prompt": prompt]
                }
                guard let dict = row as? [String: Any] else { return nil }
                guard let prompt = firstString(in: dict, keys: ["prompt", "description", "text"]) else {
                    return nil
                }
                var out = ["prompt": truncate(normalizedSingleLine(prompt), maxLength: 260)]
                if let tool = firstString(in: dict, keys: ["tool", "toolName"]) {
                    out["tool"] = truncate(normalizedSingleLine(tool), maxLength: 80)
                }
                return out
            }
        }
        return []
    }

    private func feedPlanSummary(from plan: String) -> String? {
        var firstHeading: String?
        for rawLine in plan.split(separator: "\n", omittingEmptySubsequences: false) {
            let line = String(rawLine).trimmingCharacters(in: .whitespacesAndNewlines)
            guard !line.isEmpty else { continue }
            if line.hasPrefix("#") {
                let heading = line.trimmingCharacters(in: CharacterSet(charactersIn: "# "))
                if firstHeading == nil, !heading.isEmpty {
                    firstHeading = heading
                }
                continue
            }
            if line.hasPrefix("- ") || line.hasPrefix("* ") {
                return String(line.dropFirst(2)).trimmingCharacters(in: .whitespaces)
            }
            if let dot = line.firstIndex(of: "."),
               line[..<dot].allSatisfy(\.isNumber) {
                return String(line[line.index(after: dot)...])
                    .trimmingCharacters(in: .whitespaces)
            }
            return line
        }
        return firstHeading
    }

    private func setFeedContext(
        _ context: inout [String: Any],
        key: String,
        value: String?,
        maxLength: Int
    ) {
        guard let value else { return }
        let normalized = normalizedSingleLine(value)
        guard !normalized.isEmpty else { return }
        context[key] = truncate(normalized, maxLength: maxLength)
    }

    private func mergeFeedContext(
        _ target: inout [String: Any],
        _ incoming: [String: Any],
        preferIncoming: Bool = false
    ) {
        for (key, value) in incoming {
            if preferIncoming || target[key] == nil {
                target[key] = value
            }
        }
    }

    private static func feedEventName(forClaudeSubcommand sub: String) -> String {
        switch sub {
        case "session-start", "active": return "SessionStart"
        case "prompt-submit": return "UserPromptSubmit"
        case "pre-tool-use", "cron-create-guard": return "PreToolUse"
        case "post-tool-use", "push-notification": return "PostToolUse"
        case "stop", "idle": return "Stop"
        case "session-end": return "SessionEnd"
        case "notification", "notify": return "Notification"
        default: return ""
        }
    }

    // MARK: - Feed history

    private struct FeedTUIOption {
        let id: String
        let label: String
    }

    private struct FeedTUIQuestion {
        let id: String
        let prompt: String
        let multiSelect: Bool
        let options: [FeedTUIOption]
    }

    private struct FeedTUIItem {
        let id: String
        let requestId: String?
        let workstreamId: String
        let source: String
        let kind: String
        let status: String
        let createdAt: Date?
        let title: String
        let detail: String
        let toolInputJSON: String
        let toolInputCapabilitiesJSON: String
        let defaultMode: String?
        let questionMultiSelect: Bool
        let questionOptions: [FeedTUIOption]
        let questions: [FeedTUIQuestion]

        var isPending: Bool {
            status == "pending"
        }

        var canResolve: Bool {
            isPending && requestId != nil &&
                (kind == "permissionRequest" || kind == "exitPlan" || kind == "question")
        }

        static func parse(_ dict: [String: Any]) -> FeedTUIItem? {
            guard let id = dict["id"] as? String,
                  let workstreamId = dict["workstream_id"] as? String,
                  let source = dict["source"] as? String,
                  let kind = dict["kind"] as? String,
                  let status = dict["status"] as? String else {
                return nil
            }
            let title = (dict["title"] as? String)
                ?? Self.defaultTitle(kind: kind, dict: dict)
            let detail = Self.detail(kind: kind, dict: dict)
            let createdAt = Self.dateValue(
                dict["created_at"]
                    ?? dict["createdAt"]
                    ?? dict["timestamp"]
                    ?? dict["time"]
            )
            let options: [FeedTUIOption] = (dict["question_options"] as? [[String: Any]])?.compactMap { option in
                guard let id = option["id"] as? String,
                      let label = option["label"] as? String else {
                    return nil
                }
                return FeedTUIOption(id: id, label: label)
            } ?? []
            let questions = Self.questions(dict: dict, fallbackOptions: options)
            return FeedTUIItem(
                id: id,
                requestId: dict["request_id"] as? String,
                workstreamId: workstreamId,
                source: source,
                kind: kind,
                status: status,
                createdAt: createdAt,
                title: title,
                detail: detail,
                toolInputJSON: (dict["tool_input"] as? String) ?? "",
                toolInputCapabilitiesJSON: (dict["tool_input_capabilities"] as? String)
                    ?? (dict["tool_input"] as? String)
                    ?? "",
                defaultMode: dict["default_mode"] as? String,
                questionMultiSelect: (dict["question_multi_select"] as? Bool) ?? false,
                questionOptions: options,
                questions: questions
            )
        }

        private static func questions(dict: [String: Any], fallbackOptions: [FeedTUIOption]) -> [FeedTUIQuestion] {
            if let rawQuestions = dict["questions"] as? [[String: Any]] {
                let parsed = rawQuestions.enumerated().compactMap { index, raw -> FeedTUIQuestion? in
                    let prompt = (raw["prompt"] as? String)
                        ?? (raw["question"] as? String)
                        ?? (raw["header"] as? String)
                        ?? ""
                    let options = (raw["options"] as? [[String: Any]])?.compactMap { option -> FeedTUIOption? in
                        guard let id = option["id"] as? String,
                              let label = option["label"] as? String else {
                            return nil
                        }
                        return FeedTUIOption(id: id, label: label)
                    } ?? []
                    guard !prompt.isEmpty || !options.isEmpty else { return nil }
                    return FeedTUIQuestion(
                        id: (raw["id"] as? String) ?? "question-\(index + 1)",
                        prompt: prompt,
                        multiSelect: (raw["multi_select"] as? Bool) ?? (raw["multiSelect"] as? Bool) ?? false,
                        options: options
                    )
                }
                if !parsed.isEmpty {
                    return parsed
                }
            }
            let prompt = (dict["question_prompt"] as? String)
                ?? (dict["title"] as? String)
                ?? "Answer the agent question."
            return [
                FeedTUIQuestion(
                    id: "question-1",
                    prompt: prompt,
                    multiSelect: (dict["question_multi_select"] as? Bool) ?? false,
                    options: fallbackOptions
                )
            ]
        }

        private static func defaultTitle(kind: String, dict: [String: Any]) -> String {
            switch kind {
            case "permissionRequest":
                return "Permission: \((dict["tool_name"] as? String) ?? "tool")"
            case "exitPlan":
                return "Plan"
            case "question":
                return "Question"
            default:
                return kind
            }
        }

        private static func detail(kind: String, dict: [String: Any]) -> String {
            switch kind {
            case "permissionRequest":
                let tool = (dict["tool_name"] as? String) ?? "tool"
                let input = (dict["tool_input"] as? String) ?? ""
                return input.isEmpty ? tool : "\(tool): \(input)"
            case "exitPlan":
                return (dict["plan_summary"] as? String)
                    ?? (dict["plan"] as? String)
                    ?? "Review the proposed plan"
            case "question":
                return (dict["question_prompt"] as? String) ?? "Answer the agent question"
            default:
                return (dict["text"] as? String)
                    ?? (dict["reason"] as? String)
                    ?? ((dict["cwd"] as? String) ?? "")
            }
        }

        private static func dateValue(_ rawValue: Any?) -> Date? {
            if let date = rawValue as? Date {
                return date
            }

            if let number = rawValue as? NSNumber {
                return dateFromTimeInterval(number.doubleValue)
            }

            if let value = rawValue as? Double {
                return dateFromTimeInterval(value)
            }

            if let value = rawValue as? Int {
                return dateFromTimeInterval(Double(value))
            }

            guard let value = rawValue as? String,
                  !value.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
                return nil
            }

            let isoFormatter = ISO8601DateFormatter()
            if let date = isoFormatter.date(from: value) {
                return date
            }

            let fractionalFormatter = ISO8601DateFormatter()
            fractionalFormatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
            if let date = fractionalFormatter.date(from: value) {
                return date
            }

            if let numericValue = Double(value) {
                return dateFromTimeInterval(numericValue)
            }

            return nil
        }

        private static func dateFromTimeInterval(_ value: Double) -> Date? {
            guard value.isFinite, value > 0 else { return nil }
            let seconds = value > 10_000_000_000 ? value / 1_000 : value
            return Date(timeIntervalSince1970: seconds)
        }
    }

    private enum FeedTUIKey: Equatable {
        case tick
        case up
        case down
        case enter
        case quit
        case refresh
        case deny
        case feedback
        case once
        case always
        case all
        case bypass
        case manual
        case autoAccept
        case ultraplan
        case number(Int)
        case ignored
    }

    private static let openTUIFeedCoreVersion = "0.1.106"

    private enum FeedTUIImplementation {
        case automatic
        case openTUI
        case legacy
        case help
    }

    private func runFeedTUI(arguments: [String], socketPath: String, socketPassword: String?) throws {
        let resolvedSocketPassword = SocketPasswordResolver.resolve(
            explicit: socketPassword,
            socketPath: socketPath
        )
        let implementation = try parseFeedTUIImplementation(arguments: arguments)
        if implementation == .help { return }
        if implementation == .legacy || ProcessInfo.processInfo.environment["CMUX_FEED_TUI_LEGACY"] == "1" {
            try runLegacyFeedTUI(socketPath: socketPath, socketPassword: resolvedSocketPassword)
            return
        }
        if implementation == .openTUI {
            try runOpenTUIFeedTUI(socketPath: socketPath, socketPassword: resolvedSocketPassword)
            return
        }

        do {
            try runOpenTUIFeedTUI(socketPath: socketPath, socketPassword: resolvedSocketPassword)
        } catch {
            cliWriteStderr("cmux feed tui: OpenTUI unavailable (\(error)); falling back to legacy TUI.\n")
            try runLegacyFeedTUI(socketPath: socketPath, socketPassword: resolvedSocketPassword)
        }
    }

    private func parseFeedTUIImplementation(arguments: [String]) throws -> FeedTUIImplementation {
        var implementation = FeedTUIImplementation.automatic
        for argument in arguments {
            switch argument {
            case "--opentui":
                guard implementation != .legacy else {
                    throw CLIError(message: "cmux feed tui: choose only one TUI implementation")
                }
                implementation = .openTUI
            case "--legacy":
                guard implementation != .openTUI else {
                    throw CLIError(message: "cmux feed tui: choose only one TUI implementation")
                }
                implementation = .legacy
            case "--help", "-h":
                print("Usage: cmux feed tui [--opentui|--legacy]")
                return .help
            default:
                throw CLIError(message: "cmux feed tui: unknown argument \(argument)")
            }
        }
        return implementation
    }

    private func runOpenTUIFeedTUI(socketPath: String, socketPassword: String?) throws {
        guard isatty(STDIN_FILENO) == 1, isatty(STDOUT_FILENO) == 1 else {
            throw CLIError(message: "cmux feed tui requires an interactive terminal")
        }
        guard let bunPath = resolveBunExecutable() else {
            throw CLIError(message: "Bun is required for the OpenTUI Feed")
        }

        cliWriteStderr("cmux feed tui: preparing OpenTUI Feed...\n")
        let appDirectory = try prepareOpenTUIFeedApp(bunPath: bunPath)
        let sourceURL = appDirectory.appendingPathComponent("index.ts", isDirectory: false)
        cliWriteStderr("cmux feed tui: starting OpenTUI Feed.\n")
        let process = Process()
        process.executableURL = URL(fileURLWithPath: bunPath)
        process.arguments = [sourceURL.path]
        process.currentDirectoryURL = URL(
            fileURLWithPath: FileManager.default.currentDirectoryPath,
            isDirectory: true
        )
        var environment = ProcessInfo.processInfo.environment
        environment["CMUX_SOCKET_PATH"] = socketPath; environment.removeValue(forKey: "CMUX_SOCKET")
        if let socketPassword {
            environment["CMUX_SOCKET_PASSWORD"] = socketPassword
        }
        environment["OTUI_USE_CONSOLE"] = environment["OTUI_USE_CONSOLE"] ?? "0"
        environment["OTUI_USE_ALTERNATE_SCREEN"] = "1"
        environment["CMUX_FEED_TUI_PATH"] = "opentui"
        process.environment = environment
        process.standardInput = FileHandle.standardInput
        process.standardOutput = FileHandle.standardOutput
        process.standardError = FileHandle.standardError

        let originalForegroundProcessGroup = tcgetpgrp(STDIN_FILENO)
        var didForegroundChild = false
        try cliRunProcess(process)
        if originalForegroundProcessGroup > 0 {
            let childProcessGroup = getpgid(process.processIdentifier)
            if childProcessGroup > 0 && childProcessGroup != originalForegroundProcessGroup {
                try setTerminalForegroundProcessGroup(childProcessGroup)
                _ = Darwin.kill(-childProcessGroup, SIGCONT)
                didForegroundChild = true
            }
        }
        defer {
            if didForegroundChild {
                try? setTerminalForegroundProcessGroup(originalForegroundProcessGroup)
            }
        }
        process.waitUntilExit()
        if process.terminationStatus == 0 || process.terminationStatus == 130 || (process.terminationReason == .uncaughtSignal && process.terminationStatus == SIGINT) { return }
        throw CLIError(message: "OpenTUI Feed exited with status \(process.terminationStatus)")
    }

    private func setTerminalForegroundProcessGroup(_ processGroup: pid_t) throws {
        let previousHandler = signal(SIGTTOU, SIG_IGN)
        defer { _ = signal(SIGTTOU, previousHandler) }
        guard tcsetpgrp(STDIN_FILENO, processGroup) == 0 else {
            throw CLIError(message: "cmux feed tui: failed to foreground OpenTUI process: \(String(cString: strerror(errno)))")
        }
    }

    private func resolveBunExecutable() -> String? {
        if let path = ProcessInfo.processInfo.environment["CMUX_FEED_TUI_BUN_PATH"]?
            .trimmingCharacters(in: .whitespacesAndNewlines),
           !path.isEmpty,
           FileManager.default.isExecutableFile(atPath: path) {
            return path
        }
        if let path = resolveExecutableInPath("bun") {
            return path
        }
        let homePath = ProcessInfo.processInfo.environment["HOME"] ?? NSHomeDirectory()
        for path in [
            "\(homePath)/.bun/bin/bun",
            "\(homePath)/.local/bin/bun",
            "/opt/homebrew/bin/bun",
            "/usr/local/bin/bun",
        ] {
            if FileManager.default.isExecutableFile(atPath: path) {
                return path
            }
        }
        return nil
    }

    private func prepareOpenTUIFeedApp(bunPath: String) throws -> URL {
        let fileManager = FileManager.default
        let homePath = ProcessInfo.processInfo.environment["HOME"] ?? NSHomeDirectory()
        let appDirectory = URL(fileURLWithPath: homePath, isDirectory: true)
            .appendingPathComponent(".cmuxterm", isDirectory: true)
            .appendingPathComponent("feed-tui-opentui", isDirectory: true)
        try fileManager.createDirectory(at: appDirectory, withIntermediateDirectories: true)

        let packageURL = appDirectory.appendingPathComponent("package.json", isDirectory: false)
        let sourceURL = appDirectory.appendingPathComponent("index.ts", isDirectory: false)
        let packageSource = """
        {
          "private": true,
          "type": "module",
          "dependencies": {
            "@opentui/core": "\(Self.openTUIFeedCoreVersion)"
          }
        }
        """
        try writeFileIfChanged(packageSource, to: packageURL)
        try writeFileIfChanged(try bundledOpenTUIFeedSource(), to: sourceURL)

        let installedPackageURL = appDirectory
            .appendingPathComponent("node_modules", isDirectory: true)
            .appendingPathComponent("@opentui", isDirectory: true)
            .appendingPathComponent("core", isDirectory: true)
            .appendingPathComponent("package.json", isDirectory: false)
        if !fileManager.fileExists(atPath: installedPackageURL.path)
            || installedOpenTUIVersion(at: installedPackageURL) != Self.openTUIFeedCoreVersion {
            cliWriteStderr("cmux feed tui: installing @opentui/core \(Self.openTUIFeedCoreVersion)...\n")
            try installOpenTUIFeedDependencies(bunPath: bunPath, appDirectory: appDirectory)
        }
        return appDirectory
    }

    private func bundledOpenTUIFeedSource() throws -> String {
        let fileManager = FileManager.default
        if let resourceURL = Bundle.main.resourceURL {
            let url = resourceURL
                .appendingPathComponent("feed-tui", isDirectory: true)
                .appendingPathComponent("index.ts", isDirectory: false)
            if fileManager.fileExists(atPath: url.path),
               let contents = try? String(contentsOf: url, encoding: .utf8) {
                return contents
            }
        }

        let devURL = URL(fileURLWithPath: #filePath)
            .deletingLastPathComponent()
            .deletingLastPathComponent()
            .appendingPathComponent("Resources", isDirectory: true)
            .appendingPathComponent("feed-tui", isDirectory: true)
            .appendingPathComponent("index.ts", isDirectory: false)
        if fileManager.fileExists(atPath: devURL.path),
           let contents = try? String(contentsOf: devURL, encoding: .utf8) {
            return contents
        }

        throw CLIError(message: "bundled OpenTUI Feed source not found")
    }

    private func writeFileIfChanged(_ contents: String, to url: URL) throws {
        let existing = try? String(contentsOf: url, encoding: .utf8)
        guard existing != contents else { return }
        try contents.write(to: url, atomically: true, encoding: .utf8)
    }

    private func installedOpenTUIVersion(at url: URL) -> String? {
        guard let data = try? Data(contentsOf: url),
              let object = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let version = object["version"] as? String else {
            return nil
        }
        return version
    }

    private func installOpenTUIFeedDependencies(bunPath: String, appDirectory: URL) throws {
        let process = Process()
        process.executableURL = URL(fileURLWithPath: bunPath)
        process.arguments = ["install", "--silent"]
        process.currentDirectoryURL = appDirectory
        let stdoutPipe = Pipe()
        let stderrPipe = Pipe()
        process.standardOutput = stdoutPipe
        process.standardError = stderrPipe
        let stdoutHandle = stdoutPipe.fileHandleForReading
        let stderrHandle = stderrPipe.fileHandleForReading
        var stdoutData = Data()
        var stderrData = Data()
        let drainGroup = DispatchGroup()
        drainGroup.enter()
        DispatchQueue.global(qos: .utility).async {
            stdoutData = stdoutHandle.readDataToEndOfFileOrEmpty()
            drainGroup.leave()
        }
        drainGroup.enter()
        DispatchQueue.global(qos: .utility).async {
            stderrData = stderrHandle.readDataToEndOfFileOrEmpty()
            drainGroup.leave()
        }

        try cliRunProcess(process)
        process.waitUntilExit()
        drainGroup.wait()
        guard process.terminationStatus == 0 else {
            let stderrText = String(data: stderrData, encoding: .utf8)?
                .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let stdoutText = String(data: stdoutData, encoding: .utf8)?
                .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            throw CLIError(message: stderrText.isEmpty ? (stdoutText.isEmpty ? "bun install failed" : stdoutText) : stderrText)
        }
    }

    private func runLegacyFeedTUI(socketPath: String, socketPassword: String?) throws {
        guard isatty(STDIN_FILENO) == 1, isatty(STDOUT_FILENO) == 1 else {
            throw CLIError(message: "cmux feed tui requires an interactive terminal")
        }

        let client = SocketClient(path: socketPath)
        try client.connect()
        try authenticateClientIfNeeded(client, explicitPassword: socketPassword, socketPath: socketPath)

        var rawMode = TerminalRawMode()
        guard rawMode != nil else {
            throw CLIError(message: "Failed to enter terminal raw mode")
        }

        print("\u{001B}[?1049h\u{001B}[?25l", terminator: "")
        defer {
            rawMode?.restore()
            print("\u{001B}[?25h\u{001B}[?1049l", terminator: "")
            fflush(stdout)
        }

        var selectedIndex = 0
        var selectedItemID: String?
        var scrollOffset = 0
        var statusLine = ""
        var selectedQuestionOptions: [String: Set<String>] = [:]
        var didWriteReadyMarker = false
        while true {
            let items = try feedTUIItems(client: client)
            if let selectedItemID,
               let updatedIndex = items.firstIndex(where: { $0.id == selectedItemID }) {
                selectedIndex = updatedIndex
            } else if selectedIndex >= items.count {
                selectedIndex = max(items.count - 1, 0)
            }
            selectedItemID = feedTUIItem(in: items, at: selectedIndex)?.id
            scrollOffset = adjustedFeedTUIScrollOffset(
                itemCount: items.count,
                selectedIndex: selectedIndex,
                scrollOffset: scrollOffset
            )
            renderFeedTUI(
                items: items,
                selectedIndex: selectedIndex,
                scrollOffset: scrollOffset,
                statusLine: statusLine
            )
            if !didWriteReadyMarker {
                writeFeedTUIReadyMarker(stage: "legacy-ready")
                didWriteReadyMarker = true
            }
            statusLine = ""

            let key = readFeedTUIKey(timeoutMilliseconds: 1_000)
            switch key {
            case .tick:
                continue
            case .up:
                selectedIndex = max(selectedIndex - 1, 0)
                selectedItemID = feedTUIItem(in: items, at: selectedIndex)?.id
            case .down:
                selectedIndex = min(selectedIndex + 1, max(items.count - 1, 0))
                selectedItemID = feedTUIItem(in: items, at: selectedIndex)?.id
            case .refresh:
                continue
            case .quit:
                return
            case .enter:
                if let item = feedTUIItem(in: items, at: selectedIndex) {
                    statusLine = try resolveFeedTUIItem(
                        item,
                        key: .enter,
                        client: client,
                        rawMode: &rawMode,
                        selectedQuestionOptions: &selectedQuestionOptions
                    )
                }
            case .deny:
                if let item = feedTUIItem(in: items, at: selectedIndex) {
                    statusLine = try resolveFeedTUIItem(
                        item,
                        key: .deny,
                        client: client,
                        rawMode: &rawMode,
                        selectedQuestionOptions: &selectedQuestionOptions
                    )
                }
            case .feedback:
                if let item = feedTUIItem(in: items, at: selectedIndex) {
                    statusLine = try resolveFeedTUIItem(
                        item,
                        key: .feedback,
                        client: client,
                        rawMode: &rawMode,
                        selectedQuestionOptions: &selectedQuestionOptions
                    )
                }
            case .once, .always, .all, .bypass, .manual, .autoAccept, .ultraplan, .number(_):
                if let item = feedTUIItem(in: items, at: selectedIndex) {
                    statusLine = try resolveFeedTUIItem(
                        item,
                        key: key,
                        client: client,
                        rawMode: &rawMode,
                        selectedQuestionOptions: &selectedQuestionOptions
                    )
                }
            case .ignored:
                continue
            }
        }
    }

    private func writeFeedTUIReadyMarker(stage: String) {
        guard let path = ProcessInfo.processInfo.environment["CMUX_FEED_TUI_READY_PATH"]?
            .trimmingCharacters(in: .whitespacesAndNewlines),
              !path.isEmpty else {
            return
        }
        let url = URL(fileURLWithPath: path, isDirectory: false)
        try? FileManager.default.createDirectory(
            at: url.deletingLastPathComponent(),
            withIntermediateDirectories: true
        )
        let payload = """
        {"stage":"\(stage)","pid":"\(getpid())","time":"\(Date().timeIntervalSince1970)"}
        """
        try? payload.write(to: url, atomically: true, encoding: .utf8)
    }

    private func feedTUIItems(client: SocketClient) throws -> [FeedTUIItem] {
        let payload = try client.sendV2(method: "feed.list", params: ["pending_only": true])
        let rawItems = payload["items"] as? [[String: Any]] ?? []
        return rawItems.compactMap(FeedTUIItem.parse)
            .filter(\.canResolve)
            .sorted { lhs, rhs in
                switch (lhs.createdAt, rhs.createdAt) {
                case (.some(let lhsDate), .some(let rhsDate)) where lhsDate != rhsDate:
                    return lhsDate > rhsDate
                case (.some, .none):
                    return true
                case (.none, .some):
                    return false
                default:
                    return lhs.id > rhs.id
                }
            }
    }

    private func feedTUIItem(in items: [FeedTUIItem], at index: Int) -> FeedTUIItem? {
        guard index >= 0, index < items.count else { return nil }
        return items[index]
    }

    private func feedTUIOption(in options: [FeedTUIOption], at index: Int) -> FeedTUIOption? {
        guard index >= 0, index < options.count else { return nil }
        return options[index]
    }

    private struct FeedTUILayout {
        let width: Int
        let rows: Int

        let headerRows = 3
        let footerRows = 2
        let cardRows = 5

        var visibleItemCount: Int {
            max((rows - headerRows - footerRows) / cardRows, 1)
        }
    }

    private func adjustedFeedTUIScrollOffset(
        itemCount: Int,
        selectedIndex: Int,
        scrollOffset: Int
    ) -> Int {
        guard itemCount > 0 else { return 0 }
        let size = Self.currentCLITerminalSize()
        let layout = FeedTUILayout(width: max(size.cols, 1), rows: max(size.rows, 1))
        let visibleCount = layout.visibleItemCount
        let maxOffset = max(itemCount - visibleCount, 0)
        if selectedIndex < scrollOffset {
            return max(selectedIndex, 0)
        }
        if selectedIndex >= scrollOffset + visibleCount {
            return min(selectedIndex - visibleCount + 1, maxOffset)
        }
        return min(max(scrollOffset, 0), maxOffset)
    }

    private func renderFeedTUI(
        items: [FeedTUIItem],
        selectedIndex: Int,
        scrollOffset: Int,
        statusLine: String
    ) {
        let size = Self.currentCLITerminalSize()
        let layout = FeedTUILayout(width: max(size.cols, 1), rows: max(size.rows, 1))
        let width = layout.width
        let pendingCount = items.filter(\.isPending).count
        let visibleStart = items.isEmpty ? 0 : min(scrollOffset + 1, items.count)
        let visibleEnd = min(scrollOffset + layout.visibleItemCount, items.count)

        print("\u{001B}[2J\u{001B}[H", terminator: "")
        print(feedTUILine(
            "cmux Dock Feed  latest first  \(pendingCount) pending  \(items.count) total  \(visibleStart)-\(visibleEnd)",
            width: width
        ))
        print(feedTUILine(
            "j/k arrows move  enter default  d deny  f replan  r refresh  q quit",
            width: width
        ))
        print(feedTUISeparator(width: width))

        if items.isEmpty {
            print(feedTUILine("No feed items yet.", width: width))
        } else {
            for visibleIndex in 0..<layout.visibleItemCount {
                let itemIndex = scrollOffset + visibleIndex
                guard itemIndex < items.count else {
                    for _ in 0..<layout.cardRows {
                        print(feedTUILine("", width: width))
                    }
                    continue
                }
                let item = items[itemIndex]
                let selected = itemIndex == selectedIndex
                renderFeedTUICard(item, selected: selected, width: width)
            }
        }

        let footerTop = max(layout.rows - 1, 1)
        print("\u{001B}[\(footerTop);1H", terminator: "")
        print(feedTUISeparator(width: width), terminator: "")
        print("\u{001B}[\(layout.rows);1H", terminator: "")
        let footer = statusLine.isEmpty ? selectedHelp(feedTUIItem(in: items, at: selectedIndex)) : statusLine
        print(feedTUILine(footer, width: width), terminator: "")
        fflush(stdout)
    }

    private func renderFeedTUICard(_ item: FeedTUIItem, selected: Bool, width: Int) {
        let status = item.isPending ? "[PENDING]" : "[\(item.status.uppercased())]"
        let time = relativeFeedTUITime(since: item.createdAt)
        let kind = feedTUIKindLabel(item.kind)
        let source = sanitizedTerminalText(item.source)
        let marker = selected ? ">" : " "
        let metaSuffix = time.isEmpty ? kind : "\(kind)  \(time)"
        let detailLines = wrappedTerminalLines(item.detail, width: max(width - 4, 1), maxLines: 2)
        let firstDetailLine = detailLines.indices.contains(0) ? detailLines[0] : ""
        let secondDetailLine = detailLines.indices.contains(1) ? detailLines[1] : ""

        print(feedTUILine("\(marker) \(status) @\(source)  \(metaSuffix)", width: width, highlighted: selected))
        print(feedTUILine("  \(item.title)", width: width, highlighted: selected))
        print(feedTUILine("  \(firstDetailLine)", width: width, highlighted: selected))
        print(feedTUILine("  \(secondDetailLine)", width: width, highlighted: selected))
        print(feedTUISeparator(width: width))
    }

    private func feedTUIKindLabel(_ kind: String) -> String {
        switch kind {
        case "permissionRequest":
            return "permission"
        case "exitPlan":
            return "plan"
        case "question":
            return "question"
        default:
            return kind
        }
    }

    private func relativeFeedTUITime(since date: Date?) -> String {
        guard let date else { return "" }
        let seconds = max(Int(Date().timeIntervalSince(date)), 0)
        if seconds < 60 {
            return "\(seconds)s"
        }
        let minutes = seconds / 60
        if minutes < 60 {
            return "\(minutes)m"
        }
        let hours = minutes / 60
        if hours < 24 {
            return "\(hours)h"
        }
        return "\(hours / 24)d"
    }

    private func selectedHelp(_ item: FeedTUIItem?) -> String {
        guard let item else { return "No selection" }
        guard item.canResolve else { return "Resolved or informational item" }
        switch item.kind {
        case "permissionRequest":
            let supportsOnce = feedTUISourceSupportsOncePermissionMode(
                item.source,
                toolInputJSON: item.toolInputCapabilitiesJSON
            )
            let supportsAlways = feedTUISourceSupportsAlwaysPermissionMode(
                item.source,
                toolInputJSON: item.toolInputCapabilitiesJSON
            )
            let supportsAll = feedTUISourceSupportsAllPermissionMode(
                item.source,
                toolInputJSON: item.toolInputCapabilitiesJSON
            )
            var actions: [String] = []
            if supportsOnce { actions.append("Enter/o once") }
            if supportsAlways { actions.append("a always") }
            if supportsAll { actions.append("l all tools") }
            if feedTUISourceSupportsBypassPermissions(item.source) { actions.append("b bypass") }
            actions.append("d deny")
            return "Permission: \(actions.joined(separator: ", "))"
        case "exitPlan":
            if !feedTUISourceSupportsBypassPermissions(item.source) {
                return "Plan: Enter default, a auto, m manual, u ultraplan, f replan, d deny"
            }
            return "Plan: Enter default, a auto, m manual, u ultraplan, b bypass, f replan, d deny"
        case "question":
            let questionCount = max(item.questions.count, 1)
            let firstQuestion = item.questions.first
            let optionText = (firstQuestion?.options ?? item.questionOptions).enumerated().map { index, option in
                "\(index + 1)=\(option.label)"
            }.joined(separator: "  ")
            if questionCount > 1 {
                return "Question: Enter sends defaults for \(questionCount) prompts"
            }
            if optionText.isEmpty {
                return "Question: Enter sends an empty answer"
            }
            let suffix = (firstQuestion?.multiSelect ?? item.questionMultiSelect) ? "  Enter sends selected options" : ""
            return "Question: \(optionText)\(suffix)"
        default:
            return ""
        }
    }

    private func feedTUISourceSupportsOncePermissionMode(_ source: String, toolInputJSON: String?) -> Bool {
        CMUXCLI.feedSourceSupportsOncePermissionMode(source, toolInputJSON: toolInputJSON)
    }

    private func feedTUISourceSupportsAlwaysPermissionMode(_ source: String, toolInputJSON: String?) -> Bool {
        CMUXCLI.feedSourceSupportsAlwaysPermissionMode(source, toolInputJSON: toolInputJSON)
    }

    private func feedTUISourceSupportsAllPermissionMode(_ source: String, toolInputJSON: String?) -> Bool {
        CMUXCLI.feedSourceSupportsAllPermissionMode(source, toolInputJSON: toolInputJSON)
    }

    private func feedTUISourceSupportsBypassPermissions(_ source: String) -> Bool {
        CMUXCLI.feedSourceSupportsBypassPermissions(source)
    }

    static func feedSourceSupportsPersistentPermissionModes(_ source: String) -> Bool {
        CodexTeamsApprovalBridge.feedSourceSupportsPersistentPermissionModes(source)
    }

    static func feedSourceSupportsOncePermissionMode(_ source: String, toolInputJSON: String?) -> Bool {
        CodexTeamsApprovalBridge.feedSourceSupportsOncePermissionMode(source, toolInputJSON: toolInputJSON)
    }

    static func feedSourceSupportsAlwaysPermissionMode(_ source: String, toolInputJSON: String?) -> Bool {
        CodexTeamsApprovalBridge.feedSourceSupportsAlwaysPermissionMode(source, toolInputJSON: toolInputJSON)
    }

    static func feedSourceSupportsAllPermissionMode(_ source: String, toolInputJSON: String?) -> Bool {
        CodexTeamsApprovalBridge.feedSourceSupportsAllPermissionMode(source, toolInputJSON: toolInputJSON)
    }

    static func feedSourceSupportsBypassPermissions(_ source: String) -> Bool {
        CodexTeamsApprovalBridge.feedSourceSupportsBypassPermissions(source)
    }

    private func resolveFeedTUIItem(
        _ item: FeedTUIItem,
        key: FeedTUIKey,
        client: SocketClient,
        rawMode: inout TerminalRawMode?,
        selectedQuestionOptions: inout [String: Set<String>]
    ) throws -> String {
        guard item.canResolve, let requestId = item.requestId else {
            return "No pending action for selected item"
        }

        switch item.kind {
        case "permissionRequest":
            let mode: String
            switch key {
            case .enter where feedTUISourceSupportsOncePermissionMode(
                item.source,
                toolInputJSON: item.toolInputCapabilitiesJSON
            ),
            .once where feedTUISourceSupportsOncePermissionMode(
                item.source,
                toolInputJSON: item.toolInputCapabilitiesJSON
            ):
                mode = "once"
            case .always where feedTUISourceSupportsAlwaysPermissionMode(
                item.source,
                toolInputJSON: item.toolInputCapabilitiesJSON
            ):
                mode = "always"
            case .all where feedTUISourceSupportsAllPermissionMode(
                item.source,
                toolInputJSON: item.toolInputCapabilitiesJSON
            ):
                mode = "all"
            case .bypass where feedTUISourceSupportsBypassPermissions(item.source):
                mode = "bypass"
            case .deny:
                mode = "deny"
            default:
                return "Key is not available for permission requests"
            }
            _ = try client.sendV2(
                method: "feed.permission.reply",
                params: ["request_id": requestId, "mode": mode]
            )
            return "Permission \(mode) sent"
        case "exitPlan":
            if key == .feedback {
                let feedback = readFeedTUIFeedbackPrompt(rawMode: &rawMode)
                guard !feedback.isEmpty else { return "Replan cancelled" }
                _ = try client.sendV2(
                    method: "feed.exit_plan.reply",
                    params: ["request_id": requestId, "mode": "deny", "feedback": feedback]
                )
                return "Replan feedback sent"
            }

            let mode: String
            switch key {
            case .enter:
                mode = item.defaultMode ?? "manual"
            case .autoAccept, .always:
                mode = "autoAccept"
            case .manual:
                mode = "manual"
            case .ultraplan:
                mode = "ultraplan"
            case .bypass where feedTUISourceSupportsBypassPermissions(item.source):
                mode = "bypassPermissions"
            case .deny:
                mode = "deny"
            default:
                return "Key is not available for plans"
            }
            _ = try client.sendV2(
                method: "feed.exit_plan.reply",
                params: ["request_id": requestId, "mode": mode]
            )
            return "Plan \(mode) sent"
        case "question":
            let primaryQuestion = item.questions.first
            let primaryOptions = primaryQuestion?.options ?? item.questionOptions
            let primaryMultiSelect = primaryQuestion?.multiSelect ?? item.questionMultiSelect
            if primaryOptions.isEmpty {
                guard key == .enter else {
                    return "Question has no selectable options"
                }
                _ = try client.sendV2(
                    method: "feed.question.reply",
                    params: ["request_id": requestId, "selections": [] as [String]]
                )
                return "Question answer sent"
            }

            if item.questions.count > 1, key == .enter {
                let selections = item.questions.map { question in
                    question.options.first?.label ?? ""
                }
                _ = try client.sendV2(
                    method: "feed.question.reply",
                    params: ["request_id": requestId, "selections": selections]
                )
                return "Question answer sent"
            }

            if primaryMultiSelect {
                switch key {
                case .number(let index):
                    guard let option = feedTUIOption(in: primaryOptions, at: index - 1) else {
                        return "No option \(index)"
                    }
                    var selections = selectedQuestionOptions[requestId] ?? Set<String>()
                    if selections.contains(option.id) {
                        selections.remove(option.id)
                        selectedQuestionOptions[requestId] = selections
                        return "Unselected: \(option.label)"
                    }
                    selections.insert(option.id)
                    selectedQuestionOptions[requestId] = selections
                    return "Selected: \(option.label)"
                case .enter:
                    let selected = selectedQuestionOptions[requestId] ?? Set<String>()
                    let selections = primaryOptions
                        .filter { selected.contains($0.id) }
                        .map(\.label)
                    _ = try client.sendV2(
                        method: "feed.question.reply",
                        params: ["request_id": requestId, "selections": selections]
                    )
                    selectedQuestionOptions.removeValue(forKey: requestId)
                    return selections.isEmpty ? "Question answer sent with no selections" : "Question answer sent"
                default:
                    return "Key is not available for questions"
                }
            }

            let option: FeedTUIOption?
            switch key {
            case .number(let index):
                option = feedTUIOption(in: primaryOptions, at: index - 1)
            case .enter:
                option = primaryOptions.first
            default:
                return "Key is not available for questions"
            }
            guard let option else {
                return "No question option available"
            }
            _ = try client.sendV2(
                method: "feed.question.reply",
                params: ["request_id": requestId, "selections": [option.label]]
            )
            return "Question answer sent: \(option.label)"
        default:
            return "Unsupported feed item"
        }
    }

    private func readFeedTUIFeedbackPrompt(rawMode: inout TerminalRawMode?) -> String {
        rawMode?.restore()
        print("\u{001B}[2J\u{001B}[H", terminator: "")
        print("Tell the agent what to change, then press Return.")
        print("> ", terminator: "")
        fflush(stdout)
        let value = readLine() ?? ""
        guard let restoredRawMode = TerminalRawMode() else {
            return ""
        }
        rawMode = restoredRawMode
        return value.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func readFeedTUIKey(timeoutMilliseconds: Int32? = nil) -> FeedTUIKey {
        if let timeoutMilliseconds {
            while true {
                var descriptor = pollfd(
                    fd: STDIN_FILENO,
                    events: Int16(POLLIN | POLLHUP | POLLERR),
                    revents: 0
                )
                let ready = Darwin.poll(&descriptor, 1, timeoutMilliseconds)
                if ready < 0 {
                    if errno == EINTR { continue }
                    return .ignored
                }
                if ready == 0 {
                    return .tick
                }
                if descriptor.revents & Int16(POLLHUP) != 0 {
                    return .quit
                }
                if descriptor.revents & Int16(POLLIN) == 0 {
                    return .ignored
                }
                break
            }
        }

        var byte: UInt8 = 0
        while true {
            let count = Darwin.read(STDIN_FILENO, &byte, 1)
            if count < 0 {
                if errno == EINTR { continue }
                return .ignored
            }
            if count == 0 { return .quit }
            break
        }

        switch byte {
        case 3:
            return .quit
        case 10, 13:
            return .enter
        case 27:
            guard let first = readFeedTUIByteIfReady(timeoutMilliseconds: 25),
                  let second = readFeedTUIByteIfReady(timeoutMilliseconds: 25),
                  first == 91 else {
                return .ignored
            }
            switch second {
            case 65: return .up
            case 66: return .down
            default: return .ignored
            }
        case 106, 74:
            return .down
        case 107, 75:
            return .up
        case 113, 81:
            return .quit
        case 114, 82:
            return .refresh
        case 100, 68:
            return .deny
        case 102, 70:
            return .feedback
        case 111, 79:
            return .once
        case 97, 65:
            return .always
        case 108, 76:
            return .all
        case 98, 66:
            return .bypass
        case 109, 77:
            return .manual
        case 117, 85:
            return .ultraplan
        case 49...57:
            return .number(Int(byte - 48))
        case 48:
            return .number(10)
        default:
            return .ignored
        }
    }

    private func readFeedTUIByteIfReady(timeoutMilliseconds: Int32) -> UInt8? {
        while true {
            var descriptor = pollfd(
                fd: STDIN_FILENO,
                events: Int16(POLLIN | POLLHUP | POLLERR),
                revents: 0
            )
            let ready = Darwin.poll(&descriptor, 1, timeoutMilliseconds)
            if ready < 0 {
                if errno == EINTR { continue }
                return nil
            }
            guard ready > 0, descriptor.revents & Int16(POLLIN) != 0 else {
                return nil
            }
            var byte: UInt8 = 0
            let count = Darwin.read(STDIN_FILENO, &byte, 1)
            return count == 1 ? byte : nil
        }
    }

    static func currentCLITerminalSize() -> (cols: Int, rows: Int) {
        var size = winsize()
        if ioctl(STDOUT_FILENO, TIOCGWINSZ, &size) == 0,
           size.ws_col > 0,
           size.ws_row > 0 {
            return (Int(size.ws_col), Int(size.ws_row))
        }
        return (80, 24)
    }

    private func feedTUISeparator(width: Int) -> String {
        String(repeating: "-", count: max(width, 0))
    }

    private func feedTUILine(
        _ value: String,
        width: Int,
        highlighted: Bool = false
    ) -> String {
        let line = paddedTerminalLine(truncateForTerminal(value, width: width), width: width)
        guard highlighted else { return line }
        return "\u{001B}[7m\(line)\u{001B}[0m"
    }

    private func paddedTerminalLine(_ value: String, width: Int) -> String {
        guard width > 0 else { return "" }
        if value.count >= width {
            return value
        }
        return value + String(repeating: " ", count: width - value.count)
    }

    private func wrappedTerminalLines(_ value: String, width: Int, maxLines: Int) -> [String] {
        guard maxLines > 0 else { return [] }
        guard width > 0 else { return Array(repeating: "", count: maxLines) }

        var remainder = sanitizedTerminalText(value)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        var lines: [String] = []

        while lines.count < maxLines, !remainder.isEmpty {
            if remainder.count <= width {
                lines.append(remainder)
                remainder = ""
                break
            }

            let limitIndex = remainder.index(remainder.startIndex, offsetBy: width)
            let candidate = remainder[..<limitIndex]
            if let splitIndex = candidate.lastIndex(of: " ") {
                let line = String(remainder[..<splitIndex])
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                lines.append(line.isEmpty ? String(candidate) : line)
                remainder = String(remainder[splitIndex...])
                    .trimmingCharacters(in: .whitespacesAndNewlines)
            } else {
                lines.append(String(candidate))
                remainder = String(remainder[limitIndex...])
                    .trimmingCharacters(in: .whitespacesAndNewlines)
            }
        }

        if !remainder.isEmpty, !lines.isEmpty {
            lines[lines.count - 1] = truncateForTerminal("\(lines[lines.count - 1]) ...", width: width)
        }

        while lines.count < maxLines {
            lines.append("")
        }
        return lines
    }

    private func sanitizedTerminalText(_ value: String) -> String {
        var output = ""
        for scalar in value.unicodeScalars {
            if CharacterSet.controlCharacters.contains(scalar) {
                output.append(" ")
            } else {
                output.unicodeScalars.append(scalar)
            }
        }
        return output
            .replacingOccurrences(of: "\u{001B}", with: " ")
            .replacingOccurrences(of: "\t", with: " ")
    }

    private func truncateForTerminal(_ value: String, width: Int) -> String {
        guard width > 0 else { return "" }
        let sanitized = sanitizedTerminalText(value)
        if sanitized.count <= width { return sanitized }
        let suffix = "..."
        guard width > suffix.count else {
            let end = sanitized.index(sanitized.startIndex, offsetBy: width)
            return String(sanitized[..<end])
        }
        let end = sanitized.index(sanitized.startIndex, offsetBy: width - suffix.count)
        return String(sanitized[..<end]) + suffix
    }

    private func runFeedClear() throws {
        let home = FileManager.default.homeDirectoryForCurrentUser
        let path = home
            .appendingPathComponent(".cmuxterm", isDirectory: true)
            .appendingPathComponent("workstream.jsonl", isDirectory: false)
        let fm = FileManager.default
        guard fm.fileExists(atPath: path.path) else {
            print("No Feed history to clear (\(path.path) does not exist).")
            return
        }
        let skipConfirm = ProcessInfo.processInfo.arguments.contains("--yes")
            || ProcessInfo.processInfo.arguments.contains("-y")
        if !skipConfirm {
            print("This will permanently delete \(path.path). Proceed? [y/N] ", terminator: "")
            guard readLine()?.lowercased().hasPrefix("y") == true else {
                print("Aborted.")
                return
            }
        }
        try fm.removeItem(at: path)
        print("Cleared \(path.path)")
    }

    // MARK: - OpenCode plugin install

    /// Marker matching the `// cmux-feed-plugin-marker` line emitted at
    /// the top of the generated plugin JS. Lets us detect our own
    /// plugin file and upgrade/uninstall without touching user plugins.
    private static let openCodePluginMarker = "cmux-feed-plugin-marker"

    private static let openCodePluginFileName = "cmux-feed.js"

    private func openCodeConfigDirPath() -> String {
        if let override = ProcessInfo.processInfo.environment["OPENCODE_CONFIG_DIR"],
           !override.isEmpty {
            return NSString(string: override).expandingTildeInPath
        }
        return FileManager.default.homeDirectoryForCurrentUser
            .appendingPathComponent(".config/opencode", isDirectory: true)
            .path
    }

    private func openCodePluginPath(projectLocal: Bool) -> String {
        if projectLocal {
            let cwd = FileManager.default.currentDirectoryPath
            return "\(cwd)/.opencode/plugins/\(Self.openCodePluginFileName)"
        }
        return "\(openCodeConfigDirPath())/plugins/\(Self.openCodePluginFileName)"
    }

    private func bundledOpenCodePluginSource() throws -> String {
        // The plugin JS is bundled into the .app via `Resources/opencode-plugin.js`.
        // The `cmux` CLI is often launched from `Contents/Resources/bin/cmux`,
        // where Bundle.main can be the CLI executable rather than the containing
        // app. Search the real executable path before falling back to repo dev
        // paths used by `swift run`-style local builds.
        for url in openCodePluginResourceCandidates() {
            if let contents = try? String(contentsOf: url, encoding: .utf8) {
                return contents
            }
        }
        throw CLIError(message: "bundled opencode-plugin.js not found (Bundle.main, app bundle, executable, and repo fallbacks)")
    }

    private func openCodePluginResourceCandidates() -> [URL] {
        let fileManager = FileManager.default
        var candidates: [URL] = []
        var seen: Set<String> = []

        func appendIfExisting(_ url: URL?) {
            guard let url else { return }
            let standardized = url.standardizedFileURL
            guard seen.insert(standardized.path).inserted else { return }
            guard fileManager.fileExists(atPath: standardized.path) else { return }
            candidates.append(standardized)
        }

        appendIfExisting(Bundle.main.url(forResource: "opencode-plugin", withExtension: "js"))
        appendIfExisting(Bundle.main.resourceURL?.appendingPathComponent("opencode-plugin.js", isDirectory: false))

        if let executableURL = resolvedExecutableURL() {
            let execDir = executableURL.deletingLastPathComponent().standardizedFileURL
            for relativePath in ["opencode-plugin.js", "../opencode-plugin.js", "../../Resources/opencode-plugin.js", "../../../Contents/Resources/opencode-plugin.js"] {
                appendIfExisting(execDir.appendingPathComponent(relativePath, isDirectory: false).standardizedFileURL)
            }

            var current = execDir
            for _ in 0..<4 {
                if current.pathExtension == "app" {
                    appendIfExisting(current.appendingPathComponent("Contents/Resources/opencode-plugin.js", isDirectory: false))
                    break
                }
                let projectMarker = current.appendingPathComponent("cmux.xcodeproj/project.pbxproj")
                let repoResource = current.appendingPathComponent("Resources/opencode-plugin.js", isDirectory: false)
                if fileManager.fileExists(atPath: projectMarker.path),
                   fileManager.fileExists(atPath: repoResource.path) {
                    appendIfExisting(repoResource)
                    break
                }
                current = current.deletingLastPathComponent().standardizedFileURL
            }
        }

        let devRelative = URL(fileURLWithPath: #filePath)
            .deletingLastPathComponent()
            .deletingLastPathComponent()
            .appendingPathComponent("Resources/opencode-plugin.js")
        appendIfExisting(devRelative)
        return candidates
    }

    private func installOpenCodePlugin(projectLocal: Bool) throws {
        let source = try bundledOpenCodePluginSource()
        let path = openCodePluginPath(projectLocal: projectLocal)
        let fm = FileManager.default
        // If an existing non-cmux plugin lives at the same path, refuse
        // to overwrite. Users can delete it manually or pick a different
        // name; we never clobber user content.
        let existing = fm.fileExists(atPath: path)
            ? ((try? String(contentsOfFile: path, encoding: .utf8)) ?? "")
            : ""
        if !existing.isEmpty, !existing.contains(Self.openCodePluginMarker) {
            throw CLIError(message: "\(path) exists and is not a cmux plugin; leaving it alone")
        }
        let parent = (path as NSString).deletingLastPathComponent
        try fm.createDirectory(
            atPath: parent, withIntermediateDirectories: true
        )
        let skipConfirm = ProcessInfo.processInfo.arguments.contains("--yes")
            || ProcessInfo.processInfo.arguments.contains("-y")
        if existing == source {
            print("OpenCode plugin already up to date at \(path)")
            return
        }
        if !skipConfirm {
            Self.printInstallPreview(
                path: path,
                oldContent: existing,
                newContent: source,
                fallbackContent: source
            )
            print("\nProceed? [y/N] ", terminator: "")
            guard readLine()?.lowercased().hasPrefix("y") == true else {
                print("Aborted.")
                return
            }
        }
        try source.write(toFile: path, atomically: true, encoding: .utf8)
        print("OpenCode plugin installed at \(path)")
    }

    private func uninstallOpenCodePlugin(projectLocal: Bool = false) throws {
        let fm = FileManager.default
        for path in [openCodePluginPath(projectLocal: false),
                     openCodePluginPath(projectLocal: true)] {
            guard fm.fileExists(atPath: path) else { continue }
            guard let existing = try? String(contentsOfFile: path, encoding: .utf8),
                  existing.contains(Self.openCodePluginMarker)
            else {
                print("Skipping \(path) (no cmux marker)")
                continue
            }
            try fm.removeItem(atPath: path)
            print("OpenCode plugin removed from \(path)")
        }
    }

    // MARK: - Feed (workstream) hook bridge

    /// Reads an agent hook JSON payload from stdin, forwards it to the
    /// running cmux app via the `feed.push` V2 socket verb, and (for
    /// actionable events: ExitPlanMode, AskUserQuestion, permission-
    /// requiring tools) blocks until the user resolves the item. The
    /// decision JSON is emitted on stdout in the agent's expected format
    /// so the agent honors the user's choice.
    ///
    /// Usage:
    ///   echo "<hook_json>" | cmux hooks feed --source <claude|codex|...>
    ///
    /// Designed so agents and wrappers can point a native decision hook
    /// at it and have permission/plan/question events surface in the
    /// Feed sidebar. Agent-specific lifecycle/status hooks can be
    /// chained separately. For Claude, `hooks claude pre-tool-use` is
    /// async status-only telemetry; blocking decisions come through
    /// PermissionRequest.
    private func runFeedHook(
        commandArgs: [String],
        client: SocketClient? = nil,
        socketPath: String? = nil,
        socketPassword: String? = nil,
        telemetry: CLISocketSentryTelemetry
    ) throws {
        _ = telemetry
        let source = optionValue(commandArgs, name: "--source") ?? ""
        guard !source.isEmpty else {
            throw CLIError(message: "cmux hooks feed requires --source <agent-name>")
        }

        // Outside a cmux terminal (no CMUX_SURFACE_ID) → silently no-op.
        // Also matches the graceful-fallback pattern of the other hooks.
        guard ProcessInfo.processInfo.environment["CMUX_SURFACE_ID"]?.isEmpty == false else {
            print("{}")
            return
        }

        let commandEvent = optionValue(commandArgs, name: "--event")

        // Read stdin. Claude, Codex, and the other agents all pipe hook
        // JSON through stdin; unknown inputs fall through to `{}`. Codex feed
        // events are telemetry, and native lifecycle hooks can carry arbitrary
        // transcript fragments or tool output, so cap every Codex feed
        // invocation before JSON decoding without changing other agents'
        // actionable hook reads.
        let stdinData: Data
        let shouldBoundCodexFeedStdin = source == "codex"
        if shouldBoundCodexFeedStdin {
            guard let boundedData = Self.readBoundedFeedHookStdin() else {
                print("{}")
                return
            }
            stdinData = boundedData
        } else {
            stdinData = FileHandle.standardInput.readDataToEndOfFile()
        }
        guard !stdinData.isEmpty,
              let stdinObj = try? JSONSerialization.jsonObject(with: stdinData) as? [String: Any]
        else {
            print("{}")
            return
        }

        // Derive the hook event name, mapped to our wire format. Claude
        // uses `hook_event_name`; Codex uses `event` or `hook_event_name`.
        let rawEvent = (stdinObj["hook_event_name"] as? String)
            ?? (stdinObj["event"] as? String)
            ?? commandEvent
            ?? ""
        let toolCall = stdinObj["toolCall"] as? [String: Any]
        let toolName = firstString(in: stdinObj, keys: ["tool_name", "toolName"])
            ?? toolCall.flatMap { firstString(in: $0, keys: ["name"]) }
            ?? ""

        // Decide whether this event is Feed-actionable. Non-actionable
        // events are forwarded as telemetry (non-blocking) and exit `{}`
        // so the agent proceeds without a decision.
        let (hookEventName, isActionable) = FeedEventClassifier.classify(
            source: source,
            event: rawEvent,
            toolName: toolName
        )
        let env = ProcessInfo.processInfo.environment
        if Self.shouldSuppressKiroFeedEvent(
            source: source,
            hookEventName: hookEventName,
            toolName: toolName,
            isActionable: isActionable,
            env: env
        ) {
            print("{}")
            return
        }

        // Capture the agent's PID (not our subprocess PID) so the
        // Feed can auto-expire pending cards when the agent is
        // killed/crashed. Agent wrappers export CMUX_<AGENT>_PID.
        // Other agents fall back to getppid() which walks up one
        // level — close enough to catch most kill scenarios.
        let agentPid = agentPidForFeedSource(source, env: env)
        let sessionId = firstString(
            in: stdinObj,
            keys: ["session_id", "sessionId", "conversation_id", "conversationId"]
        ) ?? stableFallbackFeedSessionId(source: source, rawObject: stdinObj, agentPid: agentPid)

        var eventDict: [String: Any] = [
            "session_id": "\(source)-\(sessionId)",
            "hook_event_name": hookEventName,
            "_source": source,
            "_ppid": agentPid,
        ]
        if let workspaceId = feedWorkspaceId(rawObject: stdinObj, fallback: env["CMUX_WORKSPACE_ID"]) {
            eventDict["workspace_id"] = workspaceId
        }
        let toolRequestInput = stdinObj["tool_input"] ?? stdinObj["toolInput"] ?? toolCall?["args"]
        let postToolUseResponseInput = stdinObj["tool_response"]
            ?? stdinObj["toolResponse"]
            ?? stdinObj["tool_result"]
            ?? stdinObj["toolResult"]
        let shouldUseCodexPostToolUseResponse = source == "codex"
            && hookEventName == "PostToolUse"
            && postToolUseResponseInput != nil
        let feedToolInput = shouldUseCodexPostToolUseResponse
            ? postToolUseResponseInput
            : toolRequestInput
        if let cwd = firstString(in: stdinObj, keys: ["cwd", "working_directory", "workingDirectory"])
            ?? firstWorkspacePath(in: stdinObj)
            ?? (toolRequestInput as? [String: Any]).flatMap({ firstString(in: $0, keys: ["Cwd", "cwd"]) }) {
            eventDict["cwd"] = cwd
        }
        if !toolName.isEmpty { eventDict["tool_name"] = toolName }
        let promptText = hookEventName == "UserPromptSubmit" ? feedPromptText(from: stdinObj) : nil
        if let feedToolInput {
            eventDict["tool_input"] = shouldUseCodexPostToolUseResponse
                ? Self.sanitizedPostToolUseFeedValue(feedToolInput)
                : feedToolInput
        }
        if let context = feedContextForEvent(
            source: source,
            hookEventName: hookEventName,
            toolName: toolName.isEmpty ? nil : toolName,
            toolInput: eventDict["tool_input"],
            rawObject: stdinObj,
            transcriptPath: firstString(in: stdinObj, keys: ["transcript_path", "transcriptPath"])
        ) {
            eventDict["context"] = context
        }
        enrichUserPromptSubmitFeedEvent(
            &eventDict,
            hookEventName: hookEventName,
            promptText: promptText
        )
        let requestId = stdinObj["_opencode_request_id"] as? String
            ?? firstString(in: stdinObj, keys: ["request_id", "tool_use_id", "toolUseID"])
            ?? "\(source)-\(sessionId)-\(rawEvent)-\(toolName)-\(Int(Date().timeIntervalSince1970 * 1000))"
        eventDict["_opencode_request_id"] = requestId

        // Sync. For actionable events we block up to 120s waiting
        // for the user's Feed click; the hook's stdout is then a
        // proper hookSpecificOutput that Claude honors directly
        // (no keystroke injection, no guessing the TUI layout).
        // If the user doesn't click in time the hook emits {}
        // and Claude falls back to its native TUI prompt.
        //
        // Wait is capped at 120s and the wrapper's hook timeout
        // is 125s so the socket always returns before Claude
        // would kill the hook subprocess itself.
        let waitTimeout: Double = isActionable ? 120 : 0
        let params: [String: Any] = [
            "event": eventDict,
            "wait_timeout_seconds": waitTimeout,
        ]

        var request: [String: Any] = [
            "method": "feed.push",
            "params": params,
        ]
        if waitTimeout > 0 {
            request["id"] = UUID().uuidString
        }
        let payload = try JSONSerialization.data(withJSONObject: request)
        let line = String(data: payload, encoding: .utf8) ?? "{}"

        if waitTimeout == 0 {
            if let client {
                _ = try? client.sendOneWay(command: line, writeTimeout: 0.05)
            } else if let socketPath {
                sendBestEffortFeedTelemetry(
                    socketPath: socketPath,
                    line: line,
                    socketPassword: socketPassword
                )
            }
            print("{}")
            return
        }

        var ownedClient: SocketClient?
        defer { ownedClient?.close() }
        let activeClient: SocketClient
        if let client {
            activeClient = client
        } else if let socketPath {
            let feedClient = SocketClient(path: socketPath)
            do {
                try feedClient.connect()
                try authenticateClientIfNeeded(
                    feedClient,
                    explicitPassword: socketPassword,
                    socketPath: socketPath
                )
            } catch {
                feedClient.close()
                print("{}")
                return
            }
            ownedClient = feedClient
            activeClient = feedClient
        } else {
            print("{}")
            return
        }

        let response: String
        do {
            response = try activeClient.send(
                command: line,
                responseTimeout: waitTimeout + 5
            )
        } catch {
            print("{}")
            return
        }

        guard let respData = response.data(using: .utf8),
              let respObj = try? JSONSerialization.jsonObject(with: respData) as? [String: Any],
              let ok = respObj["ok"] as? Bool, ok,
              let result = respObj["result"] as? [String: Any]
        else {
            print("{}")
            return
        }

        let status = result["status"] as? String ?? "acknowledged"
        if status == "resolved", let decision = result["decision"] as? [String: Any] {
            if source == "kiro", Self.emitKiroDecisionIfHandled(decision: decision) {
                return
            }
            let out = Self.renderAgentDecision(
                source: source,
                hookEventName: hookEventName,
                toolName: toolName,
                toolInput: eventDict["tool_input"],
                rawObject: stdinObj,
                decision: decision
            )
            print(out)
            return
        }
        print("{}")
    }

    private static let feedHookMaxStdinBytes = 1 * 1024 * 1024

    private static func readBoundedFeedHookStdin(
        handle: FileHandle = .standardInput
    ) -> Data? {
        var data = Data()
        while data.count <= feedHookMaxStdinBytes {
            let remainingBytes = feedHookMaxStdinBytes + 1 - data.count
            let chunkSize = min(64 * 1024, remainingBytes)
            let chunk = (try? handle.read(upToCount: chunkSize)) ?? Data()
            guard !chunk.isEmpty else { return data }
            data.append(chunk)
        }
        guard data.count <= feedHookMaxStdinBytes else {
            while !((try? handle.read(upToCount: 64 * 1024)) ?? Data()).isEmpty {}
            return nil
        }
        return data
    }

    private static let feedPostToolUseScalarStringLimitBytes = 512
    private static let feedPostToolUseMetadataKeys: Set<String> = [
        "exitcode",
        "status",
        "signal",
        "durationms",
        "timedout",
        "success",
    ]
    private static let feedPostToolUseOutputKeys: Set<String> = [
        "stdout",
        "stderr",
        "output",
        "text",
        "result",
        "message",
        "error",
    ]

    private static func sanitizedPostToolUseFeedValue(_ value: Any) -> Any {
        var summary: [String: Any] = [
            "_cmux_sanitized": true,
        ]

        if let dictionary = value as? [String: Any] {
            summary["_cmux_original_key_count"] = dictionary.count
            var summarizedKeys = Set<String>()

            for (key, rawValue) in dictionary {
                let normalizedKey = normalizedPostToolUseSummaryKey(key)
                if feedPostToolUseMetadataKeys.contains(normalizedKey),
                   let scalarValue = boundedPostToolUseScalarValue(rawValue) {
                    summary[key] = scalarValue.value
                    if scalarValue.truncated {
                        summary["\(key)_truncated"] = true
                    }
                    summarizedKeys.insert(key)
                }
                if feedPostToolUseOutputKeys.contains(normalizedKey) {
                    summarizePostToolUseOmittedField(
                        key: key,
                        rawValue: rawValue,
                        into: &summary
                    )
                    summarizedKeys.insert(key)
                }
            }

            let omittedKeys = dictionary.keys.filter { !summarizedKeys.contains($0) }.count
            if omittedKeys > 0 {
                summary["_cmux_omitted_key_count"] = omittedKeys
            }
        } else if let array = value as? [Any] {
            summary["_cmux_array_count"] = array.count
        } else if value is String {
            summary["_cmux_text_omitted"] = true
        } else if let scalarValue = boundedPostToolUseScalarValue(value) {
            summary["_cmux_value"] = scalarValue.value
            if scalarValue.truncated {
                summary["_cmux_value_truncated"] = true
            }
        }

        return summary
    }

    private static func normalizedPostToolUseSummaryKey(_ key: String) -> String {
        key
            .replacingOccurrences(of: "_", with: "")
            .replacingOccurrences(of: "-", with: "")
            .lowercased()
    }

    private static func summarizePostToolUseOmittedField(
        key: String,
        rawValue: Any,
        into summary: inout [String: Any]
    ) {
        if rawValue is String {
            summary["\(key)_text_omitted"] = true
            return
        }
        if let array = rawValue as? [Any] {
            summary["\(key)_array_count"] = array.count
            summary["\(key)_omitted"] = true
            return
        }
        if let dictionary = rawValue as? [String: Any] {
            summary["\(key)_object_key_count"] = dictionary.count
            summary["\(key)_omitted"] = true
            return
        }
        summary["\(key)_omitted"] = true
    }

    private static func boundedPostToolUseScalarValue(_ rawValue: Any) -> (value: Any, truncated: Bool)? {
        if rawValue is NSNull {
            return (NSNull(), false)
        }
        if let bool = rawValue as? Bool {
            return (bool, false)
        }
        if let number = rawValue as? NSNumber {
            return (number, false)
        }
        if let string = rawValue as? String {
            let preview = feedUTF8Prefix(
                string,
                maxBytes: feedPostToolUseScalarStringLimitBytes
            )
            return (preview.value, preview.truncated)
        }
        return nil
    }

    private static func feedUTF8Prefix(
        _ value: String,
        maxBytes: Int
    ) -> (value: String, truncated: Bool) {
        var usedBytes = 0
        var endIndex = value.startIndex
        while endIndex < value.endIndex {
            let nextIndex = value.index(after: endIndex)
            let characterBytes = value[endIndex..<nextIndex].utf8.count
            if usedBytes + characterBytes > maxBytes {
                return (String(value[..<endIndex]), true)
            }
            usedBytes += characterBytes
            endIndex = nextIndex
        }
        return (value, false)
    }

    private static func shouldSuppressKiroFeedEvent(
        source: String,
        hookEventName: String,
        toolName: String,
        isActionable: Bool,
        env: [String: String]
    ) -> Bool {
        guard source == "kiro" else { return false }
        guard env["CMUX_KIRO_NOTIFICATION_LEVEL"] != nil || hookEventName == "PreToolUse" || hookEventName == "PostToolUse" else {
            return false
        }
        guard !isActionable else { return false }
        let level = env["CMUX_KIRO_NOTIFICATION_LEVEL"]?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased() ?? "standard"
        switch level {
        case "minimal":
            return hookEventName == "PreToolUse" || hookEventName == "PostToolUse"
        case "verbose":
            return false
        default:
            if hookEventName == "PreToolUse" || hookEventName == "PostToolUse" {
                return !FeedEventClassifier.isSideEffectingTool(toolName, source: source)
            }
            return false
        }
    }

    private static func emitKiroDecisionIfHandled(decision: [String: Any]) -> Bool {
        guard (decision["kind"] as? String) == "permission" else { return false }
        let mode = (decision["mode"] as? String)?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        // Feed permission decisions carry a WorkstreamPermissionMode raw value:
        // `once` / `always` / `all` / `bypass` all allow the tool; `deny`
        // blocks. Fail closed on anything else — missing, empty, or an
        // unrecognized/typo mode — so a malformed decision blocks the tool
        // (exit 2 is Kiro's preToolUse deny signal) rather than silently
        // allowing work the user never approved.
        let allowModes: Set<String> = ["once", "always", "all", "bypass"]
        if let mode, allowModes.contains(mode) {
            print("{}")
            return true
        }
        if mode == "deny" {
            cliWriteStderr("User denied permission via cmux Feed.\n")
        } else {
            cliWriteStderr("cmux Feed returned an unrecognized Kiro permission decision; denying for safety.\n")
        }
        exit(2)
    }

    private static let skipInterviewAndPlanAnswer = "Skip interview and plan immediately"

    /// Encodes the user's decision in the agent's expected hook stdout
    /// shape so the agent honors it.
    private static func renderAgentDecision(
        source: String,
        hookEventName: String,
        toolName: String,
        toolInput: Any?,
        rawObject: [String: Any],
        decision: [String: Any]
    ) -> String {
        let kind = decision["kind"] as? String ?? ""

        func encode(_ obj: [String: Any]) -> String {
            guard let data = try? JSONSerialization.data(
                withJSONObject: obj, options: [.sortedKeys]
            ),
                  let s = String(data: data, encoding: .utf8)
            else { return "{}" }
            return s
        }

        func permissionRequestHookDecision(
            behavior: String,
            message: String? = nil,
            updatedInput: [String: Any]? = nil,
            updatedPermissions: [[String: Any]]? = nil
        ) -> [String: Any] {
            var inner: [String: Any] = ["behavior": behavior]
            if behavior == "deny" {
                inner["message"] = message ?? "User denied permission via cmux Feed."
            }
            if let updatedInput, !updatedInput.isEmpty {
                inner["updatedInput"] = updatedInput
            }
            if let updatedPermissions, !updatedPermissions.isEmpty {
                inner["updatedPermissions"] = updatedPermissions
            }
            return [
                "hookSpecificOutput": [
                    "hookEventName": "PermissionRequest",
                    "decision": inner,
                ]
            ]
        }

        // PreToolUse output for non-Claude agents that still use a
        // PreToolUse-compatible permission bridge. Claude Code does not
        // use this path.
        func nonClaudePreToolDecision(
            permission: String,
            reason: String?,
            additionalContext: String? = nil,
            updatedInput: [String: Any]? = nil
        ) -> [String: Any] {
            var specific: [String: Any] = [
                "hookEventName": "PreToolUse",
                "permissionDecision": permission,
            ]
            if let reason, !reason.isEmpty {
                specific["permissionDecisionReason"] = reason
            }
            if let additionalContext, !additionalContext.isEmpty {
                specific["additionalContext"] = additionalContext
            }
            if let updatedInput, !updatedInput.isEmpty {
                specific["updatedInput"] = updatedInput
            }
            var out: [String: Any] = [
                "hookSpecificOutput": specific
            ]
            if permission == "deny" {
                out["decision"] = "block"
                if let reason, !reason.isEmpty { out["reason"] = reason }
            } else if permission == "allow" {
                out["decision"] = "approve"
                if let additionalContext, !additionalContext.isEmpty {
                    out["systemMessage"] = additionalContext
                } else if let reason, !reason.isEmpty {
                    out["systemMessage"] = reason
                }
            }
            return out
        }

        func hermesAgentBlock(_ message: String) -> String {
            encode(["action": "block", "message": message])
        }

        switch kind {
        case "permission":
            let mode = decision["mode"] as? String ?? "deny"
            if source == "claude" {
                if mode == "deny" {
                    return encode(permissionRequestHookDecision(
                        behavior: "deny",
                        message: "User denied permission via cmux Feed."
                    ))
                }
                var updatedPermissions: [[String: Any]]?
                if mode == "always" || mode == "all" {
                    updatedPermissions = rawObject["permission_suggestions"] as? [[String: Any]]
                }
                return encode(permissionRequestHookDecision(
                    behavior: "allow",
                    updatedPermissions: updatedPermissions
                ))
            }
            if source == "codex" {
                if mode == "deny" {
                    return encode(permissionRequestHookDecision(
                        behavior: "deny",
                        message: "User denied permission via cmux Feed."
                    ))
                }
                return encode(permissionRequestHookDecision(behavior: "allow"))
            }
            if source == "hermes-agent" {
                if mode == "deny" {
                    return hermesAgentBlock("User denied permission via cmux Feed.")
                }
                return "{}"
            }
            if source == "antigravity" {
                let reason = mode == "deny"
                    ? "User denied permission via cmux Feed."
                    : "User approved via cmux Feed."
                return encode([
                    "decision": mode == "deny" ? "deny" : "allow",
                    "reason": reason,
                ])
            }
            if mode == "deny" {
                return encode(nonClaudePreToolDecision(
                    permission: "deny",
                    reason: "User denied permission via cmux Feed."
                ))
            }
            var reasonText = "User approved via cmux Feed."
            if mode == "always" || mode == "all" || mode == "bypass" {
                reasonText = "User granted \(mode) permission via cmux Feed. Reduce subsequent approval prompts for similar calls."
            }
            return encode(nonClaudePreToolDecision(
                permission: "allow",
                reason: reasonText
            ))

        case "exit_plan":
            let mode = decision["mode"] as? String ?? "manual"
            let feedback = (decision["feedback"] as? String)?
                .trimmingCharacters(in: .whitespacesAndNewlines)
            if source == "claude" {
                if let feedback, !feedback.isEmpty {
                    return encode(permissionRequestHookDecision(
                        behavior: "deny",
                        message: "User rejected the plan via cmux Feed and wants this change: \(feedback)"
                    ))
                }
                if mode == "deny" {
                    return encode(permissionRequestHookDecision(
                        behavior: "deny",
                        message: "User rejected the plan via cmux Feed."
                    ))
                }
                if mode == "ultraplan" {
                    return encode(permissionRequestHookDecision(
                        behavior: "deny",
                        message: "User chose Ultraplan via cmux Feed. Refine this plan with Ultraplan on Claude Code on the web."
                    ))
                }
                var updatedPermissions: [[String: Any]]?
                if mode == "autoAccept" {
                    updatedPermissions = [[
                        "type": "setMode",
                        "mode": "auto",
                        "destination": "session",
                    ]]
                }
                return encode(permissionRequestHookDecision(
                    behavior: "allow",
                    updatedInput: jsonDictionary(from: toolInput),
                    updatedPermissions: updatedPermissions
                ))
            }
            if source == "hermes-agent" {
                if let feedback, !feedback.isEmpty {
                    return hermesAgentBlock("User rejected the plan via cmux Feed and wants this change: \(feedback)")
                }
                if mode == "deny" {
                    return hermesAgentBlock("User rejected the plan via cmux Feed.")
                }
                return "{}"
            }
            if let feedback, !feedback.isEmpty {
                let reason = "User rejected the plan via cmux Feed and wants this change: \(feedback)"
                return encode(nonClaudePreToolDecision(
                    permission: "deny",
                    reason: reason,
                    additionalContext: reason
                ))
            }
            if mode == "deny" {
                return encode(nonClaudePreToolDecision(
                    permission: "deny",
                    reason: "User rejected the plan via cmux Feed."
                ))
            }
            if mode == "ultraplan" {
                let reason = "User chose Ultraplan via cmux Feed. Refine this plan with Ultraplan if available."
                return encode(nonClaudePreToolDecision(
                    permission: "deny",
                    reason: reason,
                    additionalContext: reason
                ))
            }
            let modeText: String
            switch mode {
            case "bypassPermissions":
                modeText = "bypass-permissions mode (no per-edit approval)"
            case "autoAccept":
                modeText = "auto mode"
            default:
                modeText = "manual-approval mode (approve each edit)"
            }
            let ctx = "User accepted this plan via cmux Feed with \(modeText). Exit plan mode now and proceed to implement without re-entering ExitPlanMode. Do not ask again."
            return encode(nonClaudePreToolDecision(
                permission: "deny",
                reason: ctx,
                additionalContext: ctx
            ))

        case "question":
            let selections = decision["selections"] as? [String] ?? []
            if selections == [Self.skipInterviewAndPlanAnswer] {
                let message = "User chose Skip interview and plan immediately via cmux Feed. Do not ask more interview questions. Write the plan now."
                if source == "claude" {
                    return encode(permissionRequestHookDecision(
                        behavior: "deny",
                        message: message
                    ))
                }
                return encode(nonClaudePreToolDecision(
                    permission: "deny",
                    reason: message,
                    additionalContext: message
                ))
            }
            if source == "hermes-agent" {
                let body: String
                if selections.isEmpty {
                    body = "The user submitted an empty answer."
                } else if selections.count == 1 {
                    body = "The user answered: \(selections[0])"
                } else {
                    body = "The user answered: \(selections.joined(separator: ", "))"
                }
                return encode(["context": body])
            }
            if source == "claude" {
                let updatedInput = claudeAskUserQuestionInput(
                    toolInput: toolInput,
                    selections: selections
                )
                return encode(permissionRequestHookDecision(
                    behavior: "allow",
                    updatedInput: updatedInput
                ))
            }
            let body: String
            if selections.isEmpty {
                body = "The user submitted an empty answer."
            } else if selections.count == 1 {
                body = "The user answered: \(selections[0])"
            } else {
                let lines = selections
                    .enumerated()
                    .map { idx, s in "\(idx + 1). \(s)" }
                    .joined(separator: "\n")
                body = "The user answered:\n\(lines)"
            }
            let ctx = "[cmux Feed] \(body). Treat these as the user's response to your AskUserQuestion prompt; do not call AskUserQuestion again for the same question."
            return encode(nonClaudePreToolDecision(
                permission: "deny",
                reason: ctx,
                additionalContext: ctx
            ))

        default:
            _ = hookEventName
            _ = toolName
            return "{}"
        }
    }

    private static func jsonDictionary(from raw: Any?) -> [String: Any]? {
        if let dict = raw as? [String: Any] { return dict }
        if let str = raw as? String,
           let data = str.data(using: .utf8),
           let obj = try? JSONSerialization.jsonObject(with: data) as? [String: Any] {
            return obj
        }
        return nil
    }

    private static func claudeAskUserQuestionInput(
        toolInput: Any?,
        selections: [String]
    ) -> [String: Any] {
        var input = jsonDictionary(from: toolInput) ?? [:]
        let questions = input["questions"] as? [[String: Any]] ?? []
        var answers: [String: String] = [:]
        for (idx, selection) in selections.enumerated() {
            let key: String
            if idx < questions.count,
               let question = questions[idx]["question"] as? String,
               !question.isEmpty {
                key = question
            } else {
                key = "Answer \(idx + 1)"
            }
            answers[key] = selection
        }
        input["answers"] = answers
        return input
    }

    // MARK: Convenience wrappers

    private func runCursorInstallHooks() throws { try installAgentHooks(Self.agentDef(named: "cursor")!) }
    private func runCursorUninstallHooks() throws { try uninstallAgentHooks(Self.agentDef(named: "cursor")!) }
    private func runCursorHook(commandArgs: [String], client: SocketClient, telemetry: CLISocketSentryTelemetry) throws {
        try runGenericAgentHook(def: Self.agentDef(named: "cursor")!, commandArgs: commandArgs, client: client, telemetry: telemetry)
    }

    private func runGeminiInstallHooks() throws { try installAgentHooks(Self.agentDef(named: "gemini")!) }
    private func runGeminiUninstallHooks() throws { try uninstallAgentHooks(Self.agentDef(named: "gemini")!) }
    private func runGeminiHook(commandArgs: [String], client: SocketClient, telemetry: CLISocketSentryTelemetry) throws {
        try runGenericAgentHook(def: Self.agentDef(named: "gemini")!, commandArgs: commandArgs, client: client, telemetry: telemetry)
    }

    // MARK: - Hooks namespace

    private func runHooksNoSocketCommand(commandArgs: [String]) throws -> Bool {
        guard let first = commandArgs.first?.lowercased() else {
            print(subcommandUsage("hooks") ?? "Usage: cmux hooks <setup|uninstall|agent>")
            return true
        }

        switch first {
        case "help", "--help", "-h":
            print(subcommandUsage("hooks") ?? "Usage: cmux hooks <setup|uninstall|agent>")
            return true

        case "setup":
            try runSetupHooks(
                uninstall: false,
                positionalAgentFilter: try Self.hooksSetupPositionalAgentFilter(from: Array(commandArgs.dropFirst()))
            )
            return true

        case "uninstall":
            try runSetupHooks(
                uninstall: true,
                positionalAgentFilter: try Self.hooksSetupPositionalAgentFilter(from: Array(commandArgs.dropFirst()))
            )
            return true

        default:
            guard let def = Self.agentDef(named: first) else {
                if first == "feed" || first == "claude" {
                    return false
                }
                throw CLIError(message: "Unknown hooks target: \(first)")
            }

            let rest = Array(commandArgs.dropFirst())
            guard let action = rest.first?.lowercased() else {
                print(subcommandUsage("hooks") ?? "Usage: cmux hooks <setup|uninstall|agent>")
                return true
            }
            let actionArgs = Array(rest.dropFirst())
            switch action {
            case "inject-args" where def.name == "codex":
                // Hidden: emit the NUL-separated codex arg list the wrapper
                // (Resources/bin/cmux-codex-wrapper) splices to inject cmux's
                // fire-and-forget hooks for one invocation. No socket required.
                try emitCodexWrapperInjectArgs()
                return true
            case "install":
                try installHooksForAgent(def, arguments: actionArgs)
                return true
            case "uninstall":
                try uninstallHooksForAgent(def, arguments: actionArgs)
                return true
            case "install-hooks", "uninstall-hooks", "remove":
                throw CLIError(message: "Unknown hooks action: \(action). Use install or uninstall.")
            default:
                return false
            }
        }
    }

    private static func hooksCommandNeedsCmuxTarget(_ commandArgs: [String]) -> Bool {
        guard let first = commandArgs.first?.lowercased() else { return false }
        if first == "feed" || first == "claude" { return true }
        guard let def = Self.agentDef(named: first) else { return false }
        let action = commandArgs.dropFirst().first?.lowercased()
        if def.name == "grok" {
            return false
        }
        return action != "install" && action != "uninstall"
    }

    private func installHooksForAgent(_ def: AgentHookDef, arguments: [String]) throws {
        if def.name == "opencode" {
            let projectLocal = arguments.contains("--project")
            if projectLocal {
                // Project-local OpenCode install manages only the plugin file.
                try installOpenCodePlugin(projectLocal: true)
                return
            }
            try installAgentHooks(def)
            try installOpenCodePlugin(projectLocal: false)
            return
        }
        try installAgentHooks(def)
    }

    private func uninstallHooksForAgent(_ def: AgentHookDef, arguments: [String]) throws {
        if def.name == "opencode" {
            let projectLocal = arguments.contains("--project")
            if projectLocal {
                try uninstallOpenCodePlugin(projectLocal: true)
                return
            }
            try uninstallAgentHooks(def)
            try uninstallOpenCodePlugin(projectLocal: false)
            return
        }
        try uninstallAgentHooks(def)
    }

    private func runHooksSocketCommand(
        commandArgs: [String],
        client: SocketClient,
        telemetry: CLISocketSentryTelemetry,
        socketPassword: String? = nil
    ) throws {
        guard let first = commandArgs.first?.lowercased() else {
            throw CLIError(message: "Usage: cmux hooks <setup|uninstall|feed|claude|agent>")
        }
        let rest = Array(commandArgs.dropFirst())

        switch first {
        case "setup", "install", "uninstall":
            throw CLIError(message: "hooks \(first) must be handled before socket dispatch")

        case "feed":
            telemetry.breadcrumb("hooks.feed.dispatch")
            do {
                try runFeedHook(commandArgs: rest, client: client, telemetry: telemetry)
                telemetry.breadcrumb("hooks.feed.completed")
            } catch {
                telemetry.breadcrumb("hooks.feed.failure")
                captureSocketTransportError(telemetry: telemetry, stage: "hooks_feed_dispatch", error: error, client: client)
                throw error
            }

        case "claude":
            telemetry.breadcrumb("hooks.claude.dispatch")
            do {
                try runClaudeHook(commandArgs: rest, client: client, telemetry: telemetry, socketPassword: socketPassword)
                telemetry.breadcrumb("hooks.claude.completed")
            } catch {
                telemetry.breadcrumb("hooks.claude.failure")
                captureSocketTransportError(telemetry: telemetry, stage: "hooks_claude_dispatch", error: error, client: client)
                throw error
            }

        default:
            guard let def = Self.agentDef(named: first) else {
                throw CLIError(message: "Unknown hooks target: \(first)")
            }
            telemetry.breadcrumb("hooks.\(def.name).dispatch")
            do {
                try runGenericAgentHook(def: def, commandArgs: rest, client: client, telemetry: telemetry, socketPassword: socketPassword)
                telemetry.breadcrumb("hooks.\(def.name).completed")
            } catch {
                telemetry.breadcrumb("hooks.\(def.name).failure")
                captureSocketTransportError(telemetry: telemetry, stage: "hooks_\(def.name)_dispatch", error: error, client: client)
                throw error
            }
        }
    }

    private static func hooksSetupPositionalAgentFilter(from args: [String]) throws -> String? {
        var skipNext = false
        var positionalAgent: String?
        for arg in args {
            if skipNext {
                skipNext = false
                continue
            }
            switch arg {
            case "--agent":
                skipNext = true
            case "--yes", "-y", "--uninstall":
                continue
            default:
                if !arg.hasPrefix("-") {
                    if positionalAgent != nil {
                        throw CLIError(message: "Too many hooks targets: specify at most one positional agent")
                    }
                    positionalAgent = arg
                }
            }
        }
        return positionalAgent
    }

    private func runSetupHooks(uninstall: Bool = false, positionalAgentFilter: String? = nil) throws {
        let args = ProcessInfo.processInfo.arguments
        let flagAgentFilter = optionValue(args, name: "--agent")
        if let flagAgentFilter, let positionalAgentFilter {
            guard let flagDef = Self.agentDef(named: flagAgentFilter) else {
                throw CLIError(message: "Unknown hooks target: \(flagAgentFilter)")
            }
            guard let positionalDef = Self.agentDef(named: positionalAgentFilter) else {
                throw CLIError(message: "Unknown hooks target: \(positionalAgentFilter)")
            }
            if flagDef.name != positionalDef.name {
                throw CLIError(message: "Conflicting hooks target: use either --agent or a positional target, not both")
            }
        }
        let agentFilter = flagAgentFilter ?? positionalAgentFilter
        let agentFilterDef: AgentHookDef?
        if let agentFilter {
            guard let def = Self.agentDef(named: agentFilter) else {
                throw CLIError(message: "Unknown hooks target: \(agentFilter)")
            }
            agentFilterDef = def
        } else {
            agentFilterDef = nil
        }
        let isUninstall = uninstall || args.contains("--uninstall")
        let fm = FileManager.default
        let verb = isUninstall ? "uninstalling" : "installing"

        print("cmux hooks \(isUninstall ? "uninstall" : "setup"): \(verb) agent hooks")
        if !isUninstall {
            print("  (Claude Code hooks are injected automatically via the claude wrapper)")
        }
        print("")

        var count = 0
        var skipped = 0
        var skippedNoBinary: [String] = []

        for def in Self.agentDefs {
            if let agentFilterDef, agentFilterDef.name != def.name { continue }
            let configDir = def.resolvedConfigDir()
            let canUseMissingConfigDir = def.createConfigDirIfMissing
                || def.name == "opencode"
                || def.name == "pi"
                || def.name == "amp"
                || (!isUninstall && def.name == "rovodev")
            if !canUseMissingConfigDir, !fm.fileExists(atPath: configDir) {
                print("  \(def.name): skipped (config dir not found)")
                skipped += 1
                continue
            }
            // On install, also skip agents whose binary isn't on PATH.
            // On uninstall, always proceed so stale configs can be
            // cleaned up regardless of whether the binary still exists.
            if !isUninstall && !Self.isBinaryOnPath(def.binaryName) {
                print("  \(def.name): skipped (binary not found on PATH)")
                skipped += 1
                skippedNoBinary.append(def.name)
                continue
            }
            print("  \(def.name):")
            if isUninstall {
                try uninstallHooksForAgent(def, arguments: [])
            } else {
                try installHooksForAgent(def, arguments: [])
            }
            count += 1
            print("")
        }

        print("Done: \(count) \(isUninstall ? "uninstalled" : "installed"), \(skipped) skipped")
        if !skippedNoBinary.isEmpty {
            print("  skipped \(skippedNoBinary.count) agents (not found on PATH): \(skippedNoBinary.joined(separator: ", "))")
        }
    }

    /// Cross-platform `command -v <name>` for the install gate.
    private static func isBinaryOnPath(_ name: String) -> Bool {
        let process = Process()
        process.launchPath = "/bin/sh"
        process.arguments = ["-c", "command -v \(name) >/dev/null 2>&1"]
        do {
            try cliRunProcess(process)
            process.waitUntilExit()
            return process.terminationStatus == 0
        } catch {
            return false
        }
    }


    private func versionSummary() -> String {
        let info = resolvedVersionInfo()
        let commit = info["CMUXCommit"].flatMap { normalizedCommitHash($0) }
        let baseSummary: String
        if let version = info["CFBundleShortVersionString"], let build = info["CFBundleVersion"] {
            baseSummary = "cmux \(version) (\(build))"
        } else if let version = info["CFBundleShortVersionString"] {
            baseSummary = "cmux \(version)"
        } else if let build = info["CFBundleVersion"] {
            baseSummary = "cmux build \(build)"
        } else {
            baseSummary = "cmux version unknown"
        }
        guard let commit else { return baseSummary }
        return "\(baseSummary) [\(commit)]"
    }

    private func printWelcome() {
        let reset = "\u{001B}[0m"
        let bold = "\u{001B}[1m"
        func trueColor(_ red: Int, _ green: Int, _ blue: Int) -> String {
            "\u{001B}[38;2;\(red);\(green);\(blue)m"
        }

        let isDark = UserDefaults.standard.string(forKey: "AppleInterfaceStyle") == "Dark"

        let c1 = trueColor(0, 212, 255)
        let c2 = trueColor(24, 181, 250)
        let c3 = trueColor(48, 150, 245)
        let c4 = trueColor(72, 119, 241)
        let c5 = trueColor(96, 88, 239)
        let c6 = trueColor(110, 73, 238)
        let c7 = trueColor(124, 58, 237)

        let tagline: String
        let subdued: String

        if isDark {
            tagline = trueColor(130, 130, 140)
            subdued = "\u{001B}[2m"
        } else {
            tagline = trueColor(90, 90, 98)
            subdued = trueColor(100, 100, 108)
        }

        let logo = """
        \(c1)  ::\(reset)
        \(c2)    ::::\(reset)              \(c1)c\(c2)m\(c3)u\(c7)x\(reset)
        \(c3)      ::::::\(reset)
        \(c4)        ::::::\(reset)        \(tagline)the open source terminal\(reset)
        \(c5)      ::::::\(reset)          \(tagline)built for coding agents\(reset)
        \(c6)    ::::\(reset)
        \(c7)  ::\(reset)
        """

        let shortcuts = """
          \(bold)Shortcuts\(reset)

          \(bold)\u{2318}N\(reset)\(subdued)                  New workspace\(reset)
          \(bold)\u{2318}T\(reset)\(subdued)                  New tab\(reset)
          \(bold)\u{2318}P\(reset)\(subdued)                  Go to workspace\(reset)
          \(bold)\u{2318}B\(reset)\(subdued)                  Toggle Left Sidebar\(reset)
          \(bold)\u{2318}\u{2325}B\(reset)\(subdued)                 Toggle Right Sidebar\(reset)
          \(bold)\u{2318}D\(reset)\(subdued)                  Split right\(reset)
          \(bold)\u{2318}\u{21E7}D\(reset)\(subdued)                 Split down\(reset)
          \(bold)\u{2318}\u{21E7}P\(reset)\(subdued)                 Command palette\(reset)
          \(bold)\u{2318}\u{21E7}R\(reset)\(subdued)                 Rename workspace\(reset)
          \(bold)\u{2318}\u{21E7}L\(reset)\(subdued)                 New browser\(reset)
          \(bold)\u{2318}\u{21E7}U\(reset)\(subdued)                 Jump to latest unread\(reset)
          \(bold)\u{2325}\u{2318}U\(reset)\(subdued)                 Toggle unread\(reset)
        """

        print()
        print(logo)
        print()
        print(shortcuts)
        print()
        print("  \(bold)Docs\(reset)\(subdued)                https://cmux.com/docs\(reset)")
        print("  \(bold)Discord\(reset)\(subdued)             https://discord.gg/xsgFEVrWCZ\(reset)")
        print("  \(bold)GitHub\(reset)\(subdued)              https://github.com/manaflow-ai/cmux (please leave a star ⭐)\(reset)")
        print("  \(bold)Email\(reset)\(subdued)               founders@manaflow.com\(reset)")
        print()
        print("  \(subdued)Run \(reset)\(bold)cmux --help\(reset)\(subdued) for all commands.\(reset)")
        print("  \(subdued)Run \(reset)\(bold)cmux shortcuts\(reset)\(subdued) to edit shortcuts.\(reset)")
        print("  \(subdued)Run \(reset)\(bold)cmux feedback\(reset)\(subdued) to report a bug.\(reset)")
        print()
    }

    private func resolvedVersionInfo() -> [String: String] {
        var info: [String: String] = [:]
        if let main = versionInfo(from: Bundle.main.infoDictionary) {
            info.merge(main, uniquingKeysWith: { current, _ in current })
        }

        let needsPlistFallback =
            info["CFBundleShortVersionString"] == nil ||
            info["CFBundleVersion"] == nil ||
            info["CMUXCommit"] == nil
        if needsPlistFallback {
            for plistURL in candidateInfoPlistURLs() {
                guard let data = try? Data(contentsOf: plistURL),
                      let raw = try? PropertyListSerialization.propertyList(from: data, options: [], format: nil),
                      let dictionary = raw as? [String: Any],
                      let parsed = versionInfo(from: dictionary)
                else {
                    continue
                }
                info.merge(parsed, uniquingKeysWith: { current, _ in current })
                if info["CFBundleShortVersionString"] != nil,
                   info["CFBundleVersion"] != nil,
                   info["CMUXCommit"] != nil {
                    break
                }
            }
        }

        let needsProjectFallback =
            info["CFBundleShortVersionString"] == nil ||
            info["CFBundleVersion"] == nil ||
            info["CMUXCommit"] == nil
        if needsProjectFallback, let fromProject = versionInfoFromProjectFile() {
            info.merge(fromProject, uniquingKeysWith: { current, _ in current })
        }

        if info["CMUXCommit"] == nil,
           let commit = normalizedCommitHash(ProcessInfo.processInfo.environment["CMUX_COMMIT"]) {
            info["CMUXCommit"] = commit
        }

        return info
    }

    private func versionInfo(from dictionary: [String: Any]?) -> [String: String]? {
        guard let dictionary else { return nil }

        var info: [String: String] = [:]
        if let version = dictionary["CFBundleShortVersionString"] as? String {
            let trimmed = version.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty && !trimmed.contains("$(") {
                info["CFBundleShortVersionString"] = trimmed
            }
        }
        if let build = dictionary["CFBundleVersion"] as? String {
            let trimmed = build.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty && !trimmed.contains("$(") {
                info["CFBundleVersion"] = trimmed
            }
        }
        if let commit = dictionary["CMUXCommit"] as? String,
           let normalizedCommit = normalizedCommitHash(commit) {
            info["CMUXCommit"] = normalizedCommit
        }
        return info.isEmpty ? nil : info
    }

    private func versionInfoFromProjectFile() -> [String: String]? {
        guard let executableURL = resolvedExecutableURL() else {
            return nil
        }

        let fileManager = FileManager.default
        var current = executableURL.deletingLastPathComponent().standardizedFileURL

        while true {
            let projectFile = current.appendingPathComponent("cmux.xcodeproj/project.pbxproj")
            if fileManager.fileExists(atPath: projectFile.path),
               let contents = try? String(contentsOf: projectFile, encoding: .utf8) {
                var info: [String: String] = [:]
                if let version = firstProjectSetting("MARKETING_VERSION", in: contents) {
                    info["CFBundleShortVersionString"] = version
                }
                if let build = firstProjectSetting("CURRENT_PROJECT_VERSION", in: contents) {
                    info["CFBundleVersion"] = build
                }
                if let commit = gitCommitHash(at: current) {
                    info["CMUXCommit"] = commit
                }
                if !info.isEmpty {
                    return info
                }
            }

            guard let parent = parentSearchURL(for: current) else {
                break
            }
            current = parent
        }

        return nil
    }

    private func firstProjectSetting(_ key: String, in source: String) -> String? {
        let pattern = NSRegularExpression.escapedPattern(for: key) + "\\s*=\\s*([^;]+);"
        guard let regex = try? NSRegularExpression(pattern: pattern) else {
            return nil
        }
        let searchRange = NSRange(source.startIndex..<source.endIndex, in: source)
        guard let match = regex.firstMatch(in: source, options: [], range: searchRange),
              match.numberOfRanges > 1,
              let valueRange = Range(match.range(at: 1), in: source)
        else {
            return nil
        }
        let value = source[valueRange]
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .trimmingCharacters(in: CharacterSet(charactersIn: "\""))
        guard !value.isEmpty, !value.contains("$(") else {
            return nil
        }
        return value
    }

    private func gitCommitHash(at directory: URL) -> String? {
        let process = Process()
        let stdout = Pipe()
        process.executableURL = URL(fileURLWithPath: "/usr/bin/env")
        process.arguments = ["git", "-C", directory.path, "rev-parse", "--short=9", "HEAD"]
        process.standardOutput = stdout
        process.standardError = Pipe()

        do {
            try cliRunProcess(process)
        } catch {
            return nil
        }
        process.waitUntilExit()
        guard process.terminationStatus == 0 else {
            return nil
        }

        let data = stdout.fileHandleForReading.readDataToEndOfFileOrEmpty()
        guard let output = String(data: data, encoding: .utf8) else {
            return nil
        }
        return normalizedCommitHash(output)
    }

    private func normalizedCommitHash(_ value: String?) -> String? {
        guard let value else { return nil }
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty, !trimmed.contains("$(") else {
            return nil
        }
        let normalized = trimmed.lowercased()
        let allowed = CharacterSet(charactersIn: "0123456789abcdef")
        guard normalized.unicodeScalars.allSatisfy({ allowed.contains($0) }) else {
            return nil
        }
        return String(normalized.prefix(12))
    }

    // Foundation can walk past "/" into "/.." when repeatedly deleting path
    // components, so stop once the canonical root is reached.
    func parentSearchURL(for url: URL) -> URL? {
        let standardized = url.standardizedFileURL
        let path = standardized.path
        guard !path.isEmpty, path != "/" else {
            return nil
        }

        let parent = standardized.deletingLastPathComponent().standardizedFileURL
        guard parent.path != path else {
            return nil
        }
        return parent
    }

    private func candidateInfoPlistURLs() -> [URL] {
        guard let executableURL = resolvedExecutableURL() else {
            return []
        }

        let fileManager = FileManager.default

        var candidates: [URL] = []
        var seen: Set<String> = []
        func appendIfExisting(_ url: URL) {
            let path = url.path
            guard !path.isEmpty else { return }
            guard seen.insert(path).inserted else { return }
            guard fileManager.fileExists(atPath: path) else { return }
            candidates.append(url)
        }

        var current = executableURL.deletingLastPathComponent().standardizedFileURL
        while true {
            if current.pathExtension == "app" {
                appendIfExisting(current.appendingPathComponent("Contents/Info.plist"))
            }
            if current.lastPathComponent == "Contents" {
                appendIfExisting(current.appendingPathComponent("Info.plist"))
            }

            let projectMarker = current.appendingPathComponent("cmux.xcodeproj/project.pbxproj")
            let repoInfo = current.appendingPathComponent("Resources/Info.plist")
            if fileManager.fileExists(atPath: projectMarker.path),
               fileManager.fileExists(atPath: repoInfo.path) {
                appendIfExisting(repoInfo)
                break
            }

            guard let parent = parentSearchURL(for: current) else {
                break
            }
            current = parent
        }

        // If we already found an ancestor bundle or repo Info.plist, avoid scanning
        // sibling app bundles. Large Resources directories can otherwise balloon RSS.
        guard candidates.isEmpty else {
            return candidates
        }

        let searchRoots = [
            executableURL.deletingLastPathComponent().standardizedFileURL,
            executableURL.deletingLastPathComponent().deletingLastPathComponent().standardizedFileURL
        ]
        for root in searchRoots {
            guard let entries = fileManager.enumerator(
                at: root,
                includingPropertiesForKeys: nil,
                options: [.skipsHiddenFiles, .skipsSubdirectoryDescendants],
                errorHandler: { _, _ in true }
            ) else {
                continue
            }
            for case let entry as URL in entries where entry.pathExtension == "app" {
                appendIfExisting(entry.appendingPathComponent("Contents/Info.plist"))
            }
        }

        return candidates
    }

    private func currentExecutablePath() -> String? {
        if let path = CLIExecutableLocator.currentExecutableURL()?.path
            .trimmingCharacters(in: .whitespacesAndNewlines),
           !path.isEmpty {
            return path
        }
        return args.first
    }

    func resolvedExecutableURL() -> URL? {
        guard let executable = currentExecutablePath(), !executable.isEmpty else {
            return nil
        }

        let expanded = (executable as NSString).expandingTildeInPath
        if let resolvedPath = realpath(expanded, nil) {
            defer { free(resolvedPath) }
            return URL(fileURLWithPath: String(cString: resolvedPath)).standardizedFileURL
        }

        return URL(fileURLWithPath: expanded).standardizedFileURL
    }

    private func usage() -> String {
        return """
        cmux - control cmux via Unix socket

        Usage:
          cmux <path>                Open a directory in a new workspace (launches cmux if needed)
          cmux [global-options] <command> [options]

        Targets:
          Commands that accept a window, workspace, pane, or surface take a UUID, a short ref (window:1/workspace:2/pane:3/surface:4), or an index.
          `tab-action` also accepts `tab:<n>` in addition to `surface:<n>`.
          Output defaults to refs; pass --id-format uuids or --id-format both to include UUIDs.

        Socket Auth:
          --password takes precedence, then CMUX_SOCKET_PASSWORD, then the password saved in Settings.

        Agent Help:
          Change cmux settings with `cmux docs settings` and `cmux settings path`; add Dock controls with `cmux docs dock`.
          Before editing, back up any existing cmux.json file to a timestamped .bak copy.
          Use printed curl commands to fetch the latest docs/schema; prefer Ghostty config for terminal behavior Ghostty already supports.
          Ghostty config lives at ~/.config/ghostty/config (terminal transparency, blur, font, theme, keybinds, etc.).
          `cmux reload-config` reloads BOTH Ghostty config and ~/.config/cmux/cmux.json, then refreshes terminals in place. No app restart needed.

